INSERT INTO `subtitles` VALUES (1,0,'2026-04-06 22:16:50.264773',6.35,'Welcome to English in a Minute.',0,4.047,1),(2,0,'2026-04-06 22:16:50.309190',12.116,'When we dish out food, we put it on a plate to give to others.',1,7.251,1),(3,0,'2026-04-06 22:16:50.312182',17.162,'But what does dish it out but can\'t take it mean?',2,12.937,1),(4,0,'2026-04-06 22:16:50.313179',22.247,'Sometimes D really bothers me.',3,19.965,1),(5,0,'2026-04-06 22:16:50.315174',23.028,'Uh-oh.',4,22.848,1),(6,0,'2026-04-06 22:16:50.317169',24.229,'What happened?',5,23.569,1),(7,0,'2026-04-06 22:16:50.321026',25.17,'Okay.',6,24.85,1),(8,0,'2026-04-06 22:16:50.323022',29.295,'She joked about your piano playing.',7,25.491,1),(9,0,'2026-04-06 22:16:50.325015',31.423,'So I joked about her singing.',8,30.102,1),(10,0,'2026-04-06 22:16:50.328008',35.907,'And she got angry at me.',9,31.483,1),(11,0,'2026-04-06 22:16:50.331997',40.051,'Oh, so she can dish it out, but she can\'t take it.',10,35.928,1),(12,0,'2026-04-06 22:16:50.333996',40.672,'That\'s it.',11,40.172,1),(13,0,'2026-04-06 22:16:50.335986',47.518,'Some people insult joke about or criticize others.',12,43.114,1),(14,0,'2026-04-06 22:16:50.339976',51.943,'But they don\'t like it when people do the same to them.',13,48.399,1),(15,0,'2026-04-06 22:16:50.341970',57.628,'So we say they can dish it out, but they can\'t take it.',14,52.683,1),(16,0,'2026-04-06 22:17:19.541100',6.436,'Welcome to English in a minute.',0,4.013,2),(17,0,'2026-04-06 22:17:19.543607',9.7,'Pie is a delicious dessert.',1,7.237,2),(18,0,'2026-04-06 22:17:19.546802',16.909,'And there are so many different flavors like cherry, lemon, banana cream.',2,10.421,2),(19,0,'2026-04-06 22:17:19.549593',21.955,'But what could the idiom pie in the sky mean?',3,18.391,2),(20,0,'2026-04-06 22:17:19.552597',27.742,'Pedro is finally moving to Hollywood to follow his acting dream.',4,23.257,2),(21,0,'2026-04-06 22:17:19.554580',30.606,'He\'s been talking about that for years.',5,27.822,2),(22,0,'2026-04-06 22:17:19.557571',33.97,'His plans are just pie in the sky.',6,31.267,2),(23,0,'2026-04-06 22:17:19.559565',37.839,'His YouTube channel has over four million subscribers.',7,34.135,2),(24,0,'2026-04-06 22:17:19.563103',39.701,'Four million.',8,39.001,2),(25,0,'2026-04-06 22:17:19.565093',48.451,'Anything pie in the sky could be great, but probably won\'t happen.',9,42.525,2),(26,0,'2026-04-06 22:17:19.567086',57.882,'As an adjective, pie in the sky describes dreams, plans, or goals that are unlikely to become reality.',10,49.312,2),(27,0,'2026-04-06 22:17:50.924771',6.517,'Welcome to English in a minute.',0,4.334,3),(28,0,'2026-04-06 22:17:50.927757',11.324,'Some people use a large ball for exercise.',1,7.518,3),(29,0,'2026-04-06 22:17:50.929747',15.43,'Is that what to get on the ball means?',2,12.505,3),(30,0,'2026-04-06 22:17:50.932738',17.212,'Hi, Ana.',3,16.791,3),(31,0,'2026-04-06 22:17:50.936728',18.614,'How was your day been?',4,17.653,3),(32,0,'2026-04-06 22:17:50.938722',20.737,'Great, very great, very productive.',5,18.734,3),(33,0,'2026-04-06 22:17:50.941714',23.441,'I finished three reports and have only one more to do.',6,20.877,3),(34,0,'2026-04-06 22:17:50.943710',26.044,'Wow, you are on the ball.',7,23.481,3),(35,0,'2026-04-06 22:17:50.946702',28.688,'How did you do them so fast?',8,26.685,3),(36,0,'2026-04-06 22:17:50.948695',29.648,'Coffee.',9,29.208,3),(37,0,'2026-04-06 22:17:50.951687',30.97,'Lots of coffee.',10,30.249,3),(38,0,'2026-04-06 22:17:50.954234',31.771,'Do you want some?',11,31.01,3),(39,0,'2026-04-06 22:17:50.955903',32.392,'I\'ll get it.',12,31.891,3),(40,0,'2026-04-06 22:17:50.958796',33.553,'I\'d love more coffee.',13,32.492,3),(41,0,'2026-04-06 22:17:50.960791',34.254,'Thank you.',14,33.673,3),(42,0,'2026-04-06 22:17:50.962786',38.779,'Sure, but maybe not that much coffee.',15,35.015,3),(43,0,'2026-04-06 22:17:50.963783',46.808,'Someone who is on the ball finishes work quickly and ahead of time.',16,41.021,3),(44,0,'2026-04-06 22:17:50.966775',54.576,'We can also say a person should get on the ball when they need to work faster or better.',17,47.809,3),(45,0,'2026-04-06 22:17:50.969766',57.78,'And that\'s English in a minute.',18,54.616,3),(46,0,'2026-04-06 22:18:22.054800',6.674,'Welcome to English in a minute.',0,4.25,4),(47,0,'2026-04-06 22:18:22.056796',10.28,'Horses are big and strong.',1,7.836,4),(48,0,'2026-04-06 22:18:22.059787',13.986,'Writing them takes skill and strength.',2,11.061,4),(49,0,'2026-04-06 22:18:22.061782',20.176,'So is the idiom hold your horses about controlling horses?',3,14.907,4),(50,0,'2026-04-06 22:18:22.062779',24.963,'Oh, Andrew, can you help me with this box?',4,22.239,4),(51,0,'2026-04-06 22:18:22.064773',26.386,'Just a second.',5,25.264,4),(52,0,'2026-04-06 22:18:22.065773',27.828,'I\'m almost done.',6,26.686,4),(53,0,'2026-04-06 22:18:22.068604',29.751,'Andrew, the box.',7,28.409,4),(54,0,'2026-04-06 22:18:22.070599',31.133,'I\'m on the last page.',8,30.052,4),(55,0,'2026-04-06 22:18:22.072881',32.234,'It\'s really heavy.',9,31.253,4),(56,0,'2026-04-06 22:18:22.074875',33.816,'Hold your horses.',10,32.274,4),(57,0,'2026-04-06 22:18:22.076871',38.281,'What\'s in the box?',11,37.4,4),(58,0,'2026-04-06 22:18:22.078865',39.742,'Horses.',12,39.222,4),(59,0,'2026-04-06 22:18:22.080860',50.313,'Hold your horses is a way of telling someone to wait, to be patient.',13,39.782,4),(60,0,'2026-04-06 22:18:22.083446',52.696,'It\'s very informal.',14,51.214,4),(61,0,'2026-04-06 22:18:22.084361',57.561,'And depending on how you say it, it could sound rude.',15,53.597,4),(62,0,'2026-04-06 22:18:57.577241',6.523,'Welcome to English in a minute.',0,4.3,5),(63,0,'2026-04-06 22:18:57.578752',13.153,'When you strike a chord in music, you play several notes at the same time.',1,7.645,5),(64,0,'2026-04-06 22:18:57.579750',17.9,'So are Anna and Andrew going to play music?',2,13.173,5),(65,0,'2026-04-06 22:18:57.581742',19.121,'I hope so.',3,18.34,5),(66,0,'2026-04-06 22:18:57.582316',24.189,'I love Amelia Earhart.',4,19.141,5),(67,0,'2026-04-06 22:18:57.584309',27.193,'Her life really struck a chord with me.',5,25.03,5),(68,0,'2026-04-06 22:18:57.585772',28.515,'Really?',6,27.253,5),(69,0,'2026-04-06 22:18:57.586738',33.362,'But she was a pilot and you\'re afraid of flying.',7,28.555,5),(70,0,'2026-04-06 22:18:57.588732',36.599,'No, her flying career didn\'t strike a cord.',8,33.595,5),(71,0,'2026-04-06 22:18:57.590852',38.902,'She loved hot chocolate.',9,36.659,5),(72,0,'2026-04-06 22:18:57.592847',51.238,'And so do I. When something strikes a cord with you, it causes strong reaction, usually because you identify with it.',10,38.942,5),(73,0,'2026-04-06 22:18:57.595497',57.426,'Striking a cord can also mean that you\'re reminded of something familiar.',11,52.239,5),(74,0,'2026-04-06 22:19:26.869887',6.543,'Welcome to English in a minute.',0,4.081,6),(75,0,'2026-04-06 22:19:26.871883',10.527,'We have to use our brains to think.',1,7.524,6),(76,0,'2026-04-06 22:19:26.872879',16.613,'So what does the expression no-brainer mean?',2,11.488,6),(77,0,'2026-04-06 22:19:26.873902',19.696,'Hey, did you watch the new episode of Catch a Criminal?',3,16.633,6),(78,0,'2026-04-06 22:19:26.875870',22.599,'Yeah, but it was such a no-brainer.',4,20.377,6),(79,0,'2026-04-06 22:19:26.876869',27.383,'The police found a gun and all the money in David\'s house.',5,22.659,6),(80,0,'2026-04-06 22:19:26.878864',33.109,'Well, what if David has a twin brother who lives with him?',6,28.084,6),(81,0,'2026-04-06 22:19:26.880858',36.62,'the police would know if David had a twin brother.',7,33.376,6),(82,0,'2026-04-06 22:19:26.882853',39.865,'Well, what if they don\'t know?',8,37.502,6),(83,0,'2026-04-06 22:19:26.883850',42.669,'Then they are really bad at their jobs.',9,39.905,6),(84,0,'2026-04-06 22:19:26.885844',50.159,'A no-brainer is something that requires little thought or is obvious.',10,44.491,6),(85,0,'2026-04-06 22:19:26.886870',54.926,'It also means it is easy to make the right choice.',11,51.281,6),(86,0,'2026-04-06 22:19:26.888863',58.05,'And that\'s English in a minute.',12,55.867,6),(87,0,'2026-04-06 22:19:50.274743',6.323,'Welcome to English in a minute.',0,4.098,7),(88,0,'2026-04-06 22:19:50.275740',11.554,'A rut in a dirt road can make wheels get stuck.',1,7.586,7),(89,0,'2026-04-06 22:19:50.276738',16.505,'But what does it mean if a person is stuck in a rut?',2,12.516,7),(90,0,'2026-04-06 22:19:50.277735',22.478,'Why are you wearing that wig?',3,20.734,7),(91,0,'2026-04-06 22:19:50.279730',27.957,'I know it looks funny, but I feel like I\'ve been stuck in a rut.',4,22.627,7),(92,0,'2026-04-06 22:19:50.281723',34.63,'I\'m just trying to change things up and feel more creative and different.',5,28.638,7),(93,0,'2026-04-06 22:19:50.283718',36.113,'Got it.',6,35.732,7),(94,0,'2026-04-06 22:19:50.285083',37.656,'Is it working?',7,36.994,7),(95,0,'2026-04-06 22:19:50.286024',41.563,'I think it\'s just making my head hot.',8,38.758,7),(96,0,'2026-04-06 22:19:50.288018',52.537,'To be stuck in a rut means you feel like you do the same thing over and over and need a change.',9,43.653,7),(97,0,'2026-04-06 22:19:50.290015',57.51,'But maybe that is not the change Andrew needs.',10,53.459,7),(98,0,'2026-04-06 22:20:11.601054',5.499,'Welcome to English in a minute.',0,3.997,8),(99,0,'2026-04-06 22:20:11.603680',11.085,'News can be any information that is, well, new to someone.',1,6.34,8),(100,0,'2026-04-06 22:20:11.604677',14.548,'But what does it mean to break the news?',2,11.745,8),(101,0,'2026-04-06 22:20:11.606604',20.895,'So, are you all ready for our big work trip to Brazil?',3,16.33,8),(102,0,'2026-04-06 22:20:11.607599',27.422,'I just bought a new travel shirt, travel sunglasses, and this travel guidebook.',4,21.696,8),(103,0,'2026-04-06 22:20:11.609593',32.309,'Andrew, I hate to break the news, but you\'re not traveling.',5,27.925,8),(104,0,'2026-04-06 22:20:11.610591',35.192,'But budget cuts.',6,32.329,8),(105,0,'2026-04-06 22:20:11.611588',37.794,'There\'s not enough money for two.',7,35.592,8),(106,0,'2026-04-06 22:20:11.613582',40.696,'But can I borrow that travel book?',8,38.855,8),(107,0,'2026-04-06 22:20:11.614649',47.863,'To break the news means to tell someone bad news.',9,43.719,8),(108,0,'2026-04-06 22:20:11.616388',51.446,'Something that will make them upset or sad.',10,48.463,8),(109,0,'2026-04-06 22:20:11.617895',57.932,'Breaking the news can be a hard thing to do, and so can hearing about it.',11,52.447,8),(110,0,'2026-04-06 22:20:33.616872',5.553,'Welcome to English in a minute.',0,4.03,9),(111,0,'2026-04-06 22:20:33.618864',11.103,'My shoulders and my head are both at the top of my body.',1,6.234,9),(112,0,'2026-04-06 22:20:33.619862',17.234,'So what does it mean if something is head and shoulders above something else?',2,11.744,9),(113,0,'2026-04-06 22:20:33.620858',22.523,'Andrew, I have found the perfect pizza.',3,19.258,9),(114,0,'2026-04-06 22:20:33.622876',24.427,'Perfect pizza palace.',4,23.105,9),(115,0,'2026-04-06 22:20:33.623877',27.793,'That place is way too expensive.',5,25.088,9),(116,0,'2026-04-06 22:20:33.625847',37.358,'Maybe, but their pizza is head and shoulders above all the other pizza places in this city, and I have tried them all.',6,28.246,9),(117,0,'2026-04-06 22:20:33.626845',39.421,'You could not.',7,38.46,9),(118,0,'2026-04-06 22:20:33.628863',49.955,'If something is head and shoulders above something else, it is better than all others, or simply the best.',8,42.084,9),(119,0,'2026-04-06 22:20:33.629835',54.621,'It\'s as if it is placed higher than everything around it.',9,50.736,9),(120,0,'2026-04-06 22:20:33.630833',57.645,'And that\'s English in a minute.',10,56.163,9),(121,0,'2026-04-06 22:20:55.066696',5.689,'Welcome to English in a minute.',0,4.047,10),(122,0,'2026-04-06 22:20:55.067715',12.317,'We all like to be treated fairly, but what about being treated squarely?',1,6.41,10),(123,0,'2026-04-06 22:20:55.068742',16.342,'Let\'s learn how to use the idiom, fair, and square.',2,13.498,10),(124,0,'2026-04-06 22:20:55.069707',20.246,'Anna, where have you been?',3,18.304,10),(125,0,'2026-04-06 22:20:55.070704',21.948,'I lost you in the crowd.',4,20.266,10),(126,0,'2026-04-06 22:20:55.071702',24.031,'I was playing games.',5,22.97,10),(127,0,'2026-04-06 22:20:55.072701',26.614,'I\'m really good at carnival games.',6,24.612,10),(128,0,'2026-04-06 22:20:55.074694',27.976,'I see that.',7,27.295,10),(129,0,'2026-04-06 22:20:55.075692',30.599,'You really want a lot of stuffed animals.',8,28.516,10),(130,0,'2026-04-06 22:20:55.077350',33.362,'Are you sure you didn\'t cheat?',9,31.52,10),(131,0,'2026-04-06 22:20:55.078345',37.211,'No, I won them all fair and square.',10,33.646,10),(132,0,'2026-04-06 22:20:55.079342',38.633,'And they\'re all mine.',11,37.271,10),(133,0,'2026-04-06 22:20:55.081336',39.855,'All mine.',12,38.673,10),(134,0,'2026-04-06 22:20:55.082334',50.831,'Fair and square describes winning something in an honest way and without any doubt.',13,45.102,10),(135,0,'2026-04-06 22:20:55.083396',55.317,'The expression is a fun one to say because it rhymes.',14,51.712,10),(136,0,'2026-04-06 22:20:55.084336',57.46,'Fair and square.',15,55.778,10),(137,0,'2026-04-06 22:21:16.521573',5.52,'Welcome to English in a minute.',0,3.997,11),(138,0,'2026-04-06 22:21:16.522571',11.209,'This piece of paper has lines at the top, middle, and bottom.',1,6.421,11),(139,0,'2026-04-06 22:21:16.523568',14.554,'But what does the bottom line mean?',2,11.87,11),(140,0,'2026-04-06 22:21:16.524565',18.701,'Andrew, did you watch the baseball game last night?',3,16.518,11),(141,0,'2026-04-06 22:21:16.525562',23.729,'Yes, I did.',4,22.828,11),(142,0,'2026-04-06 22:21:16.526560',26.113,'And I saw us lose again.',5,23.75,11),(143,0,'2026-04-06 22:21:16.527557',28.317,'We need some new players.',6,26.153,11),(144,0,'2026-04-06 22:21:16.529155',30.409,'Well, they\'re getting better.',7,28.567,11),(145,0,'2026-04-06 22:21:16.530150',31.911,'And they tried really hard.',8,30.749,11),(146,0,'2026-04-06 22:21:16.531147',38.598,'Yeah, they try hard, but the bottom line is you have to hit the ball to win.',9,32.311,11),(147,0,'2026-04-06 22:21:16.533184',40.62,'They weren\'t hitting.',10,38.658,11),(148,0,'2026-04-06 22:21:16.534135',49.069,'The bottom line means the most basic or important thing to consider in a situation.',11,40.64,11),(149,0,'2026-04-06 22:21:16.535133',54.255,'Bottom line can also be used to mean the final result or outcome.',12,50.05,11),(150,0,'2026-04-06 22:21:16.537128',57.038,'And that\'s English in a minute.',13,55.576,11),(151,0,'2026-04-06 22:21:37.638357',5.485,'Welcome to English in a minute.',0,3.963,12),(152,0,'2026-04-06 22:21:37.639356',10.39,'In a classroom, the chalkboard is also called a slate.',1,6.165,12),(153,0,'2026-04-06 22:21:37.640354',14.554,'It\'s important to clean it before starting a new lesson.',2,11.151,12),(154,0,'2026-04-06 22:21:37.641352',18.298,'So does clean slate relate to teaching?',3,15.275,12),(155,0,'2026-04-06 22:21:37.642347',21.962,'I love the start of a new year.',4,20.22,12),(156,0,'2026-04-06 22:21:37.643346',24.044,'It\'s a great time to start fresh.',5,22.002,12),(157,0,'2026-04-06 22:21:37.644341',25.185,'Make a new start.',6,24.345,12),(158,0,'2026-04-06 22:21:37.645340',26.627,'Me too.',7,26.106,12),(159,0,'2026-04-06 22:21:37.647043',31.472,'This year, I\'m going to start with a clean slate and give up bad habits.',8,27.268,12),(160,0,'2026-04-06 22:21:37.647628',36.015,'like eating donuts and drinking too much coffee?',9,32.87,12),(161,0,'2026-04-06 22:21:37.648549',36.095,'No.',10,36.035,12),(162,0,'2026-04-06 22:21:37.649547',42.946,'No other bad habits.',11,37.257,12),(163,0,'2026-04-06 22:21:37.650542',46.071,'A clean slate means a new start or beginning.',12,42.966,12),(164,0,'2026-04-06 22:21:37.651541',50.699,'This phrase comes from the use of chalk and slates in classrooms.',13,46.913,12),(165,0,'2026-04-06 22:21:37.652540',55.947,'A teacher could start a new lesson with a clean slate.',14,51.34,12),(166,0,'2026-04-06 22:21:37.657536',57.51,'And that\'s English in a minute.',15,55.968,12),(167,0,'2026-04-06 22:22:00.992511',5.532,'Welcome to English in a minute.',0,4.03,13),(168,0,'2026-04-06 22:22:00.993508',8.656,'A swing moves back and forth.',1,6.253,13),(169,0,'2026-04-06 22:22:00.994506',13.521,'But what does it mean if something is in full swing?',2,9.396,13),(170,0,'2026-04-06 22:22:00.996180',19.809,'So are you feeling excited now that the holidays are in full swing?',3,15.364,13),(171,0,'2026-04-06 22:22:00.997099',20.91,'No.',4,20.59,13),(172,0,'2026-04-06 22:22:00.999094',22.973,'I\'m really stressed.',5,20.97,13),(173,0,'2026-04-06 22:22:01.001089',25.335,'I\'m always the one planning everything.',6,23.433,13),(174,0,'2026-04-06 22:22:01.002169',29.16,'The food, the shopping, the decorations.',7,25.696,13),(175,0,'2026-04-06 22:22:01.002680',33.781,'It sounds like your holiday stress levels are in full swing too.',8,29.596,13),(176,0,'2026-04-06 22:22:01.003677',36.184,'Try some deep breathing.',9,34.202,13),(177,0,'2026-04-06 22:22:01.004674',37.666,'Good idea.',10,37.126,13),(178,0,'2026-04-06 22:22:01.005670',42.553,'Relax.',11,41.972,13),(179,0,'2026-04-06 22:22:01.007661',57.612,'When a time of year or activity is in full swing, it is at its highest level of activity and no longer at the beginning stages.',12,46.518,13),(180,0,'2026-04-06 22:22:24.742062',5.711,'Welcome to English in a minute.',0,4.148,14),(181,0,'2026-04-06 22:22:24.743059',11.48,'If something is up for grabs, does that mean you have to reach up to get it?',1,6.472,14),(182,0,'2026-04-06 22:22:24.744057',16.007,'Hey, are you coming to game night at the library?',2,13.483,14),(183,0,'2026-04-06 22:22:24.746069',17.79,'I don\'t know.',3,16.027,14),(184,0,'2026-04-06 22:22:24.747049',21.216,'It says they have prizes up for grabs.',4,17.81,14),(185,0,'2026-04-06 22:22:24.748046',21.637,'Prizes?',5,21.236,14),(186,0,'2026-04-06 22:22:24.749043',22.438,'What prizes?',6,21.917,14),(187,0,'2026-04-06 22:22:24.750042',23.419,'I love prizes.',7,22.678,14),(188,0,'2026-04-06 22:22:24.752036',28.688,'It just says here, five prizes up for grabs, so come ready to play.',8,23.86,14),(189,0,'2026-04-06 22:22:24.752869',31.152,'Maybe you\'ll win one.',9,29.61,14),(190,0,'2026-04-06 22:22:24.753862',33.857,'One, maybe I\'ll win five.',10,31.334,14),(191,0,'2026-04-06 22:22:24.754863',37.402,'Confidence helps, I guess.',11,34.779,14),(192,0,'2026-04-06 22:22:24.756854',44.572,'When something is up for grabs, it\'s available to any person who wants it.',12,39.285,14),(193,0,'2026-04-06 22:22:24.757365',49.599,'And if a prize is up for grabs, a lot of people will want it.',13,45.253,14),(194,0,'2026-04-06 22:22:24.758361',55.948,'So Anna might need more than confidence to win.',14,50.641,14),(195,0,'2026-04-06 22:22:24.760357',57.51,'And that\'s English in a minute.',15,55.968,14),(196,0,'2026-04-06 22:22:47.210820',5.539,'Welcome to English in a minute.',0,3.997,15),(197,0,'2026-04-06 22:22:47.215805',13.329,'If you are on a ship and it starts to sink, it would be a good idea to get off quickly.',1,6.2,15),(198,0,'2026-04-06 22:22:47.218821',16.754,'So, is that what jump ship means?',2,14.13,15),(199,0,'2026-04-06 22:22:47.219819',24.324,'Andrew, those stocks I told you to buy are a bit down, but don\'t worry.',3,18.296,15),(200,0,'2026-04-06 22:22:47.220818',28.469,'I know, and I\'m taking my money out of those stocks.',4,24.344,15),(201,0,'2026-04-06 22:22:47.220818',31.113,'Now is not the time to jump ship.',5,29.371,15),(202,0,'2026-04-06 22:22:47.221814',33.396,'Just be patient.',6,32.054,15),(203,0,'2026-04-06 22:22:47.222811',34.757,'The price will go up.',7,33.815,15),(204,0,'2026-04-06 22:22:47.223808',42.11,'I am a patient person, but not when it comes to my money.',8,35.358,15),(205,0,'2026-04-06 22:22:47.225805',49.803,'When we jump ship, we leave something we think is failing, like a project plan or a group.',9,42.13,15),(206,0,'2026-04-06 22:22:47.226801',57.797,'Sometimes we do this to join something better, but other times we just don\'t want to be on that ship.',10,50.785,15);
