s://res.cloudinary.com/dabb0yavq/video/upload/v1775454310/vocabulary_audio/vocab_2633_Casualties.mp3','B2','/ˈkæʒ.ju.əl.tiz/','Casualties',NULL,_binary '\0'),(2636,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454314/vocabulary_audio/vocab_2636_Precaution.mp3','B2','/prɪˈkɔː.ʃən/','Precaution',NULL,_binary '\0'),(2637,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454315/vocabulary_audio/vocab_2637_Magnitude.mp3','C1','/ˈmæɡ.nɪ.tʃuːd/','Magnitude',NULL,_binary '\0'),(2638,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454316/vocabulary_audio/vocab_2638_Debris.mp3','C1','/ˈdeb.riː/','Debris',NULL,_binary '\0'),(2639,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454318/vocabulary_audio/vocab_2639_Visibility.mp3','B2','/ˌvɪz.əˈbɪl.ə.ti/','Visibility',NULL,_binary '\0'),(2640,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454319/vocabulary_audio/vocab_2640_Flash.mp3','B1','/flæʃ/','Flash',NULL,_binary '\0'),(2642,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454321/vocabulary_audio/vocab_2642_Protocol.mp3','C1','/ˈprəʊ.tə.kɒl/','Protocol',NULL,_binary '\0'),(2643,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454323/vocabulary_audio/vocab_2643_Representative.mp3','B2','/ˌrep.rɪˈzen.tə.tɪv/','Representative',NULL,_binary '\0'),(2645,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454325/vocabulary_audio/vocab_2645_Citizen.mp3','A2','/ˈsɪt.ɪ.zən/','Citizen',NULL,_binary '\0'),(2646,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454327/vocabulary_audio/vocab_2646_Legalize.mp3','C1','/ˈliː.ɡəl.aɪz/','Legalize',NULL,_binary '\0'),(2647,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454328/vocabulary_audio/vocab_2647_Grant.mp3','B2','/ɡrɑːnt/','Grant',NULL,_binary '\0'),(2648,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454329/vocabulary_audio/vocab_2648_Document.mp3','A2','/ˈdɒk.jə.mənt/','Document',NULL,_binary '\0'),(2650,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454331/vocabulary_audio/vocab_2650_Request.mp3','A2','/rɪˈkwest/','Request',NULL,_binary '\0'),(2651,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454332/vocabulary_audio/vocab_2651_Liaison.mp3','C1','/liˈeɪ.zɒn/','Liaison',NULL,_binary '\0'),(2653,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454335/vocabulary_audio/vocab_2653_Appoint.mp3','B2','/əˈpɔɪnt/','Appoint',NULL,_binary '\0'),(2654,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454336/vocabulary_audio/vocab_2654_Immunity.mp3','C1','/ɪˈmjuː.nə.ti/','Immunity',NULL,_binary '\0'),(2656,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454338/vocabulary_audio/vocab_2656_Form.mp3','A1','/fɔːm/','Form',NULL,_binary '\0'),(2657,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454339/vocabulary_audio/vocab_2657_Scheme.mp3','B2','/skiːm/','Scheme',NULL,_binary '\0'),(2658,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454341/vocabulary_audio/vocab_2658_Distract.mp3','B2','/dɪˈstrækt/','Distract',NULL,_binary '\0'),(2661,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454344/vocabulary_audio/vocab_2661_Manipulate.mp3','C1','/məˈnɪp.jə.leɪt/','Manipulate',NULL,_binary '\0'),(2662,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454345/vocabulary_audio/vocab_2662_Counterfeit.mp3','C1','/ˈkaʊn.tə.fɪt/','Counterfeit',NULL,_binary '\0'),(2663,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454346/vocabulary_audio/vocab_2663_Target.mp3','A2','/ˈtɑː.ɡɪt/','Target',NULL,_binary '\0'),(2664,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454347/vocabulary_audio/vocab_2664_Trap.mp3','B1','/træp/','Trap',NULL,_binary '\0'),(2665,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454349/vocabulary_audio/vocab_2665_Suspicious.mp3','B2','/səˈspɪʃ.əs/','Suspicious',NULL,_binary '\0'),(2666,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454350/vocabulary_audio/vocab_2666_Fraud.mp3','C1','/frɔːd/','Fraud',NULL,_binary '\0'),(2667,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454352/vocabulary_audio/vocab_2667_Skimming.mp3','C2','/ˈskɪm.ɪŋ/','Skimming',NULL,_binary '\0'),(2668,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454353/vocabulary_audio/vocab_2668_Bait.mp3','C1','/beɪt/','Bait',NULL,_binary '\0'),(2670,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454355/vocabulary_audio/vocab_2670_Claim.mp3','B1','/kleɪm/','Claim',NULL,_binary '\0'),(2671,'https://res.cloudinary.com/dabb0yavq/video/upload/v1775454356/vocabulary_audio/vocab_2671_Lure.mp3','C2','/lʊər/','Lure',NULL,_binary '\0');
