  `vn_definition` varchar(255) DEFAULT NULL,
  `vn_example` varchar(255) DEFAULT NULL,
  `vn_word` varchar(255) DEFAULT NULL,
  `vocabulary_id` int NOT NULL,
  `deleted_at` datetime(6) DEFAULT NULL,
  `is_deleted` bit(1) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `FK349lj4xg33cg44tllpgbvlhen` (`vocabulary_id`),
  CONSTRAINT `FK349lj4xg33cg44tllpgbvlhen` FOREIGN KEY (`vocabulary_id`) REFERENCES `vocabulary` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3839 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
