INSERT INTO `vocabulary_meaning` VALUES (1,'A common greeting used when meeting someone','Hello! How are you doing today?','NOUN','Lời chào phổ biến khi gặp ai đó','Xin chào! Hôm nay bạn có khỏe không?','xin chào',1,NULL,_binary '\0'),(2,'A polite greeting said in the morning','Good morning! Did you sleep well?','NOUN','Lời chào lịch sự vào buổi sáng','Chào buổi sáng! Bạn có ngủ ngon không?','chào buổi sáng',2,NULL,_binary '\0'),(3,'A farewell said when someone is going to sleep','Good night, see you in the morning.','NOUN','Lời tạm biệt khi ai đó đi ngủ','Chúc ngủ ngon, hẹn gặp lại buổi sáng.','chúc ngủ ngon',3,NULL,_binary '\0'),(4,'A farewell expression','Goodbye! Take care of yourself.','NOUN','Lời tạm biệt','Tạm biệt! Hãy chăm sóc bản thân nhé.','tạm biệt',4,NULL,_binary '\0'),(5,'An informal farewell meaning we will meet again','I have to go now, see you later!','VERB','Lời tạm biệt thân mật có nghĩa sẽ gặp lại','Tôi phải đi rồi, hẹn gặp lại nhé!','hẹn gặp lại',5,NULL,_binary '\0'),(6,'A common greeting to ask about someone\'s wellbeing','How are you? I haven\'t seen you in ages!','VERB','Câu chào hỏi thông thường về tình trạng sức khỏe','Bạn có khỏe không? Tôi không gặp bạn đã lâu rồi!','bạn có khỏe không',6,NULL,_binary '\0'),(7,'A polite expression when meeting someone for the first time','Nice to meet you, my name is Tom.','ADJECTIVE','Lời nói lịch sự khi gặp ai đó lần đầu','Rất vui được gặp bạn, tôi tên là Tom.','rất vui được gặp bạn',7,NULL,_binary '\0'),(8,'To greet someone arriving somewhere','Welcome to our city! Enjoy your stay.','VERB','Chào đón ai đó khi họ đến','Chào mừng đến thành phố của chúng tôi! Chúc bạn có kỳ ở tốt lành.','chào mừng',8,NULL,_binary '\0'),(9,'A polite greeting used in the evening','Good evening, sir. Your table is ready.','NOUN','Lời chào lịch sự vào buổi tối','Chào buổi tối thưa ông. Bàn của ông đã sẵn sàng.','chào buổi tối',9,NULL,_binary '\0'),(10,'A farewell expression wishing someone well','Take care on your trip!','VERB','Lời tạm biệt chúc ai đó bình an','Giữ gìn sức khỏe trong chuyến đi nhé!','giữ gìn sức khỏe',10,NULL,_binary '\0'),(11,'An informal greeting','Hi there! What are you up to today?','NOUN','Lời chào thân mật','Chào bạn! Hôm nay bạn đang làm gì vậy?','chào',11,NULL,_binary '\0'),(12,'An informal farewell','Bye! Talk to you later.','NOUN','Lời tạm biệt thân mật','Tạm biệt! Nói chuyện với bạn sau nhé.','Tạm biệt',12,NULL,_binary '\0'),(13,'A word by which a person is known','My name is Linh, nice to meet you.','NOUN','Từ được dùng để gọi một người','Tên tôi là Linh, rất vui được gặp bạn.','tên',13,NULL,_binary '\0'),(14,'The length of time a person has lived','What is your age? I am twenty-five.','NOUN','Khoảng thời gian một người đã sống','Bạn bao nhiêu tuổi? Tôi hai mươi lăm tuổi.','tuổi',14,NULL,_binary '\0'),(15,'The status of belonging to a particular nation','Her nationality is Vietnamese.','NOUN','Trạng thái thuộc về một quốc gia cụ thể','Quốc tịch của cô ấy là Việt Nam.','quốc tịch',15,NULL,_binary '\0'),(16,'A person\'s job or profession','What is your occupation? I am a teacher.','NOUN','Công việc hoặc nghề nghiệp của một người','Nghề nghiệp của bạn là gì? Tôi là giáo viên.','nghề nghiệp',16,NULL,_binary '\0'),(17,'An activity done regularly for pleasure','My hobby is reading books and cooking.','NOUN','Hoạt động thường xuyên làm vì niềm vui','Sở thích của tôi là đọc sách và nấu ăn.','sở thích',17,NULL,_binary '\0'),(19,'A short description giving the main facts about someone','She created a detailed profile on the website.','NOUN','Mô tả ngắn đưa ra các thông tin chính về ai đó','Cô ấy đã tạo một hồ sơ chi tiết trên trang web.','hồ sơ',19,NULL,_binary '\0'),(20,'To make your home in a particular place','I live in Ho Chi Minh City with my family.','VERB','Cư trú tại một nơi cụ thể','Tôi sống ở thành phố Hồ Chí Minh với gia đình.','sống/ở',20,NULL,_binary '\0'),(21,'To do a job that you are paid for','I work at a hospital as a nurse.','VERB','Làm công việc được trả lương','Tôi làm việc tại bệnh viện với vai trò y tá.','làm việc',21,NULL,_binary '\0'),(22,'To give time and attention to learning','She studies English every evening.','VERB','Dành thời gian và sự chú ý để học','Cô ấy học tiếng Anh mỗi buổi tối.','học tập',22,NULL,_binary '\0'),(23,'To have been born in a particular place','Where do you come from? I come from Hanoi.','VERB','Sinh ra ở một nơi cụ thể','Bạn đến từ đâu? Tôi đến từ Hà Nội.','đến từ',23,NULL,_binary '\0'),(24,'Not in a romantic relationship','He is single and looking for a partner.','ADJECTIVE','Không có mối quan hệ tình cảm','Anh ấy đang độc thân và tìm kiếm bạn đời.','độc thân',24,NULL,_binary '\0'),(25,'A group of people related to each other','My family has five members.','NOUN','Nhóm người có quan hệ họ hàng với nhau','Gia đình tôi có năm thành viên.','gia đình',25,NULL,_binary '\0'),(26,'A female parent','My mother is a wonderful cook.','NOUN','Cha mẹ là nữ','Mẹ tôi nấu ăn rất ngon.','mẹ',26,NULL,_binary '\0'),(27,'A male parent','My father works as an engineer.','NOUN','Cha mẹ là nam','Cha tôi làm kỹ sư.','cha',27,NULL,_binary '\0'),(28,'A girl or woman who has the same parents as another','I have one older sister and one younger brother.','NOUN','Người con gái có cùng cha mẹ với người khác','Tôi có một chị gái và một em trai.','chị/em gái',28,NULL,_binary '\0'),(29,'A boy or man who has the same parents as another','My brother plays football every weekend.','NOUN','Người con trai có cùng cha mẹ với người khác','Anh trai tôi chơi bóng đá mỗi cuối tuần.','anh/em trai',29,NULL,_binary '\0'),(30,'The mother of one\'s parent','My grandmother tells the best stories.','NOUN','Mẹ của cha hoặc mẹ','Bà tôi kể những câu chuyện hay nhất.','bà',30,NULL,_binary '\0'),(31,'The father of one\'s parent','My grandfather is ninety years old.','NOUN','Cha của cha hoặc mẹ','Ông tôi chín mươi tuổi.','ông',31,NULL,_binary '\0'),(32,'The brother of one\'s parent','My uncle lives in the United States.','NOUN','Anh hoặc em trai của cha/mẹ','Chú tôi sống ở Mỹ.','chú/cậu/bác',32,NULL,_binary '\0'),(33,'The sister of one\'s parent','My aunt bakes delicious cakes.','NOUN','Chị hoặc em gái của cha/mẹ','Dì tôi làm bánh rất ngon.','dì/cô/bác',33,NULL,_binary '\0'),(34,'A child of one\'s uncle or aunt','I have ten cousins from my father\'s side.','NOUN','Con của chú, cô, bác, dì, cậu','Tôi có mười anh chị em họ bên phía cha.','anh/chị/em họ',34,NULL,_binary '\0'),(35,'A married man in relation to his spouse','Her husband cooks dinner every night.','NOUN','Người đàn ông đã kết hôn','Chồng cô ấy nấu bữa tối mỗi ngày.','chồng',35,NULL,_binary '\0'),(36,'A married woman in relation to her spouse','His wife is a doctor at the local hospital.','NOUN','Người phụ nữ đã kết hôn','Vợ anh ấy là bác sĩ tại bệnh viện địa phương.','vợ',36,NULL,_binary '\0'),(37,'A young person below the age of puberty','They have three children, two girls and a boy.','NOUN','Người trẻ dưới tuổi dậy thì','Họ có ba đứa con, hai bé gái và một bé trai.','đứa trẻ/con cái',37,NULL,_binary '\0'),(38,'Used to ask for information about something','What time does the meeting start?','NOUN','Dùng để hỏi về điều gì đó','Cuộc họp bắt đầu lúc mấy giờ?','cái gì',38,NULL,_binary '\0'),(39,'Used to ask about a place or location','Where is the nearest bus stop?','ADVERB','Dùng để hỏi về nơi chốn hay địa điểm','Trạm xe buýt gần nhất ở đâu?','ở đâu',39,NULL,_binary '\0'),(40,'Used to ask about time','When does the train leave?','ADVERB','Dùng để hỏi về thời gian','Tàu khởi hành khi nào?','khi nào',40,NULL,_binary '\0'),(41,'Used to ask about a person','Who is your English teacher?','NOUN','Dùng để hỏi về người nào đó','Ai là giáo viên tiếng Anh của bạn?','ai',41,NULL,_binary '\0'),(42,'Used to ask the reason or purpose of something','Why are you learning English?','ADVERB','Dùng để hỏi lý do hay mục đích','Tại sao bạn học tiếng Anh?','tại sao',42,NULL,_binary '\0'),(43,'Used to ask about manner or condition','How do I get to the museum from here?','ADVERB','Dùng để hỏi về cách thức hay tình trạng','Làm thế nào để đến bảo tàng từ đây?','như thế nào',43,NULL,_binary '\0'),(44,'To give an answer or response','Please reply to my message as soon as possible.','VERB','Đưa ra câu trả lời hay phản hồi','Vui lòng trả lời tin nhắn của tôi sớm nhất có thể.','trả lời',44,NULL,_binary '\0'),(45,'To put a question to someone','Don\'t be afraid to ask if you need help.','VERB','Đặt câu hỏi cho ai đó','Đừng ngại hỏi nếu bạn cần giúp đỡ.','hỏi',45,NULL,_binary '\0'),(46,'A reaction to a question or problem','Her answer to the question was very detailed.','NOUN','Phản ứng trước một câu hỏi hoặc vấn đề','Câu trả lời của cô ấy cho câu hỏi đó rất chi tiết.','câu trả lời',46,NULL,_binary '\0'),(47,'To say or do something again','Could you repeat that? I didn\'t understand.','VERB','Nói hoặc làm lại điều gì đó','Bạn có thể nhắc lại không? Tôi không hiểu.','nhắc lại',47,NULL,_binary '\0'),(48,'To make a statement less confused and more clearly comprehensible','Can you clarify what you mean by that?','VERB','Làm cho câu nói ít mơ hồ và dễ hiểu hơn','Bạn có thể làm rõ ý bạn muốn nói không?','làm rõ',48,NULL,_binary '\0'),(49,'To perceive the intended meaning of something','Do you understand the instructions?','VERB','Nhận ra ý nghĩa dự định của điều gì đó','Bạn có hiểu hướng dẫn không?','hiểu',49,NULL,_binary '\0'),(50,'To make something clear by describing it in more detail','Could you explain that rule again please?','VERB','Làm rõ điều gì bằng cách mô tả chi tiết hơn','Bạn có thể giải thích lại quy tắc đó không?','giải thích',50,NULL,_binary '\0'),(51,'Used to add politeness to a request','Please pass me the salt.','ADVERB','Dùng để thêm lịch sự vào yêu cầu','Làm ơn đưa cho tôi lọ muối.','làm ơn/xin vui lòng',51,NULL,_binary '\0'),(52,'A polite expression of gratitude','Thank you for helping me with my bags.','NOUN','Lời bày tỏ sự biết ơn lịch sự','Cảm ơn bạn đã giúp tôi mang túi.','cảm ơn bạn',52,NULL,_binary '\0'),(53,'A polite response to being thanked','You\'re welcome, it was no trouble at all.','ADJECTIVE','Câu trả lời lịch sự khi được cảm ơn','Không có gì, không phiền chút nào.','không có gì',53,NULL,_binary '\0'),(54,'Used to politely get someone\'s attention','Excuse me, do you know where the toilet is?','VERB','Dùng để thu hút sự chú ý của ai đó một cách lịch sự','Xin lỗi, bạn có biết nhà vệ sinh ở đâu không?','xin lỗi/xin phép',54,NULL,_binary '\0'),(55,'An expression of apology or regret','I\'m sorry for being late to the meeting.','ADJECTIVE','Lời xin lỗi hoặc hối tiếc','Tôi xin lỗi vì đã đến trễ buổi họp.','tôi xin lỗi',55,NULL,_binary '\0'),(56,'A feeling of happy satisfaction','It was a pleasure to meet you today.','NOUN','Cảm giác hài lòng vui vẻ','Thật vui khi được gặp bạn hôm nay.','niềm vui',56,NULL,_binary '\0'),(57,'Friendly, generous and considerate','It was very kind of you to help me.','ADJECTIVE','Thân thiện, hào phóng và quan tâm','Thật tốt bụng khi bạn giúp đỡ tôi.','tốt bụng',57,NULL,_binary '\0'),(58,'Having or showing good manners','It is polite to hold the door for others.','ADJECTIVE','Có hoặc thể hiện cách cư xử tốt','Giữ cửa cho người khác là hành động lịch sự.','lịch sự',58,NULL,_binary '\0'),(59,'Used to politely ask someone to repeat something','Pardon me, could you say that again?','VERB','Dùng để lịch sự yêu cầu ai nhắc lại','Tha lỗi, bạn có thể nói lại được không?','tha lỗi cho tôi',59,NULL,_binary '\0'),(60,'To object to something or feel disturbed by it','Do you mind if I sit here?','VERB','Phản đối điều gì hoặc cảm thấy khó chịu về nó','Bạn có phiền nếu tôi ngồi đây không?','phiền/bận tâm',60,NULL,_binary '\0'),(61,'Ready or eager to do something','I am willing to help whenever you need me.','ADJECTIVE','Sẵn sàng hoặc háo hức làm điều gì đó','Tôi sẵn lòng giúp đỡ bất cứ lúc nào bạn cần.','sẵn lòng',61,NULL,_binary '\0'),(62,'The state of the atmosphere in terms of wind, rain, temperature','What is the weather like today?','NOUN','Trạng thái của khí quyển về gió, mưa, nhiệt độ','Thời tiết hôm nay như thế nào?','thời tiết',62,NULL,_binary '\0'),(63,'Bright with sunlight','It is a lovely sunny day today.','ADJECTIVE','Sáng với ánh nắng mặt trời','Hôm nay trời nắng đẹp thật.','có nắng',63,NULL,_binary '\0'),(64,'Having a lot of rain','Take an umbrella, it looks rainy outside.','ADJECTIVE','Có nhiều mưa','Mang dù đi, bên ngoài trông như sắp mưa.','có mưa',64,NULL,_binary '\0'),(65,'Having a high temperature','It is very hot and humid today.','ADJECTIVE','Có nhiệt độ cao','Hôm nay rất nóng và ẩm.','nóng',65,NULL,_binary '\0'),(66,'Of or at a low temperature','It is too cold to go out without a coat.','ADJECTIVE','Ở nhiệt độ thấp','Trời lạnh quá để ra ngoài không mặc áo khoác.','lạnh',66,NULL,_binary '\0'),(67,'Covered with clouds','The sky is cloudy but it hasn\'t rained yet.','ADJECTIVE','Phủ đầy mây','Bầu trời nhiều mây nhưng vẫn chưa mưa.','nhiều mây',67,NULL,_binary '\0'),(68,'To talk in a friendly and informal way','I chatted with my neighbour for an hour.','VERB','Nói chuyện theo cách thân thiện và thoải mái','Tôi trò chuyện với hàng xóm trong một tiếng đồng hồ.','trò chuyện',68,NULL,_binary '\0'),(69,'An informal exchange of ideas by talking','We had an interesting conversation about travel.','NOUN','Trao đổi không chính thức về ý kiến thông qua nói chuyện','Chúng tôi đã có một cuộc trò chuyện thú vị về du lịch.','cuộc trò chuyện',69,NULL,_binary '\0'),(70,'A subject that is discussed','The main topic of our conversation was food.','NOUN','Chủ đề được thảo luận','Chủ đề chính của cuộc trò chuyện là về đồ ăn.','chủ đề',70,NULL,_binary '\0'),(71,'The natural movement of air outdoors','There is a strong wind blowing from the north.','NOUN','Sự chuyển động tự nhiên của không khí ngoài trời','Có gió mạnh thổi từ phía bắc.','gió',71,NULL,_binary '\0'),(72,'The degree of heat present in an area','The temperature dropped to five degrees last night.','NOUN','Mức độ nhiệt hiện diện trong một khu vực','Nhiệt độ giảm xuống còn năm độ tối qua.','nhiệt độ',72,NULL,_binary '\0'),(73,'An arithmetical value used for counting','What is your phone number?','NOUN','Giá trị số học dùng để đếm','Số điện thoại của bạn là gì?','số',73,NULL,_binary '\0'),(74,'To determine the total number of something','Can you count from one to twenty in English?','VERB','Xác định tổng số của điều gì đó','Bạn có thể đếm từ một đến hai mươi bằng tiếng Anh không?','đếm',74,NULL,_binary '\0'),(75,'A group of twelve','I need a dozen eggs for the cake.','NOUN','Nhóm mười hai','Tôi cần một tá trứng để làm bánh.','tá (12 cái)',75,NULL,_binary '\0'),(76,'The number equivalent to ten times ten','There were over a hundred people at the party.','NOUN','Số bằng mười nhân mười','Có hơn một trăm người ở bữa tiệc.','trăm',76,NULL,_binary '\0'),(77,'The number equivalent to one thousand','The concert attracted ten thousand fans.','NOUN','Số tương đương với một nghìn','Buổi hòa nhạc thu hút mười nghìn khán giả.','nghìn',77,NULL,_binary '\0'),(78,'One thousand times one thousand','This app has over a million downloads.','NOUN','Một nghìn nhân một nghìn','Ứng dụng này có hơn một triệu lượt tải.','triệu',78,NULL,_binary '\0'),(79,'One of two equal parts of something','I drank half a bottle of water after running.','NOUN','Một trong hai phần bằng nhau của điều gì đó','Tôi uống nửa chai nước sau khi chạy bộ.','một nửa',79,NULL,_binary '\0'),(80,'One of four equal parts of something','Only a quarter of the students passed the test.','NOUN','Một trong bốn phần bằng nhau của điều gì đó','Chỉ một phần tư số học sinh vượt qua bài kiểm tra.','một phần tư',80,NULL,_binary '\0'),(81,'Consisting of two equal parts','The price has doubled since last year.','ADJECTIVE','Bao gồm hai phần bằng nhau','Giá đã tăng gấp đôi so với năm ngoái.','gấp đôi',81,NULL,_binary '\0'),(83,'As much or as many as required','Do you have enough money for the taxi?','ADJECTIVE','Nhiều hoặc số lượng như yêu cầu','Bạn có đủ tiền cho xe taxi không?','đủ',83,NULL,_binary '\0'),(84,'The indefinite continued progress of events','What time does the supermarket close?','NOUN','Sự tiến triển liên tục không xác định của các sự kiện','Siêu thị đóng cửa lúc mấy giờ?','thời gian',84,NULL,_binary '\0'),(85,'The numbered day in a month','What is today\'s date? It is the fifteenth.','NOUN','Ngày được đánh số trong một tháng','Hôm nay là ngày bao nhiêu? Là ngày mười lăm.','ngày tháng',85,NULL,_binary '\0'),(86,'A period of seven days','I have a dentist appointment next week.','NOUN','Khoảng thời gian bảy ngày','Tôi có lịch hẹn với nha sĩ vào tuần tới.','tuần',86,NULL,_binary '\0'),(87,'One of twelve divisions of a year','My birthday is in the month of July.','NOUN','Một trong mười hai phần của một năm','Sinh nhật của tôi vào tháng Bảy.','tháng',87,NULL,_binary '\0'),(88,'A period of twelve months','We moved to this city three years ago.','NOUN','Khoảng thời gian mười hai tháng','Chúng tôi chuyển đến thành phố này ba năm trước.','năm',88,NULL,_binary '\0'),(89,'One of the four divisions of the year','Which season do you prefer, summer or winter?','NOUN','Một trong bốn phần của năm','Bạn thích mùa nào hơn, hè hay đông?','mùa',89,NULL,_binary '\0'),(90,'The day before today','I watched a great movie yesterday.','ADVERB','Ngày trước ngày hôm nay','Tôi đã xem một bộ phim hay vào hôm qua.','hôm qua',90,NULL,_binary '\0'),(91,'On this present day','Today is a public holiday, so the office is closed.','ADVERB','Vào ngày hôm nay','Hôm nay là ngày nghỉ lễ nên văn phòng đóng cửa.','hôm nay',91,NULL,_binary '\0'),(92,'The day after today','I have an important exam tomorrow morning.','ADVERB','Ngày sau ngày hôm nay','Tôi có một bài thi quan trọng sáng mai.','ngày mai',92,NULL,_binary '\0'),(93,'The latest time by which something must be completed','The deadline for this project is Friday afternoon.','NOUN','Thời gian muộn nhất để hoàn thành điều gì đó','Hạn chót của dự án này là chiều thứ Sáu.','hạn chót',93,NULL,_binary '\0'),(94,'At once; without delay','Please respond to the email immediately.','ADVERB','Ngay lập tức; không chậm trễ','Vui lòng trả lời email ngay lập tức.','ngay lập tức',94,NULL,_binary '\0'),(95,'At all times; on all occasions','She always arrives early to class.','ADVERB','Mọi lúc; trong mọi dịp','Cô ấy luôn đến lớp sớm.','luôn luôn',95,NULL,_binary '\0'),(96,'To stop sleeping and become conscious','I wake up at six every morning.','VERB','Ngừng ngủ và trở nên tỉnh táo','Tôi thức dậy lúc sáu giờ mỗi buổi sáng.','thức dậy',96,NULL,_binary '\0'),(97,'The first meal of the day','I always have breakfast before going to work.','NOUN','Bữa ăn đầu tiên trong ngày','Tôi luôn ăn sáng trước khi đi làm.','bữa sáng',97,NULL,_binary '\0'),(98,'A device that sprays water for bathing','I take a cold shower every morning to wake up.','NOUN','Thiết bị phun nước để tắm','Tôi tắm nước lạnh mỗi sáng để tỉnh ngủ.','tắm vòi hoa sen',98,NULL,_binary '\0'),(99,'To clean one\'s teeth with a toothbrush','You should brush your teeth twice a day.','VERB','Làm sạch răng bằng bàn chải đánh răng','Bạn nên đánh răng hai lần mỗi ngày.','đánh răng',99,NULL,_binary '\0'),(100,'To put on clothes','I get dressed quickly because I am always late.','VERB','Mặc quần áo vào','Tôi mặc quần áo nhanh vì tôi thường xuyên trễ giờ.','mặc quần áo',100,NULL,_binary '\0'),(101,'To tidy and arrange hair using a comb','She combs her hair every morning before school.','VERB','Chỉnh và sắp xếp tóc bằng lược','Cô ấy chải tóc mỗi sáng trước khi đi học.','chải tóc',101,NULL,_binary '\0'),(102,'A clock that can be set to ring at a specific time','I set my alarm clock for five thirty AM.','NOUN','Đồng hồ có thể đặt để reo vào một giờ cụ thể','Tôi đặt đồng hồ báo thức lúc năm giờ rưỡi sáng.','đồng hồ báo thức',102,NULL,_binary '\0'),(103,'To extend one\'s limbs to their full length','I stretch for ten minutes every morning.','VERB','Duỗi tay chân ra hết mức','Tôi giãn cơ mười phút mỗi buổi sáng.','căng cơ/giãn người',103,NULL,_binary '\0'),(104,'The process of taking air in and out of the lungs','Deep breathing helps reduce morning stress.','NOUN','Quá trình hít không khí vào và thở ra khỏi phổi','Hít thở sâu giúp giảm căng thẳng buổi sáng.','hít thở',104,NULL,_binary '\0'),(105,'A sequence of actions regularly followed','Having a morning routine improves productivity.','NOUN','Chuỗi hành động được thực hiện thường xuyên','Có thói quen buổi sáng giúp nâng cao năng suất.','thói quen hằng ngày',105,NULL,_binary '\0'),(106,'Preparing ingredients or meals in advance','I do meal prep on Sundays for the whole week.','NOUN','Chuẩn bị nguyên liệu hoặc bữa ăn trước','Tôi chuẩn bị bữa ăn vào Chủ nhật cho cả tuần.','chuẩn bị bữa ăn',106,NULL,_binary '\0'),(107,'A drink made from roasted coffee beans','A cup of coffee is my first thing every morning.','NOUN','Đồ uống làm từ hạt cà phê rang','Một tách cà phê là điều đầu tiên tôi làm mỗi sáng.','cà phê',107,NULL,_binary '\0'),(108,'A room or building where people work','She works in a big office in the city centre.','NOUN','Phòng hoặc tòa nhà nơi người ta làm việc','Cô ấy làm việc ở một văn phòng lớn ở trung tâm thành phố.','văn phòng',108,NULL,_binary '\0'),(109,'An institution where children are educated','My children go to a public school nearby.','NOUN','Cơ sở giáo dục trẻ em','Con tôi học ở một trường công gần nhà.','trường học',109,NULL,_binary '\0'),(110,'A person who teaches in a school','Our English teacher is very funny and helpful.','NOUN','Người dạy học ở trường','Giáo viên tiếng Anh của chúng tôi rất vui tính và tận tâm.','giáo viên',110,NULL,_binary '\0'),(111,'A person who is studying at a school or university','She is an excellent student and always studies hard.','NOUN','Người đang học tại trường học hoặc đại học','Cô ấy là học sinh xuất sắc và luôn học chăm chỉ.','học sinh/sinh viên',111,NULL,_binary '\0'),(112,'An assembly of people for discussion','We have a team meeting every Monday morning.','NOUN','Cuộc tập hợp mọi người để thảo luận','Chúng tôi có cuộc họp nhóm vào mỗi sáng thứ Hai.','cuộc họp',112,NULL,_binary '\0'),(113,'A section of a company dealing with a specific area','She works in the marketing department.','NOUN','Bộ phận của công ty chuyên về một lĩnh vực cụ thể','Cô ấy làm trong phòng ban marketing.','phòng ban',113,NULL,_binary '\0'),(114,'A person responsible for controlling an organization','The manager praised the team for finishing early.','NOUN','Người chịu trách nhiệm điều hành tổ chức','Quản lý khen nhóm vì hoàn thành sớm.','quản lý',114,NULL,_binary '\0'),(116,'A fixed regular payment for employment','His salary increased after the promotion.','NOUN','Khoản thanh toán cố định thường xuyên cho việc làm','Lương của anh ấy tăng sau khi được thăng chức.','lương',116,NULL,_binary '\0'),(117,'Achieving or producing a significant result','I had a very productive day at the office.','ADJECTIVE','Đạt được hoặc tạo ra kết quả đáng kể','Tôi có một ngày làm việc rất hiệu quả ở văn phòng.','có năng suất',117,NULL,_binary '\0'),(118,'An advancement in rank within an organization','She received a promotion after two years of hard work.','NOUN','Sự thăng tiến trong tổ chức','Cô ấy được thăng chức sau hai năm làm việc chăm chỉ.','thăng chức',118,NULL,_binary '\0'),(119,'A person one works with in the same organization','My colleagues are very supportive and friendly.','NOUN','Người làm cùng trong tổ chức','Đồng nghiệp của tôi rất hỗ trợ và thân thiện.','đồng nghiệp',119,NULL,_binary '\0'),(120,'A house and its occupants regarded as a unit','Each household member is responsible for some chores.','NOUN','Ngôi nhà và các thành viên trong nhà như một đơn vị','Mỗi thành viên trong nhà phụ trách một số việc nhà.','hộ gia đình',120,NULL,_binary '\0'),(121,'To remove dirt from something','I clean the bathroom every Saturday morning.','VERB','Loại bỏ bụi bẩn khỏi thứ gì đó','Tôi dọn nhà vệ sinh vào sáng thứ Bảy.','dọn dẹp/làm sạch',121,NULL,_binary '\0'),(122,'To clean a floor using a brush','Can you sweep the kitchen floor please?','VERB','Làm sạch sàn nhà bằng chổi','Bạn có thể quét sàn bếp giúp tôi không?','quét',122,NULL,_binary '\0'),(123,'To clean plates and utensils after eating','It is your turn to wash the dishes tonight.','VERB','Làm sạch đĩa và dụng cụ sau khi ăn','Đến lượt bạn rửa bát tối nay rồi.','rửa bát',123,NULL,_binary '\0'),(126,'To wipe a floor clean with a wet mop','He mops the floor after sweeping it.','VERB','Lau sàn nhà bằng cây lau ướt','Anh ấy lau sàn sau khi quét xong.','lau sàn nhà',126,NULL,_binary '\0'),(127,'The activity of tending to a garden','My mother loves gardening on the weekend.','NOUN','Hoạt động chăm sóc vườn','Mẹ tôi thích làm vườn vào cuối tuần.','làm vườn',127,NULL,_binary '\0'),(128,'The practice or skill of preparing food','Cooking a healthy meal takes about thirty minutes.','NOUN','Thực hành hoặc kỹ năng chuẩn bị thức ăn','Nấu một bữa ăn lành mạnh mất khoảng ba mươi phút.','nấu ăn',128,NULL,_binary '\0'),(129,'To carry rubbish outside to be collected','Don\'t forget to take out the trash tonight.','VERB','Mang rác ra ngoài để thu gom','Đừng quên đổ rác tối nay nhé.','đổ rác',129,NULL,_binary '\0'),(130,'To put things in their proper places','Please tidy your room before the guests arrive.','VERB','Đặt đồ vào đúng chỗ của chúng','Hãy dọn phòng gọn gàng trước khi khách đến.','dọn dẹp gọn gàng',130,NULL,_binary '\0'),(131,'A machine for washing dishes','Load the dishwasher after dinner, please.','NOUN','Máy dùng để rửa bát','Cho bát đĩa vào máy rửa bát sau bữa tối nhé.','máy rửa bát',131,NULL,_binary '\0'),(132,'Time when one is not working or busy','I spend my leisure time reading and hiking.','NOUN','Thời gian khi không làm việc hay bận rộn','Tôi dành thời gian rảnh để đọc sách và đi bộ đường dài.','thời gian rảnh',132,NULL,_binary '\0'),(133,'To look at written words and understand them','I read at least one book a month.','VERB','Nhìn vào chữ viết và hiểu chúng','Tôi đọc ít nhất một quyển sách mỗi tháng.','đọc',133,NULL,_binary '\0'),(134,'The activity of putting paint on a surface','She took up painting after retirement.','NOUN','Hoạt động phủ sơn lên bề mặt','Cô ấy bắt đầu vẽ tranh sau khi nghỉ hưu.','vẽ tranh',134,NULL,_binary '\0'),(135,'The activity of going for long walks in nature','We went hiking in the mountains last Sunday.','NOUN','Hoạt động đi bộ dài trong thiên nhiên','Chúng tôi đi bộ đường dài trên núi Chủ nhật tuần trước.','đi bộ đường dài',135,NULL,_binary '\0'),(136,'The activity of playing video games','Gaming has become very popular among young people.','NOUN','Hoạt động chơi trò chơi điện tử','Chơi game trở nên rất phổ biến trong giới trẻ.','chơi game',136,NULL,_binary '\0'),(137,'To propel oneself through water','He swims fifty laps every morning.','VERB','Tự đẩy mình qua nước','Anh ấy bơi năm mươi vòng mỗi buổi sáng.','bơi lội',137,NULL,_binary '\0'),(138,'Running at a slow, steady pace','She goes jogging in the park every evening.','NOUN','Chạy ở tốc độ chậm và đều đặn','Cô ấy đi chạy bộ trong công viên mỗi buổi tối.','chạy bộ nhẹ',138,NULL,_binary '\0'),(139,'Vocal or instrumental sounds combined','Listening to music is my favourite way to relax.','NOUN','Âm thanh giọng hát hoặc nhạc cụ kết hợp','Nghe nhạc là cách thư giãn yêu thích của tôi.','âm nhạc',139,NULL,_binary '\0'),(140,'The practice or skill of cooking food','She enrolled in a cookery class last spring.','NOUN','Thực hành hoặc kỹ năng nấu ăn','Cô ấy ghi danh một lớp nấu ăn vào mùa xuân năm ngoái.','nghệ thuật nấu ăn',140,NULL,_binary '\0'),(141,'To make a journey from one place to another','I love to travel and explore new cultures.','VERB','Thực hiện hành trình từ nơi này đến nơi khác','Tôi thích du lịch và khám phá những nền văn hóa mới.','du lịch',141,NULL,_binary '\0'),(142,'The activity of catching fish','My grandfather and I go fishing every summer.','NOUN','Hoạt động bắt cá','Ông tôi và tôi đi câu cá mỗi mùa hè.','câu cá',142,NULL,_binary '\0'),(143,'The state of being free from illness or injury','Good health is more important than wealth.','NOUN','Trạng thái không bị ốm hay chấn thương','Sức khỏe tốt quan trọng hơn sự giàu có.','sức khỏe',143,NULL,_binary '\0'),(144,'The physical structure of a person','Exercise is very important for your body.','NOUN','Cấu trúc thể chất của một người','Tập thể dục rất quan trọng cho cơ thể bạn.','cơ thể',144,NULL,_binary '\0'),(145,'A continuous pain in the head','I have a terrible headache today.','NOUN','Cơn đau liên tục trong đầu','Tôi bị nhức đầu dữ dội hôm nay.','nhức đầu',145,NULL,_binary '\0'),(146,'An abnormally high body temperature','She stayed home because she had a high fever.','NOUN','Nhiệt độ cơ thể bất thường cao','Cô ấy ở nhà vì bị sốt cao.','sốt',146,NULL,_binary '\0'),(147,'A person qualified to practise medicine','I visited the doctor because of my sore throat.','NOUN','Người có bằng cấp hành nghề y','Tôi đến gặp bác sĩ vì đau họng.','bác sĩ',147,NULL,_binary '\0'),(148,'A drug used to treat illness','Take this medicine three times a day after meals.','NOUN','Thuốc dùng để điều trị bệnh','Uống thuốc này ba lần mỗi ngày sau bữa ăn.','thuốc/y học',148,NULL,_binary '\0'),(149,'Physical activity done to stay healthy','Regular exercise helps prevent many diseases.','NOUN','Hoạt động thể chất để giữ sức khỏe','Tập thể dục đều đặn giúp ngăn ngừa nhiều bệnh.','tập thể dục',149,NULL,_binary '\0'),(150,'An institution providing medical treatment','She spent two days in the hospital after the accident.','NOUN','Cơ sở y tế cung cấp điều trị y tế','Cô ấy nằm bệnh viện hai ngày sau vụ tai nạn.','bệnh viện',150,NULL,_binary '\0'),(151,'The condition of being physically healthy','Fitness tracking apps are very popular nowadays.','NOUN','Trạng thái khoẻ mạnh về thể chất','Ứng dụng theo dõi thể lực rất phổ biến ngày nay.','thể dục/thể lực',151,NULL,_binary '\0'),(152,'The kinds of food a person habitually eats','A balanced diet includes fruit, vegetables and protein.','NOUN','Loại thức ăn một người thường xuyên ăn','Chế độ ăn cân bằng bao gồm trái cây, rau và protein.','chế độ ăn',152,NULL,_binary '\0'),(153,'A state of mental or emotional strain','Too much stress can cause serious health problems.','NOUN','Trạng thái căng thẳng tinh thần hoặc cảm xúc','Căng thẳng quá mức có thể gây ra các vấn đề sức khỏe nghiêm trọng.','căng thẳng',153,NULL,_binary '\0'),(154,'To be in a natural state of rest','Adults need at least seven hours of sleep a night.','VERB','Ở trong trạng thái nghỉ ngơi tự nhiên','Người lớn cần ít nhất bảy tiếng ngủ mỗi đêm.','ngủ',154,NULL,_binary '\0'),(155,'A garment for the upper body with a collar and sleeves','He wore a white shirt to the job interview.','NOUN','Quần áo cho phần thân trên có cổ và tay áo','Anh ấy mặc áo sơ mi trắng đến buổi phỏng vấn xin việc.','áo sơ mi',155,NULL,_binary '\0'),(156,'A garment covering the body from the waist to the ankles','These blue trousers match your jacket perfectly.','NOUN','Quần áo che phủ cơ thể từ eo đến mắt cá chân','Chiếc quần dài xanh này rất hợp với áo khoác của bạn.','quần dài',156,NULL,_binary '\0'),(157,'A one-piece garment for women','She wore a red dress to the party.','NOUN','Quần áo một mảnh dành cho phụ nữ','Cô ấy mặc đầm đỏ đến bữa tiệc.','váy đầm',157,NULL,_binary '\0'),(158,'A short coat for the upper body','Don\'t forget your jacket, it is cold outside.','NOUN','Áo khoác ngắn cho phần thân trên','Đừng quên áo khoác, bên ngoài lạnh lắm.','áo khoác',158,NULL,_binary '\0'),(159,'Coverings for the feet','I bought a new pair of running shoes.','NOUN','Vật che phủ bàn chân','Tôi mua một đôi giày chạy bộ mới.','giày',159,NULL,_binary '\0'),(160,'A shaped covering for the head','Wear a hat to protect yourself from the sun.','NOUN','Vật che đầu có hình dáng','Đội mũ để bảo vệ bạn khỏi ánh nắng mặt trời.','mũ',160,NULL,_binary '\0'),(161,'Clothing worn under outer clothes','Always pack enough clean underwear when travelling.','NOUN','Quần áo mặc dưới quần áo ngoài','Luôn mang đủ đồ lót sạch khi đi du lịch.','đồ lót',161,NULL,_binary '\0'),(162,'A garment hanging from the waist','She wore a floral skirt on the summer trip.','NOUN','Quần áo rủ từ thắt lưng','Cô ấy mặc váy hoa trong chuyến đi mùa hè.','váy',162,NULL,_binary '\0'),(163,'A knitted garment worn on the upper body','I wear a thick sweater in winter.','NOUN','Áo đan len mặc ở phần thân trên','Tôi mặc áo len dày vào mùa đông.','áo len',163,NULL,_binary '\0'),(164,'A distinctive clothing for members of the same group','Students are required to wear a uniform every day.','NOUN','Trang phục đặc trưng cho các thành viên của cùng một nhóm','Học sinh bắt buộc phải mặc đồng phục mỗi ngày.','đồng phục',164,NULL,_binary '\0'),(165,'Relaxed and informal clothing','I prefer casual clothes for the weekend.','ADJECTIVE','Quần áo thoải mái và không trang trọng','Tôi thích quần áo bình thường cho cuối tuần.','thường ngày/thoải mái',165,NULL,_binary '\0'),(166,'Suitable for official or important occasions','You should wear formal attire to the business dinner.','ADJECTIVE','Phù hợp cho các dịp chính thức hoặc quan trọng','Bạn nên mặc trang phục trang trọng đến bữa ăn kinh doanh.','trang trọng',166,NULL,_binary '\0'),(167,'A mobile phone with advanced computing ability','I use my smartphone for almost everything.','NOUN','Điện thoại di động có khả năng máy tính tiên tiến','Tôi dùng điện thoại thông minh cho hầu hết mọi thứ.','điện thoại thông minh',167,NULL,_binary '\0'),(168,'A global computer network providing information','I cannot work without an internet connection.','NOUN','Mạng máy tính toàn cầu cung cấp thông tin','Tôi không thể làm việc nếu không có kết nối internet.','mạng internet',168,NULL,_binary '\0'),(169,'A portable personal computer','She uses her laptop to attend online meetings.','NOUN','Máy tính cá nhân di động','Cô ấy dùng laptop để tham gia các cuộc họp trực tuyến.','máy tính xách tay',169,NULL,_binary '\0'),(170,'To copy data from the internet to a device','Can you download that app for me?','VERB','Sao chép dữ liệu từ internet vào thiết bị','Bạn có thể tải ứng dụng đó cho tôi không?','tải xuống',170,NULL,_binary '\0'),(171,'To transfer data to the internet from a device','I need to upload my assignment to the school website.','VERB','Chuyển dữ liệu từ thiết bị lên internet','Tôi cần tải bài tập lên trang web của trường.','tải lên',171,NULL,_binary '\0'),(172,'A secret word used to gain access','Always use a strong password for your accounts.','NOUN','Từ bí mật được dùng để truy cập','Luôn dùng mật khẩu mạnh cho các tài khoản của bạn.','mật khẩu',172,NULL,_binary '\0'),(173,'Programs used by a computer','This software is very easy to use.','NOUN','Chương trình được máy tính sử dụng','Phần mềm này rất dễ dùng.','phần mềm',173,NULL,_binary '\0'),(174,'A program designed for a specific task','I installed a translation application on my phone.','NOUN','Chương trình được thiết kế cho một nhiệm vụ cụ thể','Tôi đã cài một ứng dụng dịch thuật trên điện thoại.','ứng dụng',174,NULL,_binary '\0'),(175,'A device for capturing photographs or videos','The camera on my phone takes great photos.','NOUN','Thiết bị để chụp ảnh hoặc quay video','Máy ảnh trên điện thoại của tôi chụp ảnh rất đẹp.','máy ảnh',175,NULL,_binary '\0'),(176,'To look for information using the internet','Search the web for the nearest pharmacy.','VERB','Tìm kiếm thông tin bằng internet','Tìm kiếm trên mạng nhà thuốc gần nhất.','tìm kiếm',176,NULL,_binary '\0'),(178,'The main meal of the day, eaten in the evening','The whole family eats dinner together every night.','NOUN','Bữa ăn chính trong ngày, ăn vào buổi tối','Cả gia đình ăn tối cùng nhau mỗi tối.','bữa tối',178,NULL,_binary '\0'),(179,'To make less tense or anxious','I usually relax by watching TV after dinner.','VERB','Làm giảm sự căng thẳng hoặc lo lắng','Tôi thường thư giãn bằng cách xem TV sau bữa tối.','thư giãn',179,NULL,_binary '\0'),(180,'The act of washing one\'s body in a bathtub','A warm bath before bed helps me sleep better.','NOUN','Hành động tắm thân mình trong bồn tắm','Tắm bồn nước ấm trước khi ngủ giúp tôi ngủ ngon hơn.','tắm bồn',180,NULL,_binary '\0'),(181,'The usual time one goes to bed','My bedtime is ten thirty every night.','NOUN','Thời gian thường ngày đi ngủ','Giờ đi ngủ của tôi là mười giờ ba mươi mỗi tối.','giờ đi ngủ',181,NULL,_binary '\0'),(182,'A book in which one records daily events','She writes in her diary every night before bed.','NOUN','Cuốn sách ghi lại các sự kiện hàng ngày','Cô ấy viết nhật ký mỗi tối trước khi ngủ.','nhật ký',182,NULL,_binary '\0'),(183,'The act of focusing one\'s mind for relaxation','He practises meditation for twenty minutes before sleep.','NOUN','Hành động tập trung tâm trí để thư giãn','Anh ấy thiền hai mươi phút trước khi ngủ.','thiền',183,NULL,_binary '\0'),(184,'To turn off the lights and prepare for sleep','I turn the lights off at eleven PM every night.','VERB','Tắt đèn và chuẩn bị đi ngủ','Tôi tắt đèn lúc mười một giờ tối mỗi ngày.','tắt đèn',184,NULL,_binary '\0'),(185,'To look back at work or events to evaluate','I review my to-do list every evening.','VERB','Nhìn lại công việc hay sự kiện để đánh giá','Tôi xem lại danh sách việc cần làm mỗi buổi tối.','ôn tập/xem lại',185,NULL,_binary '\0'),(186,'To decide what you are going to do in the future','I plan my schedule for the next day every evening.','VERB','Quyết định những gì bạn sẽ làm trong tương lai','Tôi lên kế hoạch cho ngày hôm sau mỗi buổi tối.','lên kế hoạch',186,NULL,_binary '\0'),(187,'Feeling a need or wish to sleep','I feel sleepy after dinner every day.','ADJECTIVE','Cảm thấy cần hoặc muốn ngủ','Tôi cảm thấy buồn ngủ sau bữa tối mỗi ngày.','buồn ngủ',187,NULL,_binary '\0'),(188,'A series of images and feelings occurring in sleep','I had a strange dream about flying last night.','NOUN','Chuỗi hình ảnh và cảm xúc xảy ra khi ngủ','Tôi đã có một giấc mơ kỳ lạ về việc bay đêm qua.','giấc mơ',188,NULL,_binary '\0'),(191,'A person who serves food in a restaurant','The waiter recommended the grilled fish.','NOUN','Người phục vụ đồ ăn tại nhà hàng','Người phục vụ đề xuất món cá nướng.','người phục vụ',191,NULL,_binary '\0'),(192,'A liquid consumed as a beverage','What would you like to drink with your meal?','NOUN','Chất lỏng được tiêu thụ như đồ uống','Bạn muốn uống gì với bữa ăn?','đồ uống',192,NULL,_binary '\0'),(193,'A small dish served before the main course','I will have the soup as a starter.','NOUN','Món ăn nhỏ phục vụ trước món chính','Tôi sẽ gọi súp làm món khai vị.','món khai vị',193,NULL,_binary '\0'),(194,'The primary and most substantial course of a meal','For the main course, I\'ll have the steak.','NOUN','Món ăn chính và đầy đủ nhất của bữa ăn','Cho món chính, tôi sẽ gọi bít tết.','món chính',194,NULL,_binary '\0'),(195,'A sweet dish served after the main course','I always order ice cream for dessert.','NOUN','Món ngọt phục vụ sau món chính','Tôi luôn gọi kem làm tráng miệng.','tráng miệng',195,NULL,_binary '\0'),(199,'An adverse reaction to a substance','I have a nut allergy, so please check the ingredients.','NOUN','Phản ứng bất lợi với một chất','Tôi bị dị ứng với hạt, vui lòng kiểm tra thành phần.','dị ứng',199,NULL,_binary '\0'),(200,'A person who does not eat any animal products','Do you have a vegan option on the menu?','ADJECTIVE','Người không ăn bất kỳ sản phẩm động vật nào','Thực đơn có tùy chọn thuần chay không?','thuần chay',200,NULL,_binary '\0'),(201,'To prepare food by applying heat','I cook dinner for my family every evening.','VERB','Chuẩn bị thức ăn bằng cách đun nóng','Tôi nấu bữa tối cho gia đình mỗi buổi tối.','nấu ăn',201,NULL,_binary '\0'),(202,'A component of a mixture or dish','Fresh ingredients make the best meals.','NOUN','Thành phần của hỗn hợp hoặc món ăn','Nguyên liệu tươi làm nên những bữa ăn ngon nhất.','nguyên liệu',202,NULL,_binary '\0'),(203,'Instructions for preparing a meal','I followed a new recipe for chocolate cake.','NOUN','Hướng dẫn chuẩn bị bữa ăn','Tôi đã làm theo công thức bánh sô cô la mới.','công thức nấu ăn',203,NULL,_binary '\0'),(204,'To heat a liquid until it bubbles','Boil the water before adding the pasta.','VERB','Đun nóng chất lỏng cho đến khi sôi lên','Đun sôi nước trước khi cho mì vào.','đun sôi',204,NULL,_binary '\0'),(205,'To cook food in hot oil','She fried the chicken until it was golden brown.','VERB','Nấu thức ăn trong dầu nóng','Cô ấy chiên gà cho đến khi vàng giòn.','chiên/rán',205,NULL,_binary '\0'),(206,'To cook food in an oven using dry heat','I bake bread every Sunday morning.','VERB','Nấu thức ăn trong lò nướng bằng nhiệt khô','Tôi nướng bánh mì mỗi sáng Chủ nhật.','nướng lò',206,NULL,_binary '\0'),(207,'A flat metal container for cooking','Heat the pan before adding the oil.','NOUN','Dụng cụ nấu ăn kim loại phẳng','Làm nóng chảo trước khi cho dầu vào.','chảo',207,NULL,_binary '\0'),(208,'A tool with a blade for cutting food','Use a sharp knife to cut the vegetables.','NOUN','Dụng cụ có lưỡi dao để cắt thức ăn','Dùng dao sắc để cắt rau.','con dao',208,NULL,_binary '\0'),(209,'Having a pleasant or savoury flavour','This soup is very tasty and filling.','ADJECTIVE','Có hương vị dễ chịu hoặc thơm ngon','Món súp này rất ngon và no.','ngon',209,NULL,_binary '\0'),(210,'Having a strong, hot flavour','Vietnamese food is often quite spicy.','ADJECTIVE','Có hương vị mạnh và cay nóng','Đồ ăn Việt Nam thường khá cay.','cay',210,NULL,_binary '\0'),(211,'A liquid food made by boiling ingredients','Chicken soup is perfect on a cold day.','NOUN','Món ăn lỏng làm bằng cách đun sôi các nguyên liệu','Canh gà rất thích hợp vào ngày lạnh.','canh/súp',211,NULL,_binary '\0'),(212,'An appliance for keeping food cold','Put the leftovers in the fridge.','NOUN','Thiết bị giữ thực phẩm lạnh','Để thức ăn thừa vào tủ lạnh.','tủ lạnh',212,NULL,_binary '\0'),(213,'A large shop selling food and other goods','I go to the supermarket twice a week.','NOUN','Cửa hàng lớn bán thực phẩm và hàng hóa khác','Tôi đi siêu thị hai lần một tuần.','siêu thị',213,NULL,_binary '\0'),(214,'A series of names or items written one after another','I always write a shopping list before going to the store.','NOUN','Chuỗi tên hoặc mục được viết liên tiếp','Tôi luôn viết danh sách mua sắm trước khi đi cửa hàng.','danh sách',214,NULL,_binary '\0'),(216,'Grown without artificial chemicals','I prefer organic fruit over conventional ones.','ADJECTIVE','Được trồng mà không dùng hóa chất nhân tạo','Tôi thích hoa quả hữu cơ hơn là hoa quả thông thường.','hữu cơ',216,NULL,_binary '\0'),(217,'A container used for carrying shopping items','Grab a basket at the entrance to the store.','NOUN','Vật đựng dùng để đựng hàng mua sắm','Lấy một giỏ hàng ở lối vào cửa hàng.','giỏ hàng',217,NULL,_binary '\0'),(218,'A wheeled cart for moving shopping','I need a trolley for this big shop.','NOUN','Xe có bánh dùng để di chuyển hàng mua sắm','Tôi cần xe đẩy hàng cho lần mua sắm lớn này.','xe đẩy hàng',218,NULL,_binary '\0'),(219,'A person who handles payments in a shop','The cashier gave me the wrong change.','NOUN','Người xử lý thanh toán ở cửa hàng','Thu ngân đã trả lại tiền thừa sai.','thu ngân',219,NULL,_binary '\0'),(222,'A food made from flour, water and yeast','I buy a fresh loaf of bread every morning.','NOUN','Thực phẩm làm từ bột mì, nước và men','Tôi mua một ổ bánh mì tươi mỗi buổi sáng.','bánh mì',222,NULL,_binary '\0'),(223,'A white liquid produced by cows or other animals','Don\'t forget to buy milk at the supermarket.','NOUN','Chất lỏng màu trắng từ bò hoặc động vật khác','Đừng quên mua sữa ở siêu thị.','sữa',223,NULL,_binary '\0'),(224,'A place where goods are bought and sold','I love shopping at the local fresh market.','NOUN','Nơi hàng hóa được mua bán','Tôi thích mua sắm ở chợ tươi địa phương.','chợ',224,NULL,_binary '\0'),(225,'A person who sells things','The vendor offered me a good deal on the fabric.','NOUN','Người bán hàng','Người bán hàng đề xuất một deal tốt về vải.','người bán hàng',225,NULL,_binary '\0'),(227,'The amount of money expected for something','The price of vegetables has gone up this month.','NOUN','Số tiền được yêu cầu cho điều gì đó','Giá rau đã tăng tháng này.','giá cả',227,NULL,_binary '\0'),(228,'Not previously preserved or treated','I always buy fresh fish from the morning market.','ADJECTIVE','Không được bảo quản hoặc xử lý trước','Tôi luôn mua cá tươi từ chợ sáng.','tươi',228,NULL,_binary '\0'),(229,'An event when goods are sold at a lower price','The market has a big sale on Saturdays.','NOUN','Sự kiện khi hàng hóa được bán với giá thấp hơn','Chợ có khuyến mãi lớn vào thứ Bảy.','khuyến mãi',229,NULL,_binary '\0'),(230,'An article or substance made for sale','This product is made locally and very affordable.','NOUN','Bài viết hoặc chất được sản xuất để bán','Sản phẩm này được làm tại địa phương và rất phải chăng.','sản phẩm',230,NULL,_binary '\0'),(231,'A person who buys goods or services','The vendor was very kind to every customer.','NOUN','Người mua hàng hóa hoặc dịch vụ','Người bán hàng rất tử tế với mọi khách hàng.','khách hàng',231,NULL,_binary '\0'),(232,'To determine the weight of something','The vendor will weigh the fruit before telling the price.','VERB','Xác định trọng lượng của thứ gì đó','Người bán sẽ cân trái cây trước khi cho biết giá.','cân',232,NULL,_binary '\0'),(233,'Money in the form of notes and coins','Most market vendors prefer cash payment.','NOUN','Tiền dưới dạng tiền giấy và tiền xu','Hầu hết người bán chợ thích thanh toán bằng tiền mặt.','tiền mặt',233,NULL,_binary '\0'),(234,'To argue about the price of something','You should haggle at souvenir shops when travelling.','VERB','Tranh cãi về giá của điều gì đó','Bạn nên mặc cả tại các cửa hàng quà lưu niệm khi du lịch.','trả giá/mặc cả',234,NULL,_binary '\0'),(235,'A place where meals are prepared and served','Let\'s try that new Vietnamese restaurant downtown.','NOUN','Nơi bữa ăn được chuẩn bị và phục vụ','Hãy thử nhà hàng Việt Nam mới ở trung tâm thành phố.','nhà hàng',235,NULL,_binary '\0'),(236,'A small restaurant serving drinks and light meals','My favourite cafe opens at seven in the morning.','NOUN','Nhà hàng nhỏ phục vụ đồ uống và đồ ăn nhẹ','Quán cà phê yêu thích của tôi mở lúc bảy giờ sáng.','quán cà phê',236,NULL,_binary '\0'),(238,'Happening or used outside','They have an outdoor seating area with great views.','ADJECTIVE','Diễn ra hoặc được sử dụng bên ngoài','Họ có khu vực ngồi ngoài trời với tầm nhìn tuyệt vời.','ngoài trời',238,NULL,_binary '\0'),(239,'Happening or used inside a building','On rainy days I prefer indoor seating.','ADJECTIVE','Diễn ra hoặc được sử dụng bên trong tòa nhà','Vào ngày mưa tôi thích ngồi bên trong.','trong nhà',239,NULL,_binary '\0'),(240,'A thick slice of meat cooked on a grill','I ordered a medium-rare steak with fries.','NOUN','Miếng thịt dày được nướng trên vỉ','Tôi gọi bít tết chín tái với khoai tây chiên.','bít tết',240,NULL,_binary '\0'),(241,'A mixed alcoholic drink','She ordered a tropical cocktail at the beach bar.','NOUN','Đồ uống có cồn được pha trộn','Cô ấy gọi một ly cocktail nhiệt đới ở quán bar bãi biển.','cocktail',241,NULL,_binary '\0'),(242,'A plant used for flavouring food','Fresh herbs like basil make dishes more flavourful.','NOUN','Cây được dùng để tạo hương vị cho thức ăn','Thảo mộc tươi như húng quế làm cho món ăn thêm thơm ngon.','thảo mộc/rau thơm',242,NULL,_binary '\0'),(243,'A protective garment worn over clothing while cooking','The chef wore a clean white apron.','NOUN','Quần áo bảo hộ mặc ngoài quần áo khi nấu ăn','Đầu bếp mặc tạp dề trắng sạch.','tạp dề',243,NULL,_binary '\0'),(244,'A skilled professional cook','The chef came out to greet the guests personally.','NOUN','Đầu bếp chuyên nghiệp có tay nghề','Đầu bếp ra chào đón khách hàng trực tiếp.','đầu bếp',244,NULL,_binary '\0'),(245,'An amount of food suitable for one person','The portions here are huge and very filling.','NOUN','Lượng thức ăn phù hợp cho một người','Phần ăn ở đây rất lớn và no bụng.','phần ăn',245,NULL,_binary '\0'),(246,'To give money for goods or services','I paid for everything with my credit card.','VERB','Đưa tiền cho hàng hóa hoặc dịch vụ','Tôi trả tiền cho tất cả bằng thẻ tín dụng.','trả tiền',246,NULL,_binary '\0'),(247,'A card allowing the holder to buy on credit','Do you accept credit card payments here?','NOUN','Thẻ cho phép chủ thẻ mua hàng trả chậm','Ở đây có chấp nhận thanh toán bằng thẻ tín dụng không?','thẻ tín dụng',247,NULL,_binary '\0'),(249,'Costing a great deal of money','This hotel is too expensive for my budget.','ADJECTIVE','Tốn rất nhiều tiền','Khách sạn này quá đắt so với ngân sách của tôi.','đắt tiền',249,NULL,_binary '\0'),(250,'Low in price or cost','I found some really cheap but good quality items here.','ADJECTIVE','Giá thấp','Tôi tìm thấy những sản phẩm khá rẻ nhưng chất lượng tốt ở đây.','rẻ',250,NULL,_binary '\0'),(251,'The amount of money available for spending','I set a strict budget for this shopping trip.','NOUN','Số tiền có sẵn để chi tiêu','Tôi đặt ngân sách chặt chẽ cho chuyến mua sắm này.','ngân sách',251,NULL,_binary '\0'),(252,'A label showing the price of an item','Check the price tag before buying anything.','NOUN','Nhãn hiển thị giá của một mặt hàng','Kiểm tra giá trước khi mua bất cứ thứ gì.','thẻ giá',252,NULL,_binary '\0'),(253,'The whole amount after adding everything','What is the total for all these items?','NOUN','Toàn bộ số tiền sau khi cộng tất cả','Tổng cộng cho tất cả những mặt hàng này là bao nhiêu?','tổng cộng',253,NULL,_binary '\0'),(255,'An instance of buying or selling something','The transaction was completed quickly online.','NOUN','Trường hợp mua hoặc bán thứ gì đó','Giao dịch được hoàn thành nhanh chóng trực tuyến.','giao dịch',255,NULL,_binary '\0'),(256,'A small folding case for carrying money','I left my wallet at home by accident.','NOUN','Hộp gấp nhỏ để đựng tiền','Tôi vô tình để quên ví ở nhà.','ví tiền',256,NULL,_binary '\0'),(257,'A person who does not eat meat','I became a vegetarian three years ago.','NOUN','Người không ăn thịt','Tôi trở thành người ăn chay cách đây ba năm.','ăn chay',257,NULL,_binary '\0'),(258,'Not containing gluten, a protein found in wheat','Do you have any gluten-free bread?','ADJECTIVE','Không chứa gluten, một loại protein trong lúa mì','Bạn có bánh mì không gluten không?','không gluten',258,NULL,_binary '\0'),(259,'A unit of energy obtained from food','I try to track my calorie intake every day.','NOUN','Đơn vị năng lượng thu được từ thức ăn','Tôi cố gắng theo dõi lượng calo nạp vào mỗi ngày.','calo',259,NULL,_binary '\0'),(260,'The process of providing food for health','Good nutrition is essential for children\'s growth.','NOUN','Quá trình cung cấp thức ăn để duy trì sức khỏe','Dinh dưỡng tốt là điều cần thiết cho sự phát triển của trẻ em.','dinh dưỡng',260,NULL,_binary '\0'),(261,'A nutrient essential for body growth and repair','Eggs and beans are excellent sources of protein.','NOUN','Chất dinh dưỡng cần thiết cho sự phát triển và sửa chữa cơ thể','Trứng và đậu là nguồn cung cấp protein tuyệt vời.','protein',261,NULL,_binary '\0'),(262,'A substance in food that helps digestion','Vegetables and fruits are high in fibre.','NOUN','Chất trong thức ăn giúp tiêu hóa','Rau và trái cây chứa nhiều chất xơ.','chất xơ',262,NULL,_binary '\0'),(263,'Having the pleasant taste of sugar','I have a sweet tooth and love desserts.','ADJECTIVE','Có vị ngọt như đường','Tôi thích ăn ngọt và yêu thích món tráng miệng.','ngọt',263,NULL,_binary '\0'),(264,'Tasting of or containing salt','This soup is too salty, I can\'t eat it.','ADJECTIVE','Có vị muối hoặc chứa muối','Súp này quá mặn, tôi không thể ăn được.','mặn',264,NULL,_binary '\0'),(265,'Having an acidic, sharp flavour','Lemons are very sour but healthy.','ADJECTIVE','Có hương vị chua, sắc bén','Chanh rất chua nhưng tốt cho sức khỏe.','chua',265,NULL,_binary '\0'),(266,'Having a sharp, pungent taste','Dark chocolate has a rich and bitter taste.','ADJECTIVE','Có vị sắc, hăng','Sô cô la đen có vị đậm và đắng.','đắng',266,NULL,_binary '\0'),(267,'Good for health and well-being','Eating healthy food every day gives you energy.','ADJECTIVE','Tốt cho sức khỏe và sự khỏe mạnh','Ăn thức ăn lành mạnh mỗi ngày sẽ cho bạn năng lượng.','lành mạnh',267,NULL,_binary '\0'),(268,'A popular style or trend in clothing','She always follows the latest fashion trends.','NOUN','Một phong cách hay xu hướng phổ biến trong trang phục','Cô ấy luôn theo xu hướng thời trang mới nhất.','thời trang',268,NULL,_binary '\0'),(269,'A name given to a product by a company','This brand is very popular among young people.','NOUN','Tên mà công ty đặt cho sản phẩm','Thương hiệu này rất phổ biến trong giới trẻ.','thương hiệu',269,NULL,_binary '\0'),(270,'The measurement of how large something is','Do you have this shirt in a larger size?','NOUN','Số đo của kích thước một vật','Bạn có chiếc áo này cỡ lớn hơn không?','kích cỡ',270,NULL,_binary '\0'),(271,'Material made from the skin of an animal','I bought a leather handbag from this boutique.','NOUN','Vật liệu làm từ da động vật','Tôi mua một túi da từ cửa hàng thời trang này.','da thuộc',271,NULL,_binary '\0'),(272,'A soft fabric made from cotton plants','I prefer cotton clothes because they are breathable.','NOUN','Vải mềm làm từ cây bông','Tôi thích quần áo bằng vải bông vì thoáng mát.','vải bông',272,NULL,_binary '\0'),(273,'Very fashionable and up to date','She always looks trendy and stylish.','ADJECTIVE','Rất thời thượng và hợp thời','Cô ấy luôn trông hợp mốt và phong cách.','hợp mốt',273,NULL,_binary '\0'),(274,'To be the right size or shape for something','Does this jacket fit you well?','VERB','Có kích thước hoặc hình dạng phù hợp','Chiếc áo khoác này có vừa với bạn không?','vừa vặn/hợp',274,NULL,_binary '\0'),(275,'A room in a shop for trying on clothes','May I use the fitting room to try this on?','NOUN','Phòng trong cửa hàng để thử quần áo','Tôi có thể dùng phòng thử đồ để mặc thử cái này không?','phòng thử đồ',275,NULL,_binary '\0'),(276,'A set of clothes worn together','She put together a great outfit for the event.','NOUN','Bộ quần áo mặc cùng nhau','Cô ấy ghép một bộ trang phục tuyệt vời cho sự kiện.','bộ quần áo',276,NULL,_binary '\0'),(277,'Available at a reduced price','This coat is on sale for fifty percent off.','ADJECTIVE','Có sẵn với giá giảm','Chiếc áo này đang giảm giá năm mươi phần trăm.','đang giảm giá',277,NULL,_binary '\0'),(278,'A person very interested in fashion','She is a true fashionista and knows every trend.','NOUN','Người rất quan tâm đến thời trang','Cô ấy thực sự là một fashionista và biết mọi xu hướng.','người yêu thời trang',278,NULL,_binary '\0'),(279,'The course along which something moves','Can you give me directions to the train station?','NOUN','Hướng mà thứ gì đó di chuyển','Bạn có thể chỉ đường đến ga xe lửa cho tôi không?','hướng/chỉ đường',279,NULL,_binary '\0'),(280,'A public road in a city or town','Turn left at the end of this street.','NOUN','Con đường công cộng ở thành phố hoặc thị trấn','Rẽ trái ở cuối con đường này.','đường phố',280,NULL,_binary '\0'),(281,'A place where two streets meet','The pharmacy is on the corner of Main Street.','NOUN','Nơi hai con đường gặp nhau','Nhà thuốc ở góc đường phố Main.','góc đường',281,NULL,_binary '\0'),(283,'A set of coloured lights for controlling road traffic','Turn right when you see the traffic lights.','NOUN','Bộ đèn màu dùng để kiểm soát giao thông','Rẽ phải khi bạn nhìn thấy đèn giao thông.','đèn giao thông',283,NULL,_binary '\0'),(284,'A designated area for pedestrians to cross','Use the crosswalk to safely cross the road.','NOUN','Khu vực được chỉ định cho người đi bộ qua đường','Dùng vạch kẻ đường để qua đường an toàn.','vạch kẻ đường',284,NULL,_binary '\0'),(288,'Closest in distance','Can you tell me where the nearest ATM is?','ADJECTIVE','Gần nhất về khoảng cách','Bạn có thể cho tôi biết máy ATM gần nhất ở đâu không?','gần nhất',288,NULL,_binary '\0'),(289,'Beside or immediately beside something','The cafe is next to the bookshop.','ADVERB','Bên cạnh hoặc ngay sát cạnh thứ gì đó','Quán cà phê nằm bên cạnh cửa hàng sách.','bên cạnh',289,NULL,_binary '\0'),(290,'On the far side of something','The parking lot is behind the supermarket.','ADVERB','Ở phía xa hơn của thứ gì đó','Bãi đỗ xe ở phía sau siêu thị.','phía sau',290,NULL,_binary '\0'),(291,'A large vehicle that carries many passengers','I take the bus to work every morning.','NOUN','Xe lớn chở nhiều hành khách','Tôi đi xe buýt đến chỗ làm mỗi buổi sáng.','xe buýt',291,NULL,_binary '\0'),(292,'A series of connected carriages pulled by an engine','The train to Hanoi leaves at six PM.','NOUN','Các toa xe được kết nối và kéo bởi đầu máy','Tàu đi Hà Nội khởi hành lúc sáu giờ chiều.','tàu hỏa',292,NULL,_binary '\0'),(293,'An underground railway system','The subway is the fastest way to get around the city.','NOUN','Hệ thống tàu điện đi dưới lòng đất','Tàu điện ngầm là cách nhanh nhất để đi lại trong thành phố.','tàu điện ngầm',293,NULL,_binary '\0'),(295,'A piece of paper giving permission to travel','I bought a return ticket to the airport.','NOUN','Tờ giấy cho phép đi lại','Tôi mua vé khứ hồi đến sân bay.','vé',295,NULL,_binary '\0'),(297,'A list showing times of departures and arrivals','Check the timetable before going to the station.','NOUN','Danh sách hiển thị thời gian khởi hành và đến nơi','Kiểm tra lịch chạy xe trước khi đến ga.','lịch chạy xe',297,NULL,_binary '\0'),(298,'A traveller on a vehicle','All passengers must show their tickets.','NOUN','Người đi lại trên phương tiện','Tất cả hành khách phải xuất trình vé.','hành khách',298,NULL,_binary '\0'),(299,'The person who operates a vehicle','The bus driver was very friendly and helpful.','NOUN','Người điều khiển phương tiện','Tài xế xe buýt rất thân thiện và nhiệt tình.','tài xế',299,NULL,_binary '\0'),(301,'To change from one vehicle to another','You need to transfer at Central Station.','VERB','Chuyển từ phương tiện này sang phương tiện khác','Bạn cần chuyển tuyến tại Ga Trung tâm.','chuyển tuyến',301,NULL,_binary '\0'),(302,'To arrange in advance to have a seat or room','I need to book a table for Saturday evening.','VERB','Sắp xếp trước để có chỗ ngồi hoặc phòng','Tôi cần đặt bàn cho tối thứ Bảy.','đặt chỗ/đặt vé',302,NULL,_binary '\0'),(303,'To decide that a planned event will not happen','I had to cancel my hotel reservation due to illness.','VERB','Quyết định rằng sự kiện đã lên kế hoạch sẽ không xảy ra','Tôi phải hủy đặt phòng khách sạn vì bị ốm.','hủy',303,NULL,_binary '\0'),(304,'To verify or establish the truth of something','Please confirm your booking via email.','VERB','Xác minh hoặc xác lập sự thật của điều gì đó','Vui lòng xác nhận đặt chỗ của bạn qua email.','xác nhận',304,NULL,_binary '\0'),(305,'Connected to or accessible via the internet','You can book tickets online easily.','ADJECTIVE','Được kết nối hoặc có thể truy cập qua internet','Bạn có thể đặt vé trực tuyến dễ dàng.','trực tuyến',305,NULL,_binary '\0'),(307,'Able to be used or obtained','Are any rooms available for this weekend?','ADJECTIVE','Có thể sử dụng hoặc thu được','Có phòng nào trống cho cuối tuần này không?','có sẵn',307,NULL,_binary '\0'),(309,'Requiring immediate action or attention','I have an urgent request to make a booking today.','ADJECTIVE','Cần hành động hoặc sự chú ý ngay lập tức','Tôi có yêu cầu khẩn cấp phải đặt chỗ hôm nay.','khẩn cấp',309,NULL,_binary '\0'),(310,'A set of rules or principles adopted by an organization','What is the cancellation policy for this booking?','NOUN','Tập hợp quy tắc hoặc nguyên tắc của một tổ chức','Chính sách hủy đặt phòng này là gì?','chính sách',310,NULL,_binary '\0'),(311,'The importance or usefulness of something','This tour package offers great value for money.','NOUN','Tầm quan trọng hoặc tính hữu ích của điều gì đó','Gói tour này mang lại giá trị rất tốt cho đồng tiền.','giá trị',311,NULL,_binary '\0'),(312,'A formal promise that something will happen','They guarantee a full refund if the event is cancelled.','NOUN','Lời hứa chính thức rằng điều gì đó sẽ xảy ra','Họ đảm bảo hoàn tiền đầy đủ nếu sự kiện bị hủy.','đảm bảo',312,NULL,_binary '\0'),(313,'A building that provides paid accommodation','We stayed at a luxury hotel near the beach.','NOUN','Tòa nhà cung cấp chỗ ở có trả phí','Chúng tôi ở tại một khách sạn sang trọng gần bãi biển.','khách sạn',313,NULL,_binary '\0'),(316,'A separate area enclosed by walls within a building','Could you give me a room with a sea view?','NOUN','Khu vực riêng biệt được bao quanh bởi các bức tường','Bạn có thể cho tôi phòng có hướng nhìn ra biển không?','phòng',316,NULL,_binary '\0'),(317,'Assistance provided to customers','The hotel provides excellent service twenty-four hours a day.','NOUN','Sự hỗ trợ cung cấp cho khách hàng','Khách sạn cung cấp dịch vụ tuyệt vời hai mươi bốn giờ mỗi ngày.','dịch vụ',317,NULL,_binary '\0'),(318,'A useful feature of a place for comfort','This hotel has excellent amenities including a gym and pool.','NOUN','Tính năng hữu ích của một nơi để tăng sự thoải mái','Khách sạn này có tiện nghi tuyệt vời bao gồm phòng gym và hồ bơi.','tiện nghi',318,NULL,_binary '\0'),(319,'Food delivered to a hotel room','I ordered room service because I was too tired to go out.','NOUN','Thức ăn được giao đến phòng khách sạn','Tôi gọi dịch vụ phòng vì quá mệt để ra ngoài.','dịch vụ phòng',319,NULL,_binary '\0'),(323,'An electronic card used to unlock hotel rooms','The front desk will give you a key card for your room.','NOUN','Thẻ điện tử dùng để mở khóa phòng khách sạn','Lễ tân sẽ cấp cho bạn một thẻ từ cho phòng của bạn.','thẻ từ',323,NULL,_binary '\0'),(324,'The business of providing services to tourists','Tourism is a major industry in this country.','NOUN','Kinh doanh cung cấp dịch vụ cho khách du lịch','Du lịch là ngành công nghiệp chính ở quốc gia này.','du lịch',324,NULL,_binary '\0'),(325,'A person visiting a place for pleasure','Thousands of tourists visit this temple every year.','NOUN','Người đến thăm một nơi vì mục đích giải trí','Hàng nghìn khách du lịch thăm ngôi đền này mỗi năm.','khách du lịch',325,NULL,_binary '\0'),(327,'A place of interest that people visit','The theme park is the top attraction for families.','NOUN','Nơi thú vị mà người ta đến thăm','Công viên giải trí là điểm thu hút hàng đầu cho gia đình.','điểm tham quan',327,NULL,_binary '\0'),(328,'A tour led by a professional guide','We joined a guided tour of the old city.','NOUN','Tour được dẫn dắt bởi hướng dẫn viên chuyên nghiệp','Chúng tôi tham gia tour có hướng dẫn của phố cổ.','tour có hướng dẫn',328,NULL,_binary '\0'),(329,'A small item bought to remember a place','I bought a souvenir magnet for my fridge.','NOUN','Đồ vật nhỏ mua để nhớ đến một nơi','Tôi mua nam châm lưu niệm cho tủ lạnh của mình.','quà lưu niệm',329,NULL,_binary '\0'),(330,'A building where objects of historical interest are kept','We visited the National History Museum.','NOUN','Tòa nhà nơi lưu giữ các đồ vật có giá trị lịch sử','Chúng tôi đến thăm Bảo tàng Lịch sử Quốc gia.','bảo tàng',330,NULL,_binary '\0'),(332,'Having or providing beautiful natural scenery','We took a scenic drive along the coast.','ADJECTIVE','Có hoặc cung cấp cảnh thiên nhiên đẹp','Chúng tôi đi đường ven biển với cảnh đẹp tuyệt vời.','có cảnh đẹp',332,NULL,_binary '\0'),(334,'A tower with a powerful light for guiding ships','We hiked to the lighthouse at sunset.','NOUN','Tòa tháp với ánh đèn mạnh để hướng dẫn tàu thuyền','Chúng tôi đi bộ đến ngọn hải đăng lúc hoàng hôn.','ngọn hải đăng',334,NULL,_binary '\0'),(335,'A large town with many buildings','Ho Chi Minh City is the largest city in Vietnam.','NOUN','Thị trấn lớn có nhiều tòa nhà','Thành phố Hồ Chí Minh là thành phố lớn nhất Việt Nam.','thành phố',335,NULL,_binary '\0'),(336,'Land outside towns and cities','I love spending weekends in the quiet countryside.','NOUN','Vùng đất bên ngoài thành phố và thị trấn','Tôi thích dành cuối tuần ở miền quê yên tĩnh.','vùng nông thôn',336,NULL,_binary '\0'),(337,'A sandy or pebbly shore beside the sea','The beach here is clean and beautiful.','NOUN','Bờ biển cát hoặc đá sỏi bên cạnh biển','Bãi biển ở đây sạch và đẹp.','bãi biển',337,NULL,_binary '\0'),(338,'A large natural elevation of the ground','We went hiking in the mountains last summer.','NOUN','Độ cao tự nhiên lớn của mặt đất','Chúng tôi đi leo núi vào mùa hè năm ngoái.','núi',338,NULL,_binary '\0'),(339,'A large area covered in trees','The national forest is home to many wild animals.','NOUN','Khu vực rộng lớn được bao phủ bởi cây cối','Khu rừng quốc gia là nơi sinh sống của nhiều động vật hoang dã.','rừng',339,NULL,_binary '\0'),(340,'A large natural stream of water','We had a picnic by the river last weekend.','NOUN','Dòng nước tự nhiên lớn','Chúng tôi dã ngoại bên sông cuối tuần trước.','sông',340,NULL,_binary '\0'),(341,'A small community in a rural area','The old fishing village is very peaceful.','NOUN','Cộng đồng nhỏ ở khu vực nông thôn','Làng chài cũ rất yên bình.','làng/xã',341,NULL,_binary '\0'),(343,'A district forming a community in a city','This neighborhood is very safe and friendly.','NOUN','Quận tạo thành cộng đồng trong thành phố','Khu phố này rất an toàn và thân thiện.','khu phố',343,NULL,_binary '\0'),(344,'Relating to a particular area or neighbourhood','Ask the local people for restaurant recommendations.','ADJECTIVE','Liên quan đến một khu vực cụ thể','Hỏi người địa phương để được giới thiệu nhà hàng.','địa phương',344,NULL,_binary '\0'),(345,'A large green area in a town for recreation','Children love playing in the park on weekends.','NOUN','Khu vực xanh lớn trong thị trấn để vui chơi','Trẻ em thích chơi ở công viên vào cuối tuần.','công viên',345,NULL,_binary '\0'),(346,'A diagrammatic representation of an area','Use the map on your phone to find the way.','NOUN','Biểu diễn sơ đồ của một khu vực','Dùng bản đồ trên điện thoại để tìm đường.','bản đồ',346,NULL,_binary '\0'),(347,'A system that shows your exact location','My GPS told me to take the second left.','NOUN','Hệ thống hiển thị vị trí chính xác của bạn','GPS của tôi chỉ tôi rẽ trái lần thứ hai.','hệ thống định vị',347,NULL,_binary '\0'),(348,'An instrument showing the direction of north','A compass is useful when hiking in remote areas.','NOUN','Dụng cụ chỉ hướng bắc','La bàn rất hữu ích khi đi bộ ở vùng hẻo lánh.','la bàn',348,NULL,_binary '\0'),(350,'A particular place or position','Share your location with me so I can find you.','NOUN','Một nơi hoặc vị trí cụ thể','Chia sẻ vị trí của bạn với tôi để tôi có thể tìm bạn.','vị trí',350,NULL,_binary '\0'),(351,'To plan and direct the course of a journey','It is easy to navigate this city using the metro.','VERB','Lập kế hoạch và chỉ đường cho hành trình','Rất dễ để điều hướng thành phố này bằng tàu điện ngầm.','điều hướng',351,NULL,_binary '\0'),(352,'The distance north or south of the equator','The city is at a latitude of twenty-one degrees north.','NOUN','Khoảng cách về phía bắc hoặc nam của đường xích đạo','Thành phố ở vĩ độ hai mươi mốt độ bắc.','vĩ độ',352,NULL,_binary '\0'),(353,'The distance east or west from the prime meridian','Vietnam spans a wide range of longitudes.','NOUN','Khoảng cách về phía đông hoặc tây từ kinh tuyến gốc','Việt Nam trải dài trên một phạm vi kinh độ rộng.','kinh độ',353,NULL,_binary '\0'),(355,'A place where two roads cross','Turn left at the next major intersection.','NOUN','Nơi hai con đường giao nhau','Rẽ trái tại ngã tư lớn tiếp theo.','ngã tư',355,NULL,_binary '\0'),(356,'Not knowing where you are','I got lost because I didn\'t have a map.','ADJECTIVE','Không biết bạn đang ở đâu','Tôi bị lạc vì không có bản đồ.','bị lạc',356,NULL,_binary '\0'),(358,'Decided not to happen or continue','Our flight was cancelled due to the storm.','ADJECTIVE','Được quyết định không xảy ra hoặc tiếp tục','Chuyến bay của chúng tôi bị hủy do bão.','bị hủy',358,NULL,_binary '\0'),(359,'Taken unlawfully from the owner','My wallet was stolen at the market.','ADJECTIVE','Bị lấy đi trái phép từ chủ sở hữu','Ví của tôi bị trộm ở chợ.','bị đánh cắp',359,NULL,_binary '\0'),(360,'Not working properly','My suitcase wheel is broken.','ADJECTIVE','Không hoạt động bình thường','Bánh xe của vali tôi bị hỏng.','bị hỏng',360,NULL,_binary '\0'),(361,'Not in its usual place or nowhere to be found','My luggage is missing at the airport.','ADJECTIVE','Không ở vị trí thông thường hoặc không tìm thấy đâu','Hành lý của tôi bị thất lạc ở sân bay.','bị mất/thất lạc',361,NULL,_binary '\0'),(362,'An unfortunate event happening without intention','There was a minor accident on the motorway.','NOUN','Sự kiện không may xảy ra ngoài ý muốn','Có một vụ tai nạn nhỏ trên đường cao tốc.','tai nạn',362,NULL,_binary '\0'),(363,'To make it easier for someone to do something','Can you help me find the train station?','VERB','Giúp ai đó dễ dàng hơn để làm điều gì đó','Bạn có thể giúp tôi tìm ga xe lửa không?','giúp đỡ',363,NULL,_binary '\0'),(364,'A serious unexpected situation requiring action','In an emergency, call one hundred and thirteen.','NOUN','Tình huống bất ngờ nghiêm trọng cần hành động','Trong trường hợp khẩn cấp, hãy gọi một trăm mười ba.','khẩn cấp',364,NULL,_binary '\0'),(365,'To express dissatisfaction about something','I need to complain about the service I received.','VERB','Bày tỏ sự không hài lòng về điều gì đó','Tôi cần phàn nàn về dịch vụ tôi nhận được.','phàn nàn',365,NULL,_binary '\0'),(366,'To give an account of something officially','You should report the theft to the police immediately.','VERB','Đưa ra thông tin về điều gì đó một cách chính thức','Bạn nên báo vụ trộm cho cảnh sát ngay lập tức.','báo cáo',366,NULL,_binary '\0'),(367,'Feeling or showing pleasure','She looked very happy when she heard the good news.','ADJECTIVE','Cảm thấy hoặc thể hiện niềm vui','Cô ấy trông rất vui khi nghe tin tốt.','vui vẻ/hạnh phúc',367,NULL,_binary '\0'),(368,'Feeling or showing sorrow','I felt very sad when I heard about the accident.','ADJECTIVE','Cảm thấy hoặc thể hiện nỗi buồn','Tôi cảm thấy rất buồn khi nghe về vụ tai nạn.','buồn',368,NULL,_binary '\0'),(369,'Feeling or showing strong displeasure','He was angry because he missed the train.','ADJECTIVE','Cảm thấy hoặc thể hiện sự không hài lòng mạnh mẽ','Anh ấy tức giận vì lỡ chuyến tàu.','tức giận',369,NULL,_binary '\0'),(370,'Feeling afraid or frightened','She was scared by the loud thunder.','ADJECTIVE','Cảm thấy sợ hãi hoặc kinh hãi','Cô ấy bị giật mình bởi tiếng sấm to.','sợ hãi',370,NULL,_binary '\0'),(371,'Feeling very enthusiastic and eager','I am so excited about my trip to Japan!','ADJECTIVE','Cảm thấy rất nhiệt tình và háo hức','Tôi rất hào hứng về chuyến đi Nhật Bản!','hào hứng',371,NULL,_binary '\0'),(372,'Feeling sad because one has no company','Living alone can sometimes make you feel lonely.','ADJECTIVE','Cảm thấy buồn vì không có người bên cạnh','Sống một mình đôi khi có thể khiến bạn cảm thấy cô đơn.','cô đơn',372,NULL,_binary '\0'),(373,'Unable to think clearly or understand','I was confused by the complicated instructions.','ADJECTIVE','Không thể suy nghĩ rõ ràng hoặc hiểu','Tôi bối rối với những hướng dẫn phức tạp.','bối rối',373,NULL,_binary '\0'),(374,'Feeling unexpected wonder or astonishment','She was surprised by the birthday party.','ADJECTIVE','Cảm thấy sự ngạc nhiên bất ngờ','Cô ấy ngạc nhiên với bữa tiệc sinh nhật.','ngạc nhiên',374,NULL,_binary '\0'),(375,'Anxious or afraid about something','I always feel nervous before giving a speech.','ADJECTIVE','Lo lắng hoặc sợ về điều gì đó','Tôi luôn cảm thấy căng thẳng trước khi thuyết trình.','lo lắng/căng thẳng',375,NULL,_binary '\0'),(376,'Feeling weary because one is unoccupied','I am bored, let\'s do something fun!','ADJECTIVE','Cảm thấy mệt mỏi vì không có việc gì làm','Tôi chán quá, hãy làm gì đó vui nào!','chán',376,NULL,_binary '\0'),(377,'Worried and tense about an uncertain situation','She felt anxious waiting for her exam results.','ADJECTIVE','Lo lắng và căng thẳng về tình huống không chắc chắn','Cô ấy cảm thấy lo âu khi chờ kết quả thi.','lo âu',377,NULL,_binary '\0'),(378,'To find something pleasing or enjoyable','I like listening to music in the morning.','VERB','Thấy điều gì đó thú vị hoặc thích thú','Tôi thích nghe nhạc vào buổi sáng.','thích',378,NULL,_binary '\0'),(379,'To have a very strong feeling of affection','I love travelling and exploring new places.','VERB','Có cảm giác yêu mến rất mạnh mẽ','Tôi yêu thích du lịch và khám phá những nơi mới.','yêu thích',379,NULL,_binary '\0'),(380,'To dislike something very strongly','I hate eating vegetables that are not fresh.','VERB','Không thích điều gì rất mạnh mẽ','Tôi ghét ăn rau không tươi.','ghét',380,NULL,_binary '\0'),(381,'To take pleasure in something','I really enjoy cooking for my friends.','VERB','Nhận được niềm vui từ điều gì đó','Tôi thực sự tận hưởng việc nấu ăn cho bạn bè.','tận hưởng',381,NULL,_binary '\0'),(382,'To like something more than another thing','I prefer tea over coffee in the morning.','VERB','Thích điều gì đó hơn điều khác','Tôi thích uống trà hơn cà phê vào buổi sáng.','thích hơn',382,NULL,_binary '\0'),(383,'Something liked best above all others','My favourite season is autumn.','ADJECTIVE','Thứ được yêu thích nhất','Mùa yêu thích của tôi là mùa thu.','yêu thích nhất',383,NULL,_binary '\0'),(384,'Arousing curiosity or attention','That documentary was very interesting.','ADJECTIVE','Kích thích sự tò mò hoặc sự chú ý','Bộ phim tài liệu đó rất thú vị.','thú vị',384,NULL,_binary '\0'),(385,'Not interesting; dull','That lecture was so boring that I fell asleep.','ADJECTIVE','Không thú vị; tẻ nhạt','Bài giảng đó nhàm chán đến mức tôi ngủ thiếp.','nhàm chán',385,NULL,_binary '\0'),(386,'Inspiring delight or pleasure','The sunset at the beach was wonderful.','ADJECTIVE','Khơi dậy niềm vui hay sự thích thú','Hoàng hôn ở bãi biển thật tuyệt vời.','tuyệt vời',386,NULL,_binary '\0'),(387,'Causing great surprise or wonder','The view from the top of the mountain was amazing.','ADJECTIVE','Gây ra sự ngạc nhiên hay ngưỡng mộ lớn','Cảnh từ đỉnh núi nhìn xuống thật đáng kinh ngạc.','đáng kinh ngạc',387,NULL,_binary '\0'),(388,'Extremely bad or unpleasant','The weather was terrible on our holiday.','ADJECTIVE','Cực kỳ xấu hoặc khó chịu','Thời tiết rất tệ trong kỳ nghỉ của chúng tôi.','tệ hại',388,NULL,_binary '\0'),(389,'A view or judgement not necessarily based on fact','What is your opinion on working from home?','NOUN','Quan điểm hoặc nhận xét không nhất thiết dựa trên thực tế','Ý kiến của bạn về làm việc từ xa là gì?','ý kiến',389,NULL,_binary '\0'),(390,'A particular attitude towards something','From my point of view, the plan needs more detail.','NOUN','Thái độ cụ thể đối với điều gì đó','Từ quan điểm của tôi, kế hoạch cần thêm chi tiết.','quan điểm',390,NULL,_binary '\0'),(391,'To put forward an idea for consideration','I suggest we take the highway to avoid traffic.','VERB','Đề xuất ý kiến để xem xét','Tôi gợi ý đi đường cao tốc để tránh tắc đường.','gợi ý',391,NULL,_binary '\0'),(392,'To suggest as being suitable for a purpose','Can you recommend a good seafood restaurant?','VERB','Gợi ý như là phù hợp cho một mục đích','Bạn có thể giới thiệu cho tôi nhà hàng hải sản ngon không?','đề xuất/giới thiệu',392,NULL,_binary '\0'),(393,'To have a particular belief or idea','I think we should leave earlier to avoid the traffic.','VERB','Có niềm tin hoặc ý kiến cụ thể','Tôi nghĩ chúng ta nên đi sớm hơn để tránh tắc đường.','nghĩ',393,NULL,_binary '\0'),(394,'To accept something as true','I believe learning English is very important today.','VERB','Chấp nhận điều gì đó là đúng','Tôi tin rằng học tiếng Anh rất quan trọng ngày nay.','tin tưởng',394,NULL,_binary '\0'),(395,'To give a particular impression or feeling','He seems very knowledgeable about Vietnamese history.','VERB','Tạo ra ấn tượng hoặc cảm giác cụ thể','Anh ấy có vẻ rất hiểu biết về lịch sử Việt Nam.','có vẻ như',395,NULL,_binary '\0'),(396,'Taking everything into account','Overall, I think the trip was a great success.','ADVERB','Xét tất cả mọi thứ','Nhìn chung, tôi nghĩ chuyến đi là một thành công lớn.','nhìn chung',396,NULL,_binary '\0'),(398,'A feeling of uncertainty about something','I have some doubt about whether this plan will work.','NOUN','Cảm giác không chắc chắn về điều gì đó','Tôi có một số nghi ngờ về việc kế hoạch này có thành công không.','nghi ngờ',398,NULL,_binary '\0'),(399,'Without any doubt; certainly','I will definitely join the trip next month.','ADVERB','Không chút nghi ngờ; chắc chắn','Tôi chắc chắn sẽ tham gia chuyến đi tháng tới.','chắc chắn',399,NULL,_binary '\0'),(400,'To have the same opinion as someone else','I totally agree with what you said.','VERB','Có cùng ý kiến với người khác','Tôi hoàn toàn đồng ý với những gì bạn nói.','đồng ý',400,NULL,_binary '\0'),(401,'To have a different opinion from someone','I respectfully disagree with your conclusion.','VERB','Có ý kiến khác với ai đó','Tôi kính trọng không đồng ý với kết luận của bạn.','không đồng ý',401,NULL,_binary '\0'),(402,'With no qualification, restriction or limitation','Absolutely! I think that is the right decision.','ADVERB','Không có điều kiện, hạn chế hoặc giới hạn','Hoàn toàn đúng! Tôi nghĩ đó là quyết định đúng đắn.','hoàn toàn',402,NULL,_binary '\0'),(403,'Used to emphasize complete agreement','Exactly! You have understood the problem perfectly.','ADVERB','Dùng để nhấn mạnh sự đồng ý hoàn toàn','Chính xác! Bạn đã hiểu vấn đề một cách hoàn hảo.','chính xác',403,NULL,_binary '\0'),(404,'Used to present a contrasting point of view','On the other hand, it might be cheaper to fly.','ADVERB','Dùng để trình bày quan điểm đối lập','Mặt khác, đi máy bay có thể rẻ hơn.','mặt khác',404,NULL,_binary '\0'),(405,'Used to introduce a contrasting statement','I liked the food, however the service was slow.','ADVERB','Dùng để giới thiệu câu nói đối lập','Tôi thích đồ ăn, tuy nhiên dịch vụ thì chậm.','tuy nhiên',405,NULL,_binary '\0'),(406,'To some extent; not completely','I sort of agree but there are some issues.','ADVERB','Ở một mức độ nào đó; không hoàn toàn','Tôi phần nào đồng ý nhưng có một số vấn đề.','phần nào đó',406,NULL,_binary '\0'),(407,'Used to indicate a reluctant acceptance','Fair enough, I can see why you feel that way.','ADJECTIVE','Dùng để thể hiện sự chấp nhận miễn cưỡng','Có lý thôi, tôi có thể hiểu tại sao bạn cảm thấy như vậy.','có lý/đồng ý',407,NULL,_binary '\0'),(408,'An emphatic refusal or disagreement','No way! I completely disagree with that idea.','ADVERB','Sự từ chối hoặc không đồng ý nhấn mạnh','Không đời nào! Tôi hoàn toàn không đồng ý với ý tưởng đó.','không đời nào',408,NULL,_binary '\0'),(409,'A discussion where opposite views are argued','The class had an interesting debate on social media.','NOUN','Cuộc thảo luận nơi các quan điểm đối lập được tranh luận','Lớp học có một cuộc tranh luận thú vị về mạng xã hội.','tranh luận',409,NULL,_binary '\0'),(410,'As expected; of course','Naturally, I agreed when they offered me the job.','ADVERB','Như dự kiến; tất nhiên','Đương nhiên, tôi đồng ý khi họ mời tôi làm việc.','đương nhiên',410,NULL,_binary '\0'),(411,'Of great height','She is tall with long dark hair.','ADJECTIVE','Có chiều cao lớn','Cô ấy cao với mái tóc dài màu đen.','cao',411,NULL,_binary '\0'),(412,'Of small height','He is short but very athletic.','ADJECTIVE','Có chiều cao nhỏ','Anh ấy thấp nhưng rất năng động.','thấp/lùn',412,NULL,_binary '\0'),(413,'Thin in a pleasant way','She stays slim by eating healthily and exercising.','ADJECTIVE','Mỏng theo cách dễ chịu','Cô ấy giữ thân hình mảnh mai bằng cách ăn uống lành mạnh và tập thể dục.','mảnh mai',413,NULL,_binary '\0'),(415,'Quick to understand and learn','He is a clever student who always asks good questions.','ADJECTIVE','Nhanh hiểu và học hỏi','Anh ấy là học sinh thông minh luôn đặt câu hỏi hay.','thông minh',415,NULL,_binary '\0'),(416,'Kind and pleasant towards others','My new neighbours are very friendly.','ADJECTIVE','Tốt bụng và dễ chịu với người khác','Hàng xóm mới của tôi rất thân thiện.','thân thiện',416,NULL,_binary '\0'),(417,'Not joking; thoughtful','She is a serious and dedicated employee.','ADJECTIVE','Không đùa; suy nghĩ cẩn thận','Cô ấy là nhân viên nghiêm túc và tận tâm.','nghiêm túc',417,NULL,_binary '\0'),(418,'Having or expressing a sense of humour','My grandfather is very humorous and funny.','ADJECTIVE','Có hoặc thể hiện khiếu hài hước','Ông tôi rất hài hước và vui tính.','hài hước',418,NULL,_binary '\0'),(419,'Having a strong desire for success','She is ambitious and wants to become a doctor.','ADJECTIVE','Có mong muốn thành công mạnh mẽ','Cô ấy có tham vọng và muốn trở thành bác sĩ.','tham vọng',419,NULL,_binary '\0'),(420,'Feeling sure of one\'s abilities','He was confident during the interview.','ADJECTIVE','Cảm thấy chắc chắn về khả năng của mình','Anh ấy rất tự tin trong buổi phỏng vấn.','tự tin',420,NULL,_binary '\0'),(421,'Able to wait calmly without getting angry','A good teacher must be very patient.','ADJECTIVE','Có thể đợi bình tĩnh mà không tức giận','Một giáo viên tốt phải rất kiên nhẫn.','kiên nhẫn',421,NULL,_binary '\0'),(422,'A matter or situation regarded as difficult','I have a problem with my internet connection.','NOUN','Vấn đề hoặc tình huống được coi là khó khăn','Tôi có vấn đề với kết nối internet.','vấn đề',422,NULL,_binary '\0'),(423,'A thing that is hard to accomplish','She had difficulties adapting to the new environment.','NOUN','Điều khó thực hiện','Cô ấy gặp khó khăn trong việc thích nghi với môi trường mới.','khó khăn',423,NULL,_binary '\0'),(424,'Difficulty or problems','I have trouble remembering new vocabulary.','NOUN','Khó khăn hoặc vấn đề','Tôi gặp khó khăn khi nhớ từ vựng mới.','rắc rối',424,NULL,_binary '\0'),(425,'To find an answer to a problem','We need to solve this issue before the deadline.','VERB','Tìm ra câu trả lời cho một vấn đề','Chúng ta cần giải quyết vấn đề này trước hạn chót.','giải quyết',425,NULL,_binary '\0'),(426,'To take action to handle something','I don\'t know how to deal with this situation.','VERB','Hành động để xử lý điều gì đó','Tôi không biết cách xử lý tình huống này.','xử lý',426,NULL,_binary '\0'),(427,'To feel anxious or troubled','Don\'t worry, everything will be fine.','VERB','Cảm thấy lo âu hoặc bị làm phiền','Đừng lo lắng, mọi thứ sẽ ổn thôi.','lo lắng',427,NULL,_binary '\0'),(429,'Made up of many confusing parts','The instructions are too complicated to follow.','ADJECTIVE','Bao gồm nhiều phần khó hiểu','Hướng dẫn quá phức tạp để làm theo.','phức tạp',429,NULL,_binary '\0'),(430,'A means of solving a problem','We need to find a creative solution to this issue.','NOUN','Cách giải quyết vấn đề','Chúng ta cần tìm một giải pháp sáng tạo cho vấn đề này.','giải pháp',430,NULL,_binary '\0'),(431,'A task that is difficult but motivating','Learning a foreign language is a real challenge.','NOUN','Nhiệm vụ khó khăn nhưng có tính thúc đẩy','Học ngoại ngữ là một thách thức thực sự.','thách thức',431,NULL,_binary '\0'),(432,'Making sure to avoid danger or mistakes','Be careful when crossing the busy street.','ADJECTIVE','Đảm bảo tránh nguy hiểm hoặc sai lầm','Hãy cẩn thận khi qua con đường đông xe cộ.','cẩn thận',432,NULL,_binary '\0'),(433,'A polite expression of praise','She gave me a wonderful compliment on my cooking.','NOUN','Lời bày tỏ sự khen ngợi lịch sự','Cô ấy khen ngợi tôi về món ăn tuyệt vời của tôi.','lời khen',433,NULL,_binary '\0'),(434,'To give support and confidence to someone','My parents always encouraged me to follow my dreams.','VERB','Cung cấp sự hỗ trợ và tự tin cho ai đó','Bố mẹ tôi luôn khuyến khích tôi theo đuổi ước mơ.','khuyến khích',434,NULL,_binary '\0'),(435,'To express warm approval or admiration','The teacher praised the student\'s excellent work.','VERB','Bày tỏ sự chấp thuận hoặc ngưỡng mộ nồng nhiệt','Giáo viên khen ngợi bài làm xuất sắc của học sinh.','khen ngợi',435,NULL,_binary '\0'),(436,'To give someone a reason or incentive to do something','His success story motivated me to study harder.','VERB','Cho ai đó lý do hoặc khuyến khích để làm điều gì đó','Câu chuyện thành công của anh ấy khiến tôi học chăm chỉ hơn.','tạo động lực',436,NULL,_binary '\0'),(437,'An expression used to praise someone\'s achievement','Well done on passing your driving test!','ADJECTIVE','Biểu thức dùng để khen ngợi thành tích của ai đó','Giỏi lắm khi đậu bằng lái xe!','giỏi lắm',437,NULL,_binary '\0'),(438,'An informal phrase expressing praise','Great job on finishing the report on time!','NOUN','Cụm từ thân mật bày tỏ sự khen ngợi','Làm tốt lắm khi hoàn thành báo cáo đúng hạn!','làm tốt lắm',438,NULL,_binary '\0'),(439,'To give assistance to someone','I will always support you in whatever you choose.','VERB','Cung cấp sự hỗ trợ cho ai đó','Tôi sẽ luôn ủng hộ bạn trong bất cứ điều gì bạn chọn.','ủng hộ',439,NULL,_binary '\0'),(440,'An expression encouraging continued effort','Keep it up, you are doing really well!','VERB','Biểu thức khuyến khích tiếp tục nỗ lực','Cố lên, bạn đang làm rất tốt!','cố lên',440,NULL,_binary '\0'),(441,'Evoking admiration through size or quality','Your English has improved incredibly, very impressive!','ADJECTIVE','Gợi lên sự ngưỡng mộ qua kích thước hoặc chất lượng','Tiếng Anh của bạn đã cải thiện đáng kể, rất ấn tượng!','ấn tượng',441,NULL,_binary '\0'),(442,'Having a natural ability to do something well','She is a talented singer with a beautiful voice.','ADJECTIVE','Có khả năng tự nhiên để làm điều gì đó tốt','Cô ấy là ca sĩ tài năng với giọng hát đẹp.','có tài năng',442,NULL,_binary '\0'),(443,'Exceptionally good; remarkable','His performance was absolutely outstanding.','ADJECTIVE','Đặc biệt tốt; đáng chú ý','Màn trình diễn của anh ấy thực sự xuất sắc.','xuất sắc',443,NULL,_binary '\0'),(444,'A regretful acknowledgement of an offence','I owe you an apology for what I said.','NOUN','Sự thừa nhận hối lỗi','Tôi nợ bạn một lời xin lỗi vì những gì tôi đã nói.','lời xin lỗi',444,NULL,_binary '\0'),(445,'Feeling or expressing regret','I am so sorry I broke your favourite mug.','ADJECTIVE','Cảm thấy hoặc bày tỏ sự hối hận','Tôi rất xin lỗi vì đã làm vỡ chiếc cốc yêu thích của bạn.','xin lỗi',445,NULL,_binary '\0'),(446,'To stop feeling angry towards someone','Please forgive me for being so rude.','VERB','Ngừng cảm thấy tức giận với ai đó','Xin hãy tha thứ cho tôi vì đã quá thô lỗ.','tha thứ',446,NULL,_binary '\0'),(447,'The act of forgiving someone','She asked for forgiveness after the argument.','NOUN','Hành động tha thứ cho ai đó','Cô ấy cầu xin sự tha thứ sau cuộc cãi vã.','sự tha thứ',447,NULL,_binary '\0'),(448,'To feel sad about something you did','I deeply regret not calling my friend sooner.','VERB','Cảm thấy buồn về điều bạn đã làm','Tôi rất hối tiếc vì không gọi cho bạn tôi sớm hơn.','hối tiếc',448,NULL,_binary '\0'),(449,'An acknowledgement that you are at fault','I got the date wrong, completely my mistake.','NOUN','Thừa nhận rằng bạn có lỗi','Tôi nhớ sai ngày tháng, hoàn toàn là lỗi của tôi.','lỗi của tôi',449,NULL,_binary '\0'),(450,'Used to say that something is not important','Never mind, mistakes happen to everyone.','VERB','Dùng để nói rằng điều gì đó không quan trọng','Không sao đâu, ai cũng mắc sai lầm thôi.','không sao đâu',450,NULL,_binary '\0'),(451,'Used to show acceptance of an apology','It\'s okay, I know you didn\'t mean it.','ADJECTIVE','Dùng để thể hiện sự chấp nhận lời xin lỗi','Không sao, tôi biết bạn không có ý đó.','không sao',451,NULL,_binary '\0'),(452,'Genuine; without pretence','I want to offer you a sincere apology.','ADJECTIVE','Thật lòng; không giả tạo','Tôi muốn đưa ra lời xin lỗi thành thật với bạn.','thành thật',452,NULL,_binary '\0'),(453,'Free of deceit; truthful','Being honest is the first step to making things right.','ADJECTIVE','Không có sự gian lận; thành thật','Trung thực là bước đầu tiên để sửa chữa mọi thứ.','trung thực',453,NULL,_binary '\0'),(454,'To repair a relationship or fix something broken','It took time to mend their friendship after the fight.','VERB','Sửa chữa mối quan hệ hoặc sửa thứ gì bị hỏng','Mất thời gian để hàn gắn tình bạn sau cuộc cãi vã.','hàn gắn',454,NULL,_binary '\0'),(455,'Friendly and easy to talk to.','A good manager should be approachable.','ADJECTIVE','Thân thiện và dễ dàng trò chuyện.','Một người quản lý tốt nên là người dễ gần.','Dễ gần',455,NULL,_binary '\0'),(456,'The competence or skill expected of a professional.','We were impressed by the professionalism of the team.','NOUN','Năng lực hoặc kỹ năng được mong đợi ở một chuyên gia.','Chúng tôi đã bị ấn tượng bởi sự chuyên nghiệp của đội ngũ.','Sự chuyên nghiệp',456,NULL,_binary '\0'),(457,'The fact or quality of being on time.','Punctuality is crucial for business meetings.','NOUN','Đặc điểm hoặc phẩm chất luôn đến đúng giờ.','Sự đúng giờ là rất quan trọng đối với các cuộc họp kinh doanh.','Sự đúng giờ',457,NULL,_binary '\0'),(458,'Clothes, especially fine or formal ones.','Proper business attire is required for the gala.','NOUN','Quần áo, đặc biệt là loại trang trọng.','Trang phục công sở phù hợp được yêu cầu cho buổi tiệc gala.','Trang phục',458,NULL,_binary '\0'),(459,'Polite, respectful, or considerate in manner.','The staff were extremely courteous and helpful.','ADJECTIVE','Lịch sự, tôn trọng hoặc ân cần trong cách cư xử.','Nhân viên cực kỳ lịch sự và hay giúp đỡ.','Lịch sự',459,NULL,_binary '\0'),(460,'A close and harmonious relationship.','He built a good rapport with his clients.','NOUN','Mối quan hệ mật thiết và hòa thuận.','Anh ấy đã xây dựng được mối quan hệ tốt với khách hàng.','Quan hệ tốt/Sự hòa hợp',460,NULL,_binary '\0'),(461,'Easily influenced by other people or situations.','First-time clients are often very impressionable.','ADJECTIVE','Dễ dàng bị ảnh hưởng bởi người khác hoặc tình huống.','Khách hàng lần đầu thường rất dễ bị gây ấn tượng.','Dễ bị ấn tượng/Dễ bị ảnh hưởng',461,NULL,_binary '\0'),(462,'Outward behavior or bearing.','He maintained a professional demeanour throughout the crisis.','NOUN','Hành vi hoặc phong thái bên ngoài.','Anh ấy đã duy trì một thái độ chuyên nghiệp suốt cuộc khủng hoảng.','Thái độ/Cách xử sự',462,NULL,_binary '\0'),(463,'Fluent or persuasive in speaking or writing.','His eloquent speech won over the investors.','ADJECTIVE','Trôi chảy hoặc có sức thuyết phục khi nói hoặc viết.','Bài phát biểu hùng hồn của anh ấy đã chinh phục được các nhà đầu tư.','Hùng hồn/Lưu loát',463,NULL,_binary '\0'),(464,'Graceful and elegant bearing in a person.','She showed great poise during the interview.','NOUN','Phong thái duyên dáng và thanh lịch của một người.','Cô ấy đã thể hiện sự đĩnh đạc tuyệt vời trong buổi phỏng vấn.','Sự đĩnh đạc/Tự tin',464,NULL,_binary '\0'),(466,'Exercising a compelling charm which inspires devotion.','The new CEO is incredibly charismatic.','ADJECTIVE','Thể hiện một sức hút hấp dẫn truyền cảm hứng.','Vị CEO mới cực kỳ có sức lôi cuốn.','Có sức lôi cuốn',466,NULL,_binary '\0'),(467,'Required or expected to justify actions or decisions.','You will be held accountable for any errors.','ADJECTIVE','Bị yêu cầu phải giải thích cho hành động/quyết định.','Bạn sẽ phải chịu trách nhiệm cho bất kỳ sai sót nào.','Chịu trách nhiệm giải trình',467,NULL,_binary '\0'),(468,'Supervise (a person or work), especially in an official capacity.','He was hired to oversee the project.','VERB','Theo dõi (người hoặc công việc) theo chức năng chính thức.','Anh ấy được thuê để giám sát dự án.','Giám sát',468,NULL,_binary '\0'),(469,'Put a plan, order, or course of action into effect.','The team executed the plan perfectly.','VERB','Đưa một kế hoạch hoặc hành động vào thực tiễn.','Đội ngũ đã thực hiện kế hoạch một cách hoàn hảo.','Thi hành/Thực hiện',469,NULL,_binary '\0'),(470,'Establish a working relationship with someone.','She will liaise with the marketing department.','VERB','Thiết lập mối quan hệ làm việc với ai đó.','Cô ấy sẽ phối hợp với bộ phận marketing.','Giữ liên lạc/Phối hợp',470,NULL,_binary '\0'),(471,'Observe and direct the execution of a task.','I supervise a team of ten engineers.','VERB','Quan sát và hướng dẫn thực hiện một nhiệm vụ.','Tôi giám sát một đội gồm mười kỹ sư.','Quản lý/Giám sát',471,NULL,_binary '\0'),(472,'Entrust (a task or responsibility) to another person.','A good leader knows how to delegate.','VERB','Giao nhiệm vụ hoặc trách nhiệm cho người khác.','Một nhà lãnh đạo giỏi biết cách giao phó công việc.','Giao phó/Ủy thác',472,NULL,_binary '\0'),(473,'Lead an attack or movement.','She was chosen to spearhead the new marketing campaign.','VERB','Dẫn dắt một phong trào, dự án hoặc chiến dịch.','Cô ấy được chọn để dẫn đầu chiến dịch marketing mới.','Dẫn đầu/Chủ trì',473,NULL,_binary '\0'),(474,'Work jointly on an activity or project.','Researchers are collaborating with the industry to develop new products.','VERB','Làm việc cùng nhau trong một hoạt động hoặc dự án.','Các nhà nghiên cứu đang cộng tác với ngành công nghiệp để phát triển sản phẩm mới.','Cộng tác',474,NULL,_binary '\0'),(475,'Perform more than one task at the same time.','Ability to multitask is often required in a fast-paced environment.','VERB','Thực hiện nhiều nhiệm vụ cùng một lúc.','Khả năng đa nhiệm thường được yêu cầu trong một môi trường nhịp độ nhanh.','Đa nhiệm',475,NULL,_binary '\0'),(476,'The ability to do something successfully or efficiently.','The job requires a high level of technical competency.','NOUN','Khả năng thực hiện điều gì đó thành công hoặc hiệu quả.','Công việc đòi hỏi mức độ năng lực kỹ thuật cao.','Năng lực',476,NULL,_binary '\0'),(477,'A quantifiable measure used to evaluate the success of an organization.','The sales team failed to meet their KPIs this quarter.','NOUN','Thước đo có thể định lượng được dùng để đánh giá sự thành công của một tổ chức.','Đội ngũ bán hàng đã không đạt được các KPI của họ trong quý này.','Chỉ số hiệu suất cốt yếu',477,NULL,_binary '\0'),(478,'The ability to assess and initiate things independently.','We are looking for someone who can take the initiative.','NOUN','Khả năng đánh giá và bắt đầu mọi thứ một cách độc lập.','Chúng tôi đang tìm kiếm một người có thể nắm bắt sự chủ động.','Sự chủ động/Sáng kiến',478,NULL,_binary '\0'),(479,'The action or fact of complying with a wish or command.','The company is in full compliance with safety regulations.','NOUN','Hành động hoặc sự việc tuân thủ một mong muốn hoặc mệnh lệnh.','Công ty hoàn toàn tuân thủ các quy định về an toàn.','Sự tuân thủ',479,NULL,_binary '\0'),(480,'A thing that motivates or encourages one to do something.','The bonus is a great incentive for the staff to work harder.','NOUN','Một điều gì đó thúc đẩy hoặc khuyến khích ai đó làm điều gì đó.','Tiền thưởng là một sự khích lệ lớn để nhân viên làm việc chăm chỉ hơn.','Sự khích lệ/Ưu đãi',480,NULL,_binary '\0'),(481,'A period of testing of a person\'s fitness for a job.','New employees are usually on probation for three months.','NOUN','Giai đoạn kiểm tra mức độ phù hợp của một người đối với công việc.','Nhân viên mới thường thử việc trong ba tháng.','Thời gian thử việc',481,NULL,_binary '\0'),(482,'A person with senior managerial responsibility in a business.','The chief executive is responsible for the company’s overall strategy.','NOUN','Người giữ trách nhiệm quản lý cấp cao trong doanh nghiệp.','Giám đốc điều hành chịu trách nhiệm cho chiến lược tổng thể của công ty.','Người điều hành/Ủy viên',482,NULL,_binary '\0'),(483,'Relating to managing an organization or making decisions.','She has executive powers to sign the contract.','ADJECTIVE','Liên quan đến việc quản lý tổ chức hoặc đưa ra quyết định.','Cô ấy có quyền hạn điều hành để ký kết hợp đồng.','Thuộc về điều hành/quản trị',482,NULL,_binary '\0'),(484,'A member of the board of people that manages or directs a company.','He was appointed as a non-executive director.','NOUN','Thành viên của hội đồng quản lý hoặc điều hành công ty.','Ông ấy được bổ nhiệm làm giám đốc không điều hành.','Giám đốc/Thành viên hội đồng quản trị',483,NULL,_binary '\0'),(485,'A person who is in charge of a particular activity or department.','She is the Director of Marketing.','NOUN','Người đứng đầu một hoạt động hoặc bộ phận cụ thể.','Cô ấy là Giám đốc Marketing.','Trưởng phòng/Giám đốc bộ phận',483,NULL,_binary '\0'),(486,'A local office or shop that belongs to a large organization.','The bank has branches all over the country.','NOUN','Văn phòng hoặc cửa hàng địa phương thuộc về một tổ chức lớn.','Ngân hàng có chi nhánh trên khắp cả nước.','Chi nhánh',484,NULL,_binary '\0'),(487,'To expand a business into new areas.','The company is branching out into the European market.','VERB','Mở rộng kinh doanh sang các lĩnh vực hoặc địa điểm mới.','Công ty đang mở rộng chi nhánh sang thị trường Châu Âu.','Mở rộng quy mô/Phân nhánh',484,NULL,_binary '\0'),(488,'A company that is completely controlled by another company.','The group has several subsidiaries in Asia.','NOUN','Một công ty bị kiểm soát hoàn toàn bởi một công ty khác (công ty mẹ).','Tập đoàn có vài công ty con ở Châu Á.','Công ty con',485,NULL,_binary '\0'),(489,'Less important than but related or supplementary to something.','Subsidiary evidence was presented in court.','ADJECTIVE','Ít quan trọng hơn nhưng có liên quan hoặc bổ sung cho cái gì đó.','Các bằng chứng phụ trợ đã được trình bày tại tòa.','Phụ trợ/Thứ yếu',485,NULL,_binary '\0'),(490,'A person of higher rank or status.','You should report this issue to your immediate superior.','NOUN','Người có thứ bậc hoặc địa vị cao hơn.','Bạn nên báo cáo vấn đề này cho cấp trên trực tiếp của mình.','Cấp trên/Lãnh đạo trực tiếp',486,NULL,_binary '\0'),(491,'Higher in quality or or ability.','This model is technically superior to its competitors.','ADJECTIVE','Cao hơn về chất lượng hoặc khả năng.','Mẫu này vượt trội hơn về mặt kỹ thuật so với các đối thủ.','Vượt trội/Chất lượng cao',486,NULL,_binary '\0'),(492,'A person under the authority or control of another within an organization.','He treats his subordinates with respect.','NOUN','Người dưới quyền quản lý của người khác trong tổ chức.','Anh ấy đối xử với cấp dưới của mình bằng sự tôn trọng.','Cấp dưới/Nhân viên dưới quyền',487,NULL,_binary '\0'),(493,'To treat something as less important than something else.','Individual interests are sometimes subordinated to the needs of the company.','VERB','Coi trọng cái gì đó ít hơn cái khác.','Lợi ích cá nhân đôi khi phải đặt sau nhu cầu của công ty.','Đặt xuống hàng thứ yếu',487,NULL,_binary '\0'),(494,'The process of dealing with or controlling things or people.','Effective management is key to business success.','NOUN','Quá trình xử lý hoặc kiểm soát sự vật hoặc con người.','Quản lý hiệu quả là chìa khóa dẫn đến thành công của doanh nghiệp.','Sự quản lý/Điều hành',488,NULL,_binary '\0'),(495,'The people in charge of an organization.','Management has decided to implement a new policy.','NOUN','Những người chịu trách nhiệm đứng đầu một tổ chức.','Ban lãnh đạo đã quyết định thực thi một chính sách mới.','Ban quản lý/Ban lãnh đạo',488,NULL,_binary '\0'),(496,'All the people employed by a particular organization.','The company has a staff of over 480.','NOUN','Tất cả những người được thuê bởi một tổ chức.','Công ty có đội ngũ nhân viên hơn 480 người.','Đội ngũ nhân viên',489,NULL,_binary '\0'),(497,'To provide an organization with staff.','The new clinic is staffed by experienced doctors.','VERB','Cung cấp nhân viên cho một tổ chức.','Phòng khám mới được bố trí các bác sĩ giàu kinh nghiệm.','Bố trí nhân sự',489,NULL,_binary '\0'),(498,'The person in charge of an organization or group.','She is the head of the legal department.','NOUN','Người chịu trách nhiệm chính trong một tổ chức hoặc nhóm.','Cô ấy là trưởng bộ phận pháp lý.','Người đứng đầu/Thủ trưởng',490,NULL,_binary '\0'),(499,'To be in charge of something.','He was asked to head the new task force.','VERB','Chịu trách nhiệm quản lý cái gì đó.','Anh ấy được yêu cầu lãnh đạo lực lượng đặc nhiệm mới.','Lãnh đạo/Đứng đầu',490,NULL,_binary '\0'),(500,'A partner or colleague in business or at work.','He is a close business associate of mine.','NOUN','Một đối tác hoặc đồng nghiệp trong kinh doanh hoặc công việc.','Ông ấy là một đối tác kinh doanh thân thiết của tôi.','Cộng sự/Đối tác kinh doanh',491,NULL,_binary '\0'),(501,'To connect someone or something in your mind.','Most people associate this brand with high quality.','VERB','Kết nối ai đó hoặc cái gì đó trong tâm trí.','Hầu hết mọi người liên tưởng thương hiệu này với chất lượng cao.','Liên kết/Kết giao',491,NULL,_binary '\0'),(502,'A group of people who manage a business or organization.','The board of directors met to discuss the merger.','NOUN','Nhóm người quản lý một doanh nghiệp hoặc tổ chức.','Hội đồng quản trị đã họp để thảo luận về việc sáp nhập.','Hội đồng quản trị/Ban quản trị',492,NULL,_binary '\0'),(503,'To get on a ship, aircraft, or other vehicle.','Passengers are waiting to board the plane.','VERB','Lên một con tàu, máy bay hoặc phương tiện khác.','Hành khách đang chờ để lên máy bay.','Lên (tàu/máy bay...)',492,NULL,_binary '\0'),(504,'People employed in an organization or engaged in an organized undertaking.','All personnel are required to attend the safety training.','NOUN','Những người làm việc trong một tổ chức hoặc tham gia một hoạt động tập thể.','Tất cả nhân sự được yêu cầu tham dự buổi đào tạo an toàn.','Nhân sự/Nhân viên',493,NULL,_binary '\0'),(505,'The department in an organization that deals with the people it employs.','Please contact Personnel for more information about the job.','NOUN','Bộ phận trong tổ chức giải quyết các vấn đề liên quan đến nhân viên.','Vui lòng liên hệ Phòng nhân sự để biết thêm thông tin về công việc.','Phòng nhân sự',493,NULL,_binary '\0'),(506,'A separate part of a large organization.','The sales division is performing well this year.','NOUN','Một phần riêng biệt của một tổ chức lớn.','Bộ phận bán hàng đang hoạt động rất tốt trong năm nay.','Bộ phận/Phân ban',494,NULL,_binary '\0'),(507,'The action of separating something into parts.','The division of labor increases efficiency.','NOUN','Hành động chia cái gì đó thành nhiều phần.','Sự phân công lao động giúp tăng hiệu quả.','Sự chia cắt/Sự phân chia',494,NULL,_binary '\0'),(508,'A position within the hierarchy of an organization.','He rose through the ranks to become a manager.','NOUN','Vị trí trong hệ thống phân cấp của tổ chức.','Anh ấy đã thăng tiến qua các cấp bậc để trở thành người quản lý.','Thứ hạng/Cấp bậc',495,NULL,_binary '\0'),(509,'To give someone or something a place in a graded scale.','The company is ranked first in terms of innovation.','VERB','Đưa ai đó hoặc cái gì đó vào một vị trí trong thang đo.','Công ty được xếp hạng nhất về mặt đổi mới.','Xếp hạng/Đứng hàng',495,NULL,_binary '\0'),(510,'Relating to a large company or group.','We need to update our corporate identity.','ADJECTIVE','Liên quan đến một công ty lớn hoặc một tập đoàn.','Chúng ta cần cập nhật bộ nhận diện thương hiệu tập đoàn.','Thuộc về doanh nghiệp/tập đoàn',496,NULL,_binary '\0'),(511,'Involving or shared by all members of a group.','Corporate responsibility is essential nowadays.','ADJECTIVE','Liên quan đến hoặc được chia sẻ bởi tất cả các thành viên trong nhóm.','Trách nhiệm tập thể là điều thiết yếu ngày nay.','Chung/Tập thể',496,NULL,_binary '\0'),(512,'The action or process of interacting with others to exchange information and develop professional contacts.','Networking is essential for career advancement.','NOUN','Quá trình tương tác với người khác để trao đổi thông tin và phát triển các mối quan hệ chuyên nghiệp.','Kết nối mạng lưới quan hệ là điều thiết yếu để thăng tiến sự nghiệp.','Hoạt động kết nối',497,NULL,_binary '\0'),(513,'The linking of computers to operate interactively.','The company is upgrading its internal networking.','NOUN','Việc liên kết các máy tính để vận hành tương tác.','Công ty đang nâng cấp hệ thống mạng nội bộ.','Hệ thống mạng',497,NULL,_binary '\0'),(514,'A person regarded as a potential customer or client.','We are focusing on converting every prospect into a loyal customer.','NOUN','Một người được xem là khách hàng tiềm năng trong tương lai.','Chúng tôi đang tập trung vào việc biến mọi khách hàng tiềm năng thành khách hàng trung thành.','Khách hàng tiềm năng',498,NULL,_binary '\0'),(515,'The possibility or likelihood of some future event occurring.','There is little prospect of an immediate improvement.','NOUN','Khả năng xảy ra của một sự kiện trong tương lai.','Có rất ít triển vọng cho một sự cải thiện ngay lập tức.','Triển vọng/Khả năng',498,NULL,_binary '\0'),(516,'A person one knows slightly, but who is not a close friend.','He is a business acquaintance I met at the conference.','NOUN','Một người mà ta biết sơ qua nhưng không phải bạn thân.','Anh ấy là một người quen trong kinh doanh mà tôi đã gặp tại hội nghị.','Người quen',499,NULL,_binary '\0'),(517,'Knowledge or experience of something.','I have some acquaintance with French literature.','NOUN','Kiến thức hoặc kinh nghiệm về một điều gì đó.','Tôi có một chút hiểu biết về văn học Pháp.','Sự hiểu biết/Kiến thức',499,NULL,_binary '\0'),(518,'An action or event that follows or consolidates a previous one.','I sent a follow-up email after the meeting.','NOUN','Một hành động hoặc sự kiện theo sau để củng cố cái trước đó.','Tôi đã gửi một email theo dõi sau cuộc họp.','Hành động tiếp nối/Hậu mãi',500,NULL,_binary '\0'),(519,'Continuing something that has already started.','We scheduled a follow-up interview for next week.','ADJECTIVE','Tiếp tục một việc gì đó đã bắt đầu.','Chúng tôi đã lên lịch một cuộc phỏng vấn tiếp theo vào tuần tới.','Tiếp theo/Duy trì',500,NULL,_binary '\0'),(520,'The practice of exchanging things with others for mutual benefit.','Networking is based on the principle of reciprocity.','NOUN','Việc trao đổi mọi thứ với người khác để cùng có lợi.','Kết nối quan hệ dựa trên nguyên tắc có đi có lại.','Sự có đi có lại',501,NULL,_binary '\0'),(521,'To send someone to a person or place for help or advice.','My doctor referred me to a specialist.','VERB','Gửi ai đó đến một người hoặc nơi nào đó để được giúp đỡ hoặc tư vấn.','Bác sĩ của tôi đã giới thiệu tôi đến một chuyên gia.','Giới thiệu/Chỉ dẫn',502,NULL,_binary '\0'),(522,'To mention or speak about someone or something.','Please refer to the notes at the end of the book.','VERB','Đề cập hoặc nói về ai đó hoặc cái gì đó.','Vui lòng tham khảo (nhắc đến) các ghi chú ở cuối sách.','Ám chỉ/Nhắc đến',502,NULL,_binary '\0'),(523,'A relationship in which a person or thing is linked with something else.','He has good connections in the industry.','NOUN','Mối quan hệ mà trong đó một người hoặc vật được liên kết với thứ khác.','Anh ấy có những mối quan hệ tốt trong ngành.','Sự kết nối/Mối quan hệ',503,NULL,_binary '\0'),(524,'The point at which two or more things are connected.','Check the internet connection.','NOUN','Điểm mà tại đó hai hoặc nhiều thứ được nối lại với nhau.','Kiểm tra kết nối internet.','Điểm kết nối/Đầu nối',503,NULL,_binary '\0'),(525,'The process of encouraging people to be interested in the work of an organization.','We need to improve employee engagement.','NOUN','Quá trình khuyến khích mọi người quan tâm đến công việc của tổ chức.','Chúng ta cần cải thiện sự gắn kết của nhân viên.','Sự tương tác/Tham gia',504,NULL,_binary '\0'),(526,'An arrangement to do something or go somewhere at a fixed time.','I have a previous engagement and cannot attend the dinner.','NOUN','Sự sắp xếp để làm gì đó hoặc đi đâu đó vào thời gian cố định.','Tôi đã có một cuộc hẹn trước đó nên không thể tham dự bữa tối.','Cuộc hẹn/Cam kết công việc',504,NULL,_binary '\0'),(527,'Polite conversation about unimportant or uncontroversial matters.','I am not very good at making small talk.','NOUN','Cuộc trò chuyện lịch sự về những vấn đề không quan trọng.','Tôi không giỏi nói chuyện xã giao lắm.','Chuyện phiếm/Xã giao',505,NULL,_binary '\0'),(528,'To speak to someone for the first time about something.','I approached the director about a raise.','VERB','Nói chuyện với ai đó lần đầu tiên về một vấn đề gì đó.','Tôi đã tiếp cận giám đốc để đặt vấn đề tăng lương.','Tiếp cận/Đặt vấn đề',506,NULL,_binary '\0'),(529,'A way of dealing with a situation or problem.','We need a new approach to the market.','NOUN','Một cách xử lý một tình huống hoặc vấn đề.','Chúng ta cần một cách tiếp cận thị trường mới.','Phương pháp/Cách tiếp cận',506,NULL,_binary '\0'),(530,'Held in common by two or more parties.','We were introduced by a mutual friend.','ADJECTIVE','Được nắm giữ chung bởi hai hoặc nhiều bên.','Chúng tôi được giới thiệu bởi một người bạn chung.','Chung/Lẫn nhau',507,NULL,_binary '\0'),(531,'The customary code of polite behavior in society or among members of a particular profession.','Business etiquette varies from country to country.','NOUN','Bộ quy tắc về hành vi lịch sự trong xã hội hoặc trong một ngành nghề.','Nghi thức kinh doanh thay đổi tùy theo từng quốc gia.','Nghi thức/Phép tắc',508,NULL,_binary '\0'),(532,'To communicate or be involved with someone.','The students are encouraged to interact with each other.','VERB','Giao tiếp hoặc tham gia cùng ai đó.','Sinh viên được khuyến khích tương tác với nhau.','Tương tác/Giao tiếp',509,NULL,_binary '\0'),(533,'The action of introducing someone or something.','My boss gave me a brief introduction to the team.','NOUN','Hành động giới thiệu ai đó hoặc cái gì đó.','Sếp của tôi đã giới thiệu ngắn gọn tôi với cả đội.','Lời giới thiệu/Sự giới thiệu',510,NULL,_binary '\0'),(534,'A preliminary part, as of a book or musical composition.','Read the introduction before the first chapter.','NOUN','Phần sơ khởi của một cuốn sách hoặc bản nhạc.','Hãy đọc lời mở đầu trước chương đầu tiên.','Lời mở đầu/Lời dẫn',510,NULL,_binary '\0'),(535,'An act of referring someone or something for consultation, review, or further action.','Most of our new business comes from referrals.','NOUN','Hành động giới thiệu ai đó để tham khảo hoặc hành động tiếp theo.','Hầu hết các mảng kinh doanh mới của chúng tôi đến từ sự giới thiệu.','Sự giới thiệu/Thư giới thiệu',511,NULL,_binary '\0'),(536,'A person\'s education, experience, and social circumstances.','The candidate has a strong background in software engineering.','NOUN','Quá trình giáo dục, kinh nghiệm và hoàn cảnh xã hội của một người.','Ứng viên có nền tảng vững chắc về kỹ thuật phần mềm.','Nền tảng/Lý lịch',512,NULL,_binary '\0'),(537,'The area or scenery behind the main object of contemplation.','The mountains were visible in the background.','NOUN','Khu vực hoặc phong cảnh phía sau vật thể chính.','Những ngọn núi có thể nhìn thấy ở phía hậu cảnh.','Hậu cảnh/Phông nền',512,NULL,_binary '\0'),(538,'Expert skill or knowledge in a particular field.','She has considerable expertise in financial planning.','NOUN','Kỹ năng hoặc kiến thức chuyên gia trong một lĩnh vực cụ thể.','Cô ấy có kiến thức chuyên môn đáng kể trong việc lập kế hoạch tài chính.','Kiến thức chuyên môn/Sự tinh thông',513,NULL,_binary '\0'),(539,'Something that has been achieved successfully.','Completing the marathon was a great personal accomplishment.','NOUN','Một điều gì đó đã được đạt được một cách thành công.','Hoàn thành cuộc chạy marathon là một thành tích cá nhân lớn.','Thành tựu/Thành tích',514,NULL,_binary '\0'),(540,'An acquired skill or capacity.','Playing the piano is one of her many accomplishments.','NOUN','Một kỹ năng hoặc năng lực có được thông qua học tập.','Chơi piano là một trong số nhiều tài lẻ của cô ấy.','Tài lẻ/Kỹ năng hoàn thiện',514,NULL,_binary '\0'),(541,'A qualification, achievement, or aspect of a person\'s background.','She has the perfect academic credentials for the job.','NOUN','Bằng cấp, thành tựu hoặc một khía cạnh trong lý lịch của một người.','Cô ấy có bằng cấp học thuật hoàn hảo cho công việc.','Chứng chỉ/Bằng cấp',515,NULL,_binary '\0'),(542,'Information such as a username and password used to sign in.','Don’t share your login credentials with anyone.','NOUN','Thông tin như tên người dùng và mật khẩu được sử dụng để đăng nhập.','Đừng chia sẻ thông tin đăng nhập của bạn với bất kỳ ai.','Thông tin xác thực/Đăng nhập',515,NULL,_binary '\0'),(543,'All the achievements or failures of someone or something in the past.','The company has a proven track record of success.','NOUN','Tất cả các thành tựu hoặc thất bại của ai đó trong quá khứ.','Công ty có một lịch sử thành công đã được chứng minh.','Lịch sử thành tích/Hồ sơ năng lực',516,NULL,_binary '\0'),(544,'A high degree of skill; expertise.','Candidates must demonstrate proficiency in English.','NOUN','Mức độ kỹ năng hoặc trình độ chuyên môn cao.','Các ứng viên phải chứng minh sự thông thạo tiếng Anh.','Sự thông thạo/Thành thạo',517,NULL,_binary '\0'),(545,'An experienced and trusted adviser.','He was a friend and mentor to many young engineers.','NOUN','Một người cố vấn giàu kinh nghiệm và đáng tin cậy.','Ông ấy là một người bạn và là người cố vấn cho nhiều kỹ sư trẻ.','Người cố vấn',518,NULL,_binary '\0'),(546,'To advise or train someone.','The senior manager mentors several junior staff members.','VERB','Đưa ra lời khuyên hoặc đào tạo cho ai đó.','Người quản lý cấp cao cố vấn cho một vài nhân viên cấp dưới.','Cố vấn/Hướng dẫn',518,NULL,_binary '\0'),(547,'A range of work that shows someone\'s ability.','The designer showed us her portfolio during the interview.','NOUN','Tập hợp các sản phẩm/công việc thể hiện năng lực của ai đó.','Nhà thiết kế đã cho chúng tôi xem hồ sơ năng lực của cô ấy trong buổi phỏng vấn.','Hồ sơ năng lực/Danh mục tác phẩm',519,NULL,_binary '\0'),(548,'A collection of financial investments.','He has a diverse investment portfolio.','NOUN','Tập hợp các khoản đầu tư tài chính.','Anh ấy có một danh mục đầu tư đa dạng.','Danh mục đầu tư',519,NULL,_binary '\0'),(549,'To examine thoroughly and repair or improve.','The government plans to overhaul the education system.','VERB','Kiểm tra kỹ lưỡng và sửa chữa hoặc cải thiện.','Chính phủ có kế hoạch cải tổ hệ thống giáo dục.','Cải tổ/Đại tu',520,NULL,_binary '\0'),(550,'A thorough examination and repair.','The engine needs a complete overhaul.','NOUN','Việc kiểm tra kỹ lưỡng và sửa chữa tổng thể.','Động cơ cần một cuộc đại tu hoàn chỉnh.','Sự cải cách/Sự đại tu',520,NULL,_binary '\0'),(551,'The path followed by a person\'s career or an object.','The company is on an upward growth trajectory.','NOUN','Con đường phát triển sự nghiệp của một người hoặc của một vật thể.','Công ty đang trên một lộ trình tăng trưởng đi lên.','Lộ trình phát triển/Quỹ đạo',521,NULL,_binary '\0'),(552,'Having the practical knowledge or qualifications to do something.','She is highly qualified for the position.','ADJECTIVE','Có kiến thức thực tế hoặc bằng cấp để làm điều gì đó.','Cô ấy rất có năng lực cho vị trí này.','Đủ điều kiện/Có năng lực',522,NULL,_binary '\0'),(553,'Not complete or absolute; limited.','The plan received only qualified support from the board.','ADJECTIVE','Không hoàn toàn hoặc tuyệt đối; bị giới hạn.','Kế hoạch chỉ nhận được sự ủng hộ dè dặt từ hội đồng.','Dè dặt/Có điều kiện kèm theo',522,NULL,_binary '\0'),(554,'Able to adapt or be adapted to many different functions or activities.','She is a versatile employee who can handle various roles.','ADJECTIVE','Có thể thích nghi với nhiều chức năng hoặc hoạt động khác nhau.','Cô ấy là một nhân viên đa năng có thể đảm nhận nhiều vai trò khác nhau.','Đa năng/Linh hoạt',523,NULL,_binary '\0'),(555,'The position of a student or trainee who works in an organization.','Jane is doing an internship at a law firm.','NOUN','Vị trí của sinh viên hoặc thực tập sinh làm việc trong một tổ chức.','Jane đang thực tập tại một công ty luật.','Kỳ thực tập',524,NULL,_binary '\0'),(556,'A letter from a previous employer testifying to someone\'s ability.','We need a reference from your former employer.','NOUN','Thư từ chủ cũ chứng thực năng lực của ai đó.','Chúng tôi cần một thư giới thiệu từ chủ cũ của bạn.','Thư giới thiệu/Người tham chiếu',525,NULL,_binary '\0'),(557,'The action of mentioning or alluding to something.','Please keep this manual for future reference.','NOUN','Hành động đề cập đến hoặc nhắc đến điều gì đó.','Vui lòng giữ hướng dẫn này để tham khảo sau này.','Sự tham chiếu/Tham khảo',525,NULL,_binary '\0'),(558,'An action or event marking a significant change or stage in development.','The launch of the product was a major milestone for the startup.','NOUN','Một hành động hoặc sự kiện đánh dấu một thay đổi hoặc giai đoạn phát triển quan trọng.','Việc ra mắt sản phẩm là một cột mốc lớn đối với công ty khởi nghiệp.','Cột mốc/Giai đoạn quan trọng',526,NULL,_binary '\0'),(559,'The land and buildings owned or used by an organization.','Smoking is not allowed on the office premises.','NOUN','Đất đai và các tòa nhà thuộc sở hữu hoặc được sử dụng bởi một tổ chức.','Không được phép hút thuốc trong khuôn viên văn phòng.','Cơ sở/Khuôn viên',527,NULL,_binary '\0'),(560,'The way in which the parts of something are arranged.','Let me show you the layout of our open-plan office.','NOUN','Cách mà các bộ phận của một cái gì đó được sắp xếp.','Để tôi cho bạn xem sơ đồ bố trí của văn phòng mở của chúng tôi.','Bố cục/Sơ đồ bố trí',528,NULL,_binary '\0'),(561,'The design or configuration of a page or screen.','The magazine has a very modern layout.','NOUN','Thiết kế hoặc cấu hình của một trang giấy hoặc màn hình.','Tạp chí này có bố cục rất hiện đại.','Bản thiết kế/Định dạng',528,NULL,_binary '\0'),(562,'A place, amenity, or piece of equipment provided for a particular purpose.','The company provides excellent sports facilities for employees.','NOUN','Một nơi, tiện ích hoặc thiết bị được cung cấp cho một mục đích cụ thể.','Công ty cung cấp các cơ sở vật chất thể thao tuyệt vời cho nhân viên.','Cơ sở vật chất/Tiện nghi',529,NULL,_binary '\0'),(563,'A natural ability to do or learn something easily.','He has a great facility for languages.','NOUN','Khả năng bẩm sinh để làm hoặc học điều gì đó dễ dàng.','Anh ấy có năng khiếu thiên bẩm về ngôn ngữ.','Năng khiếu/Sự khéo léo',529,NULL,_binary '\0'),(564,'A small partitioned-off area of a room.','She decorated her cubicle with plants.','NOUN','Một khu vực nhỏ được ngăn ra trong một căn phòng (thường thấy ở văn phòng cũ).','Cô ấy trang trí góc làm việc của mình bằng cây xanh.','Góc làm việc/Ngăn nhỏ',530,NULL,_binary '\0'),(565,'A place or building where a specified activity or service is based.','This is the printing station where you can collect your documents.','NOUN','Nơi hoặc tòa nhà đặt một hoạt động hoặc dịch vụ cụ thể.','Đây là trạm in ấn nơi bạn có thể nhận tài liệu của mình.','Trạm/Vị trí (làm việc)',531,NULL,_binary '\0'),(566,'To assign to a particular place or post.','Security guards are stationed at every entrance.','VERB','Giao cho một vị trí hoặc đồn bốt cụ thể.','Các nhân viên an ninh được bố trí tại mọi lối vào.','Bố trí/Sắp đặt vào vị trí',531,NULL,_binary '\0'),(567,'A small room or cupboard in which food, crockery, and cutlery are kept.','Free coffee is available in the office pantry.','NOUN','Phòng nhỏ chứa đồ ăn, bát đĩa và dụng cụ ăn uống.','Cà phê miễn phí luôn có sẵn trong phòng bếp văn phòng.','Phòng chứa thực phẩm/Bếp văn phòng',532,NULL,_binary '\0'),(568,'A large entrance hall of a building.','I will meet you in the main lobby at 9 AM.','NOUN','Một sảnh vào lớn của một tòa nhà.','Tôi sẽ gặp bạn ở sảnh chính lúc 9 giờ sáng.','Sảnh/Hành lang đợi',533,NULL,_binary '\0'),(569,'To try to influence a politician or the government.','They are lobbying for better working conditions.','VERB','Cố gắng gây ảnh hưởng đến chính trị gia hoặc chính phủ.','Họ đang vận động hành lang để có điều kiện làm việc tốt hơn.','Vận động hành lang',533,NULL,_binary '\0'),(570,'The right or opportunity to use or benefit from something.','You need a key card for access to the server room.','NOUN','Quyền hoặc cơ hội để sử dụng hoặc hưởng lợi từ điều gì đó.','Bạn cần thẻ từ để có quyền vào phòng máy chủ.','Quyền truy cập/Lối vào',534,NULL,_binary '\0'),(571,'To reach or enter a place.','It is difficult to access the building after 8 PM.','VERB','Tiếp cận hoặc đi vào một nơi.','Rất khó để vào tòa nhà sau 8 giờ tối.','Truy cập/Đi vào',534,NULL,_binary '\0'),(572,'To provide lodging or sufficient space for.','This conference room can accommodate up to 48 people.','VERB','Cung cấp nơi ở hoặc đủ không gian cho.','Phòng hội thảo này có thể chứa tới 48 người.','Chứa được/Cung cấp chỗ ở',535,NULL,_binary '\0'),(573,'To fit in with the wishes or needs of.','We try to accommodate all special requests from clients.','VERB','Phù hợp với mong muốn hoặc nhu cầu của ai đó.','Chúng tôi cố gắng đáp ứng mọi yêu cầu đặc biệt từ khách hàng.','Đáp ứng/Thoả hiệp',535,NULL,_binary '\0'),(575,'To praise formally or officially.','The CEO commended the team for their hard work.','VERB','Khen ngợi một cách chính thức.','CEO đã khen ngợi đội ngũ vì sự làm việc chăm chỉ của họ.','Khen ngợi/Tuyên dương',537,NULL,_binary '\0'),(576,'To entrust someone or something to.','We commend these matters to your care.','VERB','Giao ai đó hoặc cái gì đó cho ai đó.','Chúng tôi giao phó những vấn đề này cho sự chăm sóc của bạn.','Giao phó',537,NULL,_binary '\0'),(577,'A public service such as water, gas, or electricity.','The cost of utilities is included in the rent.','NOUN','Một dịch vụ công cộng như nước, ga hoặc điện.','Chi phí điện nước đã bao gồm trong tiền thuê.','Dịch vụ tiện ích (điện, nước...)',538,NULL,_binary '\0'),(578,'The state of being useful, profitable, or beneficial.','This tool has limited utility for our current needs.','NOUN','Trạng thái hữu ích, có lợi.','Công cụ này có giá trị sử dụng hạn chế đối với nhu cầu hiện tại của chúng tôi.','Tính hữu dụng/Giá trị sử dụng',538,NULL,_binary '\0'),(579,'An area used or required for one’s work.','We offer flexible workspaces for remote employees.','NOUN','Khu vực được sử dụng hoặc yêu cầu cho công việc của một người.','Chúng tôi cung cấp không gian làm việc linh hoạt cho nhân viên làm việc từ xa.','Không gian làm việc',539,NULL,_binary '\0'),(580,'Signs collectively, especially commercial or public ones.','Better signage is needed to help visitors find the exit.','NOUN','Tập hợp các biển báo, đặc biệt là các biển thương mại hoặc công cộng.','Cần có hệ thống biển báo tốt hơn để giúp khách tìm thấy lối thoát.','Hệ thống biển báo/Chỉ dẫn',540,NULL,_binary '\0'),(581,'An area or stretch of land having a particular characteristic.','This is a quiet zone for focused work only.','NOUN','Một khu vực có đặc điểm riêng biệt.','Đây là khu vực yên tĩnh chỉ dành cho làm việc tập trung.','Khu vực/Đới',541,NULL,_binary '\0'),(582,'To divide into zones.','The city was zoned for commercial development.','VERB','Chia thành các khu vực.','Thành phố đã được phân vùng để phát triển thương mại.','Phân vùng/Chia khu vực',541,NULL,_binary '\0'),(583,'A speech or act that attempts to persuade someone to buy or do something.','He gave a three-minute pitch to the investors.','NOUN','Một bài nói ngắn gọn nhằm thuyết phục ai đó mua hàng hoặc đầu tư.','Anh ấy đã có một bài thuyết trình 3 phút trước các nhà đầu tư.','Bài thuyết trình/Lời chào hàng',542,NULL,_binary '\0'),(584,'To try to persuade someone to buy or accept something.','She pitched her idea to the marketing team.','VERB','Cố gắng thuyết phục ai đó mua hoặc chấp nhận điều gì.','Cô ấy đã trình bày và thuyết phục đội marketing về ý tưởng của mình.','Thuyết phục/Chào hàng',542,NULL,_binary '\0'),(585,'In a way that is brief but comprehensive.','The report summarizes the main points concisely.','ADVERB','Một cách ngắn gọn nhưng đầy đủ thông tin.','Bản báo cáo tóm tắt các điểm chính một cách súc tích.','Ngắn gọn/Súc tích',543,NULL,_binary '\0'),(586,'Evoking interest, attention, or admiration in a powerfully irresistible way.','The startup has a compelling vision for the future.','ADJECTIVE','Gợi lên sự quan tâm hoặc ngưỡng mộ một cách mạnh mẽ.','Công ty khởi nghiệp có một tầm nhìn đầy hấp dẫn về tương lai.','Hấp dẫn/Đầy thuyết phục',544,NULL,_binary '\0'),(587,'A service or feature intended to make a company or product attractive to customers.','Your elevator pitch should highlight your unique value proposition.','NOUN','Giá trị cốt lõi làm cho sản phẩm hoặc cá nhân trở nên hấp dẫn đối với khách hàng/nhà tuyển dụng.','Bài nói của bạn nên làm nổi bật giá trị cốt lõi độc đáo của mình.','Tuyên ngôn giá trị',545,NULL,_binary '\0'),(588,'A thing that is designed to catch people\'s attention.','The first sentence of your pitch needs to be a strong hook.','NOUN','Một thứ được thiết kế để thu hút sự chú ý của mọi người ngay lập tức.','Câu đầu tiên trong bài nói của bạn cần phải là một điểm nhấn mạnh mẽ.','Điểm nhấn/Lời dẫn dụ',546,NULL,_binary '\0'),(590,'A thing aimed at or sought; a goal.','My primary objective is to find a role in project management.','NOUN','Đích đến hoặc điều mà ai đó cố gắng đạt được.','Mục tiêu chính của tôi là tìm một vị trí trong quản lý dự án.','Mục tiêu',548,NULL,_binary '\0'),(591,'Not influenced by personal feelings or opinions.','We need an objective assessment of the project.','ADJECTIVE','Không bị ảnh hưởng bởi cảm xúc cá nhân.','Chúng ta cần một sự đánh giá khách quan về dự án.','Khách quan',548,NULL,_binary '\0'),(593,'To make or adapt for a particular purpose or person.','You should tailor your pitch to each specific audience.','VERB','Thay đổi hoặc điều chỉnh để phù hợp với mục đích hoặc đối tượng cụ thể.','Bạn nên điều chỉnh bài giới thiệu của mình cho phù hợp với từng đối tượng cụ thể.','Điều chỉnh/Thiết kế riêng',550,NULL,_binary '\0'),(595,'The powerful effect that something has on a situation or person.','The training had a positive impact on my career.','NOUN','Hiệu ứng mạnh mẽ mà điều gì đó tạo ra.','Buổi đào tạo đã có tác động tích cực đến sự nghiệp của tôi.','Sự ảnh hưởng/Tác động',552,NULL,_binary '\0'),(596,'To have a strong effect on someone or something.','The new policy will impact all employees.','VERB','Tạo ra hiệu ứng mạnh lên ai đó hoặc cái gì đó.','Chính sách mới sẽ tác động đến tất cả nhân viên.','Tác động/Ảnh hưởng',552,NULL,_binary '\0'),(597,'Having or showing the capacity to become or develop into something in the future.','He is a potential candidate for the manager position.','ADJECTIVE','Có khả năng trở thành điều gì đó trong tương lai.','Anh ấy là một ứng viên tiềm năng cho vị trí quản lý.','Tiềm năng/Tiềm tàng',553,NULL,_binary '\0'),(598,'Latent qualities or abilities that may be developed.','The team has a lot of potential.','NOUN','Các phẩm chất hoặc khả năng tiềm ẩn có thể phát triển được.','Đội ngũ này có rất nhiều tiềm năng.','Tiềm lực/Khả năng',553,NULL,_binary '\0'),(599,'An exhortation or stimulus to do something in order to achieve an aim.','End your pitch with a clear call to action, like asking for a meeting.','NOUN','Một lời mời gọi hoặc sự thúc đẩy làm điều gì đó để đạt được mục tiêu.','Kết thúc bài giới thiệu bằng một lời kêu gọi hành động rõ ràng, như yêu cầu một cuộc hẹn.','Lời kêu gọi hành động',554,NULL,_binary '\0'),(602,'A list of items to be discussed at a formal meeting.','The next item on the agenda is the budget review.','NOUN','Danh sách các đề mục cần được thảo luận trong một cuộc họp chính thức.','Mục tiếp theo trong chương trình nghị sự là xem xét ngân sách.','Chương trình nghị sự/Nội dung họp',557,NULL,_binary '\0'),(604,'To designate or treat (something) as being very or most important.','We need to prioritize the most urgent tasks on the list.','VERB','Xác định điều gì đó là quan trọng nhất để thực hiện trước.','Chúng ta cần ưu tiên các nhiệm vụ khẩn cấp nhất trong danh sách.','Ưu tiên',559,NULL,_binary '\0'),(605,'An individual article or unit, especially one that is part of a list.','Is there any other item you wish to add to the agenda?','NOUN','Một đơn vị hoặc mục riêng lẻ nằm trong một danh sách.','Còn đề mục nào khác bạn muốn thêm vào chương trình họp không?','Đề mục/Khoản',560,NULL,_binary '\0'),(606,'A specified period of time within which something exists or takes place.','What is the timeframe for completing this project?','NOUN','Một khoảng thời gian xác định để một việc gì đó diễn ra.','Khung thời gian để hoàn thành dự án này là bao lâu?','Khung thời gian',561,NULL,_binary '\0'),(607,'To distribute (resources or duties) for a particular purpose.','We have allocated ten minutes for each presentation.','VERB','Phân chia nguồn lực, thời gian hoặc nhiệm vụ cho một mục đích cụ thể.','Chúng tôi đã phân bổ 10 phút cho mỗi bài thuyết trình.','Phân bổ/Chia phần',562,NULL,_binary '\0'),(608,'A general agreement.','The goal of this meeting is to reach a consensus on the new policy.','NOUN','Sự nhất trí chung giữa các thành viên trong nhóm.','Mục tiêu của cuộc họp này là đạt được sự đồng thuận về chính sách mới.','Sự đồng thuận/Nhất trí',563,NULL,_binary '\0'),(609,'To finish something, especially a discussion or a meeting.','Let\'s wrap up this meeting by summarizing our next steps.','VERB','Hoàn thành một cuộc thảo luận hoặc cuộc họp.','Hãy kết thúc cuộc họp này bằng cách tóm tắt các bước tiếp theo.','Kết thúc/Hoàn tất',564,NULL,_binary '\0'),(610,'Items that are not on the agenda but can be discussed at the end of a meeting.','Is there any other business we need to discuss before we finish?','NOUN','Các nội dung không nằm trong nghị sự chính nhưng được thảo luận vào cuối buổi họp.','Còn vấn đề phát sinh nào khác chúng ta cần thảo luận trước khi kết thúc không?','Vấn đề phát sinh khác',565,NULL,_binary '\0'),(611,'Of short duration; concise.','The manager gave a brief introduction to the agenda.','ADJECTIVE','Diễn ra trong thời gian ngắn hoặc súc tích.','Người quản lý đã đưa ra một lời giới thiệu ngắn gọn về chương trình họp.','Ngắn gọn/Tóm lược',566,NULL,_binary '\0'),(612,'To instruct or inform someone thoroughly, especially in preparation for a task.','I need to brief you on the upcoming project.','VERB','Hướng dẫn hoặc cung cấp thông tin kỹ lưỡng cho ai đó.','Tôi cần phổ biến cho bạn về dự án sắp tới.','Phổ biến/Tóm tắt nhiệm vụ',566,NULL,_binary '\0'),(613,'The action of making a statement or situation less confused and more comprehensible.','If anyone needs clarification on the agenda, please ask now.','NOUN','Hành động giải thích để làm cho một vấn đề dễ hiểu hơn.','Nếu ai cần làm rõ điều gì về chương trình họp, vui lòng hỏi ngay bây giờ.','Sự làm rõ/Giải thích lại',567,NULL,_binary '\0'),(615,'A general review or summary of a subject.','The director provided an overview of the company’s performance.','NOUN','Một bản tóm tắt hoặc đánh giá chung về một chủ đề.','Giám đốc đã đưa ra một cái nhìn tổng quan về hiệu suất của công ty.','Tổng quan/Tóm tắt chung',569,NULL,_binary '\0'),(616,'Closely connected or appropriate to what is being done or considered.','Please keep your comments relevant to the current topic.','ADJECTIVE','Có mối liên hệ chặt chẽ hoặc phù hợp với những gì đang được thực hiện.','Vui lòng giữ các bình luận của bạn liên quan đến chủ đề hiện tại.','Liên quan/Hữu quan',570,NULL,_binary '\0'),(617,'The extent of the area or subject matter that something deals with or to which it is relevant.','We need to define the scope of the meeting to avoid wasting time.','NOUN','Mức độ hoặc lĩnh vực mà một vấn đề đề cập đến.','Chúng ta cần xác định phạm vi của cuộc họp để tránh lãng phí thời gian.','Phạm vi/Tầm nhìn',571,NULL,_binary '\0'),(618,'To suggest a lot of ideas for a future activity very quickly.','We need to brainstorm some new marketing strategies.','VERB','Đề xuất nhiều ý tưởng cho một hoạt động trong tương lai một cách nhanh chóng.','Chúng ta cần thảo luận để tìm ra một vài chiến lược marketing mới.','Động não/Thảo luận tìm ý tưởng',572,NULL,_binary '\0'),(619,'A new method, idea, product, etc.','The company encourages innovation in every department.','NOUN','Một phương pháp, ý tưởng hoặc sản phẩm mới.','Công ty khuyến khích sự đổi mới ở mọi bộ phận.','Sự đổi mới/Sáng kiến',573,NULL,_binary '\0'),(621,'A deep understanding of a person or thing.','The data provided valuable insights into customer behavior.','NOUN','Sự hiểu biết sâu sắc về một người hoặc một sự vật.','Dữ liệu đã cung cấp những cái nhìn sâu sắc quý giá về hành vi khách hàng.','Sự thấu hiểu/Cái nhìn sâu sắc',575,NULL,_binary '\0'),(622,'Thinking in an original or creative way.','We need some out-of-the-box thinking to solve this issue.','ADJECTIVE','Suy nghĩ theo một cách nguyên bản hoặc sáng tạo, không bị gò bó.','Chúng ta cần một vài suy nghĩ đột phá để giải quyết vấn đề này.','Sáng tạo/Ngoài khuôn khổ',576,NULL,_binary '\0'),(623,'The action of working with someone to produce something.','The project was a successful collaboration between two teams.','NOUN','Hành động làm việc cùng ai đó để tạo ra thứ gì đó.','Dự án là một sự hợp tác thành công giữa hai đội.','Sự cộng tác/Hợp tác',577,NULL,_binary '\0'),(624,'An idea or plan put forward for consideration.','Do you have any suggestions for the new logo?','NOUN','Một ý tưởng hoặc kế hoạch được đưa ra để xem xét.','Bạn có gợi ý nào cho logo mới không?','Lời đề nghị/Sự gợi ý',578,NULL,_binary '\0'),(625,'Possible to do easily or conveniently.','It\'s a great idea, but I’m not sure if it’s financially feasible.','ADJECTIVE','Có khả năng thực hiện được một cách dễ dàng hoặc thuận tiện.','Đó là một ý tưởng tuyệt vời, nhưng tôi không chắc liệu nó có khả thi về mặt tài chính hay không.','Khả thi',579,NULL,_binary '\0'),(626,'Information about reactions to a product, a person\'s performance of a task, etc.','We welcome your feedback on these initial designs.','NOUN','Thông tin về phản ứng đối với sản phẩm, hiệu suất làm việc của ai đó.','Chúng tôi hoan nghênh phản hồi của bạn về các thiết kế ban đầu này.','Ý kiến phản hồi/Góp ý',580,NULL,_binary '\0'),(627,'An abstract idea; a general notion.','The whole concept of the app is to simplify travel planning.','NOUN','Một ý tưởng trừu tượng hoặc quan niệm chung.','Toàn bộ ý tưởng của ứng dụng là đơn giản hóa việc lập kế hoạch du lịch.','Khái niệm/Ý tưởng',581,NULL,_binary '\0'),(628,'To add more detail concerning what has already been said.','Could you elaborate on how this feature would work?','VERB','Thêm chi tiết liên quan đến những gì đã được nói.','Bạn có thể nói rõ hơn về cách tính năng này hoạt động không?','Giải thích chi tiết/Nói rõ thêm',582,NULL,_binary '\0'),(629,'Involving many carefully arranged parts or details.','The team developed an elaborate plan for the launch.','ADJECTIVE','Bao gồm nhiều bộ phận hoặc chi tiết được sắp xếp cẩn thận.','Đội ngũ đã phát triển một kế hoạch tỉ mỉ cho buổi ra mắt.','Tỉ mỉ/Trau chuốt',582,NULL,_binary '\0'),(630,'To make an action or process easy or easier.','A good moderator can facilitate the discussion effectively.','VERB','Làm cho một hành động hoặc quá trình trở nên dễ dàng hơn.','Một người điều phối giỏi có thể thúc đẩy buổi thảo luận một cách hiệu quả.','Tạo điều kiện/Thúc đẩy',583,NULL,_binary '\0'),(631,'What is put in, taken in, or operated on by any process or system.','We need more input from the engineering team.','NOUN','Những gì được đưa vào một quá trình hoặc hệ thống.','Chúng tôi cần thêm ý kiến đóng góp từ đội ngũ kỹ thuật.','Ý kiến đóng góp/Đầu vào',584,NULL,_binary '\0'),(632,'The established set of attitudes held by someone.','To innovate, we must adopt a growth mindset.','NOUN','Tập hợp các thái độ đã được thiết lập của ai đó.','Để đổi mới, chúng ta phải áp dụng một tư duy cầu tiến.','Tư duy/Hệ tư tưởng',585,NULL,_binary '\0'),(633,'A plan of action designed to achieve a long-term goal.','We are developing a new strategy to increase sales.','NOUN','Một kế hoạch hành động được thiết kế để đạt được mục tiêu dài hạn.','Chúng tôi đang phát triển một chiến lược mới để tăng doanh số.','Chiến lược',586,NULL,_binary '\0'),(634,'Something that exists in a computer-generated environment rather than in the physical world.','We have a virtual meeting scheduled for 10 AM.','ADJECTIVE','Thứ gì đó tồn tại trong môi trường máy tính thay vì thế giới vật lý.','Chúng tôi có một cuộc họp ảo được lên lịch vào lúc 10 giờ sáng.','Ảo/Trên mạng',587,NULL,_binary '\0'),(635,'To silence a microphone or audio device.','Please mute your microphone when you are not speaking.','VERB','Làm cho micro hoặc thiết bị âm thanh không phát ra tiếng.','Vui lòng tắt tiếng micro khi bạn không phát biểu.','Tắt tiếng',588,NULL,_binary '\0'),(636,'Unable to speak.','He remained mute throughout the discussion.','ADJECTIVE','Không thể nói được.','Anh ấy giữ im lặng (không nói lời nào) suốt buổi thảo luận.','Câm/Không thốt ra lời',588,NULL,_binary '\0'),(637,'The practice of sharing the contents of your computer screen with other participants in a call.','I will use screen sharing to show you the project slides.','NOUN','Việc chia sẻ nội dung màn hình máy tính của bạn với những người tham gia khác.','Tôi sẽ sử dụng tính năng chia sẻ màn hình để cho các bạn xem các trang trình bày của dự án.','Chia sẻ màn hình',589,NULL,_binary '\0'),(638,'A delay between an action and a reaction on a computer or internet connection.','There is a significant lag in the video feed.','NOUN','Sự chậm trễ giữa hành động và phản ứng trên máy tính hoặc kết nối internet.','Có một độ trễ đáng kể trong tín hiệu video.','Độ trễ/Sự chậm trễ',590,NULL,_binary '\0'),(639,'To fall behind in movement, progress, or development.','Sales are lagging behind last year\'s figures.','VERB','Rơi vào tình trạng chậm hơn so với tiến độ hoặc sự phát triển.','Doanh số đang tụt lại so với số liệu năm ngoái.','Tụt lại/Chậm hơn',590,NULL,_binary '\0'),(640,'The capacity for data transfer of an electronic communications system.','Poor video quality is often caused by low bandwidth.','NOUN','Khả năng truyền tải dữ liệu của một hệ thống truyền thông điện tử.','Chất lượng video kém thường do băng thông thấp.','Băng thông',591,NULL,_binary '\0'),(641,'The energy or mental capacity required to deal with a situation.','I don’t have the bandwidth to take on another project right now.','NOUN','Năng lượng hoặc sức lực trí não cần thiết để giải quyết một tình huống.','Tôi không có đủ sức để nhận thêm một dự án nào khác vào lúc này.','Khả năng/Sức lực (xử lý việc)',591,NULL,_binary '\0'),(642,'A person who takes part in something.','We have over 20 participants in today\'s call.','NOUN','Một người tham gia vào một hoạt động hoặc sự kiện nào đó.','Chúng ta có hơn 20 người tham gia trong cuộc gọi hôm nay.','Người tham gia',592,NULL,_binary '\0'),(643,'A person who receives or entertains other people as guests; the person who organizes a meeting.','As the host, you can mute all participants.','NOUN','Người tiếp đón khách hoặc người tổ chức cuộc họp.','Với tư cách là người chủ trì, bạn có thể tắt tiếng tất cả người tham gia.','Người chủ trì/Chủ tiệc',593,NULL,_binary '\0'),(644,'To act as host for an event.','Our company will host the international conference next year.','VERB','Đóng vai trò là người tổ chức cho một sự kiện.','Công ty chúng tôi sẽ chủ trì hội nghị quốc tế vào năm tới.','Đứng ra tổ chức/Chủ trì',593,NULL,_binary '\0'),(645,'The type of computer system or software used.','Which platform should we use for the webinar: Zoom or Teams?','NOUN','Loại hệ thống máy tính hoặc phần mềm được sử dụng.','Chúng ta nên dùng nền tảng nào cho buổi hội thảo: Zoom hay Teams?','Nền tảng',594,NULL,_binary '\0'),(646,'A raised floor or stage.','The train is waiting at platform 9.','NOUN','Một sàn nhà hoặc sân khấu được nâng cao.','Tàu đang đợi ở sân ga số 9.','Bục/Thềm/Sân ga',594,NULL,_binary '\0'),(648,'To connect again.','I lost my internet, let me try to reconnect.','VERB','Thiết lập lại sự kết nối.','Tôi bị mất mạng, để tôi thử kết nối lại.','Kết nối lại',596,NULL,_binary '\0'),(649,'The process of identifying and solving problems, especially technical ones.','Check the help section for audio troubleshooting.','NOUN','Quá trình xác định và giải quyết các vấn đề, đặc biệt là lỗi kỹ thuật.','Kiểm tra phần trợ giúp để biết cách xử lý sự cố âm thanh.','Xử lý sự cố/Khắc phục lỗi',597,NULL,_binary '\0'),(650,'A smaller session that is separate from the main meeting.','We will split into breakout rooms for a 10-minute brainstorming.','NOUN','Một phiên thảo luận nhỏ tách biệt với cuộc họp chính.','Chúng ta sẽ chia vào các phòng họp nhóm để thảo luận ý tưởng trong 10 phút.','Phòng họp nhóm/Phòng chia nhỏ',598,NULL,_binary '\0'),(651,'Existing or occurring at the same time.','Video calls are a form of synchronous communication.','ADJECTIVE','Tồn tại hoặc xảy ra đồng thời.','Các cuộc gọi video là một hình thức giao tiếp đồng bộ (tức thời).','Đồng bộ/Cùng lúc',599,NULL,_binary '\0'),(652,'Relating to both hearing and sight.','We are experiencing some audio-visual issues.','ADJECTIVE','Liên quan đến cả thính giác và thị giác.','Chúng tôi đang gặp một vài vấn đề về nghe nhìn.','Nghe nhìn/Âm thanh hình ảnh',600,NULL,_binary '\0'),(653,'A sound or series of sounds caused by the reflection of sound waves.','Please use headphones to avoid an echo.','NOUN','Âm thanh lặp lại do sự phản xạ của sóng âm.','Vui lòng sử dụng tai nghe để tránh bị tiếng vọng.','Tiếng vang/Tiếng vọng',601,NULL,_binary '\0'),(654,'To repeat or be repeated by an echo.','His words echoed in the empty room.','VERB','Lặp lại điều gì đó hoặc được vang lại.','Những lời nói của anh ấy vang vọng trong căn phòng trống.','Lặp lại/Vang lại',601,NULL,_binary '\0'),(655,'An official written record of what was said and decided at a meeting.','She was responsible for taking the minutes of the board meeting.','NOUN','Bản ghi chép chính thức về những gì đã được thảo luận và quyết định trong cuộc họp.','Cô ấy chịu trách nhiệm ghi biên bản cuộc họp hội đồng quản trị.','Biên bản cuộc họp',602,NULL,_binary '\0'),(656,'To put thoughts, speech, or data into written or printed form.','The secretary will transcribe the recorded meeting later.','VERB','Chuyển đổi lời nói hoặc dữ liệu thành dạng văn bản.','Thư ký sẽ chép lại nội dung cuộc họp đã ghi âm sau.','Chép lại/Chuyển sang văn bản',603,NULL,_binary '\0'),(657,'A specific task or activity assigned to an individual or group to be completed after a meeting.','Please list all action items at the end of the minutes.','NOUN','Một nhiệm vụ cụ thể được giao cho cá nhân hoặc nhóm hoàn thành sau cuộc họp.','Vui lòng liệt kê tất cả các đầu việc cần làm ở cuối biên bản.','Nhiệm vụ/Công việc cần làm',604,NULL,_binary '\0'),(658,'To give someone a particular job or task.','The task was assigned to the marketing department.','VERB','Giao cho ai đó một công việc hoặc nhiệm vụ cụ thể.','Nhiệm vụ đã được giao cho bộ phận marketing.','Phân công/Giao nhiệm vụ',605,NULL,_binary '\0'),(660,'A firm decision to do or not to do something; a formal expression of opinion or intention agreed on by a legislative body.','The board passed a resolution to increase the budget.','NOUN','Một quyết định chắc chắn hoặc một ý định chính thức được thông qua bởi một tập thể.','Hội đồng quản trị đã thông qua nghị quyết tăng ngân sách.','Nghị quyết/Sự quyết tâm',607,NULL,_binary '\0'),(661,'To break off a meeting or legal case with the intention of resuming it later.','The meeting was adjourned until 2 PM.','VERB','Ngừng một cuộc họp hoặc phiên tòa với ý định tiếp tục sau đó.','Cuộc họp đã được tạm dừng cho đến 2 giờ chiều.','Tạm hoãn/Kết thúc buổi họp',608,NULL,_binary '\0'),(662,'A person who attends a meeting, conference, or other gathering.','We need a list of all attendees for the minutes.','NOUN','Một người có mặt trong cuộc họp hoặc hội nghị.','Chúng ta cần danh sách tất cả những người tham dự để ghi vào biên bản.','Người tham dự',609,NULL,_binary '\0'),(664,'A brief statement or account of the main points of something.','Each section of the minutes should include a brief summary.','NOUN','Một bản trình bày ngắn gọn về các điểm chính.','Mỗi phần của biên bản nên bao gồm một bản tóm tắt ngắn gọn.','Bản tóm tắt',611,NULL,_binary '\0'),(667,'A minor change or addition designed to improve a text, piece of legislation, etc.','There was one amendment to the previous meeting\'s minutes.','NOUN','Một thay đổi nhỏ hoặc bổ sung để hoàn thiện văn bản.','Có một sự sửa đổi đối với biên bản cuộc họp trước.','Sự sửa đổi/Bổ sung',613,NULL,_binary '\0'),(668,'Fully in agreement.','The decision to hire the new consultant was unanimous.','ADJECTIVE','Hoàn toàn đồng ý (không có ý kiến phản đối).','Quyết định thuê cố vấn mới đã nhận được sự nhất trí hoàn toàn.','Nhất trí/Đồng lòng',614,NULL,_binary '\0'),(670,'The action of sharing something out among a number of recipients.','The distribution of the minutes will happen within 24 hours.','NOUN','Hành động chia sẻ điều gì đó cho nhiều người nhận.','Việc phân phát (gửi) biên bản sẽ diễn ra trong vòng 24 giờ.','Sự phân phát/Gửi đi',616,NULL,_binary '\0'),(671,'To stop a person from speaking for a short period by saying something yourself.','I’m sorry to interrupt, but I have a quick question.','VERB','Dừng ai đó đang nói trong một thời gian ngắn bằng cách tự mình nói điều gì đó.','Xin lỗi vì đã ngắt lời, nhưng tôi có một câu hỏi nhanh.','Ngắt lời/Làm gián đoạn',617,NULL,_binary '\0'),(672,'To say something abruptly, especially as an aside or interruption.','“That’s not true,” he interjected.','VERB','Nói điều gì đó một cách đột ngột, thường là để đưa ra ý kiến phụ hoặc ngắt lời.','“Điều đó không đúng,” anh ấy xen ngang.','Xen ngang/Chêm vào',618,NULL,_binary '\0'),(673,'To put oneself into a place or situation where one is not invited or wanted.','I don\'t mean to intrude on your conversation.','VERB','Đưa bản thân vào một nơi hoặc tình huống mà mình không được mời hoặc không được mong đợi.','Tôi không có ý định làm phiền cuộc trò chuyện của các bạn.','Xen vào/Làm phiền',619,NULL,_binary '\0'),(675,'Used to ask someone to repeat something because you did not hear it.','Pardon me, could you say that again?','PHRASE','Dùng để yêu cầu ai đó lặp lại điều gì vì bạn không nghe rõ.','Xin lỗi, bạn có thể nói lại điều đó được không?','Xin lỗi/Vui lòng nhắc lại',621,NULL,_binary '\0'),(677,'An expression or feeling of disapproval or opposition.','I have a slight objection to the current proposal.','NOUN','Sự bày tỏ việc không tán thành hoặc phản đối.','Tôi có một chút phản đối đối với đề xuất hiện tại.','Sự phản đối/Ý kiến phản bác',623,NULL,_binary '\0'),(684,'A temporary stop in action or speech.','Wait for a pause in the conversation to speak up.','NOUN','Một khoảng dừng tạm thời trong hành động hoặc lời nói.','Hãy đợi một nhịp nghỉ trong cuộc trò chuyện để lên tiếng.','Sự tạm nghỉ/Nhịp nghỉ',630,NULL,_binary '\0'),(685,'Interrupt action or speech briefly.','He paused for a moment before answering.','VERB','Ngừng hành động hoặc lời nói trong chốc lát.','Anh ấy đã dừng lại một chút trước khi trả lời.','Tạm dừng',630,NULL,_binary '\0'),(686,'Having or showing skill and sensitivity in dealing with others.','A tactful interruption is better than staying silent and confused.','ADJECTIVE','Có kỹ năng và sự nhạy bén khi đối xử với người khác.','Một sự ngắt lời khéo léo thì tốt hơn là cứ im lặng và bối rối.','Khéo léo/Tinh tế',631,NULL,_binary '\0'),(688,'An agreement reached by each side making concessions.','In any partnership, you have to be prepared to make compromises.','NOUN','Một thỏa thuận đạt được bằng cách mỗi bên đều nhường nhịn một chút.','Trong bất kỳ mối quan hệ đối tác nào, bạn cũng phải sẵn sàng thực hiện những sự thỏa hiệp.','Sự thỏa hiệp',633,NULL,_binary '\0'),(689,'To settle a dispute by mutual concession; to bring into danger.','We should not compromise on safety standards.','VERB','Giải quyết tranh chấp bằng cách nhường nhịn; hoặc gây nguy hiểm cho điều gì đó.','Chúng ta không nên thỏa hiệp (làm giảm nhẹ) các tiêu chuẩn an toàn.','Thỏa hiệp/Làm tổn hại',633,NULL,_binary '\0'),(691,'To place in a straight line or bring into agreement.','We need to align our goals with the company\'s overall strategy.','VERB','Điều chỉnh để các ý kiến hoặc mục tiêu khớp với nhau.','Chúng ta cần thống nhất các mục tiêu của mình với chiến lược chung của công ty.','Thống nhất/Sắp cho thẳng hàng',635,NULL,_binary '\0'),(692,'A thing that is granted, especially in response to demands.','The management made several concessions to the workers.','NOUN','Một điều được chấp thuận nhằm đáp lại các yêu cầu hoặc để đạt được thỏa thuận.','Ban quản lý đã thực hiện một vài sự nhượng bộ đối với công nhân.','Sự nhượng bộ',636,NULL,_binary '\0'),(693,'The greater number.','The majority of the team voted in favor of the proposal.','NOUN','Số lượng lớn hơn trong một tổng thể.','Đa số các thành viên trong đội đã bỏ phiếu ủng hộ đề xuất.','Đa số/Phần lớn',637,NULL,_binary '\0'),(694,'A situation, typically one involving opposing parties, in which no progress can be made.','The negotiations reached a deadlock over the price issue.','NOUN','Tình trạng không bên nào chịu nhường bên nào khiến mọi việc không thể tiến triển.','Các cuộc đàm phán đã rơi vào bế tắc vì vấn đề giá cả.','Sự bế tắc/Đình trệ',638,NULL,_binary '\0'),(695,'To try to reach an agreement or compromise by discussion.','They are negotiating a new contract.','VERB','Cố gắng đạt được thỏa thuận thông qua thảo luận.','Họ đang đàm phán một hợp đồng mới.','Đàm phán/Thương lượng',639,NULL,_binary '\0'),(697,'To settle or find a solution to a problem or dispute.','We hope to resolve the conflict peacefully.','VERB','Tìm ra giải pháp cho một vấn đề hoặc tranh chấp.','Chúng tôi hy vọng sẽ giải quyết cuộc xung đột một cách hòa bình.','Giải quyết/Xử lý',641,NULL,_binary '\0'),(700,'Produced or conducted by two or more parties working together.','Reaching consensus requires a collaborative effort.','ADJECTIVE','Được thực hiện bởi sự phối hợp của nhiều bên.','Đạt được sự đồng thuận đòi hỏi một nỗ lực mang tính cộng tác.','Mang tính cộng tác/Hợp tác',644,NULL,_binary '\0'),(701,'The way a thing turns out; a consequence.','We are satisfied with the outcome of the meeting.','NOUN','Kết quả cuối cùng của một quá trình hoặc sự việc.','Chúng tôi hài lòng với kết quả của cuộc họp.','Kết quả/Hệ quả',645,NULL,_binary '\0'),(703,'To give a brief statement of the main points of something.','Before we finish, let me summarize the key decisions.','VERB','Trình bày ngắn gọn các điểm chính của một vấn đề.','Trước khi kết thúc, hãy để tôi tóm tắt các quyết định chính.','Tóm tắt',647,NULL,_binary '\0'),(707,'The actions that will be taken after a current stage.','Are we all clear on the next steps for this project?','NOUN','Những hành động sẽ được thực hiện sau giai đoạn hiện tại.','Tất cả chúng ta đều đã rõ các bước tiếp theo cho dự án này chưa?','Các bước tiếp theo',651,NULL,_binary '\0'),(709,'To achieve or complete something successfully.','We have accomplished a lot in today’s session.','VERB','Thực hiện thành công một mục tiêu hoặc nhiệm vụ.','Chúng ta đã đạt được rất nhiều điều trong buổi hôm nay.','Hoàn thành/Đạt được',653,NULL,_binary '\0'),(710,'To combine a number of things into a single more effective or coherent whole.','Let\'s consolidate our ideas into one final plan.','VERB','Hợp nhất các ý kiến hoặc nguồn lực lại cho chặt chẽ.','Hãy thống nhất các ý tưởng của chúng ta thành một kế hoạch cuối cùng.','Củng cố/Thống nhất',654,NULL,_binary '\0'),(715,'The quality of being coherent and intelligible.','The summary provided much-needed clarity on the project scope.','NOUN','Đảm bảo mọi thứ đều dễ hiểu và không gây nhầm lẫn.','Bản tóm tắt đã cung cấp sự rõ ràng rất cần thiết về phạm vi dự án.','Sự rõ ràng/Minh bạch',659,NULL,_binary '\0'),(716,'Recognition and enjoyment of the good qualities of someone or something.','I’d like to express my appreciation for everyone\'s input.','NOUN','Sự công nhận nỗ lực của các thành viên.','Tôi muốn bày tỏ sự cảm kích đối với ý kiến đóng góp của mọi người.','Sự cảm kích/Trân trọng',660,NULL,_binary '\0'),(717,'Toward the front; in the direction that one is facing.','I look forward to our next meeting.','ADVERB','Hướng về tương lai hoặc bước tiếp theo.','Tôi rất mong chờ cuộc họp tiếp theo của chúng ta.','Về phía trước/Tiến tới',661,NULL,_binary '\0'),(718,'An act of asking for information.','We received an enquiry about our new software package.','NOUN','Hành động hỏi để biết thông tin về điều gì đó.','Chúng tôi đã nhận được một yêu cầu thông tin về gói phần mềm mới.','Yêu cầu cung cấp thông tin/Thắc mắc',662,NULL,_binary '\0'),(719,'A formal statement setting out the estimated cost for a particular job or service.','Could you provide a quote for the office renovation?','NOUN','Một văn bản chính thức nêu chi phí ước tính cho một công việc hoặc dịch vụ.','Bạn có thể cung cấp một bản báo giá cho việc sửa sang văn phòng không?','Bản báo giá/Giá ước tính',663,NULL,_binary '\0'),(720,'To give someone a price for a job; to repeat words from a text.','The contractor quoted $5,000 for the repairs.','VERB','Đưa giá cho một công việc hoặc nhắc lại lời từ một văn bản.','Nhà thầu đã báo giá 5.000 USD cho việc sửa chữa.','Báo giá/Trích dẫn',663,NULL,_binary '\0'),(721,'A detailed description of the design and materials used to make something.','Please send us the full specifications of the product.','NOUN','Mô tả chi tiết về thiết kế và vật liệu được sử dụng để tạo ra thứ gì đó.','Vui lòng gửi cho chúng tôi các thông số kỹ thuật đầy đủ của sản phẩm.','Thông số kỹ thuật/Đặc tả',664,NULL,_binary '\0'),(722,'A list of all the goods or services that you can buy from a company.','You can find the prices in our latest spring catalogue.','NOUN','Danh sách tất cả hàng hóa hoặc dịch vụ bạn có thể mua từ một công ty.','Bạn có thể tìm thấy giá cả trong danh mục mùa xuân mới nhất của chúng tôi.','Danh mục/Cuốn giới thiệu sản phẩm',665,NULL,_binary '\0'),(723,'Expected or expecting to be something in the future.','We need to impress our prospective clients.','ADJECTIVE','Được kỳ vọng sẽ trở thành điều gì đó trong tương lai.','Chúng ta cần gây ấn tượng với các khách hàng tiềm năng của mình.','Tiềm năng/Thuộc về tương lai',666,NULL,_binary '\0'),(724,'Feeling or showing an appreciation of kindness; thankful.','I would be grateful if you could send the information by Friday.','ADJECTIVE','Cảm thấy hoặc bày tỏ sự trân trọng; thường dùng trong thư từ trang trọng.','Tôi sẽ rất cảm kích nếu bạn có thể gửi thông tin trước thứ Sáu.','Biết ơn/Cảm kích',667,NULL,_binary '\0'),(725,'An act or course of action to which a person is legally or morally bound.','This quote is provided without any obligation to buy.','NOUN','Một hành động mà một người bị ràng buộc về mặt pháp lý hoặc đạo đức.','Báo giá này được cung cấp mà không kèm theo bất kỳ nghĩa vụ mua hàng nào.','Nghĩa vụ/Trách nhiệm',668,NULL,_binary '\0'),(726,'The state of being able to be obtained or used.','Please check the availability of these items in your warehouse.','NOUN','Trạng thái có thể nhận được hoặc sử dụng được.','Vui lòng kiểm tra tình trạng còn hàng của những mặt hàng này trong kho của bạn.','Sự sẵn có/Tình trạng còn hàng',669,NULL,_binary '\0'),(729,'The time between the initiation and completion of a production process.','What is the average lead time for a custom order?','NOUN','Khoảng thời gian từ khi bắt đầu đến khi hoàn thành một quy trình sản xuất.','Thời gian chờ trung bình cho một đơn hàng tùy chỉnh là bao lâu?','Thời gian chờ/Thời gian từ lúc đặt đến lúc giao',672,NULL,_binary '\0'),(730,'A thing that is needed or wanted.','The system meets all our technical requirements.','NOUN','Một thứ cần thiết hoặc mong muốn để thực hiện mục đích nào đó.','Hệ thống đáp ứng tất cả các yêu cầu kỹ thuật của chúng tôi.','Yêu cầu/Điều kiện cần thiết',673,NULL,_binary '\0'),(732,'A condition or restriction expressed in an agreement or contract.','Please let us know your standard payment terms.','NOUN','Một điều kiện hoặc hạn chế được nêu trong một thỏa thuận hoặc hợp đồng.','Vui lòng cho chúng tôi biết các điều khoản thanh toán tiêu chuẩn của bạn.','Điều khoản/Điều kiện',675,NULL,_binary '\0'),(733,'To pause before saying or doing something.','Please do not hesitate to contact us if you need further details.','VERB','Tạm dừng trước khi nói hoặc làm điều gì đó (thường dùng ở cuối thư).','Vui lòng đừng ngần ngại liên hệ với chúng tôi nếu bạn cần thêm chi tiết.','Ngần ngại/Do dự',676,NULL,_binary '\0'),(734,'A plan for carrying out a process or procedure, giving lists of intended events and times.','I have a very tight schedule this week.','NOUN','Một bản danh sách các sự kiện và thời gian dự kiến thực hiện.','Tôi có một lịch trình rất dày đặc trong tuần này.','Lịch trình/Kế hoạch',677,NULL,_binary '\0'),(735,'To arrange or plan (an event) to take place at a particular time.','We have scheduled the meeting for next Monday.','VERB','Sắp xếp một sự kiện diễn ra vào một thời điểm cụ thể.','Chúng tôi đã lên lịch cuộc họp vào thứ Hai tới.','Lên lịch/Sắp xếp thời gian',677,NULL,_binary '\0'),(736,'An arrangement to meet someone at a particular time and place.','I’d like to make an appointment to see the manager.','NOUN','Sự sắp xếp để gặp ai đó tại một thời điểm và địa điểm cụ thể.','Tôi muốn đặt một cuộc hẹn để gặp quản lý.','Cuộc hẹn',678,NULL,_binary '\0'),(738,'To cause or arrange for (something) to take place at a time later than that first scheduled.','The meeting has been postponed until next week.','VERB','Sắp xếp để một sự việc diễn ra muộn hơn so với lịch ban đầu.','Cuộc họp đã bị hoãn lại cho đến tuần sau.','Hoãn lại/Chậm lại',680,NULL,_binary '\0'),(739,'To change the time or date of a scheduled event.','I’m afraid I have to reschedule our lunch.','VERB','Thay đổi thời gian hoặc ngày của một sự kiện đã được lên lịch.','Tôi e là tôi phải đổi lịch ăn trưa của chúng ta.','Lên lại lịch/Đổi lịch',681,NULL,_binary '\0'),(741,'A serious disagreement or argument; a clash in schedules.','I have a scheduling conflict at 3 PM.','NOUN','Tình trạng hai sự kiện diễn ra cùng lúc khiến không thể tham gia cả hai.','Tôi bị trùng lịch vào lúc 3 giờ chiều.','Sự trùng lặp/Xung đột',683,NULL,_binary '\0'),(744,'A thing that causes someone to remember something.','I set a reminder on my phone for the appointment.','NOUN','Thứ giúp ai đó nhớ lại một việc cần làm.','Tôi đã đặt lời nhắc trên điện thoại cho cuộc hẹn.','Lời nhắc nhở',686,NULL,_binary '\0'),(745,'The place where something happens, especially an organized event.','The hotel is an ideal venue for the conference.','NOUN','Nơi diễn ra một sự kiện đã được lên kế hoạch.','Khách sạn này là một địa điểm lý tưởng cho buổi hội thảo.','Địa điểm/Nơi tổ chức',687,NULL,_binary '\0'),(746,'A position in a hierarchy or sequence; a time assigned for something.','I have a free slot between 2 PM and 3 PM.','NOUN','Một vị trí hoặc khoảng thời gian được ấn định cho việc gì đó.','Tôi có một khoảng thời gian trống từ 2 giờ đến 3 giờ chiều.','Khoảng thời gian/Suất',688,NULL,_binary '\0'),(747,'Happening or doing something at the agreed or proper time; on time.','Please try to be punctual for the meeting.','ADJECTIVE','Xảy ra hoặc làm điều gì đó vào đúng thời điểm đã thỏa thuận.','Vui lòng cố gắng đi họp đúng giờ.','Đúng giờ',689,NULL,_binary '\0'),(748,'Not certain or fixed; provisional.','We have a tentative date for the launch next month.','ADJECTIVE','Chưa chắc chắn hoặc chưa được chốt cố định.','Chúng tôi có một ngày dự kiến cho buổi ra mắt vào tháng tới.','Dự kiến/Tạm thời',690,NULL,_binary '\0'),(749,'Fitting in well with a person\'s needs, activities, and plans.','Is 10 AM convenient for you?','ADJECTIVE','Phù hợp với nhu cầu, hoạt động và kế hoạch của một người.','10 giờ sáng có tiện cho bạn không?','Tiện lợi/Phù hợp',691,NULL,_binary '\0'),(752,'To briefly contact or talk to someone to update them.','I’m just touching base to see if you have any updates on the project.','IDIOM','Liên hệ ngắn gọn để cập nhật tình hình hoặc duy trì kết nối.','Tôi chỉ liên lạc nhanh để xem bạn có cập nhật gì về dự án không.','Liên lạc/Trao đổi nhanh',694,NULL,_binary '\0'),(753,'In relation to; about.','I am writing regarding the feedback you provided yesterday.','PREPOSITION','Dùng để giới thiệu chủ đề của email.','Tôi viết thư này liên quan đến những phản hồi mà bạn đã cung cấp hôm qua.','Về việc/Liên quan đến',695,NULL,_binary '\0'),(754,'With little or no delay; immediately.','Thank you for responding so promptly to my previous email.','ADVERB','Thực hiện một cách nhanh chóng, không chậm trễ.','Cảm ơn bạn đã phản hồi email trước của tôi rất nhanh chóng.','Kịp thời/Nhanh chóng',696,NULL,_binary '\0'),(756,'Coming after something in time; following.','In subsequent emails, we can discuss the implementation details.','ADJECTIVE','Xảy ra sau một sự kiện nào đó.','Trong các email tiếp theo, chúng ta có thể thảo luận chi tiết về việc triển khai.','Tiếp theo/Xảy ra sau đó',698,NULL,_binary '\0'),(757,'Communication by exchanging letters or emails.','Please keep a record of all correspondence with the client.','NOUN','Quá trình trao đổi thông tin qua lại bằng văn bản.','Vui lòng lưu lại hồ sơ của tất cả các thư từ giao dịch với khách hàng.','Thư từ giao dịch',699,NULL,_binary '\0'),(760,'Waiting to be settled or decided.','There are still a few pending tasks in our Trello board.','ADJECTIVE','Chưa được quyết định hoặc giải quyết xong.','Vẫn còn một vài tác vụ đang chờ xử lý trong bảng Trello của chúng ta.','Đang chờ xử lý',702,NULL,_binary '\0'),(761,'Able to be acted on.','Please provide actionable feedback so we can improve the code.','ADJECTIVE','Thông tin hoặc phản hồi rõ ràng đến mức có thể bắt tay vào làm ngay.','Vui lòng cung cấp phản hồi có thể thực hiện được để chúng tôi cải thiện mã nguồn.','Có thể thực hiện được',703,NULL,_binary '\0'),(764,'To say something again or a number of times, typically for emphasis or clarity.','I would like to reiterate that the deadline is non-negotiable.','VERB','Nói lại một lần nữa để nhấn mạnh hoặc làm cho rõ ràng.','Tôi muốn nhắc lại rằng thời hạn là không thể thương lượng.','Nhắc lại/Khẳng định lại',706,NULL,_binary '\0'),(765,'A written message in business or diplomacy, typically used within an organization.','The HR department issued a memo about the new holiday policy.','NOUN','Một tin nhắn văn bản trong kinh doanh, thường dùng trong phạm vi một tổ chức.','Bộ phận nhân sự đã phát đi một thông báo nội bộ về chính sách nghỉ lễ mới.','Thông báo nội bộ/Bản ghi nhớ',707,NULL,_binary '\0'),(766,'A person who receives something.','Please make sure the memo reaches all intended recipients.','NOUN','Người nhận được thư, thông báo hoặc giải thưởng.','Hãy đảm bảo rằng thông báo nội bộ đến tay tất cả những người nhận dự kiến.','Người nhận',708,NULL,_binary '\0'),(767,'The line in an email or memo that indicates what the content is about.','A clear subject line helps staff prioritize their reading.','NOUN','Dòng chữ trong email hoặc memo cho biết nội dung nói về cái gì.','Một dòng tiêu đề rõ ràng giúp nhân viên ưu tiên việc đọc của họ.','Dòng tiêu đề',709,NULL,_binary '\0'),(768,'To inform someone or give notice to someone about something.','We will notify you of any changes to the schedule.','VERB','Cung cấp thông tin chính thức cho ai đó về một sự việc.','Chúng tôi sẽ thông báo cho bạn về bất kỳ thay đổi nào đối với lịch trình.','Thông báo/Cho biết',710,NULL,_binary '\0'),(769,'To pass from place to place or person to person.','This memo will be circulated to all department heads.','VERB','Truyền tay hoặc gửi thông tin từ người này sang người khác.','Bản thông báo này sẽ được gửi tới tất cả các trưởng bộ phận.','Lưu hành/Phổ biến rộng rãi',711,NULL,_binary '\0'),(771,'To start using a plan or system.','New security measures will be implemented next month.','VERB','Bắt đầu áp dụng một kế hoạch hoặc hệ thống.','Các biện pháp an ninh mới sẽ được triển khai vào tháng tới.','Triển khai/Thực hiện',713,NULL,_binary '\0'),(773,'Something that must be done, or is demanded by law.','Attendance at the training session is mandatory.','ADJECTIVE','Thứ gì đó phải thực hiện theo quy định hoặc luật pháp.','Việc tham dự buổi đào tạo là bắt buộc.','Bắt buộc',715,NULL,_binary '\0'),(774,'Giving a lot of information clearly and in a few words.','Memos should be concise and easy to understand.','ADJECTIVE','Cung cấp nhiều thông tin một cách rõ ràng và ít lời.','Các thông báo nội bộ nên súc tích và dễ hiểu.','Súc tích/Ngắn gọn',716,NULL,_binary '\0'),(777,'Used to state that a rule or change starts right now.','The new dress code is effective immediately.','PHRASE','Dùng để tuyên bố một quy định hoặc thay đổi bắt đầu từ bây giờ.','Quy định trang phục mới có hiệu lực ngay lập tức.','Có hiệu lực ngay lập tức',719,NULL,_binary '\0'),(778,'A computer file sent with an email or memo.','Please refer to the attachment for more details.','NOUN','Một tập tin máy tính được gửi kèm theo một thông điệp.','Vui lòng tham khảo tệp đính kèm để biết thêm chi tiết.','Tệp đính kèm',720,NULL,_binary '\0'),(779,'To spread or give out something, especially information, widely.','The office manager will disseminate the updated guidelines.','VERB','Phát tán thông tin rộng rãi đến nhiều người.','Quản lý văn phòng sẽ phổ biến các hướng dẫn đã được cập nhật.','Phổ biến/Lan truyền',721,NULL,_binary '\0'),(780,'A gesture or utterance made as a greeting; the opening of a letter.','“Dear Sir/Madam” is a formal salutation.','NOUN','Lời chào mở đầu trong một bức thư hoặc cuộc gặp gỡ.','“Thưa Ông/Bà” là một lời chào trang trọng.','Lời chào/Sự chào hỏi',722,NULL,_binary '\0'),(782,'Having a relaxed, friendly, or unofficial style.','“Hi everyone” is an informal way to start a team message.','ADJECTIVE','Có phong cách thoải mái, thân thiện, không quá câu nệ nghi thức.','“Chào mọi người” là một cách thân mật để bắt đầu tin nhắn nhóm.','Thân mật/Không chính thức',724,NULL,_binary '\0'),(783,'Used at the beginning of a letter when you do not know the name of the person you are writing to.','Use “To whom it may concern” for general enquiries.','PHRASE','Dùng đầu thư khi bạn không biết rõ tên người nhận.','Dùng “Gửi những ai có liên quan” cho các yêu cầu thông tin chung.','Gửi những ai có liên quan',725,NULL,_binary '\0'),(784,'Warm and friendly.','The two managers maintained a cordial relationship.','ADJECTIVE','Nồng hậu và thân thiện (thường dùng trong bối cảnh lịch sự).','Hai vị quản lý duy trì một mối quan hệ thân ái.','Thân ái/Chân thành',726,NULL,_binary '\0'),(785,'To speak to a person or use a particular name when speaking or writing to them.','How should I address the CEO?','VERB','Dùng một cái tên hoặc danh hiệu cụ thể khi nói hoặc viết cho ai đó.','Tôi nên xưng hô với CEO như thế nào?','Xưng hô/Gọi tên',727,NULL,_binary '\0'),(787,'Suitable or proper in the circumstances.','Please choose an appropriate greeting for the client.','ADJECTIVE','Đúng đắn hoặc hợp lý trong hoàn cảnh cụ thể.','Vui lòng chọn một lời chào phù hợp cho khách hàng.','Phù hợp/Thích hợp',729,NULL,_binary '\0'),(790,'According to the customs or usual practices associated with a particular society, place, or set of circumstances.','It is customary to greet the host first.','ADJECTIVE','Theo thói quen hoặc tập quán thông thường.','Theo lệ thường thì nên chào chủ nhà trước.','Theo lệ thường/Thông thường',732,NULL,_binary '\0'),(791,'In a sincere or genuine way (often used for endings, but relates to the greeting tone).','Yours sincerely, John Doe.','ADVERB','Một cách thành thật (thường dùng ở cuối thư, nhưng liên quan đến tông giọng chào hỏi).','Trân trọng (dùng khi biết tên người nhận), John Doe.','Chân thành',733,NULL,_binary '\0'),(792,'A person of the same age, status, or ability as another specified person.','You can use less formal greetings with your peers.','NOUN','Người có cùng địa vị hoặc trình độ.','Bạn có thể dùng lời chào ít trang trọng hơn với những người ngang hàng.','Người ngang hàng/Đồng lứa',734,NULL,_binary '\0'),(794,'The general character or attitude of a place, piece of writing, situation, etc.','The greeting sets the tone for the entire email.','NOUN','Thái độ thể hiện qua lời nói hoặc văn viết.','Lời chào thiết lập sắc thái cho toàn bộ email.','Sắc thái/Giọng điệu',736,NULL,_binary '\0'),(795,'A statement that something is unsatisfactory or unacceptable.','We received a formal complaint about the late delivery.','NOUN','Một tuyên bố rằng điều gì đó không thỏa đáng hoặc không thể chấp nhận được.','Chúng tôi đã nhận được một đơn khiếu nại chính thức về việc giao hàng trễ.','Lời phàn nàn/Khiếu nại',737,NULL,_binary '\0'),(796,'To express regret for something that one has done wrong.','I sincerely apologize for any inconvenience caused.','VERB','Bày tỏ sự hối tiếc về điều gì đó mình đã làm sai.','Tôi chân thành xin lỗi vì bất kỳ sự bất tiện nào đã gây ra.','Xin lỗi',738,NULL,_binary '\0'),(797,'Not content or happy with something.','If you are dissatisfied with the service, please let us know.','ADJECTIVE','Không cảm thấy thỏa mãn hoặc vui vẻ với một điều gì đó.','Nếu bạn không hài lòng với dịch vụ, vui lòng cho chúng tôi biết.','Không hài lòng/Bất mãn',739,NULL,_binary '\0'),(798,'To put something right; to correct.','We will take immediate action to rectify the situation.','VERB','Làm cho điều gì đó đúng trở lại hoặc khắc phục một sai sót.','Chúng tôi sẽ hành động ngay lập tức để khắc phục tình hình.','Sửa chữa/Khắc phục',740,NULL,_binary '\0'),(799,'A repayment of a sum of money.','You are entitled to a full refund if the item is faulty.','NOUN','Việc trả lại một khoản tiền (thường do khách trả hàng).','Bạn có quyền nhận lại toàn bộ tiền nếu món hàng bị lỗi.','Tiền hoàn lại',741,NULL,_binary '\0'),(800,'To pay back money, typically to a customer who is not satisfied.','The company agreed to refund the customer\'s expenses.','VERB','Trả lại tiền, thường là cho khách hàng không hài lòng.','Công ty đã đồng ý hoàn trả các chi phí của khách hàng.','Hoàn tiền',741,NULL,_binary '\0'),(801,'Something, typically money, awarded to someone as a recompense for loss or injury.','The airline offered travel vouchers as compensation for the delay.','NOUN','Thứ gì đó, thường là tiền, được trao để bù đắp cho mất mát.','Hãng hàng không đã tặng phiếu giảm giá du lịch như một sự bồi thường cho việc chậm trễ.','Sự bồi thường/Đền bù',742,NULL,_binary '\0'),(802,'A rapid increase; the act of referring a matter to a higher authority.','We need a clear escalation process for complex complaints.','NOUN','Hành động chuyển một vấn đề lên cấp có thẩm quyền cao hơn để giải quyết.','Chúng ta cần một quy trình chuyển cấp rõ ràng cho những khiếu nại phức tạp.','Sự leo thang/Chuyển lên cấp trên',743,NULL,_binary '\0'),(805,'To understand and share the feelings of another.','It’s important to empathize with the customer\'s frustration.','VERB','Hiểu và chia sẻ cảm xúc với người khác.','Điều quan trọng là phải đồng cảm với sự thất vọng của khách hàng.','Đồng cảm/Thấu cảm',746,NULL,_binary '\0'),(806,'Imperfect or faulty.','The customer returned the defective monitor.','ADJECTIVE','Không hoàn hảo hoặc có sai sót về mặt kỹ thuật.','Khách hàng đã trả lại chiếc màn hình bị lỗi.','Bị lỗi/Hỏng',747,NULL,_binary '\0'),(807,'A positive declaration intended to give confidence.','We give you our full assurance that this will not happen again.','NOUN','Một lời khẳng định tích cực nhằm tạo dựng lòng tin.','Chúng tôi cam đoan với bạn rằng điều này sẽ không lặp lại lần nữa.','Sự cam đoan/Sự tự tin',748,NULL,_binary '\0'),(809,'A formal or systematic examination or research.','We are launching a full investigation into the security breach.','NOUN','Quá trình xem xét kỹ lưỡng để tìm ra nguyên nhân vấn đề.','Chúng tôi đang triển khai một cuộc điều tra toàn diện về vụ vi phạm an ninh.','Cuộc điều tra/Sự kiểm tra',750,NULL,_binary '\0'),(810,'Not satisfactory or allowable.','The quality of the product was deemed unacceptable.','ADJECTIVE','Không đạt yêu cầu hoặc không được phép diễn ra.','Chất lượng sản phẩm bị coi là không thể chấp nhận được.','Không thể chấp nhận được',751,NULL,_binary '\0'),(812,'A link from a hypertext file or document to another location or file.','Click on the hyperlink to visit our website.','NOUN','Một kết nối từ một văn bản điện tử đến một vị trí hoặc tập tin khác.','Nhấp vào siêu liên kết để truy cập trang web của chúng tôi.','Siêu liên kết/Đường dẫn',753,NULL,_binary '\0'),(813,'To send something in the same envelope or email.','I enclose a copy of the contract for your records.','VERB','Gửi kèm một thứ gì đó trong cùng một phong bì hoặc email.','Tôi gửi kèm một bản sao hợp đồng để bạn lưu hồ sơ.','Đính kèm/Gửi kèm',754,NULL,_binary '\0'),(814,'Able to be reached or entered.','The shared folder is now accessible to everyone on the team.','ADJECTIVE','Có thể tiếp cận hoặc mở ra để xem.','Thư mục chia sẻ hiện đã có thể được truy cập bởi mọi người trong nhóm.','Có thể truy cập/Sử dụng',755,NULL,_binary '\0'),(816,'Containing errors that prevent a file from being opened.','The attachment seems to be corrupt and won\'t open.','ADJECTIVE','Chứa các lỗi khiến tập tin không thể mở hoặc sử dụng được.','Tệp đính kèm dường như bị lỗi và không thể mở được.','Bị lỗi/Bị hỏng (tập tin)',757,NULL,_binary '\0'),(817,'To squeeze or press together or into a smaller space.','You should compress the images before sending the email.','VERB','Làm giảm dung lượng của tập tin để dễ gửi đi hơn.','Bạn nên nén các hình ảnh trước khi gửi email.','Nén lại',758,NULL,_binary '\0'),(818,'In a way that is safe from danger or being stolen.','The files are stored securely on our cloud server.','ADVERB','Thực hiện theo cách tránh được nguy cơ bị mất cắp hoặc xâm nhập.','Các tập tin được lưu trữ một cách an toàn trên máy chủ đám mây của chúng tôi.','Một cách an toàn/Bảo mật',759,NULL,_binary '\0'),(819,'An inspection or viewing of something before it is bought or widely available.','The email client provides a preview of the attachment.','NOUN','Việc xem qua nội dung trước khi tải về hoặc xuất bản.','Ứng dụng email cung cấp một bản xem trước của tệp đính kèm.','Bản xem trước',760,NULL,_binary '\0'),(821,'The way in which something is arranged or set out.','Please ensure the file is in a compatible format.','NOUN','Cách thức trình bày hoặc cấu trúc của một tập tin.','Vui lòng đảm bảo tập tin ở định dạng tương thích.','Định dạng',762,NULL,_binary '\0'),(822,'To get or bring something back from a place.','You can retrieve the deleted documents from the backup server.','VERB','Lấy thông tin hoặc tập tin từ bộ nhớ máy tính.','Bạn có thể truy xuất các tài liệu đã xóa từ máy chủ dự phòng.','Truy xuất/Lấy lại dữ liệu',763,NULL,_binary '\0'),(823,'To send someone or something to a different place or use for a different purpose.','The link will redirect you to our secure payment page.','VERB','Đưa người dùng hoặc dữ liệu đến một địa chỉ hoặc vị trí khác.','Đường dẫn sẽ chuyển hướng bạn đến trang thanh toán bảo mật của chúng tôi.','Chuyển hướng',764,NULL,_binary '\0'),(825,'In a way that is intended to correct something.','The link was sent correctively after the first one failed.','ADVERB','Thực hiện theo cách để sửa chữa một lỗi lầm trước đó.','Đường dẫn được gửi lại để khắc phục sau khi đường dẫn đầu tiên bị hỏng.','Một cách mang tính khắc phục/Sửa sai',766,NULL,_binary '\0'),(827,'To attract and hold the interest and attention of; charm.','The speaker managed to captivate the audience from the first minute.','VERB','Thu hút và giữ sự quan tâm và chú ý của ai đó.','Diễn giả đã thành công trong việc thu hút khán giả ngay từ phút đầu tiên.','Thu hút/Làm say đắm',768,NULL,_binary '\0'),(829,'At once; immediately.','The visual aids instantly grabbed everyone\'s attention.','ADVERB','Ngay tức thì, không chậm trễ.','Các phương tiện hỗ trợ hình ảnh đã ngay lập tức thu hút sự chú ý của mọi người.','Ngay lập tức',770,NULL,_binary '\0'),(830,'A strong desire to know or learn something.','The title of the email was designed to provoke curiosity.','NOUN','Mong muốn mạnh mẽ được biết hoặc học điều gì đó.','Tiêu đề của email được thiết kế để khơi gợi sự tò mò.','Sự tò mò/Tính hiếu kỳ',771,NULL,_binary '\0'),(831,'To stimulate or give rise to (a reaction or emotion).','You can provoke thought by asking a challenging question.','VERB','Kích thích hoặc làm nảy sinh một phản ứng hoặc cảm xúc.','Bạn có thể khơi gợi suy nghĩ bằng cách đặt một câu hỏi đầy thử thách.','Khơi gợi/Kích thích',772,NULL,_binary '\0'),(832,'Charming and attractive; tending to draw favorable attention.','We need an engaging introduction to keep people watching.','ADJECTIVE','Dễ mến và thu hút sự chú ý tích cực.','Chúng ta cần một lời giới thiệu lôi cuốn để giữ chân người xem.','Lôi cuốn/Hấp dẫn',773,NULL,_binary '\0'),(833,'In a way that relates to the achievement of long-term goals.','The hook was strategically placed at the beginning of the video.','ADVERB','Thực hiện theo cách có tính toán để đạt được mục tiêu lâu dài.','Điểm thu hút được đặt một cách chiến lược ở đầu video.','Một cách chiến lược',774,NULL,_binary '\0'),(834,'A short amusing or interesting story about a real incident or person.','Sharing a personal anecdote is a great way to start.','NOUN','Một câu chuyện ngắn thú vị về một sự việc hoặc người có thật.','Chia sẻ một câu chuyện cá nhân là một cách tuyệt vời để bắt đầu.','Chuyện vặt/Giai thoại',775,NULL,_binary '\0'),(835,'To explain or make something clear by using examples or pictures.','He used a chart to illustrate the current market trends.','VERB','Giải thích hoặc làm rõ điều gì đó bằng ví dụ hoặc hình ảnh.','Anh ấy đã sử dụng biểu đồ để minh họa các xu hướng thị trường hiện tại.','Minh họa/Làm rõ',776,NULL,_binary '\0'),(836,'Arousing one\'s curiosity or interest; fascinating.','That\'s an intriguing idea for a new mobile app.','ADJECTIVE','Kích thích sự tò mò hoặc quan tâm; cực kỳ thú vị.','Đó là một ý tưởng gợi tò mò cho một ứng dụng di động mới.','Gợi tò mò/Hấp dẫn',777,NULL,_binary '\0'),(837,'In such a manner as to achieve a desired result.','You need to communicate your value proposition effectively.','ADVERB','Thực hiện theo cách để đạt được kết quả mong muốn.','Bạn cần truyền đạt tuyên bố giá trị của mình một cách hiệu quả.','Một cách hiệu quả',778,NULL,_binary '\0'),(838,'Notice taken of someone or something.','Please pay attention to the following announcement.','NOUN','Việc để ý đến ai đó hoặc điều gì đó.','Vui lòng chú ý đến thông báo sau đây.','Sự chú ý',779,NULL,_binary '\0'),(839,'To seize suddenly and roughly; to attract attention.','The headline was designed to grab the reader\'s eye.','VERB','Bắt lấy nhanh chóng; thường dùng cho việc thu hút sự chú ý.','Tiêu đề được thiết kế để thu hút ánh nhìn của người đọc.','Nắm lấy/Thu hút (chú ý)',780,NULL,_binary '\0'),(840,'Having or showing an accurate and deep understanding.','She gave an insightful commentary on the future of AI.','ADJECTIVE','Thể hiện sự hiểu biết sâu sắc và chính xác.','Cô ấy đã đưa ra một bài bình luận sâu sắc về tương lai của AI.','Sâu sắc/Có cái nhìn sáng suốt',781,NULL,_binary '\0'),(841,'A simplified drawing showing the appearance, structure, or workings of something.','The class diagram shows the relationship between different objects.','NOUN','Một bản vẽ đơn giản hóa thể hiện cấu trúc hoặc cách hoạt động của thứ gì đó.','Sơ đồ lớp thể hiện mối quan hệ giữa các đối tượng khác nhau.','Sơ đồ/Biểu đồ',782,NULL,_binary '\0'),(843,'Clear enough to be read.','Make sure the text on your slides is legible even from the back of the room.','ADJECTIVE','Đủ rõ ràng để có thể đọc được (thường dùng cho văn bản trên slide).','Hãy đảm bảo văn bản trên slide dễ đọc ngay cả từ cuối phòng.','Dễ đọc/Rõ ràng',784,NULL,_binary '\0'),(844,'With the use of pictures, charts, or graphs.','The data is represented graphically to make it easier to understand.','ADVERB','Sử dụng hình ảnh hoặc biểu đồ để trình bày.','Dữ liệu được trình bày bằng đồ họa để dễ hiểu hơn.','Bằng đồ họa/Một cách trực quan',785,NULL,_binary '\0'),(845,'A mathematical illustration of data.','This pie chart shows the distribution of mobile users in Vietnam.','NOUN','Một hình ảnh minh họa dữ liệu toán học.','Biểu đồ hình tròn này cho thấy sự phân bổ người dùng di động tại Việt Nam.','Biểu đồ/Đồ thị',786,NULL,_binary '\0'),(846,'To pick out and emphasize.','Use a different color to highlight the key findings.','VERB','Làm cho một phần thông tin trở nên dễ chú ý hơn.','Sử dụng màu khác để làm nổi bật các phát hiện chính.','Làm nổi bật/Nhấn mạnh',787,NULL,_binary '\0'),(847,'Preventing concentration or diverting attention.','Avoid using too many animations, as they can be distracting.','ADJECTIVE','Làm mất sự tập trung hoặc chuyển hướng sự chú ý khỏi mục tiêu chính.','Tránh sử dụng quá nhiều hiệu ứng hoạt hình vì chúng có thể gây xao nhãng.','Gây xao nhãng/Mất tập trung',788,NULL,_binary '\0'),(848,'Smoothly and continuously, with no apparent gaps or spaces.','The video should transition seamlessly into the next slide.','ADVERB','Diễn ra mượt mà và liên tục, không có kẽ hở.','Video nên chuyển cảnh một cách liền mạch sang slide tiếp theo.','Một cách liền mạch/Trơn tru',789,NULL,_binary '\0'),(849,'A piece of printed information provided to an audience.','I have prepared a handout with the full technical specifications.','NOUN','Thông tin in sẵn được phát cho khán giả.','Tôi đã chuẩn bị một tài liệu phát tay với đầy đủ các thông số kỹ thuật.','Tài liệu phát tay',790,NULL,_binary '\0'),(850,'To give special importance or value to something in speaking or writing.','The presenter used bold text to emphasize the project deadline.','VERB','Tập trung sự chú ý đặc biệt vào điều gì đó.','Người thuyết trình đã sử dụng chữ đậm để nhấn mạnh thời hạn của dự án.','Nhấn mạnh/Đề cao',791,NULL,_binary '\0'),(851,'Belonging or relating to a style or fashion that is very simple and uses only a small number of colors or elements.','A minimalist design helps the audience focus on the main message.','ADJECTIVE','Phong cách đơn giản, sử dụng ít màu sắc hoặc các yếu tố trang trí.','Thiết kế tối giản giúp khán giả tập trung vào thông điệp chính.','Tối giản',792,NULL,_binary '\0'),(852,'In a way that produces very clear images in the mind.','The high-quality images vividly portrayed the user experience.','ADVERB','Mô tả theo cách tạo ra hình ảnh rất rõ ràng trong trí óc.','Các hình ảnh chất lượng cao đã mô tả trải nghiệm người dùng một cách sống động.','Một cách sống động/Rõ rệt',793,NULL,_binary '\0'),(853,'A visual representation of information or data.','This infographic summarizes the key features of the Flutter framework.','NOUN','Sự kết hợp giữa thông tin và hình ảnh đồ họa.','Đồ họa thông tin này tóm tắt các tính năng chính của framework Flutter.','Đồ họa thông tin',794,NULL,_binary '\0'),(854,'To include something within something else.','We should incorporate more videos into our presentation.','VERB','Bao gồm một thứ gì đó vào trong một cái tổng thể.','Chúng ta nên đưa thêm nhiều video vào bài thuyết trình của mình.','Kết hợp/Tích hợp',795,NULL,_binary '\0'),(855,'Concerned with beauty or the appreciation of beauty.','The aesthetic appeal of the slides is just as important as the content.','ADJECTIVE','Liên quan đến vẻ đẹp hoặc sự cảm thụ vẻ đẹp.','Sự cuốn hút về mặt thẩm mỹ của slide cũng quan trọng như nội dung vậy.','Có tính thẩm mỹ/Đẹp',796,NULL,_binary '\0'),(856,'A general direction in which something is developing or changing.','We are seeing a positive trend in user engagement this month.','NOUN','Một hướng phát triển hoặc thay đổi chung của một sự việc.','Chúng tôi đang thấy một xu hướng tích cực trong việc tương tác của người dùng tháng này.','Xu hướng',797,NULL,_binary '\0'),(857,'To examine something methodically and in detail.','We need to analyze the data before making a decision.','VERB','Xem xét cái gì đó một cách có phương pháp và chi tiết.','Chúng ta cần phân tích dữ liệu trước khi đưa ra quyết định.','Phân tích',798,NULL,_binary '\0'),(858,'Sufficiently great or important to be worthy of attention; noteworthy.','There has been a significant increase in app downloads.','ADJECTIVE','Đủ lớn hoặc đủ quan trọng để đáng được chú ý.','Đã có một sự gia tăng đáng kể trong lượt tải ứng dụng.','Đáng kể/Quan trọng',799,NULL,_binary '\0'),(859,'In a regular and even manner.','The number of active users has been growing steadily.','ADVERB','Diễn ra một cách ổn định và đều đặn theo thời gian.','Số lượng người dùng hoạt động đã và đang tăng trưởng đều đặn.','Một cách đều đặn/Vững chắc',800,NULL,_binary '\0'),(860,'An estimate or forecast of a future situation based on a study of present trends.','Our financial projections for the next quarter look promising.','NOUN','Một ước tính về tình hình trong tương lai dựa trên các xu hướng hiện tại.','Các dự phóng tài chính của chúng tôi cho quý tới trông rất hứa hẹn.','Sự dự đoán/Dự phóng',801,NULL,_binary '\0'),(861,'To rise and fall irregularly in number or amount.','The stock prices fluctuated wildly last week.','VERB','Tăng giảm không đều về số lượng hoặc giá trị.','Giá cổ phiếu đã biến động dữ dội vào tuần trước.','Biến động/Thay đổi thất thường',802,NULL,_binary '\0'),(862,'Of considerable importance, size, or worth.','We have made substantial progress on the new API integration.','ADJECTIVE','Có tầm quan trọng, kích thước hoặc giá trị đáng kể.','Chúng tôi đã đạt được tiến bộ đáng kể trong việc tích hợp API mới.','Lớn/Đáng kể',803,NULL,_binary '\0'),(863,'In an exciting or impressive manner; by a large amount.','Technology has changed dramatically over the last decade.','ADVERB','Thay đổi một cách mạnh mẽ và gây ấn tượng mạnh.','Công nghệ đã thay đổi một cách chóng mặt trong thập kỷ qua.','Một cách đột ngột/Đáng kinh ngạc',804,NULL,_binary '\0'),(864,'A mutual relationship or connection between two or more things.','There is a strong correlation between design quality and user retention.','NOUN','Mối quan hệ qua lại hoặc sự kết nối giữa hai hay nhiều thứ.','Có một sự tương quan mạnh mẽ giữa chất lượng thiết kế và việc giữ chân người dùng.','Sự tương quan',805,NULL,_binary '\0'),(865,'To perform better than.','Our new mobile app is expected to outperform its competitors.','VERB','Đạt được kết quả tốt hơn so với đối tượng khác.','Ứng dụng di động mới của chúng tôi được kỳ vọng sẽ vượt trội hơn các đối thủ cạnh tranh.','Làm tốt hơn/Vượt trội hơn',806,NULL,_binary '\0'),(866,'Liable to change rapidly and unpredictably.','The market is currently very volatile due to the economic crisis.','ADJECTIVE','Dễ dàng thay đổi nhanh chóng và khó dự đoán.','Thị trường hiện đang rất biến động do khủng hoảng kinh tế.','Dễ biến động/Không ổn định',807,NULL,_binary '\0'),(867,'In every case or on every occasion; invariably.','He has consistently delivered high-quality code.','ADVERB','Luôn luôn giữ nguyên một phong độ hoặc cách thức.','Anh ấy đã luôn cung cấp mã nguồn chất lượng cao một cách nhất quán.','Một cách nhất quán/Luôn luôn',808,NULL,_binary '\0'),(869,'To point out; show.','Recent figures indicate that the company is recovering.','VERB','Làm cho thấy sự hiện diện hoặc sự thật của điều gì đó.','Các con số gần đây cho thấy công ty đang hồi phục.','Chỉ ra/Cho thấy',810,NULL,_binary '\0'),(870,'Firmly fixed, supported, or balanced; not shaking or moving.','We are hoping for a steady expansion of our network.','ADJECTIVE','Giữ ở trạng thái cân bằng hoặc phát triển không đổi.','Chúng tôi hy vọng vào một sự mở rộng mạng lưới ổn định.','Ổn định/Vững chắc',811,NULL,_binary '\0'),(871,'An act of asking for information.','We welcome any inquiries regarding the technical implementation.','NOUN','Hành động hỏi để lấy thông tin hoặc làm rõ vấn đề.','Chúng tôi hoan nghênh mọi câu hỏi liên quan đến việc triển khai kỹ thuật.','Câu hỏi/Sự thẩm vấn',812,NULL,_binary '\0'),(873,'Performed or occurring as a result of a sudden impulse rather than being planned.','The speaker gave a spontaneous answer that impressed the board.','ADJECTIVE','Được thực hiện do sự thôi thúc nhất thời thay vì được lên kế hoạch trước.','Diễn giả đã đưa ra một câu trả lời ngẫu hứng làm ấn tượng ban điều hành.','Ngẫu hứng/Tự phát',814,NULL,_binary '\0'),(874,'In a thorough manner; completely and with great attention to detail.','Please ensure all concerns are addressed thoroughly during the Q&A.','ADVERB','Thực hiện một cách đầy đủ và chú ý đến từng chi tiết.','Hãy đảm bảo mọi lo ngại đều được giải quyết kỹ lưỡng trong phần hỏi đáp.','Một cách kỹ lưỡng/Hoàn toàn',815,NULL,_binary '\0'),(877,'Good at persuading someone to do or believe something.','The expert provided a very persuasive argument during the Q&A session.','ADJECTIVE','Có khả năng khiến người khác tin tưởng hoặc làm theo.','Vị chuyên gia đã đưa ra một lập luận rất thuyết phục trong phiên hỏi đáp.','Có tính thuyết phục',818,NULL,_binary '\0'),(878,'In a way that shows respect.','Always listen to the questioner respectfully before answering.','ADVERB','Hành xử hoặc nói năng theo cách thể hiện sự tôn trọng.','Luôn lắng nghe người hỏi một cách tôn trọng trước khi trả lời.','Một cách tôn trọng/Kính cẩn',819,NULL,_binary '\0'),(880,'To express something in an alternative way, especially for clarity.','Let me rephrase my answer to make it clearer.','VERB','Nói hoặc viết lại theo cách khác để dễ hiểu hơn.','Để tôi diễn đạt lại câu trả lời để làm nó rõ ràng hơn.','Diễn đạt lại/Cấu trúc lại câu',821,NULL,_binary '\0'),(882,'In a way that shows confidence or certainty.','The developer confidently addressed the concerns about security.','ADVERB','Thực hiện theo cách thể hiện sự chắc chắn và tin tưởng.','Nhà phát triển đã tự tin giải quyết các lo ngại về bảo mật.','Một cách tự tin',823,NULL,_binary '\0'),(884,'To accept or admit the existence or truth of.','I acknowledge your point about the potential budget risks.','VERB','Chấp nhận hoặc thừa nhận sự tồn tại hoặc sự thật của điều gì đó.','Tôi ghi nhận quan điểm của bạn về những rủi ro ngân sách tiềm ẩn.','Công nhận/Xác nhận',825,NULL,_binary '\0'),(885,'Mutually opposed or inconsistent.','The two reports contain contradictory information about the user growth.','ADJECTIVE','Đối lập nhau hoặc không nhất quán.','Hai báo cáo chứa thông tin mâu thuẫn về sự tăng trưởng người dùng.','Mâu thuẫn/Trái ngược',826,NULL,_binary '\0'),(886,'The process of changing from one state or condition to another.','A smooth transition between slides keeps the audience engaged.','NOUN','Quá trình chuyển từ ý này sang ý khác hoặc từ giai đoạn này sang giai đoạn khác.','Sự chuyển tiếp mượt mà giữa các slide giúp giữ chân khán giả.','Sự chuyển tiếp',827,NULL,_binary '\0'),(887,'To change from one form or state to another.','Now, let\'s transition to the next part of our project.','VERB','Thực hiện việc chuyển đổi trạng thái hoặc nội dung.','Bây giờ, hãy chuyển sang phần tiếp theo của dự án chúng ta.','Chuyển tiếp/Chuyển giao',827,NULL,_binary '\0'),(889,'Following in a logical order or sequence.','The tutorial provides sequential steps to install the Flutter environment.','ADJECTIVE','Sắp xếp theo một thứ tự logic nhất định.','Bài hướng dẫn cung cấp các bước theo trình tự để cài đặt môi trường Flutter.','Theo trình tự/Liên tiếp',829,NULL,_binary '\0'),(890,'As a result.','The server was down; consequently, we couldn\'t demonstrate the live chat.','ADVERB','Kết quả của hành động hoặc sự việc vừa được nhắc đến.','Máy chủ đã bị sập; hệ quả là chúng tôi không thể trình diễn tính năng chat trực tiếp.','Hệ quả là/Do đó',830,NULL,_binary '\0'),(893,'Logical and consistent.','Your presentation needs a coherent structure to be effective.','ADJECTIVE','Có tính logic và nhất quán xuyên suốt.','Bài thuyết trình của bạn cần một cấu trúc mạch lạc để đạt hiệu quả.','Mạch lạc/Chặt chẽ',833,NULL,_binary '\0'),(894,'In addition; besides.','The app is fast; furthermore, it is very easy to use.','ADVERB','Dùng để bổ sung thêm một ý quan trọng khác.','Ứng dụng này rất nhanh; hơn nữa, nó còn rất dễ sử dụng.','Hơn nữa/Thêm vào đó',834,NULL,_binary '\0'),(896,'To bring something to an end.','To conclude, I would like to emphasize our commitment to quality.','VERB','Đưa một nội dung hoặc buổi nói chuyện đến hồi kết.','Để kết luận, tôi muốn nhấn mạnh cam kết của chúng tôi về chất lượng.','Kết luận/Kết thúc',836,NULL,_binary '\0'),(897,'Serving as an example or explanation.','I will show you some illustrative examples of our UI design.','ADJECTIVE','Đóng vai trò làm ví dụ hoặc giải thích rõ hơn.','Tôi sẽ cho bạn xem một vài ví dụ minh họa về thiết kế UI của chúng tôi.','Mang tính minh họa',837,NULL,_binary '\0'),(898,'In a similar way.','The web version is fast; similarly, the mobile app performs well.','ADVERB','Dùng để nối hai ý có tính chất tương đồng.','Phiên bản web rất nhanh; tương tự, ứng dụng di động cũng hoạt động rất tốt.','Tương tự/Một cách giống nhau',838,NULL,_binary '\0'),(899,'A summary of what has been said.','Let\'s do a quick recap of the project requirements.','NOUN','Hành động nhắc lại các điểm quan trọng đã nêu.','Hãy cùng điểm lại nhanh các yêu cầu của dự án.','Sự tóm tắt lại/Điểm lại',839,NULL,_binary '\0'),(900,'To state again the main points of something.','Before moving on, let me recap the main advantages of this system.','VERB','Nhắc lại những điều cốt lõi.','Trước khi tiếp tục, hãy để tôi điểm lại các ưu điểm chính của hệ thống này.','Tóm tắt lại/Điểm lại ý chính',839,NULL,_binary '\0'),(901,'To leave the main subject temporarily in speech or writing.','I don\'t want to digress too much, but this point is interesting.','VERB','Tạm thời rời xa chủ đề chính để nói về một việc khác.','Tôi không muốn nói lạc đề quá nhiều, nhưng điểm này rất thú vị.','Lạc đề/Nói ngoài lề',840,NULL,_binary '\0'),(902,'Characterized by or capable of clear, sound reasoning.','The next logical step is to test the mobile application.','ADJECTIVE','Có tính lý luận rõ ràng và đúng đắn.','Bước hợp lý tiếp theo là kiểm thử ứng dụng di động.','Hợp lý/Logic',841,NULL,_binary '\0'),(904,'A key fact, point, or idea to be remembered, typically one consisting of a lesson or experience.','The main takeaway is that user security must be our top priority.','NOUN','Một ý tưởng hoặc sự thật quan trọng cần ghi nhớ sau buổi nói chuyện.','Điều cốt lõi cần nhớ là bảo mật người dùng phải là ưu tiên hàng đầu.','Điều cốt lõi/Bài học rút ra',843,NULL,_binary '\0'),(905,'Including or dealing with all or nearly all elements or aspects of something.','We have provided a comprehensive review of the alumni network features.','ADJECTIVE','Bao gồm tất cả hoặc hầu hết các khía cạnh của một vấn đề.','Chúng tôi đã đưa ra một bản đánh giá toàn diện về các tính năng của mạng lưới cựu sinh viên.','Toàn diện/Bao quát',844,NULL,_binary '\0'),(909,'Most noticeable or important.','Let\'s review the most salient points of the proposal.','ADJECTIVE','Những đặc điểm hoặc ý chính dễ nhận thấy nhất.','Hãy cùng xem lại những điểm then chốt nhất của bản đề xuất.','Nổi bật/Quan trọng nhất',848,NULL,_binary '\0'),(911,'A general description or plan giving those essential features.','Here is a brief outline of our action plan for the next month.','NOUN','Bản mô tả chung các đặc điểm thiết yếu.','Đây là bản phác thảo ngắn gọn về kế hoạch hành động của chúng tôi cho tháng tới.','Dàn ý/Nét phác thảo chính',850,NULL,_binary '\0'),(913,'Decisive or critical, especially in the success or failure of something.','Timely feedback is crucial for our development process.','ADJECTIVE','Mang tính quyết định đối với sự thành bại của một việc gì đó.','Phản hồi kịp thời là yếu tố cốt yếu cho quy trình phát triển của chúng tôi.','Cốt yếu/Rất quan trọng',852,NULL,_binary '\0'),(914,'For a short time; in a few words.','Let me explain the next steps briefly.','ADVERB','Trong thời gian ngắn hoặc bằng rất ít từ ngữ.','Hãy để tôi giải thích các bước tiếp theo một cách ngắn gọn.','Một cách ngắn gọn/Vắn tắt',853,NULL,_binary '\0'),(916,'To combine different ideas or facts into a whole.','It is difficult to synthesize all the user data into one report.','VERB','Kết hợp các ý tưởng hoặc dữ liệu khác nhau để tạo nên một kết luận chung.','Rất khó để tổng hợp tất cả dữ liệu người dùng vào trong một báo cáo.','Tổng hợp',855,NULL,_binary '\0'),(917,'Done or reached decisively and with authority.','We are still waiting for a definitive answer from the board.','ADJECTIVE','Được đưa ra một cách chắc chắn và không thể thay đổi.','Chúng tôi vẫn đang chờ đợi một câu trả lời cuối cùng từ ban điều hành.','Cuối cùng/Mang tính quyết định',856,NULL,_binary '\0'),(918,'A movement of part of the body, especially a hand or the head, to express an idea or meaning.','Using open hand gestures can make you appear more trustworthy.','NOUN','Sự di chuyển của một phần cơ thể để diễn đạt một ý tưởng.','Sử dụng cử chỉ tay mở có thể giúp bạn trông đáng tin cậy hơn.','Cử chỉ/Điệu bộ',857,NULL,_binary '\0'),(919,'To keep something in a particular state or condition.','It is important to maintain eye contact with your audience.','VERB','Giữ một trạng thái hoặc hành động nào đó không đổi.','Việc duy trì giao tiếp bằng mắt với khán giả là rất quan trọng.','Duy trì/Giữ vững',858,NULL,_binary '\0'),(922,'The position in which someone holds their body when standing or sitting.','Good posture can significantly improve your vocal projection.','NOUN','Cách một người giữ cơ thể khi đứng hoặc ngồi.','Tư thế tốt có thể cải thiện đáng kể khả năng phát âm của bạn.','Tư thế/Dáng đứng',861,NULL,_binary '\0'),(925,'In a way that shows intense and eager enjoyment, interest, or approval.','She spoke enthusiastically about the potential of the new Flutter app.','ADVERB','Thể hiện sự yêu thích và quan tâm mạnh mẽ.','Cô ấy đã nói một cách đầy nhiệt huyết về tiềm năng của ứng dụng Flutter mới.','Một cách nhiệt tình/Hăng hái',864,NULL,_binary '\0'),(926,'The impressive manner or appearance of a person.','The developer has a strong stage presence that commands attention.','NOUN','Vẻ ngoài hoặc cách hành xử gây ấn tượng của một người.','Nhà phát triển có một phong thái sân khấu mạnh mẽ, thu hút mọi sự chú ý.','Phong thái/Sự hiện diện',865,NULL,_binary '\0'),(927,'To transport or carry to a place; to communicate a message.','Your body language should convey confidence and openness.','VERB','Giao tiếp hoặc làm cho người khác hiểu một thông điệp.','Ngôn ngữ cơ thể của bạn nên truyền tải sự tự tin và cởi mở.','Truyền tải/Truyền đạt',866,NULL,_binary '\0'),(928,'Effectively conveying thought or feeling.','An expressive face helps the audience connect with your story.','ADJECTIVE','Thể hiện suy nghĩ hoặc cảm xúc một cách hiệu quả.','Một khuôn mặt biểu cảm giúp khán giả kết nối với câu chuyện của bạn.','Giàu cảm xúc/Diễn cảm',867,NULL,_binary '\0'),(929,'In a manner that is suitable or proper in the circumstances.','Dress appropriately for the formal presentation to show respect.','ADVERB','Thực hiện theo cách thích hợp với hoàn cảnh.','Ăn mặc phù hợp cho buổi thuyết trình trang trọng để thể hiện sự tôn trọng.','Một cách phù hợp',868,NULL,_binary '\0'),(931,'To cause to occur or operate at the same time or rate.','Try to synchronize your gestures with the points on your slides.','VERB','Làm cho các hoạt động diễn ra cùng lúc.','Hãy cố gắng đồng bộ hóa cử chỉ của bạn với các ý trên slide.','Đồng bộ hóa',870,NULL,_binary '\0'),(932,'So delicate or precise as to be difficult to analyze or describe.','A subtle nod of the head can indicate that you are listening to a question.','ADJECTIVE','Rất tinh vi hoặc khéo léo, không quá lộ liễu.','Một cái gật đầu nhẹ nhàng có thể cho thấy bạn đang lắng nghe câu hỏi.','Tinh tế/Khéo léo',871,NULL,_binary '\0'),(933,'A formal plan or suggestion put forward for consideration.','We submitted a detailed proposal for the alumni network system.','NOUN','Một kế hoạch hoặc gợi ý chính thức được đưa ra để xem xét.','Chúng tôi đã nộp một bản đề xuất chi tiết cho hệ thống mạng lưới cựu sinh viên.','Bản đề xuất/Đề nghị',872,NULL,_binary '\0'),(934,'To put forward an idea or plan for consideration.','I propose that we use Flutter to develop the mobile version.','VERB','Đưa ra một ý tưởng hoặc kế hoạch để thảo luận.','Tôi đề xuất chúng ta sử dụng Flutter để phát triển phiên bản di động.','Đề xuất/Kiến nghị',873,NULL,_binary '\0'),(935,'As good as or better than others of a comparable nature.','We offer a competitive price for high-quality software development.','ADJECTIVE','Tốt bằng hoặc hơn các đối thủ khác (thường nói về giá cả hoặc chất lượng).','Chúng tôi đưa ra một mức giá cạnh tranh cho dịch vụ phát triển phần mềm chất lượng cao.','Có tính cạnh tranh',874,NULL,_binary '\0'),(936,'In a way that is experienced or done by each of two or more parties.','We aim to reach a mutually beneficial agreement.','ADVERB','Theo cách mà cả hai bên đều cùng thực hiện hoặc cảm nhận.','Chúng tôi đặt mục tiêu đạt được một thỏa thuận có lợi cho cả hai bên.','Lẫn nhau/Cùng nhau',875,NULL,_binary '\0'),(937,'A formal statement setting out the estimated cost for a particular job.','Could you provide a written quotation for the server maintenance?','NOUN','Văn bản chính thức nêu chi phí ước tính cho một công việc cụ thể.','Bạn có thể cung cấp một bản báo giá bằng văn bản cho việc bảo trì máy chủ không?','Bản báo giá',876,NULL,_binary '\0'),(938,'To concentrate on and become expert in a particular subject or skill.','Our company specializes in building responsive web applications.','VERB','Tập trung và trở thành chuyên gia trong một lĩnh vực cụ thể.','Công ty chúng tôi chuyên về xây dựng các ứng dụng web đáp ứng.','Chuyên về/Chuyên môn hóa',877,NULL,_binary '\0'),(939,'Featuring new methods; advanced and original.','This proposal includes several innovative solutions for real-time chat.','ADJECTIVE','Sử dụng các phương pháp mới, tiên tiến và độc đáo.','Bản đề xuất này bao gồm một vài giải pháp sáng tạo cho tính năng chat thời gian thực.','Đổi mới/Sáng tạo',878,NULL,_binary '\0'),(941,'An offer of a price, especially at an auction.','Several firms have put in a bid for the government software project.','NOUN','Mức giá đề nghị để thực hiện một dự án hoặc mua tài sản.','Nhiều công ty đã tham gia đấu thầu cho dự án phần mềm của chính phủ.','Giá thầu/Sự bỏ thầu',880,NULL,_binary '\0'),(943,'Effective or productive in relation to its cost.','Using open-source libraries is a cost-effective way to develop apps.','ADJECTIVE','Đạt được kết quả tốt mà không tốn quá nhiều chi phí.','Sử dụng các thư viện mã nguồn mở là một cách tiết kiệm chi phí để phát triển ứng dụng.','Hiệu quả về chi phí',882,NULL,_binary '\0'),(944,'In a way that is good at persuading someone to do or believe something.','The sales manager presented the offer very persuasively.','ADVERB','Nói hoặc trình bày theo cách làm người khác tin tưởng.','Trưởng phòng kinh doanh đã trình bày lời đề nghị một cách rất thuyết phục.','Một cách thuyết phục',883,NULL,_binary '\0'),(945,'An offer made in response to another.','After we declined the initial price, they made a reasonable counteroffer.','NOUN','Một lời đề nghị mới được đưa ra sau khi từ chối lời đề nghị trước đó.','Sau khi chúng tôi từ chối mức giá ban đầu, họ đã đưa ra một lời đề nghị ngược lại hợp lý.','Lời phản hồi/Đề nghị ngược lại',884,NULL,_binary '\0'),(947,'Producing a great deal of profit.','The partnership with the AI firm turned out to be very lucrative.','ADJECTIVE','Mang lại rất nhiều tiền hoặc lợi ích kinh tế.','Sự hợp tác với công ty AI đó hóa ra lại mang về lợi nhuận rất lớn.','Có lợi nhuận/Sinh lời',886,NULL,_binary '\0'),(948,'An offer made in response to a previous unsatisfactory one.','We rejected their first bid and made a counter-offer with a lower price.','NOUN','Đề nghị mới sau khi từ chối đề nghị trước đó.','Chúng tôi đã từ chối giá thầu đầu tiên và đưa ra đề nghị ngược lại với giá thấp hơn.','Lời đề nghị phản hồi',887,NULL,_binary '\0'),(951,'Able to be agreed on; suitable.','The terms of your counter-offer are acceptable to our development team.','ADJECTIVE','Đủ tốt hoặc phù hợp để có thể đồng ý.','Các điều khoản trong đề nghị phản hồi của bạn có thể chấp nhận được với đội ngũ phát triển.','Chấp nhận được',889,NULL,_binary '\0'),(952,'In a way that is able to change or be changed easily.','We need to negotiate flexibly to keep the client interested.','ADVERB','Hành động có thể thay đổi tùy vào hoàn cảnh.','Chúng ta cần đàm phán linh hoạt để giữ chân khách hàng.','Linh hoạt',890,NULL,_binary '\0'),(954,'To dismiss as inadequate or inappropriate.','The board rejected the counter-offer because the cost was too high.','VERB','Không chấp nhận một đề nghị hoặc ý tưởng.','Ban điều hành đã từ chối đề nghị phản hồi vì chi phí quá cao.','Từ chối',892,NULL,_binary '\0'),(955,'A situation in which no progress can be made.','The negotiation is currently deadlocked over the ownership of the source code.','ADJECTIVE','Tình trạng không thể đi đến thống nhất.','Cuộc đàm phán hiện đang bế tắc về quyền sở hữu mã nguồn.','Bế tắc',893,NULL,_binary '\0'),(957,'Conditions under which an agreement is reached.','You should review the payment terms in the counter-offer carefully.','NOUN','Các quy định cụ thể trong một thỏa thuận.','Bạn nên xem kỹ các điều khoản thanh toán trong đề nghị phản hồi.','Điều khoản',895,NULL,_binary '\0'),(958,'To take away something from a situation.','If they don\'t accept our counter-offer, we might withdraw from the project.','VERB','Lấy lại một lời đề nghị hoặc cam kết.','Nếu họ không chấp nhận đề nghị của chúng tôi, chúng tôi có thể rút khỏi dự án.','Rút lại',896,NULL,_binary '\0'),(959,'Not likely to change; fixed.','We must remain firm on our security requirements for the alumni site.','ADJECTIVE','Không dễ thay đổi ý kiến hoặc quyết định.','Chúng ta phải giữ vững lập trường về các yêu cầu bảo mật cho trang cựu sinh viên.','Cứng rắn',897,NULL,_binary '\0'),(960,'In a way that involves working together.','The two teams worked cooperatively to resolve the API conflict.','ADVERB','Làm việc cùng nhau vì mục tiêu chung.','Hai đội đã làm việc hợp tác để giải quyết xung đột API.','Một cách hợp tác',898,NULL,_binary '\0'),(961,'The power to influence a situation.','Our expertise in Flutter gives us significant leverage in this negotiation.','NOUN','Khả năng gây ảnh hưởng để đạt mục tiêu.','Chuyên môn về Flutter mang lại cho chúng ta lợi thế lớn trong cuộc đàm phán này.','Thế mạnh',899,NULL,_binary '\0'),(962,'To alter something slightly.','We can adjust the pricing if you agree to a longer contract.','VERB','Thay đổi một chút để phù hợp hơn.','Chúng tôi có thể điều chỉnh giá nếu bạn đồng ý ký hợp đồng dài hạn hơn.','Điều chỉnh',900,NULL,_binary '\0'),(963,'Fair and sensible.','They made a reasonable counter-offer that we are currently considering.','ADJECTIVE','Công bằng và có cơ sở rõ ràng.','Họ đã đưa ra một đề nghị phản hồi hợp lý mà chúng tôi đang xem xét.','Hợp lý',901,NULL,_binary '\0'),(966,'A balance achieved between two desirable but incompatible features.','There is always a trade-off between app performance and high-end graphics.','NOUN','Sự cân bằng giữa hai yếu tố không thể có cùng lúc.','Luôn có một sự đánh đổi giữa hiệu năng ứng dụng và đồ họa cao cấp.','Sự đánh đổi',904,NULL,_binary '\0'),(967,'Open to discussion or modification.','The initial price is negotiable if you order in bulk.','ADJECTIVE','Có thể thảo luận để thay đổi hoặc điều chỉnh.','Mức giá ban đầu có thể thương lượng nếu bạn đặt hàng số lượng lớn.','Có thể thương lượng',905,NULL,_binary '\0'),(968,'The quality of bending easily or being easily modified.','Showing flexibility in payment terms can help build a long-term relationship.','NOUN','Khả năng điều chỉnh dễ dàng theo tình huống.','Thể hiện sự linh hoạt trong các điều khoản thanh toán có thể giúp xây dựng mối quan hệ lâu dài.','Sự linh hoạt',906,NULL,_binary '\0'),(971,'In a way that is severe, difficult, or not flexible.','The client reacted stiffly when we suggested a price increase.','ADVERB','Hành động thiếu linh hoạt hoặc quá nghiêm khắc.','Khách hàng phản ứng khá cứng nhắc khi chúng tôi đề xuất tăng giá.','Một cách cứng nhắc',909,NULL,_binary '\0'),(973,'Given, felt, or done in return.','A reciprocal agreement ensures that both parties provide support to each other.','ADJECTIVE','Hành động được thực hiện để đáp lại một hành động khác.','Một thỏa thuận tương hỗ đảm bảo rằng cả hai bên đều hỗ trợ lẫn nhau.','Có tính qua lại/Tương hỗ',911,NULL,_binary '\0'),(974,'To give way to arguments, demands, or pressure.','Neither side was willing to yield on the issue of data privacy.','VERB','Ngừng phản kháng và chấp nhận yêu cầu của đối phương.','Không bên nào chịu nhường bộ về vấn đề quyền riêng tư dữ liệu.','Nhường/Chịu thua',912,NULL,_binary '\0'),(975,'Relating to the identification of long-term or overall aims.','It was a strategic decision to offer the first month of the service for free.','ADJECTIVE','Liên quan đến các mục tiêu dài hạn và tổng thể.','Đó là một quyết định mang tính chiến lược khi cung cấp tháng đầu tiên miễn phí.','Mang tính chiến lược',913,NULL,_binary '\0'),(976,'A state in which opposing forces or influences are balanced.','Bargaining is about finding an equilibrium between price and quality.','NOUN','Trạng thái mà các thế lực đối lập đạt được sự ổn định.','Thương lượng là việc tìm kiếm sự cân bằng giữa giá cả và chất lượng.','Sự cân bằng',914,NULL,_binary '\0'),(977,'In an unceasingly intense or harsh way.','He relentlessly pushed for more concessions during the meeting.','ADVERB','Thực hiện một cách liên tục và mãnh liệt.','Anh ta liên tục thúc ép để có thêm nhiều sự nhượng bộ trong cuộc họp.','Một cách không ngừng nghỉ/Kiên quyết',915,NULL,_binary '\0'),(978,'To demand or specify a requirement, typically as part of a bargain.','The contract stipulates that all code must be documented in English.','VERB','Nêu rõ một yêu cầu cụ thể như một phần của thỏa thuận.','Hợp đồng quy định rằng tất cả mã nguồn phải được viết tài liệu bằng tiếng Anh.','Quy định/Đặt điều kiện',916,NULL,_binary '\0'),(979,'A physical or mental feature which is regarded as indicating a condition of disease.','A slow loading speed is just a symptom of a deeper database issue.','NOUN','Biểu hiện bên ngoài của một vấn đề lớn hơn.','Tốc độ tải chậm chỉ là triệu chứng của một vấn đề cơ sở dữ liệu sâu xa hơn.','Triệu chứng/Dấu hiệu',917,NULL,_binary '\0'),(980,'To identify the nature of a problem or illness by examination.','We need to diagnose why the Flutter app crashes on older Android versions.','VERB','Xác định bản chất của một vấn đề thông qua kiểm tra.','Chúng ta cần chẩn đoán tại sao ứng dụng Flutter bị treo trên các bản Android cũ.','Chẩn đoán',918,NULL,_binary '\0'),(981,'Real but not immediately obvious.','We must address the underlying cause of the team\'s low productivity.','ADJECTIVE','Thực tế nhưng không dễ nhận thấy ngay lập tức.','Chúng ta phải giải quyết nguyên nhân sâu xa dẫn đến năng suất thấp của nhóm.','Cơ bản/Nằm dưới bề mặt',919,NULL,_binary '\0'),(982,'To carry out a systematic or formal inquiry to discover and examine the facts.','The QA team will investigate the reported bugs in the chat module.','VERB','Thực hiện tìm hiểu có hệ thống để khám phá sự thật.','Đội QA sẽ điều tra các lỗi được báo cáo trong mô-đun trò chuyện.','Điều tra/Nghiên cứu',920,NULL,_binary '\0'),(983,'A circumstance, fact, or influence that contributes to a result.','Human error was a major factor in the data leak.','NOUN','Một tình huống hoặc sự thật góp phần vào kết quả.','Lỗi con người là một yếu tố chính trong vụ rò rỉ dữ liệu.','Yếu tố/Nhân tố',921,NULL,_binary '\0'),(984,'Done or acting according to a fixed plan or system; methodical.','We applied a systematic approach to finding the memory leak.','ADJECTIVE','Được thực hiện theo một kế hoạch hoặc hệ thống cố định.','Chúng tôi đã áp dụng một cách tiếp cận có hệ thống để tìm ra lỗi rò rỉ bộ nhớ.','Có hệ thống',922,NULL,_binary '\0'),(985,'The point or place where something begins, arises, or is derived.','The origin of the conflict was a simple misunderstanding of requirements.','NOUN','Điểm bắt đầu của một vấn đề.','Nguồn gốc của cuộc xung đột là sự hiểu lầm đơn giản về yêu cầu.','Nguồn gốc/Khởi đầu',923,NULL,_binary '\0'),(986,'In an extremely thorough and careful way.','The new code must be rigorously tested before deployment.','ADVERB','Thực hiện một cách cực kỳ kỹ lưỡng và cẩn thận.','Mã nguồn mới phải được kiểm tra một cách nghiêm ngặt trước khi triển khai.','Một cách nghiêm ngặt/Khắt khe',924,NULL,_binary '\0'),(987,'To completely remove or get rid of something.','Our goal is to eliminate all security vulnerabilities in the system.','VERB','Xóa bỏ hoàn toàn điều gì đó không mong muốn.','Mục tiêu của chúng tôi là loại bỏ tất cả các lỗ hổng bảo mật trong hệ thống.','Loại bỏ',925,NULL,_binary '\0'),(989,'Occurring often or repeatedly.','We need to fix this recurrent login error once and for all.','ADJECTIVE','Xảy ra thường xuyên hoặc nhiều lần.','Chúng ta cần khắc phục lỗi đăng nhập lặp đi lặp lại này một lần và mãi mãi.','Định kỳ/Lặp lại',927,NULL,_binary '\0'),(992,'To identify and separate a problem from other things.','We managed to isolate the bug to a single function in the API.','VERB','Xác định và tách một vấn đề ra khỏi những thứ khác.','Chúng tôi đã cô lập được lỗi nằm trong một hàm duy nhất của API.','Cô lập/Tách biệt',930,NULL,_binary '\0'),(995,'To intervene between people in a dispute in order to bring about an agreement.','The project manager had to mediate between the two developers.','VERB','Can thiệp vào một cuộc tranh chấp để giúp các bên đạt được thỏa thuận.','Quản lý dự án đã phải đứng ra hòa giải giữa hai lập trình viên.','Hòa giải/Làm trung gian',933,NULL,_binary '\0'),(997,'Not supporting or helping either side in a conflict.','It is best to remain neutral while listening to both sides of the argument.','ADJECTIVE','Không đứng về phía nào trong một cuộc xung đột.','Tốt nhất là nên giữ thái độ trung lập khi lắng nghe cả hai bên tranh luận.','Trung lập',935,NULL,_binary '\0'),(1000,'Conflict or animosity caused by a clash of wills or temperaments.','Poor communication often causes friction within the team.','NOUN','Sự bất hòa do xung đột về ý chí hoặc tính cách.','Giao tiếp kém thường gây ra sự bất đồng trong nội bộ nhóm.','Sự ma sát/Bất đồng',938,NULL,_binary '\0'),(1001,'Having or showing a confident and forceful personality.','You need to be assertive when discussing the technical feasibility of a feature.','ADJECTIVE','Thể hiện sự tự tin và kiên định với quan điểm của mình.','Bạn cần quyết đoán khi thảo luận về tính khả thi kỹ thuật của một tính năng.','Quả quyết/Quyết đoán',939,NULL,_binary '\0'),(1002,'The skill of managing international relations, typically by a country\'s representatives abroad.','Resolving this dispute will require a lot of diplomacy.','NOUN','Kỹ năng giải quyết các mối quan hệ một cách tế nhị và hiệu quả.','Việc giải quyết tranh chấp này sẽ đòi hỏi rất nhiều sự khéo léo.','Sự khéo léo/Ngoại giao',940,NULL,_binary '\0'),(1003,'To bring into harmony or agreement.','We need to harmonize our coding standards across the entire department.','VERB','Đưa các ý kiến khác nhau về trạng thái đồng thuận.','Chúng ta cần thống nhất các tiêu chuẩn mã nguồn trong toàn bộ bộ phận.','Làm cho hài hòa/Thống nhất',941,NULL,_binary '\0'),(1005,'To reduce the intensity of a conflict or potentially violent situation.','His calm response helped to de-escalate the tense situation.','VERB','Làm giảm mức độ nghiêm trọng của một cuộc xung đột.','Câu trả lời bình tĩnh của anh ấy đã giúp làm dịu đi tình huống căng thẳng.','Làm dịu đi/Giảm căng thẳng',943,NULL,_binary '\0'),(1007,'A real or imagined wrong or other cause for complaint or protest.','The employees filed a grievance regarding the new overtime policy.','NOUN','Một lý do chính đáng để than phiền hoặc phản đối.','Các nhân viên đã nộp đơn khiếu nại về chính sách làm thêm giờ mới.','Sự phàn nàn/Khiếu nại',945,NULL,_binary '\0'),(1008,'To restore friendly relations between.','It\'s hard to reconcile the need for speed with the need for security.','VERB','Khôi phục mối quan hệ tốt đẹp hoặc làm cho các ý tưởng đối lập trở nên nhất quán.','Rất khó để làm hài hòa giữa nhu cầu về tốc độ và nhu cầu về bảo mật.','Hòa giải/Làm cho nhất quán',946,NULL,_binary '\0'),(1009,'A particular and separate article, stipulation, or proviso in a treaty, bill, or contract.','The confidentiality clause prevents us from sharing the source code.','NOUN','Một mục cụ thể và riêng biệt trong một hợp đồng hoặc văn bản pháp lý.','Điều khoản bảo mật ngăn cản chúng tôi chia sẻ mã nguồn.','Điều khoản',947,NULL,_binary '\0'),(1011,'Involving an obligation that cannot be broken.','Once signed, the contract becomes a legally binding agreement.','ADJECTIVE','Liên quan đến một nghĩa vụ không thể phá bỏ.','Sau khi ký, hợp đồng trở thành một thỏa thuận có tính ràng buộc pháp lý.','Ràng buộc',949,NULL,_binary '\0'),(1012,'The state of being responsible for something, especially by law.','The developer has no liability for losses caused by third-party hosting.','NOUN','Trạng thái phải chịu trách nhiệm trước pháp luật, đặc biệt là về tài chính.','Lập trình viên không chịu trách nhiệm pháp lý cho các tổn thất do bên lưu trữ thứ ba gây ra.','Trách nhiệm pháp lý',950,NULL,_binary '\0'),(1013,'To bring to an end.','The client has the right to terminate the contract with a 30-day notice.','VERB','Làm cho một thỏa thuận hoặc hợp đồng hết hiệu lực.','Khách hàng có quyền chấm dứt hợp đồng với thông báo trước 30 ngày.','Chấm dứt/Kết thúc',951,NULL,_binary '\0'),(1015,'A condition or requirement in a legal document.','The contract includes a provision for future software updates.','NOUN','Một yêu cầu hoặc điều kiện trong văn bản pháp luật.','Hợp đồng bao gồm một điều khoản quy định cho các bản cập nhật phần mềm trong tương lai.','Điều khoản dự phòng/Quy định',953,NULL,_binary '\0'),(1016,'An act of breaking or failing to observe a law, agreement, or code of conduct.','Sharing data with competitors is a serious breach of contract.','NOUN','Hành động phá vỡ hoặc không tuân thủ luật pháp hoặc thỏa thuận.','Chia sẻ dữ liệu với đối thủ cạnh tranh là một sự vi phạm hợp đồng nghiêm trọng.','Sự vi phạm',954,NULL,_binary '\0'),(1017,'A written guarantee, issued to the purchaser of an article by its manufacturer.','We provide a one-year warranty on the software functionality.','NOUN','Cam kết bằng văn bản về chất lượng sản phẩm trong một khoảng thời gian.','Chúng tôi cung cấp bảo hành một năm cho các chức năng của phần mềm.','Sự bảo hành',955,NULL,_binary '\0'),(1018,'Security or protection against a loss or other financial burden.','The clause provides indemnity for the client in case of copyright claims.','NOUN','Sự bảo vệ hoặc cam kết trả tiền cho các tổn thất có thể xảy ra.','Điều khoản này cung cấp sự bồi thường cho khách hàng trong trường hợp có khiếu nại về bản quyền.','Sự bồi thường/Bảo đảm',956,NULL,_binary '\0'),(1020,'To compel observance of or compliance with a law, rule, or obligation.','It is difficult to enforce these terms if the contract is not signed.','VERB','Ép buộc việc tuân thủ một quy định hoặc luật lệ.','Rất khó để thực thi các điều khoản này nếu hợp đồng không được ký kết.','Thực thi/Bắt buộc tuân thủ',958,NULL,_binary '\0'),(1021,'The official power to make legal decisions and judgments.','Any legal disputes will be settled under the jurisdiction of Vietnam.','NOUN','Quyền lực chính thức để đưa ra các quyết định pháp lý (thường theo khu vực địa lý).','Mọi tranh chấp pháp lý sẽ được giải quyết theo thẩm quyền của Việt Nam.','Thẩm quyền xét xử',959,NULL,_binary '\0'),(1022,'The failure to reveal information.','You must sign a non-disclosure agreement (NDA) before joining the project.','NOUN','Cam kết không tiết lộ thông tin nhạy cảm cho bên thứ ba.','Bạn phải ký một thỏa thuận bảo mật thông tin trước khi tham gia dự án.','Sự không tiết lộ/Bảo mật thông tin',960,NULL,_binary '\0'),(1023,'A condition or requirement that is specified or demanded as part of an agreement.','One major stipulation was that the system must be accessible on mobile devices.','NOUN','Một yêu cầu cụ thể được nêu ra như một phần của thỏa thuận.','Một quy định chính là hệ thống phải có thể truy cập được trên các thiết bị di động.','Sự quy định/Điều kiện tiên quyết',961,NULL,_binary '\0'),(1024,'To complete the last part of a plan, trip, project, etc.','We are meeting tomorrow to finalize the terms of the alumni platform.','VERB','Hoàn thành phần cuối cùng của một kế hoạch hoặc dự án.','Chúng tôi sẽ họp vào ngày mai để chốt các điều khoản của nền tảng cựu sinh viên.','Hoàn tất/Chốt hạ',962,NULL,_binary '\0'),(1025,'To make something certain or complete.','A firm handshake sealed the deal between the developer and the client.','VERB','Làm cho cái gì đó trở nên chắc chắn hoặc hoàn tất (thường là thỏa thuận).','Một cái bắt tay chặt đã chốt lại thỏa thuận giữa lập trình viên và khách hàng.','Xác nhận/Đóng dấu',963,NULL,_binary '\0'),(1027,'An act of shaking someone\'s hand, typically to confirm an agreement.','In business, a virtual handshake via email can also signal a deal.','NOUN','Hành động bắt tay để xác nhận một thỏa thuận.','Trong kinh doanh, một cái bắt tay ảo qua email cũng có thể báo hiệu một thỏa thuận.','Cái bắt tay',965,NULL,_binary '\0'),(1029,'To sign or give formal consent to a treaty or agreement, making it officially valid.','The board of directors is expected to ratify the agreement by Friday.','VERB','Ký hoặc đưa ra sự đồng ý chính thức để làm cho thỏa thuận có giá trị pháp lý.','Hội đồng quản trị dự kiến sẽ phê chuẩn thỏa thuận trước thứ Sáu.','Thông qua/Phê chuẩn',967,NULL,_binary '\0'),(1030,'A promise or firm decision to do something.','We appreciate your commitment to delivering the Flutter app on time.','NOUN','Lời hứa hoặc quyết định kiên định sẽ thực hiện điều gì đó.','Chúng tôi trân trọng sự cam kết của bạn trong việc giao ứng dụng Flutter đúng hạn.','Sự cam kết',968,NULL,_binary '\0'),(1031,'To make something official or formal.','It is time to formalize our partnership with a signed document.','VERB','Làm cho một thỏa thuận miệng trở nên chính thức bằng văn bản.','Đã đến lúc chính thức hóa quan hệ đối tác của chúng ta bằng một văn bản có chữ ký.','Chính thức hóa',969,NULL,_binary '\0'),(1032,'Without opposition; with the agreement of all people involved.','The team unanimously voted to use React and Tailwind CSS for the web portal.','ADVERB','Một cách thống nhất tuyệt đối, không có sự phản đối.','Cả nhóm đã nhất trí bỏ phiếu sử dụng React và Tailwind CSS cho cổng thông tin web.','Nhất trí/Đồng lòng',970,NULL,_binary '\0'),(1036,'Subject to further confirmation; for the time being.','The schedule has been provisionally agreed upon by both parties.','ADVERB','Được chấp nhận tạm thời trước khi có sự xác nhận chính thức cuối cùng.','Lịch trình đã được cả hai bên tạm thời đồng ý.','Tạm thời',974,NULL,_binary '\0'),(1038,'Beneficial to all the parties involved.','Our goal was to create a win-win situation for the students and the lecturers.','ADJECTIVE','Mang lại lợi ích cho tất cả các bên tham gia.','Mục tiêu của chúng tôi là tạo ra một tình huống đôi bên cùng có lợi cho sinh viên và giảng viên.','Đôi bên cùng có lợi',976,NULL,_binary '\0'),(1039,'A legal agreement that allows you to use a building or land for a fixed period of time','The lease on the apartment expires next month.','NOUN','Thỏa thuận pháp lý sử dụng tài sản trong thời hạn cố định','Hợp đồng thuê căn hộ sẽ hết hạn vào tháng tới.','Hợp đồng thuê nhà',977,NULL,_binary '\0'),(1040,'To use or let someone use a building or land in exchange for rent','We decided to lease the office space for five years.','VERB','Sử dụng hoặc cho người khác sử dụng để lấy tiền thuê','Chúng tôi đã quyết định thuê văn phòng trong 5 năm.','Cho thuê/Thuê',977,NULL,_binary '\0'),(1041,'A sum of money that is given as the first part of a larger payment','We paid a one-month deposit for the new flat.','NOUN','Khoản tiền trả trước để giữ chỗ hoặc bảo đảm','Chúng tôi đã trả một tháng tiền đặt cọc cho căn hộ mới.','Tiền đặt cọc',978,NULL,_binary '\0'),(1042,'To put money into a bank account','You can deposit the rent directly into my account.','VERB','Gửi tiền vào tài khoản ngân hàng hoặc quỹ','Bạn có thể gửi tiền thuê trực tiếp vào tài khoản của tôi.','Gửi tiền',978,NULL,_binary '\0'),(1044,'To repair and improve a building so that it is in good condition again','They are renovating the old hotel to make it modern.','VERB','Sửa chữa và tân trang lại một công trình cũ','Họ đang cải tạo khách sạn cũ để làm nó hiện đại hơn.','Cải tạo, nâng cấp',980,NULL,_binary '\0'),(1045,'Rooms or buildings that are used by soldiers or workers to live in','Living quarters were provided for the staff.','NOUN','Khu vực sinh sống dành cho đối tượng cụ thể','Khu nhà ở được cung cấp cho nhân viên.','Nơi ở/Khu nhà ở',981,NULL,_binary '\0'),(1046,'One of four equal parts of something','Sales rose in the last quarter of the year.','NOUN','Một trong bốn phần bằng nhau','Doanh số tăng trong quý cuối cùng của năm.','Một phần tư',981,NULL,_binary '\0'),(1047,'Containing all the furniture that is necessary','The studio is fully-furnished and ready to move in.','ADJECTIVE','Căn hộ đã có sẵn mọi đồ đạc cần thiết','Căn hộ studio đã đủ nội thất và sẵn sàng để dọn vào.','Đầy đủ nội thất',982,NULL,_binary '\0'),(1048,'A person who owns a building and receives rent from others','The landlord is responsible for major repairs.','NOUN','Người sở hữu bất động sản cho thuê','Chủ nhà có trách nhiệm sửa chữa các hư hỏng lớn.','Chủ nhà',983,NULL,_binary '\0'),(1049,'A legal agreement by which a bank lends money to buy a property','He is still paying off the mortgage on his house.','NOUN','Hợp đồng vay tiền mua nhà dùng chính căn nhà làm vật đảm bảo','Anh ấy vẫn đang trả nợ thế chấp cho căn nhà của mình.','Vay thế chấp',984,NULL,_binary '\0'),(1050,'Public services such as electricity, gas, and water','The rent includes all utilities except for the internet.','NOUN','Các dịch vụ cơ bản phục vụ sinh hoạt','Tiền thuê bao gồm tất cả điện nước trừ internet.','Tiện ích điện nước',985,NULL,_binary '\0'),(1051,'What you can see from a particular place','The bedroom has a view of the garden.','NOUN','Góc nhìn từ một vị trí nhất định','Phòng ngủ có hướng nhìn ra khu vườn.','Hướng nhìn/Cảnh quan',986,NULL,_binary '\0'),(1052,'To look at a property before deciding to buy or rent it','We would like to view the apartment this Saturday.','VERB','Quan sát nơi ở trước khi đưa ra quyết định','Chúng tôi muốn đi xem căn hộ vào thứ Bảy này.','Xem nhà/Tham quan',986,NULL,_binary '\0'),(1053,'A person who buys and sells goods or assets for others','The real estate broker showed us several houses.','NOUN','Người trung gian kết nối người mua và người bán','Người môi giới nhà đất đã cho chúng tôi xem vài căn nhà.','Người môi giới',987,NULL,_binary '\0'),(1054,'To arrange or negotiate a deal','The government brokered a peace deal between the two sides.','VERB','Thực hiện các cuộc thương lượng để đạt được thỏa thuận','Chính phủ đã dàn xếp một thỏa thuận hòa bình giữa hai bên.','Môi giới/Dàn xếp',987,NULL,_binary '\0'),(1056,'To force someone to leave a house because they have not paid rent','The family was evicted for not paying rent for six months.','VERB','Buộc ai đó phải rời khỏi nơi ở theo luật định','Gia đình đó đã bị trục xuất vì không trả tiền thuê nhà suốt 6 tháng.','Trục xuất/Đuổi đi',989,NULL,_binary '\0'),(1057,'An expert judgment or estimate of the quality or value of something','The bank requires a professional appraisal before approving the loan.','NOUN','Đánh giá chuyên môn về giá trị của bất động sản','Ngân hàng yêu cầu định giá chuyên nghiệp trước khi duyệt khoản vay.','Sự định giá',990,NULL,_binary '\0'),(1058,'A house, especially a large or official one','This is his official residence while he is in office.','NOUN','Nơi ở chính thức hoặc một ngôi nhà lớn','Đây là nơi cư trú chính thức của ông ấy khi đương chức.','Nơi cư trú/Dinh thự',991,NULL,_binary '\0'),(1059,'To travel some distance between one\'s home and place of work on a regular basis','He commutes from Cambridge to London every day.','VERB','Di chuyển đều đặn giữa nơi ở và nơi làm việc','Anh ấy đi làm từ Cambridge đến London mỗi ngày.','Đi làm hàng ngày',992,NULL,_binary '\0'),(1060,'A regular journey of some distance to and from one\'s place of work','It\'s a long commute from the outer suburbs.','NOUN','Quãng đường di chuyển thường nhật đến chỗ làm','Đó là một quãng đường đi làm dài từ vùng ngoại ô.','Hành trình đi làm',992,NULL,_binary '\0'),(1061,'The state of being extremely full of traffic or people','The new highway was built to reduce traffic congestion.','NOUN','Tình trạng quá tải về giao thông hoặc con người','Đường cao tốc mới được xây dựng để giảm thiểu tắc nghẽn giao thông.','Sự tắc nghẽn',993,NULL,_binary '\0'),(1062,'The carrying of people or goods from one place to another','The goods were damaged in transit.','NOUN','Việc vận chuyển người hoặc hàng hóa','Hàng hóa đã bị hư hỏng trong quá trình vận chuyển.','Sự vận tải/Sự đi qua',994,NULL,_binary '\0'),(1063,'A system of buses, trains, etc. for getting around a city','The city is improving its mass transit system.','NOUN','Mạng lưới xe buýt, tàu hỏa trong thành phố','Thành phố đang cải thiện hệ thống giao thông công cộng khối lượng lớn.','Hệ thống giao thông công cộng',994,NULL,_binary '\0'),(1065,'The basic physical and organizational structures needed for the operation of a society','The government is investing in transport infrastructure.','NOUN','Hệ thống vật chất cơ bản như đường xá, cầu cống','Chính phủ đang đầu tư vào cơ sở hạ tầng giao thông.','Cơ sở hạ tầng',996,NULL,_binary '\0'),(1066,'A thing used for transporting people or goods, especially on land','Electric vehicles are becoming more popular.','NOUN','Công cụ dùng để vận chuyển người hoặc hàng hóa trên đất liền','Xe điện đang trở nên phổ biến hơn.','Phương tiện giao thông',997,NULL,_binary '\0'),(1067,'A person walking rather than travelling in a vehicle','The area is closed to vehicles to make it safer for pedestrians.','NOUN','Người di chuyển bằng chân thay vì phương tiện','Khu vực này cấm xe cộ để an toàn hơn cho người đi bộ.','Người đi bộ',998,NULL,_binary '\0'),(1069,'A vehicle that travels regularly between two places','The hotel provides a free shuttle to the airport.','NOUN','Phương tiện di chuyển đều đặn giữa hai địa điểm','Khách sạn cung cấp xe đưa đón miễn phí ra sân bay.','Xe đưa đón',1000,NULL,_binary '\0'),(1070,'To travel or take somebody between two places frequently','The bus shuttles passengers between the terminal and the car park.','VERB','Di chuyển hoặc đưa ai đó đi lại thường xuyên giữa hai nơi','Xe buýt đưa đón hành khách giữa nhà ga và bãi đậu xe.','Vận chuyển qua lại',1000,NULL,_binary '\0'),(1071,'A situation of very severe traffic congestion where no movement is possible','The accident caused total gridlock in the city centre.','NOUN','Tình trạng kẹt xe nghiêm trọng không thể di chuyển được','Vụ tai nạn đã gây ra tình trạng ùn tắc hoàn toàn ở trung tâm thành phố.','Sự đình trệ/Kẹt xe cứng nhắc',1001,NULL,_binary '\0'),(1072,'To share a car with other people to travel to work','Many employees carpool to save on petrol costs.','VERB','Chia sẻ xe với người khác để đi làm','Nhiều nhân viên đi chung xe để tiết kiệm chi phí xăng dầu.','Đi chung xe',1002,NULL,_binary '\0'),(1073,'An arrangement where people travel together in one car','Joining a carpool can reduce your daily stress.','NOUN','Sự sắp xếp người đi cùng nhau trong một xe','Tham gia nhóm đi chung xe có thể giảm bớt căng thẳng hàng ngày.','Nhóm đi chung xe',1002,NULL,_binary '\0'),(1075,'The place to which someone or something is going or being sent','It took us ten hours to reach our destination.','NOUN','Nơi mà ai đó hoặc thứ gì đó đang đi tới','Chúng tôi mất mười tiếng để đến được điểm đến.','Điểm đến',1004,NULL,_binary '\0'),(1076,'A thing that you can choose to do or have out of two or more possibilities','Cycling is a healthy alternative to driving.','NOUN','Một phương án khác có thể chọn','Đạp xe là một sự lựa chọn thay thế lành mạnh cho việc lái xe.','Sự lựa chọn thay thế',1005,NULL,_binary '\0'),(1077,'Different from the usual or traditional way','We need to find alternative routes to avoid the traffic.','ADJECTIVE','Khác với cách thông thường','Chúng ta cần tìm các tuyến đường thay thế để tránh kẹt xe.','Có tính thay thế/Khác',1005,NULL,_binary '\0'),(1078,'A boat or ship for conveying passengers and goods','We took the ferry across the river.','NOUN','Thuyền lớn chở khách và hàng hóa qua sông/biển','Chúng tôi đã đi phà qua sông.','Con phà',1006,NULL,_binary '\0'),(1079,'To carry people or goods by boat or ship','The boat ferries supplies to the island twice a week.','VERB','Vận chuyển người hoặc hàng bằng đường thủy','Con tàu chở nhu yếu phẩm ra đảo mỗi tuần hai lần.','Chở bằng phà',1006,NULL,_binary '\0'),(1081,'The act of discovering or identifying the exact cause of an illness','The early diagnosis of the disease is crucial for treatment.','NOUN','Việc xác định nguyên nhân chính xác của một căn bệnh','Việc chẩn đoán sớm căn bệnh là rất quan trọng cho việc điều trị.','Sự chẩn đoán',1008,NULL,_binary '\0'),(1082,'(of a disease) lasting for a long time; difficult to cure','He suffers from chronic back pain.','ADJECTIVE','(về bệnh tật) kéo dài trong thời gian dài và khó chữa khỏi','Anh ấy bị đau lưng mãn tính.','Mãn tính',1009,NULL,_binary '\0'),(1084,'Treatment intended to relieve or heal a disorder','She is undergoing physical therapy after her surgery.','NOUN','Phương pháp điều trị nhằm giảm bớt hoặc chữa lành một rối loạn','Cô ấy đang trải qua vật lý trị liệu sau ca phẫu thuật.','Liệu pháp/Sự điều trị',1011,NULL,_binary '\0'),(1085,'A person qualified to practise medicine, especially one who specializes in diagnosis and medical treatment','Please consult your personal physician before starting a new diet.','NOUN','Người có trình độ y khoa, chuyên về chẩn đoán và điều trị (không phẫu thuật)','Vui lòng tham khảo ý kiến bác sĩ cá nhân của bạn trước khi bắt đầu chế độ ăn mới.','Bác sĩ',1012,NULL,_binary '\0'),(1086,'The act of giving a person a vaccine to produce immunity to a disease','Flu vaccination is recommended for the elderly.','NOUN','Việc đưa vắc-xin vào cơ thể để tạo miễn dịch chống lại bệnh tật','Tiêm chủng cúm được khuyến nghị cho người cao tuổi.','Sự tiêm chủng',1013,NULL,_binary '\0'),(1087,'A thorough medical examination to make sure you are healthy','I go for a medical check-up every year.','NOUN','Cuộc khám y khoa kỹ lưỡng để đảm bảo bạn khỏe mạnh','Tôi đi kiểm tra sức khỏe tổng quát mỗi năm.','Kiểm tra tổng quát',1014,NULL,_binary '\0'),(1089,'A shop or part of a shop where medicines are prepared and sold','You can pick up your medication at the local pharmacy.','NOUN','Nơi chuẩn bị và bán các loại thuốc','Bạn có thể lấy thuốc tại nhà thuốc địa phương.','Nhà thuốc/Dược khoa',1016,NULL,_binary '\0'),(1091,'Medical treatment in which a doctor cuts open someone’s body','He underwent heart surgery last week.','NOUN','Phương pháp điều trị bằng cách mổ xẻ cơ thể','Anh ấy đã trải qua ca phẫu thuật tim vào tuần trước.','Ca phẫu thuật',1018,NULL,_binary '\0'),(1092,'A place where a doctor or dentist sees patients','The doctor is in his surgery right now.','NOUN','Nơi bác sĩ hoặc nha sĩ tiếp bệnh nhân','Bác sĩ đang ở trong phòng khám của mình lúc này.','Phòng khám/Phòng phẫu thuật',1018,NULL,_binary '\0'),(1093,'An arrangement with a company in which you pay them money and they pay the costs if you are ill','Does your health insurance cover dental work?','NOUN','Sự thỏa thuận chi trả chi phí y tế khi gặp rủi ro sức khỏe','Bảo hiểm y tế của bạn có bao trả chi phí làm răng không?','Bảo hiểm',1019,NULL,_binary '\0'),(1095,'To help somebody to have a normal life again after they have been ill','The center helps to rehabilitate people after serious accidents.','VERB','Giúp ai đó trở lại cuộc sống bình thường sau bệnh tật hoặc chấn thương','Trung tâm giúp phục hồi chức năng cho mọi người sau các tai nạn nghiêm trọng.','Phục hồi chức năng',1021,NULL,_binary '\0'),(1099,'Something bought for less than the usual price','This coat was a real bargain at only $20.','NOUN','Thứ mua được với giá rẻ hơn bình thường','Chiếc áo khoác này là một món hời thực sự với giá chỉ 20 đô.','Món hời',1024,NULL,_binary '\0'),(1100,'To discuss prices with somebody in order to reach an agreement','In some markets, you are expected to bargain.','VERB','Thương lượng để có giá tốt hơn','Ở một số khu chợ, bạn nên mặc cả.','Mặc cả',1024,NULL,_binary '\0'),(1101,'A written list of all the objects, furniture, etc. in a particular building','The store is closed for annual inventory.','NOUN','Danh sách hàng hóa hoặc tài sản hiện có','Cửa hàng đóng cửa để kiểm kê hàng năm.','Hàng tồn kho/Sự kiểm kê',1025,NULL,_binary '\0'),(1102,'Connected with the business of selling goods in large quantities to other businesses','We buy our supplies at wholesale prices.','ADJECTIVE','Kinh doanh hàng hóa số lượng lớn cho các đại lý','Chúng tôi mua nhu yếu phẩm với giá sỉ.','Bán sỉ/Bán buôn',1026,NULL,_binary '\0'),(1103,'The selling of goods to the public, usually through shops','The recommended retail price is $50.','NOUN','Việc bán hàng trực tiếp đến người tiêu dùng','Giá bán lẻ đề xuất là 50 đô la.','Bán lẻ',1027,NULL,_binary '\0'),(1104,'To buy something','Tickets must be purchased two weeks in advance.','VERB','Hành động dùng tiền để đổi lấy hàng hóa','Vé phải được mua trước hai tuần.','Mua sắm',1028,NULL,_binary '\0'),(1105,'Something that you have bought','He was dissatisfied with his latest purchase.','NOUN','Thứ mà bạn đã mua về','Anh ấy không hài lòng với món đồ vừa mua gần nhất.','Vật mua được/Sự mua sắm',1028,NULL,_binary '\0'),(1107,'Goods that are bought or sold','The store has a wide range of merchandise.','NOUN','Các sản phẩm dùng để giao dịch, mua bán','Cửa hàng có rất nhiều loại hàng hóa.','Hàng hóa',1030,NULL,_binary '\0'),(1108,'A person who buys goods or services for their own use','Consumer confidence has increased this quarter.','NOUN','Người mua hàng hoặc dịch vụ để sử dụng','Niềm tin của người tiêu dùng đã tăng trong quý này.','Người tiêu dùng',1031,NULL,_binary '\0'),(1111,'To provide somebody with something that they need','The company supplies office equipment.','VERB','Đưa cho ai đó thứ họ cần','Công ty cung cấp thiết bị văn phòng.','Cung cấp',1034,NULL,_binary '\0'),(1112,'An amount of something that is provided or available to be used','Advances in agriculture increased the food supply.','NOUN','Lượng hàng hóa có sẵn để sử dụng','Sự tiến bộ trong nông nghiệp đã tăng nguồn cung thực phẩm.','Nguồn cung/Kho dự trữ',1034,NULL,_binary '\0'),(1113,'The desire of people for a particular product or service','There is a high demand for organic food.','NOUN','Sức mua hoặc mong muốn của thị trường đối với sản phẩm','Có nhu cầu cao đối với thực phẩm hữu cơ.','Nhu cầu',1035,NULL,_binary '\0'),(1114,'To ask for something very firmly','The customers demanded a refund.','VERB','Đòi hỏi một cách kiên quyết','Khách hàng đã yêu cầu được hoàn tiền.','Yêu cầu',1035,NULL,_binary '\0'),(1116,'A drink of any type','Hot beverages such as tea and coffee are served after the meal.','NOUN','Bất kỳ loại đồ uống nào trừ nước lọc','Các loại đồ uống nóng như trà và cà phê được phục vụ sau bữa ăn.','Đồ uống/Thức uống',1037,NULL,_binary '\0'),(1117,'A style of cooking','Italian cuisine is known for its pasta and pizza.','NOUN','Phong cách nấu ăn đặc trưng của một quốc gia hoặc vùng miền','Ẩm thực Ý nổi tiếng với món mì Ý và bánh pizza.','Ẩm thực/Cách chế biến',1038,NULL,_binary '\0'),(1119,'A small dish of food served before the main part of a meal','We ordered a shrimp cocktail as an appetizer.','NOUN','Món ăn nhỏ được phục vụ trước món chính để kích thích vị giác','Chúng tôi đã gọi món cocktail tôm làm món khai vị.','Món khai vị',1040,NULL,_binary '\0'),(1120,'The main dish of a meal','For my entrée, I chose the grilled salmon.','NOUN','Món ăn quan trọng nhất trong một bữa ăn','Cho món chính, tôi đã chọn cá hồi nướng.','Món chính',1041,NULL,_binary '\0'),(1121,'The right to enter a place or group','Her wealth and status gave her an entrée into upper-class society.','NOUN','Quyền được bước vào một nơi hoặc tham gia một nhóm','Sự giàu có và địa vị đã cho cô ấy quyền gia nhập vào xã hội thượng lưu.','Sự gia nhập/Quyền vào',1041,NULL,_binary '\0'),(1122,'An arrangement to keep something, such as a table in a restaurant, for a particular person','I’d like to make a reservation for two at 8 p.m.','NOUN','Việc giữ trước một thứ gì đó (như bàn ăn) cho một người cụ thể','Tôi muốn đặt bàn cho hai người vào lúc 8 giờ tối.','Sự đặt chỗ trước',1042,NULL,_binary '\0'),(1123,'A feeling of doubt or lack of confidence about a plan or idea','I have some reservations about the new menu.','NOUN','Cảm giác nghi ngờ về một kế hoạch hoặc ý tưởng','Tôi có một vài sự dè dặt về thực đơn mới.','Sự dè dặt/Hoài nghi',1042,NULL,_binary '\0'),(1126,'To provide food and drinks for a social event','Which company is catering the wedding?','VERB','Cung cấp thức ăn và đồ uống cho các sự kiện xã hội','Công ty nào đang phục vụ tiệc cho đám cưới này vậy?','Phục vụ tiệc/Cung cấp thực phẩm',1045,NULL,_binary '\0'),(1127,'A substance, such as salt or mustard, used to add flavour to food','Ketchup and mustard are common condiments.','NOUN','Các chất như muối, mù tạt... dùng để tăng thêm hương vị khi ăn','Tương cà và mù tạt là những gia vị kèm phổ biến.','Gia vị kèm',1046,NULL,_binary '\0'),(1131,'A tool that is used in the house, especially for cooking','Make sure you have all the necessary cooking utensils.','NOUN','Các công cụ dùng trong nhà bếp hoặc để ăn uống (thìa, dĩa...)','Hãy đảm bảo bạn có đầy đủ các dụng cụ nấu nướng cần thiết.','Dụng cụ/Đồ dùng',1050,NULL,_binary '\0'),(1132,'Connected with cooking or food','He is a man of great culinary skills.','ADJECTIVE','Các vấn đề liên quan đến việc nấu nướng và ăn uống','Anh ấy là một người có kỹ năng ẩm thực tuyệt vời.','Thuộc về ẩm thực/nấu nướng',1051,NULL,_binary '\0'),(1133,'A statement about what will happen in the future, based on information that is available now','The weather forecast says it will rain tomorrow.','NOUN','Thông báo về những gì sẽ xảy ra dựa trên dữ liệu hiện có','Dự báo thời tiết nói rằng ngày mai trời sẽ mưa.','Dự báo',1052,NULL,_binary '\0'),(1134,'To say what is probably going to happen in the future','Experts forecast a surge in energy prices.','VERB','Hành động đưa ra nhận định về tương lai','Các chuyên gia dự báo một sự gia tăng giá năng lượng.','Tiên đoán/Dự báo',1052,NULL,_binary '\0'),(1135,'Rain, snow, etc. that falls to the ground','The annual precipitation in this area is very high.','NOUN','Lượng nước rơi xuống mặt đất dưới các dạng khác nhau','Lượng mưa hàng năm ở khu vực này rất cao.','Lượng mưa/Lượng tuyết rơi',1053,NULL,_binary '\0'),(1136,'The amount of water vapour in the air','The high humidity makes the heat feel even worse.','NOUN','Lượng hơi nước có trong không khí','Độ ẩm cao khiến cái nóng càng trở nên tồi tệ hơn.','Độ ẩm',1054,NULL,_binary '\0'),(1137,'(of energy or natural resources) that is replaced naturally or controlled carefully and can therefore be used without the risk of finishing it all','Wind and solar power are forms of renewable energy.','ADJECTIVE','Nguồn năng lượng tự phục hồi, không lo cạn kiệt','Năng lượng gió và mặt trời là các dạng năng lượng tái tạo.','Có thể tái tạo',1055,NULL,_binary '\0'),(1138,'All the plants and living creatures in a particular area considered in relation to their physical environment','Pollution can have a disastrous effect on the delicate ecosystem.','NOUN','Quần thể sinh vật và môi trường sống của chúng','Ô nhiễm có thể gây ra tác động thảm khốc lên hệ sinh thái mỏng manh.','Hệ sinh thái',1056,NULL,_binary '\0'),(1139,'The existence of a large number of different kinds of animals and plants which make a balanced environment','The new law aims to protect the biodiversity of the rainforest.','NOUN','Sự phong phú của nhiều loài sinh vật trong một môi trường','Luật mới nhằm bảo vệ sự đa dạng sinh học của rừng nhiệt đới.','Đa dạng sinh học',1057,NULL,_binary '\0'),(1140,'A building with glass sides and a glass roof, for growing plants in','We grow our own tomatoes in the greenhouse.','NOUN','Công trình bằng kính dùng để trồng cây','Chúng tôi tự trồng cà chua trong nhà kính.','Nhà kính',1058,NULL,_binary '\0'),(1141,'Related to the warming of the Earth\'s surface','We must reduce the emission of greenhouse gases.','ADJECTIVE','Liên quan đến hiện tượng nóng lên toàn cầu','Chúng ta phải giảm thiểu việc thải khí nhà kính.','Thuộc về hiệu ứng nhà kính',1058,NULL,_binary '\0'),(1142,'To make a substance or a place dirty or no longer pure by adding a substance that is dangerous or carries disease','The groundwater has been contaminated by industrial waste.','VERB','Làm cho một thứ không còn tinh khiết do chất độc hại','Nguồn nước ngầm đã bị ô nhiễm bởi chất thải công nghiệp.','Làm ô nhiễm/Làm bẩn',1059,NULL,_binary '\0'),(1143,'The protection of plants and animals, natural areas, and interesting and important structures and buildings','Wildlife conservation is essential for a healthy planet.','NOUN','Hành động bảo vệ thiên nhiên hoặc các công trình quan trọng','Bảo tồn động vật hoang dã là điều thiết yếu cho một hành tinh khỏe mạnh.','Sự bảo tồn',1060,NULL,_binary '\0'),(1144,'A long period of time when there is little or no rain','Farmers are facing ruin after a year of severe drought.','NOUN','Giai đoạn dài không có hoặc có rất ít mưa','Nông dân đang đối mặt với sự phá sản sau một năm hạn hán nghiêm trọng.','Hạn hán',1061,NULL,_binary '\0'),(1145,'The use of natural products and energy in a way that does not harm the environment','The company is committed to environmental sustainability.','NOUN','Khả năng duy trì mà không gây hại đến môi trường tương lai','Công ty cam kết với sự bền vững của môi trường.','Sự bền vững',1062,NULL,_binary '\0'),(1146,'(of rain) falling in large amounts','The match was cancelled due to torrential rain.','ADJECTIVE','Mô tả mưa rơi rất nhanh và nhiều','Trận đấu đã bị hủy vì mưa xối xả.','Xối xả/Cuồn cuộn',1063,NULL,_binary '\0'),(1147,'A measure of the amount of carbon dioxide that is produced by the activities of a person or company','We are trying to reduce our carbon footprint by cycling to work.','NOUN','Lượng khí CO2 thải ra từ hoạt động của con người/tổ chức','Chúng tôi đang cố gắng giảm dấu chân carbon bằng cách đạp xe đi làm.','Dấu chân carbon',1064,NULL,_binary '\0'),(1148,'To reduce something by a large amount so that there is not enough left','Intensive farming can deplete the soil of nutrients.','VERB','Hành động làm giảm đáng kể nguồn tài nguyên','Canh tác thâm canh có thể làm cạn kiệt chất dinh dưỡng trong đất.','Làm cạn kiệt/Suy yếu',1065,NULL,_binary '\0'),(1149,'The production or sending out of light, heat, gas, etc.','The government has set new targets for reducing gas emissions.','NOUN','Quá trình thải các chất (khí, nhiệt, ánh sáng) vào môi trường','Chính phủ đã đặt mục tiêu mới để giảm phát thải khí ga.','Sự phát thải/Sự tỏa ra',1066,NULL,_binary '\0'),(1150,'An activity that is done for enjoyment; a hobby','Gardening is a popular pastime among the elderly.','NOUN','Hoạt động làm để vui chơi lúc rảnh rỗi','Làm vườn là một thú tiêu khiển phổ biến của người già.','Trò giải trí/Thú tiêu khiển',1067,NULL,_binary '\0'),(1151,'The fact of people doing things for enjoyment when they are not working','The park provides facilities for outdoor recreation.','NOUN','Hoạt động thư giãn sau giờ làm việc','Công viên cung cấp các cơ sở vật chất cho việc giải trí ngoài trời.','Sự giải trí/Nghỉ ngơi',1068,NULL,_binary '\0'),(1152,'A person who takes part in a sport or other activity for enjoyment, not as a job','He is an enthusiastic amateur photographer.','NOUN','Người tham gia hoạt động vì đam mê thay vì nghề nghiệp','Anh ấy là một người chụp ảnh nghiệp dư đầy nhiệt huyết.','Người nghiệp dư',1069,NULL,_binary '\0'),(1153,'Done for pleasure and not as a job','The play was put on by an amateur theatrical group.','ADJECTIVE','Tính chất hoạt động không mang tính chuyên nghiệp','Vở kịch được dàn dựng bởi một đoàn kịch nghiệp dư.','Nghiệp dư/Không chuyên',1069,NULL,_binary '\0'),(1155,'An item valued by collectors','Rare stamps are highly prized collectibles.','NOUN','Món đồ có giá trị đối với những người đi sưu tầm','Những con tem hiếm là những vật sưu tầm rất có giá trị.','Vật sưu tầm',1071,NULL,_binary '\0'),(1156,'A person who is very interested in and involved with a particular activity or subject','She is a fitness enthusiast who goes to the gym every day.','NOUN','Người cực kỳ quan tâm và dành thời gian cho một sở thích','Cô ấy là một người đam mê thể hình, người đi tập gym mỗi ngày.','Người đam mê',1072,NULL,_binary '\0'),(1158,'A sports competition involving a number of teams or players','He won the local tennis tournament last week.','NOUN','Cuộc thi thể thao gồm nhiều đội hoặc vận động viên','Anh ấy đã thắng giải quần vợt địa phương tuần trước.','Giải đấu/Vòng đấu',1074,NULL,_binary '\0'),(1160,'To allow yourself to have or do something that you like, especially something that is considered bad for you','I occasionally indulge in a chocolate sundae.','VERB','Cho phép mình hưởng thụ thứ gì đó yêu thích','Thỉnh thoảng tôi lại nuông chiều bản thân bằng một ly kem sô-cô-la.','Nuông chiều/Thỏa mãn',1076,NULL,_binary '\0'),(1161,'Done alone; without other people','Reading is a solitary activity.','ADJECTIVE','Hoạt động thực hiện mà không có người khác','Đọc sách là một hoạt động mang tính cá nhân/làm một mình.','Làm một mình/Đơn độc',1077,NULL,_binary '\0'),(1162,'To stop worrying or thinking about work and start to relax','Music helps me to unwind after a busy day.','VERB','Hành động dừng lo lắng và bắt đầu thả lỏng','Âm nhạc giúp tôi thư giãn sau một ngày bận rộn.','Thư giãn/Nghỉ ngơi',1078,NULL,_binary '\0'),(1163,'A collection of things, for example works of art, that are shown to the public','Have you seen the Picasso exhibition at the gallery?','NOUN','Tập hợp các đồ vật hoặc tác phẩm nghệ thuật cho công chúng xem','Bạn đã xem triển lãm của Picasso ở phòng trưng bày chưa?','Cuộc triển lãm',1079,NULL,_binary '\0'),(1165,'Very interested in something','I\'ve always been fascinated by ancient history.','ADJECTIVE','Trạng thái cảm thấy cực kỳ quan tâm đến điều gì','Tôi luôn bị mê hoặc bởi lịch sử cổ đại.','Bị mê hoặc/Rất hứng thú',1081,NULL,_binary '\0'),(1166,'A system of methods used in a particular area of study or activity','The researchers explained their methodology in the first chapter.','NOUN','Hệ thống các phương pháp được sử dụng trong một lĩnh vực nghiên cứu','Các nhà nghiên cứu đã giải thích phương pháp luận của họ trong chương đầu tiên.','Phương pháp luận',1082,NULL,_binary '\0'),(1167,'An idea or explanation of something that is based on a few known facts but that has not yet been proved','The results of the experiment confirmed our hypothesis.','NOUN','Ý tưởng hoặc sự giải thích dựa trên một vài sự kiện nhưng chưa được chứng minh','Kết quả của thí nghiệm đã xác nhận giả thuyết của chúng tôi.','Giả thuyết',1083,NULL,_binary '\0'),(1168,'Based on experiments or experience rather than ideas or theories','There is no empirical evidence to support his claim.','ADJECTIVE','Dựa trên quan sát và trải nghiệm thực tế thay vì lý thuyết suông','Không có bằng chứng thực nghiệm nào hỗ trợ cho khẳng định của ông ấy.','Dựa trên thực nghiệm',1084,NULL,_binary '\0'),(1170,'Connected with what something is like or how good it is, rather than with how much of it there is','The research involved qualitative analysis of student interviews.','ADJECTIVE','Liên quan đến tính chất hoặc đặc điểm thay vì số lượng','Nghiên cứu bao gồm phân tích định tính các cuộc phỏng vấn sinh viên.','Định tính',1086,NULL,_binary '\0'),(1171,'Connected with the amount or number of something rather than with how good it is','We need to conduct quantitative research to get statistical data.','ADJECTIVE','Liên quan đến đo lường số lượng hoặc con số','Chúng ta cần thực hiện nghiên cứu định lượng để có được dữ liệu thống kê.','Định lượng',1087,NULL,_binary '\0'),(1172,'A situation, number or quantity that can vary or be varied','Temperature is the independent variable in this experiment.','NOUN','Một yếu tố hoặc con số có thể thay đổi trong nghiên cứu','Nhiệt độ là biến độc lập trong thí nghiệm này.','Biến số',1088,NULL,_binary '\0'),(1173,'Often changing; likely to change','The weather here is extremely variable.','ADJECTIVE','Tính chất không ổn định, dễ biến động','Thời tiết ở đây cực kỳ hay thay đổi.','Hay thay đổi',1088,NULL,_binary '\0'),(1174,'Moral principles that control or influence a person\'s behaviour','The medical ethics committee must approve the study.','NOUN','Các nguyên tắc chi phối hành vi (đặc biệt trong nghiên cứu)','Ủy ban đạo đức y tế phải phê duyệt nghiên cứu này.','Đạo đức/Luân thường đạo lý',1089,NULL,_binary '\0'),(1175,'A small amount of a substance that is used for testing','They took a blood sample for analysis.','NOUN','Một phần nhỏ đại diện cho tổng thể để kiểm tra','Họ đã lấy mẫu máu để phân tích.','Mẫu thử/Nhóm mẫu',1090,NULL,_binary '\0'),(1176,'To test a small amount of something to see what it is like','We sampled several different products before choosing one.','VERB','Hành động thử một phần nhỏ của thứ gì đó','Chúng tôi đã thử nghiệm vài sản phẩm khác nhau trước khi chọn một cái.','Lấy mẫu/Thử nghiệm',1090,NULL,_binary '\0'),(1177,'To prove that something is true or correct','The survey results were validated by independent experts.','VERB','Chứng minh điều gì đó là đúng hoặc hợp lệ','Kết quả khảo sát đã được các chuyên gia độc lập xác nhận.','Xác nhận/Phê chuẩn',1091,NULL,_binary '\0'),(1179,'(of a piece of work) examined by other people who work in the same area to ensure it is of high quality','You should only use peer-reviewed journals for your essay.','ADJECTIVE','Được các đồng nghiệp cùng ngành kiểm tra chất lượng','Bạn chỉ nên sử dụng các tạp chí được bình duyệt cho bài luận của mình.','Được bình duyệt/Đánh giá chuyên gia',1093,NULL,_binary '\0'),(1180,'Facts or information, especially when examined and used to find out things or to make decisions','The data was collected over a period of six months.','NOUN','Thông tin hoặc sự kiện dùng để nghiên cứu hoặc ra quyết định','Dữ liệu được thu thập trong khoảng thời gian sáu tháng.','Dữ liệu',1094,NULL,_binary '\0'),(1182,'Something that you decide when you have thought about all the information connected with the situation','The report’s final conclusion was that the project was a success.','NOUN','Quyết định đưa ra sau khi xem xét mọi thông tin','Kết luận cuối cùng của báo cáo là dự án đã thành công.','Kết luận',1096,NULL,_binary '\0'),(1183,'The end of something','The party brought the festival to a happy conclusion.','NOUN','Phần cuối cùng của một quá trình','Bữa tiệc đã đưa lễ hội đến một kết thúc tốt đẹp.','Sự kết thúc',1096,NULL,_binary '\0'),(1184,'The method and practice of teaching, especially as an academic subject or theoretical concept','Modern pedagogy emphasizes student-centered learning.','NOUN','Phương pháp và cách thức giảng dạy lý thuyết và thực hành','Sư phạm hiện đại nhấn mạnh vào việc học tập lấy học sinh làm trung tâm.','Sư phạm',1097,NULL,_binary '\0'),(1185,'The subjects comprising a course of study in a school or college','The school is adding coding to its national curriculum.','NOUN','Toàn bộ các môn học trong một khóa học tại trường','Trường học đang đưa lập trình vào chương trình học quốc gia.','Chương trình học',1098,NULL,_binary '\0'),(1186,'The ability to read and write','The government is trying to improve adult literacy rates.','NOUN','Khả năng đọc và viết cơ bản','Chính phủ đang cố gắng cải thiện tỉ lệ biết chữ ở người lớn.','Trình độ biết chữ',1099,NULL,_binary '\0'),(1187,'Knowledge or skills in a specific area','Digital literacy is essential in the modern workplace.','NOUN','Sự hiểu biết trong một lĩnh vực cụ thể','Sự am hiểu về kỹ thuật số là thiết yếu trong nơi làm việc hiện đại.','Sự am hiểu/Kiến thức về...',1099,NULL,_binary '\0'),(1188,'An amount of money given by a school to pay for the studies of a person','She won a full scholarship to study at Harvard.','NOUN','Khoản tiền hỗ trợ học tập dựa trên thành tích','Cô ấy đã giành được học bổng toàn phần để học tại Harvard.','Học bổng',1100,NULL,_binary '\0'),(1189,'Serious and detailed study of a subject','The book is a masterpiece of historical scholarship.','NOUN','Hoạt động nghiên cứu sâu sắc về một lĩnh vực','Cuốn sách là một kiệt tác của nghiên cứu lịch sử.','Sự uyên bác/Nghiên cứu học thuật',1100,NULL,_binary '\0'),(1190,'The money paid for being taught, especially in a college or university','Tuition fees at private universities are very high.','NOUN','Khoản tiền trả cho việc học tập','Học phí tại các trường đại học tư thục rất cao.','Học phí',1101,NULL,_binary '\0'),(1191,'The process of testing students and making a judgement about their knowledge','Continuous assessment is used instead of final exams.','NOUN','Quá trình kiểm tra và nhận xét về kiến thức của học sinh','Sự đánh giá liên tục được sử dụng thay cho các kỳ thi cuối kỳ.','Sự đánh giá',1102,NULL,_binary '\0'),(1192,'The practice of training people to obey rules','The school is known for its strict discipline.','NOUN','Việc rèn luyện người khác tuân thủ các quy tắc','Ngôi trường này nổi tiếng vì kỷ luật nghiêm khắc.','Kỷ luật',1103,NULL,_binary '\0'),(1193,'An area of knowledge; a subject that people study','Physiotherapy is a relatively new academic discipline.','NOUN','Lĩnh vực kiến thức chuyên sâu','Vật lý trị liệu là một ngành học học thuật tương đối mới.','Ngành học/Môn học',1103,NULL,_binary '\0'),(1194,'A department or group of related departments in a college','He is a member of the Faculty of Law.','NOUN','Một bộ phận trong trường đại học','Anh ấy là thành viên của Khoa Luật.','Khoa',1104,NULL,_binary '\0'),(1195,'The whole teaching staff of a university or college','The faculty voted against the new proposal.','NOUN','Toàn bộ đội ngũ giảng dạy trong trường','Toàn thể giảng viên đã bỏ phiếu chống lại đề xuất mới.','Ban giảng huấn/Giảng viên',1104,NULL,_binary '\0'),(1196,'Connected with the skills, knowledge, etc. that you need to have in order to do a particular job','The college offers a wide range of vocational courses.','ADJECTIVE','Liên quan đến kỹ năng cần thiết cho một công việc cụ thể','Trường cao đẳng cung cấp nhiều khóa học nghề đa dạng.','Hướng nghiệp/Dạy nghề',1105,NULL,_binary '\0'),(1197,'The highest university degree','She earned her doctorate in chemistry last year.','NOUN','Cấp bậc học thuật cao nhất trong trường đại học','Cô ấy đã nhận bằng tiến sĩ hóa học vào năm ngoái.','Học vị tiến sĩ',1106,NULL,_binary '\0'),(1199,'Not part of the usual course of work or studies at a school or college','She is involved in many extracurricular activities, such as music and drama.','ADJECTIVE','Các hoạt động nằm ngoài chương trình học chính thức','Cô ấy tham gia nhiều hoạt động ngoại khóa, chẳng hạn như âm nhạc và kịch.','Ngoại khóa',1108,NULL,_binary '\0'),(1200,'To form an opinion of the amount, value or quality of something after thinking about it carefully','We need to evaluate the effectiveness of the new teaching method.','VERB','Hình thành nhận định về giá trị hoặc chất lượng sau khi xem xét','Chúng ta cần đánh giá hiệu quả của phương pháp dạy học mới.','Đánh giá/Định giá',1109,NULL,_binary '\0'),(1201,'The advice and help given by an experienced person to a younger or less experienced person','The university provides a mentorship program for first-year students.','NOUN','Sự giúp đỡ từ người có kinh nghiệm cho người ít kinh nghiệm hơn','Trường đại học cung cấp chương trình cố vấn cho sinh viên năm nhất.','Sự hướng dẫn/Chế độ cố vấn',1110,NULL,_binary '\0'),(1202,'Made to have the same features or qualities as other things of the same type','The SAT is a standardized test used for college admissions.','ADJECTIVE','Được thiết kế theo một quy chuẩn thống nhất','SAT là một bài kiểm tra tiêu chuẩn hóa dùng cho việc tuyển sinh đại học.','Được tiêu chuẩn hóa',1111,NULL,_binary '\0'),(1203,'The relation of plants and living creatures to each other and to their environment','The oil spill caused terrible damage to the fragile ecology of the coast.','NOUN','Mối quan hệ giữa sinh vật và môi trường sống của chúng','Vụ tràn dầu đã gây ra thiệt hại khủng khiếp cho hệ sinh thái mong manh của vùng duyên hải.','Sinh thái học',1112,NULL,_binary '\0'),(1204,'The natural environment in which an animal or plant usually lives','The destruction of wildlife habitat is a major concern.','NOUN','Nơi ở tự nhiên của động thực vật','Sự phá hủy môi trường sống của động vật hoang dã là một mối lo ngại lớn.','Môi trường sống',1113,NULL,_binary '\0'),(1205,'Involving the use of natural products and energy in a way that does not harm the environment','We need to find more sustainable ways of producing energy.','ADJECTIVE','Sử dụng tài nguyên mà không gây hại lâu dài cho môi trường','Chúng ta cần tìm ra những cách bền vững hơn để sản xuất năng lượng.','Bền vững',1114,NULL,_binary '\0'),(1206,'The process of something being damaged or made worse','Environmental degradation is caused by human activities.','NOUN','Quá trình làm môi trường trở nên tệ hơn','Sự suy thoái môi trường là do các hoạt động của con người gây ra.','Sự suy thoái/Xuống cấp',1115,NULL,_binary '\0'),(1207,'The act of cutting down or burning the trees in an area','Deforestation is a major cause of global warming.','NOUN','Hành động chặt hạ hoặc đốt rừng trên diện rộng','Phá rừng là một nguyên nhân chính gây ra nóng lên toàn cầu.','Sự phá rừng',1116,NULL,_binary '\0'),(1208,'Liquid waste, especially chemicals produced by factories, that flows into rivers or the sea','The factory was fined for discharging untreated effluent into the river.','NOUN','Chất thải lỏng, đặc biệt là hóa chất từ nhà máy chảy ra sông ngòi','Nhà máy bị phạt vì xả nước thải chưa qua xử lý xuống sông.','Nước thải',1117,NULL,_binary '\0'),(1209,'Connected with the natural heat of the earth','Iceland uses geothermal energy to heat most of its homes.','ADJECTIVE','Liên quan đến nhiệt năng tự nhiên của trái đất','Iceland sử dụng năng lượng địa nhiệt để sưởi ấm hầu hết các ngôi nhà.','Thuộc địa nhiệt',1118,NULL,_binary '\0'),(1210,'A chemical used for killing insects that eat food crops','The use of chemical pesticides can contaminate the groundwater.','NOUN','Hóa chất dùng để tiêu diệt côn trùng phá hoại mùa màng','Việc sử dụng thuốc trừ sâu hóa học có thể làm ô nhiễm nước ngầm.','Thuốc trừ sâu',1119,NULL,_binary '\0'),(1211,'A person who takes an active part in the protection of the environment','Conservationists are working to save the endangered sea turtles.','NOUN','Người tham gia tích cực vào việc bảo vệ môi trường','Các nhà bảo tồn đang làm việc để cứu loài rùa biển đang bị đe dọa.','Nhà bảo tồn',1120,NULL,_binary '\0'),(1212,'A substance or object that is able to decay naturally and in a way that is not harmful','Most plastics are not biodegradable.','ADJECTIVE','Có khả năng bị vi khuẩn phân hủy tự nhiên mà không gây hại','Hầu hết các loại nhựa không thể phân hủy sinh học.','Phân hủy sinh học',1121,NULL,_binary '\0'),(1213,'The part of the earth\'s surface and atmosphere in which plants and animals can live','The biosphere is a complex system of interconnected life forms.','NOUN','Phần bề mặt và khí quyển của trái đất nơi sinh vật có thể sống','Sinh quyển là một hệ thống phức tạp của các dạng sống có liên kết với nhau.','Sinh quyển',1122,NULL,_binary '\0'),(1214,'A situation in which a plant, an animal, a way of life, etc. stops existing','Many species are on the verge of extinction.','NOUN','Tình trạng một loài động thực vật không còn tồn tại','Nhiều loài đang trên bờ vực tuyệt chủng.','Sự tuyệt chủng',1123,NULL,_binary '\0'),(1215,'A substance added to soil to make plants grow more successfully','Organic fertilizer is better for the environment than chemical one.','NOUN','Chất bồi bổ cho đất giúp cây trồng phát triển tốt','Phân bón hữu cơ tốt cho môi trường hơn phân bón hóa học.','Phân bón',1124,NULL,_binary '\0'),(1216,'The action of reducing the severity, seriousness, or painfulness of something','Climate change mitigation requires global cooperation.','NOUN','Hành động làm giảm mức độ nghiêm trọng của vấn đề','Giảm thiểu biến đổi khí hậu đòi hỏi sự hợp tác toàn cầu.','Sự giảm thiểu/Giảm nhẹ',1125,NULL,_binary '\0'),(1217,'The process by which the surface of something is gradually destroyed through the action of wind, rain, etc.','Soil erosion is a serious problem for farmers in this area.','NOUN','Quá trình bề mặt (đất, đá) bị mài mòn dần do tác động tự nhiên','Xói mòn đất là một vấn đề nghiêm trọng đối với nông dân ở khu vực này.','Sự xói mòn',1126,NULL,_binary '\0'),(1219,'An important development that may lead to an agreement or achievement','Scientists are on the verge of a major breakthrough in cancer research.','NOUN','Một sự phát triển quan trọng dẫn đến thành tựu lớn','Các nhà khoa học đang trên bờ vực của một bước đột phá lớn trong nghiên cứu ung thư.','Bước đột phá',1128,NULL,_binary '\0'),(1220,'At the newest, most advanced stage in the development of something','The lab is equipped with cutting-edge technology.','ADJECTIVE','Ở giai đoạn mới nhất, tiên tiến nhất của một sự phát triển','Phòng thí nghiệm được trang bị công nghệ tiên tiến nhất.','Tiên tiến/Hiện đại nhất',1129,NULL,_binary '\0'),(1221,'The use of machines and computers to do work that was previously done by people','Automation has led to huge job losses in the manufacturing sector.','NOUN','Việc sử dụng máy móc thay thế con người làm việc','Tự động hóa đã dẫn đến việc mất việc làm hàng loạt trong ngành sản xuất.','Sự tự động hóa',1130,NULL,_binary '\0'),(1222,'The study and development of computer systems that can perform tasks that normally require human intelligence','AI can analyze vast amounts of data much faster than humans.','NOUN','Công nghệ mô phỏng trí tuệ con người cho máy móc','AI có thể phân tích lượng dữ liệu khổng lồ nhanh hơn con người rất nhiều.','Trí tuệ nhân tạo (AI)',1131,NULL,_binary '\0'),(1223,'No longer used because something new has been invented','New technology can render old software obsolete very quickly.','ADJECTIVE','Không còn được sử dụng vì đã có thứ mới thay thế','Công nghệ mới có thể khiến các phần mềm cũ trở nên lỗi thời rất nhanh.','Lỗi thời',1132,NULL,_binary '\0'),(1224,'To completely change the way that something is done','The Internet has revolutionized the way we communicate.','VERB','Thay đổi hoàn toàn cách thức một điều gì đó được thực hiện','Internet đã cách mạng hóa cách chúng ta giao tiếp.','Cách mạng hóa',1133,NULL,_binary '\0'),(1225,'The process of changing data into a digital form','The digitalization of medical records has improved patient care.','NOUN','Quá trình chuyển đổi dữ liệu sang dạng kỹ thuật số','Việc số hóa hồ sơ y tế đã cải thiện việc chăm sóc bệnh nhân.','Sự số hóa',1134,NULL,_binary '\0'),(1226,'Knowing a lot about modern technology and how to use it','The younger generation is generally more tech-savvy than their parents.','ADJECTIVE','Có kiến thức tốt về công nghệ hiện đại và cách sử dụng','Thế hệ trẻ nhìn chung am hiểu công nghệ hơn cha mẹ họ.','Am hiểu công nghệ/Rành công nghệ',1135,NULL,_binary '\0'),(1229,'Connected with electronic communication networks, especially the internet','Companies are becoming more vulnerable to cyber attacks.','ADJECTIVE','Liên quan đến mạng máy tính hoặc internet','Các công ty đang trở nên dễ bị tổn thương hơn trước các cuộc tấn công mạng.','Thuộc về mạng/Không gian mạng',1138,NULL,_binary '\0'),(1230,'Using the most advanced machines and methods','The hospital has become a center for high-tech surgery.','ADJECTIVE','Sử dụng các máy móc và phương pháp tiên tiến nhất','Bệnh viện đã trở thành trung tâm của phẫu thuật công nghệ cao.','Công nghệ cao',1139,NULL,_binary '\0'),(1231,'A set of rules that must be followed when solving a particular problem','Social media platforms use complex algorithms to show personalized content.','NOUN','Các quy tắc giải quyết vấn đề bằng máy tính','Các nền tảng mạng xã hội sử dụng các thuật toán phức tạp để hiển thị nội dung cá nhân hóa.','Thuật toán',1140,NULL,_binary '\0'),(1232,'The quality of doing something well with no waste of time or money','New technologies have increased the efficiency of the production process.','NOUN','Khả năng làm tốt việc gì đó mà không lãng phí tài nguyên','Công nghệ mới đã làm tăng hiệu suất của quá trình sản xuất.','Hiệu quả/Hiệu suất',1141,NULL,_binary '\0'),(1233,'A standard or pattern of social behaviour that is accepted in a society','Social norms dictate how we should behave in public.','NOUN','Tiêu chuẩn hành vi được xã hội chấp nhận','Các chuẩn mực xã hội quy định cách chúng ta nên cư xử nơi công cộng.','Chuẩn mực',1142,NULL,_binary '\0'),(1234,'Data relating to the population and different groups within it','The demographics of the city have changed significantly over the last decade.','NOUN','Dữ liệu về dân số và các nhóm dân cư','Nhân khẩu học của thành phố đã thay đổi đáng kể trong thập kỷ qua.','Nhân khẩu học',1143,NULL,_binary '\0'),(1235,'To prevent a group of people from having power or influence','The new policy tends to marginalize low-income families.','VERB','Khiến một nhóm người không có quyền lực hoặc tầm ảnh hưởng','Chính sách mới có xu hướng gạt các gia đình thu nhập thấp ra ngoài lề xã hội.','Gạt ra ngoài lề',1144,NULL,_binary '\0'),(1236,'The act or process of mixing people who have previously been separated','Economic integration is essential for the region\'s growth.','NOUN','Quá trình kết nối các nhóm người khác nhau vào một cộng đồng','Hòa nhập kinh tế là điều cần thiết cho sự phát triển của khu vực.','Sự hòa nhập',1145,NULL,_binary '\0'),(1237,'A system in which people or things are arranged according to their importance','She rose quickly through the corporate hierarchy.','NOUN','Sự sắp xếp người hoặc vật theo thứ bậc quan trọng','Cô ấy thăng tiến nhanh chóng trong hệ thống cấp bậc của tập đoàn.','Hệ thống cấp bậc',1146,NULL,_binary '\0'),(1238,'The process in which more and more people start to live and work in towns and cities','Rapid urbanization has led to several environmental problems.','NOUN','Quá trình người dân tập trung sống và làm việc ở thành thị','Đô thị hóa nhanh chóng đã dẫn đến một vài vấn đề môi trường.','Sự đô thị hóa',1147,NULL,_binary '\0'),(1239,'The general health, happiness and safety of a person or a group','The government is responsible for the welfare of its citizens.','NOUN','Tình trạng sức khỏe, hạnh phúc và an toàn của cộng đồng','Chính phủ chịu trách nhiệm về phúc lợi của công dân.','Phúc lợi/Sự an sinh',1148,NULL,_binary '\0'),(1240,'The unfair difference between groups of people in society','Gender inequality is still a major issue in many workplaces.','NOUN','Sự khác biệt thiếu công bằng giữa các nhóm trong xã hội','Bất bình đẳng giới vẫn là một vấn đề lớn ở nhiều nơi làm việc.','Sự bất bình đẳng',1149,NULL,_binary '\0'),(1241,'A small part of a group that is less than half of the whole','Ethnic minorities often face challenges in accessing healthcare.','NOUN','Một phần nhỏ, ít hơn một nửa của tổng thể','Các nhóm dân tộc thiểu số thường gặp khó khăn trong việc tiếp cận y tế.','Thiểu số',1150,NULL,_binary '\0'),(1242,'The ability to move easily from one place, social class, or job to another','Education is the key to social mobility.','NOUN','Khả năng di chuyển giữa các nơi hoặc tầng lớp xã hội','Giáo dục là chìa khóa để thăng tiến trong xã hội.','Sự di động/Thăng tiến xã hội',1151,NULL,_binary '\0'),(1243,'The policy of keeping one group of people apart from another and treating them differently','The law was designed to end racial segregation in schools.','NOUN','Chính sách chia tách và đối xử khác biệt giữa các nhóm người','Luật này được thiết kế để chấm dứt sự phân biệt chủng tộc trong trường học.','Sự phân biệt/Sự chia tách',1152,NULL,_binary '\0'),(1244,'A typical example or pattern of something','The war signaled a paradigm shift in international relations.','NOUN','Một ví dụ hoặc khuôn mẫu điển hình của thứ gì đó','Cuộc chiến đã đánh dấu một sự chuyển đổi mô hình trong quan hệ quốc tế.','Mô hình/Hình mẫu',1153,NULL,_binary '\0'),(1246,'The process of becoming part of a group, country, or society','The assimilation of immigrants into American culture takes time.','NOUN','Quá trình trở thành một phần của một nhóm hoặc xã hội','Sự đồng hóa của người nhập cư vào văn hóa Mỹ cần có thời gian.','Sự đồng hóa',1155,NULL,_binary '\0'),(1247,'Tending to follow what is done or considered acceptable by society in general','She has very conventional views on marriage.','ADJECTIVE','Tuân theo những gì xã hội coi là chuẩn mực thông thường','Cô ấy có những quan điểm rất truyền thống về hôn nhân.','Theo tập quán/Truyền thống',1156,NULL,_binary '\0'),(1248,'Connected with mental processes of understanding, a person’s thoughts','A child’s cognitive development is influenced by their environment.','ADJECTIVE','Liên quan đến quá trình tư duy, hiểu biết của trí tuệ','Sự phát triển nhận thức của trẻ bị ảnh hưởng bởi môi trường xung quanh.','Thuộc về nhận thức',1157,NULL,_binary '\0'),(1249,'The way you notice things with your senses','Our perception of world events is often shaped by the media.','NOUN','Cách bạn cảm nhận mọi thứ qua giác quan','Cách nhìn nhận của chúng ta về các sự kiện thế giới thường bị định hình bởi truyền thông.','Sự tri giác',1158,NULL,_binary '\0'),(1250,'An idea, a belief or an image you have as a result of how you see or understand something','There is a general perception that the exam is very difficult.','NOUN','Quan điểm hoặc hình ảnh trong tâm trí về một vấn đề','Có một cách nhìn chung rằng kỳ thi này rất khó.','Sự am hiểu/Cách nhìn',1158,NULL,_binary '\0'),(1251,'Something that produces a reaction in a human, an animal or a plant','Light is a stimulus that causes the pupils to contract.','NOUN','Thứ gì đó tạo ra phản ứng trong cơ thể sống','Ánh sáng là một tác nhân kích thích khiến đồng tử co lại.','Tác nhân kích thích',1159,NULL,_binary '\0'),(1252,'Something that helps somebody/something to develop better or more quickly','The lower interest rates provided a stimulus to the economy.','NOUN','Thứ giúp điều gì đó phát triển nhanh hơn','Lãi suất thấp hơn đã tạo ra một sự thúc đẩy cho nền kinh tế.','Sự thúc đẩy',1159,NULL,_binary '\0'),(1253,'Connected with feelings that you have even though you are not aware of them','Many of our dreams reflect our subconscious fears.','ADJECTIVE','Liên quan đến những cảm xúc thầm kín mà bạn không nhận ra','Nhiều giấc mơ của chúng ta phản ánh những nỗi sợ trong tiềm thức.','Thuộc về tiềm thức',1160,NULL,_binary '\0'),(1254,'Connected with the way in which a person or an animal behaves','The psychologist studied the behavioral patterns of monkeys.','ADJECTIVE','Liên quan đến cách thức ứng xử của con người hoặc động vật','Nhà tâm lý học đã nghiên cứu các mô thức hành vi của loài khỉ.','Thuộc về hành vi',1161,NULL,_binary '\0'),(1255,'The reason why somebody does something or behaves in a particular way','Money is a strong motivation for many people to work hard.','NOUN','Lý do khiến ai đó hành động theo một cách cụ thể','Tiền bạc là động lực mạnh mẽ để nhiều người làm việc chăm chỉ.','Động lực/Sự thúc đẩy',1162,NULL,_binary '\0'),(1256,'The various aspects of a person’s character that combine to make them different from other people','The psychologist used a test to assess his personality.','NOUN','Các khía cạnh tính cách tạo nên sự khác biệt của một người','Nhà tâm lý học đã sử dụng một bài kiểm tra để đánh giá tính cách của anh ấy.','Nhân cách/Tính cách',1163,NULL,_binary '\0'),(1257,'A famous person, especially one who works in entertainment or sport','TV personalities are often paid a lot of money.','NOUN','Người có sức ảnh hưởng trong công chúng','Các ngôi sao truyền hình thường được trả rất nhiều tiền.','Người nổi tiếng',1163,NULL,_binary '\0'),(1259,'The ability to understand and share the feelings of another','Good counselors need to have a great deal of empathy.','NOUN','Khả năng hiểu và chia sẻ cảm xúc của người khác','Những người tư vấn giỏi cần phải có sự thấu cảm sâu sắc.','Sự thấu cảm',1165,NULL,_binary '\0'),(1260,'A mental illness in which a person suffers from strong feelings of fear and worry','Compulsive hand-washing is a symptom of neurosis.','NOUN','Bệnh lý tâm thần gây ra nỗi sợ và lo lắng cực độ','Rửa tay liên tục là một triệu chứng của chứng loạn thần kinh.','Chứng loạn thần kinh/Ám ảnh',1166,NULL,_binary '\0'),(1261,'The process of training a person or an animal to do something or to behave in a particular way','Through classical conditioning, the dog learned to salivate at the sound of a bell.','NOUN','Quá trình rèn luyện để tạo ra một hành vi cụ thể','Thông qua phản xạ có điều kiện, con chó đã học được cách tiết nước bọt khi nghe tiếng chuông.','Sự tạo điều kiện/Huấn luyện phản xạ',1167,NULL,_binary '\0'),(1262,'A quiet person who is more interested in their own thoughts and feelings than in spending time with other people','As an introvert, he prefers reading a book to attending big parties.','NOUN','Người trầm tính, quan tâm đến thế giới nội tâm hơn là giao lưu xã hội','Là một người hướng nội, anh ấy thích đọc sách hơn là tham gia những bữa tiệc lớn.','Người hướng nội',1168,NULL,_binary '\0'),(1263,'A person who is confident and full of life and who prefers being with other people to being alone','Extroverts usually thrive in social situations.','NOUN','Người tự tin, sôi nổi và thích ở bên cạnh mọi người','Những người hướng ngoại thường tỏa sáng trong các tình huống xã hội.','Người hướng ngoại',1169,NULL,_binary '\0'),(1264,'A state of having inconsistent thoughts, beliefs, or attitudes, especially as relating to behavioral decisions and attitude change','The smoker experienced cognitive dissonance knowing that cigarettes cause cancer.','NOUN','Trạng thái mâu thuẫn giữa hành vi và niềm tin trong tâm trí','Người hút thuốc trải qua sự bất hòa nhận thức khi biết rằng thuốc lá gây ung thư.','Sự bất hòa nhận thức',1170,NULL,_binary '\0'),(1265,'The ability of people or things to recover quickly after something unpleasant','The study focused on the psychological resilience of refugees.','NOUN','Khả năng lấy lại tinh thần nhanh chóng sau nghịch cảnh','Nghiên cứu tập trung vào khả năng phục hồi tâm lý của những người tị nạn.','Khả năng phục hồi/Sự kiên cường',1171,NULL,_binary '\0'),(1266,'A state of being scarce or in short supply; shortage','The scarcity of skilled workers is a major problem for the industry.','NOUN','Tình trạng nguồn cung không đủ đáp ứng nhu cầu','Sự khan hiếm lao động có tay nghề là vấn đề lớn đối với ngành này.','Sự khan hiếm',1172,NULL,_binary '\0'),(1267,'A general increase in prices and fall in the purchasing value of money','The government is taking measures to control inflation.','NOUN','Sự tăng giá chung và giảm giá trị mua hàng của tiền tệ','Chính phủ đang thực hiện các biện pháp để kiểm soát lạm phát.','Lạm phát',1173,NULL,_binary '\0'),(1268,'An amount that is extra or more than you need','The country has a trade surplus of $2 billion.','NOUN','Số lượng vượt quá nhu cầu hoặc mức cần thiết','Quốc gia này có mức thặng dư thương mại là 2 tỷ đô la.','Thặng dư/Số dư',1174,NULL,_binary '\0'),(1269,'The amount by which money spent or owed is greater than money earned','The federal budget deficit continues to grow.','NOUN','Số tiền chi ra hoặc nợ lớn hơn số tiền thu vào','Thâm hụt ngân sách liên bang tiếp tục gia tăng.','Thâm hụt',1175,NULL,_binary '\0'),(1270,'The complete control of trade in particular goods or the supply of a particular service','The company has a virtual monopoly on the world market.','NOUN','Sự kiểm soát hoàn toàn thị trường của một sản phẩm hoặc dịch vụ','Công ty đó gần như có sự độc quyền trên thị trường thế giới.','Sự độc quyền',1176,NULL,_binary '\0'),(1271,'A difficult time for the economy of a country, when there is less trade and industrial activity than usual','The country is sliding into its worst recession for forty years.','NOUN','Giai đoạn kinh tế khó khăn, hoạt động thương mại và công nghiệp giảm','Đất nước đang rơi vào cuộc suy thoái tồi tệ nhất trong 40 năm qua.','Suy thoái kinh tế',1177,NULL,_binary '\0'),(1272,'Connected with government or public money, especially taxes','The government’s fiscal policy aims to reduce the national debt.','ADJECTIVE','Liên quan đến ngân sách nhà nước hoặc thuế','Chính sách tài khóa của chính phủ nhằm giảm nợ quốc gia.','Thuộc tài chính/ngân sách',1178,NULL,_binary '\0'),(1273,'The degree to which supply or demand for a product changes as its price changes','Price elasticity of demand measures how much demand drops when prices rise.','NOUN','Mức độ thay đổi của cung/cầu khi giá cả biến động','Độ co giãn của cầu theo giá đo lường mức độ giảm cầu khi giá tăng.','Độ co giãn',1179,NULL,_binary '\0'),(1274,'The total value of goods and services produced by a country in a year (GDP)','The country’s GDP grew by 3% last year.','NOUN','Tổng giá trị hàng hóa và dịch vụ một quốc gia tạo ra trong năm','GDP của quốc gia đã tăng trưởng 3% trong năm ngoái.','Tổng sản phẩm quốc nội (GDP)',1180,NULL,_binary '\0'),(1275,'A product or a raw material that can be bought and sold','Oil is the most traded commodity in the world.','NOUN','Sản phẩm cơ bản hoặc nguyên liệu có thể mua bán (như dầu, lúa mì)','Dầu mỏ là hàng hóa được giao dịch nhiều nhất trên thế giới.','Hàng hóa/Sản phẩm thô',1181,NULL,_binary '\0'),(1276,'The percentage of a sum of money charged by a bank for borrowing it','The central bank decided to lower interest rates.','NOUN','Tỷ lệ phần trăm tiền lãi khi vay hoặc gửi ngân hàng','Ngân hàng trung ương đã quyết định hạ lãi suất.','Lãi suất',1182,NULL,_binary '\0'),(1278,'The removal of government controls from a particular industry','The deregulation of the airline industry led to lower fares.','NOUN','Việc gỡ bỏ sự kiểm soát của chính phủ đối với một ngành nào đó','Việc bãi bỏ quy định trong ngành hàng không đã dẫn đến giá vé thấp hơn.','Sự bãi bỏ quy định',1184,NULL,_binary '\0'),(1279,'The act of using energy, food or materials','The government is trying to reduce energy consumption.','NOUN','Hành động sử dụng năng lượng, thực phẩm hoặc vật liệu','Chính phủ đang cố gắng giảm mức tiêu thụ năng lượng.','Sự tiêu thụ',1185,NULL,_binary '\0'),(1280,'Wealth or property that is used to produce more wealth','The company needs to raise more capital for expansion.','NOUN','Tiền bạc hoặc tài sản dùng để tạo ra thêm lợi nhuận','Công ty cần huy động thêm vốn để mở rộng.','Vốn/Vốn liếng',1186,NULL,_binary '\0'),(1281,'The most important city of a country, usually where the central government is','Hanoi is the capital of Vietnam.','NOUN','Thành phố quan trọng nhất của một quốc gia','Hà Nội là thủ đô của Việt Nam.','Thủ đô',1186,NULL,_binary '\0'),(1283,'To come together for a formal meeting; to arrange for people to come together','The committee will convene next week to finalize the proposal.','VERB','Hành động tập hợp mọi người cho một cuộc họp chính thức','Ủy ban sẽ triệu tập vào tuần tới để hoàn thiện đề xuất.','Triệu tập/Triệu hồi',1188,NULL,_binary '\0'),(1286,'The smallest number of people who must be at a meeting before it can make official decisions','We cannot vote on the amendment because we don’t have a quorum.','NOUN','Số lượng người tối thiểu cần có để cuộc họp có giá trị pháp lý','Chúng ta không thể bỏ phiếu về sửa đổi vì không có đủ số lượng đại biểu tối thiểu.','Số lượng tối thiểu/Quorum',1191,NULL,_binary '\0'),(1310,'Given free, especially by a business','The hotel provides a complimentary breakfast.','ADJECTIVE','Đồ tặng kèm không tính tiền','Khách sạn cung cấp bữa sáng miễn phí.','Miễn phí/Biếu',1215,NULL,_binary '\0'),(1311,'The \"complimentary close\" is the part of a letter that says \"Sincerely yours,\" etc.','Don\'t forget to add a complimentary close before your signature.','ADJECTIVE','Phần chào cuối thư trước khi ký tên','Đừng quên thêm lời chào kết thúc trước chữ ký của bạn.','Chào kết thúc',1215,NULL,_binary '\0'),(1312,'A rough written version of something that is not yet in its final form','I’ve written a first draft of the report.','NOUN','Phiên bản viết thô chưa hoàn thiện','Tôi đã viết xong bản nháp đầu tiên của báo cáo.','Bản nháp',1216,NULL,_binary '\0'),(1313,'To publicly support or suggest a particular way of doing something','Many experts advocate rewarding children for good behavior.','VERB','Công khai hỗ trợ hoặc đề xuất một cách làm nào đó','Nhiều chuyên gia ủng hộ việc thưởng cho trẻ em vì hành vi tốt.','Ủng hộ/Biện hộ',1217,NULL,_binary '\0'),(1314,'A person who publicly supports or recommends a particular cause or policy','He is a strong advocate of solar energy.','NOUN','Người công khai hỗ trợ một chính sách hoặc lý tưởng','Ông ấy là một người ủng hộ mạnh mẽ năng lượng mặt trời.','Người ủng hộ',1217,NULL,_binary '\0'),(1316,'Completely certain about something','I am convinced that we made the right choice.','ADJECTIVE','Hoàn toàn chắc chắn về một điều gì đó','Tôi tin chắc rằng chúng ta đã đưa ra lựa chọn đúng đắn.','Tin chắc/Bị thuyết phục',1219,NULL,_binary '\0'),(1317,'An opinion that is stated as part of an argument','It is my contention that the scheme will never work.','NOUN','Một ý kiến được đưa ra như một phần của cuộc tranh luận','Quan điểm của tôi là kế hoạch này sẽ không bao giờ thành công.','Quan điểm tranh luận',1220,NULL,_binary '\0'),(1318,'Having doubts that a claim or statement is true or that something will happen','Many people are skeptical about the government\'s promises.','ADJECTIVE','Nghi ngờ về tính xác thực của một tuyên bố','Nhiều người hoài nghi về những lời hứa của chính phủ.','Hoài nghi',1221,NULL,_binary '\0'),(1320,'Unfairly prejudiced for or against someone or something','The news report was heavily biased against the protesters.','ADJECTIVE','Ưu ái hoặc phản đối ai đó một cách thiếu công bằng','Bản tin đó đã bị định kiến nặng nề chống lại những người biểu tình.','Định kiến/Thiên vị',1223,NULL,_binary '\0'),(1321,'To state clearly and firmly that something is true','She continued to assert that she was innocent.','VERB','Nêu rõ ràng và mạnh mẽ rằng điều gì đó là đúng','Cô ấy tiếp tục khẳng định rằng mình vô tội.','Khẳng định/Quả quyết',1224,NULL,_binary '\0'),(1322,'To say that something that somebody else has said is wrong, and that the opposite is true','The witness\'s statement contradicts the evidence.','VERB','Nói rằng điều người khác nói là sai và điều ngược lại mới đúng','Lời khai của nhân chứng mâu thuẫn với bằng chứng.','Mâu thuẫn/Phủ nhận',1225,NULL,_binary '\0'),(1323,'To form an opinion about something without knowing all the details or facts','Experts speculate that the economy will recover next year.','VERB','Đưa ra ý kiến khi chưa biết hết các chi tiết hoặc sự thật','Các chuyên gia suy đoán rằng nền kinh tế sẽ phục hồi vào năm tới.','Suy đoán',1226,NULL,_binary '\0'),(1325,'To show that something is right or reasonable','How can you justify spending so much money on a car?','VERB','Chứng minh rằng điều gì đó là đúng hoặc hợp lý','Làm sao bạn có thể biện minh cho việc chi quá nhiều tiền vào một chiếc xe hơi?','Bào chữa/Biện minh',1228,NULL,_binary '\0'),(1326,'Based on or influenced by personal feelings, tastes, or opinions','The evaluation of art is often highly subjective.','ADJECTIVE','Dựa trên hoặc bị ảnh hưởng bởi cảm xúc hoặc ý kiến cá nhân','Việc đánh giá nghệ thuật thường mang tính chủ quan cao.','Chủ quan',1229,NULL,_binary '\0'),(1327,'An idea, a belief or an understanding of something','I have only a vague notion of what she does for a living.','NOUN','Một ý tưởng hoặc niềm tin về một điều gì đó','Tôi chỉ có một quan niệm mơ hồ về việc cô ấy làm gì để kiếm sống.','Quan niệm/Ý niệm',1230,NULL,_binary '\0'),(1328,'A person\'s opinion or point of view','From a legal standpoint, the contract is invalid.','NOUN','Góc nhìn hoặc ý kiến riêng của một người','Từ lập trường pháp lý, hợp đồng này không có giá trị.','Lập trường/Quan điểm',1231,NULL,_binary '\0'),(1331,'To stay at a steady level after a period of growth or progress','Sales have plateaued after a period of rapid growth.','VERB','Ngừng tăng trưởng và duy trì ở mức ổn định','Doanh số đã đi ngang sau một giai đoạn tăng trưởng nhanh chóng.','Trạng thái bình ổn',1234,NULL,_binary '\0'),(1332,'A period of time during which the situation remains the same','The inflation rate has reached a plateau.','NOUN','Giai đoạn mà mọi thứ không thay đổi','Tỷ lệ lạm phát đã đạt đến mức ổn định.','Cao nguyên/Thời kỳ ổn định',1234,NULL,_binary '\0'),(1333,'To fall suddenly and quickly from a high level or position','Share prices plummeted following the announcement of the merger.','VERB','Rơi tự do hoặc giảm cực nhanh từ một mức cao','Giá cổ phiếu đã lao dốc sau thông báo về việc sáp nhập.','Giảm mạnh/Lao dốc',1235,NULL,_binary '\0'),(1334,'To increase very quickly and suddenly','Food prices have rocketed in recent months.','VERB','Tăng lên rất nhanh và đột ngột','Giá thực phẩm đã tăng vọt trong những tháng gần đây.','Tăng vọt',1236,NULL,_binary '\0'),(1335,'Small and not important','There has been only a marginal improvement in her condition.','ADJECTIVE','Mức độ thay đổi rất ít, không quan trọng','Chỉ có một sự cải thiện không đáng kể trong tình trạng của cô ấy.','Nhỏ/Không đáng kể',1237,NULL,_binary '\0'),(1336,'A part or share of a whole','The proportion of elderly people in the population is growing.','NOUN','Một phần trong một tổng thể','Tỷ lệ người già trong dân số đang tăng lên.','Tỷ lệ/Phần',1238,NULL,_binary '\0'),(1337,'In the same order as the people or things already mentioned','Julie and Mark are 17 and 19 years old respectively.','ADVERB','Theo đúng thứ tự đã liệt kê trước đó','Julie và Mark lần lượt là 17 và 19 tuổi.','Lần lượt là',1239,NULL,_binary '\0'),(1338,'If two or more facts, numbers, etc. correlate, there is a close connection between them','A high-fat diet correlates with an increased risk of heart disease.','VERB','Có mối liên hệ mật thiết giữa các số liệu hoặc sự kiện','Chế độ ăn nhiều chất béo có tương quan với việc tăng nguy cơ mắc bệnh tim.','Có tương quan',1240,NULL,_binary '\0'),(1340,'To become or to make something become firm, steady and unlikely to change','The patient\'s condition has stabilized.','VERB','Trở nên vững chắc, không còn thay đổi thất thường','Tình trạng của bệnh nhân đã ổn định.','Bình ổn/Ổn định',1242,NULL,_binary '\0'),(1342,'Becoming faster and faster','We are looking for exponential growth in our online sales.','ADJECTIVE','Tăng trưởng với tốc độ ngày càng nhanh','Chúng tôi đang tìm kiếm sự tăng trưởng theo cấp số nhân trong doanh số bán hàng trực tuyến.','Theo cấp số nhân',1244,NULL,_binary '\0'),(1343,'Something that is different from what is normal or expected','The high sales figures for December are a seasonal anomaly.','NOUN','Một điểm dữ liệu hoặc hiện tượng khác lạ so với quy luật','Doanh số cao trong tháng 12 là một sự bất thường theo mùa.','Sự bất thường',1245,NULL,_binary '\0'),(1344,'A difference between two or more things that should be the same','What are the reasons for the discrepancy between these two sets of figures?','NOUN','Sự không khớp giữa các con số hoặc báo cáo lẽ ra phải giống nhau','Lý do cho sự khác biệt giữa hai bộ số liệu này là gì?','Sự khác biệt/Mâu thuẫn',1246,NULL,_binary '\0'),(1352,'A person who is chosen to settle a disagreement','The dispute was eventually settled by an independent arbitrator.','NOUN','Người trung gian được chọn để giải quyết tranh chấp giữa hai bên','Tranh chấp cuối cùng đã được giải quyết bởi một trọng tài độc lập.','Người phân xử/Trọng tài',1254,NULL,_binary '\0'),(1353,'Able to change to suit new conditions or situations','You need to be flexible if you want to reach an agreement.','ADJECTIVE','Có khả năng thay đổi để phù hợp với hoàn cảnh mới','Bạn cần phải linh hoạt nếu muốn đạt được thỏa thuận.','Linh hoạt',1255,NULL,_binary '\0'),(1360,'Having a useful and helpful effect rather than being negative or with no purpose','She welcomed constructive criticism from her colleagues.','ADJECTIVE','Có tác dụng hữu ích, giúp cải thiện thay vì chỉ trích tiêu cực','Cô ấy hoan nghênh những lời phê bình mang tính xây dựng từ đồng nghiệp.','Mang tính xây dựng',1262,NULL,_binary '\0'),(1364,'The process of becoming or making something better','There is still room for improvement in your report.','NOUN','Quá trình làm cho cái gì đó tốt hơn','Vẫn còn chỗ cần cải thiện trong bản báo cáo của bạn.','Sự cải thiện/Tiến bộ',1266,NULL,_binary '\0'),(1365,'A fault in somebody’s character, a plan, a system, etc.','She is very aware of her own shortcomings.','NOUN','Một điểm yếu hoặc lỗi trong tính cách hoặc kế hoạch','Cô ấy nhận thức rất rõ về những thiếu sót của bản thân.','Khuyết điểm/Thiếu sót',1267,NULL,_binary '\0'),(1366,'The ability to do something well','He demonstrated high professional competence in managing the project.','NOUN','Khả năng thực hiện tốt một công việc nào đó','Anh ấy đã chứng minh năng lực chuyên môn cao trong việc quản lý dự án.','Năng lực/Sự thạo việc',1268,NULL,_binary '\0'),(1369,'Creating or controlling a situation by causing something to happen rather than responding to it after it has happened','Employers value proactive workers who take initiative.','ADJECTIVE','Tự mình tạo ra thay đổi thay vì chờ đợi sự việc xảy ra rồi mới phản ứng','Người sử dụng lao động đánh giá cao những nhân viên chủ động, biết nắm bắt sáng kiến.','Chủ động',1271,NULL,_binary '\0'),(1371,'A fault or a lack of something that is needed','The report highlights several deficiencies in the current system.','NOUN','Sự thiếu một yếu tố cần thiết nào đó hoặc lỗi trong hệ thống','Bản báo cáo nhấn mạnh một vài khiếm khuyết trong hệ thống hiện tại.','Sự thiếu hụt/Khiếm khuyết',1273,NULL,_binary '\0'),(1373,'To make a feeling, an idea, etc. stronger','Positive feedback can reinforce good working habits.','VERB','Làm cho một ý tưởng, thói quen hoặc cảm xúc trở nên mạnh mẽ hơn','Phản hồi tích cực có thể củng cố các thói quen làm việc tốt.','Củng cố/Tăng cường',1275,NULL,_binary '\0'),(1375,'The art of public speaking, especially in a formal and eloquent manner','The politician was famous for his fine oratory.','NOUN','Khả năng nói trước đám đông một cách hùng hồn và lôi cuốn','Vị chính trị gia đó nổi tiếng với khả năng diễn thuyết tuyệt vời của mình.','Nghệ thuật diễn thuyết',1277,NULL,_binary '\0'),(1376,'Able to express thoughts and feelings easily and clearly','She is an articulate speaker who can command an audience.','ADJECTIVE','Có thể trình bày ý nghĩ và cảm xúc một cách rõ ràng, dễ hiểu','Cô ấy là một diễn giả có khả năng diễn đạt tốt, người có thể làm chủ thính giả.','Có khả năng diễn đạt tốt',1278,NULL,_binary '\0'),(1377,'To express an idea or a feeling fluently and coherently','It is important to articulate your words clearly during a presentation.','VERB','Trình bày một ý tưởng một cách lưu loát','Việc phát âm rõ ràng các từ trong bài thuyết trình là rất quan trọng.','Phát âm rõ/Diễn đạt',1278,NULL,_binary '\0'),(1379,'Dull, tedious, and repetitious; lacking in variety and interest','The teacher\'s monotonous voice made it hard to stay awake.','ADJECTIVE','Nhàm chán, thiếu sự thay đổi về âm điệu hoặc phong cách','Giọng nói đều đều nhàm chán của giáo viên khiến mọi người khó mà tỉnh táo.','Đơn điệu/Đều đều',1280,NULL,_binary '\0'),(1380,'The art of effective or persuasive speaking or writing, especially the use of figures of speech and other compositional techniques','We should look behind the political rhetoric to see the real issues.','NOUN','Cách sử dụng ngôn từ để thuyết phục hoặc gây ấn tượng','Chúng ta nên nhìn thấu những lời lẽ hùng biện chính trị để thấy được vấn đề thực sự.','Phép hùng biện',1281,NULL,_binary '\0'),(1381,'To say or pronounce words clearly','She enunciated each word slowly and carefully.','VERB','Đọc hoặc nói các từ một cách chuẩn xác để người khác nghe rõ','Cô ấy phát âm từng chữ một cách chậm rãi và cẩn thận.','Phát âm rõ ràng',1282,NULL,_binary '\0'),(1382,'Nervousness before or during an appearance before an audience','Even experienced actors can suffer from stage fright.','NOUN','Cảm giác lo lắng khi đứng trước đám đông','Ngay cả những diễn viên dày dạn kinh nghiệm cũng có thể bị hội chứng sợ sân khấu.','Nỗi sợ sân khấu',1283,NULL,_binary '\0'),(1383,'Something that you are shown, such as a picture, a chart or a film, that helps you to understand or remember information','The speaker used several visual aids to make the data clearer.','NOUN','Các vật dụng như tranh ảnh, biểu đồ giúp bài nói dễ hiểu hơn','Diễn giả đã sử dụng một vài hình ảnh minh họa để làm cho dữ liệu rõ ràng hơn.','Hình ảnh minh họa/Công cụ hỗ trợ',1284,NULL,_binary '\0'),(1386,'To speak or perform without preparing or practising','He forgot his notes and had to improvise the last part of the presentation.','VERB','Nói hoặc thực hiện một việc gì đó mà không có kịch bản sẵn','Anh ấy quên ghi chú và phải ứng biến phần cuối của bài thuyết trình.','Ứng biến/Làm mà không chuẩn bị trước',1287,NULL,_binary '\0'),(1388,'The process of encouraging an audience to participate or show interest','Interactive polls are a great way to increase audience engagement.','NOUN','Các hoạt động giúp khán giả tham gia và hứng thú với bài nói','Các cuộc khảo sát tương tác là cách tuyệt vời để tăng sự tương tác với khán giả.','Sự tương tác với khán giả',1289,NULL,_binary '\0'),(1389,'A strong belief or opinion; the quality of showing that you believe strongly in what you are saying','She spoke with deep conviction about the need for environmental reform.','NOUN','Phong thái cho thấy bạn tin tưởng hoàn toàn vào điều mình nói','Cô ấy đã nói với niềm tin mãnh liệt về nhu cầu cải cách môi trường.','Sự tin tưởng mãnh liệt/Sự thuyết phục',1290,NULL,_binary '\0'),(1390,'Expressed clearly and in a few words','Keep your answers succinct and to the point.','ADJECTIVE','Trình bày rõ ràng bằng rất ít từ','Hãy giữ câu trả lời của bạn súc tích và đúng trọng tâm.','Ngắn gọn/Súc tích',1291,NULL,_binary '\0'),(1391,'The act of officially joining a course, school, or university','Enrollment for the spring semester begins next Monday.','NOUN','Hành động đăng ký chính thức vào một khóa học hoặc trường học','Việc đăng ký nhập học cho học kỳ mùa xuân bắt đầu vào thứ Hai tới.','Sự ghi danh/Nhập học',1292,NULL,_binary '\0'),(1392,'An official responsible for keeping a register or official records','The registrar’s office handles all questions regarding student transcripts.','NOUN','Cán bộ chịu trách nhiệm về hồ sơ sinh viên và đăng ký học tập','Văn phòng quản lý hồ sơ giải quyết tất cả các câu hỏi liên quan đến học bạ sinh viên.','Người quản lý hồ sơ',1293,NULL,_binary '\0'),(1393,'A list of the topics, books, etc. that students should study in a particular course','The professor handed out the syllabus on the first day of class.','NOUN','Danh sách các chủ đề, sách vở cần học trong một khóa học','Giáo sư đã phát đề cương môn học vào ngày đầu tiên của lớp học.','Đề cương môn học',1294,NULL,_binary '\0'),(1394,'A building for university students to live in','Living in a dormitory is a great way to meet new people.','NOUN','Tòa nhà dành cho sinh viên ở trong khuôn viên trường','Sống trong ký túc xá là một cách tuyệt vời để gặp gỡ những người bạn mới.','Ký túc xá',1295,NULL,_binary '\0'),(1395,'The money that you pay to be taught, especially in a college or university','The university has announced an increase in tuition fees for next year.','NOUN','Số tiền phải trả để được giảng dạy tại trường học','Trường đại học đã thông báo tăng học phí cho năm tới.','Học phí',1296,NULL,_binary '\0'),(1396,'Training or information that you are given before starting a new job or course','The orientation session helps students get familiar with the campus.','NOUN','Chương trình giới thiệu cho tân sinh viên trước khi nhập học','Buổi định hướng giúp sinh viên làm quen với khuôn viên trường.','Buổi định hướng',1297,NULL,_binary '\0'),(1397,'An official record of a student’s work, showing their grades','You need to submit your official transcript with your application.','NOUN','Bản ghi chép chính thức kết quả học tập của sinh viên','Bạn cần nộp bảng điểm chính thức kèm theo đơn đăng ký.','Bảng điểm/Học bạ',1298,NULL,_binary '\0'),(1399,'Something that must exist or happen before something else can happen or be done','Introduction to Statistics is a prerequisite for this advanced course.','NOUN','Môn học hoặc điều kiện cần có trước khi đăng ký một môn khác','Nhập môn Thống kê là điều kiện tiên quyết cho khóa học nâng cao này.','Điều kiện tiên quyết',1300,NULL,_binary '\0'),(1401,'Buildings, services, or equipment that are provided for a particular purpose','The campus has excellent sports facilities, including a gym and a pool.','NOUN','Trang thiết bị hoặc tòa nhà phục vụ một nhu cầu cụ thể','Khuôn viên trường có cơ sở vật chất thể thao tuyệt vời, bao gồm phòng gym và hồ bơi.','Cơ sở vật chất',1302,NULL,_binary '\0'),(1403,'A teacher who helps students with their choice of subjects and academic problems','You should consult your academic advisor before dropping a course.','NOUN','Giảng viên hỗ trợ sinh viên về việc chọn môn và các vấn đề học tập','Bạn nên tham khảo ý kiến cố vấn học tập trước khi bỏ một môn học.','Cố vấn học tập',1304,NULL,_binary '\0'),(1405,'A former student of a school, college, or university','He is a famous alumnus of Harvard University.','NOUN','Người đã từng theo học tại một trường nào đó','Ông ấy là một cựu sinh viên nổi tiếng của Đại học Harvard.','Cựu sinh viên',1306,NULL,_binary '\0'),(1406,'The place in a library where you borrow and return books','You can renew your books at the circulation desk.','NOUN','Nơi thực hiện các thủ tục mượn và trả tài liệu trong thư viện','Bạn có thể gia hạn sách tại quầy mượn trả.','Quầy mượn trả sách',1307,NULL,_binary '\0'),(1407,'Not paid, done, returned, etc. by the required time','You will have to pay a fine if the books are overdue.','ADJECTIVE','Không được trả hoặc thực hiện đúng thời gian quy định','Bạn sẽ phải nộp phạt nếu sách bị quá hạn.','Quá hạn',1309,NULL,_binary '\0'),(1409,'A list of the books and articles that have been used by someone when writing a particular book or article','Always include a bibliography at the end of your essay.','NOUN','Danh sách các sách và bài báo đã được sử dụng để viết một tác phẩm','Luôn đính kèm danh mục tài liệu tham khảo ở cuối bài luận của bạn.','Thư mục tham khảo',1311,NULL,_binary '\0'),(1411,'An organized set of data that is stored in a computer','Students can access the online database to search for journals.','NOUN','Tập hợp dữ liệu được tổ chức và lưu trữ trên máy tính','Sinh viên có thể truy cập cơ sở dữ liệu trực tuyến để tìm kiếm các tạp chí.','Cơ sở dữ liệu',1313,NULL,_binary '\0'),(1412,'A system in which one library borrows a book from another library for a person to use','If we don’t have the book, we can get it for you through an interlibrary loan.','NOUN','Hệ thống cho phép mượn sách từ các thư viện khác trong cùng mạng lưới','Nếu chúng tôi không có cuốn sách đó, chúng tôi có thể mượn giúp bạn thông qua hệ thống mượn liên thư viện.','Mượn liên thư viện',1314,NULL,_binary '\0'),(1413,'The practice of taking someone else\'s work or ideas and passing them off as one\'s own','The university has a strict policy against plagiarism.','NOUN','Hành động lấy ý tưởng hoặc tác phẩm của người khác và coi là của mình','Trường đại học có chính sách nghiêm ngặt chống lại việc đạo văn.','Sự đạo văn',1315,NULL,_binary '\0'),(1415,'The area of a library where the main part of the collection of books is kept on shelves','I spent all afternoon browsing in the library stacks.','NOUN','Khu vực chứa các giá sách chính trong thư viện','Tôi đã dành cả buổi chiều để tìm kiếm trong các dãy kệ sách của thư viện.','Dãy kệ sách',1317,NULL,_binary '\0'),(1417,'A copy of a book, piece of music, etc. before it has been printed','The library houses several rare medieval manuscripts.','NOUN','Bản viết tay hoặc đánh máy của một tác phẩm trước khi được in ấn','Thư viện lưu giữ một vài bản thảo thời trung cổ quý hiếm.','Bản thảo',1319,NULL,_binary '\0'),(1418,'To extend the period of validity of something','I need to renew my library books for another two weeks.','VERB','Kéo dài thời gian hiệu lực của việc mượn sách','Tôi cần gia hạn sách thư viện thêm hai tuần nữa.','Gia hạn',1320,NULL,_binary '\0'),(1419,'A words or lines taken from a book or a person that are used in a new book','The essay lacks proper citations of the sources used.','NOUN','Việc dẫn lại lời văn hoặc ý tưởng từ một nguồn tài liệu khác','Bài luận này thiếu các trích dẫn đúng cách cho các nguồn đã sử dụng.','Sự trích dẫn',1321,NULL,_binary '\0'),(1423,'A decision to stop something that has been planned','There is a 24-hour cancellation policy for this hotel.','NOUN','Quyết định dừng một việc đã được lên kế hoạch','Khách sạn này có chính sách hủy phòng trong vòng 24 giờ.','Sự hủy bỏ',1325,NULL,_binary '\0'),(1424,'That cannot be returned, especially money','The deposit is non-refundable if you cancel after the deadline.','ADJECTIVE','Tiền đã trả không thể lấy lại được','Tiền đặt cọc sẽ không được hoàn lại nếu bạn hủy sau thời hạn.','Không hoàn lại',1326,NULL,_binary '\0'),(1425,'Having no more space or rooms available','I’m afraid the restaurant is fully booked for tonight.','ADJECTIVE','Không còn chỗ trống hoặc phòng trống','Tôi e rằng nhà hàng đã kín chỗ vào tối nay.','Đã hết chỗ/Đã đặt kín',1327,NULL,_binary '\0'),(1426,'Two people or things that are complementary are different but together form a useful or attractive combination','The hotel offers complementary services such as spa and gym access.','ADJECTIVE','Kết hợp với nhau để tạo nên một bộ hoàn chỉnh hoặc tốt hơn','Khách sạn cung cấp các dịch vụ bổ sung như quyền sử dụng spa và phòng gym.','Bổ sung/Bù trừ',1328,NULL,_binary '\0'),(1427,'A plan of a journey, including the route and the places that you will visit','We will send you a detailed itinerary two weeks before the trip.','NOUN','Kế hoạch cho một chuyến đi, bao gồm lộ trình và các địa điểm tham quan','Chúng tôi sẽ gửi cho bạn lịch trình chi tiết hai tuần trước chuyến đi.','Lịch trình',1329,NULL,_binary '\0'),(1430,'A printed piece of paper that can be used instead of money to pay for something','You can redeem this voucher for a free night at any of our hotels.','NOUN','Tờ phiếu dùng để thanh toán hoặc đổi lấy dịch vụ','Bạn có thể đổi phiếu này để lấy một đêm nghỉ miễn phí tại bất kỳ khách sạn nào của chúng tôi.','Phiếu mua hàng/Voucher',1332,NULL,_binary '\0'),(1431,'An extra amount of money that you must pay in addition to the usual price','There is a $10 surcharge for weekend bookings.','NOUN','Khoản tiền trả thêm ngoài giá thông thường','Có khoản phụ phí 10 USD cho việc đặt chỗ vào cuối tuần.','Phụ phí',1333,NULL,_binary '\0'),(1432,'To promise the same room, seat, etc. to two different people at the same time','I’m sorry, but we seem to have double-booked your table.','VERB','Vô tình cho hai người khác nhau đặt cùng một chỗ vào cùng một thời điểm','Tôi xin lỗi, nhưng có vẻ như chúng tôi đã cho đặt trùng bàn của bạn.','Đặt trùng chỗ',1334,NULL,_binary '\0'),(1433,'The time of year when the most people visit a place','Prices are much higher during the peak season.','NOUN','Khoảng thời gian trong năm có lượng khách du lịch đông nhất','Giá cả cao hơn nhiều trong mùa cao điểm.','Mùa cao điểm',1335,NULL,_binary '\0'),(1434,'A person or thing that is ready to be used if necessary; a way of traveling where you wait for a seat on a flight to become available','I’m on standby for the 5 PM flight to London.','NOUN','Tình trạng chờ để có ghế trống vào phút chót','Tôi đang trong danh sách chờ cho chuyến bay lúc 5 giờ chiều đi London.','Vé chờ/Chế độ chờ',1336,NULL,_binary '\0'),(1437,'A long passage in a building from which doors lead into rooms','His office is at the end of the corridor on the left.','NOUN','Lối đi dài trong tòa nhà dẫn vào các phòng','Văn phòng của anh ấy nằm ở cuối hành lang bên tay trái.','Hành lang',1339,NULL,_binary '\0'),(1438,'Next to or adjoining something else','The cafeteria is adjacent to the main library.','ADJECTIVE','Vị trí nằm ngay cạnh hoặc tiếp giáp với thứ gì đó','Nhà ăn nằm ngay sát cạnh thư viện chính.','Kế bên/Sát cạnh',1340,NULL,_binary '\0'),(1442,'Two lines that are parallel to each other are the same distance apart along their whole length','The high street runs parallel to the river.','ADJECTIVE','Vị trí chạy dài cùng hướng và cách đều một vật khác','Phố chính chạy song song với con sông.','Song song với',1344,NULL,_binary '\0'),(1444,'A quicker or shorter way of getting to a place','I know a shortcut through the park.','NOUN','Cách đi nhanh hơn hoặc ngắn hơn để đến một nơi','Tôi biết một con đường tắt đi xuyên qua công viên.','Đường tắt',1346,NULL,_binary '\0'),(1450,'An extra telephone line that is connected to the main line in an office or large building','If you know the extension of the person you want to talk to, please dial it now.','NOUN','Số điện thoại phụ kết nối với tổng đài nội bộ','Nếu bạn biết số máy lẻ của người cần gặp, vui lòng bấm số ngay bây giờ.','Số máy lẻ',1352,NULL,_binary '\0'),(1451,'To connect somebody by telephone','Hold the line, please. I’ll put you through to the manager.','PHRASAL_VERB','Nối đường dây điện thoại để ai đó nói chuyện với người khác','Vui lòng giữ máy. Tôi sẽ chuyển máy cho bạn tới quản lý.','Kết nối máy/Chuyển máy',1353,NULL,_binary '\0'),(1452,'To wait on the telephone until the person you want to talk to is available','Could you hold the line while I check that for you?','IDIOM','Đợi trên đường dây điện thoại cho đến khi gặp được người cần gặp','Bạn có thể giữ máy trong khi tôi kiểm tra thông tin đó không?','Giữ máy/Chờ máy',1354,NULL,_binary '\0'),(1454,'To end a telephone conversation by putting the receiver down or pressing a button','Don’t hang up yet, I have one more thing to say.','PHRASAL_VERB','Kết thúc cuộc gọi điện thoại','Đừng cúp máy vội, tôi còn một điều nữa muốn nói.','Gác máy/Cúp máy',1356,NULL,_binary '\0'),(1455,'An electronic system which can store telephone messages from people','I left a message on your voicemail this morning.','NOUN','Hệ thống điện tử lưu lại tin nhắn lời nói khi không nghe máy','Tôi đã để lại một tin nhắn trong thư thoại của bạn sáng nay.','Thư thoại',1357,NULL,_binary '\0'),(1457,'Something that temporarily stops an activity or a situation','I’m sorry for the interruption, but there’s an urgent call for you.','NOUN','Hành động ngắt lời khi người khác đang nói hoặc làm việc','Xin lỗi vì đã ngắt lời, nhưng có một cuộc gọi khẩn cho bạn.','Sự gián đoạn/Ngắt lời',1359,NULL,_binary '\0'),(1458,'To interrupt or person on the telephone by breaking the connection','We were cut off in the middle of our conversation.','PHRASAL_VERB','Cuộc gọi bị ngắt giữa chừng do lỗi kỹ thuật hoặc sóng yếu','Chúng tôi đã bị ngắt kết nối ngay giữa cuộc hội thoại.','Bị cắt đứt liên lạc',1360,NULL,_binary '\0'),(1459,'Using computers or machines to do a job that was previously done by people','You will hear an automated message asking you to select an option.','ADJECTIVE','Hệ thống trả lời tự động không cần người trực trực tiếp','Bạn sẽ nghe thấy một tin nhắn tự động yêu cầu bạn chọn một tùy chọn.','Tự động',1361,NULL,_binary '\0'),(1460,'To press the buttons on a telephone to call a particular number','Dial 9 to get an outside line.','VERB','Thực hiện việc bấm số để gọi điện','Bấm số 9 để thực hiện cuộc gọi ra bên ngoài.','Quay số/Bấm số',1362,NULL,_binary '\0'),(1461,'To speak more loudly so that people can hear you','Could you speak up a bit? The line is very faint.','PHRASAL_VERB','Yêu cầu người ở đầu dây bên kia nói lớn hơn','Bạn có thể nói to hơn một chút không? Tín hiệu nghe rất nhỏ.','Nói to lên',1363,NULL,_binary '\0'),(1468,'A short summary of a book, speech, or academic paper','Please read the abstract before coming to the seminar.','NOUN','Đoạn tóm tắt ngắn gọn nội dung của một bài báo cáo khoa học','Vui lòng đọc bản tóm tắt trước khi đến buổi hội thảo.','Bản tóm tắt',1370,NULL,_binary '\0'),(1471,'A detailed study of a particular person, group, or situation over a period of time','The professor used a case study to illustrate the marketing concept.','NOUN','Việc nghiên cứu chi tiết về một đối tượng hoặc tình huống cụ thể','Giáo sư đã sử dụng một nghiên cứu điển hình để minh họa cho khái niệm marketing.','Nghiên cứu điển hình',1373,NULL,_binary '\0'),(1472,'An examination of books and articles on a particular subject','Your thesis must include a comprehensive literature review.','NOUN','Phần tóm tắt và đánh giá các nghiên cứu đã thực hiện trước đó về một chủ đề','Luận văn của bạn phải bao gồm một phần tổng quan tài liệu toàn diện.','Tổng quan tài liệu',1374,NULL,_binary '\0'),(1473,'Happening before a more important action or event','The preliminary findings suggest that the treatment is effective.','ADJECTIVE','Diễn ra trước một sự kiện hoặc hành động quan trọng hơn','Những phát hiện sơ bộ cho thấy phương pháp điều trị này có hiệu quả.','Sơ bộ/Mở đầu',1375,NULL,_binary '\0'),(1474,'The set of technical words or expressions used in a particular subject','Scientific terminology can be difficult for non-specialists to understand.','NOUN','Tập hợp các từ chuyên môn được sử dụng trong một lĩnh vực cụ thể','Thuật ngữ khoa học có thể khó hiểu đối với những người không chuyên.','Thuật ngữ',1376,NULL,_binary '\0'),(1480,'A person who is applying for a job','We are interviewing several candidates for the sales manager position.','NOUN','Người nộp đơn xin việc hoặc ứng cử vào một vị trí','Chúng tôi đang phỏng vấn một vài ứng viên cho vị trí quản lý bán hàng.','Ứng viên',1382,NULL,_binary '\0'),(1481,'The qualities, training or experience that make you suitable for a particular job','She has impressive academic credentials from top universities.','NOUN','Các phẩm chất, bằng cấp hoặc kinh nghiệm giúp bạn phù hợp với công việc','Cô ấy có bằng cấp học thuật ấn tượng từ những trường đại học hàng đầu.','Năng lực/Chứng chỉ',1383,NULL,_binary '\0'),(1482,'The good and bad qualities of a person','Be prepared to talk about your strengths and weaknesses during the interview.','NOUN','Những ưu điểm và khuyết điểm của một người','Hãy chuẩn bị để nói về điểm mạnh và điểm yếu của bạn trong buổi phỏng vấn.','Điểm mạnh và điểm yếu',1384,NULL,_binary '\0'),(1484,'The ability to communicate or interact well with other people','Good interpersonal skills are essential for this customer-facing role.','NOUN','Khả năng giao tiếp và tương tác tốt với những người khác','Kỹ năng giao tiếp tốt là rất cần thiết cho vị trí tiếp xúc với khách hàng này.','Kỹ năng giao tiếp ứng xử',1386,NULL,_binary '\0'),(1487,'The process of finding new people to join an organization','The company has a very rigorous recruitment process.','NOUN','Quá trình tìm kiếm người mới gia nhập một tổ chức','Công ty có một quy trình tuyển dụng rất khắt khe.','Sự tuyển dụng',1389,NULL,_binary '\0'),(1488,'A salary that is as good as or better than those offered by other companies','We offer a competitive salary and an excellent benefits package.','NOUN','Mức lương tốt tương đương hoặc cao hơn so với các công ty khác cùng ngành','Chúng tôi cung cấp một mức lương cạnh tranh và gói phúc lợi tuyệt vời.','Mức lương cạnh tranh',1390,NULL,_binary '\0'),(1489,'A person who agrees to write a report on your character or ability to do a job','We will contact your references after the final interview.','NOUN','Người xác nhận năng lực và đạo đức làm việc của ứng viên','Chúng tôi sẽ liên hệ với những người tham chiếu của bạn sau buổi phỏng vấn cuối cùng.','Người tham chiếu',1391,NULL,_binary '\0'),(1490,'Having more experience or better qualifications than are needed for a job','He was rejected because they thought he was overqualified for the position.','ADJECTIVE','Có kinh nghiệm hoặc bằng cấp cao hơn mức cần thiết cho công việc','Anh ấy bị từ chối vì họ nghĩ rằng anh ấy thừa tiêu chuẩn cho vị trí đó.','Thừa tiêu chuẩn',1392,NULL,_binary '\0'),(1491,'To arrange something so that it is in the correct position or relation to something else','My career goals align perfectly with the company\'s mission.','VERB','Phù hợp với mục tiêu hoặc giá trị của một tổ chức','Mục tiêu nghề nghiệp của tôi hoàn toàn phù hợp với sứ mệnh của công ty.','Phù hợp/Đồng bộ với',1393,NULL,_binary '\0'),(1492,'Involving a lot of stress or urgent tasks','I have experience working in a high-pressure environment.','ADJECTIVE','Môi trường làm việc căng thẳng với nhiều nhiệm vụ khẩn cấp','Tôi có kinh nghiệm làm việc trong môi trường áp lực cao.','Áp lực cao',1394,NULL,_binary '\0'),(1494,'A small number of candidates who have been chosen from all the people who applied for a job','She has been put on the shortlist for the position.','NOUN','Danh sách những ứng viên xuất sắc nhất được chọn vào vòng phỏng vấn cuối','Cô ấy đã được đưa vào danh sách rút gọn cho vị trí này.','Danh sách rút gọn',1396,NULL,_binary '\0'),(1495,'An amount of money paid to somebody for the work they have done','The committee will determine the appropriate remuneration for the CEO.','NOUN','Số tiền trả cho ai đó tương xứng với công việc họ đã làm (bao gồm lương và thưởng)','Ủy ban sẽ quyết định mức thù lao phù hợp cho vị trí Giám đốc điều hành.','Thù lao',1397,NULL,_binary '\0'),(1496,'Something that you get for working, in addition to your pay, such as a company car or health insurance','Fringe benefits such as free meals can make a job much more attractive.','NOUN','Các lợi ích thêm ngoài lương như xe công ty, bảo hiểm, hay thẻ tập gym','Các phúc lợi phụ như bữa ăn miễn phí có thể làm cho công việc hấp dẫn hơn nhiều.','Phúc lợi phụ',1398,NULL,_binary '\0'),(1497,'The state of being no longer in a job because there is no more work available, rather than due to poor performance','The factory closure resulted in hundreds of redundancies.','NOUN','Tình trạng mất việc do công ty không còn nhu cầu vị trí đó (không phải do lỗi nhân viên)','Việc đóng cửa nhà máy đã dẫn đến hàng trăm vụ cắt giảm nhân sự.','Sự cắt giảm nhân sự',1399,NULL,_binary '\0'),(1499,'To officially tell somebody that you are leaving your job, an organization, etc.','He resigned from the board of directors for personal reasons.','VERB','Chính thức thông báo rời bỏ vị trí công tác','Ông ấy đã từ chức khỏi hội đồng quản trị vì lý do cá nhân.','Từ chức/Thôi việc',1401,NULL,_binary '\0'),(1500,'Money that an employer pays to an employee whose job has been cut','The laid-off workers were offered a generous severance pay package.','NOUN','Khoản tiền công ty trả cho nhân viên khi họ bị cho thôi việc (do cắt giảm)','Những công nhân bị sa thải đã được đề nghị một gói trợ cấp thôi việc hậu hĩnh.','Trợ cấp thôi việc',1402,NULL,_binary '\0'),(1501,'A system in which employees can choose their own starting and finishing times within certain limits','Flexitime allows parents to balance their work and family life.','NOUN','Chế độ cho phép nhân viên tự chọn giờ bắt đầu và kết thúc làm việc','Giờ làm việc linh hoạt cho phép cha mẹ cân bằng giữa công việc và gia đình.','Giờ làm việc linh hoạt',1403,NULL,_binary '\0'),(1504,'An amount of money paid regularly by a government or company to somebody who has retired','She lives on a modest state pension.','NOUN','Khoản tiền trả định kỳ cho người đã nghỉ hưu','Bà ấy sống dựa vào khoản lương hưu nhà nước khiêm tốn.','Lương hưu',1406,NULL,_binary '\0'),(1505,'Time that you spend working at your job in addition to your normal working hours','We had to work a lot of overtime to meet the deadline.','NOUN','Thời gian làm việc ngoài giờ quy định','Chúng tôi đã phải làm thêm giờ rất nhiều để kịp thời hạn.','Giờ làm thêm',1407,NULL,_binary '\0'),(1506,'The rate at which employees leave a company and are replaced by new people','High labor turnover can be a sign of poor management.','NOUN','Tốc độ nhân viên nghỉ việc và được thay thế bởi người mới','Tỷ lệ nghỉ việc cao có thể là dấu hiệu của việc quản lý kém.','Tỷ lệ biến động nhân sự',1408,NULL,_binary '\0'),(1507,'The lowest payment for hour, day, or month that can be given to a worker by law','The government is planning to increase the national minimum wage.','NOUN','Mức thù lao thấp nhất mà người sử dụng lao động phải trả theo luật','Chính phủ đang lên kế hoạch tăng mức lương tối thiểu quốc gia.','Lương tối thiểu',1409,NULL,_binary '\0'),(1508,'An official order or commission to do something','The company has a mandate to improve workplace safety.','NOUN','Một yêu cầu chính thức phải thực hiện điều gì đó','Công ty có chỉ thị phải cải thiện an toàn tại nơi làm việc.','Chỉ thị/Lệnh',1410,NULL,_binary '\0'),(1509,'A job that is available in an organization and that nobody is doing','There is currently a vacancy for a junior accountant.','NOUN','Một công việc đang cần tuyển người','Hiện đang có một vị trí trống cho nhân viên kế toán sơ cấp.','Vị trí trống',1411,NULL,_binary '\0'),(1511,'A work of art such as a painting, movie, or book that is made with great skill','The Mona Lisa is considered a masterpiece of the Renaissance.','NOUN','Một tác phẩm nghệ thuật xuất sắc được tạo ra với kỹ năng bậc thầy','Mona Lisa được coi là một kiệt tác của thời kỳ Phục hưng.','Kiệt tác',1413,NULL,_binary '\0'),(1512,'An object that is made by a person, especially one of historical or cultural interest','The museum displays ancient artifacts found in the Mekong Delta.','NOUN','Vật thể do con người tạo ra, có giá trị lịch sử hoặc văn hóa','Bảo tàng trưng bày các cổ vật được tìm thấy ở Đồng bằng sông Cửu Long.','Hiện vật/Cổ vật',1414,NULL,_binary '\0'),(1513,'The branch of philosophy that deals with the principles of beauty and artistic taste','The building was designed with a focus on modern aesthetics.','NOUN','Các nguyên tắc về vẻ đẹp và thị hiếu nghệ thuật','Tòa nhà được thiết kế tập trung vào tính thẩm mỹ hiện đại.','Mỹ học/Tính thẩm mỹ',1415,NULL,_binary '\0'),(1514,'To select, organize, and look after the items in an exhibition or collection','He was invited to curate an exhibition of contemporary Vietnamese art.','VERB','Lựa chọn, tổ chức và chăm sóc các hiện vật trong một cuộc triển lãm','Anh ấy được mời giám tuyển một cuộc triển lãm nghệ thuật đương đại Việt Nam.','Giám tuyển/Phụ trách trưng bày',1416,NULL,_binary '\0'),(1515,'The act of keeping something the same or of preventing it from being damaged','The government is committed to the preservation of historic buildings.','NOUN','Hành động giữ gìn hoặc ngăn chặn sự hư hại của một vật gì đó','Chính phủ cam kết bảo tồn các tòa nhà lịch sử.','Sự bảo tồn',1417,NULL,_binary '\0'),(1517,'Belonging to the present time','The museum features both classical and contemporary art.','ADJECTIVE','Thuộc về thời điểm hiện tại, ngày nay','Bảo tàng trưng bày cả nghệ thuật cổ điển và đương đại.','Đương đại',1419,NULL,_binary '\0'),(1520,'The traditional beliefs, customs, and stories of a community, passed through the generations by word of mouth','Modern literature often draws inspiration from Vietnamese folklore.','NOUN','Các niềm tin, phong tục và câu chuyện truyền miệng của một cộng đồng','Văn học hiện đại thường lấy cảm hứng từ văn hóa dân gian Việt Nam.','Văn hóa dân gian',1422,NULL,_binary '\0'),(1521,'A painting, usually a large one, done directly on a wall','The city is famous for its colorful street murals.','NOUN','Tác phẩm hội họa được vẽ trực tiếp lên bề mặt tường','Thành phố nổi tiếng với những bức tranh tường đường phố đầy màu sắc.','Tranh khổ lớn/Tranh tường',1423,NULL,_binary '\0'),(1522,'Belonging to a particular place rather than coming to it from somewhere else','The gallery displays the works of indigenous artists.','ADJECTIVE','Gốc gác tại một địa phương cụ thể, không phải từ nơi khác đến','Phòng trưng bày trưng bày các tác phẩm của các nghệ sĩ bản địa.','Bản địa',1424,NULL,_binary '\0'),(1523,'The design and style of buildings','I am fascinated by the ancient architecture of Hoi An.','NOUN','Thiết kế và phong cách của các tòa nhà','Tôi bị lôi cuốn bởi kiến trúc cổ kính của Hội An.','Kiến trúc',1425,NULL,_binary '\0'),(1524,'That cannot be touched; not physical','UNESCO recognizes Quan Ho singing as an intangible cultural heritage.','ADJECTIVE','Không thể chạm vào được, không có thực thể vật chất','UNESCO công nhận dân ca Quan họ là di sản văn hóa phi vật thể.','Phi vật thể',1426,NULL,_binary '\0'),(1526,'A law or a set of laws passed by a parliament','New legislation will be introduced to help small businesses.','NOUN','Một bộ luật hoặc các quy định được quốc hội thông qua','Luật mới sẽ được đưa ra để giúp đỡ các doanh nghiệp nhỏ.','Pháp luật/Việc lập pháp',1428,NULL,_binary '\0'),(1528,'To take a claim or dispute to a court of law','The parties decided to settle the dispute rather than litigate.','VERB','Đưa một yêu cầu hoặc tranh chấp ra tòa án','Các bên đã quyết định hòa giải tranh chấp thay vì kiện tụng ra tòa.','Kiện tụng/Tranh chấp pháp lý',1430,NULL,_binary '\0'),(1529,'A person who brings a case against another in a court of law','The plaintiff is seeking damages for breach of contract.','NOUN','Người đứng ra kiện người khác trong một vụ án dân sự','Nguyên đơn đang yêu cầu bồi thường thiệt hại do vi phạm hợp đồng.','Nguyên đơn',1431,NULL,_binary '\0'),(1530,'A person or group against whom a criminal or civil action is brought','The jury found the defendant not guilty.','NOUN','Người bị kiện hoặc bị buộc tội trong một vụ án','Bồi thẩm đoàn đã tuyên bị cáo không có tội.','Bị đơn/Bị cáo',1432,NULL,_binary '\0'),(1531,'An official rule made by a government or some other authority','The new environmental regulations are very strict.','NOUN','Quy tắc chính thức do chính phủ hoặc cơ quan có thẩm quyền ban hành','Các quy định mới về môi trường rất nghiêm ngặt.','Quy định/Quy tắc',1433,NULL,_binary '\0'),(1532,'Ideas, designs, etc. that belong to a person or company and that other people are not allowed to copy','The company protects its intellectual property through patents.','NOUN','Các ý tưởng, thiết kế... thuộc về một cá nhân/công ty mà người khác không được sao chép','Công ty bảo vệ quyền sở hữu trí tuệ của mình thông qua bằng sáng chế.','Sở hữu trí tuệ',1434,NULL,_binary '\0'),(1534,'A formal written or spoken statement, especially one given in a court of law','Her testimony was crucial to the outcome of the trial.','NOUN','Lời khẳng định chính thức bằng văn bản hoặc bằng lời nói trước tòa','Lời khai của cô ấy mang tính quyết định đối với kết quả của phiên tòa.','Lời khai/Chứng cứ',1436,NULL,_binary '\0'),(1535,'A decision that is made by a jury in a court of law','The jury reached a unanimous verdict of guilty.','NOUN','Quyết định cuối cùng của bồi thẩm đoàn hoặc thẩm phán','Bồi thẩm đoàn đã đưa ra phán quyết đồng thuận là có tội.','Phán quyết/Tuyên án',1437,NULL,_binary '\0'),(1536,'Having no legal force; not valid','The contract was declared null and void by the judge.','ADJECTIVE','Không có hiệu lực pháp lý; không còn giá trị','Hợp đồng đã bị thẩm phán tuyên bố vô hiệu.','Vô hiệu/Không có giá trị',1438,NULL,_binary '\0'),(1539,'The settling of a dispute by an impartial third party','The dispute has been referred to arbitration.','NOUN','Việc giải quyết tranh chấp thông qua một bên thứ ba trung lập','Vụ tranh chấp đã được chuyển sang quy trình phân xử bằng trọng tài.','Sự phân xử bằng trọng tài',1441,NULL,_binary '\0'),(1541,'The process of paying to have part of a company’s work done by another company','Many tech companies use outsourcing to reduce labor costs.','NOUN','Việc thuê một đơn vị bên ngoài thực hiện các phần việc của công ty','Nhiều công ty công nghệ sử dụng hình thức thuê ngoài để giảm chi phí nhân công.','Thuê ngoài/Gia công ngoài',1443,NULL,_binary '\0'),(1542,'The process of cultures becoming similar to each other and losing their unique features','Critics of globalisation fear cultural homogenisation caused by Western influence.','NOUN','Quá trình các nền văn hóa trở nên giống nhau và mất đi bản sắc riêng','Những người chỉ trích toàn cầu hóa lo sợ sự đồng nhất hóa văn hóa gây ra bởi ảnh hưởng phương Tây.','Sự đồng nhất hóa văn hóa',1444,NULL,_binary '\0'),(1543,'A large company that has offices or factories in many different countries','Multinational corporations play a key role in the global economy.','NOUN','Công ty quy mô lớn hoạt động tại nhiều quốc gia khác nhau','Các tập đoàn đa quốc gia đóng vai trò then chốt trong nền kinh tế toàn cầu.','Tập đoàn đa quốc gia',1445,NULL,_binary '\0'),(1544,'The process of making objects or activities of the same type have the same features or qualities','Globalisation leads to the standardisation of consumer products worldwide.','NOUN','Làm cho các sản phẩm hoặc hoạt động cùng loại trở nên đồng nhất về chất lượng','Toàn cầu hóa dẫn đến việc tiêu chuẩn hóa các sản phẩm tiêu dùng trên toàn thế giới.','Sự tiêu chuẩn hóa',1446,NULL,_binary '\0'),(1547,'The practice of a company having work done in another country, often because costs are lower there','Offshoring has led to job losses in the domestic manufacturing sector.','NOUN','Việc công ty chuyển các hoạt động sản xuất sang quốc gia khác để tận dụng chi phí thấp','Việc chuyển sản xuất ra nước ngoài đã dẫn đến tình trạng mất việc làm trong ngành sản xuất nội địa.','Chuyển sản xuất ra nước ngoài',1449,NULL,_binary '\0'),(1548,'The process of making something, especially a law or an economic system, less strict','Trade liberalisation has opened up new markets for local exporters.','NOUN','Nới lỏng các quy định, đặc biệt là trong hệ thống kinh tế hoặc luật pháp','Tự do hóa thương mại đã mở ra những thị trường mới cho các nhà xuất khẩu địa phương.','Sự tự do hóa',1450,NULL,_binary '\0'),(1549,'A situation in which people or things depend on each other','The global economy is characterized by increasing interdependence among nations.','NOUN','Mối quan hệ mà các bên cần có nhau để tồn tại hoặc phát triển','Nền kinh tế toàn cầu được đặc trưng bởi sự phụ thuộc lẫn nhau ngày càng tăng giữa các quốc gia.','Sự phụ thuộc lẫn nhau',1451,NULL,_binary '\0'),(1550,'The process of a country adopting the customs and culture of Western Europe and North America','Westernisation is evident in the fashion and music of many Asian cities.','NOUN','Quá trình tiếp nhận văn hóa và phong tục của các nước phương Tây','Sự Tây hóa thể hiện rõ trong thời trang và âm nhạc của nhiều thành phố châu Á.','Sự Tây hóa',1452,NULL,_binary '\0'),(1551,'The principle or practice of protecting a country’s own industry by taxing foreign goods','The government was accused of protectionism for raising tariffs on imported steel.','NOUN','Chính sách bảo vệ sản xuất nội địa bằng cách đánh thuế hàng nhập khẩu','Chính phủ bị cáo buộc theo chủ nghĩa bảo hộ vì tăng thuế đánh vào thép nhập khẩu.','Chủ nghĩa bảo hộ',1453,NULL,_binary '\0'),(1552,'The movement of highly skilled and qualified people to a country where they can work in better conditions','Many developing countries suffer from a brain drain as doctors and engineers move abroad.','NOUN','Sự di cư của những người có trình độ cao sang các nước có điều kiện làm việc tốt hơn','Nhiều nước đang phát triển chịu cảnh chảy máu chất xám khi bác sĩ và kỹ sư ra nước ngoài.','Chảy máu chất xám',1454,NULL,_binary '\0'),(1554,'A situation in which somebody treats somebody else in an unfair way, especially in order to make money from their work','Child labor is a form of exploitation found in some global supply chains.','NOUN','Việc đối xử không công bằng với ai đó để trục lợi từ sức lao động của họ','Lao động trẻ em là một hình thức bóc lột được tìm thấy trong một số chuỗi cung ứng toàn cầu.','Sự bóc lột/khai thác',1456,NULL,_binary '\0'),(1555,'A statement or action which shows that you support or approve of something or somebody','The brand increased its sales significantly after the celebrity endorsement.','NOUN','Việc người nổi tiếng xác nhận chất lượng và khuyên dùng một sản phẩm','Thương hiệu đã tăng doanh số đáng kể sau khi có sự bảo chứng của người nổi tiếng.','Sự bảo chứng',1457,NULL,_binary '\0'),(1556,'The time when the largest number of people are watching TV or listening to the radio','Advertising rates are much higher during prime time.','NOUN','Thời điểm có lượng người xem truyền hình hoặc nghe đài đông nhất','Giá quảng cáo cao hơn nhiều trong khung giờ vàng.','Giờ vàng',1458,NULL,_binary '\0'),(1557,'The use of shocking details to cause a lot of excitement or interest, especially by newspapers and television','The media was accused of sensationalism in its coverage of the scandal.','NOUN','Cách đưa tin phóng đại, gây sốc để thu hút sự chú ý','Truyền thông bị cáo buộc đưa tin giật gân khi đưa tin về vụ bê bối.','Sự giật gân',1459,NULL,_binary '\0'),(1558,'The particular group of people to which an advertisement, a product, a website or a television programme is directed','The target audience for this video game is mainly teenage boys.','NOUN','Nhóm người cụ thể mà một sản phẩm hoặc quảng cáo hướng tới','Khách hàng mục tiêu của trò chơi điện tử này chủ yếu là nam thiếu niên.','Khách hàng mục tiêu',1460,NULL,_binary '\0'),(1559,'Affecting your mind even though you are not aware of it','Some people believe that subliminal messages in ads can influence our buying habits.','ADJECTIVE','Tác động đến tâm trí một cách kín đáo mà người đó không nhận ra','Một số người tin rằng các thông điệp ẩn trong quảng cáo có thể ảnh hưởng đến thói quen mua hàng.','Thuộc về tiềm thức',1461,NULL,_binary '\0'),(1560,'The total number of copies of a newspaper or magazine that are sold each day, week, etc.','The newspaper has a daily circulation of more than 200,000 copies.','NOUN','Tổng số bản báo hoặc tạp chí được bán ra trong một kỳ','Tờ báo có lượng phát hành hàng ngày hơn 200.000 bản.','Số lượng phát hành',1462,NULL,_binary '\0'),(1561,'A large board on the outside of a building or at the side of the road, used for putting advertisements on','The new movie is being advertised on billboards all over the city.','NOUN','Bảng quảng cáo kích thước lớn đặt ở ven đường hoặc trên tòa nhà','Bộ phim mới đang được quảng cáo trên các biển hiệu khắp thành phố.','Biển quảng cáo ngoài trời',1463,NULL,_binary '\0'),(1563,'An official statement made to journalists by a large organization, a political party, or a government department','The company issued a press release to announce the launch of its new product.','NOUN','Văn bản chính thức gửi tới giới truyền thông để công bố thông tin','Công ty đã phát đi một thông cáo báo chí để công bố việc ra mắt sản phẩm mới.','Thông cáo báo chí',1465,NULL,_binary '\0'),(1564,'Spread by people telling each other','The restaurant relies on word-of-mouth advertising rather than expensive ads.','ADJECTIVE','Hình thức quảng cáo thông qua việc mọi người tự kể cho nhau nghe','Nhà hàng dựa vào quảng cáo truyền miệng hơn là các quảng cáo đắt tiền.','Truyền miệng',1466,NULL,_binary '\0'),(1566,'The attention that is given to somebody/something by newspapers, television, etc.','The trial attracted a lot of bad publicity for the company.','NOUN','Sự quan tâm mà dư luận hoặc truyền thông dành cho một đối tượng','Phiên tòa đã thu hút nhiều sự chú ý tiêu cực cho công ty.','Sự quảng bá/Sự chú ý',1468,NULL,_binary '\0'),(1567,'A short, easily remembered phrase used an advertisement','Their advertising slogan is one of the most famous in the world.','NOUN','Cụm từ ngắn gọn, dễ nhớ dùng trong quảng cáo','Khẩu hiệu quảng cáo của họ là một trong những khẩu hiệu nổi tiếng nhất thế giới.','Khẩu hiệu/Slogan',1469,NULL,_binary '\0'),(1568,'A long television advertisement that provides a lot of information and seems like a normal programme','I stayed up late and watched a long infomercial about kitchen appliances.','NOUN','Đoạn quảng cáo dài cung cấp nhiều thông tin, trông giống một chương trình truyền hình','Tôi đã thức muộn và xem một đoạn quảng cáo dài về thiết bị nhà bếp.','Quảng cáo truyền hình dài',1470,NULL,_binary '\0'),(1569,'Sources of information and news such as newspapers, magazines, radio and television, that reach and influence large numbers of people','The mass media has a huge influence on public opinion.','NOUN','Các kênh thông tin như báo, đài, tivi có sức lan tỏa tới lượng lớn công chúng','Truyền thông đại chúng có ảnh hưởng khổng lồ đến dư luận.','Truyền thông đại chúng',1471,NULL,_binary '\0'),(1571,'A place to live, work or stay in','The price of the tour includes flights and hotel accommodation.','NOUN','Nơi dừng chân nghỉ ngơi như khách sạn, nhà nghỉ, căn hộ','Giá của tour du lịch đã bao gồm vé máy bay và chỗ ở tại khách sạn.','Chỗ ở/Nơi lưu trú',1473,NULL,_binary '\0'),(1574,'The business of organizing holidays to natural areas, especially areas that are far away, in a way that helps the local people and does not damage the environment','Ecotourism is becoming more popular as people become more aware of environmental issues.','NOUN','Hình thức du lịch đến các vùng tự nhiên mà không gây hại đến môi trường','Du lịch sinh thái đang trở nên phổ biến hơn khi mọi người nhận thức rõ hơn về các vấn đề môi trường.','Du lịch sinh thái',1477,NULL,_binary '\0'),(1575,'In a place where few people go, far from main roads or towns','We prefer to go to places that are off the beaten track.','IDIOM','Ở những nơi xa xôi, hẻo lánh, chưa được nhiều du khách khai phá','Chúng tôi thích đi đến những nơi ít người biết đến hơn.','Nơi ít người biết đến',1478,NULL,_binary '\0'),(1578,'A journey to a place and back again','A round-trip ticket is often cheaper than two one-way tickets.','ADJECTIVE','Chuyến đi bao gồm cả lượt đi và lượt về','Một chiếc vé khứ hồi thường rẻ hơn hai chiếc vé một chiều.','Khứ hồi',1481,NULL,_binary '\0'),(1579,'Friendly and generous behaviour towards guests','We were amazed by the hospitality of the local people.','NOUN','Sự tiếp đãi thân thiện và hào phóng đối với khách khứa','Chúng tôi đã rất ngạc nhiên bởi lòng hiếu khách của người dân địa phương.','Lòng hiếu khách',1482,NULL,_binary '\0'),(1581,'Including everything','We booked an all-inclusive holiday in Greece.','ADJECTIVE','Bao gồm tất cả các dịch vụ (ăn uống, ở, đi lại) trong một mức giá','Chúng tôi đã đặt một kỳ nghỉ trọn gói ở Hy Lạp.','Trọn gói',1484,NULL,_binary '\0'),(1583,'The feeling of being tired and confused after a long plane journey because of the difference in time','I am still suffering from jet lag after my flight from New York.','NOUN','Cảm giác mệt mỏi, rối loạn nhịp sinh học sau một chuyến bay dài xuyên qua nhiều múi giờ','Tôi vẫn đang bị mệt mỏi do lệch múi giờ sau chuyến bay từ New York.','Mệt mỏi do lệch múi giờ',1486,NULL,_binary '\0'),(1584,'A long and distinct period of history with a particular feature or characteristic','The death of the king marked the end of an era.','NOUN','Một giai đoạn lịch sử dài và khác biệt với những đặc điểm riêng','Cái chết của vị vua đã đánh dấu sự kết thúc của một thời đại.','Kỷ nguyên/Thời đại',1487,NULL,_binary '\0'),(1585,'A person in your family who lived a long time ago','His ancestors came from Scotland in the 19th century.','NOUN','Người trong gia đình đã sống từ rất lâu đời trước đó','Tổ tiên của ông ấy đến từ Scotland vào thế kỷ 19.','Tổ tiên',1488,NULL,_binary '\0'),(1586,'The ancient past, especially the period of classical and other human civilizations before the Middle Ages','Many beautiful statues have survived from antiquity.','NOUN','Giai đoạn lịch sử xa xưa, đặc biệt là trước thời Trung cổ','Nhiều bức tượng đẹp từ thời cổ đại vẫn còn tồn tại đến nay.','Thời cổ đại',1489,NULL,_binary '\0'),(1588,'Arranged in the order in which they happened','The facts should be presented in chronological order.','ADJECTIVE','Được sắp xếp theo trình tự các sự kiện đã xảy ra','Các sự thật nên được trình bày theo thứ tự thời gian.','Theo thứ tự thời gian',1491,NULL,_binary '\0'),(1589,'The act of taking control of an area or a country that is not your own, especially using force','The colonization of the Americas changed the world forever.','NOUN','Hành động kiểm soát một khu vực hoặc quốc gia khác, thường bằng vũ lực','Sự thực dân hóa châu Mỹ đã thay đổi thế giới mãi mãi.','Sự thực dân hóa',1492,NULL,_binary '\0'),(1590,'Something that is part of your history or that remains from an earlier time','The war left a legacy of hatred and fear.','NOUN','Những gì còn sót lại hoặc được truyền lại từ một thời kỳ trước đó','Cuộc chiến đã để lại một hệ quả của lòng thù hận và sợ hãi.','Di sản/Hệ quả',1493,NULL,_binary '\0'),(1592,'Connected with the time in history before information was written down','Paintings of animals have been found on the walls of prehistoric caves.','ADJECTIVE','Thuộc về thời kỳ lịch sử trước khi con người biết chữ viết','Những bức vẽ động vật đã được tìm thấy trên tường của các hang động tiền sử.','Tiền sử',1495,NULL,_binary '\0'),(1593,'Belonging to a very early stage in the development of normal people or animals','Primitive man used stone tools for hunting.','ADJECTIVE','Thuộc về giai đoạn phát triển rất sớm, còn thô sơ','Người nguyên thủy sử dụng công cụ bằng đá để săn bắn.','Nguyên thủy/Sơ khai',1496,NULL,_binary '\0'),(1594,'An object, a tradition, a system, etc. that has survived from the past','The ship is a relic of the Spanish Armada.','NOUN','Một vật thể hoặc truyền thống còn sót lại từ quá khứ','Con tàu là một di vật còn sót lại của hạm đội Tây Ban Nha.','Di vật/Tàn tích',1497,NULL,_binary '\0'),(1595,'The period in Europe during the 14th, 15th and 16th centuries when there was a new interest in art, literature and science','The Renaissance was a time of great artistic achievement.','NOUN','Giai đoạn từ thế kỷ 14 đến 16 tại châu Âu với sự bùng nổ về nghệ thuật và khoa học','Phục hưng là thời đại của những thành tựu nghệ thuật vĩ đại.','Thời kỳ Phục hưng',1498,NULL,_binary '\0'),(1596,'Free to govern itself; having complete power','The country became a sovereign state in 1945.','ADJECTIVE','Tự do cai trị, không bị lệ thuộc vào quốc gia khác','Quốc gia này đã trở thành một nhà nước có chủ quyền vào năm 1945.','Có chủ quyền',1499,NULL,_binary '\0'),(1597,'The right to take an official position or title, especially that of a king or queen','The question of the succession to the throne was finally settled.','NOUN','Quyền được tiếp nhận tước vị hoặc vị trí chính thức (thường là ngai vàng)','Vấn đề kế vị ngai vàng cuối cùng đã được giải quyết.','Sự kế vị',1500,NULL,_binary '\0'),(1598,'To find something in the ground by digging; to discover something that was hidden','Archaeologists have unearthed a large number of ancient coins.','VERB','Tìm thấy thứ gì đó dưới lòng đất hoặc khám phá ra điều gì đó bị che giấu','Các nhà khảo cổ học đã khai quật được một số lượng lớn đồng tiền cổ.','Khai quật/Tìm ra',1501,NULL,_binary '\0'),(1601,'A computer system designed to mimic the way the human brain learns and processes information.','Deep learning models are built upon complex artificial neural networks.','NOUN','Hệ thống máy tính được thiết kế để mô phỏng cách não người học và xử lý thông tin.','Các mô hình học sâu được xây dựng trên các mạng nơ-ron nhân tạo phức tạp.','Mạng nơ-ron',1504,NULL,_binary '\0'),(1602,'A collection of related sets of information that is composed of separate elements but can be manipulated as a unit by a computer.','The researchers used a massive dataset to train the facial recognition system.','NOUN','Một bộ sưu tập các thông tin liên quan có thể được xử lý như một đơn vị bởi máy tính.','Các nhà nghiên cứu đã sử dụng một tập dữ liệu khổng lồ để huấn luyện hệ thống nhận diện khuôn mặt.','Tập dữ liệu',1505,NULL,_binary '\0'),(1603,'A method of learning or solving problems that allows people to discover things themselves and learn from their own experiences.','The algorithm uses a heuristic approach to find an approximate solution quickly.','ADJECTIVE','Một phương pháp học tập hoặc giải quyết vấn đề bằng cách tự khám phá và rút kinh nghiệm.','Thuật toán sử dụng phương pháp phỏng đoán để tìm ra giải pháp gần đúng một cách nhanh chóng.','Phỏng đoán/Kinh nghiệm',1506,NULL,_binary '\0'),(1604,'The process of drawing a conclusion from evidence and reasoning.','In AI, inference is the process of a trained model making predictions on new data.','NOUN','Quá trình đưa ra kết luận từ bằng chứng và lập luận.','Trong AI, suy luận là quá trình mô hình đã huấn luyện đưa ra dự đoán trên dữ liệu mới.','Sự suy luận',1507,NULL,_binary '\0'),(1605,'The production of an analysis that corresponds too closely or exactly to a particular set of data, and may therefore fail to fit additional data.','The model suffered from overfitting and performed poorly in real-world tests.','NOUN','Việc phân tích dữ liệu quá sát với tập dữ liệu mẫu dẫn đến việc dự đoán sai trên dữ liệu mới.','Mô hình gặp tình trạng quá khớp và hoạt động kém trong các thử nghiệm thực tế.','Sự quá khớp',1508,NULL,_binary '\0'),(1606,'A statistical method used in finance, investing, and other disciplines that attempts to determine the strength and character of the relationship between one dependent variable and a series of other variables.','Linear regression is a fundamental technique in predictive modeling.','NOUN','Phương pháp thống kê xác định mối quan hệ giữa biến phụ thuộc và các biến độc lập.','Hồi quy tuyến tính là một kỹ thuật cơ bản trong mô hình hóa dự đoán.','Hồi quy',1509,NULL,_binary '\0'),(1607,'A type of machine learning where the model is trained on a labeled dataset.','Most image recognition tasks use supervised learning with human-labeled photos.','NOUN','Một loại học máy trong đó mô hình được huấn luyện trên tập dữ liệu đã được gán nhãn.','Hầu hết các nhiệm vụ nhận diện hình ảnh đều sử dụng học có giám sát với ảnh được gán nhãn bởi con người.','Học có giám sát',1510,NULL,_binary '\0'),(1608,'A type of machine learning that looks for previously unknown patterns in a dataset without pre-existing labels.','Clustering customers based on purchase behavior is a classic example of unsupervised learning.','NOUN','Một loại học máy tìm kiếm các mẫu chưa biết trong tập dữ liệu mà không cần nhãn có sẵn.','Phân nhóm khách hàng dựa trên hành vi mua sắm là một ví dụ điển hình của học không giám sát.','Học không giám sát',1511,NULL,_binary '\0'),(1609,'The ability of a computer program to understand human language as it is spoken and written.','Chatbots use natural language processing to interact with users.','NOUN','Khả năng của chương trình máy tính hiểu ngôn ngữ con người ở dạng nói và viết.','Robot trò chuyện sử dụng xử lý ngôn ngữ tự nhiên để tương tác với người dùng.','Xử lý ngôn ngữ tự nhiên',1512,NULL,_binary '\0'),(1610,'A field of AI that enables computers and systems to derive meaningful information from digital images and videos.','Self-driving cars rely on computer vision to identify traffic signs and pedestrians.','NOUN','Lĩnh vực AI cho phép máy tính trích xuất thông tin có ý nghĩa từ hình ảnh và video kỹ thuật số.','Xe tự lái dựa vào thị giác máy tính để nhận diện biển báo giao thông và người đi bộ.','Thị giác máy tính',1513,NULL,_binary '\0'),(1611,'A subfield of machine learning based on artificial neural networks with multiple layers.','Deep learning has revolutionized the field of speech recognition.','NOUN','Một lĩnh vực con của học máy dựa trên các mạng nơ-ron nhân tạo có nhiều lớp.','Học sâu đã cách mạng hóa lĩnh vực nhận dạng giọng nói.','Học sâu',1514,NULL,_binary '\0'),(1612,'A method used in artificial neural networks to calculate a gradient that is needed in the calculation of the weights to be used in the network.','Backpropagation is the key algorithm for training deep neural networks.','NOUN','Phương pháp trong mạng nơ-ron để tính toán độ dốc cần thiết nhằm cập nhật trọng số.','Lan truyền ngược là thuật toán then chốt để huấn luyện các mạng nơ-ron sâu.','Lan truyền ngược',1515,NULL,_binary '\0'),(1613,'A systematic error in a sampling or analytical process that leads to incorrect results.','The dataset contained a significant bias toward one specific demographic.','NOUN','Một sai số có hệ thống trong quá trình lấy mẫu hoặc phân tích dẫn đến kết quả sai.','Tập dữ liệu chứa một độ chệch đáng kể thiên về một nhóm nhân khẩu học cụ thể.','Độ chệch',1516,NULL,_binary '\0'),(1614,'The action of supporting or opposing a particular person or thing in an unfair way.','It is important to eliminate human bias when designing hiring algorithms.','NOUN','Hành động ủng hộ hoặc phản đối một người hoặc sự vật một cách không công bằng.','Việc loại bỏ thành kiến của con người khi thiết kế các thuật toán tuyển dụng là rất quan trọng.','Thành kiến',1516,NULL,_binary '\0'),(1615,'Positioned in or relating to the sky, or outer space as observed in astronomy.','The sun, moon, and stars are celestial bodies.','ADJECTIVE','Nằm ở hoặc liên quan đến bầu trời, hoặc không gian bên ngoài được quan sát trong thiên văn học.','Mặt trời, mặt trăng và các ngôi sao là những thiên thể.','Thuộc về thiên thể',1517,NULL,_binary '\0'),(1616,'the curved path through which objects in space move','The Earth moves in an orbit around the Sun.','NOUN','Đường cong mà các vật thể trong không gian di chuyển theo','Trái Đất chuyển động theo quỹ đạo quanh Mặt Trời.','Quỹ đạo',1518,NULL,_binary '\0'),(1617,'A planet that orbits a star outside the solar system.','Astronomers have discovered thousands of exoplanets in the Milky Way.','NOUN','Một hành tinh quay quanh một ngôi sao nằm ngoài hệ mặt trời của chúng ta.','Các nhà thiên văn học đã phát hiện hàng ngàn hành tinh ngoài hệ mặt trời trong dải Ngân hà.','Hành tinh ngoài hệ mặt trời',1519,NULL,_binary '\0'),(1618,'A star that suddenly increases greatly in brightness because of a catastrophic explosion that ejects most of its mass.','A supernova can briefly outshine an entire galaxy.','NOUN','Một ngôi sao đột ngột tăng mạnh độ sáng do một vụ nổ thảm khốc đẩy hầu hết khối lượng của nó ra ngoài.','Một siêu tân tinh có thể tỏa sáng rực rỡ hơn cả một thiên hà trong thời gian ngắn.','Siêu tân tinh',1520,NULL,_binary '\0'),(1619,'A cloud of gas and dust in outer space, visible in the night sky as a bright patch or as a dark silhouette.','The Orion Nebula is one of the brightest nebulae visible to the naked eye.','NOUN','Một đám mây khí và bụi trong không gian vũ trụ, có thể nhìn thấy như một vùng sáng hoặc bóng đen.','Tinh vân Orion là một trong những tinh vân sáng nhất có thể nhìn thấy bằng mắt thường.','Tinh vân',1521,NULL,_binary '\0'),(1620,'A region of space having a gravitational field so intense that no matter or radiation can escape.','Nothing, not even light, can escape the pull of a black hole.','NOUN','Một vùng không gian có trường hấp dẫn mạnh đến mức không vật chất hay bức xạ nào có thể thoát ra.','Không gì, kể cả ánh sáng, có thể thoát khỏi lực hút của hố đen.','Hố đen',1522,NULL,_binary '\0'),(1621,'The distance that light travels in one year, about 9.46 trillion kilometers.','Proxima Centauri is about 4.2 light-years away from Earth.','NOUN','Khoảng cách mà ánh sáng đi được trong một năm, khoảng 9,46 nghìn tỷ km.','Proxima Centauri cách Trái đất khoảng 4,2 năm ánh sáng.','Năm ánh sáng',1523,NULL,_binary '\0'),(1622,'A group of stars forming a recognizable pattern that is traditionally named after its apparent form.','Orion is one of the most easily recognized constellations.','NOUN','Một nhóm các ngôi sao tạo thành một hình mẫu có thể nhận biết, thường được đặt tên theo hình dạng của nó.','Orion là một trong những chòm sao dễ nhận diện nhất.','Chòm sao',1524,NULL,_binary '\0'),(1623,'The study of the origin, evolution, and eventual fate of the universe.','Modern cosmology is based heavily on the Big Bang theory.','NOUN','Nghiên cứu về nguồn gốc, sự tiến hóa và số phận cuối cùng của vũ trụ.','Vũ trụ học hiện đại dựa trên lý thuyết Big Bang.','Vũ trụ học',1525,NULL,_binary '\0'),(1624,'The branch of astronomy concerned with the physical nature of stars and other celestial bodies.','She decided to pursue a degree in astrophysics to study dark matter.','NOUN','Nhánh thiên văn học liên quan đến bản chất vật lý của các ngôi sao và các thiên thể khác.','Cô ấy quyết định theo đuổi bằng vật lý thiên văn để nghiên cứu vật chất tối.','Vật lý thiên văn',1526,NULL,_binary '\0'),(1625,'Occurring or situated between stars.','Voyager 1 is the first spacecraft to enter interstellar space.','ADJECTIVE','Xảy ra hoặc nằm ở giữa các ngôi sao.','Voyager 1 là tàu vũ trụ đầu tiên đi vào không gian giữa các vì sao.','Giữa các vì sao',1527,NULL,_binary '\0'),(1626,'Relating to the force that attracts a body toward the center of the earth, or toward any other physical body having mass.','The moon’s gravitational pull causes the tides on Earth.','ADJECTIVE','Liên quan đến lực hút một vật thể về phía tâm trái đất, hoặc về phía bất kỳ vật thể nào khác có khối lượng.','Lực hút trọng lực của mặt trăng gây ra thủy triều trên Trái đất.','Thuộc trọng lực',1528,NULL,_binary '\0'),(1627,'An artificial body placed in orbit around the earth or moon or another planet in order to collect information or for communication.','The satellite transmits weather data back to Earth.','NOUN','Một vật thể nhân tạo được đặt vào quỹ đạo quanh trái đất hoặc mặt trăng để thu thập thông tin hoặc viễn thông.','Vệ tinh truyền dữ liệu thời tiết trở lại Trái đất.','Vệ tinh',1529,NULL,_binary '\0'),(1628,'An obscurement of the light from one celestial body by the passage of another between it and the observer or between it and its source of illumination.','A total solar eclipse is a rare and spectacular event.','NOUN','Sự che khuất ánh sáng từ một thiên thể do một thiên thể khác đi qua giữa nó và người quan sát.','Nhật thực toàn phần là một sự kiện hiếm gặp và ngoạn mục.','Nhật thực/Nguyệt thực',1530,NULL,_binary '\0'),(1629,'The branch of technology and industry concerned with both aviation and space flight.','He works for a major aerospace company in Europe.','NOUN','Nhánh công nghệ và công nghiệp liên quan đến cả hàng không và chuyến bay vào không gian.','Anh ấy làm việc cho một công ty hàng không vũ trụ lớn ở Châu Âu.','Hàng không vũ trụ',1531,NULL,_binary '\0'),(1630,'The process of converting information or data into a code, especially to prevent unauthorized access.','Data encryption is vital for protecting sensitive information online.','NOUN','Quá trình chuyển đổi thông tin hoặc dữ liệu thành mã, đặc biệt là để ngăn chặn truy cập trái phép.','Mã hóa dữ liệu là tối quan trọng để bảo vệ thông tin nhạy cảm trực tuyến.','Sự mã hóa',1532,NULL,_binary '\0'),(1631,'A flaw or weakness in a system\'s design, implementation, or operation that could be exploited.','The software update fixes a major security vulnerability.','NOUN','Một khiếm khuyết hoặc điểm yếu trong thiết kế, triển khai hoặc vận hành hệ thống có thể bị khai thác.','Bản cập nhật phần mềm khắc phục một lỗ hổng bảo mật nghiêm trọng.','Lỗ hổng bảo mật',1533,NULL,_binary '\0'),(1632,'The process or action of verifying the identity of a user or process.','Two-factor authentication adds an extra layer of security to your account.','NOUN','Quá trình hoặc hành động xác minh danh tính của người dùng hoặc quy trình.','Xác thực hai yếu tố thêm một lớp bảo mật bổ sung cho tài khoản của bạn.','Sự xác thực',1534,NULL,_binary '\0'),(1633,'The process of giving someone permission to do or have something.','You need specific authorization to access these confidential files.','NOUN','Quá trình cấp phép cho ai đó làm hoặc sở hữu cái gì đó.','Bạn cần sự cấp quyền cụ thể để truy cập các tệp bảo mật này.','Sự cấp quyền',1535,NULL,_binary '\0'),(1634,'The fraudulent practice of sending emails purporting to be from reputable companies to induce individuals to reveal personal information.','Many people fall victim to phishing scams every year.','NOUN','Hành vi gian lận gửi email giả danh các công ty uy tín để dụ cá nhân tiết lộ thông tin cá nhân.','Nhiều người trở thành nạn nhân của các vụ lừa đảo giả mạo mỗi năm.','Tấn công giả mạo',1536,NULL,_binary '\0'),(1635,'Software that is specifically designed to disrupt, damage, or gain unauthorized access to a computer system.','The system was infected with malware through a suspicious download.','NOUN','Phần mềm được thiết kế đặc biệt để phá hoại, gây hỏng hoặc truy cập trái phép vào hệ thống máy tính.','Hệ thống bị nhiễm phần mềm độc hại thông qua một bản tải xuống đáng ngờ.','Phần mềm độc hại',1537,NULL,_binary '\0'),(1636,'A part of a computer system or network that is designed to block unauthorized access while permitting outward communication.','The company installed a strict firewall to protect its internal network.','NOUN','Một phần của hệ thống máy tính hoặc mạng được thiết kế để chặn truy cập trái phép trong khi vẫn cho phép giao tiếp ra ngoài.','Công ty đã cài đặt một tường lửa nghiêm ngặt để bảo vệ mạng nội bộ.','Tường lửa',1538,NULL,_binary '\0'),(1637,'The art of writing or solving codes.','Modern cryptography is essential for secure online transactions.','NOUN','Nghệ thuật viết hoặc giải các mã số.','Mật mã học hiện đại là thiết yếu cho các giao dịch trực tuyến an toàn.','Mật mã học',1539,NULL,_binary '\0'),(1639,'A type of malicious software designed to block access to a computer system until a sum of money is paid.','The hospital’s systems were held hostage by a ransomware attack.','NOUN','Một loại phần mềm độc hại được thiết kế để chặn quyền truy cập vào hệ thống máy tính cho đến khi một khoản tiền được thanh toán.','Hệ thống của bệnh viện đã bị khống chế bởi một cuộc tấn công mã độc tống tiền.','Mã độc tống tiền',1541,NULL,_binary '\0'),(1641,'The state of being whole and undivided; in computing, ensuring data has not been altered.','We must ensure the integrity of the database during the migration.','NOUN','Trạng thái nguyên vẹn; trong tin học, là việc đảm bảo dữ liệu không bị thay đổi trái phép.','Chúng ta phải đảm bảo tính toàn vẹn của cơ sở dữ liệu trong quá trình di chuyển.','Tính toàn vẹn',1543,NULL,_binary '\0'),(1642,'The state of keeping or being kept secret or private.','All employees must sign a confidentiality agreement.','NOUN','Trạng thái giữ bí mật hoặc được giữ riêng tư.','Tất cả nhân viên phải ký một thỏa thuận bảo mật.','Tính bảo mật',1544,NULL,_binary '\0'),(1643,'The process of removing personally identifiable information from data sets.','Data anonymization allows researchers to use records without violating privacy.','NOUN','Quá trình xóa bỏ thông tin nhận dạng cá nhân khỏi các tập dữ liệu.','Ẩn danh hóa dữ liệu cho phép các nhà nghiên cứu sử dụng hồ sơ mà không vi phạm quyền riêng tư.','Sự ẩn danh hóa',1545,NULL,_binary '\0'),(1644,'The process of taking encoded or encrypted text and converting it back into text that you or the computer can read.','The recipient needs a private key for the decryption of the message.','NOUN','Quá trình lấy văn bản đã được mã hóa và chuyển đổi nó trở lại thành văn bản mà bạn hoặc máy tính có thể đọc được.','Người nhận cần một khóa riêng tư để giải mã tin nhắn.','Sự giải mã',1546,NULL,_binary '\0'),(1645,'A component of a machine that is responsible for moving and controlling a mechanism or system.','The robot’s arm is moved by a series of electric actuators.','NOUN','Một bộ phận của máy móc chịu trách nhiệm di chuyển và điều khiển một cơ cấu hoặc hệ thống.','Cánh tay robot được di chuyển bởi một loạt các bộ truyền động điện.','Bộ truyền động',1547,NULL,_binary '\0'),(1646,'The branch of mechanics concerned with the motion of objects without reference to the forces which cause the motion.','Engineers must calculate the kinematics of the robotic joints precisely.','NOUN','Nhánh cơ học liên quan đến chuyển động của các vật thể mà không xét đến các lực gây ra chuyển động đó.','Các kỹ sư phải tính toán chính xác động học của các khớp nối robot.','Động học',1548,NULL,_binary '\0'),(1647,'A device which detects or measures a physical property and records, indicates, or otherwise responds to it.','The robot uses ultrasonic sensors to avoid obstacles.','NOUN','Một thiết bị phát hiện hoặc đo lường một đặc tính vật lý và ghi lại, chỉ thị hoặc phản hồi lại nó.','Robot sử dụng cảm biến siêu âm để tránh vật cản.','Cảm biến',1549,NULL,_binary '\0'),(1648,'A device used to handle or consume materials without direct human contact; the \"arm\" of a robot.','The mechanical manipulator can pick up heavy parts with high precision.','NOUN','Thiết bị dùng để xử lý vật liệu mà không cần tiếp xúc trực tiếp với người; \"cánh tay\" của robot.','Tay máy cơ khí có thể gắp các bộ phận nặng với độ chính xác cao.','Tay máy',1550,NULL,_binary '\0'),(1649,'e.g., a gripper or tool','The robot uses an end-effector such as a gripper or tool.','NOUN','Ví dụ: bộ kẹp hoặc dụng cụ','Robot sử dụng cơ cấu chấp hành cuối như bộ kẹp hoặc dụng cụ.','Cơ cấu chấp hành cuối',1551,NULL,_binary '\0'),(1650,'The science of communications and automatic control systems in both machines and living things.','Early research in cybernetics laid the foundation for modern robotics.','NOUN','Khoa học về thông tin liên lạc và hệ thống điều khiển tự động ở cả máy móc và sinh vật sống.','Các nghiên cứu ban đầu về điều khiển học đã đặt nền móng cho robot hiện đại.','Điều khiển học',1552,NULL,_binary '\0'),(1651,'Acting independently or having the freedom to do so; not controlled by others.','Autonomous robots are used to explore dangerous environments like deep oceans.','ADJECTIVE','Hoạt động độc lập hoặc có quyền tự do thực hiện; không bị kiểm soát bởi người khác.','Robot tự hành được sử dụng để khám phá các môi trường nguy hiểm như đại dương sâu.','Tự hành / Tự chủ',1553,NULL,_binary '\0'),(1652,'The operation of a system or machine at a distance.','Teleoperation allows surgeons to perform operations from a different city.','NOUN','Việc vận hành một hệ thống hoặc máy móc từ một khoảng cách xa.','Điều khiển từ xa cho phép các bác sĩ phẫu thuật thực hiện ca mổ từ một thành phố khác.','Điều khiển từ xa',1554,NULL,_binary '\0'),(1653,'The science and technology of transmitting and understanding information through the sense of touch.','Haptics technology provides tactile feedback to the robot operator.','NOUN','Khoa học và công nghệ truyền tải và hiểu thông tin thông qua cảm giác chạm.','Công nghệ xúc giác cung cấp phản hồi xúc giác cho người vận hành robot.','Công nghệ xúc giác',1555,NULL,_binary '\0'),(1654,'An automatic device that uses error-sensing negative feedback to correct the performance of a mechanism.','Precision movements in CNC machines are controlled by servomechanisms.','NOUN','Một thiết bị tự động sử dụng phản hồi để điều chỉnh hiệu suất của một cơ cấu.','Các chuyển động chính xác trong máy CNC được điều khiển bởi các cơ cấu tùy động.','Cơ cấu tùy động (Servo)',1556,NULL,_binary '\0'),(1655,'The process of adjusting an instrument or device so that it can be used in an accurate and reliable way.','Regular calibration of the robotic sensors is necessary to maintain accuracy.','NOUN','Quá trình điều chỉnh một dụng cụ hoặc thiết bị để nó có thể được sử dụng một cách chính xác và tin cậy.','Hiệu chuẩn thường xuyên các cảm biến robot là cần thiết để duy trì độ chính xác.','Sự hiệu chuẩn',1557,NULL,_binary '\0'),(1656,'The capacity to be changed in size or scale.','The modular design of the system ensures high scalability.','NOUN','Khả năng thay đổi về kích thước hoặc quy mô.','Thiết kế mô-đun của hệ thống đảm bảo khả năng mở rộng cao.','Khả năng mở rộng',1558,NULL,_binary '\0'),(1657,'Nearness in space, time, or relationship.','Proximity sensors detect the presence of nearby objects without physical contact.','NOUN','Sự gần nhau về không gian, thời gian hoặc mối quan hệ.','Cảm biến tiệm cận phát hiện sự hiện diện của các vật thể gần đó mà không cần tiếp xúc vật lý.','Sự gần gũi / Khoảng cách gần',1559,NULL,_binary '\0'),(1658,'The amount of material or items passing through a system or process.','Automation can significantly increase the throughput of the factory.','NOUN','Lượng vật liệu hoặc vật phẩm đi qua một hệ thống hoặc quy trình.','Tự động hóa có thể tăng đáng kể năng suất của nhà máy.','Năng suất / Lưu lượng',1560,NULL,_binary '\0'),(1659,'The combination of mechanical engineering, computing, and electronics as used in the design and manufacture of intelligent products.','Mechatronics is a key field for students interested in robotics.','NOUN','Sự kết hợp giữa kỹ thuật cơ khí, máy tính và điện tử trong thiết kế và sản xuất các sản phẩm thông minh.','Cơ điện tử là lĩnh vực then chốt cho sinh viên yêu thích robot.','Cơ điện tử',1561,NULL,_binary '\0'),(1660,'The complete set of genetic material of a living thing.','Scientists have finally mapped the entire human genome.','NOUN','Toàn bộ vật chất di truyền của một sinh vật.','Các nhà khoa học cuối cùng đã lập bản đồ toàn bộ bộ gen người.','Bộ gen',1562,NULL,_binary '\0'),(1661,'Relating to DNA that has been formed artificially by combining constituents from different organisms.','Recombinant DNA technology is used to produce human insulin.','ADJECTIVE','Liên quan đến DNA được hình thành nhân tạo bằng cách kết hợp các thành phần từ các sinh vật khác nhau.','Công nghệ DNA tái tổ hợp được sử dụng để sản xuất insulin cho người.','Tái tổ hợp',1563,NULL,_binary '\0'),(1662,'A technology that can be used to edit genes; a way of finding a specific bit of DNA inside a cell.','CRISPR allows for precise changes to be made to the DNA of living organisms.','NOUN','Một công nghệ dùng để chỉnh sửa gen; một cách tìm kiếm một đoạn DNA cụ thể bên trong tế bào.','CRISPR cho phép thực hiện các thay đổi chính xác đối với DNA của sinh vật sống.','Công nghệ chỉnh sửa gen CRISPR',1564,NULL,_binary '\0'),(1663,'To identify the order of the genetic information in a DNA molecule.','It used to take years to sequence a single gene.','VERB','Xác định thứ tự của thông tin di truyền trong một phân tử DNA.','Trước đây phải mất nhiều năm để giải trình tự một gen duy nhất.','Giải trình tự',1565,NULL,_binary '\0'),(1664,'A permanent change in the genetic material of an organism.','The disease is caused by a genetic mutation.','NOUN','Sự thay đổi vĩnh viễn trong vật chất di truyền của một sinh vật.','Căn bệnh này được gây ra bởi một sự đột biến di truyền.','Sự đột biến',1566,NULL,_binary '\0'),(1665,'The process of creating an exact genetic copy of a cell, tissue, or organism.','Ethical debates surround the cloning of complex animals.','NOUN','Quá trình tạo ra một bản sao di truyền chính xác của một tế bào, mô hoặc sinh vật.','Các cuộc tranh luận về đạo đức xoay quanh việc nhân bản vô tính các động vật phức tạp.','Nhân bản vô tính',1567,NULL,_binary '\0'),(1666,'A bacterium, virus, or other microorganism that can cause disease.','Biotechnology helps in creating vaccines against dangerous pathogens.','NOUN','Vi khuẩn, virus hoặc vi sinh vật khác có thể gây bệnh.','Công nghệ sinh học giúp tạo ra vaccine chống lại các mầm bệnh nguy hiểm.','Mầm bệnh',1568,NULL,_binary '\0'),(1667,'The process of an animal or plant breeding with an individual of another species or variety.','The hybridization of corn has led to much higher yields.','NOUN','Quá trình động vật hoặc thực vật giao phối với một cá thể thuộc loài hoặc giống khác.','Việc lai tạo ngô đã dẫn đến năng suất cao hơn nhiều.','Sự lai tạo',1569,NULL,_binary '\0'),(1668,'The use of either naturally occurring or deliberately introduced microorganisms to consume and break down environmental pollutants.','Bioremediation is being used to clean up oil spills in the ocean.','NOUN','Việc sử dụng vi sinh vật để tiêu thụ và phân hủy các chất gây ô nhiễm môi trường.','Xử lý sinh học đang được sử dụng để làm sạch các vụ tràn dầu trên đại dương.','Xử lý sinh học',1570,NULL,_binary '\0'),(1669,'Relating to an organism that contains genetic material into which DNA from an unrelated organism has been artificially introduced.','Transgenic crops are often resistant to certain pests.','ADJECTIVE','Liên quan đến sinh vật có chứa vật chất di truyền mà DNA từ một sinh vật không liên quan đã được đưa vào nhân tạo.','Cây trồng chuyển gen thường có khả năng chống lại một số loại sâu bệnh.','Chuyển gen',1571,NULL,_binary '\0'),(1670,'A chemical process by which molecules such as glucose are broken down anaerobically.','Fermentation is a key process in the production of yogurt and bread.','NOUN','Quá trình hóa học trong đó các phân tử như glucose bị phân hủy kỵ khí.','Lên men là quá trình then chốt trong sản xuất sữa chua và bánh mì.','Sự lên men',1572,NULL,_binary '\0'),(1671,'A substance produced by a living organism which acts as a catalyst to bring about a specific biochemical reaction.','Restriction enzymes are used to cut DNA at specific sites.','NOUN','Chất do sinh vật sống tạo ra đóng vai trò là chất xúc tác cho một phản ứng hóa sinh cụ thể.','Enzyme giới hạn được sử dụng để cắt DNA tại các vị trí cụ thể.','Enzyme / Men tiêu hóa',1573,NULL,_binary '\0'),(1672,'A simple cell in the body that is able to develop into any one of various kinds of cells.','Stem cell research offers hope for curing spinal cord injuries.','NOUN','Một tế bào đơn giản trong cơ thể có khả năng phát triển thành bất kỳ loại tế bào nào khác.','Nghiên cứu tế bào gốc mang lại hy vọng chữa khỏi các chấn thương tủy sống.','Tế bào gốc',1574,NULL,_binary '\0'),(1674,'The ethics of medical and biological research.','Advances in gene editing raise complex questions in bioethics.','NOUN','Các nguyên tắc đạo đức trong nghiên cứu y học và sinh học.','Những tiến bộ trong chỉnh sửa gen đặt ra những câu hỏi phức tạp về đạo đức sinh học.','Đạo đức sinh học',1576,NULL,_binary '\0'),(1675,'The basic unit of quantum information, representing a state that can be 0, 1, or both simultaneously.','Unlike a classical bit, a qubit can exist in a state of superposition.','NOUN','Đơn vị cơ bản của thông tin lượng tử, có thể đại diện cho trạng thái 0, 1 hoặc cả hai cùng lúc.','Không giống như bit cổ điển, một qubit có thể tồn tại ở trạng thái chồng chập.','Bit lượng tử',1577,NULL,_binary '\0'),(1676,'A fundamental principle of quantum mechanics where a physical system exists partly in all its theoretically possible states simultaneously.','Superposition allows quantum computers to process vast amounts of data at once.','NOUN','Một nguyên lý cơ bản của cơ học lượng tử, nơi một hệ vật lý tồn tại đồng thời trong tất cả các trạng thái có thể có.','Sự chồng chập cho phép máy tính lượng tử xử lý lượng dữ liệu khổng lồ cùng một lúc.','Sự chồng chập',1578,NULL,_binary '\0'),(1677,'A phenomenon where quantum particles become connected so that the state of one instantly influences the other, regardless of distance.','Einstein famously referred to quantum entanglement as \"spooky action at a distance.\"','NOUN','Hiện tượng các hạt lượng tử kết nối với nhau sao cho trạng thái của hạt này ảnh hưởng tức thì đến hạt kia, bất kể khoảng cách.','Einstein đã gọi vướng víu lượng tử một cách nổi tiếng là \"hành động ma quái ở khoảng cách xa\".','Sự vướng víu lượng tử',1579,NULL,_binary '\0'),(1678,'The loss of quantum coherence, where a quantum system interacts with its environment and loses its quantum properties.','Quantum decoherence is a major obstacle in building stable quantum computers.','NOUN','Sự mất đi tính kết hợp lượng tử khi một hệ lượng tử tương tác với môi trường và mất đi các đặc tính lượng tử của nó.','Mất kết hợp lượng tử là một trở ngại lớn trong việc xây dựng máy tính lượng tử ổn định.','Sự mất kết hợp lượng tử',1580,NULL,_binary '\0'),(1679,'A step-by-step procedure performed on a quantum computer to solve a problem.','Shor’s algorithm is a famous quantum algorithm for factoring large numbers.','NOUN','Một quy trình từng bước được thực hiện trên máy tính lượng tử để giải quyết một vấn đề.','Thuật toán Shor là một thuật toán lượng tử nổi tiếng để phân tích các số lớn thành thừa số.','Thuật toán lượng tử',1581,NULL,_binary '\0'),(1680,'The point where a quantum computer can solve a problem that is impossible for a classical computer to solve in a reasonable time.','Google claimed to have achieved quantum supremacy in 2019.','NOUN','Thời điểm mà máy tính lượng tử có thể giải quyết một vấn đề mà máy tính cổ điển không thể giải được trong thời gian hợp lý.','Google tuyên bố đã đạt được lợi thế tối cao lượng tử vào năm 2019.','Lợi thế tối cao lượng tử',1582,NULL,_binary '\0'),(1681,'The study of the production and behavior of materials at very low temperatures.','Quantum processors often require cryogenics to function properly.','NOUN','Việc nghiên cứu sản xuất và hành vi của vật liệu ở nhiệt độ rất thấp.','Các bộ xử lý lượng tử thường yêu cầu kỹ thuật nhiệt độ thấp để hoạt động bình thường.','Kỹ thuật nhiệt độ thấp',1583,NULL,_binary '\0'),(1682,'The process in which two or more quantum states combine to create a new state, either reinforcing or canceling each other.','Quantum interference is used to bias the probability of certain outcomes in a calculation.','NOUN','Quá trình trong đó hai hoặc nhiều trạng thái lượng tử kết hợp tạo ra trạng thái mới, củng cố hoặc triệt tiêu lẫn nhau.','Giao thoa lượng tử được dùng để điều chỉnh xác suất của một số kết quả nhất định trong tính toán.','Sự giao thoa lượng tử',1584,NULL,_binary '\0'),(1683,'The transfer of quantum information from one location to another using entanglement.','Quantum teleportation does not move physical matter, but information about its state.','NOUN','Việc truyền thông tin lượng tử từ vị trí này sang vị trí khác bằng cách sử dụng vướng víu lượng tử.','Dịch chuyển tức thời lượng tử không di chuyển vật chất vật lý, mà là thông tin về trạng thái của nó.','Dịch chuyển tức thời lượng tử',1585,NULL,_binary '\0'),(1684,'A basic quantum circuit operating on a small number of qubits.','Quantum gates are the building blocks of quantum circuits.','NOUN','Một mạch lượng tử cơ bản hoạt động trên một số lượng nhỏ các qubit.','Cổng lượng tử là những khối xây dựng nên các mạch lượng tử.','Cổng lượng tử',1586,NULL,_binary '\0'),(1685,'Based on or adapted to a theory of probability; subject to chance.','Quantum computing is inherently probabilistic rather than deterministic.','ADJECTIVE','Dựa trên hoặc thích ứng với lý thuyết xác suất; phụ thuộc vào sự ngẫu nhiên.','Máy tính lượng tử về bản chất là mang tính xác suất thay vì mang tính tất định.','Thuộc về xác suất',1587,NULL,_binary '\0'),(1686,'A quantum computing method used for finding the optimal solution to a problem by exploring a large search space.','D-Wave is a company that focuses on quantum annealing technology.','NOUN','Một phương pháp tính toán lượng tử được sử dụng để tìm giải pháp tối ưu bằng cách khám phá một không gian tìm kiếm lớn.','D-Wave là một công ty tập trung vào công nghệ ủ lượng tử.','Ủ lượng tử',1588,NULL,_binary '\0'),(1687,'Techniques used to protect quantum information from errors due to decoherence and other quantum noise.','Reliable quantum error correction is essential for practical quantum computing.','NOUN','Các kỹ thuật dùng để bảo vệ thông tin lượng tử khỏi các lỗi do mất kết hợp và nhiễu lượng tử khác.','Sửa lỗi lượng tử đáng tin cậy là điều thiết yếu cho tính toán lượng tử thực tiễn.','Sửa lỗi lượng tử',1589,NULL,_binary '\0'),(1688,'The property of a quantum system that allows it to maintain its quantum state over time.','Maintaining coherence for a long time is one of the hardest tasks in physics.','NOUN','Đặc tính của một hệ lượng tử cho phép nó duy trì trạng thái lượng tử của mình theo thời gian.','Duy trì tính kết hợp trong thời gian dài là một trong những nhiệm vụ khó khăn nhất trong vật lý.','Tính kết hợp',1590,NULL,_binary '\0'),(1689,'A program or device that mimics the behavior of a quantum system.','Researchers use a quantum simulator to study molecules that are too complex for classical PCs.','NOUN','Một chương trình hoặc thiết bị bắt chước hành vi của một hệ lượng tử.','Các nhà nghiên cứu sử dụng trình mô phỏng lượng tử để nghiên cứu các phân tử quá phức tạp đối với máy tính cổ điển.','Trình mô phỏng lượng tử',1591,NULL,_binary '\0'),(1691,'The delay before a transfer of data begins following an instruction for its transfer.','Low latency is crucial for real-time applications like online gaming.','NOUN','Khoảng thời gian chậm trễ trước khi việc truyền dữ liệu bắt đầu sau một lệnh truyền.','Độ trễ thấp là rất quan trọng đối với các ứng dụng thời gian thực như trò chơi trực tuyến.','Độ trễ',1593,NULL,_binary '\0'),(1692,'The range of radio frequencies used for communication.','Governments auction off parts of the wireless spectrum to mobile operators.','NOUN','Dải tần số vô tuyến được sử dụng để liên lạc.','Chính phủ đấu giá các phần của phổ vô tuyến không dây cho các nhà khai thác di động.','Phổ (tần số)',1594,NULL,_binary '\0'),(1695,'Using glass or plastic threads to transmit data using light.','Fiber-optic cables provide much faster internet speeds than copper wires.','ADJECTIVE','Sử dụng các sợi thủy tinh hoặc nhựa để truyền dữ liệu bằng ánh sáng.','Cáp quang cung cấp tốc độ internet nhanh hơn nhiều so với dây đồng.','Cáp quang',1597,NULL,_binary '\0'),(1696,'A band of radio frequencies that offer high speeds but have short range.','5G mmWave technology can deliver gigabit speeds in crowded areas.','NOUN','Một dải tần số vô tuyến cung cấp tốc độ cao nhưng có phạm vi ngắn.','Công nghệ 5G mmWave có thể cung cấp tốc độ gigabit ở những khu vực đông đúc.','Sóng milimet',1598,NULL,_binary '\0'),(1697,'The process of varying one or more properties of a periodic waveform, called the carrier signal, with a modulating signal.','Quadrature Amplitude Modulation (QAM) is used to increase data rates.','NOUN','Quá trình thay đổi một hoặc nhiều đặc tính của một dạng sóng định kỳ, được gọi là tín hiệu mang, bằng một tín hiệu điều chế.','Điều chế biên độ vuông góc (QAM) được sử dụng để tăng tốc độ dữ liệu.','Sự điều chế',1599,NULL,_binary '\0'),(1698,'A type of virtual networking architecture that allows multiple virtual networks to run on top of a single shared physical network infrastructure.','Network slicing allows operators to provide dedicated portions of their network for specific use cases.','NOUN','Một loại kiến trúc mạng ảo cho phép nhiều mạng ảo chạy trên cùng một hạ tầng mạng vật lý chung.','Phân đoạn mạng cho phép các nhà vận hành cung cấp các phần mạng riêng biệt cho các mục đích sử dụng cụ thể.','Phân đoạn mạng',1600,NULL,_binary '\0'),(1699,'The movement of a wave through a medium.','Radio wave propagation can be affected by weather and buildings.','NOUN','Sự di chuyển của một con sóng qua một môi trường.','Sự truyền dẫn sóng vô tuyến có thể bị ảnh hưởng bởi thời tiết và các tòa nhà.','Sự truyền dẫn',1601,NULL,_binary '\0'),(1700,'The process of transferring a mobile station from one base station to another.','A seamless handover is necessary to prevent dropped calls while driving.','NOUN','Quá trình chuyển một trạm di động từ trạm cơ sở này sang trạm cơ sở khác.','Sự chuyển giao liền mạch là cần thiết để ngăn chặn việc rớt cuộc gọi khi đang lái xe.','Sự chuyển giao (thuê bao)',1602,NULL,_binary '\0'),(1701,'A method for multiplying the capacity of a radio link using multiple transmission and receiving antennas.','Massive MIMO is a foundational technology for 5G networks.','NOUN','Phương pháp nhân băng thông của một liên kết vô tuyến bằng cách sử dụng nhiều ăng-ten truyền và nhận.','Massive MIMO là công nghệ nền tảng cho mạng 5G.','Công nghệ nhiều ăng-ten (MIMO)',1603,NULL,_binary '\0'),(1702,'A fixed transceiver that is the main communication point for one or more wireless mobile devices.','The mobile phone connects to the nearest base station to access the network.','NOUN','Một bộ thu phát cố định là điểm liên lạc chính cho một hoặc nhiều thiết bị di động không dây.','Điện thoại di động kết nối với trạm cơ sở gần nhất để truy cập mạng.','Trạm thu phát cơ sở',1604,NULL,_binary '\0'),(1703,'The ability of computer systems or software to exchange and make use of information.','Standardization ensures interoperability between equipment from different vendors.','NOUN','Khả năng của các hệ thống máy tính hoặc phần mềm để trao đổi và sử dụng thông tin.','Tiêu chuẩn hóa đảm bảo khả năng tương tác giữa thiết bị từ các nhà cung cấp khác nhau.','Khả năng tương tác / Tính liên thông',1605,NULL,_binary '\0'),(1704,'The tendency for different technological systems to evolve toward performing similar tasks.','The convergence of mobile and internet technologies has changed how we communicate.','NOUN','Xu hướng các hệ thống công nghệ khác nhau tiến hóa để thực hiện các nhiệm vụ tương tự nhau.','Sự hội tụ của công nghệ di động và internet đã thay đổi cách chúng ta liên lạc.','Sự hội tụ (công nghệ)',1606,NULL,_binary '\0'),(1705,'A scale of measurement that involves nanometers (one-billionth of a meter).','At the nanoscale, materials can have very different physical properties.','NOUN','Thang đo lường liên quan đến nanomet (một phần tỷ mét).','Ở thang nano, vật liệu có thể có các tính chất vật lý rất khác biệt.','Thang nano',1607,NULL,_binary '\0'),(1706,'Cylindrical molecules of carbon with extraordinary strength and unique electrical properties.','Carbon nanotubes are being researched for use in super-strong structural materials.','NOUN','Các phân tử carbon dạng hình trụ có độ bền phi thường và các đặc tính điện độc đáo.','Ống nano carbon đang được nghiên cứu để sử dụng trong các vật liệu cấu trúc siêu bền.','Ống nano carbon',1608,NULL,_binary '\0'),(1707,'A single layer of carbon atoms arranged in a two-dimensional honeycomb lattice.','Graphene is an excellent conductor of heat and electricity.','NOUN','Một lớp nguyên tử carbon duy nhất được sắp xếp trong mạng tinh thể tổ ong hai chiều.','Graphene là một chất dẫn nhiệt và dẫn điện tuyệt vời.','Graphene',1609,NULL,_binary '\0'),(1708,'A proposed type of manufacturing where objects are built atom by atom or molecule by molecule.','Molecular manufacturing could lead to the creation of incredibly precise devices.','NOUN','Một loại hình sản xuất được đề xuất trong đó các vật thể được chế tạo theo từng nguyên tử hoặc phân tử.','Sản xuất phân tử có thể dẫn đến việc tạo ra các thiết bị cực kỳ chính xác.','Sản xuất phân tử',1610,NULL,_binary '\0'),(1709,'A hypothetical, very small robot designed to perform tasks at the nanoscale.','Nanobots could one day be used to repair damaged cells inside the human body.','NOUN','Một loại robot giả tưởng siêu nhỏ được thiết kế để thực hiện các nhiệm vụ ở quy mô nano.','Robot nano một ngày nào đó có thể được sử dụng để sửa chữa các tế bào bị hư hại bên trong cơ thể con người.','Robot nano',1611,NULL,_binary '\0'),(1710,'The medical application of nanotechnology, such as for targeted drug delivery.','Nanomedicine aims to provide more effective treatments with fewer side effects.','NOUN','Ứng dụng y tế của công nghệ nano, chẳng hạn như để đưa thuốc đến chính xác mục tiêu.','Y học nano nhằm cung cấp các phương pháp điều trị hiệu quả hơn với ít tác dụng phụ hơn.','Y học nano',1612,NULL,_binary '\0'),(1711,'A tiny semiconductor particle which has optical and electronic properties that differ from larger particles.','Quantum dots are used in high-quality display screens and medical imaging.','NOUN','Một hạt bán dẫn cực nhỏ có các đặc tính quang học và điện tử khác với các hạt lớn hơn.','Chấm lượng tử được sử dụng trong màn hình hiển thị chất lượng cao và hình ảnh y khoa.','Chấm lượng tử',1613,NULL,_binary '\0'),(1712,'A process in which components spontaneously form an organized structure or pattern.','Molecular self-assembly is a key concept in creating new nanomaterials.','NOUN','Quá trình trong đó các thành phần tự phát hình thành một cấu trúc hoặc mô hình có tổ chức.','Sự tự lắp ghép phân tử là một khái niệm then chốt trong việc tạo ra các vật liệu nano mới.','Sự tự lắp ghép',1614,NULL,_binary '\0'),(1713,'A multiphase solid material where one of the phases has one, two, or three dimensions of less than 100 nanometers.','Nanocomposites are used to make lightweight but extremely strong car parts.','NOUN','Một vật liệu rắn nhiều pha, trong đó một trong các pha có kích thước nhỏ hơn 100 nanomet.','Vật liệu nano composite được dùng để chế tạo các bộ phận xe hơi nhẹ nhưng cực kỳ bền.','Vật liệu nano composite',1615,NULL,_binary '\0'),(1714,'The total area of the surface of a three-dimensional object.','Nanoparticles have a very high surface area-to-volume ratio.','NOUN','Tổng diện tích bề mặt của một vật thể ba chiều.','Các hạt nano có tỷ lệ diện tích bề mặt trên thể tích rất cao.','Diện tích bề mặt',1616,NULL,_binary '\0'),(1715,'A microscopic particle of matter that is measured in nanometers.','Silver nanoparticles are used in some clothing for their antibacterial properties.','NOUN','Một hạt vật chất siêu hiển vi được đo bằng nanomet.','Các hạt nano bạc được sử dụng trong một số loại quần áo vì đặc tính kháng khuẩn của chúng.','Hạt nano',1617,NULL,_binary '\0'),(1716,'The quality of being toxic or poisonous.','Researchers must study the potential toxicity of new nanomaterials.','NOUN','Đặc tính gây độc hoặc có hại.','Các nhà nghiên cứu phải nghiên cứu độc tính tiềm tàng của các vật liệu nano mới.','Độc tính',1618,NULL,_binary '\0'),(1717,'Not harmful to living tissue.','Materials used in medical implants must be biocompatible.','ADJECTIVE','Không gây hại cho mô sống.','Vật liệu được sử dụng trong cấy ghép y tế phải có tính tương thích sinh học.','Tương thích sinh học',1619,NULL,_binary '\0'),(1718,'A process used in nanotechnology to print patterns on a surface.','Extreme ultraviolet lithography is used to create modern computer chips.','NOUN','Một quy trình được sử dụng trong công nghệ nano để in các hoa văn lên một bề mặt.','Phép in thạch bản cực tím được sử dụng để tạo ra các chip máy tính hiện đại.','Phép in thạch bản',1620,NULL,_binary '\0'),(1719,'A substance that increases the rate of a chemical reaction without itself undergoing any permanent chemical change.','Nanoparticles can act as highly efficient catalysts for industrial reactions.','NOUN','Một chất làm tăng tốc độ phản ứng hóa học mà bản thân nó không bị thay đổi hóa học vĩnh viễn.','Các hạt nano có thể đóng vai trò là chất xúc tác hiệu quả cao cho các phản ứng công nghiệp.','Chất xúc tác',1621,NULL,_binary '\0'),(1720,'The state or extent of being connected or interconnected.','Seamless connectivity is the backbone of any IoT ecosystem.','NOUN','Trạng thái hoặc mức độ được kết nối hoặc liên kết với nhau.','Khả năng kết nối liền mạch là xương sống của bất kỳ hệ sinh thái IoT nào.','Khả năng kết nối',1622,NULL,_binary '\0'),(1721,'A distributed computing paradigm that brings computation and data storage closer to the sources of data.','Edge computing reduces latency by processing data locally instead of in the cloud.','NOUN','Mô hình điện toán phân tán giúp đưa việc tính toán và lưu trữ dữ liệu đến gần hơn với nguồn dữ liệu.','Điện toán biên giảm độ trễ bằng cách xử lý dữ liệu cục bộ thay vì trên đám mây.','Điện toán biên',1623,NULL,_binary '\0'),(1723,'The process of recording and transmitting the readings of an instrument to a distant station.','IoT devices provide real-time telemetry data for industrial monitoring.','NOUN','Quá trình ghi lại và truyền các kết quả đo của một thiết bị đến một trạm ở xa.','Các thiết bị IoT cung cấp dữ liệu đo từ xa theo thời gian thực để giám sát công nghiệp.','Phép đo từ xa',1625,NULL,_binary '\0'),(1725,'Software that is permanently stored in a chip or hardware device.','IoT security often depends on keeping the device firmware up to date.','NOUN','Phần mềm được lưu trữ vĩnh viễn trong một chip hoặc thiết bị phần cứng.','Bảo mật IoT thường phụ thuộc vào việc cập nhật phần sụn của thiết bị thường xuyên.','Phần sụn',1627,NULL,_binary '\0'),(1726,'A device used to connect different networks or to bridge IoT devices to the cloud.','The IoT gateway translates protocols between sensors and the central server.','NOUN','Một thiết bị dùng để kết nối các mạng khác nhau hoặc làm cầu nối thiết bị IoT với đám mây.','Cổng IoT chuyển đổi các giao thức giữa cảm biến và máy chủ trung tâm.','Cổng kết nối',1628,NULL,_binary '\0'),(1729,'The process of setting up and configuring an IoT device to connect to a network.','Zero-touch provisioning allows devices to configure themselves automatically.','NOUN','Quá trình thiết lập và cấu hình một thiết bị IoT để kết nối vào mạng.','Thiết lập không chạm cho phép các thiết bị tự cấu hình một cách tự động.','Sự cung cấp/Thiết lập',1631,NULL,_binary '\0'),(1730,'Present, appearing, or found everywhere.','IoT aims to create a world of ubiquitous computing.','ADJECTIVE','Hiện diện, xuất hiện hoặc được tìm thấy ở mọi nơi.','IoT hướng tới việc tạo ra một thế giới điện toán hiện diện ở khắp mọi nơi.','Phổ biến khắp nơi',1632,NULL,_binary '\0'),(1731,'A device that can be worn on the body, often used for health tracking.','Smartwatches are the most common type of consumer wearable.','NOUN','Một thiết bị có thể đeo trên người, thường dùng để theo dõi sức khỏe.','Đồng hồ thông minh là loại thiết bị đeo phổ biến nhất cho người tiêu dùng.','Thiết bị đeo',1633,NULL,_binary '\0'),(1732,'A small Bluetooth device that transmits signals to nearby smartphones.','Retailers use beacons to send personalized coupons to customers in-store.','NOUN','Một thiết bị Bluetooth nhỏ truyền tín hiệu đến các điện thoại thông minh ở gần.','Các nhà bán lẻ sử dụng beacon để gửi phiếu giảm giá cá nhân hóa cho khách hàng trong cửa hàng.','Thiết bị phát tín hiệu (Beacon)',1634,NULL,_binary '\0'),(1733,'Any physical device within a network that is capable of sending, receiving, or forwarding information.','Each sensor in the forest acts as a node in the wildfire detection network.','NOUN','Bất kỳ thiết bị vật lý nào trong mạng có khả năng gửi, nhận hoặc chuyển tiếp thông tin.','Mỗi cảm biến trong rừng đóng vai trò như một nút trong mạng lưới phát hiện cháy rừng.','Nút (mạng)',1635,NULL,_binary '\0'),(1734,'The process of gathering and summarizing raw data from multiple sources.','Data aggregation helps in making sense of the noise from thousands of sensors.','NOUN','Quá trình thu thập và tóm tắt dữ liệu thô từ nhiều nguồn khác nhau.','Tổng hợp dữ liệu giúp làm rõ thông tin từ hàng ngàn cảm biến nhiễu.','Sự tổng hợp dữ liệu',1636,NULL,_binary '\0'),(1735,'The process by which radiation from a planet’s atmosphere warms the planet’s surface to a temperature above what it would be without its atmosphere.','The greenhouse effect is intensified by the burning of fossil fuels.','NOUN','Quá trình bức xạ từ khí quyển của một hành tinh làm nóng bề mặt hành tinh đó lên cao hơn mức bình thường.','Hiệu ứng nhà kính bị gia tăng mạnh do việc đốt nhiên liệu hóa thạch.','Hiệu ứng nhà kính',1637,NULL,_binary '\0'),(1736,'The process of capturing and storing atmospheric carbon dioxide.','Forests play a crucial role in natural carbon sequestration.','NOUN','Quá trình thu giữ và lưu trữ khí carbon dioxide từ khí quyển.','Rừng đóng một vai trò quan trọng trong việc cô lập carbon tự nhiên.','Sự cô lập carbon',1638,NULL,_binary '\0'),(1737,'Adjustments in ecological, social, or economic systems in response to actual or expected climatic stimuli.','The government is investing in climate adaptation strategies for coastal cities.','NOUN','Sự điều chỉnh trong các hệ sinh thái, xã hội hoặc kinh tế để ứng phó với các tác động khí hậu.','Chính phủ đang đầu tư vào các chiến lược thích ứng khí hậu cho các thành phố ven biển.','Sự thích ứng (biến đổi khí hậu)',1639,NULL,_binary '\0'),(1739,'The point at which a series of small changes or incidents becomes significant enough to cause a larger, more important change.','Scientists fear we are approaching a tipping point in the melting of Arctic ice.','NOUN','Thời điểm mà một chuỗi các thay đổi nhỏ trở nên đủ đáng kể để gây ra một thay đổi lớn hơn và quan trọng hơn.','Các nhà khoa học lo ngại chúng ta đang tiến gần đến điểm tới hạn trong việc tan băng ở Bắc Cực.','Điểm tới hạn',1641,NULL,_binary '\0'),(1740,'(Chiefly of environmental pollution and pollutants) originating in human activity.','Most scientists agree that recent global warming is largely anthropogenic.','ADJECTIVE','(Chủ yếu nói về ô nhiễm) có nguồn gốc từ hoạt động của con người.','Hầu hết các nhà khoa học đồng ý rằng sự nóng lên toàn cầu gần đây phần lớn là do con người gây ra.','Do con người gây ra',1642,NULL,_binary '\0'),(1741,'The decrease in the number, type, or variety of living organisms within an ecosystem.','Climate change is a major driver of global biodiversity loss.','NOUN','Sự sụt giảm về số lượng, loại hoặc sự phong phú của các sinh vật sống trong một hệ sinh thái.','Biến đổi khí hậu là tác nhân chính gây ra sự mất đa dạng sinh học toàn cầu.','Sự mất đa dạng sinh học',1643,NULL,_binary '\0'),(1742,'The process by which fertile land becomes desert, typically as a result of drought, deforestation, or inappropriate agriculture.','Overgrazing and climate change are accelerating desertification in sub-Saharan Africa.','NOUN','Quá trình đất màu mỡ trở thành sa mạc, thường là do hạn hán, phá rừng hoặc nông nghiệp không phù hợp.','Chăn thả quá mức và biến đổi khí hậu đang đẩy nhanh quá trình sa mạc hóa ở vùng cận Sahara châu Phi.','Sự sa mạc hóa',1644,NULL,_binary '\0'),(1743,'A thick subsurface layer of soil that remains frozen throughout the year, occurring chiefly in polar regions.','The thawing of permafrost releases large amounts of methane into the atmosphere.','NOUN','Lớp đất dày dưới bề mặt luôn bị đóng băng quanh năm, chủ yếu xuất hiện ở các vùng cực.','Sự tan chảy của tầng đất đóng băng vĩnh cửu giải phóng một lượng lớn khí methane vào khí quyển.','Tầng đất đóng băng vĩnh cửu',1645,NULL,_binary '\0'),(1744,'A reduction in the pH of the ocean over an extended period, caused primarily by uptake of carbon dioxide.','Ocean acidification threatens the survival of coral reefs and shellfish.','NOUN','Sự sụt giảm độ pH của đại dương trong một thời gian dài, chủ yếu do sự hấp thụ carbon dioxide.','Sự axit hóa đại dương đe dọa sự sống sót của các rặng san hô và loài động vật có vỏ.','Sự axit hóa đại dương',1646,NULL,_binary '\0'),(1747,'A natural fuel such as coal or gas, formed in the geological past from the remains of living organisms.','We need to transition away from fossil fuels to renewable energy sources.','NOUN','Nhiên liệu tự nhiên như than đá hoặc khí đốt, được hình thành trong quá khứ địa chất từ xác sinh vật.','Chúng ta cần chuyển đổi từ nhiên liệu hóa thạch sang các nguồn năng lượng tái tạo.','Nhiên liệu hóa thạch',1649,NULL,_binary '\0'),(1748,'Unusual, severe or unseasonal weather; weather at the extremes of the historical distribution.','Climate change has led to an increase in the frequency of extreme weather events.','NOUN','Thời tiết bất thường, khắc nghiệt hoặc trái mùa; nằm ở mức cực độ của dữ liệu lịch sử.','Biến đổi khí hậu đã dẫn đến sự gia tăng tần suất của các hiện tượng thời tiết cực đoan.','Hiện tượng thời tiết cực đoan',1650,NULL,_binary '\0'),(1751,'Animals or plants that may soon not exist because there are very few now alive.','The giant panda is one of the most famous endangered species.','ADJECTIVE','Động vật hoặc thực vật có thể sớm không còn tồn tại vì hiện nay còn sống rất ít.','Gấu trúc khổng lồ là một trong những loài có nguy cơ tuyệt chủng nổi tiếng nhất.','Có nguy cơ tuyệt chủng',1653,NULL,_binary '\0'),(1753,'The illegal act of catching or killing animals, birds, or fish on someone else’s property or in a protected area.','Poaching has pushed the rhinoceros to the brink of extinction.','NOUN','Hành vi bất hợp pháp khi bắt hoặc giết động vật, chim hoặc cá trên tài sản của người khác hoặc trong khu vực được bảo vệ.','Săn bắn trái phép đã đẩy loài tê giác đến bờ vực tuyệt chủng.','Săn bắn trái phép',1655,NULL,_binary '\0'),(1755,'A place where birds or animals can live and be protected, especially from being hunted or dangerous conditions.','The island is a sanctuary for several rare species of sea birds.','NOUN','Nơi chim chóc hoặc động vật có thể sinh sống và được bảo vệ, đặc biệt là khỏi việc bị săn bắn.','Hòn đảo này là khu bảo tồn của một số loài chim biển quý hiếm.','Khu bảo tồn',1657,NULL,_binary '\0'),(1756,'A species on which other species in an ecosystem largely depend, such that if it were removed the ecosystem would change drastically.','Sea otters are a keystone species in kelp forest ecosystems.','NOUN','Một loài mà các loài khác trong hệ sinh thái phụ thuộc phần lớn vào nó, nếu mất đi hệ sinh thái sẽ thay đổi mạnh mẽ.','Rái cá biển là một loài then chốt trong hệ sinh thái rừng tảo bẹ.','Loài ưu thế / Loài then chốt',1658,NULL,_binary '\0'),(1757,'The process of breaking into separate parts, often referring to habitat being split by roads or development.','Habitat fragmentation prevents animals from finding mates and food.','NOUN','Quá trình chia cắt thành các phần riêng biệt, thường nói về môi trường sống bị chia cắt bởi đường sá hoặc xây dựng.','Sự phân mảnh môi trường sống ngăn cản động vật tìm bạn đời và thức ăn.','Sự phân mảnh (môi trường sống)',1659,NULL,_binary '\0'),(1758,'A species that is not native to a specific location and has a tendency to spread to a degree believed to cause damage.','The introduction of invasive species can disrupt local food webs.','NOUN','Một loài không có nguồn gốc tại địa phương và có xu hướng lan rộng gây hại.','Việc đưa vào các loài xâm hại có thể làm xáo trộn lưới thức ăn địa phương.','Loài ngoại lai xâm hại',1660,NULL,_binary '\0'),(1761,'A biogeographic region with significant levels of biodiversity that is threatened by human habitation.','Southeast Asia is home to several critical biodiversity hotspots.','NOUN','Một vùng địa sinh học có mức độ đa dạng sinh học đáng kể nhưng đang bị đe dọa bởi sự định cư của con người.','Đông Nam Á là nơi có một số điểm nóng đa dạng sinh học quan trọng.','Điểm nóng đa dạng sinh học',1663,NULL,_binary '\0'),(1762,'The act of planting trees on an area of land that has become empty or spoiled.','Reforestation is one of the most effective ways to combat climate change.','NOUN','Hành động trồng cây trên một khu vực đất đã bị trống hoặc bị hư hỏng.','Tái trồng rừng là một trong những cách hiệu quả nhất để chống lại biến đổi khí hậu.','Sự tái trồng rừng',1664,NULL,_binary '\0'),(1763,'The process of breeding animals in controlled environments within closed facilities, such as zoos or research centers.','Captive breeding programs help increase the population of nearly extinct animals.','NOUN','Quá trình nhân giống động vật trong môi trường được kiểm soát như vườn thú hoặc trung tâm nghiên cứu.','Các chương trình nhân giống trong môi trường nuôi nhốt giúp tăng quần thể các động vật sắp tuyệt chủng.','Nhân giống trong môi trường nuôi nhốt',1665,NULL,_binary '\0'),(1764,'(Especially of a plant or animal) native and restricted to a certain place.','The lemur is endemic to the island of Madagascar.','ADJECTIVE','(Đặc biệt là thực vật hoặc động vật) bản địa và chỉ giới hạn ở một nơi nhất định.','Vượn cáo là loài đặc hữu của đảo Madagascar.','Đặc hữu',1666,NULL,_binary '\0'),(1765,'Relating to the production of electric current at the junction of two substances exposed to light.','Photovoltaic cells are the primary components of solar panels.','ADJECTIVE','Liên quan đến việc tạo ra dòng điện tại điểm tiếp giáp của hai chất khi tiếp xúc với ánh sáng.','Các tế bào quang điện là thành phần chính của các tấm pin mặt trời.','Thuộc về điện quang / Quang điện',1667,NULL,_binary '\0'),(1767,'Relating to the generation of electricity using flowing water to drive a turbine.','The construction of the new hydroelectric dam caused environmental concerns.','ADJECTIVE','Liên quan đến việc tạo ra điện bằng cách sử dụng dòng nước chảy để làm quay tuabin.','Việc xây dựng đập thủy điện mới đã gây ra những lo ngại về môi trường.','Thuộc về thủy điện',1669,NULL,_binary '\0'),(1768,'Organic matter used as a fuel, especially in a power station for the generation of electricity.','Wood chips and agricultural waste are common types of biomass.','NOUN','Vật chất hữu cơ được dùng làm nhiên liệu, đặc biệt là trong nhà máy điện để tạo ra điện.','Gỗ vụn và chất thải nông nghiệp là những loại sinh khối phổ biến.','Sinh khối',1670,NULL,_binary '\0'),(1769,'The quality of being not continuous or steady (often used for solar/wind energy).','Energy storage systems are needed to overcome the intermittency of wind power.','NOUN','Đặc tính không liên tục hoặc không ổn định (thường dùng cho năng lượng mặt trời/gió).','Hệ thống lưu trữ năng lượng là cần thiết để khắc phục tính gián đoạn của năng lượng gió.','Tính gián đoạn',1671,NULL,_binary '\0'),(1770,'The reduction or removal of carbon dioxide emissions from a process or economy.','Decarbonization of the transport sector is a major challenge.','NOUN','Việc giảm thiểu hoặc loại bỏ lượng khí thải carbon dioxide khỏi một quy trình hoặc nền kinh tế.','Sự khử carbon trong ngành giao thông vận tải là một thách thức lớn.','Sự khử carbon',1672,NULL,_binary '\0'),(1771,'The balance between the amount of greenhouse gas produced and the amount removed from the atmosphere.','The country has pledged to reach net zero emissions by 2050.','NOUN','Sự cân bằng giữa lượng khí nhà kính tạo ra và lượng khí được loại bỏ khỏi khí quyển.','Quốc gia này đã cam kết đạt mức phát thải ròng bằng không vào năm 2050.','Phát thải ròng bằng không',1673,NULL,_binary '\0'),(1772,'A network of cables and equipment for distributing electricity over a large area.','Smart grids can manage the integration of renewable energy more effectively.','NOUN','Mạng lưới dây cáp và thiết bị để phân phối điện trên một khu vực rộng lớn.','Lưới điện thông minh có thể quản lý việc tích hợp năng lượng tái tạo hiệu quả hơn.','Lưới điện (Lưới điện thông minh)',1674,NULL,_binary '\0'),(1773,'The possibility that can be made, done, or achieved, or is reasonable.','A feasibility study was conducted before building the offshore wind farm.','NOUN','Khả năng có thể được thực hiện, hoàn thành hoặc đạt được, hoặc là hợp lý.','Một nghiên cứu khả thi đã được thực hiện trước khi xây dựng trang trại gió ngoài khơi.','Tính khả thi',1675,NULL,_binary '\0'),(1775,'A reduction in something, or the act of reducing it to a very small amount.','The depletion of natural resources is a major threat to future generations.','NOUN','Sự sụt giảm một thứ gì đó, hoặc hành động làm giảm nó xuống một lượng rất nhỏ.','Sự cạn kiệt tài nguyên thiên nhiên là mối đe dọa lớn đối với các thế hệ tương lai.','Sự cạn kiệt',1677,NULL,_binary '\0'),(1776,'Working or operating quickly and effectively in an organized way, with minimum waste.','Modern wind turbines are much more efficient than older models.','ADJECTIVE','Làm việc hoặc vận hành nhanh chóng và hiệu quả một cách có tổ chức, với lãng phí tối thiểu.','Các tuabin gió hiện đại hiệu quả hơn nhiều so với các mẫu cũ.','Hiệu quả (về năng lượng/thời gian)',1678,NULL,_binary '\0'),(1777,'An economic system aimed at eliminating waste and the continual use of resources.','Transitioning to a circular economy can help reduce industrial pollution.','NOUN','Hệ thống kinh tế nhằm loại bỏ chất thải và sử dụng tài nguyên liên tục.','Chuyển đổi sang kinh tế tuần hoàn có thể giúp giảm ô nhiễm công nghiệp.','Kinh tế tuần hoàn',1679,NULL,_binary '\0'),(1778,'To pay part of the cost of something, often by a government.','The government decided to subsidize solar panel installation for households.','VERB','Chi trả một phần chi phí của một thứ gì đó, thường do chính phủ thực hiện.','Chính phủ đã quyết định trợ giá lắp đặt tấm pin mặt trời cho các hộ gia đình.','Trợ giá / Trợ cấp',1680,NULL,_binary '\0'),(1779,'The action of compensating for carbon dioxide emissions by participating in projects that reduce or store carbon.','Many airlines now offer carbon offsetting programs for their passengers.','NOUN','Hành động bù đắp lượng khí thải CO2 bằng cách tham gia vào các dự án giảm thiểu hoặc lưu trữ carbon.','Nhiều hãng hàng không hiện cung cấp các chương trình bù đắp carbon cho hành khách của họ.','Sự bù đắp (carbon)',1681,NULL,_binary '\0'),(1780,'Microscopic marine plants that form the base of several ocean food webs.','Phytoplankton produce a significant portion of the Earth’s oxygen.','NOUN','Các thực vật biển siêu hiển vi tạo thành nền tảng của nhiều lưới thức ăn đại dương.','Phù du thực vật tạo ra một phần đáng kể lượng oxy trên Trái đất.','Phù du thực vật',1682,NULL,_binary '\0'),(1781,'The portion of the ocean floor where light does not penetrate and the temperatures are near freezing.','Unique and strange creatures have adapted to survive in the abyssal zone.','NOUN','Phần đáy đại dương nơi ánh sáng không xuyên tới và nhiệt độ gần như đóng băng.','Những sinh vật độc đáo và kỳ lạ đã thích nghi để tồn tại ở vùng vực thẳm.','Vùng vực thẳm',1683,NULL,_binary '\0'),(1782,'The process when corals lose their vibrant colors and turn white due to environmental stressors like rising water temperatures.','Coral bleaching is a direct consequence of global ocean warming.','NOUN','Quá trình san hô mất đi màu sắc rực rỡ và chuyển sang màu trắng do các tác nhân gây căng thẳng môi trường như nhiệt độ nước tăng.','Tẩy trắng san hô là hệ quả trực tiếp của việc nóng lên của đại dương toàn cầu.','Sự tẩy trắng san hô',1684,NULL,_binary '\0'),(1783,'The wide part of a river at the place where it joins the sea.','Estuaries are highly productive ecosystems that serve as nurseries for many fish species.','NOUN','Phần rộng của một con sông tại nơi nó đổ ra biển.','Cửa sông là hệ sinh thái có năng suất cao, đóng vai trò là nơi nuôi dưỡng cho nhiều loài cá.','Cửa sông',1685,NULL,_binary '\0'),(1784,'The concentration of dissolved salts in water.','The salinity of the Dead Sea is much higher than that of the ocean.','NOUN','Nồng độ muối hòa tan trong nước.','Độ mặn của Biển Chết cao hơn nhiều so với đại dương.','Độ mặn',1686,NULL,_binary '\0'),(1785,'Large-scale ocean circulation that is driven by global density gradients created by surface heat and freshwater fluxes.','Thermohaline circulation plays a vital role in regulating the Earth’s climate.','NOUN','Vòng tuần hoàn đại dương quy mô lớn được thúc đẩy bởi sự chênh lệch mật độ toàn cầu do nhiệt độ bề mặt và lưu lượng nước ngọt.','Vòng tuần hoàn nhiệt muối đóng vai trò quan trọng trong việc điều hòa khí hậu Trái đất.','Vòng tuần hoàn nhiệt muối',1687,NULL,_binary '\0'),(1786,'The production and emission of light by a living organism.','Many deep-sea creatures use bioluminescence to lure prey or attract mates.','NOUN','Sự tạo ra và phát xạ ánh sáng bởi một sinh vật sống.','Nhiều sinh vật biển sâu sử dụng sự phát quang sinh học để dụ mồi hoặc thu hút bạn tình.','Sự phát quang sinh học',1688,NULL,_binary '\0'),(1787,'Relating to, or occurring at the bottom of a body of water.','Benthic organisms live on or near the ocean floor.','ADJECTIVE','Liên quan đến, hoặc xảy ra ở đáy của một vực nước.','Các sinh vật tầng đáy sống trên hoặc gần đáy đại dương.','Thuộc về tầng đáy',1689,NULL,_binary '\0'),(1788,'A process in which deep, cold water rises toward the surface.','Upwelling brings nutrients to the surface, supporting rich fishing grounds.','NOUN','Quá trình nước lạnh từ sâu dưới lòng đại dương trồi lên phía bề mặt.','Hiện tượng nước trồi mang chất dinh dưỡng lên bề mặt, hỗ trợ các ngư trường phong phú.','Sự trồi lên của nước (nước trồi)',1690,NULL,_binary '\0'),(1789,'An animal with a hard shell and several pairs of legs, which usually lives in water (e.g., crabs, lobsters).','Crustaceans are an important food source for many marine predators.','NOUN','Động vật có vỏ cứng và nhiều đôi chân, thường sống dưới nước (ví dụ: cua, tôm hùm).','Loài giáp xác là nguồn thức ăn quan trọng cho nhiều loài săn mồi biển.','Loài giáp xác',1691,NULL,_binary '\0'),(1790,'A marine mammal of the order Cetacea (e.g., whales, dolphins, or porpoises).','Cetaceans are known for their high intelligence and complex social structures.','NOUN','Động vật có vú biển thuộc bộ Cá voi (ví dụ: cá voi, cá heo).','Các loài bộ cá voi được biết đến với trí thông minh cao và cấu trúc xã hội phức tạp.','Động vật bộ cá voi',1692,NULL,_binary '\0'),(1791,'An opening in the sea floor out of which heated mineral-rich water flows.','Hydrothermal vents support ecosystems that do not depend on sunlight.','NOUN','Một khe hở dưới đáy biển nơi dòng nước giàu khoáng chất bị nung nóng chảy ra.','Miệng phun thủy nhiệt hỗ trợ các hệ sinh thái không phụ thuộc vào ánh sáng mặt trời.','Miệng phun thủy nhiệt',1693,NULL,_binary '\0'),(1792,'Relating to the open ocean, rather than waters near the shore or the sea floor.','Blue sharks are pelagic hunters that travel long distances across the ocean.','ADJECTIVE','Liên quan đến vùng biển khơi, thay vì vùng nước gần bờ hoặc đáy biển.','Cá mập xanh là loài săn mồi vùng biển khơi di chuyển quãng đường dài khắp đại dương.','Thuộc về vùng biển khơi',1694,NULL,_binary '\0'),(1793,'The act of catching too many fish in an area so that there are not enough fish left to breed and keep the population at the same level.','Overfishing is a major threat to global food security.','NOUN','Hành động đánh bắt quá nhiều cá trong một khu vực khiến không còn đủ cá để sinh sản và duy trì quần thể.','Đánh bắt quá mức là một mối đe dọa lớn đối với an ninh lương thực toàn cầu.','Đánh bắt quá mức',1695,NULL,_binary '\0'),(1794,'An area of the ocean where a government has placed limits on human activity.','Establishing MPAs is essential for the recovery of depleted fish stocks.','NOUN','Một vùng đại dương nơi chính phủ đặt ra các giới hạn đối với hoạt động của con người.','Thiết lập các khu bảo tồn biển là điều thiết yếu để phục hồi các trữ lượng cá đã bị cạn kiệt.','Khu bảo tồn biển',1696,NULL,_binary '\0'),(1795,'A smaller earthquake that occurs after a larger earthquake in the same area.','Rescue workers were hampered by frequent aftershocks.','NOUN','Một trận động đất nhỏ hơn xảy ra sau một trận động đất lớn trong cùng một khu vực.','Các nhân viên cứu hộ đã bị cản trở bởi các dư chấn thường xuyên.','Dư chấn',1697,NULL,_binary '\0'),(1796,'The point on the earth’s surface vertically above the focus of an earthquake.','The city located at the epicenter suffered the most damage.','NOUN','Điểm trên bề mặt trái đất nằm thẳng đứng phía trên tiêu điểm của một trận động đất.','Thành phố nằm tại tâm chấn đã chịu thiệt hại nặng nề nhất.','Tâm chấn',1698,NULL,_binary '\0'),(1798,'A sudden local flood, typically due to heavy rain.','The hikers were caught in a flash flood after the thunderstorm.','NOUN','Trận lụt cục bộ đột ngột, thường do mưa lớn gây ra.','Những người đi bộ đường dài đã bị kẹt trong một trận lũ quét sau cơn giông bão.','Lũ quét',1700,NULL,_binary '\0'),(1800,'The action of moving people from a dangerous place to a safe place.','The mayor ordered a mandatory evacuation before the hurricane made landfall.','NOUN','Hành động di chuyển mọi người từ nơi nguy hiểm đến nơi an toàn.','Thị trưởng đã ra lệnh sơ tán bắt buộc trước khi cơn bão đổ bộ vào đất liền.','Sự sơ tán',1702,NULL,_binary '\0'),(1802,'Material and logistic assistance in response to humanitarian crises.','The UN is sending humanitarian aid to the victims of the drought.','NOUN','Sự hỗ trợ về vật chất và hậu cần để ứng phó với các cuộc khủng hoảng nhân đạo.','Liên Hợp Quốc đang gửi viện trợ nhân đạo cho các nạn nhân của đợt hạn hán.','Viện trợ nhân đạo',1704,NULL,_binary '\0'),(1805,'Someone whose job is to go to the scene of an emergency to provide help (e.g., firefighters, paramedics).','First responders arrived within minutes of the explosion.','NOUN','Người có công việc là đến hiện trường khẩn cấp để hỗ trợ (ví dụ: lính cứu hỏa, nhân viên cấp cứu).','Những người ứng cứu đầu tiên đã đến trong vòng vài phút sau vụ nổ.','Người ứng cứu đầu tiên',1707,NULL,_binary '\0'),(1806,'A mass of earth or rock that slides down a mountain or cliff.','Deforestation increases the risk of landslides during the rainy season.','NOUN','Một khối đất hoặc đá trượt xuống từ núi hoặc vách đá.','Phá rừng làm tăng nguy cơ sạt lở đất trong mùa mưa.','Sạt lở đất',1708,NULL,_binary '\0'),(1807,'A scientist who studies the atmosphere and predicts the weather.','Meteorologists are monitoring the progress of the tropical storm.','NOUN','Nhà khoa học nghiên cứu khí quyển và dự báo thời tiết.','Các nhà khí tượng học đang theo dõi tiến trình của cơn bão nhiệt đới.','Nhà khí tượng học',1709,NULL,_binary '\0'),(1809,'Relating to earthquakes or other vibrations of the earth.','Engineers must ensure the bridge can withstand seismic activity.','ADJECTIVE','Liên quan đến động đất hoặc các rung động khác của trái đất.','Các kỹ sư phải đảm bảo cây cầu có thể chịu được hoạt động địa chấn.','Thuộc về địa chấn',1711,NULL,_binary '\0'),(1810,'A large naturally occurring community of flora and fauna occupying a major habitat, e.g., tundra or tropical rainforest.','The tropical rainforest is a biome known for its high biodiversity.','NOUN','Một cộng đồng thực vật và động vật lớn tự nhiên chiếm một môi trường sống chính.','Rừng mưa nhiệt đới là một khu sinh học nổi tiếng với sự đa dạng sinh học cao.','Biôm / Khu sinh học',1712,NULL,_binary '\0'),(1811,'A close and long-term biological interaction between two different biological organisms.','The relationship between bees and flowers is a classic example of symbiosis.','NOUN','Sự tương tác sinh học lâu dài và chặt chẽ giữa hai sinh vật khác nhau.','Mối quan hệ giữa ong và hoa là một ví dụ điển hình về sự cộng sinh.','Sự cộng sinh',1713,NULL,_binary '\0'),(1812,'The position that an organism occupies in a food chain.','Apex predators occupy the highest trophic level in an ecosystem.','NOUN','Vị trí mà một sinh vật chiếm giữ trong chuỗi thức ăn.','Các loài săn mồi đầu bảng chiếm bậc dinh dưỡng cao nhất trong một hệ sinh thái.','Bậc dinh dưỡng',1714,NULL,_binary '\0'),(1814,'The specific role or position that an organism has within its ecosystem.','Each species has a unique ecological niche that prevents direct competition.','NOUN','Vai trò hoặc vị trí cụ thể mà một sinh vật có trong hệ sinh thái của nó.','Mỗi loài có một ngách sinh thái riêng biệt giúp ngăn chặn sự cạnh tranh trực tiếp.','Ngách sinh thái',1716,NULL,_binary '\0'),(1815,'The process by which green plants use sunlight to synthesize nutrients from carbon dioxide and water.','Photosynthesis is essential for the survival of almost all life on Earth.','NOUN','Quá trình thực vật xanh sử dụng ánh sáng mặt trời để tổng hợp chất dinh dưỡng từ CO2 và nước.','Quang hợp là điều thiết yếu cho sự sống của hầu hết mọi sinh vật trên Trái đất.','Quá trình quang hợp',1717,NULL,_binary '\0'),(1816,'An organism, especially a soil bacterium, fungus, or invertebrate, that decomposes organic material.','Fungi act as important decomposers in the forest ecosystem.','NOUN','Sinh vật phân hủy các vật chất hữu cơ, đặc biệt là vi khuẩn đất, nấm hoặc động vật không xương sống.','Nấm đóng vai trò là sinh vật phân giải quan trọng trong hệ sinh thái rừng.','Sinh vật phân giải',1718,NULL,_binary '\0'),(1817,'A system of interlocking and interdependent food chains.','The introduction of a new predator can disrupt the entire food web.','NOUN','Hệ thống các chuỗi thức ăn đan xen và phụ thuộc lẫn nhau.','Sự xuất hiện của một loài săn mồi mới có thể làm xáo trộn toàn bộ lưới thức ăn.','Lưới thức ăn',1719,NULL,_binary '\0'),(1819,'Areas where water covers the soil, or is present either at or near the surface of the soil all year.','Wetlands act as natural filters for water and provide habitats for many birds.','NOUN','Các khu vực nước bao phủ đất, hoặc hiện diện tại/gần bề mặt đất quanh năm.','Vùng đất ngập nước đóng vai trò như bộ lọc nước tự nhiên và cung cấp môi trường sống cho nhiều loài chim.','Vùng đất ngập nước',1721,NULL,_binary '\0'),(1821,'A layer of vegetation beneath the main canopy of a forest.','Plants in the understory are adapted to low light conditions.','NOUN','Lớp thực vật bên dưới tán rừng chính.','Thực vật ở tầng dưới tán thích nghi với điều kiện ánh sáng thấp.','Tầng dưới tán',1723,NULL,_binary '\0'),(1823,'Seasonal movement of animals from one region to another.','The annual migration of wildebeests is a spectacular event.','NOUN','Sự di chuyển theo mùa của động vật từ vùng này sang vùng khác.','Sự di cư hàng năm của linh dương đầu bò là một sự kiện ngoạn mục.','Sự di cư',1725,NULL,_binary '\0'),(1824,'An animal that naturally preys on others.','Lions are top predators in the African savanna.','NOUN','Động vật săn bắt các loài khác một cách tự nhiên.','Sư tử là loài săn mồi hàng đầu ở thảo nguyên châu Phi.','Động vật săn mồi',1726,NULL,_binary '\0'),(1825,'A substance that makes something less pure or makes it poisonous.','The spring water was tested for bacterial contaminants.','NOUN','Một chất làm cho thứ gì đó kém tinh khiết hơn hoặc gây độc.','Nước suối đã được kiểm tra các chất gây ô nhiễm vi khuẩn.','Chất gây ô nhiễm',1727,NULL,_binary '\0'),(1827,'A place where garbage is buried.','The city is running out of space for new landfill sites.','NOUN','Nơi rác thải được chôn dưới đất.','Thành phố đang hết chỗ cho các bãi chôn lấp rác mới.','Bãi chôn lấp rác',1729,NULL,_binary '\0'),(1829,'The process of burning something completely.','Waste-to-energy plants use incineration to generate electricity.','NOUN','Quá trình đốt cháy hoàn toàn thứ gì đó.','Các nhà máy biến rác thành năng lượng sử dụng việc đốt rác để tạo ra điện.','Sự thiêu hủy / Đốt rác',1731,NULL,_binary '\0'),(1830,'Solid particles and liquid droplets found in the air.','High levels of particulate matter can cause respiratory problems.','NOUN','Các hạt rắn và giọt lỏng tìm thấy trong không khí.','Nồng độ bụi mịn cao có thể gây ra các vấn đề về hô hấp.','Bụi mịn / Vật chất hạt',1732,NULL,_binary '\0'),(1831,'Waste that is dangerous or potentially harmful to our health or the environment.','Old batteries and chemicals must be disposed of as hazardous waste.','NOUN','Chất thải gây nguy hiểm hoặc có tiềm năng gây hại cho sức khỏe hoặc môi trường.','Pin cũ và hóa chất phải được xử lý như chất thải nguy hại.','Chất thải nguy hại',1733,NULL,_binary '\0'),(1832,'A type of air pollution that looks like a mixture of smoke and fog.','Many major cities suffer from thick smog during the winter months.','NOUN','Một loại ô nhiễm không khí trông giống như hỗn hợp của khói và sương mù.','Nhiều thành phố lớn phải chịu cảnh sương khói dày đặc trong những tháng mùa đông.','Khói lẫn sương (Sương quang hóa)',1734,NULL,_binary '\0'),(1833,'Excessive richness of nutrients in a body of water, frequently due to runoff from the land, which causes a dense growth of plant life.','Eutrophication leads to oxygen depletion in lakes, killing fish.','NOUN','Sự dư thừa chất dinh dưỡng trong vực nước, thường do rửa trôi đất, gây ra sự phát triển dày đặc của thực vật.','Hiện tượng phú dưỡng dẫn đến cạn kiệt oxy trong hồ, làm chết cá.','Hiện tượng phú dưỡng',1735,NULL,_binary '\0'),(1834,'Extremely small pieces of plastic in the environment resulting from the disposal and breakdown of consumer products.','Microplastics have been found in the deepest parts of the ocean.','NOUN','Những mảnh nhựa cực nhỏ trong môi trường là kết quả của việc thải bỏ và phân hủy các sản phẩm tiêu dùng.','Vi nhựa đã được tìm thấy ở những phần sâu nhất của đại dương.','Vi nhựa',1736,NULL,_binary '\0'),(1835,'The process of collecting and allowing organic waste to decompose to be used as fertilizer.','Composting food scraps is an easy way to reduce household waste.','NOUN','Quá trình thu thập và để chất thải hữu cơ phân hủy để sử dụng làm phân bón.','Ủ phân từ vụn thức ăn là một cách dễ dàng để giảm rác thải sinh hoạt.','Sự ủ phân hữu cơ',1737,NULL,_binary '\0'),(1836,'The action of remedying something, especially the reversal or stopping of environmental damage.','The cost of soil remediation at the old industrial site was very high.','NOUN','Hành động khắc phục điều gì đó, đặc biệt là đảo ngược hoặc ngăn chặn thiệt hại môi trường.','Chi phí khắc phục đất tại địa điểm công nghiệp cũ là rất cao.','Sự khắc phục (môi trường)',1738,NULL,_binary '\0'),(1837,'A colorless, odorless radioactive gas that can cause cancer.','Basements should be tested for radon to ensure indoor air safety.','NOUN','Một loại khí phóng xạ không màu, không mùi có thể gây ung thư.','Các tầng hầm nên được kiểm tra khí radon để đảm bảo an toàn không khí trong nhà.','Khí Radon',1739,NULL,_binary '\0'),(1838,'Water from rain or snow that flows over the surface of the ground into streams.','Agricultural runoff often contains high levels of nitrogen and phosphorus.','NOUN','Nước từ mưa hoặc tuyết chảy trên bề mặt đất vào các dòng suối.','Nước chảy tràn từ nông nghiệp thường chứa hàm lượng nitơ và phốt pho cao.','Nước chảy tràn',1740,NULL,_binary '\0'),(1839,'The process of separating waste into different categories for recycling.','Automated sorting systems have improved the efficiency of recycling centers.','NOUN','Quá trình tách chất thải thành các danh mục khác nhau để tái chế.','Hệ thống phân loại tự động đã cải thiện hiệu quả của các trung tâm tái chế.','Sự phân loại (rác)',1741,NULL,_binary '\0'),(1842,'The establishment of a forest or stand of trees in an area where there was no previous tree cover.','Afforestation can help prevent soil erosion in previously barren lands.','NOUN','Việc thiết lập một khu rừng hoặc rặng cây ở một khu vực trước đây không có cây bao phủ.','Trồng rừng mới có thể giúp ngăn ngừa xói mòn đất ở những vùng đất khô cằn trước đây.','Sự trồng rừng mới',1744,NULL,_binary '\0'),(1843,'The activity or business of cutting down trees for lumber.','Illegal logging remains a significant threat to protected national parks.','NOUN','Hoạt động hoặc công việc kinh doanh chặt hạ cây cối để lấy gỗ.','Khai thác gỗ lậu vẫn là một mối đe dọa lớn đối với các vườn quốc gia được bảo vệ.','Khai thác gỗ',1745,NULL,_binary '\0'),(1844,'A logging practice in which most or all trees in a specific area are uniformly cut down.','Clear-cutting can lead to severe soil degradation and loss of wildlife.','NOUN','Một phương pháp khai thác gỗ trong đó hầu hết hoặc tất cả cây cối trong một khu vực cụ thể bị chặt hạ đồng loạt.','Chặt trắng có thể dẫn đến suy thoái đất nghiêm trọng và mất đi động vật hoang dã.','Chặt trắng',1746,NULL,_binary '\0'),(1847,'The process by which large, continuous habitats are divided into smaller, isolated patches.','Fragmentation makes it difficult for large mammals to find enough food.','NOUN','Quá trình chia cắt các môi trường sống lớn, liên tục thành các mảng nhỏ và cô lập.','Sự phân mảnh khiến các loài động vật có vú lớn khó tìm đủ thức ăn.','Sự phân mảnh môi trường sống',1749,NULL,_binary '\0'),(1848,'The wearing away of the top layer of soil by water, wind, or human activity.','Trees help prevent soil erosion by holding the earth with their roots.','NOUN','Sự bào mòn lớp đất mặt bởi nước, gió hoặc hoạt động của con người.','Cây xanh giúp ngăn ngừa xói mòn đất bằng cách giữ đất bằng rễ của chúng.','Xói mòn đất',1750,NULL,_binary '\0'),(1849,'The practice of managing forests to meet current needs for wood while preserving the forest for future generations.','Sustainable forestry involves selective logging and extensive replanting.','NOUN','Việc quản lý rừng để đáp ứng nhu cầu hiện tại về gỗ trong khi vẫn bảo tồn rừng cho các thế hệ tương lai.','Lâm nghiệp bền vững bao gồm khai thác gỗ có chọn lọc và trồng lại rừng trên diện rộng.','Lâm nghiệp bền vững',1751,NULL,_binary '\0'),(1850,'An area of land that separates waters flowing to different rivers, basins, or seas.','Forests protect watersheds by regulating water flow and filtering pollutants.','NOUN','Một khu vực đất ngăn cách các dòng nước chảy vào các con sông, lưu vực hoặc biển khác nhau.','Rừng bảo vệ các lưu vực bằng cách điều tiết dòng chảy của nước và lọc các chất ô nhiễm.','Lưu vực / Đường phân thủy',1752,NULL,_binary '\0'),(1852,'A forest, ocean, or other natural environment viewed in terms of its ability to absorb carbon dioxide from the atmosphere.','The Amazon rainforest acts as a massive carbon sink for the planet.','NOUN','Một khu rừng, đại dương hoặc môi trường tự nhiên khác được xem xét dựa trên khả năng hấp thụ CO2 từ khí quyển.','Rừng mưa Amazon đóng vai trò như một bể chứa carbon khổng lồ cho hành tinh.','Bể chứa carbon',1754,NULL,_binary '\0'),(1853,'The act of using too much of a natural resource, so that there is not enough left.','The overexploitation of timber resources has led to local forest depletion.','NOUN','Hành động sử dụng quá nhiều một tài nguyên thiên nhiên, khiến nó không còn đủ.','Khai thác quá mức tài nguyên gỗ đã dẫn đến sự cạn kiệt rừng tại địa phương.','Khai thác quá mức',1755,NULL,_binary '\0'),(1856,'The power or authority of a state to govern itself or another state.','The government is determined to protect the country’s national sovereignty.','NOUN','Quyền lực hoặc thẩm quyền của một quốc gia trong việc tự quản lý hoặc quản lý một quốc gia khác.','Chính phủ quyết tâm bảo vệ chủ quyền quốc gia.','Chủ quyền',1758,NULL,_binary '\0'),(1857,'The principle of participation by three or more parties, especially rival nations, in a common action.','The United Nations is a cornerstone of global multilateralism.','NOUN','Nguyên tắc tham gia của ba hoặc nhiều bên, đặc biệt là các quốc gia đối thủ, trong một hành động chung.','Liên Hợp Quốc là nền tảng của chủ nghĩa đa phương toàn cầu.','Chủ nghĩa đa phương',1759,NULL,_binary '\0'),(1860,'A strong action taken by one or more nations toward another nation to force it to obey international law.','The UN imposed economic sanctions on the regime to stop the violence.','NOUN','Một hành động mạnh mẽ của một hoặc nhiều quốc gia đối với quốc gia khác để buộc quốc gia đó tuân thủ luật pháp quốc tế.','Liên Hợp Quốc đã áp đặt các lệnh trừng phạt kinh tế lên chế độ này để ngăn chặn bạo lực.','Lệnh trừng phạt',1762,NULL,_binary '\0'),(1862,'Leadership or dominance, especially by one country or social group over others.','The rise of a new power challenged the existing global hegemony.','NOUN','Sự lãnh đạo hoặc thống trị, đặc biệt là của một quốc gia hoặc nhóm xã hội đối với những bên khác.','Sự trỗi dậy của một cường quốc mới đã thách thức quyền bá chủ toàn cầu hiện tại.','Sự bá quyền / Quyền bá chủ',1764,NULL,_binary '\0'),(1863,'The process in which a minority group or culture comes to resemble a society’s majority group.','Immigrants often struggle with the balance between cultural assimilation and preserving their heritage.','NOUN','Quá trình mà một nhóm hoặc nền văn hóa thiểu số trở nên giống với nhóm đa số của xã hội.','Người nhập cư thường đấu tranh để cân bằng giữa sự đồng hóa văn hóa và việc bảo tồn di sản.','Sự đồng hóa văn hóa',1765,NULL,_binary '\0'),(1864,'The movement towards political cooperation among transnational actors, aimed at negotiating responses to problems that affect more than one state.','Issues like climate change require a strong framework for global governance.','NOUN','Sự hợp tác chính trị giữa các tác nhân xuyên quốc gia nhằm đàm phán giải pháp cho các vấn đề ảnh hưởng đến nhiều quốc gia.','Các vấn đề như biến đổi khí hậu đòi hỏi một khuôn khổ quản trị toàn cầu mạnh mẽ.','Quản trị toàn cầu',1766,NULL,_binary '\0'),(1866,'A non-profit organization that operates independently of any government, typically one whose purpose is to address a social or political issue.','The NGO provides emergency medical relief in conflict zones.','NOUN','Một tổ chức phi lợi nhuận hoạt động độc lập với chính phủ, thường nhằm giải quyết các vấn đề xã hội hoặc chính trị.','Tổ chức phi chính phủ này cung cấp cứu trợ y tế khẩn cấp tại các vùng xung đột.','Tổ chức phi chính phủ',1768,NULL,_binary '\0'),(1867,'Extending or operating across national boundaries.','Transnational corporations have a massive influence on the world economy.','ADJECTIVE','Mở rộng hoặc vận hành vượt qua biên giới quốc gia.','Các tập đoàn xuyên quốc gia có tầm ảnh hưởng khổng lồ lên nền kinh tế thế giới.','Xuyên quốc gia',1769,NULL,_binary '\0'),(1868,'Dislike of or prejudice against people from other countries.','Globalization can sometimes lead to a rise in nationalism and xenophobia.','NOUN','Sự không thích hoặc định kiến đối với những người đến từ các quốc gia khác.','Toàn cầu hóa đôi khi có thể dẫn đến sự gia tăng chủ nghĩa dân tộc và bài ngoại.','Chứng sợ người lạ / Bài ngoại',1770,NULL,_binary '\0'),(1869,'Involving two parties, especially countries.','The two nations signed a bilateral trade agreement yesterday.','ADJECTIVE','Liên quan đến hai bên, đặc biệt là hai quốc gia.','Hai quốc gia đã ký kết một hiệp định thương mại song phương vào hôm qua.','Song phương',1771,NULL,_binary '\0'),(1870,'The rapid and often poorly planned spread of cities and suburbs into surrounding areas.','Urban sprawl often leads to increased dependence on cars and loss of farmland.','NOUN','Sự lan rộng nhanh chóng và thường thiếu quy hoạch của các thành phố vào các khu vực xung quanh.','Sự mở rộng đô thị vô độ thường dẫn đến việc gia tăng sự phụ thuộc vào ô tô và mất đất canh tác.','Sự mở rộng đô thị (vô độ)',1772,NULL,_binary '\0'),(1871,'A very large city, typically one with a population of over ten million people.','Tokyo is one of the world’s most populous megacities.','NOUN','Một thành phố rất lớn, thường có dân số trên mười triệu người.','Tokyo là một trong những siêu đô thị đông dân nhất thế giới.','Siêu đô thị',1773,NULL,_binary '\0'),(1872,'The process of changing the character of a neighborhood through the influx of more affluent residents and businesses.','Gentrification often forces low-income families to move out of their original neighborhoods.','NOUN','Quá trình thay đổi đặc điểm của một khu phố thông qua sự đổ bộ của những cư dân và doanh nghiệp giàu có hơn.','Sự quý tộc hóa thường buộc các gia đình thu nhập thấp phải chuyển khỏi khu phố cũ của họ.','Sự chỉnh trang đô thị / Quý tộc hóa',1774,NULL,_binary '\0'),(1875,'A very large city, often the most important city in a large area or country.','Ho Chi Minh City is a bustling metropolis and the economic heart of Vietnam.','NOUN','Một thành phố rất lớn, thường là quan trọng nhất trong một khu vực rộng lớn hoặc một quốc gia.','Thành phố Hồ Chí Minh là một đô thị sầm uất và là trái tim kinh tế của Việt Nam.','Đô thị lớn / Thủ phủ',1777,NULL,_binary '\0'),(1876,'An urban development that maximizes the amount of residential, business and leisure space within walking distance of public transport.','TOD aims to create walkable communities and reduce dependence on private vehicles.','NOUN','Quy hoạch đô thị tối đa hóa không gian ở và làm việc trong khoảng cách đi bộ đến các phương tiện công cộng.','TOD nhằm tạo ra các cộng đồng thân thiện với người đi bộ và giảm sự phụ thuộc vào xe cá nhân.','Phát triển định hướng giao thông công cộng',1778,NULL,_binary '\0'),(1877,'The network of physical objects embedded with sensors and software for the purpose of connecting and exchanging data.','IoT technology allows smart streetlights to dim when no one is around.','NOUN','Mạng lưới các vật thể vật lý được nhúng cảm biến và phần mềm để kết nối và trao đổi dữ liệu.','Công nghệ IoT cho phép đèn đường thông minh giảm độ sáng khi không có người xung quanh.','Mạng lưới vạn vật kết nối',1779,NULL,_binary '\0'),(1878,'The process of urban growth that meets the needs of the present without compromising the ability of future generations.','Sustainable urbanization focuses on green spaces and efficient waste management.','NOUN','Quá trình tăng trưởng đô thị đáp ứng nhu cầu hiện tại mà không làm tổn hại đến khả năng của các thế hệ tương lai.','Đô thị hóa bền vững tập trung vào không gian xanh và quản lý chất thải hiệu quả.','Đô thị hóa bền vững',1780,NULL,_binary '\0'),(1879,'Systems for taking dirty water and other waste products away from buildings in order to protect people’s health.','Many slums in megacities lack proper sanitation facilities.','NOUN','Các hệ thống dẫn nước bẩn và chất thải ra khỏi các tòa nhà để bảo vệ sức khỏe con người.','Nhiều khu ổ chuột ở các siêu đô thị thiếu các cơ sở vệ sinh phù hợp.','Hệ thống vệ sinh',1781,NULL,_binary '\0'),(1881,'The qualities that make a place a good place to live.','The city council is working to improve the livability of the downtown area.','NOUN','Các đặc điểm khiến một nơi trở thành nơi đáng sống.','Hội đồng thành phố đang nỗ lực cải thiện chất lượng sống của khu vực trung tâm.','Khả năng sống tốt / Chất lượng sống',1783,NULL,_binary '\0'),(1882,'The number of people or things in a particular area in relation to its size.','The high population density in the city center leads to expensive housing.','NOUN','Số lượng người hoặc vật trong một khu vực cụ thể so với diện tích của nó.','Mật độ dân số cao ở trung tâm thành phố dẫn đến giá nhà ở đắt đỏ.','Mật độ',1784,NULL,_binary '\0'),(1886,'The average number of children born to women during their reproductive years.','A declining fertility rate can lead to a shrinking workforce in the future.','NOUN','Số lượng con trung bình mà một người phụ nữ sinh ra trong độ tuổi sinh đẻ.','Tỷ suất sinh giảm có thể dẫn đến lực lượng lao động bị thu hẹp trong tương lai.','Tỷ suất sinh',1788,NULL,_binary '\0'),(1887,'The number of deaths in a particular population during a specific period.','Improved healthcare has significantly lowered the infant mortality rate.','NOUN','Số ca tử vong trong một quần thể nhất định trong một khoảng thời gian cụ thể.','Y tế cải thiện đã làm giảm đáng kể tỷ lệ tử vong ở trẻ sơ sinh.','Tỷ lệ tử vong',1789,NULL,_binary '\0'),(1888,'The average period that a person may expect to live.','Life expectancy has increased worldwide due to better nutrition and medicine.','NOUN','Khoảng thời gian trung bình mà một người có thể kỳ vọng sẽ sống.','Tuổi thọ trung bình đã tăng trên toàn thế giới nhờ dinh dưỡng và y tế tốt hơn.','Tuổi thọ trung bình',1790,NULL,_binary '\0'),(1889,'An increase in the median age of a population due to declining fertility and rising life expectancy.','Japan is facing significant economic challenges due to its rapidly aging population.','NOUN','Sự gia tăng độ tuổi trung bình của một quần thể do tỷ suất sinh giảm và tuổi thọ tăng.','Nhật Bản đang đối mặt với những thách thức kinh tế lớn do dân số già hóa nhanh chóng.','Dân số già',1791,NULL,_binary '\0'),(1890,'An age-population ratio of those typically not in the labor force and those typically in the labor force.','A high dependency ratio puts a heavy burden on the tax-paying workforce.','NOUN','Tỷ lệ giữa những người không nằm trong lực lượng lao động (trẻ em, người già) và những người trong lực lượng lao động.','Tỷ lệ phụ thuộc cao gây áp lực nặng nề lên lực lượng lao động đóng thuế.','Tỷ lệ phụ thuộc',1792,NULL,_binary '\0'),(1893,'The condition of having a population so dense as to cause environmental deterioration or an impaired quality of life.','Overpopulation can strain a country’s natural resources and infrastructure.','NOUN','Tình trạng dân số quá đông đúc gây suy thoái môi trường hoặc suy giảm chất lượng cuộc sống.','Quá tải dân số có thể làm cạn kiệt tài nguyên thiên nhiên và cơ sở hạ tầng của một quốc gia.','Sự bùng nổ dân số / Quá tải dân số',1795,NULL,_binary '\0'),(1894,'A graphical illustration that shows the distribution of various age groups in a population.','The population pyramid of a developing country usually has a wide base.','NOUN','Minh họa đồ họa thể hiện sự phân bố của các nhóm tuổi khác nhau trong một quần thể.','Tháp dân số của một quốc gia đang phát triển thường có phần đáy rộng.','Tháp dân số',1796,NULL,_binary '\0'),(1896,'An official count or survey of a population, typically recording various details of individuals.','The government conducts a national census every ten years.','NOUN','Việc đếm hoặc khảo sát chính thức một quần thể, thường ghi lại các chi tiết khác nhau về cá nhân.','Chính phủ tiến hành điều tra dân số quốc gia mười năm một lần.','Cuộc điều tra dân số',1798,NULL,_binary '\0'),(1897,'The fertility rate at which a population exactly replaces itself from one generation to the next.','Most developed nations have fertility rates below the replacement level.','NOUN','Tỷ suất sinh mà tại đó một quần thể tự thay thế chính xác từ thế hệ này sang thế hệ tiếp theo.','Hầu hết các quốc gia phát triển đều có tỷ suất sinh dưới mức thay thế.','Mức sinh thay thế',1799,NULL,_binary '\0'),(1898,'The economic growth potential that can result from shifts in a population’s age structure.','Vietnam is currently benefiting from its demographic dividend.','NOUN','Tiềm năng tăng trưởng kinh tế có thể có được từ sự thay đổi trong cấu trúc tuổi của dân số.','Việt Nam hiện đang hưởng lợi từ cơ cấu dân số vàng.','Cơ cấu dân số vàng / Lợi tức nhân khẩu học',1800,NULL,_binary '\0'),(1901,'An environment in which a person encounters only beliefs and opinions that coincide with their own.','Social media can create echo chambers where users are never exposed to opposing views.','NOUN','Môi trường mà một người chỉ tiếp xúc với những niềm tin và ý kiến trùng khớp với ý kiến của chính họ.','Mạng xã hội có thể tạo ra các phòng kín tiếng vang nơi người dùng không bao giờ tiếp xúc với các quan điểm trái chiều.','Phòng kín tiếng vang / Hiệu ứng lồng kính',1803,NULL,_binary '\0'),(1902,'Circulated rapidly and widely from one internet user to another.','The video went viral within hours of being posted.','ADJECTIVE','Được lan truyền nhanh chóng và rộng rãi từ người dùng internet này sang người dùng khác.','Video đó đã lan truyền chóng mặt chỉ trong vài giờ sau khi đăng tải.','Lan truyền nhanh chóng (vi-rút)',1804,NULL,_binary '\0'),(1903,'The use of electronic communication to bully a person, typically by sending messages of an intimidating or threatening nature.','Schools are implementing new policies to combat cyberbullying.','NOUN','Việc sử dụng liên lạc điện tử để bắt nạt một người, thường bằng cách gửi tin nhắn có tính chất đe dọa.','Các trường học đang triển khai các chính sách mới để chống lại nạn bắt nạt qua mạng.','Bắt nạt qua mạng',1805,NULL,_binary '\0'),(1904,'A person with the ability to influence potential buyers of a product or service by promoting or recommending the items on social media.','Brands are increasingly collaborating with micro-influencers to reach niche markets.','NOUN','Người có khả năng ảnh hưởng đến người mua tiềm năng bằng cách quảng bá hoặc đề xuất các mặt hàng trên mạng xã hội.','Các thương hiệu đang ngày càng hợp tác với những người có ảnh hưởng nhỏ để tiếp cận các thị trường ngách.','Người có sức ảnh hưởng',1806,NULL,_binary '\0'),(1905,'The information about a particular person that exists on the internet as a result of their online activity.','It is important to be mindful of your digital footprint when applying for jobs.','NOUN','Thông tin về một người cụ thể tồn tại trên internet do kết quả của hoạt động trực tuyến của họ.','Điều quan trọng là phải lưu ý đến dấu chân số của bạn khi nộp đơn xin việc.','Dấu chân số',1807,NULL,_binary '\0'),(1907,'False or inaccurate information that is spread, regardless of intent to deceive.','Social media platforms are under pressure to flag health misinformation.','NOUN','Thông tin sai hoặc không chính xác được lan truyền, bất kể có ý định lừa dối hay không.','Các nền tảng mạng xã hội đang chịu áp lực phải gắn thẻ các thông tin sai lệch về sức khỏe.','Thông tin sai lệch',1809,NULL,_binary '\0'),(1908,'The controls available on social networking sites which let users decide who can see their information.','Check your privacy settings regularly to protect your personal data.','NOUN','Các quyền kiểm soát trên mạng xã hội cho phép người dùng quyết định ai có thể xem thông tin của họ.','Hãy kiểm tra cài đặt quyền riêng tư thường xuyên để bảo vệ dữ liệu cá nhân của bạn.','Cài đặt quyền riêng tư',1810,NULL,_binary '\0'),(1909,'Content whose main purpose is to attract attention and encourage visitors to click on a link to a particular web page.','Many news sites use sensational clickbait to drive traffic to their articles.','NOUN','Nội dung có mục đích chính là thu hút sự chú ý và khuyến khích người xem nhấp vào một liên kết.','Nhiều trang tin tức sử dụng mồi nhấp chuột giật gân để dẫn lưu lượng truy cập vào bài báo của họ.','Mồi nhấp chuột',1811,NULL,_binary '\0'),(1910,'The process of gathering large amounts of data from websites, often for marketing or research purposes.','Unauthorized data harvesting remains a major concern for online privacy.','NOUN','Quá trình thu thập lượng lớn dữ liệu từ các trang web, thường cho mục đích tiếp thị hoặc nghiên cứu.','Thu thập dữ liệu trái phép vẫn là một mối lo ngại lớn đối với quyền riêng tư trực tuyến.','Thu thập dữ liệu / Khai thác dữ liệu',1812,NULL,_binary '\0'),(1911,'The situation in which someone’s name is not given or known.','The internet provides a degree of anonymity that can encourage honest discussion or toxic behavior.','NOUN','Tình trạng mà tên của ai đó không được đưa ra hoặc không được biết đến.','Internet cung cấp một mức độ ẩn danh có thể khuyến khích thảo luận trung thực hoặc các hành vi độc hại.','Sự ẩn danh',1813,NULL,_binary '\0'),(1912,'The process of earning money from an asset, business, or content.','Content creators explore various monetization strategies, including sponsorships and ads.','NOUN','Quá trình kiếm tiền từ một tài sản, doanh nghiệp hoặc nội dung.','Các nhà sáng tạo nội dung khám phá nhiều chiến lược kiếm tiền khác nhau, bao gồm quảng cáo và tài trợ.','Sự kiếm tiền (từ nội dung)',1814,NULL,_binary '\0'),(1913,'The involvement of users in the communication process, allowing them to influence the content.','The high level of interactivity on live streaming platforms builds a strong community.','NOUN','Sự tham gia của người dùng vào quá trình giao tiếp, cho phép họ ảnh hưởng đến nội dung.','Tính tương tác cao trên các nền tảng phát trực tiếp xây dựng một cộng đồng mạnh mẽ.','Tính tương tác',1815,NULL,_binary '\0'),(1914,'Any form of content, such as images, videos, text, and audio, that has been posted by users on online platforms.','UGC is often perceived as more authentic than traditional advertising.','NOUN','Bất kỳ hình thức nội dung nào được đăng bởi người dùng trên các nền tảng trực tuyến.','Nội dung do người dùng tạo ra thường được coi là xác thực hơn quảng cáo truyền thống.','Nội dung do người dùng tạo ra',1816,NULL,_binary '\0'),(1917,'The belief that different cultures within a society should all be given importance.','Multiculturalism has enriched the culinary scene of many major cities.','NOUN','Niềm tin rằng các nền văn hóa khác nhau trong một xã hội đều nên được coi trọng.','Chủ nghĩa đa văn hóa đã làm phong phú thêm bức tranh ẩm thực của nhiều thành phố lớn.','Chủ nghĩa đa văn hóa',1819,NULL,_binary '\0'),(1919,'The act of treating a person or group as insignificant or peripheral.','The marginalization of certain ethnic groups often results in high poverty rates.','NOUN','Hành động đối xử với một người hoặc nhóm người như thể họ không quan trọng hoặc nằm bên lề.','Việc gạt các nhóm dân tộc nhất định ra ngoài lề thường dẫn đến tỷ lệ nghèo đói cao.','Sự gạt ra ngoài lề xã hội',1821,NULL,_binary '\0'),(1920,'A person who lives outside their native country.','There is a large expatriate community living in Ho Chi Minh City.','NOUN','Một người sống bên ngoài quốc gia quê hương của họ.','Có một cộng đồng người nước ngoài lớn đang sinh sống tại Thành phố Hồ Chí Minh.','Người biệt xứ / Người làm việc tại nước ngoài',1822,NULL,_binary '\0'),(1921,'A person who has been forced to leave their country in order to escape war, persecution, or natural disaster.','The international community must provide support for millions of refugees.','NOUN','Một người buộc phải rời khỏi đất nước của mình để thoát khỏi chiến tranh, đàn áp hoặc thiên tai.','Cộng đồng quốc tế phải hỗ trợ cho hàng triệu người tị nạn.','Người tị nạn',1823,NULL,_binary '\0'),(1922,'A person who has left their home country and is seeking protective status in another country.','The government is reviewing the applications of hundreds of asylum seekers.','NOUN','Người đã rời bỏ quê hương và đang tìm kiếm tư cách được bảo vệ tại một quốc gia khác.','Chính phủ đang xem xét đơn đăng ký của hàng trăm người xin tị nạn.','Người xin tị nạn',1824,NULL,_binary '\0'),(1923,'The process of cultural change and psychological change that results following meeting between cultures.','Acculturation can lead to the adoption of new customs while retaining original traditions.','NOUN','Quá trình thay đổi văn hóa và tâm lý diễn ra sau sự gặp gỡ giữa các nền văn hóa.','Tiếp biến văn hóa có thể dẫn đến việc tiếp nhận các phong tục mới trong khi vẫn giữ lại các truyền thống ban đầu.','Sự tiếp biến văn hóa',1825,NULL,_binary '\0'),(1924,'A sum of money sent in payment or as a gift, typically by a migrant to their home country.','Remittances from overseas workers play a vital role in the economy of many developing nations.','NOUN','Số tiền được gửi đi để thanh toán hoặc làm quà tặng, thường là bởi người di cư gửi về quê hương.','Kiều hối từ lao động ở nước ngoài đóng vai trò quan trọng trong nền kinh tế của nhiều quốc gia đang phát triển.','Kiều hối / Tiền gửi về',1826,NULL,_binary '\0'),(1925,'A group of people who spread from one original country to other countries.','The Vietnamese diaspora has established vibrant communities in various parts of the world.','NOUN','Một nhóm người tản mát từ một quốc gia gốc sang các quốc gia khác.','Cộng đồng người Việt hải ngoại đã thiết lập các cộng đồng sôi động ở nhiều nơi trên thế giới.','Cộng đồng hải ngoại / Sự ly tán',1827,NULL,_binary '\0'),(1927,'The action or state of including or being included within a group or structure.','Social inclusion programs aim to provide equal opportunities for all citizens.','NOUN','Hành động hoặc trạng thái bao gồm hoặc được bao gồm trong một nhóm hoặc cấu trúc.','Các chương trình hòa nhập xã hội nhằm cung cấp cơ hội bình đẳng cho tất cả công dân.','Sự bao hàm / Sự hòa nhập',1829,NULL,_binary '\0'),(1928,'The legal process by which a non-citizen in a country may acquire citizenship.','After living in the country for five years, they applied for naturalization.','NOUN','Quá trình pháp lý mà qua đó một người không phải là công dân của một quốc gia có thể có được quốc tịch.','Sau khi sống ở đất nước này 5 năm, họ đã nộp đơn xin nhập quốc tịch.','Sự nhập quốc tịch',1830,NULL,_binary '\0'),(1929,'An increase in the number of highly trained or intelligent people in a country due to emigration.','Developing nations hope to experience a brain gain when their citizens return home with new skills.','NOUN','Sự gia tăng số lượng những người được đào tạo cao hoặc thông minh vào một quốc gia nhờ di cư.','Các quốc gia đang phát triển hy vọng có được sự thu hút chất xám khi công dân của họ trở về nhà với những kỹ năng mới.','Thu hút chất xám',1831,NULL,_binary '\0'),(1931,'The action of excavating something, especially an archaeological site.','The excavation revealed the remains of a Roman villa.','NOUN','Hành động đào bới thứ gì đó, đặc biệt là tại một địa điểm khảo cổ.','Cuộc khai quật đã hé lộ tàn tích của một biệt thự La Mã.','Sự khai quật',1833,NULL,_binary '\0'),(1933,'Traditions or living expressions inherited from our ancestors and passed on to our descendants.','Traditional music and folklore are part of a nation’s intangible heritage.','NOUN','Các truyền thống hoặc biểu hiện sống được thừa hưởng từ tổ tiên và truyền lại cho hậu thế.','Âm nhạc truyền thống và văn học dân gian là một phần của di sản phi vật thể quốc gia.','Di sản phi vật thể',1835,NULL,_binary '\0'),(1936,'The family or the race of people that you come from.','He was able to trace his ancestry back to the 18th century.','NOUN','Gia đình hoặc chủng tộc người mà bạn xuất thân từ đó.','Anh ấy đã có thể truy cứu dòng dõi của mình về tận thế kỷ 18.','Tổ tiên / Dòng dõi',1838,NULL,_binary '\0'),(1937,'Writing consisting of pictures, used in ancient Egypt.','Scholars spent years trying to decipher the ancient hieroglyphics.','NOUN','Hệ thống chữ viết bao gồm các hình vẽ, được sử dụng ở Ai Cập cổ đại.','Các học giả đã dành nhiều năm để cố gắng giải mã chữ tượng hình cổ đại.','Chữ tượng hình',1839,NULL,_binary '\0'),(1938,'The shape of a bone, a shell, or a plant or animal that has been preserved in rock for a very long period.','The team found a dinosaur fossil during their field trip.','NOUN','Hình dạng của xương, vỏ sò, hoặc thực vật/động vật đã được bảo tồn trong đá trong một thời gian rất dài.','Nhóm nghiên cứu đã tìm thấy hóa thạch khủng long trong chuyến khảo sát thực địa.','Hóa thạch',1840,NULL,_binary '\0'),(1942,'Words that are written or cut in something, e.g., a stone or a coin.','The inscription on the gravestone was barely legible.','NOUN','Những chữ được viết hoặc khắc vào thứ gì đó, ví dụ như đá hoặc đồng xu.','Dòng chữ khắc trên bia mộ hầu như không thể đọc được.','Câu chữ khắc',1844,NULL,_binary '\0'),(1944,'A landmark or area with legal protection by an international convention for having cultural, historical, or scientific significance.','Ha Long Bay was recognized as a UNESCO World Heritage Site in 1994.','NOUN','Một danh lam thắng cảnh hoặc khu vực được bảo vệ pháp lý bởi một công ước quốc tế vì có tầm quan trọng về văn hóa, lịch sử hoặc khoa học.','Vịnh Hạ Long đã được UNESCO công nhận là Di sản Thế giới vào năm 1994.','Di sản Thế giới',1846,NULL,_binary '\0'),(1945,'A group of rights that have been recognized by a high degree of protection from encroachment.','Freedom of speech is considered one of the fundamental rights in a democracy.','NOUN','Nhóm các quyền được công nhận với mức độ bảo vệ cao khỏi sự xâm phạm.','Tự do ngôn luận được coi là một trong những quyền cơ bản trong một nền dân chủ.','Quyền cơ bản',1847,NULL,_binary '\0'),(1946,'The unjust or prejudicial treatment of different categories of people, especially on the grounds of race, age, or sex.','The law prohibits discrimination in the workplace based on gender.','NOUN','Sự đối xử không công bằng hoặc có định kiến đối với các nhóm người khác nhau, đặc biệt là dựa trên chủng tộc, tuổi tác hoặc giới tính.','Luật pháp nghiêm cấm phân biệt đối xử tại nơi làm việc dựa trên giới tính.','Sự phân biệt đối xử',1848,NULL,_binary '\0'),(1947,'Justice in terms of the distribution of wealth, opportunities, and privileges within a society.','Many activists dedicate their lives to fighting for social justice.','NOUN','Sự công bằng trong việc phân phối của cải, cơ hội và đặc quyền trong một xã hội.','Nhiều nhà hoạt động cống hiến cả cuộc đời để đấu tranh cho công bằng xã hội.','Công bằng xã hội',1849,NULL,_binary '\0'),(1949,'The process of becoming stronger and more confident, especially in controlling one’s life and claiming one’s rights.','Women’s empowerment is a key goal of global development programs.','NOUN','Quá trình trở nên mạnh mẽ và tự tin hơn, đặc biệt là trong việc kiểm soát cuộc sống và đòi hỏi quyền lợi cá nhân.','Trao quyền cho phụ nữ là mục tiêu then chốt của các chương trình phát triển toàn cầu.','Sự trao quyền',1851,NULL,_binary '\0'),(1950,'Public support for or recommendation of a particular cause or policy.','The group’s advocacy for child safety led to new legislation.','NOUN','Sự ủng hộ công khai hoặc đề xuất cho một mục tiêu hoặc chính sách cụ thể.','Sự vận động của nhóm vì an toàn trẻ em đã dẫn đến một bộ luật mới.','Sự vận động / Sự ủng hộ',1852,NULL,_binary '\0'),(1951,'Prolonged cruel or unjust treatment or control.','The people rose up against centuries of political oppression.','NOUN','Sự đối xử hoặc kiểm soát tàn bạo hoặc bất công kéo dài.','Người dân đã đứng lên chống lại hàng thế kỷ áp bức chính trị.','Sự áp bức',1853,NULL,_binary '\0'),(1952,'Involved in or connected with improving people’s lives and reducing suffering.','The NGO provided humanitarian aid to the victims of the earthquake.','ADJECTIVE','Liên quan đến việc cải thiện cuộc sống và giảm bớt đau khổ cho con người.','Tổ chức phi chính phủ đã cung cấp viện trợ nhân đạo cho các nạn nhân động đất.','Nhân đạo',1854,NULL,_binary '\0'),(1953,'The rights of citizens to be free from government interference.','During the war, some civil liberties were temporarily suspended.','NOUN','Quyền của công dân được tự do khỏi sự can thiệp quá mức từ chính phủ.','Trong thời chiến, một số quyền tự do dân sự đã bị tạm đình chỉ.','Quyền tự do dân sự',1855,NULL,_binary '\0'),(1954,'A special right, advantage, or immunity granted or available only to a particular person or group.','Education should be a right for all, not a privilege for the wealthy.','NOUN','Một quyền lợi, lợi thế hoặc quyền miễn trừ đặc biệt chỉ dành cho một người hoặc nhóm cụ thể.','Giáo dục nên là quyền của tất cả mọi người, không phải là đặc quyền của người giàu.','Đặc quyền',1856,NULL,_binary '\0'),(1956,'Agreement of feeling or action, especially among individuals with a common interest; mutual support within a group.','The workers showed great solidarity during the strike.','NOUN','Sự đồng thuận về cảm xúc hoặc hành động, đặc biệt là giữa những cá nhân có lợi ích chung.','Các công nhân đã thể hiện sự đoàn kết tuyệt vời trong cuộc bãi công.','Sự đoàn kết',1858,NULL,_binary '\0'),(1957,'A historic document adopted by the United Nations General Assembly that enshrines the rights and freedoms of all human beings.','The UDHR remains a fundamental global standard for human rights.','NOUN','Một văn kiện lịch sử được Đại hội đồng Liên Hợp Quốc thông qua, ghi nhận các quyền và tự do của tất cả con người.','Tuyên ngôn Quốc tế Nhân quyền vẫn là một tiêu chuẩn toàn cầu cơ bản cho quyền con người.','Tuyên ngôn Quốc tế Nhân quyền',1859,NULL,_binary '\0'),(1958,'The fact of being responsible for what you do and able to give a satisfactory reason for it.','Transparency and accountability are essential for a fair legal system.','NOUN','Thực tế của việc chịu trách nhiệm về những gì bạn làm và có khả năng đưa ra lý do thỏa đáng cho việc đó.','Sự minh bạch và trách nhiệm giải trình là thiết yếu cho một hệ thống pháp luật công bằng.','Trách nhiệm giải trình',1860,NULL,_binary '\0'),(1959,'An unfair act or an example of unfair treatment.','The film highlights the social injustice faced by marginalized communities.','NOUN','Một hành động không công bằng hoặc một ví dụ về sự đối xử bất công.','Bộ phim làm nổi bật sự bất công xã hội mà các cộng đồng bị gạt ra ngoài lề phải đối mặt.','Sự bất công',1861,NULL,_binary '\0'),(1963,'Learning something by repeating it until you remember it, rather than by understanding the meaning of it.','Critics argue that rote learning discourages critical thinking and creativity.','NOUN','Việc học thứ gì đó bằng cách lặp đi lặp lại cho đến khi nhớ, thay vì hiểu ý nghĩa của nó.','Các nhà phê bình lập luận rằng học vẹt làm nản lòng tư duy phản biện và sự sáng tạo.','Học vẹt',1865,NULL,_binary '\0'),(1964,'The construction of thought processes, including remembering, problem solving, and decision-making.','Interactive play is crucial for the early cognitive development of children.','NOUN','Việc xây dựng các quá trình suy nghĩ, bao gồm ghi nhớ, giải quyết vấn đề và đưa ra quyết định.','Trò chơi tương tác là tối quan trọng cho sự phát triển nhận thức sớm của trẻ em.','Phát triển nhận thức',1866,NULL,_binary '\0'),(1965,'Education and training that provides the necessary skills and knowledge for a particular job.','The government is promoting vocational training to reduce youth unemployment.','NOUN','Giáo dục và đào tạo cung cấp các kỹ năng và kiến thức cần thiết cho một công việc cụ thể.','Chính phủ đang thúc đẩy đào tạo nghề để giảm tỷ lệ thất nghiệp ở thanh niên.','Đào tạo nghề',1867,NULL,_binary '\0'),(1966,'Education at university or college level.','More students are seeking tertiary education to improve their career prospects.','NOUN','Giáo dục ở cấp độ đại học hoặc cao đẳng.','Nhiều sinh viên đang tìm kiếm giáo dục đại học để cải thiện triển vọng nghề nghiệp của mình.','Giáo dục đại học/cao đẳng',1868,NULL,_binary '\0'),(1967,'A philosophy of education based on the premise that each person finds identity, meaning, and purpose through connections to the community and natural world.','Holistic education focuses on a student’s emotional, social, and spiritual well-being.','NOUN','Triết lý giáo dục dựa trên tiền đề rằng mỗi người tìm thấy bản sắc, ý nghĩa và mục đích thông qua sự kết nối với cộng đồng và thế giới tự nhiên.','Giáo dục toàn diện tập trung vào sức khỏe cảm xúc, xã hội và tinh thần của học sinh.','Giáo dục toàn diện',1869,NULL,_binary '\0'),(1968,'An assessment intended to improve student learning and help teachers adjust their teaching strategies during the learning process.','Quizzes and class discussions are common types of formative assessment.','NOUN','Việc đánh giá nhằm cải thiện việc học của học sinh và giúp giáo viên điều chỉnh chiến lược giảng dạy trong quá trình học.','Các bài kiểm tra ngắn và thảo luận lớp là những loại đánh giá quá trình phổ biến.','Đánh giá quá trình',1870,NULL,_binary '\0'),(1969,'A test that is administered and scored in a consistent, or standard, manner.','The use of standardized testing is a highly debated topic in educational policy.','NOUN','Một bài kiểm tra được quản lý và chấm điểm theo một cách thức nhất quán hoặc tiêu chuẩn.','Việc sử dụng kiểm tra tiêu chuẩn hóa là một chủ đề gây tranh cãi nhiều trong chính sách giáo dục.','Kiểm tra tiêu chuẩn hóa',1871,NULL,_binary '\0'),(1970,'The freedom of educational institutions and teachers to govern themselves and design their own curriculum.','Universities fight to maintain their academic autonomy from government interference.','NOUN','Quyền tự do của các tổ chức giáo dục và giáo viên trong việc tự quản lý và thiết kế chương trình học của riêng họ.','Các trường đại học đấu tranh để duy trì sự tự chủ học thuật khỏi sự can thiệp của chính phủ.','Tự chủ học thuật',1872,NULL,_binary '\0'),(1971,'An educational model in which students with special needs spend most or all of their time with non-special needs students.','Inclusive education promotes diversity and mutual respect in the classroom.','NOUN','Mô hình giáo dục trong đó học sinh có nhu cầu đặc biệt dành phần lớn thời gian học cùng với học sinh bình thường.','Giáo dục hòa nhập thúc đẩy sự đa dạng và tôn trọng lẫn nhau trong lớp học.','Giáo dục hòa nhập',1873,NULL,_binary '\0'),(1972,'A style of education in which students learn via electronic and online media as well as traditional face-to-face teaching.','Blended learning offers more flexibility for students with busy schedules.','NOUN','Một phong cách giáo dục trong đó học sinh học qua các phương tiện điện tử trực tuyến cũng như giảng dạy trực tiếp truyền thống.','Học tập kết hợp mang lại nhiều sự linh hoạt hơn cho sinh viên có lịch trình bận rộn.','Học tập kết hợp',1874,NULL,_binary '\0'),(1973,'A method of study where teachers and students do not meet in a classroom but use the internet, mail, etc.','The pandemic forced schools worldwide to switch to distance learning.','NOUN','Phương pháp học tập mà giáo viên và học sinh không gặp nhau trong lớp mà sử dụng internet, thư từ, v.v.','Đại dịch đã buộc các trường học trên toàn thế giới phải chuyển sang học từ xa.','Học từ xa',1875,NULL,_binary '\0'),(1974,'The specialized skills and knowledge required to teach effectively.','Teacher training programs focus on developing both subject knowledge and pedagogical skills.','NOUN','Các kỹ năng và kiến thức chuyên môn cần thiết để giảng dạy hiệu quả.','Các chương trình đào tạo giáo viên tập trung vào việc phát triển cả kiến thức chuyên môn và kỹ năng sư phạm.','Kỹ năng sư phạm',1876,NULL,_binary '\0'),(1975,'Information, especially of a biased or misleading nature, used to promote a political cause or point of view.','The wartime government used film as a powerful tool for national propaganda.','NOUN','Thông tin, đặc biệt là có tính thiên kiến hoặc gây hiểu lầm, được sử dụng để thúc đẩy một mục tiêu chính trị hoặc quan điểm.','Chính phủ thời chiến đã sử dụng phim ảnh như một công cụ mạnh mẽ để tuyên truyền quốc gia.','Tuyên truyền',1877,NULL,_binary '\0'),(1976,'The general opinion or feeling of the public about a particular issue.','Public sentiment has shifted in favor of stricter environmental regulations.','NOUN','Ý kiến hoặc cảm nhận chung của công chúng về một vấn đề cụ thể.','Thái độ của công chúng đã chuyển sang ủng hộ các quy định nghiêm ngặt hơn về môi trường.','Dư luận / Thái độ công chúng',1878,NULL,_binary '\0'),(1978,'The ability of the news media to influence the importance placed on the topics of the public agenda.','Through agenda-setting, the media decides which issues get the most attention.','NOUN','Khả năng của truyền thông tin tức trong việc gây ảnh hưởng đến mức độ quan trọng của các chủ đề trong tâm trí công chúng.','Thông qua việc định hướng dư luận, truyền thông quyết định vấn đề nào nhận được nhiều sự chú ý nhất.','Thiết lập chương trình nghị sự / Định hướng dư luận',1880,NULL,_binary '\0'),(1980,'The ability to access, analyze, evaluate, and create media in a variety of forms.','Media literacy is essential for identifying fake news and bias.','NOUN','Khả năng truy cập, phân tích, đánh giá và sáng tạo truyền thông dưới nhiều hình thức khác nhau.','Khả năng hiểu biết truyền thông là thiết yếu để nhận diện tin giả và sự thiên kiến.','Khả năng hiểu biết truyền thông',1882,NULL,_binary '\0'),(1982,'Media that is disseminated via the largest distribution channels, reflecting prevailing currents of thought.','Many people now prefer social media over traditional mainstream media for news.','NOUN','Truyền thông được phổ biến qua các kênh phân phối lớn nhất, phản ánh các dòng tư tưởng chủ đạo.','Nhiều người hiện nay ưa chuộng mạng xã hội hơn truyền thông chính thống truyền thống để cập nhật tin tức.','Truyền thông chính thống',1884,NULL,_binary '\0'),(1983,'Discussion about matters of public concern within a society.','Social media has dramatically expanded the arena of public discourse.','NOUN','Các cuộc thảo luận về những vấn đề được công chúng quan tâm trong một xã hội.','Mạng xã hội đã mở rộng đáng kể đấu trường thảo luận xã hội.','Đối thoại công cộng / Thảo luận xã hội',1885,NULL,_binary '\0'),(1984,'Broadcasting or publishing that is intended both to entertain and to inform.','The news program was criticized for drifting toward shallow infotainment.','NOUN','Việc phát sóng hoặc xuất bản nhằm mục đích vừa để giải trí vừa để cung cấp thông tin.','Chương trình tin tức bị chỉ trích vì trôi dần về phía thông tin giải trí nông cạn.','Thông tin giải trí',1886,NULL,_binary '\0'),(1985,'The activity of controlling, and usually limiting, general access to something.','Editors act as gatekeepers, deciding which stories are worth publishing.','NOUN','Hoạt động kiểm soát và thường là giới hạn quyền tiếp cận chung vào một thứ gì đó (thường là thông tin).','Các biên tập viên đóng vai trò là những người canh cổng, quyết định câu chuyện nào xứng đáng được đăng tải.','Kiểm duyệt đầu vào / Canh cổng thông tin',1887,NULL,_binary '\0'),(1986,'An assessment of public opinion by questioning a representative sample of people.','The latest opinion poll shows a decline in the prime minister’s popularity.','NOUN','Việc đánh giá ý kiến công chúng bằng cách đặt câu hỏi cho một nhóm người đại diện.','Cuộc thăm dò ý kiến mới nhất cho thấy sự sụt giảm trong mức độ phổ biến của thủ tướng.','Thăm dò ý kiến',1888,NULL,_binary '\0'),(1987,'A particular bias, interpretation, or point of view intended to create a favorable (or unfavorable) impression.','The candidate’s press secretary tried to put a positive spin on the poor debate performance.','NOUN','Một cách giải thích hoặc góc nhìn thiên kiến nhằm tạo ra ấn tượng thuận lợi (hoặc bất lợi).','Thư ký báo chí của ứng cử viên đã cố gắng thêu dệt một góc nhìn tích cực cho màn tranh luận kém cỏi.','Sự \"xoay\" thông tin / Thêu dệt',1889,NULL,_binary '\0'),(1988,'The use of humor, irony, exaggeration, or ridicule to expose and criticize people’s stupidity or vices.','Political satire can be an effective way to hold leaders accountable.','NOUN','Việc sử dụng sự hài hước, mỉa mai, cường điệu hoặc nhạo báng để phơi bày và chỉ trích sự ngu ngốc hoặc thói hư tật xấu.','Châm biếm chính trị có thể là một cách hiệu quả để yêu cầu các nhà lãnh đạo chịu trách nhiệm.','Châm biếm',1890,NULL,_binary '\0'),(1989,'The professional maintenance of a favorable public image by a company or other organization.','The company hired a PR firm to handle the fallout from the scandal.','NOUN','Việc duy trì chuyên nghiệp một hình ảnh công chúng thuận lợi bởi một công ty hoặc tổ chức.','Công ty đã thuê một công ty PR để xử lý hậu quả từ vụ bê bối.','Quan hệ công chúng',1891,NULL,_binary '\0'),(1991,'The mental action or process of acquiring knowledge and understanding through thought, experience, and the senses.','The drug is being tested for its ability to improve cognition in elderly patients.','NOUN','Hoạt động hoặc quá trình tâm trí tiếp nhận kiến thức và hiểu biết thông qua suy nghĩ, trải nghiệm và giác quan.','Loại thuốc này đang được thử nghiệm về khả năng cải thiện nhận thức ở bệnh nhân cao tuổi.','Nhận thức (quá trình tư duy)',1893,NULL,_binary '\0'),(1992,'Data or information received through the five senses.','The brain processes constant sensory input to help us navigate the environment.','NOUN','Dữ liệu hoặc thông tin nhận được thông qua năm giác quan.','Bộ não xử lý các thông tin cảm giác đầu vào liên tục để giúp chúng ta định hướng trong môi trường.','Thông tin cảm giác đầu vào',1894,NULL,_binary '\0'),(1993,'The length of time a person can concentrate on a particular task or subject.','Young children typically have a shorter attention span than adults.','NOUN','Khoảng thời gian một người có thể tập trung vào một nhiệm vụ hoặc chủ đề cụ thể.','Trẻ nhỏ thường có khoảng thời gian tập trung ngắn hơn người lớn.','Khoảng thời gian tập trung',1895,NULL,_binary '\0'),(1994,'The change of information in any manner detectable by an observer.','Cognitive psychology often compares human information processing to computer systems.','NOUN','Sự thay đổi thông tin theo bất kỳ cách thức nào mà người quan sát có thể phát hiện được.','Tâm lý học nhận thức thường so sánh việc xử lý thông tin của con người với các hệ thống máy tính.','Xử lý thông tin',1896,NULL,_binary '\0'),(1995,'Memory that involves the storage of information for a brief period.','Distractions can easily interfere with short-term memory.','NOUN','Trí nhớ liên quan đến việc lưu trữ thông tin trong một khoảng thời gian ngắn.','Sự xao nhãng có thể dễ dàng can thiệp vào trí nhớ ngắn hạn.','Trí nhớ ngắn hạn',1897,NULL,_binary '\0'),(1996,'The storage of information over extended periods.','Repeat practice is essential for moving information into long-term memory.','NOUN','Việc lưu trữ thông tin trong thời gian dài.','Việc luyện tập lặp đi lặp lại là cần thiết để chuyển thông tin vào trí nhớ dài hạn.','Trí nhớ dài hạn',1898,NULL,_binary '\0'),(1997,'The process of focusing on a particular object in the environment for a certain period of time.','Selective attention allows us to focus on a conversation in a noisy room.','NOUN','Quá trình tập trung vào một đối tượng cụ thể trong môi trường trong một khoảng thời gian nhất định.','Sự chú ý có chọn lọc cho phép chúng ta tập trung vào một cuộc hội thoại trong một căn phòng ồn ào.','Sự chú ý có chọn lọc',1899,NULL,_binary '\0'),(1998,'The unconscious attribution of particular qualities to a member of a certain social group.','Implicit bias can influence our decisions without us even realizing it.','NOUN','Sự gán ghép vô thức các phẩm chất cụ thể cho một thành viên của một nhóm xã hội nhất định.','Thành kiến ngầm có thể ảnh hưởng đến các quyết định của chúng ta mà chính chúng ta không nhận ra.','Thành kiến ngầm',1900,NULL,_binary '\0'),(1999,'A mental structure that helps organize and interpret information.','Our mental schemas help us quickly categorize new objects we encounter.','NOUN','Cấu trúc tâm trí giúp tổ chức và giải thích thông tin.','Lược đồ tâm trí của chúng ta giúp chúng ta nhanh chóng phân loại các đối tượng mới mà chúng ta gặp phải.','Lược đồ tâm trí',1901,NULL,_binary '\0'),(2004,'A set of cognitive processes that are necessary for the cognitive control of behavior.','Planning and emotional control are key components of executive function.','NOUN','Một tập hợp các quá trình nhận thức cần thiết cho việc kiểm soát hành vi bằng nhận thức.','Lập kế hoạch và kiểm soát cảm xúc là những thành phần chính của chức năng điều hành.','Chức năng điều hành',1906,NULL,_binary '\0'),(2006,'The state of being comfortable, healthy, or happy.','The company implemented a new program to improve employee well-being.','NOUN','Trạng thái thoải mái, khỏe mạnh hoặc hạnh phúc.','Công ty đã triển khai một chương trình mới để cải thiện phúc lợi của nhân viên.','Sự hạnh phúc / Trạng thái khỏe mạnh',1908,NULL,_binary '\0'),(2007,'A mark of disgrace associated with a particular circumstance, quality, or person.','There is still a significant social stigma attached to seeking mental health support.','NOUN','Sự ô nhục gắn liền với một hoàn cảnh, phẩm chất hoặc con người cụ thể.','Vẫn còn một sự kỳ thị xã hội đáng kể liên quan đến việc tìm kiếm hỗ trợ sức khỏe tâm thần.','Sự kỳ thị / Định kiến xấu',1909,NULL,_binary '\0'),(2008,'A state of emotional, physical, and mental exhaustion caused by excessive and prolonged stress.','Many software developers experience burnout due to tight deadlines and long hours.','NOUN','Trạng thái kiệt sức về cảm xúc, thể chất và tinh thần do căng thẳng kéo dài.','Nhiều lập trình viên bị kiệt sức do deadline gấp và làm việc nhiều giờ.','Sự kiệt sức (do công việc)',1910,NULL,_binary '\0'),(2012,'The quality or state of being conscious or aware of something, often practiced through meditation.','Mindfulness meditation can help reduce anxiety and improve focus.','NOUN','Trạng thái nhận thức về điều gì đó, thường được thực hành qua thiền định.','Thiền chánh niệm có thể giúp giảm lo âu và cải thiện sự tập trung.','Sự tỉnh thức / Chánh niệm',1914,NULL,_binary '\0'),(2013,'An illness that disrupts normal physical or mental functions.','He was diagnosed with a sleep disorder that affects his daily life.','NOUN','Một căn bệnh làm gián đoạn các chức năng thể chất hoặc tinh thần bình thường.','Anh ấy được chẩn đoán mắc chứng rối loạn giấc ngủ ảnh hưởng đến cuộc sống hàng ngày.','Sự rối loạn',1915,NULL,_binary '\0'),(2014,'An adaptation to environmental stress that is based on conscious or unconscious choices.','Exercise can be a healthy coping mechanism for managing negative emotions.','NOUN','Sự thích nghi với căng thẳng môi trường dựa trên những lựa chọn có ý thức hoặc vô thức.','Tập thể dục có thể là một cơ chế ứng phó lành mạnh để quản lý cảm xúc tiêu cực.','Cơ chế ứng phó',1916,NULL,_binary '\0'),(2015,'The range of differences in individual brain function and behavioral traits.','The concept of neurodiversity promotes the idea that conditions like autism are natural variations.','NOUN','Phạm vi khác biệt trong chức năng não bộ và đặc điểm hành vi của từng cá nhân.','Khái niệm đa dạng thần kinh thúc đẩy ý tưởng rằng các tình trạng như tự kỷ là những biến thể tự nhiên.','Sự đa dạng thần kinh',1917,NULL,_binary '\0'),(2016,'Confidence in one’s own worth or abilities; self-respect.','Positive reinforcement can help build a child’s self-esteem.','NOUN','Sự tin tưởng vào giá trị hoặc khả năng của chính mình.','Sự củng cố tích cực có thể giúp xây dựng lòng tự trọng của trẻ.','Lòng tự trọng / Sự tự tin vào bản thân',1918,NULL,_binary '\0'),(2017,'A severe mental disorder in which thought and emotions are so impaired that contact is lost with external reality.','Early intervention is vital in the treatment of first-episode psychosis.','NOUN','Rối loạn tâm thần nặng khiến tư duy và cảm xúc bị suy giảm đến mức mất liên lạc với thực tế.','Can thiệp sớm là rất quan trọng trong điều trị giai đoạn đầu của chứng loạn thần.','Loạn thần',1919,NULL,_binary '\0'),(2018,'An extreme or irrational fear of or aversion to something.','She has a phobia of flying, which makes travel difficult.','NOUN','Nỗi sợ hãi cực độ hoặc phi lý đối với một thứ gì đó.','Cô ấy mắc chứng sợ bay, điều này khiến việc di chuyển trở nên khó khăn.','Chứng ám ảnh sợ hãi',1920,NULL,_binary '\0'),(2019,'Professional guidance of the individual by utilizing psychological methods.','Student counseling services are available to help with academic and personal issues.','NOUN','Sự hướng dẫn chuyên nghiệp cho cá nhân bằng cách sử dụng các phương pháp tâm lý.','Dịch vụ tư vấn cho sinh viên luôn sẵn sàng hỗ trợ các vấn đề học tập và cá nhân.','Tư vấn tâm lý',1921,NULL,_binary '\0'),(2020,'The belief in or practice of disinterested and selfless concern for the well-being of others.','Altruism is a fundamental human trait that helps build cohesive societies.','NOUN','Niềm tin hoặc thực hành quan tâm không vụ lợi và quên mình đến hạnh phúc của người khác.','Lòng vị tha là một đặc điểm cơ bản của con người giúp xây dựng các xã hội gắn kết.','Lòng vị tha / Chủ nghĩa vị tha',1922,NULL,_binary '\0'),(2021,'Behavior in accordance with socially accepted conventions or standards.','Many teenagers feel a strong pressure to maintain conformity with their peers.','NOUN','Hành vi phù hợp với các quy ước hoặc tiêu chuẩn được xã hội chấp nhận.','Nhiều thanh thiếu niên cảm thấy áp lực mạnh mẽ phải duy trì sự đồng khuôn với bạn bè đồng trang lứa.','Sự tuân thủ / Sự đồng khuôn',1923,NULL,_binary '\0'),(2022,'The process of encouraging or establishing a belief or pattern of behavior, especially by encouragement or reward.','Positive reinforcement is often more effective than punishment in behavioral modification.','NOUN','Quá trình khuyến khích hoặc thiết lập một niềm tin hoặc mô hình hành vi, đặc biệt là bằng phần thưởng.','Củng cố tích cực thường hiệu quả hơn hình phạt trong việc sửa đổi hành vi.','Sự củng cố (hành vi)',1924,NULL,_binary '\0'),(2023,'A slight push or encouragement towards a particular action, often using subtle environmental changes.','Placing healthy snacks at eye level is a nudge to encourage better eating habits.','NOUN','Một sự thúc đẩy hoặc khuyến khích nhẹ nhàng hướng tới một hành động cụ thể, thường bằng cách thay đổi môi trường tinh vi.','Đặt đồ ăn nhẹ lành mạnh ở ngang tầm mắt là một \"cú hích\" để khuyến khích thói quen ăn uống tốt hơn.','Cú hích / Sự khuyến khích nhẹ',1925,NULL,_binary '\0'),(2025,'The unwritten rules of beliefs, attitudes, and behaviors that are considered acceptable in a particular social group.','Social norms dictate how people should behave in different cultural settings.','NOUN','Quy tắc niềm tin, thái độ và hành vi không thành văn được coi là chấp nhận được trong một nhóm xã hội.','Chuẩn mực xã hội quy định cách mọi người nên hành xử trong các bối cảnh văn hóa khác nhau.','Các chuẩn mực xã hội',1927,NULL,_binary '\0'),(2026,'The diminishing of a physiological or emotional response to a frequently repeated stimulus.','Habituation explains why we eventually stop noticing the ticking of a clock.','NOUN','Sự giảm dần phản ứng sinh lý hoặc cảm xúc đối với một kích thích lặp đi lặp lại thường xuyên.','Sự quen nhờn giải thích tại sao cuối cùng chúng ta ngừng chú ý đến tiếng tích tắc của đồng hồ.','Sự quen nhờn / Sự thích nghi dần',1928,NULL,_binary '\0'),(2028,'A theory that describes the way people choose between probabilistic alternatives that involve risk, where the probabilities of outcomes are uncertain.','Prospect theory suggests that people value gains and losses differently.','NOUN','Lý thuyết mô tả cách mọi người lựa chọn giữa các lựa chọn có rủi ro khi kết quả là không chắc chắn.','Lý thuyết triển vọng gợi ý rằng con người đánh giá lãi và lỗ theo cách khác nhau.','Lý thuyết triển vọng',1930,NULL,_binary '\0'),(2029,'A cognitive bias where an individual relies too heavily on an initial piece of information offered.','The initial price suggested in a negotiation acts as an anchoring bias.','NOUN','Một thiên kiến nhận thức mà cá nhân dựa quá nhiều vào thông tin ban đầu được đưa ra.','Mức giá ban đầu được đề xuất trong một cuộc đàm phán đóng vai trò như một thiên kiến mỏ neo.','Thiên kiến mỏ neo',1931,NULL,_binary '\0'),(2030,'A method of economic analysis that applies psychological insights into human behavior to explain economic decision-making.','Behavioral economics helps explain why people don’t always save enough for retirement.','NOUN','Phương pháp phân tích kinh tế áp dụng hiểu biết tâm lý về hành vi con người để giải thích việc đưa ra quyết định kinh tế.','Kinh tế học hành vi giúp giải thích tại sao mọi người không phải lúc nào cũng tiết kiệm đủ cho nghỉ hưu.','Kinh tế học hành vi',1932,NULL,_binary '\0'),(2031,'An emotional bias; a preference for the current state of affairs.','Status quo bias can make people resistant to beneficial changes in organizational structure.','NOUN','Một thiên kiến cảm xúc; sự ưu tiên cho hiện trạng đang có.','Thiên kiến giữ nguyên trạng thái có thể khiến mọi người phản đối những thay đổi có lợi trong cấu trúc tổ chức.','Thiên kiến duy trì trạng thái hiện hữu',1933,NULL,_binary '\0'),(2032,'The introduction of one stimulus that influences how people respond to a subsequent stimulus.','Exposure to the word \"yellow\" can act as priming for a faster recognition of the word \"banana\".','NOUN','Việc giới thiệu một kích thích gây ảnh hưởng đến cách mọi người phản ứng với kích thích tiếp theo.','Tiếp xúc với từ \"vàng\" có thể đóng vai trò là hiệu ứng mồi giúp nhận biết từ \"chuối\" nhanh hơn.','Hiệu ứng mồi',1934,NULL,_binary '\0'),(2033,'The tendency for people to perform differently when in the presence of others than when alone.','Social facilitation explains why athletes often perform better during a competition than in practice.','NOUN','Xu hướng mọi người thực hiện hành động khác đi khi có mặt người khác so với khi ở một mình.','Hiệu ứng khán giả giải thích tại sao các vận động viên thường thi đấu tốt hơn trong cuộc thi so với khi tập luyện.','Sự tạo thuận lợi xã hội / Hiệu ứng khán giả',1935,NULL,_binary '\0'),(2034,'A tendency to prefer avoiding losses to acquiring equivalent gains.','Loss aversion suggests that the pain of losing $100 is stronger than the joy of gaining $100.','NOUN','Xu hướng thích tránh thua lỗ hơn là đạt được lợi ích tương đương.','Tâm lý sợ thua lỗ gợi ý rằng nỗi đau khi mất 100 đô la mạnh hơn niềm vui khi kiếm được 100 đô la.','Tâm lý sợ thua lỗ',1936,NULL,_binary '\0'),(2035,'The initial learning of information by placing it into memory.','Effective encoding is the first step in creating a lasting memory.','NOUN','Quá trình học thông tin ban đầu bằng cách đưa nó vào bộ nhớ.','Mã hóa hiệu quả là bước đầu tiên trong việc tạo ra một trí nhớ lâu dài.','Mã hóa',1937,NULL,_binary '\0'),(2036,'The process by which a temporary memory becomes more stable and long-term.','Sleep plays a vital role in the consolidation of new information.','NOUN','Quá trình mà một trí nhớ tạm thời trở nên ổn định và lâu dài hơn.','Giấc ngủ đóng vai trò quan trọng trong việc củng cố các thông tin mới.','Sự củng cố trí nhớ',1938,NULL,_binary '\0'),(2037,'The process of getting stored information out of memory storage.','Test-taking is actually a form of retrieval practice that strengthens learning.','NOUN','Quá trình lấy thông tin đã lưu trữ ra khỏi bộ nhớ.','Làm bài kiểm tra thực chất là một hình thức luyện tập truy xuất giúp tăng cường việc học.','Sự truy xuất / Sự nhớ lại',1939,NULL,_binary '\0'),(2038,'A learning technique that incorporates increasing intervals of time between subsequent review of previously learned material.','Spaced repetition is one of the most effective ways to learn new vocabulary.','NOUN','Kỹ thuật học tập kết hợp việc tăng dần khoảng thời gian giữa các lần ôn tập tài liệu đã học.','Lặp lại ngắt quãng là một trong những cách hiệu quả nhất để học từ vựng mới.','Lặp lại ngắt quãng',1940,NULL,_binary '\0'),(2039,'A hypothesis that describes the decline of memory retention in time.','The forgetting curve shows that we lose most of what we learn within the first 24 hours if we don’t review.','NOUN','Giả thuyết mô tả sự suy giảm khả năng lưu giữ trí nhớ theo thời gian.','Đường cong quên lãng cho thấy chúng ta mất đi hầu hết những gì đã học trong 24 giờ đầu nếu không ôn tập.','Đường cong quên lãng',1941,NULL,_binary '\0'),(2040,'Systems such as patterns of letters, ideas, or associations which assist in remembering something.','Using mnemonics can make it easier to remember complex lists of data.','NOUN','Các hệ thống như mô hình chữ cái, ý tưởng hoặc sự liên tưởng giúp hỗ trợ việc ghi nhớ.','Sử dụng các mẹo ghi nhớ có thể giúp việc nhớ các danh sách dữ liệu phức tạp trở nên dễ dàng hơn.','Phương pháp ghi nhớ / Mẹo ghi nhớ',1942,NULL,_binary '\0'),(2041,'The ability of the brain to form and reorganize synaptic connections, especially in response to learning or experience.','Neuroplasticity allows the brain to adapt and learn new skills even in adulthood.','NOUN','Khả năng của não bộ trong việc hình thành và tổ chức lại các kết nối synap, đặc biệt là để đáp ứng với việc học hoặc trải nghiệm.','Tính dẻo thần kinh cho phép não bộ thích nghi và học các kỹ năng mới ngay cả ở tuổi trưởng thành.','Tính dẻo thần kinh',1943,NULL,_binary '\0'),(2042,'The part of short-term memory that is concerned with immediate conscious perceptual and linguistic processing.','Solving a complex math problem in your head requires a lot of working memory.','NOUN','Một phần của trí nhớ ngắn hạn liên quan đến việc xử lý ngôn ngữ và tri giác có ý thức ngay lập tức.','Giải một bài toán phức tạp trong đầu đòi hỏi rất nhiều trí nhớ làm việc.','Trí nhớ làm việc',1944,NULL,_binary '\0'),(2043,'The total amount of mental effort being used in the working memory.','Information should be presented clearly to avoid excessive cognitive load on students.','NOUN','Tổng lượng nỗ lực tâm trí đang được sử dụng trong trí nhớ làm việc.','Thông tin nên được trình bày rõ ràng để tránh gây tải trọng nhận thức quá mức cho học sinh.','Tải trọng nhận thức',1945,NULL,_binary '\0'),(2044,'A process by which individual pieces of an information set are bound together into a meaningful whole.','Chunking phone numbers into groups of three or four digits makes them easier to remember.','NOUN','Quá trình mà các phần riêng lẻ của một tập hợp thông tin được liên kết với nhau thành một khối có ý nghĩa.','Việc chia số điện thoại thành các nhóm 3 hoặc 4 chữ số giúp chúng dễ nhớ hơn.','Sự phân nhóm thông tin',1946,NULL,_binary '\0'),(2045,'Memory of facts and events that can be consciously recalled.','Knowing the capital of France is an example of declarative memory.','NOUN','Trí nhớ về các sự thật và sự kiện có thể được hồi tưởng một cách có ý thức.','Biết thủ đô của Pháp là một ví dụ về trí nhớ tường thuật.','Trí nhớ tường thuật / Trí nhớ sự kiện',1947,NULL,_binary '\0'),(2046,'The memory of how to do things, such as riding a bike or typing.','Procedural memory is often involuntary and can be difficult to explain in words.','NOUN','Trí nhớ về cách làm mọi việc, chẳng hạn như đi xe đạp hoặc đánh máy.','Trí nhớ quy trình thường là vô thức và có thể khó giải thích bằng lời.','Trí nhớ quy trình',1948,NULL,_binary '\0'),(2047,'The process of adding more information to existing, basic information to enhance learning.','Elaboration techniques, like connecting new words to personal stories, improve retention.','NOUN','Quá trình thêm nhiều thông tin vào thông tin cơ bản hiện có để tăng cường việc học.','Các kỹ thuật mở rộng, như kết nối từ mới với những câu chuyện cá nhân, giúp cải thiện khả năng ghi nhớ.','Sự mở rộng / Sự chi tiết hóa',1949,NULL,_binary '\0'),(2048,'Awareness and understanding of one’s own thought processes.','Metacognition helps students recognize which study methods work best for them.','NOUN','Sự nhận thức và hiểu biết về các quá trình tư duy của chính mình.','Siêu nhận thức giúp học sinh nhận ra phương pháp học tập nào hiệu quả nhất đối với họ.','Siêu nhận thức',1950,NULL,_binary '\0'),(2049,'The biological process by which specific patterns of synaptic activity result in changes in synaptic strength.','Synaptic plasticity is believed to be the cellular basis for learning and memory.','NOUN','Quá trình sinh học mà qua đó các mô hình hoạt động synap cụ thể dẫn đến những thay đổi về sức mạnh của synap.','Tính dẻo của synap được tin là cơ sở tế bào cho việc học tập và trí nhớ.','Tính dẻo của synap',1951,NULL,_binary '\0'),(2050,'The ability to solve new problems, use logic in new situations, and identify patterns.','Fluid intelligence tends to peak in young adulthood and slowly decline with age.','NOUN','Khả năng giải quyết các vấn đề mới, sử dụng logic trong các tình huống mới và xác định các quy luật.','Trí tuệ lỏng có xu hướng đạt đỉnh ở độ tuổi thanh niên và giảm dần theo tuổi tác.','Trí tuệ lỏng',1952,NULL,_binary '\0'),(2051,'The ability to use learned knowledge and experience.','Vocabulary and general knowledge are components of crystallized intelligence.','NOUN','Khả năng sử dụng kiến thức và kinh nghiệm đã học được.','Từ vựng và kiến thức tổng quát là các thành phần của trí tuệ kết tinh.','Trí tuệ kết tinh',1953,NULL,_binary '\0'),(2052,'A thought process used to generate creative ideas by exploring many possible solutions.','Brainstorming sessions encourage divergent thinking to find unique solutions.','NOUN','Quá trình tư duy được sử dụng để tạo ra các ý tưởng sáng tạo bằng cách khám phá nhiều giải pháp khả thi.','Các buổi động não khuyến khích tư duy phân kỳ để tìm ra những giải pháp độc đáo.','Tư duy phân kỳ',1954,NULL,_binary '\0'),(2053,'The ability to give the \"correct\" answer to standard questions that do not require significant creativity.','Standardized tests often measure convergent thinking rather than creativity.','NOUN','Khả năng đưa ra câu trả lời \"đúng\" cho các câu hỏi tiêu chuẩn không đòi hỏi sự sáng tạo đáng kể.','Các bài kiểm tra tiêu chuẩn thường đo lường tư duy hội tụ thay vì sự sáng tạo.','Tư duy hội tụ',1955,NULL,_binary '\0'),(2054,'The capacity to be aware of, control, and express one’s emotions, and to handle interpersonal relationships judiciously and empathetically.','High emotional intelligence is often a better predictor of career success than IQ.','NOUN','Khả năng nhận biết, kiểm soát và diễn đạt cảm xúc của bản thân, cũng như xử lý các mối quan hệ một cách khôn ngoan và đồng cảm.','Trí tuệ cảm xúc cao thường là chỉ số dự báo thành công nghề nghiệp tốt hơn IQ.','Trí tuệ cảm xúc',1956,NULL,_binary '\0'),(2055,'The mental ability to switch between thinking about two different concepts, and to think about multiple concepts simultaneously.','Learning a new programming language requires high cognitive flexibility.','NOUN','Khả năng tâm trí chuyển đổi giữa việc suy nghĩ về hai khái niệm khác nhau hoặc suy nghĩ về nhiều khái niệm cùng lúc.','Học một ngôn ngữ lập trình mới đòi hỏi sự linh hoạt nhận thức cao.','Sự linh hoạt nhận thức',1957,NULL,_binary '\0'),(2056,'The solving of problems by an indirect and creative approach, typically through viewing the problem in a new and unusual light.','Lateral thinking puzzles help train the brain to look for non-obvious answers.','NOUN','Việc giải quyết vấn đề bằng cách tiếp cận gián tiếp và sáng tạo, thường là nhìn nhận vấn đề dưới một góc độ mới lạ.','Các câu đố tư duy ngoại biên giúp huấn luyện não bộ tìm kiếm những câu trả lời không hiển nhiên.','Tư duy ngoại biên / Tư duy theo chiều ngang',1958,NULL,_binary '\0'),(2057,'A desire to invest time and energy into learning more about a particular topic or idea.','His intellectual curiosity led him to research deep into the history of AI.','NOUN','Khao khát đầu tư thời gian và năng lượng để tìm hiểu thêm về một chủ đề hoặc ý tưởng cụ thể.','Sự tò mò trí tuệ đã dẫn dắt anh ấy nghiên cứu sâu vào lịch sử của AI.','Sự tò mò trí tuệ',1959,NULL,_binary '\0'),(2058,'The quality of being clever, original, and inventive.','The engineers showed great ingenuity in repairing the machine with limited parts.','NOUN','Phẩm chất thông minh, độc đáo và đầy sáng kiến.','Các kỹ sư đã thể hiện sự tài tình tuyệt vời trong việc sửa chữa máy móc với các linh kiện hạn chế.','Sự khéo léo / Sự tài tình',1960,NULL,_binary '\0'),(2059,'The inability to access one’s internal creativity.','Every writer experiences a creative block at some point in their career.','NOUN','Trạng thái không thể tiếp cận được khả năng sáng tạo nội tại của bản thân.','Mọi nhà văn đều trải qua sự bế tắc sáng tạo tại một thời điểm nào đó trong sự nghiệp.','Sự bế tắc sáng tạo',1961,NULL,_binary '\0'),(2062,'Possession of high levels of intellectual or creative ability.','Schools often have special programs to support children with high giftedness.','NOUN','Việc sở hữu mức độ cao về khả năng trí tuệ hoặc sáng tạo.','Các trường học thường có chương trình đặc biệt để hỗ trợ trẻ em có năng khiếu cao.','Năng khiếu / Sự thiên bẩm',1964,NULL,_binary '\0'),(2063,'A systematic error in thinking that occurs when people are processing and interpreting information.','Being aware of your own cognitive biases can lead to better decision-making.','NOUN','Một lỗi hệ thống trong tư duy xảy ra khi con người xử lý và giải thích thông tin.','Nhận thức được các thiên kiến nhận thức của chính mình có thể dẫn đến việc đưa ra quyết định tốt hơn.','Thiên kiến nhận thức',1965,NULL,_binary '\0'),(2064,'The mental state in which a person performing some activity is fully immersed in a feeling of energized focus.','Artists often describe being in a flow state when they lose track of time while painting.','NOUN','Trạng thái tâm trí mà một người đang thực hiện một hoạt động hoàn toàn chìm đắm trong cảm giác tập trung tràn đầy năng lượng.','Các nghệ sĩ thường mô tả việc ở trong trạng thái dòng chảy khi họ quên mất thời gian trong lúc vẽ.','Trạng thái dòng chảy',1966,NULL,_binary '\0'),(2065,'The ability to monitor and manage your emotional state.','Emotional regulation is a vital skill for maintaining professional relationships under stress.','NOUN','Khả năng theo dõi và quản lý trạng thái cảm xúc của bản thân.','Điều tiết cảm xúc là một kỹ năng quan trọng để duy trì các mối quan hệ chuyên nghiệp dưới áp lực.','Điều tiết cảm xúc',1967,NULL,_binary '\0'),(2066,'Conscious knowledge of one’s own character, feelings, motives, and desires.','Developing self-awareness helps individuals understand how their actions affect others.','NOUN','Kiến thức có ý thức về tính cách, cảm xúc, động lực và mong muốn của chính mình.','Phát triển sự tự nhận thức giúp các cá nhân hiểu hành động của họ ảnh hưởng đến người khác như thế nào.','Sự tự nhận thức',1968,NULL,_binary '\0'),(2067,'The skills we use to communicate and interact with each other, both verbally and non-verbally.','Good social skills are essential for effective teamwork and leadership.','NOUN','Các kỹ năng chúng ta sử dụng để giao tiếp và tương tác với nhau, cả bằng lời nói và phi ngôn ngữ.','Kỹ năng xã hội tốt là điều cần thiết để làm việc nhóm và lãnh đạo hiệu quả.','Kỹ năng xã hội',1969,NULL,_binary '\0'),(2068,'The examination or observation of one’s own mental and emotional processes.','Quiet moments of introspection can lead to profound personal growth.','NOUN','Việc xem xét hoặc quan sát các quá trình tâm trí và cảm xúc của chính mình.','Những khoảnh khắc tự vấn tĩnh lặng có thể dẫn đến sự phát triển cá nhân sâu sắc.','Sự tự vấn / Sự nội quan',1970,NULL,_binary '\0'),(2070,'Recognition or affirmation that a person or their feelings or opinions are valid or worthwhile.','Emotional validation is a powerful tool in resolving conflicts.','NOUN','Sự thừa nhận hoặc khẳng định rằng một người hoặc cảm xúc, ý kiến của họ là có giá trị.','Sự xác nhận cảm xúc là một công cụ mạnh mẽ trong việc giải quyết xung đột.','Sự công nhận / Sự xác nhận cảm xúc',1972,NULL,_binary '\0'),(2071,'A person’s or animal’s nature, especially as it permanently affects their behavior.','His calm temperament makes him well-suited for high-stress environments.','NOUN','Bản chất của một người hoặc động vật, đặc biệt là khi nó ảnh hưởng lâu dài đến hành vi của họ.','Tính khí điềm tĩnh khiến anh ấy rất phù hợp với những môi trường áp lực cao.','Tính khí',1973,NULL,_binary '\0'),(2072,'A measure of a person’s level of emotional intelligence.','Many employers now value a high EQ as much as technical expertise.','NOUN','Phép đo mức độ trí tuệ cảm xúc của một người.','Nhiều nhà tuyển dụng hiện nay coi trọng chỉ số EQ cao tương đương với chuyên môn kỹ thuật.','Chỉ số thông minh cảm xúc',1974,NULL,_binary '\0'),(2073,'The practice of listening with the intent to understand the speaker’s perspective and feelings.','Empathic listening is a core component of effective counseling.','NOUN','Thực hành lắng nghe với ý định thấu hiểu góc nhìn và cảm xúc của người nói.','Lắng nghe thấu cảm là thành phần cốt lõi của việc tư vấn hiệu quả.','Lắng nghe thấu cảm',1975,NULL,_binary '\0'),(2074,'The phenomenon of having one person’s emotions and related behaviors directly trigger similar emotions and behaviors in others.','The leader’s anxiety caused a wave of emotional contagion throughout the office.','NOUN','Hiện tượng cảm xúc và hành vi của một người trực tiếp kích hoạt những cảm xúc và hành vi tương tự ở người khác.','Sự lo lắng của người lãnh đạo đã gây ra một làn sóng lây lan cảm xúc khắp văn phòng.','Sự lây lan cảm xúc',1976,NULL,_binary '\0'),(2076,'The ability to manage your emotions and behavior in accordance with the demands of the situation.','Self-regulation helps students stay focused and manage classroom frustrations.','NOUN','Khả năng quản lý cảm xúc và hành vi của bản thân phù hợp với yêu cầu của tình huống.','Sự tự điều chỉnh giúp học sinh giữ tập trung và quản lý những bực bội trong lớp học.','Sự tự điều chỉnh',1978,NULL,_binary '\0'),(2077,'Relating to moods, feelings, and attitudes.','The teacher focused on the affective development of the students, not just academic skills.','ADJECTIVE','Liên quan đến tâm trạng, cảm giác và thái độ.','Giáo viên tập trung vào sự phát triển cảm xúc của học sinh, không chỉ các kỹ năng học thuật.','Thuộc về cảm xúc / Biểu cảm',1979,NULL,_binary '\0'),(2078,'The state of having mixed feelings or contradictory ideas about something or someone.','She felt a certain ambivalence about leaving her job for a new opportunity.','NOUN','Trạng thái có những cảm xúc lẫn lộn hoặc ý tưởng mâu thuẫn về điều gì đó hoặc ai đó.','Cô cảm thấy có sự mâu thuẫn nhất định về việc rời bỏ công việc để theo đuổi cơ hội mới.','Sự mâu thuẫn trong cảm xúc',1980,NULL,_binary '\0'),(2079,'The process of releasing, and thereby providing relief from, strong or repressed emotions.','Crying can often provide a sense of catharsis after a period of intense stress.','NOUN','Quá trình giải tỏa, và từ đó mang lại sự nhẹ nhõm khỏi những cảm xúc mạnh mẽ hoặc bị kìm nén.','Khóc thường có thể mang lại cảm giác thanh tẩy cảm xúc sau một giai đoạn căng thẳng cực độ.','Sự thanh tẩy cảm xúc',1981,NULL,_binary '\0'),(2080,'The debate over whether a person’s development is predisposed in their DNA, or a majority of it is influenced by life experiences and environment.','The nature vs. nurture debate is central to understanding personality development.','NOUN','Cuộc tranh luận về việc sự phát triển của một người là do di truyền (DNA) hay phần lớn do trải nghiệm sống và môi trường.','Cuộc tranh luận giữa bản chất và nuôi dưỡng là trung tâm để hiểu về sự phát triển tính cách.','Bản chất đối lập nuôi dưỡng',1982,NULL,_binary '\0'),(2081,'A distinguishing quality or characteristic, typically one belonging to a person.','Optimism is a personality trait that helps people cope with failure.','NOUN','Một phẩm chất hoặc đặc điểm phân biệt, thường thuộc về một người.','Lạc quan là một nét tính cách giúp con người đối mặt với thất bại.','Đặc điểm / Nét tính cách',1983,NULL,_binary '\0'),(2082,'The realization or fulfillment of one’s talents and potentialities, especially considered as a drive or need present in everyone.','Maslow defined self-actualization as the highest level of psychological development.','NOUN','Việc nhận ra hoặc hoàn thiện tài năng và tiềm năng của chính mình.','Maslow định nghĩa tự hiện thực hóa là cấp độ cao nhất của sự phát triển tâm lý.','Sự tự hiện thực hóa / Thể hiện bản thân',1984,NULL,_binary '\0'),(2083,'The quality of being outgoing and directing one’s interest outward, especially when with other people.','High levels of extraversion are often linked to success in sales and leadership roles.','NOUN','Phẩm chất cởi mở và hướng mối quan tâm của mình ra bên ngoài, đặc biệt là khi ở cùng người khác.','Mức độ hướng ngoại cao thường liên quan đến thành công trong các vai trò bán hàng và lãnh đạo.','Sự hướng ngoại',1985,NULL,_binary '\0'),(2084,'The quality of being shy and directing one’s interest inward.','Introversion does not mean a lack of social skills, but rather a preference for quiet environments.','NOUN','Phẩm chất nhút nhát và hướng mối quan tâm của mình vào bên trong.','Hướng nội không có nghĩa là thiếu kỹ năng xã hội, mà là sự ưu tiên cho môi trường yên tĩnh.','Sự hướng nội',1986,NULL,_binary '\0'),(2085,'The quality of wishing to do one’s work or duty well and thoroughly.','Conscientiousness is a key predictor of academic and professional achievement.','NOUN','Phẩm chất mong muốn hoàn thành công việc hoặc nhiệm vụ của mình một cách tốt đẹp và thấu đáo.','Sự tận tâm là một chỉ số dự báo chính cho thành tích học tập và nghề nghiệp.','Sự tận tâm / Sự chu đáo',1987,NULL,_binary '\0'),(2086,'The quality of being kind, sympathetic, cooperative, warm, and considerate.','High agreeableness helps in building trust and maintaining harmony in a team.','NOUN','Phẩm chất tốt bụng, thông cảm, hợp tác, ấm áp và chu đáo.','Sự dễ chịu cao giúp xây dựng lòng tin và duy trì sự hòa hợp trong một nhóm.','Sự dễ chịu / Tính hòa đồng',1988,NULL,_binary '\0'),(2087,'A personality trait characterized by anxiety, fear, moodiness, worry, envy, frustration, jealousy, and loneliness.','Individuals high in neuroticism may respond more poorly to environmental stress.','NOUN','Một nét tính cách đặc trưng bởi sự lo lắng, sợ hãi, buồn rầu và dễ thất vọng.','Những cá nhân có tính bất ổn cảm xúc cao có thể phản ứng kém hơn với căng thẳng môi trường.','Sự nhạy cảm tâm lý / Tính bất ổn cảm xúc',1989,NULL,_binary '\0'),(2088,'A personality trait involving a general appreciation for art, emotion, adventure, unusual ideas, and variety of experience.','Creative professionals often score high on openness to experience.','NOUN','Nét tính cách bao gồm sự đánh giá cao về nghệ thuật, ý tưởng mới lạ và sự đa dạng của trải nghiệm.','Các chuyên gia sáng tạo thường đạt điểm cao về sự sẵn sàng trải nghiệm.','Sự sẵn sàng trải nghiệm / Tính cởi mở',1990,NULL,_binary '\0'),(2089,'The degree to which people believe that they, as opposed to external forces, have control over the outcome of events in their lives.','People with an internal locus of control believe their own actions determine their success.','NOUN','Mức độ mà mọi người tin rằng họ (thay vì các lực lượng bên ngoài) có quyền kiểm soát kết quả của các sự kiện trong đời.','Những người có điểm kiểm soát nội tại tin rằng hành động của chính họ quyết định thành công của họ.','Điểm kiểm soát',1991,NULL,_binary '\0'),(2090,'An individual’s belief in their capacity to execute behaviors necessary to produce specific performance attainments.','Self-efficacy influences how people approach goals, tasks, and challenges.','NOUN','Niềm tin của một cá nhân vào khả năng thực hiện các hành vi cần thiết để đạt được thành tích cụ thể.','Niềm tin vào năng lực bản thân ảnh hưởng đến cách mọi người tiếp cận mục tiêu, nhiệm vụ và thử thách.','Niềm tin vào năng lực bản thân',1992,NULL,_binary '\0'),(2091,'A period of uncertainty and confusion in which a person’s sense of identity becomes insecure.','Many teenagers go through an identity crisis as they transition to adulthood.','NOUN','Giai đoạn không chắc chắn và bối rối, trong đó ý thức về bản thân của một người trở nên không ổn định.','Nhiều thanh thiếu niên trải qua một cuộc khủng hoảng danh tính khi họ chuyển sang tuổi trưởng thành.','Khủng hoảng danh tính',1993,NULL,_binary '\0'),(2092,'The theory that people learn from one another, via observation, imitation, and modeling.','Social learning theory explains how children adopt the personality traits of their parents.','NOUN','Lý thuyết cho rằng mọi người học hỏi lẫn nhau thông qua quan sát và bắt chước.','Lý thuyết học tập xã hội giải thích cách trẻ em tiếp nhận các nét tính cách của cha mẹ chúng.','Lý thuyết học tập xã hội',1994,NULL,_binary '\0'),(2094,'A very typical example of a certain person or thing; an original model.','In Jungian psychology, the \"Hero\" is a universal archetype found in many cultures.','NOUN','Một ví dụ rất điển hình về một kiểu người hoặc vật cụ thể; một mô hình gốc.','Trong tâm lý học Jung, \"Người hùng\" là một hình mẫu nguyên hợp phổ biến tìm thấy trong nhiều nền văn hóa.','Hình mẫu nguyên hợp / Nguyên mẫu',1996,NULL,_binary '\0'),(2095,'A specialized cell transmitting nerve impulses; a nerve cell.','The human brain contains approximately 86 billion neurons.','NOUN','Một tế bào chuyên biệt truyền các xung thần kinh.','Não bộ con người chứa khoảng 86 tỷ tế bào thần kinh.','Tế bào thần kinh',1997,NULL,_binary '\0'),(2096,'A junction between two nerve cells, consisting of a minute gap across which impulses pass by diffusion of a neurotransmitter.','Learning involves the strengthening of synapses between neurons.','NOUN','Điểm tiếp xúc giữa hai tế bào thần kinh, nơi các xung động được truyền đi.','Việc học tập bao gồm sự củng cố các khớp thần kinh giữa các tế bào thần kinh.','Khớp thần kinh / Synap',1998,NULL,_binary '\0'),(2097,'A chemical substance that is released at the end of a nerve fiber by the arrival of a nerve impulse.','Dopamine is a neurotransmitter associated with pleasure and reward.','NOUN','Một chất hóa học được giải phóng để truyền tín hiệu giữa các tế bào thần kinh.','Dopamine là một chất dẫn truyền thần kinh liên quan đến cảm giác hưng phấn và phần thưởng.','Chất dẫn truyền thần kinh',1999,NULL,_binary '\0'),(2098,'The outer layer of the cerebrum, composed of folded gray matter and playing an important role in consciousness.','The cerebral cortex is responsible for higher-level processes such as reasoning and language.','NOUN','Lớp ngoài cùng của đại não, đóng vai trò quan trọng trong ý thức và tư duy bậc cao.','Vỏ não chịu trách nhiệm cho các quá trình cấp cao như lập luận và ngôn ngữ.','Vỏ não',2000,NULL,_binary '\0'),(2099,'A complex brain structure embedded deep into temporal lobe, involved in learning and memory.','Damage to the hippocampus can prevent the formation of new long-term memories.','NOUN','Một cấu trúc não nằm sâu trong thùy thái dương, liên quan đến việc học và ghi nhớ.','Tổn thương hồi hải mã có thể ngăn cản việc hình thành các ký ức dài hạn mới.','Hồi hải mã',2001,NULL,_binary '\0'),(2100,'A roughly almond-shaped mass of gray matter inside each cerebral hemisphere, involved with the experiencing of emotions.','The amygdala plays a key role in the \"fight or flight\" response.','NOUN','Cấu trúc hình hạnh nhân trong não, liên quan đến việc xử lý cảm xúc, đặc biệt là sợ hãi.','Hạch hạnh nhân đóng vai trò quan trọng trong phản ứng \"chiến hay chạy\".','Hạnh nhân (não bộ)',2002,NULL,_binary '\0'),(2101,'The gray matter of the anterior part of the frontal lobe, highly developed in humans and playing a role in the regulation of complex cognitive, emotional, and behavioral functioning.','The prefrontal cortex is one of the last brain regions to fully mature.','NOUN','Phần não liên quan đến việc lập kế hoạch, ra quyết định và điều chỉnh hành vi xã hội.','Vỏ não trước trán là một trong những vùng não phát triển hoàn thiện muộn nhất.','Vỏ não trước trán',2003,NULL,_binary '\0'),(2102,'The darker tissue of the brain and spinal cord, consisting mainly of nerve cell bodies and branching dendrites.','Meditation has been shown to increase the density of gray matter in certain brain areas.','NOUN','Mô não chứa chủ yếu các thân tế bào thần kinh, chịu trách nhiệm xử lý thông tin.','Thiền đã được chứng minh là làm tăng mật độ chất xám ở một số vùng não.','Chất xám',2004,NULL,_binary '\0'),(2103,'The paler tissue of the brain and spinal cord, consisting mainly of nerve fibers with their myelin sheaths.','White matter acts as the brain’s communication network.','NOUN','Mô não chứa các sợi thần kinh, đóng vai trò như các đường dẫn truyền tín hiệu giữa các vùng chất xám.','Chất trắng đóng vai trò như mạng lưới truyền thông của não bộ.','Chất trắng',2005,NULL,_binary '\0'),(2104,'A neurotransmitter that plays several important roles in the brain and body, especially in reward-motivated behavior.','Social media notifications can trigger a small release of dopamine in the brain.','NOUN','Một chất dẫn truyền thần kinh liên quan đến hệ thống phần thưởng và động lực.','Thông báo mạng xã hội có thể kích thích một lượng nhỏ dopamine được giải phóng trong não.','Dopamine',2006,NULL,_binary '\0'),(2105,'A compound present in blood platelets and serum, which constricts the blood vessels and acts as a neurotransmitter, primarily responsible for mood stabilization.','Low levels of serotonin are often linked to depression.','NOUN','Chất dẫn truyền thần kinh quan trọng trong việc điều hòa tâm trạng, giấc ngủ và tiêu hóa.','Mức serotonin thấp thường liên quan đến trầm cảm.','Serotonin',2007,NULL,_binary '\0'),(2106,'The process by which nervous system cells, the neurons, are produced by neural stem cells.','Aerobic exercise has been found to promote neurogenesis in the hippocampus.','NOUN','Quá trình hình thành các tế bào thần kinh mới trong não.','Tập thể dục nhịp điệu đã được chứng minh là thúc đẩy sự hình thành tế bào thần kinh mới ở hồi hải mã.','Sự sản sinh tế bào thần kinh mới',2008,NULL,_binary '\0'),(2107,'The quality of being easily shaped or molded; the brain’s ability to change and adapt.','Brain plasticity is highest during childhood but continues throughout life.','NOUN','Khả năng thay đổi và thích nghi của não bộ trước các trải nghiệm mới.','Tính dẻo của não cao nhất trong thời thơ ấu nhưng vẫn tiếp tục suốt cuộc đời.','Tính dẻo / Khả năng thích ứng',2009,NULL,_binary '\0'),(2108,'The two halves of the cerebrum, connected by the corpus callosum.','The left and right hemispheres of the brain often specialize in different types of processing.','NOUN','Hai nửa của đại não, được kết nối bởi thể chai.','Hai bán cầu não trái và phải thường chuyên trách các loại xử lý khác nhau.','Bán cầu não',2010,NULL,_binary '\0'),(2109,'A series of connected neurons that send signals from one part of the brain to another.','Repeating a habit strengthens the neural pathways associated with that behavior.','NOUN','Chuỗi các tế bào thần kinh kết nối với nhau để truyền tín hiệu trong não.','Việc lặp lại một thói quen sẽ củng cố các đường dẫn truyền thần kinh liên quan đến hành vi đó.','Đường dẫn truyền thần kinh',2011,NULL,_binary '\0'),(2112,'A market in which prices are falling, encouraging selling.','Investors tend to be cautious during a bear market to avoid heavy losses.','NOUN','Thị trường mà giá cả đang giảm, khuyến khích việc bán ra.','Các nhà đầu tư có xu hướng thận trọng trong thị trường gấu để tránh thua lỗ nặng.','Thị trường gấu (thị trường xuống giá)',2014,NULL,_binary '\0'),(2113,'A market in which share prices are rising, encouraging buying.','The tech sector led the way in the recent bull market.','NOUN','Thị trường mà giá cổ phiếu đang tăng, khuyến khích việc mua vào.','Ngành công nghệ đã dẫn đầu trong thị trường tăng giá gần đây.','Thị trường bò tót (thị trường tăng giá)',2015,NULL,_binary '\0'),(2114,'The amount of a product which is available and the amount which is wanted by customers, together as a factor which determines its price.','The price of oil is largely determined by global supply and demand.','NOUN','Lượng hàng hóa có sẵn và lượng hàng khách hàng muốn mua, là yếu tố quyết định giá cả.','Giá dầu phần lớn được quyết định bởi cung và cầu toàn cầu.','Cung và cầu',2016,NULL,_binary '\0'),(2116,'The use of government spending and tax policies to influence economic conditions.','Changes in fiscal policy can have a major impact on national unemployment rates.','NOUN','Việc sử dụng chi tiêu chính phủ và chính sách thuế để gây ảnh hưởng đến các điều kiện kinh tế.','Những thay đổi trong chính sách tài khóa có thể có tác động lớn đến tỷ lệ thất nghiệp quốc gia.','Chính sách tài khóa',2018,NULL,_binary '\0'),(2117,'The process by which the monetary authority of a country controls the supply of money.','The central bank raised interest rates as part of its monetary policy.','NOUN','Quá trình mà cơ quan tiền tệ của một quốc gia kiểm soát cung tiền.','Ngân hàng trung ương đã tăng lãi suất như một phần của chính sách tiền tệ.','Chính sách tiền tệ',2019,NULL,_binary '\0'),(2118,'The financial ability to buy goods and services.','Inflation eroded the purchasing power of low-income families.','NOUN','Khả năng tài chính để mua hàng hóa và dịch vụ.','Lạm phát đã làm xói mòn sức mua của các gia đình có thu nhập thấp.','Sức mua',2020,NULL,_binary '\0'),(2119,'The rate at which the price of a stock or market increases or decreases for a set of returns.','High market volatility can lead to significant risks for short-term investors.','NOUN','Tốc độ tăng hoặc giảm giá của một cổ phiếu hoặc thị trường.','Biến động thị trường cao có thể dẫn đến rủi ro lớn cho các nhà đầu tư ngắn hạn.','Biến động thị trường',2021,NULL,_binary '\0'),(2120,'A market that has some characteristics of a developed market, but does not fully meet its standards.','Many international firms are expanding their operations in emerging markets.','NOUN','Thị trường có một số đặc điểm của thị trường phát triển nhưng chưa đáp ứng đầy đủ các tiêu chuẩn.','Nhiều công ty quốc tế đang mở rộng hoạt động tại các thị trường mới nổi.','Thị trường mới nổi',2022,NULL,_binary '\0'),(2122,'The market price where the quantity of goods supplied is equal to the quantity of goods demanded.','The equilibrium price is reached when the interests of buyers and sellers meet.','NOUN','Giá thị trường nơi lượng cung hàng hóa bằng với lượng cầu hàng hóa.','Giá cân bằng được đạt tới khi lợi ích của người mua và người bán gặp nhau.','Giá cân bằng',2024,NULL,_binary '\0'),(2123,'The part of economics concerned with large-scale or general economic factors, such as interest rates and national productivity.','Macroeconomics helps governments formulate strategies for long-term growth.','NOUN','Nhánh kinh tế học liên quan đến các yếu tố kinh tế quy mô lớn hoặc tổng quát.','Kinh tế học vĩ mô giúp chính phủ xây dựng các chiến lược tăng trưởng dài hạn.','Kinh tế học vĩ mô',2025,NULL,_binary '\0'),(2124,'The part of economics concerned with single factors and the effects of individual decisions.','Microeconomics studies how households and firms make decisions to allocate limited resources.','NOUN','Nhánh kinh tế học liên quan đến các yếu tố đơn lẻ và tác động của các quyết định cá nhân.','Kinh tế học vi mô nghiên cứu cách các hộ gia đình và doanh nghiệp ra quyết định phân bổ nguồn lực hạn chế.','Kinh tế học vi mô',2026,NULL,_binary '\0'),(2125,'Monetary inflation occurring at a very high rate.','Hyperinflation can lead to a total collapse of a country’s currency system.','NOUN','Tình trạng lạm phát xảy ra với tốc độ cực cao và mất kiểm soát.','Siêu lạm phát có thể dẫn đến sự sụp đổ hoàn toàn hệ thống tiền tệ của một quốc gia.','Siêu lạm phát',2027,NULL,_binary '\0'),(2126,'Reduction of the general level of prices in an economy.','Deflation may sound good for consumers, but it can signal a weak economy.','NOUN','Sự sụt giảm mức giá chung của hàng hóa và dịch vụ trong nền kinh tế.','Giảm phát nghe có vẻ tốt cho người tiêu dùng, nhưng nó có thể là dấu hiệu của một nền kinh tế yếu kém.','Giảm phát',2028,NULL,_binary '\0'),(2127,'A national bank that provides financial and banking services for its country’s government and commercial banking system.','The Central Bank of Vietnam monitors the exchange rate of the VND.','NOUN','Ngân hàng quốc gia quản lý chính sách tiền tệ và hệ thống ngân hàng thương mại.','Ngân hàng Trung ương Việt Nam giám sát tỷ giá hối đoái của đồng Việt Nam đồng.','Ngân hàng trung ương',2029,NULL,_binary '\0'),(2129,'The introduction of new money into the money supply by a central bank.','Quantitative easing was used extensively after the 2008 financial crisis.','NOUN','Việc bơm thêm tiền vào nền kinh tế của ngân hàng trung ương để kích thích tăng trưởng.','Nới lỏng định lượng đã được sử dụng rộng rãi sau cuộc khủng hoảng tài chính năm 2008.','Nới lỏng định lượng',2031,NULL,_binary '\0'),(2130,'Persistent high inflation combined with high unemployment and stagnant demand in a country’s economy.','Stagflation is a difficult situation for policymakers to manage.','NOUN','Tình trạng lạm phát cao kéo dài kết hợp với tỷ lệ thất nghiệp cao và tăng trưởng trì trệ.','Lạm phát đình trệ là một tình huống khó khăn để các nhà hoạch định chính sách quản lý.','Lạm phát đình trệ',2032,NULL,_binary '\0'),(2131,'A situation in which prices in an economy do not change much over time.','The primary goal of many central banks is to maintain price stability.','NOUN','Tình trạng mà giá cả trong nền kinh tế không thay đổi nhiều theo thời gian.','Mục tiêu hàng đầu của nhiều ngân hàng trung ương là duy trì sự ổn định giá cả.','Ổn định giá cả',2033,NULL,_binary '\0'),(2132,'A measure that examines the weighted average of prices of a basket of consumer goods and services.','The CPI is a key indicator used to measure inflation.','NOUN','Chỉ số đo lường mức giá trung bình của một rổ hàng hóa và dịch vụ tiêu dùng.','CPI là một chỉ số quan trọng được sử dụng để đo lường lạm phát.','Chỉ số giá tiêu dùng (CPI)',2034,NULL,_binary '\0'),(2133,'A policy that seeks to slow down an economy by raising interest rates and reducing the money supply.','Tight monetary policy is often used to combat high inflation.','NOUN','Chính sách nhằm làm chậm nền kinh tế bằng cách tăng lãi suất và giảm cung tiền.','Chính sách tiền tệ thắt chặt thường được sử dụng để chống lại lạm phát cao.','Chính sách tiền tệ thắt chặt',2035,NULL,_binary '\0'),(2134,'A policy that seeks to stimulate an economy by lowering interest rates and increasing the money supply.','Loose monetary policy can encourage investment during a recession.','NOUN','Chính sách nhằm kích thích kinh tế bằng cách hạ lãi suất và tăng cung tiền.','Chính sách tiền tệ nới lỏng có thể khuyến khích đầu tư trong thời kỳ suy thoái.','Chính sách tiền tệ nới lỏng',2036,NULL,_binary '\0'),(2135,'The availability of liquid assets (cash) to a market or company.','The central bank ensures there is enough liquidity in the banking system.','NOUN','Khả năng chuyển đổi tài sản thành tiền mặt một cách nhanh chóng.','Ngân hàng trung ương đảm bảo có đủ tính thanh khoản trong hệ thống ngân hàng.','Tính thanh khoản',2037,NULL,_binary '\0'),(2136,'The buying and selling of government securities in the open market by a central bank.','OMO is a tool used by central banks to regulate the money supply.','NOUN','Việc mua và bán các giấy tờ có giá của chính phủ trên thị trường mở bởi ngân hàng trung ương.','Nghiệp vụ thị trường mở là công cụ được các ngân hàng trung ương sử dụng để điều tiết cung tiền.','Nghiệp vụ thị trường mở',2038,NULL,_binary '\0'),(2137,'The amount of cash that banks must have, in their vaults or at the central bank, in reserve against deposits.','Decreasing the reserve requirement allows banks to lend more money.','NOUN','Số tiền mặt mà các ngân hàng phải giữ lại (tại quỹ hoặc tại ngân hàng trung ương) so với lượng tiền gửi.','Giảm dự trữ bắt buộc cho phép các ngân hàng cho vay nhiều tiền hơn.','Dự trữ bắt buộc',2039,NULL,_binary '\0'),(2138,'A theory which states that exchange rates between currencies are in equilibrium when their purchasing power is the same in each of the two countries.','PPP is used to compare the standard of living between different nations.','NOUN','Lý thuyết cho rằng tỷ giá hối đoái ở trạng thái cân bằng khi sức mua của chúng là như nhau ở mỗi quốc gia.','PPP được sử dụng để so sánh mức sống giữa các quốc gia khác nhau.','Ngang giá sức mua (PPP)',2040,NULL,_binary '\0'),(2139,'The reduction in the official value of a currency in relation to other currencies.','Currency devaluation can make a country’s exports cheaper and more competitive.','NOUN','Sự sụt giảm giá trị chính thức của một đồng tiền so với các đồng tiền khác.','Phá giá tiền tệ có thể làm cho hàng hóa xuất khẩu của một quốc gia rẻ hơn và cạnh tranh hơn.','Phá giá tiền tệ',2041,NULL,_binary '\0'),(2140,'Capital invested in a project in which there is a substantial element of risk, typically a new or expanding business.','Many tech startups rely on venture capital to scale their operations quickly.','NOUN','Nguồn vốn đầu tư vào các dự án có rủi ro cao, thường là các doanh nghiệp mới hoặc đang mở rộng.','Nhiều startup công nghệ dựa vào vốn mạo hiểm để mở rộng quy mô hoạt động nhanh chóng.','Vốn mạo hiểm',2042,NULL,_binary '\0'),(2141,'A wealthy individual who provides capital for a business start-up, usually in exchange for convertible debt or ownership equity.','An angel investor provided the initial funding needed to launch the app.','NOUN','Cá nhân giàu có cung cấp vốn cho startup, thường để đổi lấy nợ chuyển đổi hoặc cổ phần sở hữu.','Một nhà đầu tư thiên thần đã cung cấp khoản vốn ban đầu cần thiết để ra mắt ứng dụng.','Nhà đầu tư thiên thần',2043,NULL,_binary '\0'),(2143,'Starting a company with little capital, relying on personal savings and revenue from the business.','The founders chose bootstrapping to maintain full control over their company.','NOUN','Bắt đầu một công ty với ít vốn, dựa vào tiền tiết kiệm cá nhân và doanh thu từ chính doanh nghiệp.','Các nhà sáng lập đã chọn khởi nghiệp tự thân để duy trì quyền kiểm soát hoàn toàn công ty.','Tự thân vận động / Khởi nghiệp tự thân',2045,NULL,_binary '\0'),(2144,'A version of a product with just enough features to be usable by early customers who can then provide feedback for future product development.','We launched an MVP to test market demand before adding more complex features.','NOUN','Phiên bản sản phẩm có đủ các tính năng cơ bản để khách hàng sử dụng và phản hồi.','Chúng tôi đã ra mắt MVP để kiểm tra nhu cầu thị trường trước khi thêm các tính năng phức tạp hơn.','Sản phẩm khả thi tối thiểu',2046,NULL,_binary '\0'),(2145,'A fundamental change in business strategy when the current model is not working.','The startup decided to pivot from a B2C model to a B2B platform.','VERB','Sự thay đổi cơ bản trong chiến lược kinh doanh khi mô hình hiện tại không hiệu quả.','Startup đã quyết định chuyển hướng từ mô hình B2C sang nền tảng B2B.','Thay đổi chiến lược / Chuyển hướng',2047,NULL,_binary '\0'),(2147,'A brief presentation used to provide audiences with a quick overview of your business plan.','They spent weeks refining their pitch deck before meeting the investors.','NOUN','Bản thuyết trình ngắn gọn cung cấp cái nhìn tổng quan về kế hoạch kinh doanh cho nhà đầu tư.','Họ đã dành nhiều tuần để hoàn thiện bản thuyết trình trước khi gặp các nhà đầu tư.','Bản thuyết trình gọi vốn',2049,NULL,_binary '\0'),(2148,'The rate at which a new company uses up its venture capital to finance overhead before generating positive cash flow.','Startups must monitor their burn rate to ensure they don’t run out of cash too soon.','NOUN','Tốc độ một công ty mới tiêu tốn vốn đầu tư trước khi có dòng tiền dương.','Các startup phải theo dõi tốc độ đốt tiền để đảm bảo không hết tiền quá sớm.','Tốc độ đốt tiền',2050,NULL,_binary '\0'),(2149,'A privately held startup company with a value of over $1 billion.','Becoming a unicorn is the ultimate dream for many entrepreneurs.','NOUN','Một công ty khởi nghiệp chưa niêm yết có giá trị trên 1 tỷ đô la.','Trở thành kỳ lân là giấc mơ cuối cùng của nhiều doanh nhân.','Kỳ lân (công ty khởi nghiệp)',2051,NULL,_binary '\0'),(2150,'The process of helping new businesses to develop by providing office space, services, and training.','The university offers an incubation program for student-led startups.','NOUN','Quá trình hỗ trợ doanh nghiệp mới phát triển qua không gian làm việc, dịch vụ và đào tạo.','Trường đại học cung cấp một chương trình ươm tạo cho các startup do sinh viên dẫn dắt.','Ươm tạo doanh nghiệp',2052,NULL,_binary '\0'),(2151,'An innovation that creates a new market and value network and eventually disrupts an existing market.','Digital photography was a disruptive innovation for the film industry.','NOUN','Sự đổi mới tạo ra thị trường mới và cuối cùng phá vỡ thị trường hiện có.','Nhiếp ảnh kỹ thuật số là một sự đổi mới đột phá đối với ngành công nghiệp phim ảnh.','Đổi mới sáng tạo mang tính đột phá',2053,NULL,_binary '\0'),(2152,'A strategic plan to sell ownership in a company to investors or another company.','The founders are considering an IPO as their primary exit strategy.','NOUN','Kế hoạch bán quyền sở hữu công ty cho nhà đầu tư hoặc công ty khác.','Các nhà sáng lập đang xem xét IPO như chiến lược thoát vốn chính của họ.','Chiến lược thoát vốn',2054,NULL,_binary '\0'),(2153,'The cost related to convincing a customer to buy a product or service.','Lowering the CAC while increasing the customer lifetime value is crucial for profitability.','NOUN','Chi phí liên quan đến việc thuyết phục khách hàng mua sản phẩm hoặc dịch vụ.','Hạ thấp CAC trong khi tăng giá trị vòng đời khách hàng là điều quan trọng để có lợi nhuận.','Chi phí thu hút khách hàng',2055,NULL,_binary '\0'),(2154,'Comprehensive appraisal of a business undertaken by a prospective buyer, especially to establish its assets and liabilities.','The venture capital firm is conducting due diligence before finalizing the investment.','NOUN','Việc đánh giá toàn diện doanh nghiệp của người mua tiềm năng để xác định tài sản và nợ phải trả.','Công ty vốn mạo hiểm đang tiến hành thẩm định chuyên sâu trước khi hoàn tất khoản đầu tư.','Thẩm định chuyên sâu',2056,NULL,_binary '\0'),(2155,'The management of the flow of goods and services, involving the movement and storage of raw materials and finished goods.','Effective supply chain management can significantly reduce operational costs.','NOUN','Quản lý dòng chảy hàng hóa và dịch vụ, bao gồm vận chuyển và lưu kho nguyên liệu thô và thành phẩm.','Quản trị chuỗi cung ứng hiệu quả có thể giảm đáng kể chi phí vận hành.','Quản trị chuỗi cung ứng',2057,NULL,_binary '\0'),(2156,'The detailed organization and implementation of a complex operation, specifically the movement of goods.','The company is looking for a specialist to oversee their international logistics.','NOUN','Việc tổ chức và thực hiện chi tiết một hoạt động phức tạp, cụ thể là việc di chuyển hàng hóa.','Công ty đang tìm kiếm một chuyên gia để giám sát hoạt động hậu cần quốc tế của họ.','Hậu cần / Logistics',2058,NULL,_binary '\0'),(2157,'A set of rules which define the responsibilities of sellers and buyers for the delivery of goods under sales contracts.','FOB and CIF are two of the most commonly used Incoterms in global trade.','NOUN','Bộ quy tắc định nghĩa trách nhiệm của người bán và người mua trong việc giao hàng theo hợp đồng.','FOB và CIF là hai trong số các điều khoản Incoterms được sử dụng phổ biến nhất.','Điều khoản thương mại quốc tế',2059,NULL,_binary '\0'),(2158,'The process of passing goods through customs so that they can enter or leave a country.','The delay in customs clearance caused a major setback for the production schedule.','NOUN','Quá trình đưa hàng hóa qua hải quan để có thể nhập khẩu hoặc xuất khẩu khỏi một quốc gia.','Việc chậm trễ trong thông quan hải quan đã gây ra trở ngại lớn cho tiến độ sản xuất.','Thông quan hải quan',2060,NULL,_binary '\0'),(2159,'A detailed list of a shipment of goods in the form of a receipt given by the carrier to the person consigning the goods.','The Bill of Lading acts as a document of title and a contract of carriage.','NOUN','Danh sách chi tiết hàng hóa dưới dạng biên lai do người chuyên chở cấp cho người gửi hàng.','Vận đơn đóng vai trò là chứng từ sở hữu và hợp đồng vận chuyển.','Vận đơn',2061,NULL,_binary '\0'),(2160,'A person or company that organizes shipments for individuals or corporations to get goods from the manufacturer to a market.','The freight forwarder handled all the paperwork for our overseas shipment.','NOUN','Người hoặc công ty tổ chức việc vận chuyển hàng hóa từ nhà sản xuất đến thị trường.','Đại lý giao nhận đã xử lý tất cả giấy tờ cho lô hàng nước ngoài của chúng tôi.','Đại lý giao nhận vận tải',2062,NULL,_binary '\0'),(2161,'A tax or duty to be paid on a particular class of imports or exports.','The government imposed new tariffs on imported steel to protect local industries.','NOUN','Một loại thuế phải trả cho một loại hàng hóa nhập khẩu hoặc xuất khẩu cụ thể.','Chính phủ đã áp đặt thuế quan mới đối với thép nhập khẩu để bảo vệ các ngành công nghiệp địa phương.','Thuế quan',2063,NULL,_binary '\0'),(2162,'A limited quantity of a particular product which under official controls can be produced, exported, or imported.','The import quota for rice was reached before the end of the year.','NOUN','Số lượng hạn chế của một loại sản phẩm cụ thể có thể được sản xuất, xuất khẩu hoặc nhập khẩu.','Hạn ngạch nhập khẩu gạo đã đạt mức tối đa trước khi kết thúc năm.','Hạn ngạch',2064,NULL,_binary '\0'),(2163,'A pact between two or more nations to reduce barriers to imports and exports among them.','The FTA has significantly increased trade between Vietnam and the European Union.','NOUN','Thỏa thuận giữa hai hoặc nhiều quốc gia nhằm giảm rào cản xuất nhập khẩu giữa họ.','Hiệp định FTA đã làm tăng đáng kể thương mại giữa Việt Nam và Liên minh Châu Âu.','Hiệp định thương mại tự do',2065,NULL,_binary '\0'),(2165,'The practice or process of storing goods in a warehouse.','Strategic warehousing locations can reduce transportation costs significantly.','NOUN','Hoạt động hoặc quy trình lưu trữ hàng hóa trong kho.','Các địa điểm lưu kho chiến lược có thể giảm chi phí vận tải đáng kể.','Lưu kho / Hoạt động kho bãi',2067,NULL,_binary '\0'),(2167,'The action of obtaining or procuring something, especially for business purposes.','The procurement department is responsible for selecting reliable suppliers.','NOUN','Hoạt động mua sắm hoặc đạt được thứ gì đó, đặc biệt là cho mục đích kinh doanh.','Bộ phận thu mua chịu trách nhiệm lựa chọn các nhà cung cấp đáng tin cậy.','Sự thu mua / Thu mua vật tư',2069,NULL,_binary '\0'),(2168,'An economic measure of international trade in which a country’s imports exceed its exports.','A persistent trade deficit can put pressure on a nation’s currency.','NOUN','Chỉ số kinh tế khi giá trị nhập khẩu của một quốc gia lớn hơn giá trị xuất khẩu.','Thâm hụt thương mại kéo dài có thể gây áp lực lên đồng tiền của một quốc gia.','Thâm hụt thương mại',2070,NULL,_binary '\0'),(2169,'The transportation of goods under a single contract, but performed with at least two different modes of transport.','Multimodal transport provides flexibility and efficiency in global shipping.','NOUN','Vận chuyển hàng hóa theo một hợp đồng duy nhất nhưng sử dụng ít nhất hai phương thức vận tải khác nhau.','Vận tải đa phương thức mang lại sự linh hoạt và hiệu quả trong vận chuyển toàn cầu.','Vận tải đa phương thức',2071,NULL,_binary '\0'),(2170,'An investment strategy that aims to balance risk and reward by apportioning a portfolio’s assets according to an individual’s goals.','Proper asset allocation is key to managing investment risk over time.','NOUN','Chiến lược đầu tư nhằm cân bằng rủi ro và lợi nhuận bằng cách chia tài sản vào các danh mục khác nhau.','Phân bổ tài sản hợp lý là chìa khóa để quản lý rủi ro đầu tư theo thời gian.','Phân bổ tài sản',2072,NULL,_binary '\0'),(2172,'A sum of money paid regularly by a company to its shareholders out of its profits.','Many investors prefer companies that pay consistent dividends.','NOUN','Số tiền mà công ty trả định kỳ cho cổ đông từ lợi nhuận của mình.','Nhiều nhà đầu tư thích những công ty trả cổ tức đều đặn.','Cổ tức',2074,NULL,_binary '\0'),(2173,'A profit from the sale of property or of an investment.','You may have to pay taxes on any capital gains you make from selling stocks.','NOUN','Khoản lợi nhuận thu được từ việc bán tài sản hoặc các khoản đầu tư.','Bạn có thể phải nộp thuế cho bất kỳ khoản lợi nhuận vốn nào có được từ việc bán cổ phiếu.','Lợi nhuận vốn',2075,NULL,_binary '\0'),(2174,'Interest calculated on the principal and also on the accumulated interest of previous periods.','Compound interest is a powerful tool for long-term wealth building.','NOUN','Tiền lãi được tính trên số tiền gốc và cả số lãi tích lũy của các kỳ trước.','Lãi kép là một công cụ mạnh mẽ để xây dựng sự giàu có trong dài hạn.','Lãi kép',2076,NULL,_binary '\0'),(2175,'The strategy of spreading investments among different financial instruments and industries.','Diversification helps to minimize the impact of a single underperforming asset.','NOUN','Chiến lược phân bổ các khoản đầu tư vào nhiều công cụ tài chính và ngành nghề khác nhau.','Đa dạng hóa giúp giảm thiểu tác động của một tài sản hoạt động kém hiệu quả.','Đa dạng hóa',2077,NULL,_binary '\0'),(2176,'The total wealth of an individual or company, calculated as the value of all assets minus all liabilities.','The CEO’s net worth increased significantly after the company went public.','NOUN','Tổng tài sản của một cá nhân hoặc công ty sau khi trừ đi tất cả các khoản nợ.','Giá trị tài sản ròng của CEO đã tăng đáng kể sau khi công ty niêm yết cổ phiếu.','Giá trị tài sản ròng',2078,NULL,_binary '\0'),(2177,'An investment program funded by shareholders that trades in diversified holdings and is professionally managed.','Investing in a mutual fund is a good way for beginners to enter the stock market.','NOUN','Chương trình đầu tư do cổ đông đóng góp, giao dịch các danh mục đa dạng và được quản lý chuyên nghiệp.','Đầu tư vào quỹ tương hỗ là cách tốt để người mới bắt đầu gia nhập thị trường chứng khoán.','Quỹ tương hỗ',2079,NULL,_binary '\0'),(2178,'A type of investment fund that is traded on stock exchanges, much like stocks.','ETFs often track an index, such as the S&P 500.','NOUN','Loại quỹ đầu tư được giao dịch trên sàn chứng khoán giống như cổ phiếu.','Các quỹ ETF thường theo dõi một chỉ số, ví dụ như S&P 500.','Quỹ hoán đổi danh mục (ETF)',2080,NULL,_binary '\0'),(2179,'The degree of variability in investment returns that an investor is willing to withstand.','Your risk tolerance usually decreases as you get closer to retirement.','NOUN','Mức độ biến động của lợi nhuận đầu tư mà một nhà đầu tư sẵn lòng chịu đựng.','Khả năng chấp nhận rủi ro của bạn thường giảm đi khi bạn gần đến tuổi nghỉ hưu.','Khả năng chấp nhận rủi ro',2081,NULL,_binary '\0'),(2180,'A limited partnership of investors that uses high-risk methods, such as investing with borrowed money, in hopes of realizing large capital gains.','Hedge funds are typically only available to accredited investors.','NOUN','Quỹ đầu tư sử dụng các phương pháp rủi ro cao với hy vọng đạt được lợi nhuận vốn lớn.','Các quỹ đầu cơ thường chỉ dành cho các nhà đầu tư tổ chức hoặc cá nhân có tài sản lớn.','Quỹ đầu cơ',2082,NULL,_binary '\0'),(2183,'A performance measure used to evaluate the efficiency of an investment.','We calculated the ROI of the marketing campaign to see if it was worth the cost.','NOUN','Chỉ số đo lường hiệu quả của một khoản đầu tư.','Chúng tôi đã tính toán ROI của chiến dịch marketing để xem liệu nó có đáng chi phí bỏ ra không.','Tỷ suất hoàn vốn (ROI)',2085,NULL,_binary '\0'),(2184,'A grouping of investments that exhibit similar characteristics and are subject to the same laws and regulations.','Equities and fixed income are two different asset classes.','NOUN','Nhóm các khoản đầu tư có đặc điểm tương tự và chịu sự điều chỉnh của cùng các quy định.','Cổ phiếu và thu nhập cố định là hai lớp tài sản khác nhau.','Lớp tài sản',2086,NULL,_binary '\0'),(2185,'A group of people who jointly supervise the activities of an organization.','The Board of Directors is responsible for making major corporate decisions.','NOUN','Nhóm người cùng giám sát và quản lý các hoạt động của một tổ chức.','Hội đồng quản trị có trách nhiệm đưa ra các quyết định quan trọng của công ty.','Hội đồng quản trị',2087,NULL,_binary '\0'),(2187,'A person with an interest or concern in something, especially a business.','The company must consider the needs of all stakeholders, not just the owners.','NOUN','Người có quyền lợi hoặc mối quan tâm đến một doanh nghiệp (như nhân viên, khách hàng, cổ đông).','Công ty phải xem xét nhu cầu của tất cả các bên liên quan, không chỉ của những người chủ.','Bên liên quan',2089,NULL,_binary '\0'),(2188,'A business model in which companies make a concerted effort to operate in ways that enhance rather than degrade society and the environment.','CSR initiatives can improve a company’s brand image and reputation.','NOUN','Mô hình kinh doanh mà công ty nỗ lực hoạt động để đóng góp tích cực cho xã hội và môi trường.','Các sáng kiến CSR có thể cải thiện hình ảnh thương hiệu và danh tiếng của công ty.','Trách nhiệm xã hội của doanh nghiệp',2090,NULL,_binary '\0'),(2189,'A decision-making problem between two possible moral imperatives, neither of which is unambiguously acceptable or preferable.','Managers often face ethical dilemmas when balancing profit and safety.','NOUN','Vấn đề phải lựa chọn giữa hai nguyên tắc đạo đức mà không có lựa chọn nào hoàn hảo.','Các nhà quản lý thường đối mặt với những tình huống lưỡng nan về đạo đức khi cân bằng giữa lợi nhuận và an toàn.','Tiến thoái lưỡng nan về đạo đức',2091,NULL,_binary '\0'),(2190,'A situation in which a person is in a position to derive personal benefit from actions or decisions made in their official capacity.','Employees are required to disclose any potential conflict of interest to HR.','NOUN','Tình huống mà một người có thể thu lợi cá nhân từ các quyết định trong công việc chuyên môn.','Nhân viên được yêu cầu tiết lộ bất kỳ xung đột lợi ích tiềm ẩn nào cho bộ phận nhân sự.','Xung đột lợi ích',2092,NULL,_binary '\0'),(2191,'A person who informs on a person or organization engaged in an illicit activity.','The whistleblower exposed the company’s tax evasion scheme.','NOUN','Người báo cáo về các hoạt động bất hợp pháp của một cá nhân hoặc tổ chức.','Người tố giác đã phơi bày âm mưu trốn thuế của công ty.','Người tố giác',2093,NULL,_binary '\0'),(2192,'A legal obligation of one party to act in the best interest of another.','Corporate officers have a fiduciary duty to the company’s shareholders.','NOUN','Nghĩa vụ pháp lý của một bên phải hành động vì lợi ích tốt nhất của bên kia.','Các cán bộ công ty có nghĩa vụ ủy thác đối với các cổ đông của công ty.','Nghĩa vụ ủy thác',2094,NULL,_binary '\0'),(2193,'The quality of being done in an open way without secrets.','Transparency in financial reporting is vital for maintaining investor trust.','NOUN','Phẩm chất hoạt động một cách cởi mở và không giấu giếm.','Minh bạch trong báo cáo tài chính là yếu tố sống còn để duy trì niềm tin của nhà đầu tư.','Sự minh bạch',2095,NULL,_binary '\0'),(2195,'A set of rules outlining the social norms and religious rules and responsibilities of, or proper practices for, an individual, party or organization.','All employees must sign the company’s code of conduct upon hiring.','NOUN','Bộ quy tắc quy định về chuẩn mực và trách nhiệm của một cá nhân hoặc tổ chức.','Tất cả nhân viên phải ký vào bộ quy tắc ứng xử của công ty khi được tuyển dụng.','Bộ quy tắc ứng xử',2097,NULL,_binary '\0'),(2197,'The illegal practice of trading on the stock exchange to one’s own advantage through having access to confidential information.','Insider trading is a serious crime that undermines the fairness of the stock market.','NOUN','Việc mua bán cổ phiếu bất hợp pháp bằng cách sử dụng thông tin mật để trục lợi.','Giao dịch nội gián là tội ác nghiêm trọng phá hoại sự công bằng của thị trường chứng khoán.','Giao dịch nội gián',2099,NULL,_binary '\0'),(2199,'The rights that grant shareholders certain privileges within a corporation.','Good corporate governance protects shareholders’ rights and ensures fair treatment.','NOUN','Các quyền lợi cho phép cổ đông có những đặc quyền nhất định trong một tập đoàn.','Quản trị doanh nghiệp tốt bảo vệ quyền của cổ đông và đảm bảo đối xử công bằng.','Quyền của cổ đông',2101,NULL,_binary '\0'),(2200,'The study of individuals, groups, or organizations and all the activities associated with the purchase, use, and disposal of goods and services.','Understanding consumer behavior is essential for creating effective marketing campaigns.','NOUN','Nghiên cứu về các cá nhân/nhóm và các hoạt động liên quan đến việc mua sắm, sử dụng hàng hóa.','Hiểu hành vi người tiêu dùng là điều thiết yếu để tạo ra các chiến dịch marketing hiệu quả.','Hành vi người tiêu dùng',2102,NULL,_binary '\0'),(2201,'The measurement of physiological and neural signals to gain insight into customers’ motivations, preferences, and decisions.','Neuromarketing helps companies understand why consumers prefer one brand over another at a subconscious level.','NOUN','Việc đo lường các tín hiệu sinh lý và thần kinh để hiểu động cơ và quyết định của khách hàng.','Tiếp thị thần kinh giúp công ty hiểu tại sao người tiêu dùng thích thương hiệu này hơn thương hiệu kia ở mức độ tiềm thức.','Tiếp thị thần kinh',2103,NULL,_binary '\0'),(2203,'The tendency of some consumers to continue buying the same brand of goods rather than competing brands.','Excellent customer service is a key driver of brand loyalty.','NOUN','Xu hướng người tiêu dùng tiếp tục mua cùng một thương hiệu thay vì chọn đối thủ.','Dịch vụ khách hàng tuyệt vời là động lực chính của lòng trung thành với thương hiệu.','Lòng trung thành với thương hiệu',2105,NULL,_binary '\0'),(2204,'Marketing that engages the consumers’ senses and affects their perception, judgment, and behavior.','The scent of freshly baked bread in a supermarket is a classic example of sensory marketing.','NOUN','Tiếp thị tác động vào các giác quan của người tiêu dùng để ảnh hưởng đến nhận thức và hành vi.','Mùi bánh mì mới nướng trong siêu thị là một ví dụ điển hình của tiếp thị giác quan.','Tiếp thị giác quan',2106,NULL,_binary '\0'),(2206,'The buying of goods without planning to do so in advance, as a sudden decision.','Retailers place small items near the checkout counter to encourage impulse buying.','NOUN','Việc mua hàng mà không có kế hoạch trước, do một quyết định bất ngờ.','Các nhà bán lẻ đặt các món đồ nhỏ gần quầy thanh toán để khuyến khích mua sắm ngẫu hứng.','Mua sắm ngẫu hứng',2108,NULL,_binary '\0'),(2207,'A neuromarketing technique that measures where a person is looking and for how long.','Eye tracking data shows that consumers focus more on images than on text in ads.','NOUN','Kỹ thuật đo lường nơi một người đang nhìn và trong bao lâu.','Dữ liệu theo dõi ánh mắt cho thấy người tiêu dùng tập trung vào hình ảnh nhiều hơn văn bản trong quảng cáo.','Theo dõi ánh mắt',2109,NULL,_binary '\0'),(2208,'The degree to which a consumer feels an emotional connection to a brand or advertisement.','High emotional engagement leads to better brand recall.','NOUN','Mức độ mà người tiêu dùng cảm thấy có sự kết nối cảm xúc với thương hiệu hoặc quảng cáo.','Sự gắn kết cảm xúc cao dẫn đến khả năng ghi nhớ thương hiệu tốt hơn.','Sự gắn kết cảm xúc',2110,NULL,_binary '\0'),(2209,'A psychological phenomenon where people assume the actions of others in an attempt to reflect correct behavior for a given situation.','Positive reviews and testimonials are powerful forms of social proof.','NOUN','Hiện tượng tâm lý mà mọi người bắt chước hành động của người khác để hành xử \"đúng\".','Đánh giá tích cực và lời chứng thực là những hình thức bằng chứng xã hội mạnh mẽ.','Bằng chứng xã hội',2111,NULL,_binary '\0'),(2210,'A cognitive bias where an individual relies too heavily on an initial piece of information offered when making decisions.','The original price serves as an anchor, making the discounted price look like a bargain.','NOUN','Xu hướng phụ thuộc quá nhiều vào thông tin đầu tiên nhận được khi đưa ra quyết định.','Giá gốc đóng vai trò như một mỏ neo, làm cho giá giảm trông có vẻ như một món hời.','Hiệu ứng mỏ neo',2112,NULL,_binary '\0'),(2211,'The economic theory that a limited supply of a good, coupled with high demand for that good, results in a mismatch between the desired supply and demand equilibrium.','\"Limited edition\" products exploit the scarcity principle to drive sales.','NOUN','Thuyết cho rằng sự khan hiếm làm tăng giá trị và mong muốn sở hữu sản phẩm.','Các sản phẩm \"phiên bản giới hạn\" khai thác nguyên tắc khan hiếm để thúc đẩy doanh số.','Nguyên tắc khan hiếm',2113,NULL,_binary '\0'),(2213,'The measurement and statistical analysis of people’s unique physical and behavioral characteristics.','Neuromarketers use biometrics like heart rate and skin conductance to measure emotional responses.','NOUN','Việc đo lường và phân tích các đặc điểm thể chất và hành vi độc nhất của con người.','Các nhà tiếp thị thần kinh sử dụng sinh trắc học như nhịp tim để đo lường phản ứng cảm xúc.','Sinh trắc học',2115,NULL,_binary '\0'),(2215,'A tax in which the tax rate increases as the taxable amount increases.','Income tax is often a progressive tax, where high earners pay a higher percentage.','NOUN','Loại thuế mà thuế suất tăng dần khi thu nhập chịu thuế tăng lên.','Thuế thu nhập thường là loại thuế lũy tiến, trong đó những người có thu nhập cao phải trả tỷ lệ phần trăm cao hơn.','Thuế lũy tiến',2117,NULL,_binary '\0'),(2216,'A tax on the profits of a corporation.','The government decided to lower corporate tax to attract foreign investment.','NOUN','Loại thuế đánh trực tiếp trên lợi nhuận của các công ty và tổ chức kinh tế.','Chính phủ đã quyết định hạ thuế thu nhập doanh nghiệp để thu hút đầu tư nước ngoài.','Thuế thu nhập doanh nghiệp',2118,NULL,_binary '\0'),(2217,'A tax on the amount by which the value of an article has been increased at each stage of its production or distribution.','Most consumer goods in Vietnam are subject to a 10% Value-Added Tax.','NOUN','Thuế tính trên giá trị tăng thêm của hàng hóa, dịch vụ phát sinh trong quá trình sản xuất, lưu thông.','Hầu hết hàng hóa tiêu dùng tại Việt Nam chịu thuế giá trị gia tăng 10%.','Thuế giá trị gia tăng (VAT)',2119,NULL,_binary '\0'),(2218,'An indicator of financial health in which expenditures exceed revenue.','A large budget deficit may force the government to borrow more money.','NOUN','Tình trạng chi tiêu của chính phủ vượt quá nguồn thu (chủ yếu từ thuế).','Thâm hụt ngân sách lớn có thể buộc chính phủ phải vay thêm tiền.','Thâm hụt ngân sách',2120,NULL,_binary '\0'),(2219,'A period when income or receipts exceed outlays or expenditures.','The government aims for a budget surplus to pay down national debt.','NOUN','Tình trạng nguồn thu của chính phủ lớn hơn mức chi tiêu.','Chính phủ nỗ lực đạt được thặng dư ngân sách để trả nợ quốc gia.','Thặng dư ngân sách',2121,NULL,_binary '\0'),(2220,'Money spent by the state; government expenditure.','Increased public spending on infrastructure can stimulate economic growth.','NOUN','Các khoản chi tiêu của nhà nước cho cơ sở hạ tầng, giáo dục, y tế và quốc phòng.','Việc tăng chi tiêu công cho cơ sở hạ tầng có thể kích thích tăng trưởng kinh tế.','Chi tiêu công',2122,NULL,_binary '\0'),(2221,'The illegal non-payment or underpayment of taxes.','Tax evasion is a serious criminal offense punishable by heavy fines or imprisonment.','NOUN','Hành vi bất hợp pháp nhằm không nộp thuế hoặc nộp ít hơn mức quy định.','Trốn thuế là một tội hình sự nghiêm trọng có thể bị phạt tiền nặng hoặc bỏ tù.','Trốn thuế',2123,NULL,_binary '\0'),(2222,'The arrangement of one’s financial affairs to minimize tax liability within the law.','Companies often use complex accounting methods for legal tax avoidance.','NOUN','Việc sử dụng các phương thức hợp pháp để giảm thiểu số thuế phải nộp.','Các công ty thường sử dụng các phương pháp kế toán phức tạp để tránh thuế một cách hợp pháp.','Tránh thuế',2124,NULL,_binary '\0'),(2223,'A tax levied on certain goods and commodities produced or sold within a country, such as alcohol or tobacco.','High excise duties are often placed on luxury goods.','NOUN','Loại thuế đánh vào một số hàng hóa dịch vụ đặc biệt (như rượu, bia, thuốc lá).','Các mức thuế tiêu thụ đặc biệt cao thường được áp dụng đối với hàng hóa xa xỉ.','Thuế tiêu thụ đặc biệt',2125,NULL,_binary '\0'),(2224,'An aspect of a country’s tax code that is designed to encourage a particular economic activity.','The city offered tax incentives to tech companies that relocate their headquarters.','NOUN','Các quy định về thuế nhằm khuyến khích một hoạt động kinh tế cụ thể.','Thành phố đã đưa ra các ưu đãi thuế cho các công ty công nghệ chuyển trụ sở về đây.','Ưu đãi thuế',2126,NULL,_binary '\0'),(2225,'The use of government spending and tax measures to support economic activity during a recession.','The government announced a massive fiscal stimulus package to combat the effects of the pandemic.','NOUN','Việc sử dụng chi tiêu và thuế để thúc đẩy kinh tế trong thời kỳ suy thoái.','Chính phủ đã công bố một gói kích cầu tài khóa khổng lồ để chống lại các tác động của đại dịch.','Kích cầu tài khóa',2127,NULL,_binary '\0'),(2226,'The amount of money that a country’s government has borrowed.','Maintaining a sustainable level of sovereign debt is crucial for national financial stability.','NOUN','Tổng số tiền mà chính phủ của một quốc gia đã vay nợ.','Duy trì mức nợ công bền vững là yếu tố then chốt cho sự ổn định tài chính quốc gia.','Nợ công / Nợ chính phủ',2128,NULL,_binary '\0'),(2227,'A tax, such as income tax, which is levied on the income or profits of the person who pays it.','Direct taxes are paid directly to the government by the individual or organization.','NOUN','Loại thuế đánh trực tiếp vào thu nhập hoặc tài sản của người nộp thuế.','Thuế trực thu được cá nhân hoặc tổ chức nộp trực tiếp cho chính phủ.','Thuế trực thu',2129,NULL,_binary '\0'),(2228,'A tax levied on goods and services rather than on income or profits.','Sales tax and VAT are examples of indirect taxes.','NOUN','Loại thuế được tính vào giá hàng hóa, dịch vụ và do người tiêu dùng cuối cùng chi trả.','Thuế bán hàng và thuế giá trị gia tăng (VAT) là những ví dụ về thuế gián thu.','Thuế gián thu',2130,NULL,_binary '\0'),(2229,'A range of incomes taxed at a given rate.','A pay rise might push you into a higher tax bracket.','NOUN','Khoảng thu nhập bị đánh thuế ở một mức thuế suất nhất định.','Việc tăng lương có thể khiến bạn rơi vào khung thuế cao hơn.','Bậc thuế',2131,NULL,_binary '\0'),(2230,'A labor market characterized by the prevalence of short-term contracts or freelance work as opposed to permanent jobs.','Ride-sharing apps are a primary example of the growing gig economy.','NOUN','Thị trường lao động với các công việc ngắn hạn, tự do thay vì công việc cố định.','Các ứng dụng chia sẻ xe là ví dụ điển hình cho sự phát triển của nền kinh tế tự do (gig economy).','Nền kinh tế gig / Kinh tế việc làm tự do',2132,NULL,_binary '\0'),(2231,'A working style that allows professionals to work outside of a traditional office environment.','Many software developers prefer remote work to maintain a better work-life balance.','NOUN','Hình thức làm việc cho phép nhân viên làm việc bên ngoài văn phòng truyền thống.','Nhiều nhà phát triển phần mềm thích làm việc từ xa để duy trì sự cân bằng giữa công việc và cuộc sống tốt hơn.','Làm việc từ xa',2133,NULL,_binary '\0'),(2233,'The process of learning new skills or of teaching workers new skills.','Companies are investing in upskilling programs to help employees adapt to new technologies.','NOUN','Quá trình học thêm các kỹ năng mới để đáp ứng yêu cầu công việc hiện đại.','Các công ty đang đầu tư vào các chương trình nâng cao kỹ năng để giúp nhân viên thích nghi với công nghệ mới.','Nâng cao kỹ năng',2135,NULL,_binary '\0'),(2234,'The process of learning new skills so you can do a different job.','Reskilling is essential for workers whose jobs have been replaced by robots.','NOUN','Quá trình học các kỹ năng mới để chuyển sang làm một công việc khác hoàn toàn.','Đào tạo lại kỹ năng là điều cần thiết cho những người lao động có công việc bị thay thế bởi robot.','Đào tạo lại kỹ năng',2136,NULL,_binary '\0'),(2235,'The percentage of the population that is either employed or actively seeking employment.','A declining labor participation rate can signal an aging population.','NOUN','Tỷ lệ phần trăm dân số đang có việc làm hoặc đang tích cực tìm việc.','Tỷ lệ tham gia lực lượng lao động giảm có thể là dấu hiệu của tình trạng già hóa dân số.','Tỷ lệ tham gia lực lượng lao động',2137,NULL,_binary '\0'),(2236,'Personal attributes that enable someone to interact effectively and harmoniously with other people.','In the future of work, soft skills like empathy and communication will be more valuable than ever.','NOUN','Các thuộc tính cá nhân giúp con người tương tác hiệu quả và hòa hợp với người khác.','Trong tương lai của công việc, các kỹ năng mềm như sự thấu cảm và giao tiếp sẽ trở nên giá trị hơn bao giờ hết.','Kỹ năng mềm',2138,NULL,_binary '\0'),(2237,'A government program in which every adult citizen receives a set amount of money regularly.','Some economists argue that UBI is necessary to support people displaced by AI.','NOUN','Chương trình chính phủ cấp một khoản tiền định kỳ cho mọi công dân trưởng thành.','Một số nhà kinh tế lập luận rằng thu nhập cơ bản phổ quát là cần thiết để hỗ trợ những người bị thay thế bởi trí tuệ nhân tạo (AI).','Thu nhập cơ bản phổ quát',2139,NULL,_binary '\0'),(2238,'The condition in which people in a labor force are employed at less than full-time or at jobs inadequate for their training or economic needs.','The recession led to a high rate of underemployment among recent graduates.','NOUN','Tình trạng làm việc bán thời gian ngoài ý muốn hoặc làm việc thấp hơn trình độ chuyên môn.','Sự suy thoái đã dẫn đến tỷ lệ thiếu việc làm cao trong nhóm sinh viên mới tốt nghiệp.','Thiếu việc làm / Làm việc dưới năng lực',2140,NULL,_binary '\0'),(2240,'Negotiation of wages and other conditions of employment by an organized body of employees.','Through collective bargaining, the union secured a 5% pay increase for all workers.','NOUN','Việc đàm phán lương và điều kiện làm việc bởi một tổ chức đại diện người lao động (công đoàn).','Thông qua thương lượng tập thể, công đoàn đã đảm bảo mức tăng lương 5% cho tất cả công nhân.','Thương lượng tập thể',2142,NULL,_binary '\0'),(2241,'A person who works independently or who is not committed to a particular employer long-term.','Working as a freelancer offers flexibility but lacks traditional job benefits.','NOUN','Người làm việc độc lập và không cam kết lâu dài với một chủ lao động cụ thể.','Làm việc như một người làm nghề tự do mang lại sự linh hoạt nhưng thiếu các phúc lợi công việc truyền thống.','Người làm nghề tự do',2143,NULL,_binary '\0'),(2242,'The skills, knowledge, and experience possessed by an individual or population, viewed in terms of their value to an organization.','Investing in education is the best way to increase a nation’s human capital.','NOUN','Kỹ năng, kiến thức và kinh nghiệm của con người được xem xét dưới góc độ giá trị kinh tế.','Đầu tư vào giáo dục là cách tốt nhất để gia tăng vốn nhân lực của một quốc gia.','Vốn nhân lực',2144,NULL,_binary '\0'),(2243,'A person who earns a living working online while traveling from place to place.','The rise of remote work has made the lifestyle of a digital nomad more accessible.','NOUN','Người làm việc trực tuyến và di chuyển giữa nhiều địa điểm khác nhau.','Sự phát triển của làm việc từ xa đã làm cho lối sống du mục kỹ thuật số trở nên dễ tiếp cận hơn.','Du mục kỹ thuật số',2145,NULL,_binary '\0'),(2244,'The loss of jobs due to factors such as technological change, economic decline, or outsourcing.','Technological job displacement is a major concern in the era of artificial intelligence.','NOUN','Việc mất việc do thay đổi công nghệ, suy thoái kinh tế hoặc thuê ngoài.','Sự mất việc làm do công nghệ là một mối lo ngại lớn trong thời đại trí tuệ nhân tạo.','Sự mất việc làm (do thay đổi cơ cấu)',2146,NULL,_binary '\0'),(3042,'An official document issued by a government for travel','Don\'t forget to bring your passport.','NOUN','Giấy tờ chính thức do chính phủ cấp để đi du lịch','Đừng quên mang theo hộ chiếu của bạn.','Hộ chiếu',2147,NULL,_binary '\0'),(3043,'A rectangular case with a handle for carrying clothes','My suitcase is over the weight limit.','NOUN','Một chiếc túi hình chữ nhật có tay cầm để đựng quần áo','Va li của tôi bị quá trọng lượng cho phép.','Va li',2148,NULL,_binary '\0'),(3044,'The amount of luggage a passenger is allowed to carry','What is the baggage allowance for this flight?','NOUN','Lượng hành lý mà hành khách được phép mang theo','Hạn mức hành lý cho chuyến bay này là bao nhiêu?','Hành lý miễn cước',2149,NULL,_binary '\0'),(3045,'A small bag that you take onto the plane with you','You can only take one carry-on bag.','NOUN','Một chiếc túi nhỏ mà bạn mang lên máy bay cùng mình','Bạn chỉ có thể mang theo một túi hành lý xách tay.','Hành lý xách tay',2150,NULL,_binary '\0'),(3046,'The place where you register for your flight','Please go to the check-in counter at Terminal 1.','NOUN','Nơi bạn đăng ký cho chuyến bay của mình','Vui lòng đến quầy làm thủ tục tại Nhà ga số 1.','Quầy làm thủ tục',2151,NULL,_binary '\0'),(3047,'Luggage that is heavier than the permitted weight','I had to pay $50 for excess baggage.','NOUN','Hành lý nặng hơn trọng lượng cho phép','Tôi đã phải trả 50 đô la cho hành lý quá cước.','Hành lý quá cước',2152,NULL,_binary '\0'),(3048,'Easily broken or damaged','Please mark this bag as fragile.','ADJECTIVE','Dễ bị gãy hoặc hư hỏng','Làm ơn đánh dấu chiếc túi này là hàng dễ vỡ.','Dễ vỡ',2153,NULL,_binary '\0'),(3049,'A label attached to a bag showing the owner details','Put your name on the luggage tag.','NOUN','Nhãn gắn vào túi hiển thị thông tin chủ sở hữu','Hãy ghi tên bạn vào thẻ hành lý.','Thẻ hành lý',2154,NULL,_binary '\0'),(3050,'A moving strip used to transport luggage','Wait for your bags at the conveyor belt.','NOUN','Một dải chuyển động dùng để vận chuyển hành lý','Hãy đợi lấy túi tại băng chuyền.','Băng chuyền',2155,NULL,_binary '\0'),(3051,'A document provided during check-in to board the plane','Keep your boarding pass handy.','NOUN','Tài liệu cấp khi làm thủ tục để lên máy bay','Hãy giữ thẻ lên máy bay sẵn trên tay.','Thẻ lên máy bay',2156,NULL,_binary '\0'),(3052,'A device used for weighing luggage','Put your bag on the scales.','NOUN','Thiết bị dùng để cân hành lý','Hãy đặt túi của bạn lên cân.','Cân',2157,NULL,_binary '\0'),(3053,'Official papers that prove who you are','We need to see your identification.','NOUN','Giấy tờ chính thức chứng minh danh tính','Chúng tôi cần kiểm tra giấy tờ tùy thân của bạn.','Giấy tờ tùy thân',2158,NULL,_binary '\0'),(3054,'The maximum weight allowed for a bag','Don\'t exceed the weight limit.','NOUN','Trọng lượng tối đa được phép','Đừng vượt quá hạn mức trọng lượng.','Hạn mức trọng lượng',2159,NULL,_binary '\0'),(3055,'Substances like water or gels','No liquids over 100ml are allowed.','NOUN','Các chất như nước hoặc gel','Không được mang chất lỏng trên 100ml.','Chất lỏng',2160,NULL,_binary '\0'),(3056,'Things that are not allowed on the aircraft','Check the list of prohibited items.','NOUN','Những thứ không được mang lên máy bay','Hãy kiểm tra danh sách vật phẩm bị cấm.','Vật phẩm bị cấm',2161,NULL,_binary '\0'),(3057,'A machine that influences metal objects on your body','Remove your belt before walking through the metal detector.','NOUN','Máy phát hiện các vật thể kim loại trên người','Hãy tháo thắt lưng trước khi đi qua máy dò kim loại.','Máy dò kim loại',2162,NULL,_binary '\0'),(3058,'A machine used to see inside your luggage','Put your backpack on the belt for the X-ray machine.','NOUN','Máy dùng để nhìn vào bên trong hành lý của bạn','Hãy đặt ba lô của bạn lên băng chuyền của máy quét tia X.','Máy quét tia X',2163,NULL,_binary '\0'),(3059,'A form showing goods brought into a country','You must fill out a customs declaration form.','NOUN','Mẫu đơn kê khai hàng hóa mang vào một quốc gia','Bạn phải điền vào tờ khai hải quan.','Tờ khai hải quan',2164,NULL,_binary '\0'),(3060,'Goods that can be bought without paying tax','I bought some perfume at the duty-free shop.','ADJECTIVE','Hàng hóa có thể mua mà không phải trả thuế','Tôi đã mua một ít nước hoa tại cửa hàng miễn thuế.','Miễn thuế',2165,NULL,_binary '\0'),(3061,'To tell customs about goods you are bringing','Do you have anything to declare?','VERB','Thông báo cho hải quan về hàng hóa bạn mang theo','Bạn có gì cần khai báo không?','Khai báo',2166,NULL,_binary '\0'),(3062,'Items that are limited by rules','Alcohol and tobacco are restricted items.','NOUN','Các vật phẩm bị giới hạn bởi các quy định','Rượu và thuốc lá là những mặt hàng bị hạn chế.','Hàng hóa bị hạn chế',2167,NULL,_binary '\0'),(3063,'A person whose job is to protect a place','Follow the instructions of the security officer.','NOUN','Người có công việc bảo vệ một địa điểm','Hãy làm theo hướng dẫn của nhân viên an ninh.','Nhân viên an ninh',2168,NULL,_binary '\0'),(3064,'A search of someone by touching their clothes','I had to undergo a manual pat-down.','NOUN','Việc tìm kiếm ai đó bằng cách chạm vào quần áo của họ','Tôi đã phải trải qua một cuộc khám xét thân thể bằng tay.','Khám xét thân thể',2169,NULL,_binary '\0'),(3065,'A device that reads information or images','Please step inside the body scanner.','NOUN','Thiết bị đọc thông tin hoặc hình ảnh','Vui lòng bước vào bên trong máy quét toàn thân.','Máy quét',2170,NULL,_binary '\0'),(3066,'The act of looking at something carefully','My bags were chosen for a random inspection.','NOUN','Hành động xem xét một cái gì đó cẩn thận','Túi của tôi đã bị chọn để kiểm tra ngẫu nhiên.','Sự kiểm tra',2171,NULL,_binary '\0'),(3067,'A flat object used for carrying small items','Put your phone and keys in the tray.','NOUN','Vật phẳng dùng để đựng các đồ vật nhỏ','Hãy để điện thoại và chìa khóa của bạn vào khay.','Khay',2172,NULL,_binary '\0'),(3068,'Taking things into a country illegally','Customs works to prevent drug smuggling.','NOUN','Đưa đồ vật vào một quốc gia một cách bất hợp pháp','Hải quan làm việc để ngăn chặn việc buôn lậu ma túy.','Sự buôn lậu',2173,NULL,_binary '\0'),(3069,'Items that are produced to be sold','You must pay tax on commercial goods.','NOUN','Các mặt hàng được sản xuất để bán','Bạn phải trả thuế cho hàng hóa thương mại.','Hàng hóa',2174,NULL,_binary '\0'),(3070,'An unplanned search of a person or luggage','Don\'t worry, it is just a random check.','NOUN','Việc khám xét không có kế hoạch trước đối với người hoặc hành lý','Đừng lo lắng, đó chỉ là một cuộc kiểm tra ngẫu nhiên thôi.','Kiểm tra ngẫu nhiên',2175,NULL,_binary '\0'),(3071,'Permission to enter a restricted area','Wait for your security clearance before proceeding.','NOUN','Sự cho phép để vào một khu vực hạn chế','Hãy đợi sự cho phép an ninh trước khi tiếp tục.','Sự cho phép an ninh',2176,NULL,_binary '\0'),(3072,'A seating area in an airport for passengers waiting to board','We waited in the departure lounge for two hours.','NOUN','Khu vực ghế ngồi cho hành khách đợi lên máy bay','Chúng tôi đã đợi ở phòng chờ khởi hành trong hai tiếng.','Phòng chờ khởi hành',2177,NULL,_binary '\0'),(3073,'A place where you can ask for help or directions','Ask for a map at the information desk.','NOUN','Nơi bạn có thể yêu cầu trợ giúp hoặc hỏi đường','Hãy hỏi xin bản đồ tại quầy thông tin.','Quầy thông tin',2178,NULL,_binary '\0'),(3074,'A place where you can swap one country\'s money for another','Where is the nearest currency exchange?','NOUN','Nơi bạn có thể đổi tiền của quốc gia này sang quốc gia khác','Quầy đổi ngoại tệ gần nhất ở đâu?','Quầy đổi ngoại tệ',2179,NULL,_binary '\0'),(3075,'A store in an airport that sells goods without tax','I bought some chocolates at the duty-free shop.','NOUN','Cửa hàng trong sân bay bán hàng hóa không tính thuế','Tôi đã mua một ít sô-cô-la tại cửa hàng miễn thuế.','Cửa hàng miễn thuế',2180,NULL,_binary '\0'),(3076,'An area with many different restaurants','Let\'s meet at the food court for lunch.','NOUN','Khu vực có nhiều nhà hàng khác nhau','Hãy gặp nhau ở khu ẩm thực để ăn trưa nhé.','Khu ẩm thực',2181,NULL,_binary '\0'),(3077,'A machine that lets you take out cash','I need to find an ATM to get some cash.','NOUN','Máy cho phép bạn rút tiền mặt','Tôi cần tìm máy rút tiền để lấy một ít tiền mặt.','Máy rút tiền tự động',2182,NULL,_binary '\0'),(3078,'A place where lost items are kept','I left my umbrella at the lost and found.','NOUN','Nơi lưu giữ những vật phẩm bị mất','Tôi đã để quên ô ở phòng thất lạc đồ.','Phòng thất lạc đồ',2183,NULL,_binary '\0'),(3079,'A place to charge electronic devices','My phone is dead; I need a charging station.','NOUN','Nơi để sạc các thiết bị điện tử','Điện thoại tôi hết pin rồi; tôi cần một trạm sạc.','Trạm sạc',2184,NULL,_binary '\0'),(3080,'A location where you can connect to the internet','The airport provides a free Wi-Fi hotspot.','NOUN','Vị trí mà bạn có thể kết nối internet','Sân bay cung cấp điểm phát Wi-Fi miễn phí.','Điểm phát Wi-Fi',2185,NULL,_binary '\0'),(3081,'A private lounge for premium passengers','Business class passengers have access to the executive lounge.','NOUN','Phòng chờ riêng dành cho hành khách cao cấp','Hành khách hạng thương gia được quyền vào phòng chờ thương gia.','Phòng chờ hạng thương gia',2186,NULL,_binary '\0'),(3082,'A room with toilets and sinks','The restrooms are located near gate 5.','NOUN','Phòng có bồn cầu và bồn rửa','Nhà vệ sinh nằm gần cổng số 5.','Nhà vệ sinh',2187,NULL,_binary '\0'),(3083,'A designated place where people are allowed to smoke','Is there a smoking area inside the terminal?','NOUN','Nơi quy định mà mọi người được phép hút thuốc','Có khu vực hút thuốc bên trong nhà ga không?','Khu vực hút thuốc',2188,NULL,_binary '\0'),(3085,'A quiet room used for religious purposes','The airport has a multi-faith prayer room.','NOUN','Phòng yên tĩnh dùng cho mục đích tôn giáo','Sân bay có phòng cầu nguyện cho nhiều tôn giáo.','Phòng cầu nguyện',2190,NULL,_binary '\0'),(3086,'A place that sells newspapers and magazines','I bought a magazine at the newsstand.','NOUN','Nơi bán báo và tạp chí','Tôi đã mua một tờ tạp chí tại sạp báo.','Sạp báo',2191,NULL,_binary '\0'),(3088,'The process of getting on a plane','Boarding will begin in ten minutes.','NOUN','Quá trình đi lên máy bay','Việc lên máy bay sẽ bắt đầu trong mười phút tới.','Sự lên máy bay',2193,NULL,_binary '\0'),(3089,'The time when passengers can start getting on the plane','Check your ticket for the boarding time.','NOUN','Thời điểm hành khách có thể bắt đầu lên máy bay','Hãy kiểm tra vé để biết giờ lên máy bay.','Giờ lên máy bay',2194,NULL,_binary '\0'),(3091,'Not late; happening at the planned time','The flight is scheduled to leave on time.','ADJECTIVE','Không muộn; xảy ra vào thời gian đã định','Chuyến bay dự kiến sẽ khởi hành đúng giờ.','Đúng giờ',2196,NULL,_binary '\0'),(3092,'Happening later than planned','My flight is delayed due to bad weather.','ADJECTIVE','Xảy ra muộn hơn so với kế hoạch','Chuyến bay của tôi bị hoãn do thời tiết xấu.','Bị hoãn',2197,NULL,_binary '\0'),(3093,'Decided that a planned event will not happen','The flight to Paris has been canceled.','ADJECTIVE','Quyết định rằng một sự kiện đã lên kế hoạch sẽ không diễn ra','Chuyến bay đến Paris đã bị hủy.','Bị hủy',2198,NULL,_binary '\0'),(3094,'The final announcement for passengers to board','This is the last call for flight VN123.','NOUN','Thông báo cuối cùng để hành khách lên máy bay','Đây là lời gọi cuối cùng cho chuyến bay VN123.','Lời gọi cuối cùng',2199,NULL,_binary '\0'),(3096,'A specific code for a particular flight','What is your flight number?','NOUN','Mã số cụ thể cho một chuyến bay nhất định','Số hiệu chuyến bay của bạn là gì?','Số hiệu chuyến bay',2201,NULL,_binary '\0'),(3097,'A flight that requires passengers to change planes','I have a connecting flight in Singapore.','NOUN','Chuyến bay yêu cầu hành khách phải đổi máy bay','Tôi có một chuyến bay chuyển tiếp tại Singapore.','Chuyến bay chuyển tiếp',2202,NULL,_binary '\0'),(3098,'A flight that goes from one place to another without stopping','Is there a direct flight to London?','NOUN','Chuyến bay đi từ nơi này đến nơi khác mà không dừng lại','Có chuyến bay thẳng đến Luân Đôn không?','Chuyến bay thẳng',2203,NULL,_binary '\0'),(3099,'A short stay between two parts of a journey','We had a 24-hour stopover in Dubai.','NOUN','Một điểm nghỉ ngắn giữa hai chặng của một hành trình','Chúng tôi đã có 24 giờ dừng chân tại Dubai.','Điểm dừng',2204,NULL,_binary '\0'),(3100,'The long road where planes take off and land','The plane is waiting on the runway.','NOUN','Con đường dài nơi máy bay cất cánh và hạ cánh','Máy bay đang đợi trên đường băng.','Đường băng',2205,NULL,_binary '\0'),(3101,'The moment when a plane leaves the ground','Please fasten your seatbelts for take-off.','NOUN','Thời điểm máy bay rời khỏi mặt đất','Vui lòng thắt dây an toàn để cất cánh.','Cất cánh',2206,NULL,_binary '\0'),(3102,'A person who serves passengers on an aircraft','The flight attendant showed us how to use the oxygen mask.','NOUN','Người phục vụ hành khách trên máy bay','Tiếp viên hàng không đã hướng dẫn chúng tôi cách sử dụng mặt nạ oxy.','Tiếp viên hàng không',2207,NULL,_binary '\0'),(3103,'A strap used to hold a person in their seat','Please fasten your seatbelt during turbulence.','NOUN','Dây đai dùng để giữ một người ngồi yên tại ghế','Vui lòng thắt dây an toàn khi máy bay đi vào vùng nhiễu động.','Dây an toàn',2208,NULL,_binary '\0'),(3104,'A storage area above the seats on a plane','Please put your small bags in the overhead locker.','NOUN','Khu vực lưu trữ phía trên chỗ ngồi trên máy bay','Vui lòng để túi nhỏ của bạn vào ngăn hành lý phía trên.','Ngăn hành lý phía trên',2209,NULL,_binary '\0'),(3105,'A seat next to the walkway between the rows of seats','I prefer an aisle seat so I can stretch my legs.','NOUN','Chỗ ngồi bên cạnh lối đi giữa các dãy ghế','Tôi thích ghế gần lối đi để có thể duỗi chân.','Ghế gần lối đi',2210,NULL,_binary '\0'),(3106,'A seat next to the window of a plane','She loves the window seat to watch the clouds.','NOUN','Chỗ ngồi cạnh cửa sổ máy bay','Cô ấy thích ghế cạnh cửa sổ để ngắm mây.','Ghế cạnh cửa sổ',2211,NULL,_binary '\0'),(3107,'Unsteady movement of air that causes a plane to shake','The plane hit some turbulence over the ocean.','NOUN','Chuyển động không ổn định của không khí khiến máy bay bị rung lắc','Máy bay gặp hiện tượng nhiễu động khi bay qua đại dương.','Sự nhiễu động',2212,NULL,_binary '\0'),(3108,'A jacket that helps you float in water','Your life vest is under your seat.','NOUN','Áo khoác giúp bạn nổi trong nước','Áo phao của bạn nằm dưới ghế ngồi.','Áo phao',2213,NULL,_binary '\0'),(3109,'A small table that folds down from the back of the seat','Please put your tray table in the upright position.','NOUN','Bàn nhỏ gập xuống từ phía sau ghế ngồi','Vui lòng gập bàn ăn của bạn lại vị trí ban đầu.','Bàn ăn tại ghế',2214,NULL,_binary '\0'),(3110,'A device to breathe through if air pressure drops','The oxygen masks will drop down automatically.','NOUN','Thiết bị để thở nếu áp suất không khí giảm','Mặt nạ oxy sẽ tự động rơi xuống.','Mặt nạ oxy',2215,NULL,_binary '\0'),(3111,'Movies, music, and games provided during the flight','There is a great selection of movies on the in-flight entertainment.','NOUN','Phim, nhạc và trò chơi được cung cấp trong chuyến bay','Có một danh sách phim tuyệt vời trên hệ thống giải trí của máy bay.','Giải trí trên máy bay',2216,NULL,_binary '\0'),(3112,'A thick cover used for keeping warm','Could I have an extra blanket, please?','NOUN','Tấm đắp dày dùng để giữ ấm','Cho tôi xin thêm một chiếc chăn được không?','Chăn',2217,NULL,_binary '\0'),(3114,'A presentation of emergency procedures','Please pay attention to the safety demonstration.','NOUN','Việc trình bày các quy trình khẩn cấp','Vui lòng chú ý lắng nghe hướng dẫn an toàn.','Hướng dẫn an toàn',2219,NULL,_binary '\0'),(3115,'Drinks and small snacks provided','Light refreshments will be served shortly.','NOUN','Đồ uống và thức ăn nhẹ được cung cấp','Đồ ăn nhẹ sẽ sớm được phục vụ.','Đồ ăn nhẹ',2220,NULL,_binary '\0'),(3116,'A button used to summon a flight attendant','Press the call button if you need assistance.','NOUN','Nút bấm dùng để gọi tiếp viên hàng không','Hãy nhấn nút gọi tiếp viên nếu bạn cần trợ giúp.','Nút gọi tiếp viên',2221,NULL,_binary '\0'),(3117,'The place where officials check the documents of people entering a country','You need to go through immigration after landing.','NOUN','Nơi các quan chức kiểm tra giấy tờ của những người vào một quốc gia','Bạn cần đi qua khu vực nhập cảnh sau khi hạ cánh.','Cục quản lý xuất nhập cảnh',2222,NULL,_binary '\0'),(3118,'An official mark in a passport that allows you to enter a country','Do I need a visa to visit Vietnam?','NOUN','Dấu xác nhận chính thức trong hộ chiếu cho phép bạn vào một quốc gia','Tôi có cần thị thực để đến Việt Nam không?','Thị thực',2223,NULL,_binary '\0'),(3119,'A person who lives in a particular place','There is a separate line for local residents.','NOUN','Một người sống ở một nơi cụ thể','Có một hàng đợi riêng dành cho cư dân địa phương.','Cư dân / Người trú ngụ',2224,NULL,_binary '\0'),(3121,'A person from a different country','There was a long queue for foreigners at the airport.','NOUN','Một người đến từ một quốc gia khác','Có một hàng dài những người nước ngoài tại sân bay.','Người nước ngoài',2226,NULL,_binary '\0'),(3122,'To come to an end (of a document)','My passport will expire next month.','VERB','Kết thúc thời hạn hiệu lực (của một loại giấy tờ)','Hộ chiếu của tôi sẽ hết hạn vào tháng tới.','Hết hạn',2227,NULL,_binary '\0'),(3123,'An official document allowing someone to enter a country','You must present your entry permit at the desk.','NOUN','Tài liệu chính thức cho phép ai đó vào một quốc gia','Bạn phải trình giấy phép nhập cảnh tại quầy.','Giấy phép nhập cảnh',2228,NULL,_binary '\0'),(3125,'The length of time you will stay in a country','What is your intended duration of stay?','NOUN','Khoảng thời gian bạn sẽ ở lại một quốc gia','Thời gian lưu trú dự kiến của bạn là bao lâu?','Thời gian lưu trú',2230,NULL,_binary '\0'),(3126,'The reason why you are visiting a country','Is the purpose of your visit business or pleasure?','NOUN','Lý do tại sao bạn đến thăm một quốc gia','Mục đích chuyến đi của bạn là công tác hay du lịch?','Mục đích chuyến đi',2231,NULL,_binary '\0'),(3128,'A mark made by the pattern of lines on a finger','Place your index finger on the scanner for a fingerprint.','NOUN','Vết để lại do các đường nét trên đầu ngón tay','Hãy đặt ngón trỏ lên máy quét để lấy dấu vân tay.','Dấu vân tay',2233,NULL,_binary '\0'),(3129,'An official mark put on a document','The officer put a stamp in my passport.','NOUN','Một dấu xác nhận chính thức được đóng lên tài liệu','Viên chức đã đóng dấu vào hộ chiếu của tôi.','Con dấu',2234,NULL,_binary '\0'),(3130,'A form given to passengers before they arrive at a country','Fill out the arrival card before you reach the desk.','NOUN','Mẫu đơn phát cho hành khách trước khi họ đến một quốc gia','Hãy điền tờ khai nhập cảnh trước khi bạn đến quầy.','Tờ khai nhập cảnh',2235,NULL,_binary '\0'),(3131,'The act of forcing a person to leave a country','Illegal entry can lead to deportation.','NOUN','Hành động buộc một người phải rời khỏi một quốc gia','Nhập cảnh trái phép có thể dẫn đến việc bị trục xuất.','Sự trục xuất',2236,NULL,_binary '\0'),(3132,'The area in an airport where arriving passengers collect their luggage','Follow the signs to the baggage claim area.','NOUN','Khu vực trong sân bay nơi hành khách đến nhận lại hành lý của mình','Hãy đi theo biển báo để đến khu vực nhận hành lý.','Khu vực nhận hành lý',2237,NULL,_binary '\0'),(3133,'A moving belt that delivers luggage to passengers','Your bags will be on carousel number 5.','NOUN','Băng chuyền chuyển hành lý đến cho hành khách','Hành lý của bạn sẽ ở băng chuyền số 5.','Băng chuyền hành lý',2238,NULL,_binary '\0'),(3134,'Bags that have failed to arrive at the destination','Go to the lost luggage desk to report your missing bag.','NOUN','Những chiếc túi không đến được điểm đến như dự kiến','Hãy đến quầy hành lý thất lạc để báo cáo việc mất túi.','Hành lý thất lạc',2239,NULL,_binary '\0'),(3135,'Harmed or broken','My suitcase was damaged during the flight.','ADJECTIVE','Bị hại hoặc bị gãy, vỡ','Va li của tôi đã bị hư hỏng trong chuyến bay.','Bị hư hỏng',2240,NULL,_binary '\0'),(3136,'A person who loads and unloads luggage from aircraft','The baggage handlers are loading the plane now.','NOUN','Người xếp và dỡ hành lý khỏi máy bay','Các nhân viên bốc xếp đang đưa hành lý lên máy bay.','Nhân viên bốc xếp hành lý',2241,NULL,_binary '\0'),(3137,'An official document used to request compensation','You need to fill out a claim form for the lost items.','NOUN','Tài liệu chính thức dùng để yêu cầu bồi thường','Bạn cần điền vào mẫu đơn khiếu nại cho các đồ vật bị mất.','Mẫu đơn khiếu nại',2242,NULL,_binary '\0'),(3140,'A unique code on a luggage tag','The officer asked for my baggage tag number.','NOUN','Mã số duy nhất trên thẻ hành lý','Viên chức đã hỏi số thẻ hành lý của tôi.','Số thẻ hành lý',2245,NULL,_binary '\0'),(3141,'A special feature that helps identify something','Does your suitcase have any identification marks?','NOUN','Đặc điểm riêng biệt giúp nhận dạng vật gì đó','Va li của bạn có dấu hiệu nhận dạng nào không?','Dấu hiệu nhận dạng',2246,NULL,_binary '\0'),(3142,'An official report for lost or damaged luggage','You must get a PIR before leaving the airport.','NOUN','Báo cáo chính thức cho hành lý bị mất hoặc hư hỏng','Bạn phải lấy biên bản PIR trước khi rời khỏi sân bay.','Biên bản bất thường về tài sản',2247,NULL,_binary '\0'),(3143,'Heavier than the allowed amount','Your bag is overweight by two kilograms.','ADJECTIVE','Nặng hơn mức cho phép','Túi của bạn bị quá trọng lượng hai kg.','Quá trọng lượng',2248,NULL,_binary '\0'),(3144,'Put in the wrong place','The luggage was misplaced during the transfer.','ADJECTIVE','Bị đặt sai vị trí','Hành lý đã bị để nhầm chỗ trong quá trình chuyển tiếp.','Bị để nhầm chỗ',2249,NULL,_binary '\0'),(3145,'The act of taking something to a person or place','The airline will arrange the delivery of your bags.','NOUN','Hành động mang thứ gì đó đến một người hoặc địa điểm','Hãng hàng không sẽ sắp xếp việc giao lại túi cho bạn.','Sự giao hàng / Vận chuyển',2250,NULL,_binary '\0'),(3146,'A number used to follow the progress of a delivery','Use this tracking number to check your bag\'s status.','NOUN','Số dùng để theo dõi tiến trình giao hàng','Sử dụng mã số theo dõi này để kiểm tra tình trạng túi của bạn.','Mã số theo dõi',2251,NULL,_binary '\0'),(3150,'A series of numbers given to prove a booking is made','Can you give me your confirmation number, please?','NOUN','Một dãy số được cung cấp để chứng minh việc đặt chỗ đã hoàn tất','Bạn có thể cho tôi biết mã số xác nhận của bạn không?','Mã số xác nhận',2255,NULL,_binary '\0'),(3152,'The amount of money charged for a room','What is the nightly rate for a single room?','NOUN','Số tiền phải trả cho một căn phòng','Giá phòng đơn mỗi đêm là bao nhiêu?','Mức giá / Giá phòng',2257,NULL,_binary '\0'),(3154,'Rules about how and when a booking can be cancelled','Please read our cancellation policy before booking.','NOUN','Các quy định về cách thức và thời điểm có thể hủy đặt phòng','Vui lòng đọc chính sách hủy phòng của chúng tôi trước khi đặt.','Chính sách hủy phòng',2259,NULL,_binary '\0'),(3156,'Buying something a long time before you use it','Advance purchase rates are usually much cheaper.','NOUN','Mua thứ gì đó một thời gian dài trước khi sử dụng','Giá đặt phòng trước thường rẻ hơn nhiều.','Mua/Đặt trước',2261,NULL,_binary '\0'),(3159,'A room for two people with one large bed','Is the double room available for three nights?','NOUN','Phòng dành cho hai người với một chiếc giường lớn','Phòng đôi còn trống trong ba đêm không?','Phòng đôi (1 giường lớn)',2264,NULL,_binary '\0'),(3160,'A room for two people with two separate beds','We would prefer a twin room instead of a double.','NOUN','Phòng dành cho hai người với hai chiếc giường riêng biệt','Chúng tôi muốn một phòng hai giường đơn thay vì phòng giường đôi.','Phòng đôi (2 giường đơn)',2265,NULL,_binary '\0'),(3161,'The date on which you arrive at a hotel','Please confirm your check-in date and time.','NOUN','Ngày mà bạn đến khách sạn','Vui lòng xác nhận ngày và giờ nhận phòng của bạn.','Ngày nhận phòng',2266,NULL,_binary '\0'),(3162,'The act of registering at a hotel','Check-in is at 2 PM.','NOUN','Việc làm thủ tục đăng ký khi đến khách sạn','Giờ nhận phòng là 2 giờ chiều.','Sự nhận phòng',2267,NULL,_binary '\0'),(3163,'The counter or desk where you register','Please go to the check-in to get your key.','NOUN','Nơi bạn thực hiện việc đăng ký','Vui lòng đến quầy làm thủ tục để lấy chìa khóa.','Quầy làm thủ tục',2267,NULL,_binary '\0'),(3164,'The area where visitors are greeted','Call reception if you need extra towels.','NOUN','Khu vực đón tiếp khách','Hãy gọi lễ tân nếu bạn cần thêm khăn tắm.','Quầy lễ tân',2268,NULL,_binary '\0'),(3165,'A person who works at the front desk','The receptionist handed me the room key.','NOUN','Người làm việc tại quầy tiếp đón','Nhân viên lễ tân đã đưa cho tôi chìa khóa phòng.','Nhân viên lễ tân',2269,NULL,_binary '\0'),(3166,'The main desk in a hotel lobby','You can leave your messages at the front desk.','NOUN','Quầy chính ở sảnh khách sạn','Bạn có thể để lại tin nhắn tại quầy tiếp tân.','Bàn tiếp tân / Quầy trước',2270,NULL,_binary '\0'),(3167,'A person whose job is to carry luggage','The porter will take your bags to your room.','NOUN','Người có công việc là mang vác hành lý','Nhân viên khuân vác sẽ mang túi của bạn lên phòng.','Nhân viên khuân vác',2271,NULL,_binary '\0'),(3168,'A staff member who carries luggage and shows guests to their rooms','The bellhop helped us with our heavy suitcases.','NOUN','Nhân viên mang hành lý và dẫn khách nhận phòng','Nhân viên phục vụ sảnh đã giúp chúng tôi với những chiếc va li nặng.','Nhân viên phục vụ sảnh',2272,NULL,_binary '\0'),(3171,'A document you fill in with your personal details','Please sign the registration form at the bottom.','NOUN','Tài liệu bạn điền thông tin cá nhân khi nhận phòng','Vui lòng ký tên vào phía dưới phiếu đăng ký.','Phiếu đăng ký',2275,NULL,_binary '\0'),(3172,'A cart used for moving heavy bags','The porter loaded the bags onto the luggage trolley.','NOUN','Xe dùng để di chuyển các túi đồ nặng','Nhân viên khuân vác đã chất túi lên xe đẩy hành lý.','Xe đẩy hành lý',2276,NULL,_binary '\0'),(3173,'A person staying in a hotel','The hotel can accommodate up to 500 guests.','NOUN','Người đang ở lại khách sạn','Khách sạn có thể chứa tới 500 khách.','Khách nghỉ / Khách lưu trú',2277,NULL,_binary '\0'),(3174,'A person invited to a place or event','He was a special guest at the opening ceremony.','NOUN','Người được mời đến một nơi hoặc sự kiện','Ông ấy là khách mời đặc biệt tại lễ khai trương.','Khách mời',2277,NULL,_binary '\0'),(3176,'Checking into a hotel after the standard time','Is there an extra charge for late check-in?','NOUN','Thực hiện thủ tục nhận phòng sau giờ quy định','Có tính thêm phí khi nhận phòng muộn không?','Nhận phòng muộn',2279,NULL,_binary '\0'),(3177,'A person who parks cars for guests','Leave your keys with the valet.','NOUN','Người đỗ xe cho khách','Hãy để lại chìa khóa cho nhân viên đỗ xe.','Nhân viên đỗ xe',2280,NULL,_binary '\0'),(3178,'A person who cleans clothes for guests','The hotel offers a valet service for laundry.','NOUN','Người làm sạch quần áo cho khách','Khách sạn cung cấp dịch vụ giặt ủi riêng.','Nhân viên giặt ủi / Phục vụ riêng',2280,NULL,_binary '\0'),(3179,'A small amount of extra money given for service','It is common to give the porter a small tip.','NOUN','Một khoản tiền nhỏ thêm cho dịch vụ','Thường thì người ta sẽ cho nhân viên khuân vác một ít tiền boa.','Tiền boa / Tiền típ',2281,NULL,_binary '\0'),(3180,'A useful piece of advice','The receptionist gave us some great tips on local restaurants.','NOUN','Một mẩu lời khuyên hữu ích','Nhân viên lễ tân đã cho chúng tôi vài mẹo hay về các nhà hàng địa phương.','Lời khuyên / Mẹo',2281,NULL,_binary '\0'),(3181,'A room intended for one person to stay in','I booked a single room for my business trip.','NOUN','Phòng dành cho một người ở','Tôi đã đặt một phòng đơn cho chuyến công tác của mình.','Phòng đơn',2282,NULL,_binary '\0'),(3182,'A set of connected rooms in a hotel','The presidential suite is on the top floor.','NOUN','Một nhóm các phòng thông nhau (thường có phòng khách và phòng ngủ)','Phòng tổng thống nằm ở tầng cao nhất.','Phòng bộ / Dãy phòng',2283,NULL,_binary '\0'),(3183,'A set of matching things (furniture or software)','The hotel rooms feature a modern furniture suite.','NOUN','Một bộ đồ nội thất hoặc bộ phần mềm đi kèm','Các phòng khách sạn có bộ nội thất hiện đại.','Bộ / Tập hợp',2283,NULL,_binary '\0'),(3185,'A system that keeps the air cool in a building','Does the room have individually controlled air conditioning?','NOUN','Hệ thống giữ cho không khí trong tòa nhà luôn mát mẻ','Phòng có điều hòa điều khiển riêng biệt không?','Điều hòa nhiệt độ',2285,NULL,_binary '\0'),(3186,'A small fridge in a hotel room containing drinks','Items in the mini-bar are not free of charge.','NOUN','Tủ lạnh nhỏ trong phòng khách sạn chứa đồ uống','Đồ trong tủ lạnh nhỏ không được miễn phí.','Quầy bar nhỏ / Tủ lạnh nhỏ',2286,NULL,_binary '\0'),(3187,'Two hotel rooms that are next to each other','We requested adjoining rooms for our children.','NOUN','Hai phòng khách sạn nằm cạnh nhau','Chúng tôi đã yêu cầu các phòng liền kề cho con cái.','Phòng liền kề',2287,NULL,_binary '\0'),(3188,'An area with a wall or bars around it that is joined to the outside wall','Our room had a small balcony overlooking the sea.','NOUN','Khu vực có tường hoặc thanh chắn gắn vào bức tường phía ngoài','Phòng chúng tôi có một ban công nhỏ nhìn ra biển.','Ban công',2288,NULL,_binary '\0'),(3189,'A strong metal box with a lock for storing valuables','Please put your jewelry in the hotel safe.','NOUN','Hộp kim loại chắc chắn có khóa để cất đồ quý giá','Vui lòng để trang sức của bạn vào két sắt của khách sạn.','Két sắt',2289,NULL,_binary '\0'),(3190,'Not in danger or likely to be harmed','I feel very safe in this neighborhood.','ADJECTIVE','Không gặp nguy hiểm hoặc không dễ bị tổn hại','Tôi cảm thấy rất an toàn ở khu vực này.','An toàn',2289,NULL,_binary '\0'),(3191,'Items used in washing and taking care of your body','Complimentary toiletries are provided in the bathroom.','NOUN','Các vật dụng dùng để tắm rửa và chăm sóc cơ thể','Đồ vệ sinh cá nhân miễn phí được cung cấp trong phòng tắm.','Đồ vệ sinh cá nhân',2290,NULL,_binary '\0'),(3192,'Soft loose shoes worn in the house','The hotel provides disposable slippers for guests.','NOUN','Giày mềm, lỏng dùng để đi trong nhà','Khách sạn cung cấp dép đi trong nhà dùng một lần cho khách.','Dép đi trong nhà',2291,NULL,_binary '\0'),(3195,'A container for boiling water','There is an electric kettle and tea bags in the room.','NOUN','Dụng cụ dùng để đun sôi nước','Trong phòng có ấm đun nước điện và trà túi lọc.','Ấm đun nước',2293,NULL,_binary '\0'),(3196,'The sheets and pillowcases used on a bed','We change the bed linen every morning.','NOUN','Tấm trải và vỏ gối dùng trên giường','Chúng tôi thay ga trải giường mỗi sáng.','Ga trải giường và vỏ gối',2294,NULL,_binary '\0'),(3197,'A loose piece of clothing worn before or after a bath','Soft white bathrobes are available in the closet.','NOUN','Quần áo rộng mặc trước hoặc sau khi tắm','Áo choàng tắm trắng mềm có sẵn trong tủ quần áo.','Áo choàng tắm',2295,NULL,_binary '\0'),(3198,'A machine that blows hot air to dry hair','You will find a hairdryer in the bathroom drawer.','NOUN','Máy thổi khí nóng để làm khô tóc','Bạn sẽ thấy máy sấy tóc trong ngăn kéo phòng tắm.','Máy sấy tóc',2296,NULL,_binary '\0'),(3201,'A room or building equipped for physical exercise','Is there a gym in the hotel?','NOUN','Phòng hoặc tòa nhà được trang bị để tập thể dục','Trong khách sạn có phòng tập gym không?','Phòng tập thể dục',2298,NULL,_binary '\0'),(3202,'Physical education classes','We have gym on Wednesdays.','NOUN','Các lớp học giáo dục thể chất','Chúng tôi có tiết thể dục vào các ngày thứ Tư.','Môn thể dục',2298,NULL,_binary '\0'),(3203,'An area of water for people to swim in','The outdoor swimming pool is heated in winter.','NOUN','Một khu vực chứa nước để mọi người bơi lội','Hồ bơi ngoài trời được sưởi ấm vào mùa đông.','Hồ bơi',2299,NULL,_binary '\0'),(3204,'A place where people go to improve their health through beauty treatments','You can book a massage at the hotel spa.','NOUN','Nơi mọi người đến để cải thiện sức khỏe qua các liệu pháp làm đẹp','Bạn có thể đặt lịch massage tại spa của khách sạn.','Spa / Khu nghỉ dưỡng sức khỏe',2300,NULL,_binary '\0'),(3205,'A room that is heated to a very high temperature to make people sweat','Relaxing in the sauna is a great way to end the day.','NOUN','Phòng được làm nóng ở nhiệt độ cao để khiến người ta đổ mồ hôi','Thư giãn trong phòng xông hơi là một cách tuyệt vời để kết thúc ngày dài.','Phòng xông hơi khô',2301,NULL,_binary '\0'),(3206,'An exercise machine for running or walking in one place','I spent 30 minutes on the treadmill this morning.','NOUN','Máy tập thể dục để chạy hoặc đi bộ tại chỗ','Tôi đã dành 30 phút trên máy chạy bộ sáng nay.','Máy chạy bộ',2302,NULL,_binary '\0'),(3207,'A boring job that is always the same','She felt like she was on a treadmill of endless meetings.','NOUN','Một công việc nhàm chán và luôn lặp lại','Cô ấy cảm thấy như đang trong vòng xoáy của những cuộc họp vô tận.','Công việc đơn điệu / Vòng lặp',2302,NULL,_binary '\0'),(3208,'A room with lockers for changing clothes','You can leave your clothes in the locker room.','NOUN','Phòng có tủ để đồ để thay quần áo','Bạn có thể để quần áo trong phòng thay đồ.','Phòng thay đồ có tủ khóa',2303,NULL,_binary '\0'),(3209,'A place in a hotel with computers, printers, and internet','I need to print some documents at the business center.','NOUN','Nơi trong khách sạn có máy tính, máy in và internet','Tôi cần in một số tài liệu tại trung tâm dịch vụ văn phòng.','Trung tâm dịch vụ văn phòng',2304,NULL,_binary '\0'),(3210,'A large room for formal meetings','The presentation will be held in the main conference room.','NOUN','Phòng lớn dành cho các cuộc họp trang trọng','Buổi thuyết trình sẽ được tổ chức tại phòng hội nghị chính.','Phòng hội nghị',2305,NULL,_binary '\0'),(3211,'A bar located on the top of a building','The rooftop bar offers a panoramic view of the city.','NOUN','Quầy bar nằm trên đỉnh của tòa nhà','Quầy bar tầng thượng có tầm nhìn toàn cảnh thành phố.','Quầy bar tầng thượng',2306,NULL,_binary '\0'),(3212,'An area where cars can be left','The hotel parking lot is free for guests.','NOUN','Khu vực có thể để xe','Bãi đậu xe khách sạn miễn phí cho khách lưu trú.','Bãi đậu xe',2307,NULL,_binary '\0'),(3213,'A machine that carries people up and down in a building','Take the elevator to the 10th floor.','NOUN','Máy chở người lên xuống trong tòa nhà','Hãy đi thang máy lên tầng 10.','Thang máy',2308,NULL,_binary '\0'),(3214,'A room in a hotel for waiting or relaxing','You can relax in the guest lounge.','NOUN','Phòng trong khách sạn để chờ đợi hoặc thư giãn','Bạn có thể thư giãn tại sảnh dành cho khách.','Phòng chờ / Sảnh thư giãn',2309,NULL,_binary '\0'),(3215,'To stand, sit, or lie in a lazy way','They spent the afternoon lounging by the pool.','VERB','Đứng, ngồi hoặc nằm một cách thong thả, lười biếng','Họ đã dành cả buổi chiều thư giãn bên hồ bơi.','Ngồi/Nằm thư giãn',2309,NULL,_binary '\0'),(3216,'A room filled with hot steam for relaxation','The steam room is good for your skin.','NOUN','Phòng chứa đầy hơi nước nóng để thư giãn','Phòng xông hơi ướt rất tốt cho làn da của bạn.','Phòng xông hơi ướt',2310,NULL,_binary '\0'),(3217,'A brand name for a bath with bubbles and jets of water','The hotel suite includes a private Jacuzzi.','NOUN','Tên thương hiệu cho bồn tắm có bọt khí và tia nước phun','Phòng suite của khách sạn bao gồm bồn sục riêng.','Bồn tắm massage / Bồn sục',2311,NULL,_binary '\0'),(3221,'A meal where guests serve themselves from a variety of dishes set out on a table','A buffet lunch is served in the main dining hall.','NOUN','Bữa ăn nơi khách tự phục vụ từ các món bày sẵn trên bàn','Bữa trưa buffet được phục vụ tại sảnh ăn chính.','Tiệc tự chọn / Buffet',2314,NULL,_binary '\0'),(3222,'To ask for food or drink in a restaurant','I would like to order a club sandwich.','VERB','Yêu cầu đồ ăn hoặc thức uống trong nhà hàng','Tôi muốn đặt một chiếc bánh mì kẹp club sandwich.','Đặt món / Gọi món',2315,NULL,_binary '\0'),(3223,'The way in which people or things are arranged','Please list the names in alphabetical order.','NOUN','Cách thức mà người hoặc vật được sắp xếp','Vui lòng liệt kê các tên theo thứ tự bảng chữ cái.','Thứ tự / Trật tự',2315,NULL,_binary '\0'),(3224,'A light breakfast of bread, butter, jam, and coffee','A continental breakfast is included in your room rate.','NOUN','Bữa sáng nhẹ gồm bánh mì, bơ, mứt và cà phê','Bữa sáng kiểu Âu đã bao gồm trong giá phòng của bạn.','Bữa sáng kiểu Âu nhẹ',2316,NULL,_binary '\0'),(3225,'A list of food and drinks available in a restaurant','Could we see the dessert menu, please?','NOUN','Danh sách các món ăn thức uống có sẵn trong nhà hàng','Cho chúng tôi xem thực đơn tráng miệng được không?','Thực đơn',2317,NULL,_binary '\0'),(3226,'A list of choices on a computer screen','Go to the \"Edit\" menu to find the \"Copy\" command.','NOUN','Danh sách các lựa chọn trên màn hình máy tính','Vào danh mục \"Edit\" để tìm lệnh \"Copy\".','Danh mục / Trình đơn',2317,NULL,_binary '\0'),(3228,'To provide food or drink','Breakfast is served from 7 to 10 AM.','VERB','Cung cấp đồ ăn hoặc thức uống','Bữa sáng được phục vụ từ 7 đến 10 giờ sáng.','Phục vụ',2319,NULL,_binary '\0'),(3229,'To work for an organization or person','She has served the hotel for over ten years.','VERB','Làm việc cho một tổ chức hoặc cá nhân','Cô ấy đã phục vụ tại khách sạn hơn mười năm.','Phục vụ / Phụng sự',2319,NULL,_binary '\0'),(3230,'Knives, forks, and spoons used for eating food','Could you bring some extra cutlery for our room?','NOUN','Dao, nĩa và thìa dùng để ăn uống','Bạn có thể mang thêm một bộ dao nĩa lên phòng chúng tôi không?','Bộ dụng cụ ăn / Dao nĩa',2320,NULL,_binary '\0'),(3232,'A request for payment of money owed','Can I have the bill, please?','NOUN','Yêu cầu thanh toán số tiền nợ','Cho tôi xin hóa đơn được không?','Hóa đơn',2322,NULL,_binary '\0'),(3233,'A formal statement of a planned new law','The government introduced a new bill on education.','NOUN','Một bản tuyên bố chính thức về một luật mới đang được lên kế hoạch','Chính phủ đã đưa ra một dự luật mới về giáo dục.','Dự luật',2322,NULL,_binary '\0'),(3234,'A style of eating that is usually expensive and high quality','The hotel is famous for its award-winning fine dining restaurant.','NOUN','Phong cách ăn uống thường đắt đỏ và có chất lượng cao','Khách sạn nổi tiếng với nhà hàng ẩm thực cao cấp đã đạt giải thưởng.','Ẩm thực cao cấp',2323,NULL,_binary '\0'),(3235,'Special needs regarding food (e.g., allergies or vegetarian)','Please inform us of any dietary requirements before you arrive.','NOUN','Nhu cầu đặc biệt về thực phẩm (ví dụ: dị ứng hoặc ăn chay)','Vui lòng thông báo cho chúng tôi bất kỳ yêu cầu ăn uống đặc biệt nào trước khi bạn đến.','Yêu cầu về chế độ ăn uống',2324,NULL,_binary '\0'),(3236,'Light food and drinks','Light refreshments will be served during the break.','NOUN','Đồ ăn và thức uống nhẹ nhàng','Đồ ăn nhẹ sẽ được phục vụ trong giờ nghỉ.','Món ăn nhẹ / Đồ giải khát',2325,NULL,_binary '\0'),(3237,'An amount of money added to the bill for the service','The bill includes a 10% service charge.','NOUN','Một khoản tiền được cộng vào hóa đơn cho việc phục vụ','Hóa đơn đã bao gồm 10% phí phục vụ.','Phí phục vụ',2326,NULL,_binary '\0'),(3238,'The department in a hotel responsible for cleaning and maintenance','You can request extra pillows from housekeeping.','NOUN','Bộ phận trong khách sạn chịu trách nhiệm dọn dẹp và bảo trì','Bạn có thể yêu cầu thêm gối từ bộ phận buồng phòng.','Bộ phận buồng phòng',2327,NULL,_binary '\0'),(3239,'The management of household affairs','She is very good at housekeeping.','NOUN','Việc quản lý các công việc trong gia đình','Cô ấy rất giỏi việc dọn dẹp nhà cửa.','Công việc nội trợ / dọn dẹp',2327,NULL,_binary '\0'),(3240,'Clothes and sheets that need to be washed','I have a large pile of laundry to do.','NOUN','Quần áo và ga trải giường cần được làm sạch','Tôi có một đống quần áo lớn cần phải giặt.','Quần áo cần giặt',2328,NULL,_binary '\0'),(3241,'A place where clothes are washed and ironed','Does the hotel have an on-site laundry?','NOUN','Nơi quần áo được giặt và là ủi','Khách sạn có chỗ giặt ủi tại chỗ không?','Tiệm giặt ủi',2328,NULL,_binary '\0'),(3242,'A woman who works as a servant or cleans hotel rooms','The maid will clean your room every morning.','NOUN','Người phụ nữ làm công việc dọn dẹp hoặc phục vụ','Nhân viên dọn phòng sẽ dọn phòng của bạn mỗi sáng.','Nữ nhân viên dọn phòng',2329,NULL,_binary '\0'),(3243,'A tool used to make clothes smooth','I need an iron to press my shirt.','NOUN','Dụng cụ dùng để làm phẳng quần áo','Tôi cần một cái bàn là để ủi áo sơ mi.','Bàn là / Bàn ủi',2330,NULL,_binary '\0'),(3244,'To make clothes flat and smooth','She was ironing her dress for the party.','VERB','Làm cho quần áo phẳng và mịn','Cô ấy đang ủi váy để đi dự tiệc.','Ủi / Là (quần áo)',2330,NULL,_binary '\0'),(3245,'A chemical substance used for washing','Use only a small amount of laundry detergent.','NOUN','Chất hóa học dùng để giặt giũ','Chỉ sử dụng một lượng nhỏ bột giặt.','Bột giặt / Chất tẩy rửa',2331,NULL,_binary '\0'),(3246,'A sign hung on a door to ask people not to enter','Hang the \"Do not disturb\" sign on the handle.','PHRASE','Biển báo treo trên cửa yêu cầu mọi người không vào','Hãy treo biển \"Vui lòng đừng làm phiền\" lên tay nắm cửa.','Vui lòng đừng làm phiền',2332,NULL,_binary '\0'),(3247,'A strong chemical used for cleaning and making things white','She used bleach to get the stains out of the white sheets.','NOUN','Hóa chất mạnh dùng để làm sạch và làm trắng','Cô ấy dùng thuốc tẩy để loại bỏ vết bẩn trên ga trải giường trắng.','Thuốc tẩy',2333,NULL,_binary '\0'),(3248,'To make something whiter or lighter using chemicals','The sun has bleached the curtains.','VERB','Làm cho thứ gì đó trắng hơn hoặc nhạt màu hơn bằng hóa chất','Ánh nắng mặt trời đã làm bạc màu những tấm rèm.','Tẩy trắng / Làm bạc màu',2333,NULL,_binary '\0'),(3249,'A machine used for cleaning floors by sucking up dust','I need a new vacuum for the carpets.','NOUN','Máy dùng để làm sạch sàn nhà bằng cách hút bụi','Tôi cần một chiếc máy hút bụi mới cho những tấm thảm.','Máy hút bụi',2334,NULL,_binary '\0'),(3250,'To clean something with a vacuum cleaner','The housekeeping staff will vacuum the hallway now.','VERB','Làm sạch thứ gì đó bằng máy hút bụi','Nhân viên buồng phòng sẽ hút bụi hành lang ngay bây giờ.','Hút bụi (sàn nhà/thảm)',2334,NULL,_binary '\0'),(3251,'A dirty mark on something that is difficult to remove','There is a coffee stain on the tablecloth.','NOUN','Dấu vết bẩn trên thứ gì đó khó tẩy rửa','Có một vết ố cà phê trên khăn trải bàn.','Vết bẩn / Vết ố',2335,NULL,_binary '\0'),(3252,'To leave a mark on something','Tomato sauce stains very easily.','VERB','Để lại dấu vết trên thứ gì đó','Sốt cà chua rất dễ làm ố quần áo.','Làm bẩn / Làm ố',2335,NULL,_binary '\0'),(3253,'The process of cleaning clothes without using water','This suit needs to be sent to dry cleaning.','NOUN','Quá trình giặt quần áo mà không sử dụng nước','Bộ vest này cần được gửi đi giặt khô.','Giặt khô',2336,NULL,_binary '\0'),(3254,'A white substance found in foods like potatoes and rice','Corn starch is used as a thickener.','NOUN','Chất trắng tìm thấy trong thực phẩm như khoai tây và gạo','Tinh bột ngô được dùng làm chất làm đặc.','Tinh bột',2337,NULL,_binary '\0'),(3255,'A substance used to make cloth stiff','He likes plenty of starch in his shirt collars.','NOUN','Chất dùng để làm cho vải cứng cáp','Anh ấy thích cổ áo sơ mi của mình được hồ cứng.','Hồ vải / Nước hồ',2337,NULL,_binary '\0'),(3256,'A liquid used when washing clothes to make them feel soft','The towels are so soft because of the fabric softener.','NOUN','Chất lỏng dùng khi giặt đồ để làm vải mềm mại','Khăn tắm rất mềm nhờ có nước xả vải.','Nước xả vải',2338,NULL,_binary '\0'),(3257,'To bend something over so that one part covers another','The maid will wash and fold your clothes.','VERB','Uốn cong thứ gì đó để phần này đè lên phần kia','Nhân viên dọn phòng sẽ giặt và gấp quần áo cho bạn.','Gấp / Gập',2339,NULL,_binary '\0'),(3258,'A part of something that has been folded','The paper had a sharp fold in the middle.','NOUN','Một phần của thứ gì đó đã được gấp lại','Tờ giấy có một nếp gấp sắc cạnh ở chính giữa.','Nếp gấp',2339,NULL,_binary '\0'),(3259,'To become smaller','My wool sweater shrank in the wash.','VERB','Trở nên nhỏ hơn (thường do giặt nước nóng)','Chiếc áo len của tôi đã bị co lại khi giặt.','Co lại / Rút lại',2340,NULL,_binary '\0'),(3260,'To fix something that is broken or damaged','Maintenance is coming to repair the leaking tap.','VERB','Khắc phục thứ gì đó bị hỏng hoặc hư hại','Nhân viên bảo trì đang đến để sửa vòi nước bị rò rỉ.','Sửa chữa',2341,NULL,_binary '\0'),(3261,'The act of fixing something','The building is in need of major repairs.','NOUN','Hành động sửa chữa một vật gì đó','Tòa nhà đang cần được sửa chữa lớn.','Sự sửa chữa / Việc tu sửa',2341,NULL,_binary '\0'),(3262,'The act of leaving a hotel after paying the bill','The standard check-out time is 11 AM.','NOUN','Hành động rời khỏi khách sạn sau khi thanh toán hóa đơn','Giờ trả phòng tiêu chuẩn là 11 giờ sáng.','Sự trả phòng',2342,NULL,_binary '\0'),(3263,'The place where you pay in a supermarket','There were long queues at the check-outs.','NOUN','Nơi bạn thanh toán tiền trong siêu thị','Có những hàng dài đợi tại quầy thu ngân.','Quầy thu ngân',2342,NULL,_binary '\0'),(3266,'A formal list of goods or services provided with the sum due','The company requested a formal invoice for the business stay.','NOUN','Danh sách chính thức hàng hóa/dịch vụ đã cung cấp kèm tổng số tiền nợ','Công ty yêu cầu một hóa đơn chính thức cho kỳ lưu trú công tác.','Hóa đơn giá trị gia tăng / Chứng từ',2344,NULL,_binary '\0'),(3267,'The payment of an amount of money owed','We require full settlement of the account upon check-out.','NOUN','Việc thanh toán một khoản tiền nợ','Chúng tôi yêu cầu thanh toán toàn bộ tài khoản khi trả phòng.','Sự thanh quyết toán',2345,NULL,_binary '\0'),(3268,'An official agreement that finishes an argument','The parties reached a financial settlement out of court.','NOUN','Một thỏa thuận chính thức nhằm kết thúc một tranh chấp','Các bên đã đạt được một thỏa thuận tài chính ngoài tòa án.','Sự thỏa thuận / Hòa giải',2345,NULL,_binary '\0'),(3270,'A piece of paper that proves you have paid for something','Keep your receipt in case you want to claim expenses.','NOUN','Tờ giấy chứng minh bạn đã thanh toán cho thứ gì đó','Hãy giữ biên lai trong trường hợp bạn muốn thanh toán lại chi phí.','Biên lai / Phiếu thu',2347,NULL,_binary '\0'),(3271,'The act of receiving something','We are in receipt of your letter.','NOUN','Hành động nhận được một thứ gì đó','Chúng tôi đã nhận được thư của bạn.','Sự nhận được',2347,NULL,_binary '\0'),(3272,'An additional fee for exceeding a deadline','A late charge was applied because we checked out after 2 PM.','NOUN','Khoản phí bổ sung do quá thời hạn quy định','Một khoản phí trả phòng muộn đã được áp dụng vì chúng tôi trả phòng sau 2 giờ chiều.','Phí trễ hạn / Phí trả muộn',2348,NULL,_binary '\0'),(3273,'The way a guest chooses to pay (cash, credit card, etc.)','What is your preferred method of payment?','NOUN','Cách thức mà khách lựa chọn để trả tiền','Phương thức thanh toán ưu tiên của bạn là gì?','Phương thức thanh toán',2349,NULL,_binary '\0'),(3274,'To charge someone too much money for something','I think the hotel overcharged us for the mini-bar items.','VERB','Thu của ai đó quá nhiều tiền cho một thứ gì đó','Tôi nghĩ khách sạn đã tính phí quá cao cho các đồ trong tủ lạnh nhỏ.','Tính phí quá cao / Tính nhầm giá',2350,NULL,_binary '\0'),(3275,'To leave a room or building so that it is available for others','Guests are requested to vacate their rooms by noon.','VERB','Rời khỏi phòng hoặc tòa nhà để người khác có thể sử dụng','Khách được yêu cầu trả phòng trước buổi trưa.','Bỏ trống / Rời khỏi',2351,NULL,_binary '\0'),(3276,'To leave a job or position','He vacated the post after five years.','VERB','Rời bỏ một công việc hoặc vị trí chức vụ','Ông ấy đã rời bỏ vị trí sau 5 năm.','Từ bỏ / Bỏ trống (vị trí)',2351,NULL,_binary '\0'),(3277,'The amount of money remaining in an account','Would you like to pay the remaining balance by card?','NOUN','Số tiền còn lại trong tài khoản hoặc còn nợ','Bạn có muốn thanh toán số dư còn lại bằng thẻ không?','Số dư / Số tiền nợ lại',2352,NULL,_binary '\0'),(3278,'A state where things are of equal weight or force','He lost his balance and fell off the bike.','NOUN','Trạng thái mà các vật có trọng lượng hoặc lực bằng nhau','Anh ấy mất thăng bằng và ngã khỏi xe đạp.','Sự cân bằng',2352,NULL,_binary '\0'),(3279,'Your name written in your own characteristic way','We need your signature on the final bill.','NOUN','Tên của bạn được viết theo cách đặc trưng riêng','Chúng tôi cần chữ ký của bạn trên hóa đơn cuối cùng.','Chữ ký',2353,NULL,_binary '\0'),(3280,'A representative feature of a person or thing','The chef prepared his signature dish for us.','ADJECTIVE','Một đặc điểm tiêu biểu của một người hoặc vật','Đầu bếp đã chuẩn bị món ăn đặc trưng của ông ấy cho chúng tôi.','Mang tính đặc trưng',2353,NULL,_binary '\0'),(3282,'To divide something into two or more parts','Can we split the bill between the two rooms?','VERB','Chia thứ gì đó thành hai hoặc nhiều phần','Chúng tôi có thể tách hóa đơn giữa hai phòng được không?','Chia / Tách (hóa đơn)',2355,NULL,_binary '\0'),(3283,'To tear or crack','He split his trousers when he bent down.','VERB','Làm rách hoặc làm nứt thứ gì đó','Anh ấy bị rách quần khi cúi xuống.','Làm rách / Làm nứt',2355,NULL,_binary '\0'),(3284,'A fast procedure for leaving the hotel without waiting at the desk','Use the express check-out box to drop off your key cards.','NOUN','Thủ tục rời khách sạn nhanh chóng mà không cần chờ đợi tại quầy','Sử dụng hộp trả phòng nhanh để gửi lại thẻ chìa khóa của bạn.','Thủ tục trả phòng nhanh',2356,NULL,_binary '\0'),(3287,'One of the separate parts of a train where people sit','The front carriage of the train was almost empty.','NOUN','Một trong những phần riêng biệt của đoàn tàu nơi hành khách ngồi','Toa tàu phía trước gần như trống rỗng.','Toa hành khách',2358,NULL,_binary '\0'),(3288,'A vehicle with four wheels that is pulled by horses','The royal couple rode in a horse-drawn carriage.','NOUN','Xe bốn bánh được kéo bởi ngựa','Cặp đôi hoàng gia đã đi trên một chiếc xe ngựa kéo.','Xe ngựa',2358,NULL,_binary '\0'),(3289,'A railway track or a system of tracks','The Jubilee Line is closed for maintenance this weekend.','NOUN','Một đường ray xe lửa hoặc hệ thống các đường ray','Tuyến Jubilee bị đóng cửa để bảo trì vào cuối tuần này.','Tuyến / Đường ray',2359,NULL,_binary '\0'),(3290,'A long, thin mark or a row of people','Please wait behind the yellow line.','NOUN','Một vệt dài, mỏng hoặc một hàng người/vật','Vui lòng đợi phía sau vạch kẻ màu vàng.','Hàng / Dòng / Đường kẻ',2359,NULL,_binary '\0'),(3293,'The pair of long metal bars that a train runs on','Workers are repairing a section of the track.','NOUN','Cặp thanh kim loại dài mà tàu chạy trên đó','Các công nhân đang sửa chữa một đoạn đường ray.','Đường ray',2361,NULL,_binary '\0'),(3294,'To follow the progress or movement of someone or something','You can track your train in real-time using the app.','VERB','Theo dõi tiến trình hoặc sự di chuyển của ai đó/thứ gì đó','Bạn có thể theo dõi đoàn tàu theo thời gian thực bằng ứng dụng.','Theo dõi',2361,NULL,_binary '\0'),(3295,'The last stop on a train or bus line','This train terminates here; everyone must leave at the terminal.','NOUN','Điểm dừng cuối cùng của một tuyến tàu hoặc xe buýt','Tàu này kết thúc tại đây; mọi người phải xuống ở ga cuối.','Ga cuối / Bến cuối',2362,NULL,_binary '\0'),(3296,'Leading gradually to death','The patient was diagnosed with terminal cancer.','ADJECTIVE','Dẫn đến cái chết một cách dần dần','Bệnh nhân được chẩn đoán mắc ung thư giai đoạn cuối.','Vô phương cứu chữa / Giai đoạn cuối',2362,NULL,_binary '\0'),(3297,'The price you pay to travel on a bus, train, etc.','The train fare has increased by 10% this year.','NOUN','Số tiền bạn trả để đi xe buýt, tàu hỏa, v.v.','Giá vé tàu hỏa đã tăng 10% trong năm nay.','Giá vé',2363,NULL,_binary '\0'),(3298,'Food of a particular type','The restaurant offers traditional rustic fare.','NOUN','Thức ăn của một loại cụ thể','Nhà hàng cung cấp những món ăn dân dã truyền thống.','Thức ăn / Thực đơn',2363,NULL,_binary '\0'),(3299,'Someone who checks tickets on a bus or train','The conductor asked to see our tickets.','NOUN','Người kiểm tra vé trên xe buýt hoặc tàu hỏa','Người soát vé yêu cầu xem vé của chúng tôi.','Người soát vé',2364,NULL,_binary '\0'),(3300,'Someone who directs the performance of an orchestra','The conductor raised his baton to start the symphony.','NOUN','Người điều khiển buổi biểu diễn của dàn nhạc','Nhạc trưởng giơ gậy chỉ huy để bắt đầu bản giao hưởng.','Nhạc trưởng',2364,NULL,_binary '\0'),(3301,'A station where you can change from one line to another','Kings Cross is a major interchange for the Tube.','NOUN','Một nhà ga nơi bạn có thể đổi từ tuyến này sang tuyến khác','Kings Cross là một ga trung chuyển lớn của hệ thống tàu điện ngầm.','Ga trung chuyển / Điểm kết nối',2365,NULL,_binary '\0'),(3302,'An exchange of ideas, information, etc.','There is a continuous interchange of ideas between the two teams.','NOUN','Sự trao đổi ý tưởng, thông tin, v.v.','Có một sự trao đổi ý tưởng liên tục giữa hai đội.','Sự trao đổi',2365,NULL,_binary '\0'),(3305,'A period of time when you have to wait because of a problem','We apologize for the delay to your journey.','NOUN','Một khoảng thời gian bạn phải chờ đợi do có sự cố','Chúng tôi xin lỗi vì sự chậm trễ cho hành trình của bạn.','Sự chậm trễ / Trì hoãn',2367,NULL,_binary '\0'),(3306,'To make something happen later than planned','Heavy snow delayed all trains this morning.','VERB','Làm cho việc gì đó xảy ra muộn hơn so với kế hoạch','Tuyết rơi dày đã làm chậm tất cả các đoàn tàu sáng nay.','Trì hoãn / Làm chậm lại',2367,NULL,_binary '\0'),(3307,'Legal or acceptable','Is this ticket still valid for the return journey?','ADJECTIVE','Hợp pháp hoặc có thể chấp nhận được','Vé này còn hiệu lực cho hành trình lượt về không?','Có hiệu lực / Hợp lệ',2368,NULL,_binary '\0'),(3308,'Based on truth or a good reason','You raise a valid point in the discussion.','ADJECTIVE','Dựa trên sự thật hoặc một lý do chính đáng','Bạn đưa ra một luận điểm xác đáng trong cuộc thảo luận.','Xác đáng / Có căn cứ',2368,NULL,_binary '\0'),(3309,'A railway system in which electric trains travel through tunnels','I usually go to work on the underground.','NOUN','Hệ thống đường sắt mà tàu điện chạy qua các đường hầm','Tôi thường đi làm bằng tàu điện ngầm.','Tàu điện ngầm',2369,NULL,_binary '\0'),(3310,'Below the surface of the earth','Rats often live in underground tunnels.','ADJECTIVE','Ở phía dưới bề mặt trái đất','Chuột thường sống trong các đường hầm dưới lòng đất.','Dưới lòng đất',2369,NULL,_binary '\0'),(3311,'The place where you show your ticket to enter a platform','Put your ticket in the slot at the automatic gate.','NOUN','Nơi bạn xuất trình vé để vào sân ga','Hãy đưa vé vào khe ở cổng soát vé tự động.','Cổng soát vé',2370,NULL,_binary '\0'),(3312,'A part of a fence that opens like a door','Please close the garden gate behind you.','NOUN','Một phần của hàng rào mở ra như cửa','Vui lòng đóng cổng vườn sau lưng bạn.','Cổng (hàng rào)',2370,NULL,_binary '\0'),(3313,'A ticket that can be used for any number of journeys within a period','An annual season ticket is much cheaper for commuters.','NOUN','Vé có thể sử dụng cho số lần di chuyển bất kỳ trong một khoảng thời gian','Vé tháng năm rẻ hơn nhiều đối với những người đi làm xa hằng ngày.','Vé tháng / Vé định kỳ',2371,NULL,_binary '\0'),(3314,'A comfortable bus used for long journeys','We took a coach from Hanoi to Da Nang.','NOUN','Loại xe buýt thoải mái dùng cho các chuyến đi dài','Chúng tôi đã đi xe khách từ Hà Nội vào Đà Nẵng.','Xe khách / Xe liên tỉnh',2372,NULL,_binary '\0'),(3315,'Someone whose job is to train a person or a team','The basketball coach called a timeout.','NOUN','Người có công việc là đào tạo một cá nhân hoặc một đội','Huấn luyện viên bóng rổ đã gọi tạm dừng hội ý.','Huấn luyện viên',2372,NULL,_binary '\0'),(3318,'A bus with two floors','Double-decker buses are a symbol of London.','NOUN','Xe buýt có hai tầng để chở khách','Xe buýt hai tầng là một biểu tượng của London.','Xe buýt hai tầng',2374,NULL,_binary '\0'),(3319,'A place where buses or trains are kept and repaired','The buses return to the depot at midnight.','NOUN','Nơi cất giữ và sửa chữa xe buýt hoặc tàu hỏa','Các xe buýt quay trở về bãi đỗ vào nửa đêm.','Bãi đỗ xe / Trạm bảo dưỡng',2375,NULL,_binary '\0'),(3320,'A building where large amounts of goods are stored','The company built a new distribution depot.','NOUN','Tòa nhà nơi lưu trữ lượng lớn hàng hóa','Công ty đã xây dựng một kho phân phối mới.','Kho chứa hàng / Tổng kho',2375,NULL,_binary '\0'),(3321,'A particular way from one place to another','The bus driver had to change his route due to the accident.','NOUN','Một con đường cụ thể đi từ nơi này đến nơi khác','Tài xế xe buýt phải thay đổi lộ trình do tai nạn.','Tuyến đường / Lộ trình',2376,NULL,_binary '\0'),(3322,'To send something along a particular way','All calls are routed through the central switchboard.','VERB','Gửi thứ gì đó đi theo một lộ trình cụ thể','Tất cả các cuộc gọi đều được định tuyến qua tổng đài trung tâm.','Định tuyến / Gửi đi',2376,NULL,_binary '\0'),(3323,'Going straight from one place to another without stopping','Is there a direct coach to the airport?','ADJECTIVE','Đi thẳng từ nơi này đến nơi khác mà không dừng lại nửa chừng','Có chuyến xe khách trực tiếp nào đến sân bay không?','Trực tiếp / Không dừng',2377,NULL,_binary '\0'),(3324,'To tell someone the way to a place','Can you direct me to the bus station?','VERB','Chỉ cho ai đó đường đi đến một nơi','Bạn có thể chỉ đường cho tôi đến bến xe buýt không?','Chỉ đường / Hướng dẫn',2377,NULL,_binary '\0'),(3325,'To get on a bus, train, etc. in order to travel','I need to catch the 8:30 coach.','VERB','Lên xe buýt, tàu hỏa, v.v. để di chuyển','Tôi cần bắt chuyến xe khách lúc 8:30.','Bắt (xe/tàu)',2378,NULL,_binary '\0'),(3326,'To take hold of something that is moving','He caught the ball with one hand.','VERB','Nắm lấy thứ gì đó đang chuyển động','Anh ấy đã bắt được quả bóng bằng một tay.','Bắt được / Chụp được',2378,NULL,_binary '\0'),(3327,'A place where vehicles stop or wait','The coach for Dalat is at stand number 5.','NOUN','Nơi xe cộ dừng lại hoặc chờ đợi trong bến','Xe khách đi Đà Lạt đang ở vị trí đỗ số 5.','Vị trí đỗ / Cột đỗ',2379,NULL,_binary '\0'),(3328,'To be in a vertical position on your feet','I had to stand on the bus because it was so crowded.','VERB','Ở tư thế thẳng đứng trên đôi chân','Tôi đã phải đứng trên xe buýt vì nó quá đông.','Đứng',2379,NULL,_binary '\0'),(3329,'A bed in a boat, train, or coach','I booked a lower berth for the overnight journey.','NOUN','Giường trên tàu thủy, tàu hỏa hoặc xe khách','Tôi đã đặt một giường nằm tầng dưới cho hành trình qua đêm.','Giường nằm',2380,NULL,_binary '\0'),(3330,'A place where a ship lies at anchor','The ship slipped into its berth at dawn.','NOUN','Nơi tàu thủy đậu khi neo giữ','Con tàu đã tiến vào bến đỗ lúc bình minh.','Bến đỗ (cho tàu thủy)',2380,NULL,_binary '\0'),(3331,'The amount of space available for your legs when sitting','This coach has extra leg room for tall passengers.','NOUN','Khoảng trống dành cho chân khi ngồi','Chiếc xe khách này có thêm chỗ để chân cho hành khách cao.','Chỗ để chân',2381,NULL,_binary '\0'),(3332,'A place where a bus only stops if a passenger signals','You need to press the bell for a request stop.','NOUN','Nơi xe buýt chỉ dừng nếu hành khách ra hiệu','Bạn cần bấm chuông cho điểm dừng theo yêu cầu.','Điểm dừng theo yêu cầu',2382,NULL,_binary '\0'),(3333,'A bus equipped with beds for passengers to sleep on','Sleeper buses are very popular for long-distance travel in Vietnam.','NOUN','Xe buýt được trang bị giường để hành khách ngủ','Xe giường nằm rất phổ biến cho du lịch đường dài ở Việt Nam.','Xe giường nằm',2383,NULL,_binary '\0'),(3334,'To call someone or signal for a vehicle to stop','It was raining, so we tried to hail a taxi.','VERB','Gọi ai đó hoặc ra hiệu cho xe dừng lại','Trời đang mưa, nên chúng tôi đã cố vẫy một chiếc taxi.','Vẫy / Gọi (xe buýt/taxi)',2384,NULL,_binary '\0'),(3335,'Small, hard balls of ice that fall from the sky like rain','The car was damaged by the hail.','NOUN','Những viên đá nhỏ, cứng rơi từ trên trời xuống như mưa','Chiếc xe bị hư hại do mưa đá.','Mưa đá',2384,NULL,_binary '\0'),(3338,'A person who travels some distance to work on a regular basis','The morning bus is always full of commuters.','NOUN','Người thường xuyên di chuyển một quãng đường nhất định để đi làm','Chuyến xe buýt buổi sáng luôn đầy những người đi làm.','Người đi làm xa hằng ngày',2386,NULL,_binary '\0'),(3343,'A sudden and great increase','Expect surge pricing during rush hour.','NOUN','Sự tăng lên đột ngột và mạnh mẽ (thường là về giá cước)','Hãy chuẩn bị cho việc giá tăng cao vào giờ cao điểm.','Sự tăng giá nhanh / Giá cao điểm',2389,NULL,_binary '\0'),(3344,'A sudden strong feeling','She felt a surge of relief when the car arrived.','NOUN','Một cảm giác mạnh mẽ ập đến bất ngờ','Cô cảm thấy một sự nhẹ nhõm dâng trào khi chiếc xe đến.','Sự dâng trào (cảm xúc)',2389,NULL,_binary '\0'),(3345,'A device in a taxi that measures the distance and shows the fare','Please make sure the driver turns on the meter.','NOUN','Thiết bị trong taxi đo quãng đường và hiển thị tiền cước','Hãy đảm bảo rằng tài xế đã bật đồng hồ tính tiền.','Đồng hồ tính tiền',2390,NULL,_binary '\0'),(3346,'A unit of length','The car was parked only a few meters away.','NOUN','Đơn vị đo chiều dài','Chiếc xe chỉ đậu cách đó vài mét.','Mét',2390,NULL,_binary '\0'),(3347,'An arrangement to have something kept for you','I made a booking for a large taxi to fit all our bags.','NOUN','Việc sắp xếp để có một thứ gì đó được giữ cho bạn','Tôi đã đặt một chiếc taxi lớn để chở vừa tất cả túi xách.','Sự đặt xe / Đặt chỗ',2391,NULL,_binary '\0'),(3350,'The act of picking someone up or the place where this happens','The app shows the exact pickup point.','NOUN','Hành động đón ai đó hoặc địa điểm nơi việc này diễn ra','Ứng dụng hiển thị chính xác điểm đón.','Điểm đón / Sự đón khách',2393,NULL,_binary '\0'),(3351,'A type of small truck','He drives a white pickup truck.','NOUN','Một loại xe tải nhỏ có thùng hở phía sau','Anh ấy lái một chiếc xe bán tải màu trắng.','Xe bán tải',2393,NULL,_binary '\0'),(3353,'A measurement of how good someone or something is','This driver has a 5-star rating.','NOUN','Phép đo mức độ tốt của ai đó hoặc thứ gì đó','Tài xế này có đánh giá 5 sao.','Đánh giá / Xếp hạng (sao)',2395,NULL,_binary '\0'),(3354,'To guess the cost, size, or value of something','The app estimates the travel time to be 20 minutes.','VERB','Đoán chi phí, kích thước hoặc giá trị của thứ gì đó','Ứng dụng ước tính thời gian di chuyển là 20 phút.','Ước tính / Ước lượng',2396,NULL,_binary '\0'),(3355,'A statement of how much a piece of work will cost','Can you give me an estimate for the car repair?','NOUN','Một văn bản nêu rõ chi phí cho một công việc','Bạn có thể cho tôi một bản báo giá sửa xe không?','Bản ước tính / Báo giá sơ bộ',2396,NULL,_binary '\0'),(3356,'A journey in a vehicle','Thanks for the ride!','NOUN','Một hành trình di chuyển trên phương tiện','Cảm ơn vì chuyến xe nhé!','Chuyến xe / Cuộc hành trình',2397,NULL,_binary '\0'),(3357,'To sit on and control a bicycle, motorcycle, or horse','He rides his motorbike to work.','VERB','Ngồi trên và điều khiển xe đạp, xe máy hoặc ngựa','Anh ấy lái xe máy đi làm.','Cưỡi / Lái (xe máy, xe đạp)',2397,NULL,_binary '\0'),(3358,'The interior of a vehicle or aircraft','The car has a very spacious cabin.','NOUN','Nội thất bên trong một phương tiện hoặc máy bay','Chiếc xe có khoang hành khách rất rộng rãi.','Khoang hành khách / Cabin',2398,NULL,_binary '\0'),(3359,'A small house made of wood','We stayed in a log cabin in the mountains.','NOUN','Một ngôi nhà nhỏ làm bằng gỗ','Chúng tôi đã ở trong một ngôi nhà gỗ trên núi.','Nhà gỗ nhỏ / Túp lều',2398,NULL,_binary '\0'),(3360,'To share a vehicle with other passengers','I decided to pool the ride to save money.','VERB','Chia sẻ phương tiện với những hành khách khác','Tôi quyết định đi chung xe để tiết kiệm tiền.','Đi chung xe / Gộp chuyến',2399,NULL,_binary '\0'),(3361,'A swimming pool','The hotel has an indoor pool.','NOUN','Một khu vực chứa nước để bơi','Khách sạn có hồ bơi trong nhà.','Hồ bơi',2399,NULL,_binary '\0'),(3362,'To send a vehicle to a place','The taxi company will dispatch a car immediately.','VERB','Gửi một phương tiện đến một địa điểm nhất định','Công ty taxi sẽ điều một chiếc xe đến ngay lập tức.','Điều động / Gửi xe đi',2400,NULL,_binary '\0'),(3363,'An official report or message','The latest dispatch from the front line was encouraging.','NOUN','Một báo cáo hoặc thông báo chính thức','Bản tin mới nhất từ tiền tuyến rất đáng khích lệ.','Bản tin / Công văn',2400,NULL,_binary '\0'),(3365,'An arrangement to rent something, or the amount of money paid','The car rental includes unlimited mileage.','NOUN','Sự sắp xếp để thuê thứ gì đó hoặc số tiền trả để thuê','Việc thuê xe bao gồm cả số dặm đi không giới hạn.','Sự thuê mướn / Tiền thuê',2402,NULL,_binary '\0'),(3366,'Relating to the act of renting','We need to find a rental agency near the airport.','ADJECTIVE','Liên quan đến việc thuê mướn','Chúng ta cần tìm một đại lý cho thuê xe gần sân bay.','Cho thuê',2402,NULL,_binary '\0'),(3367,'To drive a vehicle backwards','He reversed the car into the garage.','VERB','Điều khiển phương tiện đi lùi lại phía sau','Anh ấy đã lùi xe vào trong ga-ra.','Lùi xe',2403,NULL,_binary '\0'),(3368,'The opposite of something or the back of a coin','The results were the reverse of what we expected.','NOUN','Điều trái ngược với cái gì đó hoặc mặt sau của đồng xu','Kết quả hoàn toàn trái ngược với những gì chúng tôi mong đợi.','Điều ngược lại / Mặt sau',2403,NULL,_binary '\0'),(3369,'A device that controls the speed and power of an engine','Don\'t forget to change gear when you speed up.','NOUN','Thiết bị điều khiển tốc độ và sức mạnh của động cơ','Đừng quên sang số khi bạn tăng tốc.','Số (xe) / Bánh răng',2404,NULL,_binary '\0'),(3370,'Equipment used for a particular activity','We need to pack our camping gear.','NOUN','Thiết bị được sử dụng cho một hoạt động cụ thể','Chúng ta cần đóng gói đồ dùng cắm trại của mình.','Đồ dùng / Trang thiết bị',2404,NULL,_binary '\0'),(3372,'A device used for slowing down or stopping a vehicle','She slammed on the brakes to avoid the dog.','NOUN','Thiết bị dùng để làm chậm hoặc dừng phương tiện','Cô ấy đạp mạnh phanh để tránh con chó.','Phanh / Thắng',2406,NULL,_binary '\0'),(3373,'To slow down or stop a vehicle by using a brake','The driver braked hard at the red light.','VERB','Làm chậm hoặc dừng phương tiện bằng cách dùng phanh','Tài xế đã phanh gấp tại đèn đỏ.','Phanh lại / Đạp thắng',2406,NULL,_binary '\0'),(3374,'An official document that gives you permission to do something','You must show your driver\'s license to rent a car.','NOUN','Văn bản chính thức cho phép bạn làm điều gì đó','Bạn phải xuất trình bằng lái xe để thuê xe.','Giấy phép / Bằng lái',2407,NULL,_binary '\0'),(3375,'To give someone official permission to do something','The restaurant is licensed to serve alcohol.','VERB','Cho phép ai đó làm điều gì đó một cách chính thức','Nhà hàng này được cấp phép phục vụ đồ uống có cồn.','Cấp phép',2407,NULL,_binary '\0'),(3376,'The total distance a vehicle has traveled','This used car has very low mileage.','NOUN','Tổng quãng đường mà một phương tiện đã di chuyển','Chiếc xe cũ này có số dặm đã đi rất thấp.','Số dặm / Quãng đường đã đi',2408,NULL,_binary '\0'),(3377,'The distance a vehicle can travel using a particular amount of fuel','The car gets great gas mileage.','NOUN','Quãng đường xe có thể đi được với một lượng nhiên liệu nhất định','Chiếc xe này có mức tiêu thụ xăng rất tốt.','Mức tiêu hao nhiên liệu',2408,NULL,_binary '\0'),(3378,'A container for holding liquid or gas','Please return the rental car with a full tank of gas.','NOUN','Thùng chứa chất lỏng hoặc khí','Vui lòng trả xe thuê với bình xăng đầy.','Bình chứa / Bình xăng',2409,NULL,_binary '\0'),(3379,'A heavy military vehicle with large guns','The army moved the tanks to the border.','NOUN','Phương tiện quân sự hạng nặng có súng lớn','Quân đội đã di chuyển các xe tăng ra biên giới.','Xe tăng',2409,NULL,_binary '\0'),(3380,'To look at something carefully to check its condition','You should inspect the car for scratches before driving away.','VERB','Xem xét thứ gì đó cẩn thận để kiểm tra tình trạng của nó','Bạn nên kiểm tra xe xem có vết xước không trước khi lái đi.','Kiểm tra / Thanh tra',2410,NULL,_binary '\0'),(3381,'Harm or injury that causes loss of value','The client is responsible for any damage to the vehicle.','NOUN','Sự tổn hại gây ra mất giá trị','Khách hàng chịu trách nhiệm cho bất kỳ hư hại nào đối với phương tiện.','Sự hư hại / Thiệt hại',2411,NULL,_binary '\0'),(3382,'To harm or spoil something','The storm damaged several cars in the lot.','VERB','Làm hại hoặc làm hỏng thứ gì đó','Cơn bão đã làm hỏng vài chiếc xe trong bãi đỗ.','Làm hỏng / Gây thiệt hại',2411,NULL,_binary '\0'),(3383,'To go past another vehicle that is moving more slowly','It\'s dangerous to overtake on a narrow bridge.','VERB','Đi qua một phương tiện khác đang di chuyển chậm hơn','Vượt xe trên một cây cầu hẹp là rất nguy hiểm.','Vượt mặt / Vượt xe',2412,NULL,_binary '\0'),(3384,'To start to go faster','The car can accelerate from 0 to 100 km/h in 6 seconds.','VERB','Bắt đầu đi nhanh hơn','Chiếc xe có thể tăng tốc từ 0 lên 100 km/h trong 6 giây.','Tăng tốc',2413,NULL,_binary '\0'),(3385,'A light or sound that gives information or a warning','Always use your turn signal before changing lanes.','NOUN','Ánh sáng hoặc âm thanh đưa ra thông tin hoặc cảnh báo','Luôn sử dụng đèn xi-nhan trước khi chuyển làn.','Tín hiệu / Đèn báo',2414,NULL,_binary '\0'),(3386,'To make a movement or sound to give information','The driver signaled that it was safe to pass.','VERB','Thực hiện một cử động hoặc âm thanh để đưa ra thông tin','Tài xế đã ra hiệu rằng vượt xe là an toàn.','Ra hiệu / Phát tín hiệu',2414,NULL,_binary '\0'),(3387,'A part of a wide road marked by painted white lines','Stay in the left lane if you want to turn left.','NOUN','Một phần của con đường rộng được đánh dấu bằng các vạch kẻ trắng','Hãy đi ở làn bên trái nếu bạn muốn rẽ trái.','Làn đường',2415,NULL,_binary '\0'),(3388,'A narrow road in the countryside or city','The hotel is located down a quiet country lane.','NOUN','Con đường hẹp ở nông thôn hoặc thành phố','Khách sạn nằm ở cuối một con đường quê yên tĩnh.','Đường nhỏ / Con hẻm',2415,NULL,_binary '\0'),(3389,'An amount of money that has to be paid as a punishment','If you park illegally, you will have to pay a fine.','NOUN','Một khoản tiền phải trả như một hình phạt','Nếu bạn đậu xe trái phép, bạn sẽ phải nộp tiền phạt.','Tiền phạt',2416,NULL,_binary '\0'),(3390,'Good or well','Everything is fine with the car rental contract.','ADJECTIVE','Tốt hoặc khỏe mạnh','Mọi thứ đều ổn với hợp đồng thuê xe.','Tốt / Khỏe / Ổn',2416,NULL,_binary '\0'),(3391,'A place where two or more roads or railway lines meet','Turn right at the next junction.','NOUN','Nơi hai hoặc nhiều con đường hoặc đường ray gặp nhau','Rẽ phải tại giao lộ tiếp theo.','Giao lộ / Điểm giao nhau',2417,NULL,_binary '\0'),(3392,'The act of joining or the state of being joined','The junction of the two rivers is a popular tourist spot.','NOUN','Hành động kết nối hoặc trạng thái được kết nối','Nơi hợp lưu của hai dòng sông là một điểm du lịch nổi tiếng.','Sự kết nối / Mối nối',2417,NULL,_binary '\0'),(3393,'A place where three or more roads join and traffic must go around a central island','Take the second exit at the roundabout.','NOUN','Nơi ba hoặc nhiều con đường gặp nhau và xe cộ phải đi quanh một đảo trung tâm','Đi theo lối ra thứ hai tại vòng xoay.','Vòng xoay / Bùng binh',2418,NULL,_binary '\0'),(3394,'Not done or said using the shortest, simplest, or most direct way','He told the story in a very roundabout way.','ADJECTIVE','Không được thực hiện hoặc nói theo cách ngắn nhất hoặc trực tiếp nhất','Anh ấy kể câu chuyện theo một cách rất quanh co.','Quanh co / Đường vòng',2418,NULL,_binary '\0'),(3395,'A building or place that is easily recognized','The lighthouse is a famous landmark in this city.','NOUN','Một tòa nhà hoặc địa điểm dễ dàng nhận ra để định hướng','Ngọn hải đăng là một địa danh nổi bật nổi tiếng ở thành phố này.','Mốc lộ trình / Địa danh nổi bật',2419,NULL,_binary '\0'),(3396,'An important stage in the development of something','This court case is a landmark in legal history.','NOUN','Một giai đoạn quan trọng trong sự phát triển của cái gì đó','Vụ kiện này là một bước ngoặt trong lịch sử pháp lý.','Bước ngoặt / Cột mốc quan trọng',2419,NULL,_binary '\0'),(3398,'To discover your position in relation to the things around you','It took me a moment to orient myself after getting off the bus.','VERB','Khám phá vị trí của bạn trong mối tương quan với vạn vật xung quanh','Tôi mất một lúc để định hướng lại bản thân sau khi xuống xe buýt.','Định hướng / Xác định vị trí',2421,NULL,_binary '\0'),(3399,'The countries in the East, especially East Asia','He has traveled extensively throughout the Orient.','NOUN','Các quốc gia ở phía Đông, đặc biệt là Đông Á','Anh ấy đã du lịch khắp phương Đông.','Phương Đông',2421,NULL,_binary '\0'),(3400,'The distance along a street from one intersection to the next','Walk two blocks and turn left.','NOUN','Khoảng cách dọc theo một con đường từ ngã tư này đến ngã tư tiếp theo','Đi qua hai dãy nhà rồi rẽ trái.','Dãy nhà / Khối phố',2422,NULL,_binary '\0'),(3401,'To prevent movement through something','An accident is blocking the main road.','VERB','Ngăn cản sự di chuyển qua thứ gì đó','Một tai nạn đang làm tắc nghẽn con đường chính.','Chặn / Làm tắc nghẽn',2422,NULL,_binary '\0'),(3402,'To move or turn in a particular direction','When you reach the fork in the road, bear right.','VERB','Di chuyển hoặc rẽ theo một hướng cụ thể','Khi bạn đến ngã ba đường, hãy đi chếch về bên phải.','Đi chếch về / Hướng về',2423,NULL,_binary '\0'),(3403,'To accept or tolerate something unpleasant','I can\'t bear the thought of getting lost again.','VERB','Chấp nhận hoặc chịu đựng điều gì đó không thoải mái','Tôi không thể chịu nổi ý nghĩ bị lạc đường một lần nữa.','Chịu đựng / Mang theo',2423,NULL,_binary '\0'),(3404,'Being in a position on the other side','The bank is opposite the post office.','ADJECTIVE','Ở vị trí phía bên kia','Ngân hàng nằm đối diện bưu điện.','Đối diện',2424,NULL,_binary '\0'),(3405,'A person or thing that is totally different','Black is the opposite of white.','NOUN','Một người hoặc vật hoàn toàn khác biệt','Đen là từ trái nghĩa của trắng.','Điều trái ngược / Từ trái nghĩa',2424,NULL,_binary '\0'),(3406,'A place where a road or river divides into two parts','Take the left fork after the bridge.','NOUN','Nơi con đường hoặc dòng sông chia làm hai phần','Đi theo nhánh bên trái sau khi qua cầu.','Ngã ba đường / Nhánh rẽ',2425,NULL,_binary '\0'),(3407,'A small object with three or four points, used for eating food','He ate his salad with a fork.','NOUN','Vật dụng nhỏ có ba hoặc bốn đầu nhọn, dùng để ăn thức ăn','Anh ấy ăn salad bằng nĩa.','Cái nĩa',2425,NULL,_binary '\0'),(3408,'The direction in which a ship, aircraft, or person is moving','The ship changed its heading to avoid the storm.','NOUN','Hướng mà tàu, máy bay hoặc một người đang di chuyển','Con tàu đã thay đổi hướng đi để tránh bão.','Hướng đi / Phương hướng',2426,NULL,_binary '\0'),(3409,'Words written at the top of a text as a title','Read the headings before you start the article.','NOUN','Các từ được viết ở đầu văn bản như một cái tên','Hãy đọc các tiêu đề trước khi bạn bắt đầu bài báo.','Tiêu đề / Đề mục',2426,NULL,_binary '\0'),(3410,'To go from one side of something to the other','Be careful when you cross the street.','VERB','Đi từ phía bên này sang phía bên kia của cái gì đó','Hãy cẩn thận khi bạn băng qua đường.','Băng qua / Vượt qua',2427,NULL,_binary '\0'),(3411,'Annoyed or fairly angry','My mom was cross with me because I got lost.','ADJECTIVE','Bực mình hoặc khá tức giận','Mẹ tôi đã giận tôi vì tôi bị lạc đường.','Giận dữ / Khó chịu',2427,NULL,_binary '\0'),(3412,'A pole with a sign that shows the way to a place','Follow the signpost for the city center.','NOUN','Cột có biển báo chỉ đường đến một địa điểm','Đi theo biển chỉ dẫn về hướng trung tâm thành phố.','Biển chỉ dẫn / Cột mốc đường',2428,NULL,_binary '\0'),(3413,'To show the direction of something or provide clear information','The teacher signposted the main points of the lecture.','VERB','Chỉ ra hướng của cái gì đó hoặc cung cấp thông tin rõ ràng','Giáo viên đã chỉ dẫn các điểm chính của bài giảng.','Chỉ dẫn / Đánh dấu',2428,NULL,_binary '\0'),(3414,'To plan in detail how something will happen','We need to map out the best route to the station.','PHRASAL_VERB','Lập kế hoạch chi tiết về cách một việc gì đó sẽ diễn ra','Chúng ta cần vạch ra lộ trình tốt nhất đến nhà ga.','Lên lộ trình / Vạch ra kế hoạch',2429,NULL,_binary '\0'),(3415,'To make a map of an area','Scientists are mapping out the ocean floor.','PHRASAL_VERB','Tạo ra bản đồ của một khu vực','Các nhà khoa học đang vẽ bản đồ đáy đại dương.','Vẽ bản đồ / Quy hoạch',2429,NULL,_binary '\0'),(3416,'Continuing in one direction without bending','Go straight ahead for about 200 meters.','ADVERB','Tiếp tục theo một hướng mà không rẽ hay uốn lượn','Đi thẳng về phía trước khoảng 200 mét.','Thẳng / Đi thẳng',2430,NULL,_binary '\0'),(3417,'Immediately','Go straight home after the trip.','ADVERB','Ngay tức khắc','Về nhà ngay sau chuyến đi nhé.','Ngay lập tức',2430,NULL,_binary '\0'),(3418,'To not know where you are','I lost my way in the narrow streets.','VERB','Không biết mình đang ở đâu','Tôi đã bị lạc đường trong những con phố hẹp.','Lạc đường / Mất phương hướng',2431,NULL,_binary '\0'),(3419,'To no longer have something because you do not know where it is','Don\'t lose your map!','VERB','Không còn sở hữu thứ gì đó vì không biết nó ở đâu','Đừng để mất bản đồ của bạn!','Đánh mất / Thất lạc',2431,NULL,_binary '\0'),(3424,'A place where ships are loaded and unloaded','The ferry is still at the dock.','NOUN','Nơi tàu thuyền bốc dỡ hàng hóa hoặc hành khách','Chiếc phà vẫn còn đang ở bến.','Bến tàu / Vũng tàu đậu',2434,NULL,_binary '\0'),(3425,'To sail into a harbor or stay at a dock','The ship docked at dawn.','VERB','Đi vào cảng hoặc neo lại tại bến','Con tàu đã cập bến lúc bình minh.','Cập bến',2434,NULL,_binary '\0'),(3426,'A large ship or boat','The harbor is full of fishing vessels.','NOUN','Một con tàu hoặc thuyền lớn (thường dùng trong văn bản chính thức)','Cảng đầy những tàu đánh cá.','Tàu lớn / Thuyền lớn',2435,NULL,_binary '\0'),(3427,'A tube that carries blood through the body or a container','The doctor checked his blood vessels.','NOUN','Ống dẫn máu trong cơ thể hoặc một vật chứa chất lỏng','Bác sĩ đã kiểm tra mạch máu của anh ấy.','Mạch / Bình chứa',2435,NULL,_binary '\0'),(3428,'A holiday on a large ship, visiting several places','They went on a luxury cruise around the Caribbean.','NOUN','Một kỳ nghỉ trên tàu lớn, đi thăm nhiều nơi','Họ đã đi một chuyến du ngoạn sang trọng quanh vùng Caribbean.','Chuyến du ngoạn / Du thuyền',2436,NULL,_binary '\0'),(3429,'To travel at a steady speed','The boat was cruising at 15 knots.','VERB','Di chuyển với một tốc độ ổn định','Con thuyền đang chạy với tốc độ đều 15 hải lý/giờ.','Chạy với tốc độ đều / Đi dạo',2436,NULL,_binary '\0'),(3430,'A town by the sea or a river where ships arrive and leave','The ship is due to arrive in port at midnight.','NOUN','Một thị trấn bên biển hoặc sông nơi tàu bè đến và đi','Con tàu dự kiến sẽ cập cảng vào nửa đêm.','Cảng biển / Thành phố cảng',2437,NULL,_binary '\0'),(3431,'The left side of a ship or a part of a computer','Insert the drive into the USB port.','NOUN','Mạn trái của tàu hoặc một bộ phận của máy tính để kết nối','Cắm ổ đĩa vào cổng USB.','Cổng / Mạn trái',2437,NULL,_binary '\0'),(3432,'The outside top level of a ship that you can walk or stand on','Let\'s go up on deck to see the sunset.','NOUN','Tầng trên cùng ngoài trời của con tàu mà bạn có thể đi bộ hoặc đứng trên đó','Hãy lên boong tàu để ngắm hoàng hôn.','Boong tàu',2438,NULL,_binary '\0'),(3433,'A complete set of playing cards','He shuffled the deck before dealing the cards.','NOUN','Một bộ bài tây đầy đủ','Anh ấy tráo bộ bài trước khi chia.','Bộ bài',2438,NULL,_binary '\0'),(3434,'The back part of a ship or boat','The name of the boat was painted on the stern.','NOUN','Phần phía sau của một con tàu hoặc thuyền','Tên của con thuyền được sơn ở phía đuôi.','Đuôi tàu',2439,NULL,_binary '\0'),(3435,'Severe, or showing disapproval','The captain gave a stern warning to the crew.','ADJECTIVE','Nghiêm khắc, hoặc thể hiện sự không hài lòng','Thuyền trưởng đã đưa ra một lời cảnh báo nghiêm khắc cho thủy thủ đoàn.','Nghiêm nghị / Khắt khe',2439,NULL,_binary '\0'),(3438,'A long structure built from the land out over water','The ferry leaves from the pier every hour.','NOUN','Một cấu trúc dài được xây dựng từ đất liền nhô ra mặt nước','Phà rời cầu tàu mỗi giờ một chuyến.','Cầu tàu / Cầu cảng',2441,NULL,_binary '\0'),(3439,'A long, thin stretch of water made by people','The Panama Canal is vital for international shipping.','NOUN','Một dải nước dài, mỏng do con người tạo ra','Kênh đào Panama rất quan trọng đối với vận tải biển quốc tế.','Kênh đào',2442,NULL,_binary '\0'),(3440,'A tube-shaped passage in the body','The doctor examined his ear canal.','NOUN','Một lối đi hình ống trong cơ thể','Bác sĩ đã kiểm tra ống tai của anh ấy.','Ống / Kênh (cơ thể)',2442,NULL,_binary '\0'),(3441,'To move a boat through water using oars','They spent the afternoon rowing around the lake.','VERB','Di chuyển thuyền trong nước bằng mái chèo','Họ đã dành cả buổi chiều để chèo thuyền quanh hồ.','Chèo thuyền',2443,NULL,_binary '\0'),(3442,'A line of things or people next to each other','We were sitting in the front row of the boat.','NOUN','Một hàng vật hoặc người nằm cạnh nhau','Chúng tôi đang ngồi ở hàng ghế đầu của con thuyền.','Hàng / Dãy',2443,NULL,_binary '\0'),(3443,'A heavy metal object used to keep a ship in one place','The ship dropped anchor in the bay.','NOUN','Một vật nặng bằng kim loại dùng để giữ con tàu ở một chỗ','Con tàu đã thả neo trong vịnh.','Mỏ neo',2444,NULL,_binary '\0'),(3444,'Someone who reads the news on TV or a person who provides support','She is the main anchor for the evening news.','NOUN','Người đọc tin tức trên TV hoặc một người mang lại sự hỗ trợ/chỗ dựa','Cô ấy là biên tập viên chính cho bản tin buổi tối.','Người dẫn chương trình chính / Trụ cột',2444,NULL,_binary '\0'),(3445,'To rent a ship, aircraft, or bus for a special use','They decided to charter a boat for the company trip.','VERB','Thuê tàu, máy bay hoặc xe buýt cho một mục đích sử dụng đặc biệt','Họ quyết định thuê trọn một con thuyền cho chuyến đi của công ty.','Thuê trọn gói / Thuê chuyến',2445,NULL,_binary '\0'),(3446,'A formal statement of the rights of a group','The UN Charter promotes international peace.','NOUN','Một văn bản chính thức về quyền lợi của một nhóm','Hiến chương Liên Hợp Quốc thúc đẩy hòa bình quốc tế.','Hiến chương / Điều lệ',2445,NULL,_binary '\0'),(3447,'The track of waves left by a ship moving through water','The small boat was tossed about in the ferry\'s wake.','NOUN','Vệt sóng để lại bởi một con tàu khi di chuyển trên nước','Con thuyền nhỏ bị chao đảo trong đường rẽ nước của chiếc phà.','Đường rẽ nước / Vệt sóng',2446,NULL,_binary '\0'),(3448,'To stop sleeping','I usually wake up early to catch the first boat.','VERB','Ngừng ngủ','Tôi thường thức dậy sớm để bắt chuyến thuyền đầu tiên.','Thức giấc / Tỉnh dậy',2446,NULL,_binary '\0'),(3449,'A frame or shelf for storing or displaying things','Please return the bike to the rental rack.','NOUN','Khung hoặc kệ để cất giữ hoặc trưng bày đồ vật','Vui lòng trả xe đạp về giá để xe cho thuê.','Giá để xe / Kệ',2447,NULL,_binary '\0'),(3450,'To cause physical or mental pain','He was racked by guilt after the accident.','VERB','Gây ra nỗi đau về thể xác hoặc tinh thần','Anh ấy bị dằn vặt bởi cảm giác tội lỗi sau tai nạn.','Hành hạ / Làm đau đớn',2447,NULL,_binary '\0'),(3451,'To open something that was locked','You can unlock the scooter by scanning the QR code.','VERB','Mở một thứ gì đó đang bị khóa','Bạn có thể mở khóa xe điện bằng cách quét mã QR.','Mở khóa',2448,NULL,_binary '\0'),(3452,'To release or make something available','This course will help you unlock your potential.','VERB','Giải phóng hoặc làm cho thứ gì đó có sẵn','Khóa học này sẽ giúp bạn khai phá tiềm năng của mình.','Khai phá / Tiết lộ',2448,NULL,_binary '\0'),(3453,'A lever worked by the foot','My foot slipped off the bike pedal.','NOUN','Cần gạt được điều khiển bằng chân','Chân tôi bị trượt khỏi bàn đạp xe đạp.','Bàn đạp',2449,NULL,_binary '\0'),(3454,'To push the pedals of a bicycle','He pedaled as fast as he could.','VERB','Nhấn bàn đạp của xe đạp','Anh ấy đã đạp xe nhanh nhất có thể.','Đạp bàn đạp / Đạp xe',2449,NULL,_binary '\0'),(3455,'A hard hat that protects your head','You should always wear a helmet when riding a scooter.','NOUN','Mũ cứng dùng để bảo vệ đầu','Bạn luôn nên đội mũ bảo hiểm khi đi xe điện.','Mũ bảo hiểm',2450,NULL,_binary '\0'),(3456,'A series of metal rings connected together','The bike chain is rusty and needs oil.','NOUN','Một chuỗi các vòng kim loại kết nối với nhau','Xích xe đạp bị rỉ sét và cần tra dầu.','Dây xích / Xích xe',2451,NULL,_binary '\0'),(3457,'A number of similar establishments under one ownership','This is the largest bike rental chain in the city.','NOUN','Một số cơ sở tương tự thuộc cùng một quyền sở hữu','Đây là chuỗi cho thuê xe đạp lớn nhất thành phố.','Chuỗi (cửa hàng/nhà hàng)',2451,NULL,_binary '\0'),(3460,'The basic structure of a vehicle','The bicycle has a lightweight aluminum frame.','NOUN','Cấu trúc cơ bản của một phương tiện','Chiếc xe đạp có khung nhôm trọng lượng nhẹ.','Khung xe',2453,NULL,_binary '\0'),(3461,'A border for a picture or a mirror','I bought a wooden frame for the photo.','NOUN','Viền bao quanh một bức tranh hoặc gương','Tôi đã mua một cái khung gỗ cho bức ảnh.','Khung hình / Khung ảnh',2453,NULL,_binary '\0'),(3462,'A metal bar that holds a bicycle or motorcycle upright','Put the kickstand down before you walk away.','NOUN','Thanh kim loại giữ cho xe đạp hoặc xe máy đứng thẳng','Hãy gạt chân chống xuống trước khi bạn đi.','Chân chống',2454,NULL,_binary '\0'),(3463,'The bar that you hold when riding a bicycle or motorcycle','Keep both hands on the handlebar at all times.','NOUN','Thanh mà bạn cầm khi đi xe đạp hoặc xe máy','Luôn giữ cả hai tay trên tay lái.','Tay lái / Ghi-đông',2455,NULL,_binary '\0'),(3464,'A central point of activity or transport','The rental hub is located near the park entrance.','NOUN','Một điểm trung tâm của hoạt động hoặc giao thông','Trạm thuê xe nằm gần lối vào công viên.','Trung tâm / Trạm tập trung',2456,NULL,_binary '\0'),(3465,'The central part of a wheel','The wheel hub needs to be greased.','NOUN','Phần trung tâm của một bánh xe','Trục bánh xe cần được bôi trơn.','Trục bánh xe',2456,NULL,_binary '\0'),(3468,'A tire that does not have enough air in it','I can\'t ride this bike because the tire is flat.','ADJECTIVE','Lốp xe không có đủ không khí bên trong','Tôi không thể đi chiếc xe này vì lốp bị xẹp.','Xẹp / Thủng (lốp)',2458,NULL,_binary '\0'),(3469,'A set of rooms for living in','They live in a small flat downtown.','NOUN','Một dãy các phòng để ở','Họ sống trong một căn hộ nhỏ ở trung tâm.','Căn hộ',2458,NULL,_binary '\0'),(3470,'A hollow metal object that makes a ringing sound','Ring the bell to warn pedestrians.','NOUN','Vật kim loại rỗng tạo ra tiếng reng reng','Hãy rung chuông để cảnh báo người đi bộ.','Chuông xe',2459,NULL,_binary '\0'),(3471,'The sound made by a bell','I didn\'t hear the door bell.','NOUN','Âm thanh tạo ra bởi cái chuông','Tôi không nghe thấy tiếng chuông cửa.','Tiếng chuông',2459,NULL,_binary '\0'),(3472,'A piece of equipment for forcing liquid or gas into something','Do you have a bike pump I could borrow?','NOUN','Một thiết bị để ép chất lỏng hoặc khí vào thứ gì đó','Bạn có cái bơm xe đạp nào cho tôi mượn không?','Cái bơm',2460,NULL,_binary '\0'),(3473,'To force liquid or gas to move in a particular direction','The heart pumps blood around the body.','VERB','Ép chất lỏng hoặc khí di chuyển theo một hướng cụ thể','Tim bơm máu đi khắp cơ thể.','Bơm (nước/khí)',2460,NULL,_binary '\0'),(3476,'A structure or building that is built to honour a special person or event','The Lincoln Memorial is a famous monument in Washington, D.C.','NOUN','Một cấu trúc hoặc tòa nhà được xây dựng để vinh danh một người hoặc sự kiện đặc biệt','Đài tưởng niệm Lincoln là một di tích nổi tiếng ở Washington, D.C.','Đài tưởng niệm / Di tích',2462,NULL,_binary '\0'),(3477,'An object or event that is a great example of something','His career is a monument to hard work.','NOUN','Một vật hoặc sự kiện là ví dụ tuyệt vời cho cái gì đó','Sự nghiệp của ông là một minh chứng cho sự làm việc chăm chỉ.','Minh chứng / Đài đài bền vững',2462,NULL,_binary '\0'),(3480,'An object made from a hard material, especially one of a person or animal','The Statue of Liberty is located in New York.','NOUN','Một vật được làm từ vật liệu cứng, đặc biệt là hình một người hoặc con vật','Tượng Nữ thần Tự do nằm ở New York.','Bức tượng',2464,NULL,_binary '\0'),(3481,'Features belonging to the culture of a particular society','Hoi An is a UNESCO World Heritage Site.','NOUN','Các đặc điểm thuộc về văn hóa của một xã hội cụ thể','Hội An là Di sản Thế giới của UNESCO.','Di sản',2465,NULL,_binary '\0'),(3482,'The history, traditions, and qualities that a country or family has','She is proud of her Vietnamese heritage.','NOUN','Lịch sử, truyền thống và phẩm chất mà một quốc gia hoặc gia đình có','Cô ấy tự hào về nguồn cội Việt Nam của mình.','Truyền thống / Gia thế',2465,NULL,_binary '\0'),(3483,'A place where something is, was, or will be built','This is the site of an ancient temple.','NOUN','Nơi mà một cái gì đó đang, đã hoặc sẽ được xây dựng','Đây là địa điểm của một ngôi đền cổ.','Địa điểm / Vị trí',2466,NULL,_binary '\0'),(3484,'A website','Check the travel site for ticket prices.','NOUN','Một trang thông tin trên mạng internet','Kiểm tra trang web du lịch để biết giá vé.','Trang web',2466,NULL,_binary '\0'),(3485,'An open area with buildings around it in a town or city','Ba Dinh Square is where the President Ho Chi Minh read the Declaration of Independence.','NOUN','Một khu vực mở có các tòa nhà xung quanh trong một thị trấn hoặc thành phố','Quảng trường Ba Đình là nơi Chủ tịch Hồ Chí Minh đọc Tuyên ngôn Độc lập.','Quảng trường',2467,NULL,_binary '\0'),(3486,'A shape with four equal sides and four 90° angles','The floor was covered with black and white squares.','NOUN','Một hình có bốn cạnh bằng nhau và bốn góc 90 độ','Sàn nhà được bao phủ bởi những ô vuông đen và trắng.','Hình vuông',2467,NULL,_binary '\0'),(3487,'The official home of a king, queen, or president','We visited the Independence Palace in Ho Chi Minh City.','NOUN','Nơi ở chính thức của vua, hoàng hậu hoặc tổng thống','Chúng tôi đã đến thăm Dinh Độc Lập tại Thành phố Hồ Chí Minh.','Cung điện / Dinh thự',2468,NULL,_binary '\0'),(3488,'A rounded roof on a building','The cathedral is famous for its golden dome.','NOUN','Một mái nhà hình tròn trên một tòa nhà','Nhà thờ nổi tiếng với mái vòm dát vàng.','Mái vòm',2469,NULL,_binary '\0'),(3489,'Something shaped like a dome','The mountain had a smooth, snow-covered dome.','NOUN','Thứ gì đó có hình dạng giống như mái vòm','Ngọn núi có đỉnh hình vòm nhẵn bóng bao phủ bởi tuyết.','Vật hình vòm',2469,NULL,_binary '\0'),(3490,'A tall, narrow structure that either stands alone or is part of a building','The Tower of London is a historic castle.','NOUN','Một cấu trúc cao, hẹp đứng một mình hoặc là một phần của tòa nhà','Tháp London là một lâu đài lịch sử.','Tòa tháp',2470,NULL,_binary '\0'),(3491,'To be very tall or at a high level','The skyscraper towers over the other buildings.','VERB','Rất cao hoặc ở một mức độ cao','Tòa nhà chọc trời cao vượt lên trên các tòa nhà khác.','Cao ngất ngưởng / Vượt trội',2470,NULL,_binary '\0'),(3492,'A tall vertical structure used as a support or ornament','The temple was supported by stone pillars.','NOUN','Một cấu trúc thẳng đứng cao được sử dụng làm vật đỡ hoặc trang trí','Ngôi đền được chống đỡ bởi những cột đá.','Cột trụ / Trụ cột',2471,NULL,_binary '\0'),(3493,'A very important member or part of a group','He is a pillar of the local community.','NOUN','Một thành viên hoặc bộ phận rất quan trọng của một nhóm','Ông ấy là một trụ cột của cộng đồng địa phương.','Trụ cột / Người quan trọng',2471,NULL,_binary '\0'),(3494,'An object which is built to help people remember a person or event','A memorial was erected to those who died in the war.','NOUN','Một vật được xây dựng để giúp mọi người nhớ về một người hoặc sự kiện','Một đài tưởng niệm đã được dựng lên cho những người đã ngã xuống trong chiến tranh.','Đài tưởng niệm / Vật kỷ niệm',2472,NULL,_binary '\0'),(3495,'Done to remember a person or an event','The school held a memorial service for the late teacher.','ADJECTIVE','Được thực hiện để ghi nhớ một người hoặc sự kiện','Trường đã tổ chức một buổi lễ tưởng niệm cho người thầy quá cố.','Thuộc về tưởng niệm / Kỷ niệm',2472,NULL,_binary '\0'),(3496,'A curved structure that goes over an opening','The Arc de Triomphe is a famous arch in Paris.','NOUN','Một cấu trúc cong đi ngang qua một khoảng hở','Khải hoàn môn là một cổng vòm nổi tiếng ở Paris.','Cổng vòm / Khải hoàn môn',2473,NULL,_binary '\0'),(3497,'To be curved in shape','The trees arched over the road.','VERB','Có hình dạng cong','Những cái cây uốn cong thành vòm qua con đường.','Uốn cong / Hình cung',2473,NULL,_binary '\0'),(3498,'The front of a building','The cathedral has a magnificent stone facade.','NOUN','Phần phía trước của một tòa nhà','Nhà thờ có một mặt tiền bằng đá tráng lệ.','Mặt tiền',2474,NULL,_binary '\0'),(3499,'A false appearance that hides the real feelings or situation','Behind his friendly facade, he was actually quite angry.','NOUN','Vẻ ngoài sai lệch che giấu cảm xúc hoặc tình huống thực sự','Đằng sau vẻ ngoài thân thiện, anh ta thực chất khá tức giận.','Vẻ bề ngoài / Sự giả tạo',2474,NULL,_binary '\0'),(3500,'A place for worship that is holy because of a connection with a holy person or object','The temple is a sacred shrine for many pilgrims.','NOUN','Một nơi thờ cúng linh thiêng vì có liên quan đến một người hoặc vật thánh','Ngôi đền là một đền thờ thiêng liêng đối với nhiều người hành hương.','Đền thờ / Miếu thờ',2475,NULL,_binary '\0'),(3501,'A structure that forces water up into the air as an ornament','The Trevi Fountain is one of the most famous sights in Rome.','NOUN','Một cấu trúc đẩy nước lên không trung để làm vật trang trí','Đài phun nước Trevi là một trong những cảnh đẹp nổi tiếng nhất ở Rome.','Đài phun nước',2476,NULL,_binary '\0'),(3502,'A source of something','She is a fountain of knowledge about local history.','NOUN','Một nguồn cung cấp thứ gì đó','Cô ấy là một nguồn tri thức về lịch sử địa phương.','Nguồn / Suối nguồn',2476,NULL,_binary '\0'),(3503,'An object or a collection of objects shown in a museum','The museum\'s newest exhibit features ancient Egyptian jewelry.','NOUN','Một vật hoặc bộ sưu tập các vật được trình chiếu trong bảo tàng','Vật trưng bày mới nhất của bảo tàng giới thiệu đồ trang sức Ai Cập cổ đại.','Vật trưng bày / Cuộc triển lãm',2477,NULL,_binary '\0'),(3504,'To show something publicly','Local artists will exhibit their work at the gallery next week.','VERB','Trình bày cái gì đó một cách công khai','Các nghệ sĩ địa phương sẽ triển lãm tác phẩm của họ tại phòng trưng bày vào tuần tới.','Trưng bày / Triển lãm',2477,NULL,_binary '\0'),(3505,'A room or building for showing works of art','The National Gallery houses a vast collection of paintings.','NOUN','Một phòng hoặc tòa nhà để trình chiếu các tác phẩm nghệ thuật','Phòng trưng bày Quốc gia lưu giữ một bộ sưu tập tranh khổng lồ.','Phòng trưng bày / Triển lãm tranh',2478,NULL,_binary '\0'),(3506,'A collection of photographs or images','You can find the screenshots in your phone\'s gallery.','NOUN','Một bộ sưu tập các bức ảnh hoặc hình ảnh','Bạn có thể tìm thấy ảnh chụp màn hình trong thư viện ảnh của điện thoại.','Thư viện ảnh',2478,NULL,_binary '\0'),(3507,'A person in charge of a museum or art gallery','The curator explained the history of the artifacts.','NOUN','Người chịu trách nhiệm quản lý bảo tàng hoặc phòng trưng bày nghệ thuật','Người giám tuyển đã giải thích lịch sử của các hiện vật.','Quản thủ / Người giám tuyển',2479,NULL,_binary '\0'),(3509,'A group of objects of a particular type that someone has collected','The museum has a famous collection of sculptures.','NOUN','Một nhóm các đồ vật cùng loại mà ai đó đã sưu tầm','Bảo tàng có một bộ sưu tập điêu khắc nổi tiếng.','Bộ sưu tập',2481,NULL,_binary '\0'),(3510,'The act of bringing things together from different places','Garbage collection happens every Tuesday.','NOUN','Hành động mang các thứ từ nhiều nơi về cùng một chỗ','Việc thu gom rác diễn ra vào mỗi thứ Ba.','Sự thu gom / Việc thu thập',2481,NULL,_binary '\0'),(3512,'To keep something as it is, especially in order to prevent it from being damaged','Special chemicals are used to preserve old manuscripts.','VERB','Giữ cái gì đó như hiện trạng, đặc biệt là để ngăn nó bị hư hại','Các hóa chất đặc biệt được sử dụng để bảo tồn các bản thảo cổ.','Bảo tồn / Gìn giữ',2483,NULL,_binary '\0'),(3513,'Food made from fruit or vegetables boiled with sugar and water','I love eating strawberry preserves with toast.','NOUN','Thực phẩm làm từ trái cây hoặc rau củ đun sôi với đường và nước','Tôi thích ăn mứt dâu với bánh mì nướng.','Mứt / Đồ ngâm',2483,NULL,_binary '\0'),(3514,'A collection of historical records or the place where they are kept','I found the old photographs in the family archives.','NOUN','Một bộ sưu tập các hồ sơ lịch sử hoặc nơi lưu giữ chúng','Tôi đã tìm thấy những bức ảnh cũ trong hồ sơ lưu trữ của gia đình.','Kho lưu trữ / Hồ sơ lưu trữ',2484,NULL,_binary '\0'),(3515,'To store historical records or other information in an archive','The emails are automatically archived after one year.','VERB','Lưu trữ các hồ sơ lịch sử hoặc thông tin khác vào kho','Các email được tự động lưu trữ sau một năm.','Lưu trữ / Cất giữ',2484,NULL,_binary '\0'),(3516,'The act or process of returning something to its earlier good condition','The restoration of the cathedral took five years.','NOUN','Hành động hoặc quá trình đưa cái gì đó trở lại tình trạng tốt trước đây','Việc trùng tu nhà thờ đã mất năm năm.','Sự phục chế / Trùng tu',2485,NULL,_binary '\0'),(3517,'The act of starting something again','The government promised the restoration of public order.','NOUN','Hành động bắt đầu lại cái gì đó','Chính phủ hứa hẹn khôi phục trật tự công cộng.','Sự khôi phục',2485,NULL,_binary '\0'),(3520,'A recorded tour, usually on a handheld device, for museum visitors','You can rent an audio guide at the entrance for $5.','NOUN','Một chuyến tham quan được ghi âm sẵn, thường trên thiết bị cầm tay cho khách tham quan bảo tàng','Bạn có thể thuê máy thuyết minh tự động tại lối vào với giá 5 đô la.','Thiết bị thuyết minh tự động',2487,NULL,_binary '\0'),(3521,'A method or material used by an artist','Oil paint is a popular medium for portrait artists.','NOUN','Phương pháp hoặc vật liệu được nghệ sĩ sử dụng','Sơn dầu là một chất liệu phổ biến cho các họa sĩ vẽ chân dung.','Chất liệu / Phương tiện truyền đạt',2488,NULL,_binary '\0'),(3522,'Being in the middle between an upper and lower amount','I\'d like my steak medium, please.','ADJECTIVE','Ở mức giữa lượng trên và lượng dưới','Tôi muốn bít tết của mình chín vừa.','Trung bình / Vừa',2488,NULL,_binary '\0'),(3523,'A part of a large building that sticks out from the main part','The Impressionist paintings are in the East Wing.','NOUN','Một phần của tòa nhà lớn nhô ra khỏi phần chính','Các bức tranh trường phái Ấn tượng nằm ở dãy nhà phía Đông.','Cánh / Dãy nhà',2489,NULL,_binary '\0'),(3524,'One of the parts of the body that a bird, insect, or bat uses for flying','The bird spread its wings and flew away.','NOUN','Một bộ phận cơ thể của chim, côn trùng để bay','Con chim dang rộng đôi cánh và bay đi.','Cánh (chim/máy bay)',2489,NULL,_binary '\0'),(3525,'The act of entering a place or a door/gate','Entry to the museum is free on Sundays.','NOUN','Hành động đi vào một nơi hoặc cái cửa/cổng','Vào cửa bảo tàng miễn phí vào các ngày Chủ nhật.','Lối vào / Sự đi vào',2490,NULL,_binary '\0'),(3526,'A piece of work that is submitted for a competition','There are over 500 entries in the art competition.','NOUN','Một tác phẩm được gửi đi để thi đấu','Có hơn 500 tác phẩm dự thi trong cuộc thi nghệ thuật.','Tác phẩm dự thi / Mục (từ điển)',2490,NULL,_binary '\0'),(3527,'A shop that sells things that people give as presents, often for tourists','I bought some postcards in the museum gift shop.','NOUN','Cửa hàng bán những thứ làm quà tặng, thường dành cho khách du lịch','Tôi đã mua một vài tấm bưu thiếp trong cửa hàng lưu niệm của bảo tàng.','Cửa hàng lưu niệm',2491,NULL,_binary '\0'),(3528,'A short journey or trip, especially one taken as a leisure activity','The hotel organizes daily excursions to the local islands.','NOUN','Một hành trình hoặc chuyến đi ngắn, đặc biệt là hoạt động giải trí','Khách sạn tổ chức các chuyến tham quan hàng ngày đến các đảo địa phương.','Chuyến tham quan / Dã ngoại',2492,NULL,_binary '\0'),(3529,'A short period of visiting a new place or doing something different','The professor made a brief excursion into the field of sociology.','NOUN','Một khoảng thời gian ngắn làm điều gì đó khác biệt so với bình thường','Vị giáo sư đã có một lần lấn sân ngắn sang lĩnh vực xã hội học.','Sự chệch hướng / Lấn sân',2492,NULL,_binary '\0'),(3530,'A person who shows the way to others, especially one employed to show tourists around','Our guide was very knowledgeable about the temple history.','NOUN','Người chỉ đường cho người khác, đặc biệt là người được thuê để dẫn khách du lịch tham quan','Hướng dẫn viên của chúng tôi rất am hiểu về lịch sử ngôi đền.','Hướng dẫn viên',2493,NULL,_binary '\0'),(3531,'To show someone how to do something or where to go','The signs will guide you to the exit.','VERB','Chỉ cho ai đó cách làm gì hoặc đi đâu','Các biển báo sẽ dẫn bạn đến lối ra.','Hướng dẫn / Dẫn dắt',2493,NULL,_binary '\0'),(3533,'Information that is given to someone just before they do something','The tour leader gave us a quick briefing before we started the hike.','NOUN','Thông tin được đưa cho ai đó ngay trước khi họ thực hiện việc gì','Trưởng đoàn đã hướng dẫn ngắn cho chúng tôi trước khi bắt đầu đi bộ đường dài.','Buổi hướng dẫn ngắn / Thông tin tóm tắt',2495,NULL,_binary '\0'),(3534,'An organized journey for a particular purpose, especially to explore','They are planning an expedition to the North Pole.','NOUN','Một hành trình có tổ chức cho một mục đích cụ thể, đặc biệt là để khám phá','Họ đang lên kế hoạch cho một cuộc thám hiểm đến Bắc Cực.','Cuộc thám hiểm / Đoàn thám hiểm',2496,NULL,_binary '\0'),(3535,'Speed in doing something','The court case was processed with great expedition.','NOUN','Tốc độ trong khi thực hiện một việc gì đó','Vụ kiện đã được xử lý với sự nhanh chóng đáng kinh ngạc.','Sự nhanh chóng / Mau lẹ',2496,NULL,_binary '\0'),(3536,'A spoken description of an event while it is happening','The bus tour features a live commentary in English.','NOUN','Mô tả bằng lời nói về một sự kiện khi nó đang diễn ra','Tour xe buýt có thuyết minh trực tiếp bằng tiếng Anh.','Bài thuyết minh / Lời bình luận',2497,NULL,_binary '\0'),(3537,'A set of notes explaining a book or text','He wrote a detailed commentary on the new law.','NOUN','Một bộ các ghi chú giải thích một cuốn sách hoặc văn bản','Ông ấy đã viết một bản chú giải chi tiết về bộ luật mới.','Bài phê bình / Chú giải',2497,NULL,_binary '\0'),(3540,'Going or ready to go to a particular place','The tour group is bound for the city center.','ADJECTIVE','Đang đi hoặc sẵn sàng đi đến một nơi cụ thể','Đoàn khách du lịch đang hướng về trung tâm thành phố.','Đang đi đến / Hướng về',2499,NULL,_binary '\0'),(3541,'Certain or extremely likely to happen','You are bound to enjoy the excursion.','ADJECTIVE','Chắc chắn hoặc cực kỳ có khả năng xảy ra','Bạn chắc chắn sẽ thích chuyến tham quan này thôi.','Nhất định / Chắc chắn',2499,NULL,_binary '\0'),(3542,'The act of leaving a place','The coach departure is scheduled for 8 AM.','NOUN','Hành động rời khỏi một nơi','Giờ khởi hành của xe khách được lên lịch vào lúc 8 giờ sáng.','Sự khởi hành / Giờ đi',2500,NULL,_binary '\0'),(3543,'A change from what is expected or ordinary','This new tour style is a radical departure from their usual trips.','NOUN','Một sự thay đổi so với những gì được mong đợi hoặc bình thường','Kiểu tour mới này là một sự thay đổi hoàn toàn so với những chuyến đi thông thường của họ.','Sự thay đổi / Khác biệt',2500,NULL,_binary '\0'),(3545,'A particular spot or place','The meeting point for the tour is the clock tower.','NOUN','Một địa điểm hoặc vị trí cụ thể','Điểm tập trung của tour là tháp đồng hồ.','Địa điểm / Điểm dừng',2502,NULL,_binary '\0'),(3546,'An opinion or the purpose of something','I don\'t see the point of visiting the same place twice.','NOUN','Một ý kiến hoặc mục đích của cái gì đó','Tôi không thấy mục đích của việc tham quan cùng một nơi hai lần.','Quan điểm / Mục đích',2502,NULL,_binary '\0'),(3547,'To move forward or continue an action','Please proceed to the boarding gate.','VERB','Tiến lên phía trước hoặc tiếp tục một hành động','Vui lòng tiến về phía cổng lên máy bay.','Tiếp tục / Tiến về phía trước',2503,NULL,_binary '\0'),(3548,'To start a legal action against someone','The company decided to proceed against the contractor.','VERB','Bắt đầu một hành động pháp lý chống lại ai đó','Công ty quyết định kiện nhà thầu.','Kiện / Khởi tố',2503,NULL,_binary '\0'),(3549,'A story or a description of a series of events','The tour guide provided a compelling narrative of the city\'s past.','NOUN','Một câu chuyện hoặc mô tả về một loạt các sự kiện','Hướng dẫn viên đã kể một câu chuyện hấp dẫn về quá khứ của thành phố.','Lời kể / Câu chuyện',2504,NULL,_binary '\0'),(3550,'Telling a story','The book is written in a narrative style.','ADJECTIVE','Kể một câu chuyện','Cuốn sách được viết theo phong cách kể chuyện.','Thuộc về kể chuyện',2504,NULL,_binary '\0'),(3551,'To collect someone or something from a place','The bus will pick you up at the hotel lobby.','PHRASAL_VERB','Thu thập ai đó hoặc cái gì đó từ một nơi','Xe buýt sẽ đón bạn tại sảnh khách sạn.','Đón (người/vật)',2505,NULL,_binary '\0'),(3552,'To learn a new skill without much effort','He picked up some local phrases during the tour.','PHRASAL_VERB','Học một kỹ năng mới mà không tốn nhiều công sức','Anh ấy đã học lỏm được vài cụm từ địa phương trong chuyến tham quan.','Học lỏm / Tiếp thu',2505,NULL,_binary '\0'),(3553,'A particular place','This is a great spot for taking photos.','NOUN','Một nơi cụ thể','Đây là một địa điểm tuyệt vời để chụp ảnh.','Địa điểm / Nơi chốn',2506,NULL,_binary '\0'),(3554,'To see or notice someone or something','Can you spot the eagle on that tree?','VERB','Nhìn thấy hoặc chú ý đến ai đó hoặc cái gì đó','Bạn có phát hiện ra con đại bàng trên cái cây đó không?','Phát hiện / Nhận ra',2506,NULL,_binary '\0'),(3555,'A large table or a small shop with an open front from which goods are sold in a public place','There are many food stalls at the night market.','NOUN','Một chiếc bàn lớn hoặc cửa hàng nhỏ có mặt trước mở để bán hàng ở nơi công cộng','Có rất nhiều sạp đồ ăn tại chợ đêm.','Gian hàng / Sạp hàng',2507,NULL,_binary '\0'),(3556,'To delay taking action or to stop an engine from working','The car stalled in the middle of the road.','VERB','Trì hoãn hành động hoặc làm cho động cơ ngừng hoạt động','Chiếc xe bị chết máy ngay giữa đường.','Trì hoãn / Làm chết máy',2507,NULL,_binary '\0'),(3559,'Food or other things that have been grown or produced on a farm','The market sells fresh local produce.','NOUN','Thực phẩm hoặc những thứ khác được trồng hoặc sản xuất tại trang trại','Khu chợ bán các loại nông sản địa phương tươi ngon.','Nông sản',2509,NULL,_binary '\0'),(3560,'To make something or bring something into existence','The factory produces high-quality clothes.','VERB','Làm ra cái gì đó hoặc mang cái gì đó vào sự tồn tại','Nhà máy sản xuất quần áo chất lượng cao.','Sản xuất / Chế tạo',2509,NULL,_binary '\0'),(3561,'The money that is returned to you when you have paid more than the price','Don\'t forget to take your change.','NOUN','Số tiền được trả lại cho bạn khi bạn đã trả nhiều hơn giá niêm yết','Đừng quên nhận tiền thừa của bạn.','Tiền thừa / Tiền lẻ',2510,NULL,_binary '\0'),(3562,'To make something or someone different','I need to change my clothes before going out.','VERB','Làm cho cái gì đó hoặc ai đó trở nên khác đi','Tôi cần thay quần áo trước khi đi chơi.','Thay đổi',2510,NULL,_binary '\0'),(3564,'A product that is extremely good in a particular place','Seafood is a specialty of this coastal town.','NOUN','Một sản phẩm cực kỳ ngon hoặc nổi tiếng ở một địa phương cụ thể','Hải sản là đặc sản của thị trấn ven biển này.','Đặc sản / Món đặc trưng',2512,NULL,_binary '\0'),(3565,'A subject that someone knows a lot about','His specialty is international law.','NOUN','Một chủ đề mà ai đó biết rất nhiều về nó','Chuyên môn của anh ấy là luật quốc tế.','Chuyên môn / Lĩnh vực chuyên sâu',2512,NULL,_binary '\0'),(3566,'An object that is old, and often rare or beautiful','He collects antiques from the 19th century.','NOUN','Một đồ vật cũ, thường hiếm hoặc đẹp','Anh ấy sưu tầm đồ cổ từ thế kỷ 19.','Đồ cổ',2513,NULL,_binary '\0'),(3567,'Made in an earlier period and collected because of being beautiful or rare','The hotel is furnished with antique furniture.','ADJECTIVE','Được làm từ thời kỳ trước và được sưu tầm vì đẹp hoặc hiếm','Khách sạn được trang bị đồ nội thất cổ kính.','Cổ xưa / Cổ kính',2513,NULL,_binary '\0'),(3569,'A market, usually taking place outside, where old or used goods are sold cheaply','I found a vintage watch at the weekend flea market.','NOUN','Một khu chợ, thường diễn ra ngoài trời, nơi bán đồ cũ hoặc đã qua sử dụng với giá rẻ','Tôi đã tìm thấy một chiếc đồng hồ cổ tại chợ trời cuối tuần.','Chợ trời',2515,NULL,_binary '\0'),(3572,'To look through a book or look at things in a shop without a particular purpose','I was just browsing around the market stalls.','VERB','Xem qua một cuốn sách hoặc nhìn đồ vật trong cửa hàng mà không có mục đích cụ thể','Tôi chỉ đang dạo quanh xem qua các gian hàng ở chợ thôi.','Xem qua / Nhìn quanh',2517,NULL,_binary '\0'),(3573,'To look at information on the internet','I spent hours browsing the travel websites.','VERB','Xem thông tin trên mạng internet','Tôi đã dành hàng giờ để duyệt các trang web du lịch.','Duyệt web',2517,NULL,_binary '\0'),(3574,'Having a particular value, especially in money','This souvenir is definitely worth the price.','ADJECTIVE','Có một giá trị cụ thể, đặc biệt là về tiền bạc','Món quà lưu niệm này chắc chắn xứng đáng với giá tiền.','Trị giá / Đáng giá',2518,NULL,_binary '\0'),(3575,'The amount of money that something can be sold for','The experts estimated the worth of the painting.','NOUN','Số tiền mà một thứ gì đó có thể được bán','Các chuyên gia đã ước tính giá trị của bức tranh.','Giá trị / Tầm quan trọng',2518,NULL,_binary '\0'),(3576,'A reduction in the usual price','They offer a 10% discount for students.','NOUN','Một sự giảm giá so với giá thông thường','Họ giảm giá 10% cho sinh viên.','Sự giảm giá / Chiết khấu',2519,NULL,_binary '\0'),(3577,'To decide that something is not true or important','You shouldn\'t discount the possibility of rain.','VERB','Quyết định rằng điều gì đó không đúng hoặc không quan trọng','Bạn không nên loại trừ khả năng trời sẽ mưa.','Coi nhẹ / Bác bỏ',2519,NULL,_binary '\0'),(3578,'Large size or quantity','It\'s cheaper to buy spices in bulk at the market.','NOUN','Kích thước hoặc số lượng lớn','Mua gia vị với số lượng lớn ở chợ sẽ rẻ hơn.','Số lượng lớn / Khối lượng lớn',2520,NULL,_binary '\0'),(3579,'The largest part or most of something','The bulk of the tourists were from Europe.','NOUN','Phần lớn nhất hoặc hầu hết của cái gì đó','Phần lớn khách du lịch đến từ Châu Âu.','Phần lớn / Đa số',2520,NULL,_binary '\0'),(3580,'Skill in making things by hand','The village is famous for its traditional crafts.','NOUN','Kỹ năng làm đồ vật bằng tay','Ngôi làng nổi tiếng với các nghề thủ công truyền thống.','Nghề thủ công / Đồ thủ công',2521,NULL,_binary '\0'),(3581,'To make something using a lot of skill','He carefully crafted a beautiful wooden box.','VERB','Làm ra cái gì đó bằng rất nhiều kỹ năng','Anh ấy đã cẩn thận chế tác một chiếc hộp gỗ tuyệt đẹp.','Chế tác / Làm thủ công',2521,NULL,_binary '\0'),(3582,'A path through a countryside, mountain, or forest','Follow the marked trail to reach the waterfall.','NOUN','Một con đường băng qua vùng nông thôn, núi hoặc rừng','Hãy đi theo con đường mòn được đánh dấu để đến thác nước.','Đường mòn / Lối đi',2522,NULL,_binary '\0'),(3583,'A series of marks left by something that has passed','The jet left a white trail across the sky.','NOUN','Một loạt các dấu vết để lại bởi thứ gì đó đã đi qua','Chiếc phản lực để lại một vệt trắng trên bầu trời.','Dấu vết / Vệt kéo dài',2522,NULL,_binary '\0'),(3584,'An area of land kept separate for a particular purpose, especially to protect animals','We visited a nature reserve to see the rare birds.','NOUN','Một vùng đất được giữ riêng biệt cho một mục đích cụ thể, đặc biệt là để bảo vệ động vật','Chúng tôi đã đến thăm một khu bảo tồn thiên nhiên để ngắm những loài chim quý hiếm.','Khu bảo tồn',2523,NULL,_binary '\0'),(3585,'To keep something for a particular person or purpose','I reserved a table for two at the restaurant.','VERB','Giữ cái gì đó cho một người hoặc mục đích cụ thể','Tôi đã đặt một bàn cho hai người tại nhà hàng.','Đặt trước / Để dành',2523,NULL,_binary '\0'),(3586,'A surface of which one end is at a higher level than another','The mountain has a very steep slope.','NOUN','Một bề mặt có một đầu ở mức cao hơn đầu kia','Ngọn núi có sườn rất dốc.','Dốc / Sườn núi',2524,NULL,_binary '\0'),(3587,'To be at an angle to the horizontal','The garden slopes down towards the river.','VERB','Nằm ở một góc so với phương ngang','Khu vườn dốc xuống phía dòng sông.','Nghiêng / Dốc',2524,NULL,_binary '\0'),(3588,'An area of low land from which water flows into a river','The Amazon basin is home to the world\'s largest rainforest.','NOUN','Một vùng đất thấp nơi nước chảy vào một con sông','Lưu vực sông Amazon là nơi có rừng mưa lớn nhất thế giới.','Lưu vực / Lòng chảo',2525,NULL,_binary '\0'),(3589,'An open container used for washing or holding liquids','Fill the basin with warm water.','NOUN','Một vật chứa hở dùng để rửa hoặc đựng chất lỏng','Hãy đổ đầy nước ấm vào chậu.','Cái chậu / Bồn rửa',2525,NULL,_binary '\0'),(3590,'The pointed top of a mountain','It took them six hours to reach the peak.','NOUN','Phần chóp nhọn của một ngọn núi','Họ đã mất sáu giờ để lên tới đỉnh.','Đỉnh (núi)',2526,NULL,_binary '\0'),(3591,'The highest, strongest, or best point, value, or level','Traffic is worst during peak hours.','NOUN','Điểm, giá trị hoặc mức độ cao nhất, mạnh nhất hoặc tốt nhất','Giao thông tệ nhất là trong giờ cao điểm.','Cao điểm / Đỉnh điểm',2526,NULL,_binary '\0'),(3592,'A high place where you can see a wide area','There is a magnificent lookout at the top of the cliff.','NOUN','Một nơi cao nơi bạn có thể nhìn thấy một khu vực rộng lớn','Có một điểm quan sát tuyệt vời trên đỉnh vách đá.','Điểm quan sát / Đài quan sát',2527,NULL,_binary '\0'),(3593,'A person who is watching for danger','One of the burglars acted as a lookout.','NOUN','Người đang canh chừng nguy hiểm','Một trong những tên trộm đóng vai trò là người cảnh giới.','Người canh gác / Người cảnh giới',2527,NULL,_binary '\0'),(3595,'The leaves of a plant or tree of plants or trees','The autumn foliage is beautiful in this forest.','NOUN','Lá của một cái cây hoặc của các loại thực vật nói chung','Tán lá mùa thu ở khu rừng này rất đẹp.','Tán lá / Bộ lá',2529,NULL,_binary '\0'),(3596,'An area of land, when considering its natural features','The rocky terrain made the hike very difficult.','NOUN','Một vùng đất khi xem xét các đặc điểm tự nhiên của nó','Địa hình đá lởm chởm khiến chuyến đi bộ rất khó khăn.','Địa hình',2530,NULL,_binary '\0'),(3597,'A long seat for two or more people','We sat on a park bench and watched the sunset.','NOUN','Một chiếc ghế dài cho hai hoặc nhiều người ngồi','Chúng tôi ngồi trên ghế dài trong công viên và ngắm hoàng hôn.','Ghế dài / Ghế đá',2531,NULL,_binary '\0'),(3598,'A long, sturdy table for working on','He has a workbench in the garage.','NOUN','Một chiếc bàn dài, chắc chắn để làm việc trên đó','Anh ấy có một chiếc bàn làm việc trong nhà để xe.','Bàn thợ / Bàn thí nghiệm',2531,NULL,_binary '\0'),(3599,'A small narrow river','The trail follows a small mountain stream.','NOUN','Một con sông nhỏ và hẹp','Con đường mòn chạy dọc theo một dòng suối nhỏ trên núi.','Dòng suối',2532,NULL,_binary '\0'),(3600,'A continuous flow of things or people','There was a steady stream of visitors to the park.','NOUN','Một dòng chảy liên tục của đồ vật hoặc con người','Có một dòng khách tham quan ổn định đến công viên.','Luồng / Dòng chảy',2532,NULL,_binary '\0'),(3601,'A route or track between one place and another','The path leads to a beautiful hidden garden.','NOUN','Một lộ trình hoặc đường đi giữa nơi này và nơi khác','Lối đi dẫn đến một khu vườn ẩn tuyệt đẹp.','Lối đi / Đường mòn',2533,NULL,_binary '\0'),(3602,'A plan of action or a way of life','She is still trying to find her career path.','NOUN','Một kế hoạch hành động hoặc một cách sống','Cô ấy vẫn đang cố gắng tìm ra con đường sự nghiệp của mình.','Con đường / Hướng đi (sự nghiệp/đời sống)',2533,NULL,_binary '\0'),(3603,'A deep, narrow valley with steep sides, usually with a river at the bottom','The river has cut a deep gorge into the rock.','NOUN','Một thung lũng sâu, hẹp với hai bên dốc, thường có một con sông ở đáy','Con sông đã cắt một hẻm núi sâu vào đá.','Hẻm núi',2534,NULL,_binary '\0'),(3604,'To eat until you are unable to eat any more','They gorged themselves on chocolate.','VERB','Ăn cho đến khi bạn không thể ăn thêm được nữa','Họ đã ăn socola một cách ngấu nghiến.','Ăn ngấu nghiến / Ăn quá mức',2534,NULL,_binary '\0'),(3606,'The branches and leaves that spread out at the top of a group of trees','Birds live high up in the forest canopy.','NOUN','Các cành và lá xòe ra ở phần trên cùng của một nhóm cây','Chim chóc sống trên cao ở tán rừng.','Tán rừng / Vòm lá',2536,NULL,_binary '\0'),(3607,'A cover fixed over a seat or bed','The shop has a red and white striped canopy.','NOUN','Một tấm che được cố định trên một chỗ ngồi hoặc giường','Cửa hàng có một mái che sọc đỏ và trắng.','Mái che / Tấm bạt',2536,NULL,_binary '\0'),(3608,'A special social event, such as a party, when you celebrate something','The city held a massive celebration for Tet.','NOUN','Một sự kiện xã hội đặc biệt để ăn mừng một điều gì đó','Thành phố đã tổ chức một buổi lễ kỷ niệm lớn cho dịp Tết.','Lễ kỷ niệm / Sự ăn mừng',2537,NULL,_binary '\0'),(3609,'The act of praising something','The festival is a celebration of local traditional art.','NOUN','Hành động khen ngợi hoặc tôn vinh điều gì đó','Lễ hội là một sự tôn vinh nghệ thuật truyền thống địa phương.','Sự tôn vinh / Ca ngợi',2537,NULL,_binary '\0'),(3610,'A large number of people walking or riding in vehicles, usually as part of a public celebration','Thousands of people watched the floral parade.','NOUN','Một nhóm lớn người đi bộ hoặc đi xe, thường là một phần của lễ kỷ niệm công cộng','Hàng ngàn người đã xem cuộc diễu hành hoa.','Cuộc diễu hành',2538,NULL,_binary '\0'),(3611,'To walk somewhere to show that you are proud of something','The victors paraded through the streets.','VERB','Đi đâu đó để chứng tỏ bạn tự hào về điều gì đó','Những người chiến thắng đã diễu hành qua các con phố.','Diễu hành / Phô trương',2538,NULL,_binary '\0'),(3612,'A formal religious or public occasion, typically one celebrating a particular event','The opening ceremony of the festival was spectacular.','NOUN','Một dịp tôn giáo hoặc công cộng trang trọng, thường là để kỷ niệm một sự kiện','Lễ khai mạc của lễ hội thật hoành tráng.','Nghi lễ / Nghi thức',2539,NULL,_binary '\0'),(3613,'Formal behavior','There is no need for ceremony between friends.','NOUN','Hành vi trang trọng quá mức','Bạn bè với nhau thì không cần phải khách sáo.','Sự khách sáo / Nghi thức trịnh trọng',2539,NULL,_binary '\0'),(3614,'A way of behaving that has been established for a long time','It is a local custom to wear traditional clothes during the event.','NOUN','Một cách cư xử đã được thiết lập từ lâu đời','Mặc trang phục truyền thống trong sự kiện là một phong tục địa phương.','Phong tục / Tập quán',2540,NULL,_binary '\0'),(3615,'Specially made for a particular person','The shop offers custom-made souvenirs.','ADJECTIVE','Được làm đặc biệt cho một người cụ thể','Cửa hàng cung cấp các món quà lưu niệm được làm theo yêu cầu.','Tùy chỉnh / Thiết kế riêng',2540,NULL,_binary '\0'),(3616,'A set of fixed actions and sometimes words performed regularly','Coffee is part of my morning ritual.','NOUN','Một tập hợp các hành động và lời nói cố định được thực hiện thường xuyên','Cà phê là một phần trong thói quen buổi sáng của tôi.','Nghi lễ / Trình thức',2541,NULL,_binary '\0'),(3617,'Done as part of a ritual','The priest performed a ritual dance.','ADJECTIVE','Được thực hiện như một phần của nghi lễ','Vị linh mục đã thực hiện một điệu nhảy nghi lễ.','Thuộc về nghi lễ',2541,NULL,_binary '\0'),(3618,'A large meal, typically a celebratory one','The wedding feast lasted for three days.','NOUN','Một bữa ăn lớn, thường là để chúc mừng','Yến tiệc đám cưới kéo dài trong ba ngày.','Yến tiệc / Bữa tiệc thịnh soạn',2542,NULL,_binary '\0'),(3619,'To eat a lot of food or to enjoy something greatly','We feasted our eyes on the beautiful lanterns.','VERB','Ăn nhiều thức ăn hoặc tận hưởng điều gì đó một cách tuyệt vời','Chúng tôi đã mãn nhãn khi ngắm nhìn những chiếc đèn lồng đẹp đẽ.','Thưởng thức / Ăn uống no say',2542,NULL,_binary '\0'),(3621,'An unusual or unexpected event or situation that attracts attention','The fireworks display was a magnificent spectacle.','NOUN','Một sự kiện hoặc tình huống bất thường hoặc bất ngờ thu hút sự chú ý','Màn bắn pháo hoa là một quang cảnh lộng lẫy.','Cảnh tượng / Quang cảnh',2544,NULL,_binary '\0'),(3622,'Glasses','He was wearing a pair of wire-rimmed spectacles.','NOUN','Kính đeo mắt','Anh ấy đã đeo một cặp kính gọng sắt.','Kính mắt',2544,NULL,_binary '\0'),(3623,'A public festival, often with music and dancing in the streets','The Rio Carnival is the most famous in the world.','NOUN','Một lễ hội công cộng, thường có âm nhạc và nhảy múa trên đường phố','Lễ hội Carnival ở Rio là nổi tiếng nhất thế giới.','Lễ hội hóa trang / Hội chợ vui chơi',2545,NULL,_binary '\0'),(3624,'The action of entertaining other people by dancing, singing, or acting','The lion dance performance starts at 7 PM.','NOUN','Hành động giải trí cho người khác bằng cách nhảy múa, ca hát hoặc diễn xuất','Màn trình diễn múa lân bắt đầu lúc 7 giờ tối.','Buổi biểu diễn / Màn trình diễn',2546,NULL,_binary '\0'),(3625,'How well a person, machine, etc. does a piece of work or an activity','High-performance computers are needed for coding.','NOUN','Một người, máy móc... thực hiện một công việc hoặc hoạt động tốt đến mức nào','Máy tính hiệu suất cao là cần thiết để lập trình.','Hiệu suất / Khả năng làm việc',2546,NULL,_binary '\0'),(3626,'The mood or feeling that exists in a place and at a particular time','The festival has a very friendly atmosphere.','NOUN','Tâm trạng hoặc cảm giác tồn tại ở một nơi và vào một thời điểm cụ thể','Lễ hội có một bầu không khí rất thân thiện.','Bầu không khí / Cảm giác',2547,NULL,_binary '\0'),(3627,'The mixture of gases that surrounds the earth','Pollution is damaging the earth\'s atmosphere.','NOUN','Hỗn hợp khí bao quanh trái đất','Ô nhiễm đang hủy hoại bầu khí quyển của trái đất.','Khí quyển',2547,NULL,_binary '\0'),(3628,'A belief or custom that has existed for a long time','It is a tradition to visit relatives during the holidays.','NOUN','Một niềm tin hoặc phong tục đã tồn tại từ lâu đời','Thăm người thân trong kỳ nghỉ là một truyền thống.','Truyền thống',2548,NULL,_binary '\0'),(3631,'A public event where goods are sold or there is entertainment','Let\'s go to the craft fair this weekend.','NOUN','Một sự kiện công cộng nơi hàng hóa được bán hoặc có hoạt động giải trí','Hãy đi đến hội chợ thủ công vào cuối tuần này.','Hội chợ',2550,NULL,_binary '\0'),(3632,'Treating people equally or being quite good','The judge gave a fair decision.','ADJECTIVE','Đối xử công bằng với mọi người hoặc ở mức khá tốt','Thẩm phán đã đưa ra một quyết định công bằng.','Công bằng / Khá tốt',2550,NULL,_binary '\0'),(3633,'A person who uses a particular shop or supports a person or organization','The festival was supported by wealthy patrons.','NOUN','Người sử dụng một cửa hàng cụ thể hoặc ủng hộ một người hoặc tổ chức','Lễ hội đã được ủng hộ bởi các nhà bảo trợ giàu có.','Khách hàng quen / Người bảo trợ',2551,NULL,_binary '\0'),(3634,'A saint who is believed to protect a particular place or group','St. George is the patron saint of England.','NOUN','Vị thánh được tin là bảo vệ một địa điểm hoặc nhóm người cụ thể','Thánh George là thánh bảo hộ của nước Anh.','Thánh bảo hộ',2551,NULL,_binary '\0'),(3635,'With a view of a wide area of land','The hotel balcony offers a panoramic view of the bay.','ADJECTIVE','Với góc nhìn rộng lớn về một vùng đất','Ban công khách sạn có tầm nhìn toàn cảnh ra vịnh.','Toàn cảnh / Tầm mắt rộng',2552,NULL,_binary '\0'),(3638,'The way that objects appear smaller when they are further away','The artist used perspective to create a sense of depth.','NOUN','Cách mà các vật thể trông nhỏ hơn khi chúng ở xa hơn','Họa sĩ đã sử dụng luật xa gần để tạo ra cảm giác về chiều sâu.','Luật xa gần / Góc nhìn',2554,NULL,_binary '\0'),(3639,'A particular way of considering something','Traveling gives you a different perspective on life.','NOUN','Một cách cụ thể để xem xét điều gì đó','Đi du lịch mang lại cho bạn một góc nhìn khác về cuộc sống.','Quan điểm / Cách nhìn nhận',2554,NULL,_binary '\0'),(3640,'The point at which images are clear and not blurry','The camera struggled to find focus in low light.','NOUN','Điểm mà hình ảnh rõ nét và không bị nhòe','Máy ảnh gặp khó khăn trong việc lấy nét trong điều kiện ánh sáng yếu.','Tiêu cự / Điểm lấy nét',2555,NULL,_binary '\0'),(3641,'To give a lot of attention to one particular person, subject, or thing','I need to focus on my coding project right now.','VERB','Dành nhiều sự chú ý cho một người, chủ đề hoặc vật cụ thể','Tôi cần tập trung vào dự án lập trình của mình ngay bây giờ.','Tập trung',2555,NULL,_binary '\0'),(3642,'The general situation in which particular events happen','The mountains provided a dramatic backdrop for our photos.','NOUN','Tình huống chung nơi các sự kiện cụ thể diễn ra','Những ngọn núi đã tạo nên một phông nền đầy kịch tính cho những bức ảnh của chúng tôi.','Phông nền / Bối cảnh nền',2556,NULL,_binary '\0'),(3643,'A large piece of cloth with a scene painted on it, used at the back of a stage','The stage backdrop was painted to look like a forest.','NOUN','Một tấm vải lớn có vẽ cảnh vật trên đó, dùng phía sau sân khấu','Màn hậu trường sân khấu được vẽ trông giống như một khu rừng.','Tấm màn hậu trường',2556,NULL,_binary '\0'),(3644,'To record or take a picture of something','He managed to capture the bird in mid-flight.','VERB','Ghi lại hoặc chụp một bức ảnh của điều gì đó','Anh ấy đã chụp được khoảnh khắc con chim đang bay.','Chụp lại / Ghi lại',2557,NULL,_binary '\0'),(3645,'To take someone as a prisoner or take control of a place','The city was captured after a long siege.','VERB','Bắt ai đó làm tù binh hoặc kiểm soát một địa điểm','Thành phố đã bị chiếm sau một cuộc bao vây dài.','Bắt giữ / Chiếm lấy',2557,NULL,_binary '\0'),(3647,'The amount of light allowed to reach the film or sensor','A long exposure was needed to take a picture of the stars.','NOUN','Lượng ánh sáng được phép tiếp cận phim hoặc cảm biến','Cần một khoảng thời gian phơi sáng dài để chụp ảnh các vì sao.','Sự phơi sáng',2559,NULL,_binary '\0'),(3648,'The state of having no protection from something harmful','Prolonged exposure to the sun can damage your skin.','NOUN','Tình trạng không có sự bảo vệ khỏi một thứ gì đó có hại','Tiếp xúc lâu với ánh nắng mặt trời có thể làm hỏng làn da của bạn.','Sự tiếp xúc / Sự phơi nhiễm',2559,NULL,_binary '\0'),(3649,'The position from which you look at something','From this angle, the building looks even taller.','NOUN','Vị trí mà bạn nhìn vào một cái gì đó','Từ góc này, tòa nhà trông còn cao hơn nữa.','Góc chụp / Góc nhìn',2560,NULL,_binary '\0'),(3650,'The space between two lines that meet each other','A right angle is 90 degrees.','NOUN','Khoảng cách giữa hai đường thẳng gặp nhau','Một góc vuông là 90 độ.','Góc (hình học)',2560,NULL,_binary '\0'),(3651,'A piece of glass or plastic that changes the light in a camera','I used a vintage filter to give the photo an old look.','NOUN','Một mảnh thủy tinh hoặc nhựa làm thay đổi ánh sáng trong máy ảnh','Tôi đã sử dụng bộ lọc cổ điển để tạo cho bức ảnh một vẻ ngoài cũ kỹ.','Bộ lọc ảnh / Kính lọc',2561,NULL,_binary '\0'),(3652,'To remove something from a liquid or gas','The water is filtered to remove impurities.','VERB','Loại bỏ thứ gì đó khỏi chất lỏng hoặc chất khí','Nước được lọc để loại bỏ các tạp chất.','Lọc (nước/khí)',2561,NULL,_binary '\0'),(3653,'The way that people or things are arranged in a painting or photograph','The composition of this landscape photo is perfect.','NOUN','Cách mà con người hoặc đồ vật được sắp xếp trong một bức tranh hoặc bức ảnh','Bố cục của bức ảnh phong cảnh này thật hoàn hảo.','Bố cục',2562,NULL,_binary '\0'),(3654,'A short piece of writing or a musical work','We had to write a composition about our summer holiday.','NOUN','Một bài viết ngắn hoặc một tác phẩm âm nhạc','Chúng tôi đã phải viết một bài luận về kỳ nghỉ hè của mình.','Bài luận / Bản nhạc / Thành phần',2562,NULL,_binary '\0'),(3655,'The difference between the light and dark areas of a picture','The photo lacks contrast and looks a bit flat.','NOUN','Sự khác biệt giữa các vùng sáng và tối của một bức ảnh','Bức ảnh thiếu độ tương phản và trông hơi phẳng.','Độ tương phản',2563,NULL,_binary '\0'),(3656,'An obvious difference between two or more things','There is a sharp contrast between the rich and the poor.','NOUN','Sự khác biệt rõ ràng giữa hai hoặc nhiều thứ','Có một sự đối lập gay gắt giữa người giàu và người nghèo.','Sự đối lập / Tương phản',2563,NULL,_binary '\0'),(3657,'The main person or thing shown in a photograph','The subject of the photo was a small child playing.','NOUN','Người hoặc vật chính được hiển thị trong một bức ảnh','Chủ thể của bức ảnh là một đứa trẻ đang chơi đùa.','Chủ thể',2564,NULL,_binary '\0'),(3658,'An area of knowledge that is studied in school','My favorite subject is history.','NOUN','Một lĩnh vực kiến thức được học ở trường','Môn học yêu thích của tôi là lịch sử.','Môn học / Chủ đề',2564,NULL,_binary '\0'),(3659,'Far away','I could see the distant mountains through the haze.','ADJECTIVE','Ở xa','Tôi có thể nhìn thấy những ngọn núi xa xăm qua màn sương mù.','Xa xôi / Cách biệt',2565,NULL,_binary '\0'),(3660,'Not friendly or not willing to take part in things','She has been very distant lately.','ADJECTIVE','Không thân thiện hoặc không sẵn lòng tham gia vào mọi việc','Dạo này cô ấy rất xa cách.','Xa cách / Lạnh nhạt',2565,NULL,_binary '\0'),(3661,'A beautiful view from a high place','From the peak, a magnificent vista opened up before us.','NOUN','Một khung cảnh đẹp từ một nơi cao','Từ trên đỉnh núi, một khung cảnh lộng lẫy hiện ra trước mắt chúng tôi.','Khung cảnh / Tầm nhìn xa',2566,NULL,_binary '\0'),(3662,'A set of possibilities in the future','The new job opened up whole new vistas for him.','NOUN','Một tập hợp các khả năng trong tương lai','Công việc mới đã mở ra những viễn cảnh hoàn toàn mới cho anh ấy.','Triển vọng / Viễn cảnh',2566,NULL,_binary '\0'),(3663,'The act of agreeing that someone should go into a hospital for treatment','The patient required immediate admission to the ICU.','NOUN','Hành động đồng ý rằng ai đó nên vào bệnh viện để điều trị','Bệnh nhân cần được nhập viện ngay lập tức vào khoa hồi sức tích cực.','Sự nhập viện',2567,NULL,_binary '\0'),(3664,'The act of agreeing that something is true, or the money paid to enter a place','Admission to the museum is free on Sundays.','NOUN','Hành động đồng ý rằng điều gì đó là đúng, hoặc số tiền trả để vào một nơi','Vào cửa bảo tàng miễn phí vào các ngày Chủ nhật.','Sự thú nhận / Phí vào cổng',2567,NULL,_binary '\0'),(3665,'To allow someone officially to leave a hospital','The doctor will discharge you once your tests are clear.','VERB','Cho phép ai đó chính thức rời khỏi bệnh viện','Bác sĩ sẽ cho bạn xuất viện khi các xét nghiệm của bạn ổn định.','Cho xuất viện',2568,NULL,_binary '\0'),(3666,'To send out a substance, especially waste, or to release electricity','The battery will discharge if not used for a long time.','VERB','Thải ra một chất, đặc biệt là chất thải, hoặc giải phóng điện','Pin sẽ bị phóng điện (hết pin) nếu không được sử dụng trong thời gian dài.','Phóng điện / Thải ra',2568,NULL,_binary '\0'),(3667,'Extremely serious or dangerous (medical condition)','The accident victim is in critical condition.','ADJECTIVE','Cực kỳ nghiêm trọng hoặc nguy hiểm (tình trạng sức khỏe)','Nạn nhân vụ tai nạn đang trong tình trạng nguy kịch.','Nguy kịch',2569,NULL,_binary '\0'),(3668,'Extremely important or expressing adverse disapproval','This is a critical bug that needs to be fixed immediately.','ADJECTIVE','Cực kỳ quan trọng hoặc thể hiện sự không đồng tình','Đây là một lỗi cực kỳ nghiêm trọng cần được sửa ngay lập tức.','Quan trọng / Chỉ trích',2569,NULL,_binary '\0'),(3669,'A separate room or area in a hospital for people with the same type of condition','He was moved to the maternity ward.','NOUN','Một phòng hoặc khu vực riêng biệt trong bệnh viện cho những người có cùng loại bệnh','Anh ấy đã được chuyển đến khoa sản.','Buồng bệnh / Khoa',2570,NULL,_binary '\0'),(3670,'One of the parts into which a town or city is divided','The local council is divided into ten wards.','NOUN','Một trong những phần mà thị trấn hoặc thành phố được chia ra','Hội đồng địa phương được chia thành mười phường.','Phường / Khu vực hành chính',2570,NULL,_binary '\0'),(3671,'Not likely to change or fail; firmly established','The patient is in a stable condition after surgery.','ADJECTIVE','Không có khả năng thay đổi hoặc thất bại; được thiết lập vững chắc','Bệnh nhân đang trong tình trạng ổn định sau phẫu thuật.','Ổn định',2571,NULL,_binary '\0'),(3672,'A building in which horses are kept','The horses were led back to the stable.','NOUN','Một tòa nhà nơi ngựa được giữ','Những con ngựa đã được dẫn trở lại chuồng.','Chuồng ngựa',2571,NULL,_binary '\0'),(3673,'A severe injury to the body','The patient suffered multiple traumas in the car crash.','NOUN','Một vết thương nghiêm trọng đối với cơ thể','Bệnh nhân bị nhiều chấn thương trong vụ va chạm xe hơi.','Chấn thương thể xác',2572,NULL,_binary '\0'),(3674,'Severe emotional shock and pain','The war left the children with deep psychological trauma.','NOUN','Sốc và đau đớn về mặt cảm xúc nghiêm trọng','Chiến tranh đã để lại cho những đứa trẻ những sang chấn tâm lý sâu sắc.','Sang chấn tâm lý',2572,NULL,_binary '\0'),(3675,'A person who works as a doctor or a lawyer','You should consult a general practitioner (GP) for your flu.','NOUN','Một người làm việc như một bác sĩ hoặc một luật sư','Bạn nên tham khảo ý kiến bác sĩ đa khoa về bệnh cúm của mình.','Người hành nghề / Bác sĩ',2573,NULL,_binary '\0'),(3676,'Someone who regularly does a particular activity','She is an experienced practitioner of yoga.','NOUN','Người thường xuyên thực hiện một hoạt động cụ thể','Cô ấy là một người thực hành yoga dày dạn kinh nghiệm.','Người thực hành',2573,NULL,_binary '\0'),(3677,'The part of a hospital where people who are hurt in accidents are treated','The victims were rushed to the casualty department.','NOUN','Phần của bệnh viện nơi những người bị thương trong tai nạn được điều trị','Các nạn nhân đã được đưa đi cấp cứu ngay lập tức.','Khoa cấp cứu',2574,NULL,_binary '\0'),(3678,'A person injured or killed in a serious accident or war','There were many casualties in the earthquake.','NOUN','Một người bị thương hoặc bị giết trong một tai nạn nghiêm trọng hoặc chiến tranh','Đã có rất nhiều thương vong trong trận động đất.','Thương vong',2574,NULL,_binary '\0'),(3679,'Permission for something to happen or agreement to do something','They cannot perform surgery without the patient\'s consent.','NOUN','Sự cho phép điều gì đó xảy ra hoặc thỏa thuận làm điều gì đó','Họ không thể thực hiện phẫu thuật nếu không có sự đồng ý của bệnh nhân.','Sự đồng ý / Chấp thuận',2575,NULL,_binary '\0'),(3680,'To agree to do something, or to allow someone to do something','He consented to the search of his luggage.','VERB','Đồng ý làm việc gì đó, hoặc cho phép ai đó làm việc gì đó','Anh ấy đã đồng ý để họ khám xét hành lý của mình.','Đồng ý / Bằng lòng',2575,NULL,_binary '\0'),(3683,'A medical operation','The dental procedure will take about an hour.','NOUN','Một hoạt động y tế','Thủ thuật nha khoa sẽ mất khoảng một giờ.','Thủ thuật / Ca phẫu thuật',2577,NULL,_binary '\0'),(3684,'A set of actions that is the official or accepted way of doing something','You must follow the proper security procedure.','NOUN','Một tập hợp các hành động là cách chính thức hoặc được chấp nhận để làm điều gì đó','Bạn phải tuân thủ quy trình an ninh đúng quy định.','Quy trình / Thủ tục',2577,NULL,_binary '\0'),(3685,'Completely clean and free from dirt and bacteria','The operating theatre must be kept sterile.','ADJECTIVE','Hoàn toàn sạch sẽ và không có bụi bẩn cũng như vi khuẩn','Phòng phẫu thuật phải được giữ vô trùng.','Vô trùng / Khử trùng',2578,NULL,_binary '\0'),(3686,'Unable to produce young or plants','The land is sterile and cannot support crops.','ADJECTIVE','Không thể sinh con hoặc không thể trồng cây','Vùng đất này cằn cỗi và không thể canh tác vụ mùa.','Vô sinh / Cằn cỗi',2578,NULL,_binary '\0'),(3687,'To watch and check a situation carefully for a period of time','Nurses monitor the patient\'s heart rate constantly.','VERB','Quan sát và kiểm tra một tình huống cẩn thận trong một khoảng thời gian','Các y tá theo dõi nhịp tim của bệnh nhân liên tục.','Theo dõi / Giám sát',2579,NULL,_binary '\0'),(3688,'A device with a screen used for showing information','I need a new monitor for my computer setup.','NOUN','Một thiết bị có màn hình dùng để hiển thị thông tin','Tôi cần một màn hình mới cho dàn máy tính của mình.','Màn hình / Thiết bị giám sát',2579,NULL,_binary '\0'),(3689,'Very serious or bad','He has a severe allergic reaction to nuts.','ADJECTIVE','Rất nghiêm trọng hoặc rất tệ','Anh ấy bị dị ứng nghiêm trọng với các loại hạt.','Nghiêm trọng / Khốc liệt',2580,NULL,_binary '\0'),(3690,'Very strict or harsh','The punishment for breaking the rule was severe.','ADJECTIVE','Rất nghiêm khắc hoặc khắc nghiệt','Hình phạt cho việc vi phạm quy định rất khắt khe.','Khắt khe / Nghiêm khắc',2580,NULL,_binary '\0'),(3691,'To wash something by rubbing it hard with a brush','Surgeons must scrub their hands before an operation.','VERB','Rửa cái gì đó bằng cách chà xát mạnh bằng bàn chải','Các bác sĩ phẫu thuật phải sát khuẩn tay trước ca mổ.','Cọ rửa / Sát khuẩn',2581,NULL,_binary '\0'),(3692,'To decide not to do something you had planned','They had to scrub the mission due to technical issues.','VERB','Quyết định không làm điều gì đó bạn đã lên kế hoạch','Họ đã phải hủy bỏ nhiệm vụ do các vấn đề kỹ thuật.','Hủy bỏ / Loại bỏ',2581,NULL,_binary '\0'),(3693,'A piece of paper on which a doctor writes the details of the medicine that someone needs','You can\'t buy these antibiotics without a prescription.','NOUN','Tờ giấy bác sĩ viết chi tiết loại thuốc mà ai đó cần','Bạn không thể mua những loại kháng sinh này mà không có đơn thuốc.','Đơn thuốc',2582,NULL,_binary '\0'),(3694,'A way of thinking or acting that someone suggests in order to solve a problem','Her prescription for the economy involves cutting taxes.','NOUN','Cách suy nghĩ hoặc hành động mà ai đó gợi ý để giải quyết một vấn đề','Giải pháp của bà ấy cho nền kinh tế bao gồm việc cắt giảm thuế.','Quy định / Giải pháp đề ra',2582,NULL,_binary '\0'),(3695,'A measured amount of something such as medicine','The label says the standard dose is two tablets.','NOUN','Một lượng đo lường của thứ gì đó chẳng hạn như thuốc','Nhãn ghi liều lượng tiêu chuẩn là hai viên nén.','Liều lượng / Liều thuốc',2583,NULL,_binary '\0'),(3696,'An amount of something unpleasant','I had a heavy dose of the flu last winter.','NOUN','Một lượng của thứ gì đó không dễ chịu','Tôi đã bị một trận cúm nặng vào mùa đông năm ngoái.','Một chầu / Một trận',2583,NULL,_binary '\0'),(3697,'If your stomach is upset, you feel slightly ill','I have an upset stomach after eating that street food.','ADJECTIVE','Nếu dạ dày của bạn bị \"upset\", bạn cảm thấy hơi khó chịu/đau','Tôi bị đau bụng sau khi ăn món ăn đường phố đó.','Rối loạn (tiêu hóa) / Đau bụng',2584,NULL,_binary '\0'),(3698,'Worried, unhappy, or angry','She was very upset about the flight delay.','ADJECTIVE','Lo lắng, không hạnh phúc hoặc tức giận','Cô ấy đã rất buồn về việc chuyến bay bị trì hoãn.','Buồn bã / Thất vọng',2584,NULL,_binary '\0'),(3699,'A feeling of happiness that something unpleasant has not happened or has ended','The medicine brought immediate relief from the pain.','NOUN','Cảm giác hạnh phúc khi điều gì đó không vui đã không xảy ra hoặc đã kết thúc','Thuốc đã mang lại sự giảm đau ngay lập tức.','Sự giảm nhẹ / Sự giảm đau',2585,NULL,_binary '\0'),(3700,'Food, money, or services that provide help for people in need','Musicians raised money for famine relief.','NOUN','Thực phẩm, tiền bạc hoặc các dịch vụ cung cấp sự giúp đỡ cho những người cần thiết','Các nhạc sĩ đã gây quỹ để cứu trợ nạn đói.','Sự cứu trợ',2585,NULL,_binary '\0'),(3701,'A long, flat, narrow surface or table in a shop','You can buy vitamins over the counter.','NOUN','Một bề mặt hoặc bàn dài, phẳng, hẹp trong cửa hàng','Bạn có thể mua vitamin trực tiếp tại quầy (không cần đơn).','Quầy hàng / Quầy thuốc',2586,NULL,_binary '\0'),(3702,'To react to something with an opposing opinion or action','The government is taking steps to counter the spread of the virus.','VERB','Phản ứng lại điều gì đó bằng một ý kiến hoặc hành động đối lập','Chính phủ đang thực hiện các bước để chống lại sự lây lan của virus.','Phản đối / Chống lại',2586,NULL,_binary '\0'),(3703,'A drug that is sold without a brand name','The pharmacist suggested a generic version of the medicine.','ADJECTIVE','Một loại thuốc được bán mà không có tên thương hiệu','Dược sĩ đã gợi ý một phiên bản thuốc gốc của loại thuốc này.','Thuốc gốc / Không thương hiệu',2587,NULL,_binary '\0'),(3704,'Shared by, typical of, or relating to a whole group of similar things','In Java, generics allow you to write reusable code.','ADJECTIVE','Được chia sẻ bởi, điển hình của hoặc liên quan đến toàn bộ nhóm những thứ tương tự','Trong Java, generics cho phép bạn viết mã có thể tái sử dụng.','Chung chung / Phổ quát',2587,NULL,_binary '\0'),(3705,'A set of medical treatments or a period of taking medicine','You must finish the full course of antibiotics.','NOUN','Một tập hợp các phương pháp điều trị y tế hoặc một khoảng thời gian uống thuốc','Bạn phải hoàn thành toàn bộ liệu trình kháng sinh.','Đợt điều trị / Liệu trình',2588,NULL,_binary '\0'),(3706,'A series of lessons or a part of a meal','The main course was grilled salmon.','NOUN','Một loạt các bài học hoặc một phần của bữa ăn','Món chính là cá hồi nướng.','Khóa học / Món ăn',2588,NULL,_binary '\0'),(3707,'The quality of being easily upset or damaged','She has a sensitivity to penicillin.','NOUN','Khả năng dễ bị khó chịu hoặc bị tổn thương','Cô ấy nhạy cảm với penicillin.','Sự nhạy cảm / Dễ kích ứng',2589,NULL,_binary '\0'),(3708,'The ability of a device to record very small changes','The sensor has high sensitivity to movement.','NOUN','Khả năng của một thiết bị ghi lại những thay đổi rất nhỏ','Cảm biến có độ nhạy cao với chuyển động.','Độ nhạy / Sự nhạy bén',2589,NULL,_binary '\0'),(3709,'Something that is added to something else in order to improve it or complete it','I take vitamin supplements every morning.','NOUN','Thứ gì đó được thêm vào thứ khác để cải thiện hoặc hoàn thiện nó','Tôi uống thực phẩm bổ sung vitamin mỗi sáng.','Thực phẩm bổ sung / Phần bổ sung',2590,NULL,_binary '\0'),(3710,'To add something to something else in order to improve it','He supplements his income by doing freelance web development.','VERB','Thêm thứ gì đó vào thứ khác để cải thiện nó','Anh ấy bổ sung thu nhập của mình bằng cách làm lập trình web tự do.','Bổ sung / Thêm vào',2590,NULL,_binary '\0'),(3711,'To change in a physical or chemical way when put with another substance','Some people react badly to this medicine.','VERB','Thay đổi theo cách vật lý hoặc hóa học khi đặt cùng một chất khác','Một số người phản ứng xấu với loại thuốc này.','Phản ứng (dị ứng)',2591,NULL,_binary '\0'),(3712,'To act in a particular way as a direct result of something else','The library (React) helps developers build user interfaces.','VERB','Hành động theo một cách cụ thể như kết quả trực tiếp của một điều gì đó khác','Thư viện (React) giúp các nhà phát triển xây dựng giao diện người dùng.','Phản ứng / Đối đáp',2591,NULL,_binary '\0'),(3713,'Of, on, for, or coming from the outside','This cream is for external use only.','ADJECTIVE','Của, trên, cho, hoặc đến từ bên ngoài','Kem này chỉ dùng ngoài da.','Dùng ngoài / Bên ngoài',2592,NULL,_binary '\0'),(3714,'Coming from outside a company, organization, or country','The project uses an external API.','ADJECTIVE','Đến từ bên ngoài một công ty, tổ chức hoặc quốc gia','Dự án sử dụng một API bên ngoài.','Bên ngoài / Ngoại vi',2592,NULL,_binary '\0'),(3715,'A lot of small red spots on the skin','The allergy caused a red rash all over his body.','NOUN','Nhiều đốm đỏ nhỏ trên da','Dị ứng đã gây ra phát ban đỏ khắp cơ thể anh ấy.','Phát ban / Nổi mẩn',2593,NULL,_binary '\0'),(3716,'Careless or unwise, without thought for what might happen','Don\'t make any rash decisions.','ADJECTIVE','Cẩu thả hoặc không khôn ngoan, không suy nghĩ về những gì có thể xảy ra','Đừng đưa ra bất kỳ quyết định hấp tấp nào.','Hấp tấp / Thiếu suy nghĩ',2593,NULL,_binary '\0'),(3717,'Painful and uncomfortable because of injury, infection, or too much exercise','I have a sore throat and a fever.','ADJECTIVE','Đau đớn và khó chịu do chấn thương, nhiễm trùng hoặc tập thể dục quá nhiều','Tôi bị đau họng và sốt.','Đau / Nhức / Tấy',2594,NULL,_binary '\0'),(3718,'A painful, often red, place on your body where the skin has been damaged','The saddle caused sores on the horse\'s back.','NOUN','Một nơi đau đớn, thường đỏ trên cơ thể nơi da bị tổn thương','Yên ngựa đã gây ra những vết loét trên lưng ngựa.','Chỗ đau / Vết loét',2594,NULL,_binary '\0'),(3719,'Feeling sleepy and unable to think clearly','This medicine might make you feel drowsy.','ADJECTIVE','Cảm thấy buồn ngủ và không thể suy nghĩ rõ ràng','Thuốc này có thể khiến bạn cảm thấy lơ mơ buồn ngủ.','Buồn ngủ / Lơ mơ',2595,NULL,_binary '\0'),(3720,'A drug that is used to reduce or stop pain','I took a painkiller for my headache.','NOUN','Một loại thuốc được sử dụng để giảm hoặc ngăn chặn cơn đau','Tôi đã uống một viên thuốc giảm đau cho cơn đau đầu của mình.','Thuốc giảm đau',2596,NULL,_binary '\0'),(3721,'Something that someone says or writes officially, in court or to the police','I need to go to the police station to make a statement.','NOUN','Điều mà ai đó nói hoặc viết chính thức trước tòa hoặc với cảnh sát','Tôi cần đến đồn cảnh sát để viết bản tường trình.','Lời khai / Bản tường trình',2597,NULL,_binary '\0'),(3722,'A record of the amounts of money paid out of a bank account, or a line of code','Check your bank statement for any unauthorized transactions.','NOUN','Bản ghi số tiền đã chi trả từ tài khoản ngân hàng, hoặc một dòng mã','Hãy kiểm tra sao kê ngân hàng để xem có giao dịch lạ nào không.','Câu lệnh / Sao kê ngân hàng',2597,NULL,_binary '\0'),(3723,'A person who sees an event happening, especially a crime or an accident','The police are looking for witnesses to the robbery.','NOUN','Người nhìn thấy một sự kiện xảy ra, đặc biệt là một tội ác hoặc tai nạn','Cảnh sát đang tìm kiếm nhân chứng cho vụ cướp.','Nhân chứng',2598,NULL,_binary '\0'),(3724,'To see something happen','Did anyone witness the accident?','VERB','Nhìn thấy điều gì đó xảy ra','Có ai chứng kiến vụ tai nạn không?','Chứng kiến',2598,NULL,_binary '\0'),(3725,'To officially record something, such as a complaint','You should file a police report immediately.','VERB','Ghi lại điều gì đó một cách chính thức, chẳng hạn như một khiếu nại','Bạn nên nộp báo cáo cảnh sát ngay lập tức.','Nộp đơn / Đệ trình',2599,NULL,_binary '\0'),(3726,'Information stored on a computer, or a folder for papers','The police have a file on every suspect.','NOUN','Thông tin được lưu trữ trên máy tính, hoặc một thư mục đựng giấy tờ','Cảnh sát có một bộ hồ sơ về mọi nghi phạm.','Tập tin / Hồ sơ',2599,NULL,_binary '\0'),(3727,'The crime of stealing something','Identity theft is becoming more common online.','NOUN','Tội ăn trộm một thứ gì đó','Trộm cắp danh tính đang trở nên phổ biến hơn trên mạng.','Vụ trộm / Hành vi trộm cắp',2600,NULL,_binary '\0'),(3728,'Something that you own or have with you at a particular time','Please keep your personal possessions with you at all times.','NOUN','Thứ mà bạn sở hữu hoặc mang theo bên mình tại một thời điểm cụ thể','Vui lòng luôn mang theo tài sản cá nhân bên mình.','Tài sản / Vật sở hữu',2601,NULL,_binary '\0'),(3729,'The fact that you have or own something','The drugs were found in his possession.','NOUN','Việc bạn có hoặc sở hữu một cái gì đó','Ma túy được tìm thấy trong sự chiếm hữu của anh ta.','Sự chiếm hữu / Quyền sở hữu',2601,NULL,_binary '\0'),(3730,'A person believed to have committed a crime','The police have arrested a suspect in the robbery.','NOUN','Người bị tin là đã phạm tội','Cảnh sát đã bắt giữ một nghi phạm trong vụ cướp.','Nghi phạm',2602,NULL,_binary '\0'),(3731,'To think that someone has committed a crime or that something is true','I suspect that they are lying.','VERB','Nghĩ rằng ai đó đã phạm tội hoặc điều gì đó là đúng','Tôi nghi ngờ rằng họ đang nói dối.','Nghi ngờ',2602,NULL,_binary '\0'),(3732,'Someone who has been hurt, damaged, or killed because of something','The victim of the pickpocketing reported it to the police.','NOUN','Người đã bị thương, bị thiệt hại hoặc bị giết vì điều gì đó','Nạn nhân của vụ móc túi đã báo cáo với cảnh sát.','Nạn nhân',2603,NULL,_binary '\0'),(3733,'The state of being kept in prison, especially while waiting for a trial','The suspect is currently in police custody.','NOUN','Tình trạng bị giữ trong tù, đặc biệt là khi chờ xét xử','Nghi phạm hiện đang bị cảnh sát tạm giam.','Sự tạm giam / Sự bắt giữ',2604,NULL,_binary '\0'),(3734,'The legal right to look after a child','The parents are fighting for custody of their children.','NOUN','Quyền pháp lý để chăm sóc một đứa trẻ','Cha mẹ đang đấu tranh để giành quyền nuôi con.','Quyền nuôi con',2604,NULL,_binary '\0'),(3735,'To say or write what someone or something is like','Can you describe the person who took your bag?','VERB','Nói hoặc viết về ai đó hoặc cái gì đó như thế nào','Bạn có thể mô tả người đã lấy túi của bạn không?','Mô tả / Nhận dạng',2605,NULL,_binary '\0'),(3737,'To get back something that was lost or stolen','The police managed to recover the stolen laptop.','VERB','Lấy lại thứ gì đó đã bị mất hoặc bị đánh cắp','Cảnh sát đã tìm lại được chiếc máy tính xách tay bị đánh cắp.','Tìm lại được / Thu hồi',2607,NULL,_binary '\0'),(3738,'To become well again after an illness or injury','It took her a long time to recover from the accident.','VERB','Trở nên khỏe lại sau một cơn bạo bệnh hoặc chấn thương','Cô ấy đã mất một thời gian dài để hồi phục sau tai nạn.','Hồi phục / Bình phục',2607,NULL,_binary '\0'),(3741,'To have a document legalized by a notary public','You need to have the statement notarized.','VERB','Làm cho một tài liệu được hợp pháp hóa bởi một công chứng viên','Bạn cần phải đi công chứng bản tường trình này.','Công chứng',2609,NULL,_binary '\0'),(3742,'A single piece of information about something','Please give the officer every detail about the incident.','NOUN','Một mẩu thông tin đơn lẻ về cái gì đó','Vui lòng cung cấp cho viên cảnh sát mọi chi tiết về sự việc.','Chi tiết / Tình tiết',2610,NULL,_binary '\0'),(3743,'To give someone a particular job to do','Four officers were detailed to watch the building.','VERB','Giao cho ai đó một công việc cụ thể để làm','Bốn cảnh sát đã được biệt phái để canh gác tòa nhà.','Phân công / Biệt phái',2610,NULL,_binary '\0'),(3744,'A person who has a position of authority in the police force','The police officer asked for my ID.','NOUN','Người có vị trí quyền hạn trong lực lượng cảnh sát','Viên cảnh sát đã yêu cầu xem căn cước của tôi.','Viên cảnh sát / Sĩ quan',2611,NULL,_binary '\0'),(3745,'A person who has an important position in an organization','He is the Chief Executive Officer (CEO).','NOUN','Người có chức vụ quan trọng trong một tổ chức','Ông ấy là Giám đốc điều hành.','Cán bộ / Nhân viên quản lý',2611,NULL,_binary '\0'),(3746,'The state of being legally or officially acceptable','Check the validity of your passport before booking the flight.','NOUN','Tình trạng được chấp nhận hợp pháp hoặc chính thức','Hãy kiểm tra thời hạn hiệu lực của hộ chiếu trước khi đặt vé máy bay.','Thời hạn hiệu lực / Giá trị pháp lý',2612,NULL,_binary '\0'),(3747,'The quality of being based on truth or reason','We need to check the validity of the input data.','NOUN','Chất lượng dựa trên sự thật hoặc lý lẽ','Chúng ta cần kiểm tra tính hợp lệ của dữ liệu đầu vào.','Tính hợp lệ / Sự đúng đắn',2612,NULL,_binary '\0'),(3748,'To produce or provide something official','The embassy will issue a temporary travel document.','VERB','Sản xuất hoặc cung cấp một thứ gì đó chính thức','Đại sứ quán sẽ cấp một tài liệu du lịch tạm thời.','Cấp / Phát / Ban hành',2613,NULL,_binary '\0'),(3749,'A subject or problem that people are thinking and talking about','I found a critical issue in the backend logic.','NOUN','Một chủ đề hoặc vấn đề mà mọi người đang suy nghĩ và bàn tán','Tôi đã tìm thấy một vấn đề nghiêm trọng trong logic backend.','Vấn đề / Sự cố',2613,NULL,_binary '\0'),(3750,'Something that is an exact copy of something else','I kept a duplicate of my birth certificate in the safe.','NOUN','Thứ gì đó là bản sao chính xác của một thứ khác','Tôi đã giữ một bản sao giấy khai sinh trong két sắt.','Bản sao / Vật mô phỏng',2614,NULL,_binary '\0'),(3751,'To make an exact copy of something','The system found a duplicate record in the database.','VERB','Tạo ra một bản sao chính xác của cái gì đó','Hệ thống đã tìm thấy một bản ghi trùng lặp trong cơ sở dữ liệu.','Nhân bản / Làm giống hệt',2614,NULL,_binary '\0'),(3753,'The office where a consul works','Contact the Vietnamese consulate if you lose your passport.','NOUN','Văn phòng nơi lãnh sự làm việc','Hãy liên hệ với lãnh sự quán Việt Nam nếu bạn bị mất hộ chiếu.','Lãnh sự quán',2616,NULL,_binary '\0'),(3754,'Who a person is, or the qualities of a person or group that make them different from others','The police are trying to establish the identity of the man.','NOUN','Một người là ai, hoặc những phẩm chất khiến họ khác biệt','Cảnh sát đang cố gắng xác định danh tính của người đàn ông.','Danh tính / Bản sắc',2617,NULL,_binary '\0'),(3755,'The state of being the same','The identity operator (===) checks if two references point to the same object.','NOUN','Tình trạng giống hệt nhau','Toán tử đồng nhất (===) kiểm tra xem hai tham chiếu có trỏ cùng một đối tượng không.','Sự đồng nhất / Định danh',2617,NULL,_binary '\0'),(3756,'The act of checking that something is true or accurate','The embassy requires verification of your flight details.','NOUN','Hành động kiểm tra điều gì đó là đúng hoặc chính xác','Đại sứ quán yêu cầu xác minh chi tiết chuyến bay của bạn.','Sự xác minh / Kiểm chứng',2618,NULL,_binary '\0'),(3757,'Real, true, or what people say it is','Is this an authentic copy of the document?','ADJECTIVE','Thật, đúng, hoặc đúng như những gì người ta nói','Đây có phải là bản sao xác thực của tài liệu không?','Thật / Chính gốc / Xác thực',2619,NULL,_binary '\0'),(3758,'Based on facts; accurate and reliable','The restaurant serves authentic Vietnamese food.','ADJECTIVE','Dựa trên sự thật; chính xác và đáng tin cậy','Nhà hàng phục vụ món ăn Việt Nam chuẩn vị.','Đáng tin / Chân thực',2619,NULL,_binary '\0'),(3759,'The act of making something legally acceptable for a second time','The renewal of a passport can take up to two weeks.','NOUN','Hành động làm cho thứ gì đó được chấp nhận hợp pháp lần thứ hai','Việc gia hạn hộ chiếu có thể mất tới hai tuần.','Sự gia hạn / Đổi mới',2620,NULL,_binary '\0'),(3760,'To state officially that something is true and correct','The document was certified by a lawyer.','VERB','Tuyên bố chính thức rằng điều gì đó là đúng và chính xác','Tài liệu đã được chứng thực bởi một luật sư.','Chứng nhận / Xác thực',2621,NULL,_binary '\0'),(3761,'Not lasting or needed for very long','He was given a temporary passport to travel home.','ADJECTIVE','Không kéo dài hoặc không cần thiết trong thời gian dài','Anh ấy đã được cấp một hộ chiếu tạm thời để về nước.','Tạm thời',2622,NULL,_binary '\0'),(3764,'An amount of money paid for a particular piece of work or service','There is a $50 fee for a replacement passport.','NOUN','Số tiền trả cho một công việc hoặc dịch vụ cụ thể','Có một khoản phí 50 đô la để cấp lại hộ chiếu.','Phí / Lệ phí',2624,NULL,_binary '\0'),(3765,'To give up something to someone else','You must surrender your old passport when you get a new one.','VERB','Từ bỏ thứ gì đó cho người khác','Bạn phải giao nộp hộ chiếu cũ khi nhận hộ chiếu mới.','Giao nộp / Hoàn trả',2625,NULL,_binary '\0'),(3766,'To stop fighting and admit defeat','The troops were forced to surrender.','VERB','Ngừng chiến đấu và thừa nhận thất bại','Các binh sĩ bị buộc phải đầu hàng.','Đầu hàng',2625,NULL,_binary '\0'),(3767,'A written statement made on oath, for use as evidence in court','I had to sign an affidavit stating that my passport was lost.','NOUN','Một văn bản viết theo lời thề, dùng làm bằng chứng trước tòa','Tôi đã phải ký một bản cam đoan xác nhận rằng hộ chiếu của mình đã bị mất.','Bản tuyên thệ / Giấy cam đoan',2626,NULL,_binary '\0'),(3770,'To move people from a dangerous place to a safe place','Thousands were ordered to evacuate the coastal area.','VERB','Di chuyển người từ nơi nguy hiểm đến nơi an toàn','Hàng ngàn người đã được lệnh sơ tán khỏi khu vực ven biển.','Sơ tán',2628,NULL,_binary '\0'),(3771,'A warning to people to be prepared for something dangerous','A flood alert has been issued for the riverside towns.','NOUN','Lời cảnh báo mọi người chuẩn bị cho điều gì đó nguy hiểm','Cảnh báo lũ lụt đã được ban bố cho các thị trấn ven sông.','Cảnh báo / Báo động',2629,NULL,_binary '\0'),(3772,'Quick to see, understand, and act in a particular situation','You need to be alert when driving in heavy snow.','ADJECTIVE','Nhanh chóng nhìn thấy, hiểu và hành động trong một tình huống cụ thể','Bạn cần phải cảnh giác khi lái xe trong trời tuyết dày.','Tỉnh táo / Cảnh giác',2629,NULL,_binary '\0'),(3773,'A building or place that provides protection from bad weather or danger','We found shelter under a large tree during the storm.','NOUN','Một tòa nhà hoặc địa điểm cung cấp sự bảo vệ khỏi thời tiết xấu hoặc nguy hiểm','Chúng tôi đã tìm thấy chỗ trú dưới một cái cây lớn trong suốt cơn bão.','Nơi trú ẩn / Chỗ trú',2630,NULL,_binary '\0'),(3774,'To protect yourself, or another person or thing, from bad weather or danger','The umbrella sheltered us from the rain.','VERB','Bảo vệ bản thân hoặc người/vật khác khỏi thời tiết xấu hoặc nguy hiểm','Chiếc ô đã che chở chúng tôi khỏi cơn mưa.','Che chở / Trú ẩn',2630,NULL,_binary '\0'),(3775,'A slight shaking movement in the ground','The slight tremor was felt miles away from the epicenter.','NOUN','Một chuyển động rung lắc nhẹ trên mặt đất','Dư chấn nhẹ được cảm nhận từ cách tâm chấn hàng dặm.','Dư chấn / Sự rung lắc',2631,NULL,_binary '\0'),(3776,'A slight shaking movement in your body caused by fear or illness','There was a slight tremor in her voice.','NOUN','Một chuyển động rung nhẹ trong cơ thể gây ra bởi nỗi sợ hãi hoặc bệnh tật','Có một sự run rẩy nhẹ trong giọng nói của cô ấy.','Sự run rẩy',2631,NULL,_binary '\0'),(3778,'People who are injured or killed in an accident, war, or natural disaster','There were no casualties reported after the earthquake.','NOUN','Những người bị thương hoặc bị giết trong một tai nạn, chiến tranh hoặc thiên tai','Không có thương vong nào được báo cáo sau trận động đất.','Thương vong',2633,NULL,_binary '\0'),(3782,'Something that is done in order to prevent something bad from happening','They took precautions against the hurricane by boarding up windows.','NOUN','Thứ gì đó được thực hiện để ngăn chặn điều tồi tệ xảy ra','Họ đã thực hiện các biện pháp phòng ngừa bão bằng cách đóng ván vào cửa sổ.','Biện pháp phòng ngừa',2636,NULL,_binary '\0'),(3783,'The large size or importance of something, or the strength of an earthquake','An earthquake of magnitude 6.5 struck the island.','NOUN','Kích thước lớn hoặc tầm quan trọng của cái gì đó, hoặc sức mạnh của một trận động đất','Một trận động đất có cường độ 6,5 đã tấn công hòn đảo.','Cường độ / Độ lớn',2637,NULL,_binary '\0'),(3784,'The great size or importance of something','We did not realize the magnitude of the problem.','NOUN','Quy mô hoặc tầm quan trọng to lớn của một thứ gì đó','Chúng tôi đã không nhận ra quy mô của vấn đề.','Tầm quan trọng / Quy mô',2637,NULL,_binary '\0'),(3785,'Broken or torn pieces of something larger','Emergency teams are clearing debris from the streets.','NOUN','Các mảnh bị vỡ hoặc xé rách của một thứ gì đó lớn hơn','Các đội khẩn cấp đang dọn dẹp các mảnh vụn trên đường phố.','Mảnh vụn / Đống đổ nát',2638,NULL,_binary '\0'),(3786,'How far you can see, depending on weather conditions','Visibility was reduced to less than 50 meters in the thick fog.','NOUN','Bạn có thể nhìn thấy bao xa, tùy thuộc vào điều kiện thời tiết','Tầm nhìn bị giảm xuống còn dưới 50 mét trong màn sương mù dày đặc.','Tầm nhìn',2639,NULL,_binary '\0'),(3787,'The degree to which something can be seen','We adjusted the visibility of the widget in Flutter.','NOUN','Mức độ mà một cái gì đó có thể được nhìn thấy','Chúng tôi đã điều chỉnh khả năng hiển thị của widget trong Flutter.','Khả năng hiển thị / Độ rõ ràng',2639,NULL,_binary '\0'),(3788,'Happening suddenly and quickly','Be careful of flash floods in the desert.','ADJECTIVE','Xảy ra một cách đột ngột và nhanh chóng','Hãy cẩn thận với lũ quét trong sa mạc.','Đột ngột / Chớp nhoáng',2640,NULL,_binary '\0'),(3789,'A sudden bright light','The flash of lightning lit up the room.','NOUN','Một ánh sáng chói lọi đột ngột','Ánh chớp của tia sét đã làm sáng cả căn phòng.','Ánh chớp / Đèn flash',2640,NULL,_binary '\0'),(3792,'The system of rules and acceptable behaviour used at official ceremonies','A breach of diplomatic protocol can cause serious tension.','NOUN','Hệ thống các quy tắc và hành vi được chấp nhận trong các buổi lễ chính thức','Một sự vi phạm nghi thức ngoại giao có thể gây ra căng thẳng nghiêm trọng.','Nghi thức / Quy tắc ngoại giao',2642,NULL,_binary '\0'),(3793,'A set of rules governing the exchange of data between devices','HTTP is the standard protocol for transferring data on the web.','NOUN','Một tập hợp các quy tắc quản lý việc trao đổi dữ liệu giữa các thiết bị','HTTP là giao thức tiêu chuẩn để truyền dữ liệu trên web.','Giao thức / Quy trình',2642,NULL,_binary '\0'),(3794,'Someone who speaks or acts on behalf of an organization or government','The consular representative helped the tourists after the accident.','NOUN','Người nói hoặc hành động thay mặt cho một tổ chức hoặc chính phủ','Người đại diện lãnh sự đã giúp đỡ các khách du lịch sau vụ tai nạn.','Người đại diện / Đại biểu',2643,NULL,_binary '\0'),(3795,'Typical of a particular group of people or things','Is this sample representative of the whole population?','ADJECTIVE','Điển hình cho một nhóm người hoặc vật cụ thể','Mẫu này có tiêu biểu cho toàn bộ quần thể không?','Tiêu biểu / Điển hình',2643,NULL,_binary '\0'),(3797,'A person who is a member of a particular country','The embassy provides assistance to its citizens abroad.','NOUN','Một người là thành viên của một quốc gia cụ thể','Đại sứ quán cung cấp sự hỗ trợ cho công dân của mình ở nước ngoài.','Công dân',2645,NULL,_binary '\0'),(3798,'A person who lives in a particular city or town','The citizens of Ho Chi Minh City are very friendly.','NOUN','Người sống ở một thành phố hoặc thị trấn cụ thể','Người dân Thành phố Hồ Chí Minh rất thân thiện.','Người dân / Cư dân',2645,NULL,_binary '\0'),(3799,'To make something legal or to have a document officially recognized','You need to legalize your educational documents at the consulate.','VERB','Làm cho cái gì đó trở nên hợp pháp hoặc được công nhận chính thức','Bạn cần hợp pháp hóa các giấy tờ học tập tại lãnh sự quán.','Hợp pháp hóa',2646,NULL,_binary '\0'),(3800,'To give or allow someone something, usually in an official way','The embassy granted him an emergency travel document.','VERB','Trao hoặc cho phép ai đó điều gì đó, thường theo cách chính thức','Đại sứ quán đã cấp cho anh ấy một giấy tờ du lịch khẩn cấp.','Cấp / Ban cho / Chấp thuận',2647,NULL,_binary '\0'),(3801,'An amount of money given especially by the government for a specific purpose','She received a research grant from the university.','NOUN','Một khoản tiền được chính phủ cấp cho một mục đích cụ thể','Cô ấy đã nhận được một khoản tài trợ nghiên cứu từ trường đại học.','Khoản trợ cấp / Tiền tài trợ',2647,NULL,_binary '\0'),(3802,'A paper or computer file that gives information','Please bring all original documents to the interview.','NOUN','Một tờ giấy hoặc tệp máy tính cung cấp thông tin','Vui lòng mang theo tất cả giấy tờ gốc đến buổi phỏng vấn.','Tài liệu / Giấy tờ',2648,NULL,_binary '\0'),(3803,'To record information about something','Developers must document their code carefully.','VERB','Ghi lại thông tin về một cái gì đó','Các nhà phát triển phải viết tài liệu cho mã của họ một cách cẩn thận.','Ghi chép / Lưu hồ sơ',2648,NULL,_binary '\0'),(3805,'The act of politely or officially asking for something','Your request for a new passport is being processed.','NOUN','Hành động yêu cầu điều gì đó một cách lịch sự hoặc chính thức','Yêu cầu cấp hộ chiếu mới của bạn đang được xử lý.','Lời yêu cầu / Thỉnh cầu',2650,NULL,_binary '\0'),(3806,'A message sent to a server to ask for a resource','The frontend sends a GET request to the backend.','NOUN','Một tin nhắn gửi đến máy chủ để yêu cầu một tài nguyên','Frontend gửi một request GET đến backend.','Yêu cầu (HTTP Request)',2650,NULL,_binary '\0'),(3807,'Communication between people or groups who work together','He serves as a liaison between the embassy and the local police.','NOUN','Sự giao tiếp giữa những người hoặc nhóm làm việc cùng nhau','Anh ấy đóng vai trò là đầu mối liên lạc giữa đại sứ quán và cảnh sát địa phương.','Sự liên lạc / Đầu mối liên hệ',2651,NULL,_binary '\0'),(3809,'To choose someone officially for a job or a responsibility','He was appointed as the new consul general.','VERB','Chọn ai đó một cách chính thức cho một công việc hoặc trách nhiệm','Ông ấy đã được bổ nhiệm làm tổng lãnh sự mới.','Bổ nhiệm / Chỉ định',2653,NULL,_binary '\0'),(3810,'To arrange a time or place for something to happen','You should arrive at the appointed time.','VERB','Sắp xếp thời gian hoặc địa điểm để điều gì đó xảy ra','Bạn nên đến vào thời gian đã ấn định.','Sắp xếp / Ấn định',2653,NULL,_binary '\0'),(3811,'Official protection from legal action','Diplomatic immunity protects officials from local prosecution.','NOUN','Sự bảo vệ chính thức khỏi các hành động pháp lý','Quyền miễn trừ ngoại giao bảo vệ các quan chức khỏi bị truy tố tại địa phương.','Quyền miễn trừ',2654,NULL,_binary '\0'),(3812,'The ability of the body to resist a particular disease','The vaccine provides immunity against the virus.','NOUN','Khả năng của cơ thể để chống lại một căn bệnh cụ thể','Vắc-xin cung cấp khả năng miễn dịch chống lại virus.','Khả năng miễn dịch',2654,NULL,_binary '\0'),(3814,'A printed document with blank spaces for information to be filled in','Please fill out this application form for a visa renewal.','NOUN','Một tài liệu in có các khoảng trống để điền thông tin vào','Vui lòng điền vào mẫu đơn này để gia hạn thị thực.','Mẫu đơn / Tờ khai',2656,NULL,_binary '\0'),(3815,'The shape or appearance of something','Swimming is a great form of exercise.','NOUN','Hình dạng hoặc diện mạo của cái gì đó','Bơi lội là một hình thức tập thể dục tuyệt vời.','Hình dạng / Hình thức',2656,NULL,_binary '\0'),(3816,'An organized plan for doing something, especially something dishonest','They were involved in a scheme to defraud tourists.','NOUN','Một kế hoạch có tổ chức để làm điều gì đó, đặc biệt là điều không trung thực','Họ đã tham gia vào một âm mưu lừa gạt khách du lịch.','Âm mưu / Thủ đoạn',2657,NULL,_binary '\0'),(3817,'An official plan or system','The database schema (scheme) defines the structure of the alumni system.','NOUN','Một kế hoạch hoặc hệ thống chính thức','Lược đồ cơ sở dữ liệu định nghĩa cấu trúc của hệ thống cựu sinh viên.','Lược đồ / Hệ thống',2657,NULL,_binary '\0'),(3818,'To take someone\'s attention away from what they are doing','One person distracted the tourist while the other stole his wallet.','VERB','Lấy đi sự chú ý của ai đó khỏi những gì họ đang làm','Một người đánh lạc hướng du khách trong khi người kia lấy trộm ví của anh ta.','Làm xao nhãng / Đánh lạc hướng',2658,NULL,_binary '\0'),(3821,'To control or influence something or someone in a clever or dishonest way','Scammers manipulate victims by creating a sense of urgency.','VERB','Kiểm soát hoặc ảnh hưởng đến thứ gì đó hoặc ai đó một cách khéo léo hoặc không trung thực','Kẻ lừa đảo thao túng nạn nhân bằng cách tạo ra cảm giác cấp bách.','Thao túng / Điều khiển',2661,NULL,_binary '\0'),(3822,'To control something using the hands','The app allows you to manipulate SVG images easily.','VERB','Kiểm soát thứ gì đó bằng tay hoặc công cụ','Ứng dụng cho phép bạn thao tác với hình ảnh SVG một cách dễ dàng.','Thao tác / Xử lý',2661,NULL,_binary '\0'),(3823,'Made to look like the original of something, usually for dishonest purposes','Be careful of counterfeit banknotes in crowded markets.','ADJECTIVE','Được làm cho giống với bản gốc của thứ gì đó, thường vì mục đích không trung thực','Hãy cẩn thận với tiền giấy giả mạo ở các khu chợ đông đúc.','Giả mạo / Hàng giả',2662,NULL,_binary '\0'),(3824,'A person or object that is used as an aim for an attack','Tourists who look lost are an easy target for scammers.','NOUN','Một người hoặc vật thể được sử dụng làm mục tiêu cho một cuộc tấn công','Những du khách trông có vẻ lạc đường là mục tiêu dễ dàng cho kẻ lừa đảo.','Mục tiêu / Đối tượng nhắm tới',2663,NULL,_binary '\0'),(3825,'A result that you try to achieve','We reached our sales target for this quarter.','NOUN','Kết quả mà bạn cố gắng đạt được','Chúng tôi đã đạt được chỉ tiêu doanh số cho quý này.','Chỉ tiêu / Đích đến',2663,NULL,_binary '\0'),(3826,'A device or a situation that is intended to catch or deceive people','That souvenir shop is a classic tourist trap.','NOUN','Một thiết bị hoặc tình huống nhằm mục đích bắt hoặc đánh lừa mọi người','Cửa hàng lưu niệm đó là một cái bẫy du khách điển hình.','Cái bẫy',2664,NULL,_binary '\0'),(3827,'To catch an animal in a trap, or to keep someone in a place they cannot leave','I felt trapped in the long meeting.','VERB','Bắt một con vật bằng bẫy, hoặc giữ ai đó ở một nơi họ không thể rời đi','Tôi cảm thấy bị mắc kẹt trong cuộc họp dài.','Bắt giữ / Làm mắc kẹt',2664,NULL,_binary '\0'),(3828,'Feeling that someone has done something wrong, dishonest, or illegal','If a deal seems too good to be true, it is probably suspicious.','ADJECTIVE','Cảm giác rằng ai đó đã làm điều gì đó sai trái, không trung thực hoặc bất hợp pháp','Nếu một thỏa thuận có vẻ quá tốt để thành sự thật, nó có lẽ là khả nghi.','Khả nghi / Nghi ngờ',2665,NULL,_binary '\0'),(3829,'The crime of getting money by deceiving people','Credit card fraud is a major risk when using public Wi-Fi.','NOUN','Tội lấy tiền bằng cách đánh lừa mọi người','Gian lận thẻ tín dụng là một rủi ro lớn khi sử dụng Wi-Fi công cộng.','Sự gian lận / Tội lừa đảo',2666,NULL,_binary '\0'),(3830,'The illegal act of copying information from the magnetic strip of a credit card','Card skimming often happens at unattended ATMs.','NOUN','Hành vi bất hợp pháp sao chép thông tin từ dải từ của thẻ tín dụng','Việc đọc trộm thẻ thường xảy ra tại các máy ATM không có người trông coi.','Hành vi đọc trộm thẻ',2667,NULL,_binary '\0'),(3831,'Reading something quickly to get a general idea','Skimming is a useful skill for the TOEIC reading section.','NOUN','Đọc thứ gì đó nhanh chóng để lấy ý tưởng chung','Đọc lướt là một kỹ năng hữu ích cho phần đọc TOEIC.','Sự đọc lướt',2667,NULL,_binary '\0'),(3832,'Something that is said or offered to make someone react in a particular way','Free gifts are often used as bait to lure people into shops.','NOUN','Thứ gì đó được nói hoặc đưa ra để khiến ai đó phản ứng theo một cách cụ thể','Quà tặng miễn phí thường được dùng làm mồi nhử để lôi kéo người dân vào cửa hàng.','Mồi nhử',2668,NULL,_binary '\0'),(3833,'To intentionally make someone angry by criticizing them or using other methods','The scammers baited him with a fake prize.','VERB','Cố tình làm ai đó tức giận bằng cách chỉ trích họ hoặc sử dụng các phương pháp khác','Kẻ lừa đảo đã nhử anh ta bằng một giải thưởng giả.','Chọc giận / Nhử',2668,NULL,_binary '\0'),(3836,'To say that something is true, although you have not proved it','The scammer claimed to be a local police officer.','VERB','Nói rằng điều gì đó là đúng, mặc dù bạn chưa chứng minh được','Kẻ lừa đảo tự nhận là một sĩ quan cảnh sát địa phương.','Tuyên bố / Tự nhận',2670,NULL,_binary '\0'),(3837,'A request to an insurance company for payment','I filed an insurance claim after my phone was stolen.','NOUN','Yêu cầu một công ty bảo hiểm thanh toán','Tôi đã nộp đơn yêu cầu bồi thường bảo hiểm sau khi điện thoại bị mất cắp.','Yêu cầu bồi thường / Khiếu nại',2670,NULL,_binary '\0'),(3838,'To persuade someone to do something or go somewhere by offering them something exciting','Scammers try to lure tourists into quiet alleys.','VERB','Thuyết phục ai đó làm điều gì đó hoặc đi đâu đó bằng cách cung cấp cho họ thứ gì đó thú vị','Kẻ lừa đảo cố gắng lôi kéo du khách vào những con hẻm vắng.','Lôi kéo / Nhử',2671,NULL,_binary '\0');
